-- 데이터베이스 > SQL과 관계형 DB (436문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (61, 3, 1, 1, 'SQL에서 데이터베이스의 구조를 정의하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'DDL', 'DDL은 데이터베이스 객체의 구조를 정의하는 명령어로, 테이블 생성, 수정, 삭제 등에 사용됩니다.'),
    (62, 3, 1, 2, 'LEFT JOIN과 FULL OUTER JOIN의 차이점으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LEFT JOIN은 왼쪽 테이블의 모든 행을 반환한다."}, {"id": "B", "text": "FULL OUTER JOIN은 두 테이블의 모든 행을 반환한다."}, {"id": "C", "text": "LEFT JOIN은 오른쪽 테이블의 모든 행을 반환한다."}, {"id": "D", "text": "FULL OUTER JOIN은 중복된 행만 반환한다."}]', 'A', 'LEFT JOIN은 왼쪽 테이블의 모든 행을 반환하며, 오른쪽 테이블에 매칭되는 행이 없으면 NULL로 채워집니다.'),
    (63, 3, 1, 3, '다음 중 DCL의 역할에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 삭제 권한 부여"}, {"id": "B", "text": "테이블 구조 변경"}, {"id": "C", "text": "데이터 삽입 권한 회수"}, {"id": "D", "text": "데이터 조회 권한 부여"}]', 'B', 'DCL은 데이터베이스의 접근 권한을 관리하는 명령어로, 테이블 구조 변경은 DDL의 역할입니다.'),
    (64, 3, 1, 4, 'DISTINCT 키워드의 역할은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중복된 행을 제거한다."}, {"id": "B", "text": "데이터를 정렬한다."}, {"id": "C", "text": "결과 집합의 행 수를 제한한다."}, {"id": "D", "text": "특정 조건에 맞는 데이터만 선택한다."}]', '["A"]', 'DISTINCT는 SELECT 문에서 중복된 행을 제거하여 유일한 값만 반환하는 역할을 합니다.'),
    (65, 3, 1, 5, '뷰(View)의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 보안 및 접근 제어"}, {"id": "B", "text": "데이터를 영구 저장하기 위해"}, {"id": "C", "text": "데이터를 직접 수정하기 위해"}, {"id": "D", "text": "데이터의 백업을 위해"}]', 'A', '뷰는 데이터에 대한 접근을 제어하고 보안을 강화하는 데 유용하다.'),
    (66, 3, 1, 6, '트랜잭션의 ACID 속성 중에서 ''일관성''이 의미하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 트랜잭션이 성공적으로 끝나야 한다"}, {"id": "B", "text": "트랜잭션 수행 후 데이터의 상태가 일관되게 유지되어야 한다"}, {"id": "C", "text": "트랜잭션은 독립적으로 실행되어야 한다"}, {"id": "D", "text": "트랜잭션은 언제든지 중단 가능해야 한다"}]', 'B', '일관성은 트랜잭션이 수행된 후 데이터가 일관된 상태를 유지하는 것을 의미한다.'),
    (67, 3, 1, 7, 'DML의 예에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "SELECT"}, {"id": "B", "text": "INSERT"}, {"id": "C", "text": "UPDATE"}, {"id": "D", "text": "GRANT"}]', 'D', 'GRANT는 DCL(Data Control Language)로 데이터에 대한 권한을 부여하는 명령어이다.'),
    (68, 3, 1, 8, '다음 중 관계 해석에 맞는 SQL 문을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT * FROM Users"}, {"id": "B", "text": "DELETE FROM Orders WHERE OrderID = 1"}, {"id": "C", "text": "CREATE TABLE Products (ID INT, Name VARCHAR(100))"}, {"id": "D", "text": "UPDATE Users SET Age = 30 WHERE ID = 2"}]', '["A", "B", "D"]', 'SELECT, DELETE, UPDATE는 데이터 조작을 위한 DML 명령이다.'),
    (69, 3, 1, 9, 'ERD의 가장 기본적인 구성 요소는 무엇인가?', 'SHORT_ANSWER', NULL, '엔티티와 관계', 'ERD는 엔티티와 그들 간의 관계를 시각적으로 표현한 다이어그램이다.'),
    (70, 3, 1, 10, 'SQL에서 데이터를 삽입하기 위한 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'INSERT', 'INSERT는 SQL에서 새로운 데이터를 테이블에 추가하는 데 사용되는 명령어입니다.'),
    (71, 3, 1, 11, '스칼라 서브쿼리는 어떤 상황에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단일 값 결과를 반환할 때"}, {"id": "B", "text": "여러 행을 반환할 때"}, {"id": "C", "text": "데이터베이스를 삭제할 때"}, {"id": "D", "text": "다중 테이블 조인이 필요할 때"}]', 'A', '스칼라 서브쿼리는 한 개의 값만 반환할 수 있는 서브쿼리로, 특정 조건을 갖춘 값을 조회할 때 사용됩니다.'),
    (72, 3, 1, 12, 'HAVING 절은 주로 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 삽입할 때"}, {"id": "B", "text": "그룹화된 결과에 조건을 달 때"}, {"id": "C", "text": "테이블 구조를 변경할 때"}, {"id": "D", "text": "데이터를 삭제할 때"}]', 'B', 'HAVING 절은 GROUP BY 절과 함께 사용되어 집계된 결과에 조건을 걸 때 사용됩니다.'),
    (73, 3, 1, 13, '다음 중 DISTINCT의 사용 목적이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중복 제거"}, {"id": "B", "text": "데이터 삽입"}, {"id": "C", "text": "고유한 결과 추출"}, {"id": "D", "text": "결과 정렬"}]', '["B", "D"]', 'DISTINCT는 중복된 값을 제거하고 고유한 결과를 추출하는 데 사용되며, 데이터 삽입이나 결과 정렬과는 관계가 없습니다.'),
    (74, 3, 1, 14, 'ERD에서 엔티티와 관계의 시각적 표현을 통해 무엇을 이해할 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 간의 관계"}, {"id": "B", "text": "쿼리 성능"}, {"id": "C", "text": "트랜잭션 처리"}, {"id": "D", "text": "데이터 검색"}]', 'A', 'ERD는 데이터 간의 관계를 시각적으로 표현하여 이해하는 데 도움을 줍니다.'),
    (75, 3, 1, 15, '트랜잭션의 ACID 속성 중 ''Durability''는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원자성"}, {"id": "B", "text": "일관성"}, {"id": "C", "text": "격리성"}, {"id": "D", "text": "지속성"}]', 'D', 'Durability는 트랜잭션이 성공적으로 완료된 후, 그 결과가 영구적으로 저장됨을 의미합니다.'),
    (76, 3, 1, 16, 'DCL의 목적이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "사용자 권한 관리"}, {"id": "B", "text": "데이터 검색"}, {"id": "C", "text": "데이터 수정"}, {"id": "D", "text": "데이터 보안"}]', '["B", "C"]', 'DCL은 사용자 권한 관리와 데이터 보안에 관련된 명령어로, 데이터 검색이나 수정과는 관련이 없습니다.'),
    (77, 3, 1, 17, '커서(Cursor)의 주 용도는 무엇인가?', 'SHORT_ANSWER', NULL, 'SQL 쿼리 결과를 탐색하고 조작하기 위함', '커서는 SQL 쿼리의 결과 집합에서 개별 행을 접근하고 조작하기 위해 사용됩니다.'),
    (78, 3, 1, 18, '인덱스(Index)의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 검색 성능을 향상시키기 위함', '인덱스는 데이터베이스에서 데이터를 더 빠르게 검색하기 위한 구조입니다.'),
    (79, 3, 1, 19, '트리거의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 무결성 유지"}, {"id": "B", "text": "데이터베이스 백업"}, {"id": "C", "text": "데이터 암호화"}, {"id": "D", "text": "데이터 시각화"}]', 'A', '트리거는 데이터 변경 시 자동으로 특정 작업을 수행하여 데이터 무결성을 유지하는 역할을 한다.'),
    (80, 3, 1, 20, '트랜잭션의 ACID 특성 중 Isolation의 의미는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원자성"}, {"id": "B", "text": "일관성"}, {"id": "C", "text": "독립성"}, {"id": "D", "text": "지속성"}]', 'C', 'Isolation은 트랜잭션이 서로 독립적으로 실행되어야 함을 의미한다.'),
    (81, 3, 1, 21, '다음 중 DDL에 해당하지 않는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CREATE"}, {"id": "B", "text": "SELECT"}, {"id": "C", "text": "ALTER"}, {"id": "D", "text": "DROP"}]', 'B', 'SELECT는 데이터 조회를 위한 DML 명령어로, DDL에는 포함되지 않는다.'),
    (82, 3, 1, 22, '정규화의 주요 목적은 무엇인가? (복수 선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 중복 제거"}, {"id": "B", "text": "데이터 무결성 향상"}, {"id": "C", "text": "쿼리 성능 향상"}, {"id": "D", "text": "데이터 암호화"}]', '["A", "B"]', '정규화는 데이터 중복을 제거하고 무결성을 향상시키기 위한 과정이다.'),
    (83, 3, 1, 23, '트랜잭션이란 무엇인가?', 'SHORT_ANSWER', NULL, '데이터베이스의 일관성을 유지하기 위해 수행되는 작업의 집합', ''),
    (84, 3, 1, 24, '인덱스의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 검색 속도 향상"}, {"id": "B", "text": "데이터 중복 생성"}, {"id": "C", "text": "데이터 무결성 강화"}, {"id": "D", "text": "데이터 암호화"}]', 'A', '인덱스는 데이터 검색 속도를 향상시키기 위해 사용되는 구조입니다.'),
    (85, 3, 1, 25, 'ERD에서 엔티티와 그 관계를 시각적으로 표현하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스 설계의 용이성"}, {"id": "B", "text": "보안 강화를 위해"}, {"id": "C", "text": "데이터를 암호화하기 위해"}, {"id": "D", "text": "서버 성능 향상을 위해"}]', 'A', 'ERD는 데이터베이스 구조를 시각적으로 표현하여 설계를 용이하게 합니다.'),
    (86, 3, 1, 26, '이상 현상을 방지하기 위한 데이터베이스 설계 과정은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정규화"}, {"id": "B", "text": "비정규화"}, {"id": "C", "text": "인덱스 생성"}, {"id": "D", "text": "데이터 마이닝"}]', 'A', '정규화는 이상 현상을 방지하기 위한 데이터베이스 설계 과정입니다.'),
    (87, 3, 1, 27, 'SQL에서 데이터 삽입, 수정, 삭제를 담당하는 언어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DML"}, {"id": "B", "text": "DDL"}, {"id": "C", "text": "DCL"}, {"id": "D", "text": "TCL"}]', '["A"]', 'DML(Data Manipulation Language)은 데이터 삽입, 수정, 삭제를 담당하는 언어입니다.'),
    (88, 3, 1, 28, '관계 대수에서 사용되는 기본적인 연산자는 무엇인가요?', 'SHORT_ANSWER', NULL, '선택, 투영, 합집합, 차집합, 교집합', '관계 대수에서 사용되는 기본적인 연산자는 선택, 투영, 합집합, 차집합, 교집합입니다.'),
    (89, 3, 1, 29, 'SQL의 SELECT 문에서 데이터를 필터링하는 데 사용되는 절은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHERE"}, {"id": "B", "text": "GROUP BY"}, {"id": "C", "text": "HAVING"}, {"id": "D", "text": "ORDER BY"}]', 'A', 'WHERE 절은 SELECT 문에서 조건에 맞는 데이터를 필터링하는 데 사용됩니다.'),
    (90, 3, 1, 30, 'GROUP BY 절은 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬하기 위해"}, {"id": "B", "text": "데이터를 그룹화하기 위해"}, {"id": "C", "text": "데이터를 삭제하기 위해"}, {"id": "D", "text": "데이터를 추가하기 위해"}]', 'B', 'GROUP BY 절은 특정 열을 기준으로 데이터를 그룹화하여 집계하는 데 사용됩니다.'),
    (91, 3, 1, 31, '다음 중 DDL에 해당하지 않는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CREATE"}, {"id": "B", "text": "INSERT"}, {"id": "C", "text": "ALTER"}, {"id": "D", "text": "DROP"}]', 'B', 'INSERT 문은 데이터 조작어(DML)에 해당하고, DDL은 데이터 구조를 정의하는 명령어입니다.'),
    (92, 3, 1, 32, 'HAVING 절은 주로 어떤 상황에서 사용되나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "집계 함수와 함께 사용될 때"}, {"id": "B", "text": "일반 열에 조건을 걸 때"}, {"id": "C", "text": "데이터를 삽입할 때"}, {"id": "D", "text": "데이터를 필터링할 때"}]', '["A"]', 'HAVING 절은 GROUP BY로 그룹화한 후, 집계 함수와 함께 조건을 설정할 때 주로 사용됩니다.'),
    (93, 3, 1, 33, 'SQL에서 인라인 뷰의 정의는 무엇인가요?', 'SHORT_ANSWER', NULL, 'FROM 절 내에서 서브쿼리를 사용하는 가상의 테이블', '인라인 뷰는 SELECT 쿼리의 FROM 절 내에 서브쿼리를 포함시켜 가상의 테이블을 만드는 것입니다.'),
    (94, 3, 1, 34, 'DCL의 주된 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스 구조 정의"}, {"id": "B", "text": "데이터에 대한 접근 권한 제어"}, {"id": "C", "text": "데이터 검색 쿼리 작성"}, {"id": "D", "text": "데이터 중복 제거"}]', 'B', 'DCL(Data Control Language)은 데이터베이스 사용자에 대한 접근 권한을 설정하고 제어하는 역할을 합니다.'),
    (95, 3, 1, 35, '정규화의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 일관성 유지"}, {"id": "B", "text": "데이터 중복 최소화"}, {"id": "C", "text": "쿼리 성능 향상"}, {"id": "D", "text": "보안 강화"}]', 'B', '정규화는 데이터베이스에서 데이터 중복을 최소화하고, 무결성을 유지하기 위해 데이터를 구조적으로 정리하는 과정입니다.'),
    (96, 3, 1, 36, '프로시저와 함수의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로시저는 값을 반환하고, 함수는 반환하지 않는다."}, {"id": "B", "text": "프로시저는 여러 작업을 수행할 수 있지만, 함수는 하나의 작업만 수행한다."}, {"id": "C", "text": "프로시저는 호출 시 매개변수를 받을 수 있지만, 함수는 받을 수 없다."}, {"id": "D", "text": "프로시저는 결과를 반환하지 않는 반면, 함수는 항상 결과를 반환한다."}]', 'D', '프로시저는 주로 작업을 수행하기 위한 블록이고, 함수는 항상 값을 반환하는 특징이 있습니다.'),
    (97, 3, 1, 37, '관계 해석과 관계 대수의 차이를 설명하시오.', 'SHORT_ANSWER', NULL, '관계 해석은 선언적 접근 방식으로 데이터를 선택하는 방법을 기술하며, 관계 대수는 절차적 접근 방식으로 데이터를 추출하기 위한 연산을 정의한다.', '관계 해석은 쿼리의 결과를 어떻게 도출할 것인지에 대한 의도를 표현하고, 관계 대수는 실제 어떻게 도출할지를 명시합니다.'),
    (98, 3, 1, 38, '트랜잭션의 원자성에 대한 설명으로 옳은 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "트랜잭션이 완료되거나 전혀 수행되지 않아야 한다."}, {"id": "B", "text": "트랜잭션 중 일부 작업만 수행될 수 있다."}, {"id": "C", "text": "트랜잭션은 항상 데이터베이스에 기록되어야 한다."}, {"id": "D", "text": "트랜잭션의 모든 작업은 하나의 단위로 처리된다."}]', '["A", "D"]', '트랜잭션의 원자성은 모든 작업이 하나의 단위로 처리되어, 성공하면 모두 완료되고 실패하면 전부 취소되는 것을 보장합니다.'),
    (99, 3, 1, 39, 'SQL이 포함하는 데이터 조작 언어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DML"}, {"id": "B", "text": "DDL"}, {"id": "C", "text": "DCL"}, {"id": "D", "text": "TCL"}]', 'A', 'SQL의 DML은 데이터베이스에서 데이터를 조작하는 데 사용되는 언어입니다.'),
    (100, 3, 1, 40, 'ERD의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 흐름 분석"}, {"id": "B", "text": "데이터 구조 시각화"}, {"id": "C", "text": "쿼리 최적화"}, {"id": "D", "text": "데이터 보안"}]', 'B', 'ERD는 데이터베이스의 구조를 시각적으로 표현하여 이해하기 쉽게 만들어줍니다.'),
    (101, 3, 1, 41, '트리거의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 입력 자동화"}, {"id": "B", "text": "사용자 정의 함수 생성"}, {"id": "C", "text": "데이터 삭제 방지"}, {"id": "D", "text": "특정 이벤트 발생 시 자동 실행"}]', 'D', '트리거는 특정 이벤트가 발생할 때 자동으로 실행되는 프로시저입니다.'),
    (102, 3, 1, 42, '다음 중 DML에 포함되는 명령어를 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "INSERT"}, {"id": "B", "text": "CREATE"}, {"id": "C", "text": "UPDATE"}, {"id": "D", "text": "DELETE"}]', '["A", "C", "D"]', 'DML은 데이터의 삽입(INSERT), 수정(UPDATE), 삭제(DELETE)와 관련된 명령어를 포함합니다.'),
    (103, 3, 1, 43, '뷰(View)의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '특정 쿼리 결과를 저장하여 쉽게 접근할 수 있도록 하는 것', '뷰는 복잡한 쿼리 결과를 미리 정의하여 필요할 때 쉽게 사용할 수 있게 도와줍니다.'),
    (104, 3, 1, 44, '인덱스의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 검색 속도 향상"}, {"id": "B", "text": "데이터 무결성 유지"}, {"id": "C", "text": "데이터 삭제 속도 향상"}, {"id": "D", "text": "데이터 저장 공간 절약"}]', 'A', '인덱스는 데이터베이스에서 데이터를 더욱 빠르게 검색하기 위해 사용됩니다.'),
    (105, 3, 1, 45, '정규화의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 제거"}, {"id": "B", "text": "SQL 쿼리 최적화"}, {"id": "C", "text": "보안 강화"}, {"id": "D", "text": "데이터 시각화"}]', 'A', '정규화는 데이터베이스 내에서 데이터의 중복을 제거하고 무결성을 유지하기 위해 수행됩니다.'),
    (106, 3, 1, 46, 'DML에 포함되지 않는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "INSERT"}, {"id": "B", "text": "UPDATE"}, {"id": "C", "text": "DELETE"}, {"id": "D", "text": "CREATE"}]', 'D', 'DML, 즉 데이터 조작 언어는 INSERT, UPDATE, DELETE와 같은 명령어로 구성되며, CREATE는 DDL(데이터 정의 언어)에 해당합니다.'),
    (107, 3, 1, 47, '정규화의 단계 중 1NF의 조건으로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 열이 원자값을 가져야 한다."}, {"id": "B", "text": "부분 종속이 없어야 한다."}, {"id": "C", "text": "모든 기본키가 유일해야 한다."}, {"id": "D", "text": "각 레코드가 고유해야 한다."}]', '["A", "C", "D"]', '1NF(제 1 정규형)는 모든 열이 원자값을 가져야 하며, 모든 기본키가 유일해야 하고 각 레코드가 고유해야 한다는 조건을 갖습니다.'),
    (108, 3, 1, 48, '커서의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '행을 순차적으로 접근하고 처리하기 위해 사용된다.', '커서는 데이터베이스에서 결과 집합을 탐색하고 각 행에 대해 작업을 수행하는 데 사용됩니다.'),
    (109, 3, 1, 49, 'DISTINCT 키워드는 어떤 목적으로 사용되는가?', 'SHORT_ANSWER', NULL, '중복된 값을 제거하여 고유한 데이터만 선택하기 위함입니다.', 'DISTINCT는 SQL 쿼리에서 중복된 레코드를 제거하는 데 사용됩니다.'),
    (110, 3, 1, 50, 'LEFT JOIN과 FULL OUTER JOIN의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LEFT JOIN은 왼쪽 테이블의 모든 행을 반환하며, FULL OUTER JOIN은 두 테이블의 모든 행을 반환한다."}, {"id": "B", "text": "LEFT JOIN은 오른쪽 테이블의 모든 행을 반환하고, FULL OUTER JOIN은 중복된 행만 반환한다."}, {"id": "C", "text": "LEFT JOIN과 FULL OUTER JOIN은 동일하다."}, {"id": "D", "text": "LEFT JOIN은 조건에 맞는 행만 반환하고 FULL OUTER JOIN은 조건에 관계없이 모든 행을 반환한다."}]', 'A', 'LEFT JOIN은 왼쪽 테이블의 모든 행을 반환하고, 조건이 일치하지 않으면 NULL 값을 포함합니다. 반면 FULL OUTER JOIN은 두 테이블의 모든 행을 반환합니다.'),
    (111, 3, 1, 51, '서브쿼리를 사용하는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단일 쿼리로 데이터를 조회하기 위함이다."}, {"id": "B", "text": "복잡한 데이터 검색을 가능하게 하기 위함이다."}, {"id": "C", "text": "쿼리의 실행 속도를 빨리 하기 위함이다."}, {"id": "D", "text": "쿼리를 간단하게 만들기 위해서이다."}]', 'B', '서브쿼리는 다른 쿼리의 결과를 기반으로 데이터를 검색할 수 있게 하여 복잡한 조건으로 데이터를 필터링할 수 있습니다.'),
    (112, 3, 1, 52, 'ORDER BY 절의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "결과 집합을 정렬한다."}, {"id": "B", "text": "결과 집합에서 특정 열을 선택한다."}, {"id": "C", "text": "중복된 데이터를 제거한다."}, {"id": "D", "text": "데이터를 삽입한다."}]', '["A"]', 'ORDER BY 절은 SQL 쿼리의 결과 집합을 지정한 열의 값에 따라 정렬합니다.'),
    (113, 3, 1, 53, 'DDL의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터 정의 언어', 'DDL은 데이터베이스 객체의 구조를 정의하는 언어로, CREATE, ALTER, DROP과 같은 명령어를 포함합니다.'),
    (114, 3, 1, 54, 'FULL OUTER JOIN의 결과는 어떤 경우에 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 테이블의 모든 행을 포함한다."}, {"id": "B", "text": "첫 번째 테이블의 행만 포함한다."}, {"id": "C", "text": "두 번째 테이블의 행만 포함한다."}, {"id": "D", "text": "조건이 일치하는 행만 포함한다."}]', 'A', 'FULL OUTER JOIN은 두 테이블 간의 모든 행을 포함하여 결합하며, 매칭이 없는 경우 NULL을 반환합니다.'),
    (115, 3, 1, 55, 'HAVING 절은 언제 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "GROUP BY 이후 집계된 결과를 필터링할 때 사용한다."}, {"id": "B", "text": "데이터를 추가할 때 사용한다."}, {"id": "C", "text": "테이블 구조를 변경할 때 사용한다."}, {"id": "D", "text": "기본 데이터 선택 시 사용한다."}]', 'A', 'HAVING 절은 GROUP BY를 통해 그룹화된 데이터에 대한 조건을 지정할 때 사용됩니다.'),
    (116, 3, 1, 56, '다음 중 JOIN의 종류가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "INNER JOIN"}, {"id": "B", "text": "LEFT JOIN"}, {"id": "C", "text": "OUTER JOIN"}, {"id": "D", "text": "FULL JOIN"}]', '["C"]', 'OUTER JOIN은 JOIN의 일반적인 용어이며, LEFT, RIGHT, FULL이 포함됩니다.'),
    (117, 3, 1, 57, 'GROUP BY 절의 주 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 그룹화하여 집계하는 것"}, {"id": "B", "text": "두 테이블을 조인하는 것"}, {"id": "C", "text": "행을 삭제하는 것"}, {"id": "D", "text": "데이터를 업데이트하는 것"}]', 'A', 'GROUP BY 절은 데이터를 특정 기준에 따라 그룹화하여 집계 결과를 생성하는 데 사용됩니다.'),
    (118, 3, 1, 58, 'RIGHT JOIN의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "오른쪽 테이블의 모든 행을 포함한다"}, {"id": "B", "text": "왼쪽 테이블의 모든 행을 포함한다"}, {"id": "C", "text": "두 테이블의 모든 행을 포함한다"}, {"id": "D", "text": "조인을 사용하지 않는다"}]', 'A', 'RIGHT JOIN은 오른쪽 테이블의 모든 행과 일치하는 왼쪽 테이블의 행을 반환하는 조인입니다.'),
    (119, 3, 1, 59, 'HAVING 절은 어떤 경우에 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "집계된 결과에 조건을 적용할 때"}, {"id": "B", "text": "신규 데이터를 삽입할 때"}, {"id": "C", "text": "데이터를 정렬할 때"}, {"id": "D", "text": "데이터를 삭제할 때"}]', 'A', 'HAVING 절은 GROUP BY로 집계된 결과에 필터를 적용할 때 사용됩니다.'),
    (120, 3, 1, 60, '다음 중 DELETE와 UPDATE 문을 모두 사용하는 상황은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "테이블의 특정 데이터를 수정하고 삭제할 때"}, {"id": "B", "text": "데이터를 조회할 때"}, {"id": "C", "text": "데이터베이스를 백업할 때"}, {"id": "D", "text": "데이터를 삽입할 때"}]', '["A"]', 'DELETE 문은 특정 행을 삭제하는 데 사용되고, UPDATE 문은 행의 데이터를 수정하는 데 사용됩니다.'),
    (121, 3, 1, 61, '인라인 뷰란 무엇인가요?', 'SHORT_ANSWER', NULL, '서브쿼리의 결과를 사용하는 가상의 테이블입니다.', '인라인 뷰는 서브쿼리의 결과를 테이블처럼 사용하여 복잡한 쿼리를 단순화하는 데 활용됩니다.'),
    (122, 3, 1, 62, '다음 SQL 쿼리에서 ROW_NUMBER() 함수는 어떤 역할을 하나요? SELECT employee_id, salary, ROW_NUMBER() OVER (ORDER BY salary DESC) AS rank FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원에게 고유 번호를 부여한다."}, {"id": "B", "text": "급여를 기준으로 동점인 직원들에게 동일한 순위를 부여한다."}, {"id": "C", "text": "이전 직원의 급여 값을 참조한다."}, {"id": "D", "text": "급여의 평균을 계산한다."}]', 'A', 'ROW_NUMBER() 함수는 각 행에 고유한 번호를 부여합니다.'),
    (123, 3, 1, 63, '다음 SQL 쿼리에서 LAG() 함수의 역할은 무엇인가요? SELECT employee_id, salary, LAG(salary, 1) OVER (ORDER BY salary DESC) AS previous_salary FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 직원의 급여를 계산한다."}, {"id": "B", "text": "기존 직원의 급여를 비교한다."}, {"id": "C", "text": "이전 행의 급여 값을 참조한다."}, {"id": "D", "text": "급여의 총합을 계산한다."}]', 'C', 'LAG() 함수는 이전 행의 급여 값을 참조하여 보여줍니다.'),
    (124, 3, 1, 64, 'ROW_NUMBER()와 RANK()의 주요 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ROW_NUMBER는 중복된 값에 대해 고유 번호를 부여한다."}, {"id": "B", "text": "RANK는 중복되는 값에 대해 동일한 순위를 부여한다."}, {"id": "C", "text": "ROW_NUMBER는 동점인 경우 건너뛰는 순위를 제공한다."}, {"id": "D", "text": "RANK는 항상 연속된 순위를 제공한다."}]', '["A", "B"]', 'ROW_NUMBER()는 중복된 값에 대해 고유 번호를 부여하고, RANK()는 동일한 값에 동일한 순위를 부여합니다.'),
    (125, 3, 1, 65, '다음 SQL 쿼리에서 ''rank'' 열은 어떤 값을 나타내는가? SELECT employee_id, salary, ROW_NUMBER() OVER (ORDER BY salary DESC) AS rank FROM employees;', 'SHORT_ANSWER', NULL, '급여에 따라 매겨진 직원의 순위', '''rank'' 열은 급여를 기준으로 매겨진 직원의 순위를 나타냅니다.'),
    (126, 3, 1, 66, '다음 SQL 구문을 통해 어떤 작업을 수행했는가? `SELECT * FROM users WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "id가 1인 사용자 정보를 락을 걸고 조회한다."}, {"id": "B", "text": "모든 사용자의 정보를 조회한다."}, {"id": "C", "text": "id가 1인 사용자 정보를 삭제한다."}, {"id": "D", "text": "id가 1인 사용자 정보를 업데이트한다."}]', 'A', 'FOR UPDATE는 id가 1인 사용자 정보를 락을 걸고 조회하는 명령이다.'),
    (127, 3, 1, 67, '트랜잭션의 시작을 나타내는 SQL 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'BEGIN', '트랜잭션의 시작은 BEGIN 명령어로 나타낸다.'),
    (128, 3, 1, 68, '다음 SQL 구문에서 락을 걸지를 알고 싶다: `UPDATE accounts SET balance = balance - 100 WHERE id = 1;` 이 SQL 구문에 FOR UPDATE를 추가하면 어떻게 되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "락을 걸고 업데이트하지 않는다."}, {"id": "B", "text": "락을 걸어 동시에 다른 트랜잭션에서 접근을 차단한다."}, {"id": "C", "text": "업데이트를 무효화한다."}, {"id": "D", "text": "업데이트가 바로 실행된다."}]', 'B', 'FOR UPDATE를 추가하면 해당 행에 락이 걸려 다른 트랜잭션이 접근할 수 없다.'),
    (129, 3, 1, 69, 'SQL에서 트랜잭션의 상태를 확인하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SHOW TRANSACTIONS;"}, {"id": "B", "text": "SELECT @@autocommit;"}, {"id": "C", "text": "SHOW STATUS;"}, {"id": "D", "text": "ROLLBACK;"}]', '["B", "C"]', '트랜잭션의 상태를 확인하기 위해 SELECT @@autocommit;와 SHOW STATUS;를 사용할 수 있다.'),
    (130, 3, 1, 70, 'SQL에서 COALESCE 함수의 역할은 무엇인가요? 예시: SELECT COALESCE(column_name, ''default_value'') FROM table_name; 이때 column_name이 NULL일 경우 무엇이 반환되나요?', 'SHORT_ANSWER', NULL, '''default_value''', 'COALESCE 함수는 인자로 받은 값 중 NULL이 아닌 첫 번째 값을 반환하기 때문에, column_name이 NULL일 경우 ''default_value''를 반환합니다.'),
    (131, 3, 1, 71, 'IFNULL 함수의 사용 예시로 알맞은 코드는 무엇인가요? 
SELECT IFNULL(column_name, ''N/A'') FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "column_name이 NULL일 경우 ''N/A''가 반환된다."}, {"id": "B", "text": "column_name이 NULL일 경우 NULL이 반환된다."}, {"id": "C", "text": "column_name이 NULL일 경우 column_name의 값을 반환한다."}, {"id": "D", "text": "column_name이 NULL일 경우 에러가 발생한다."}]', 'A', 'IFNULL 함수는 첫 번째 인자가 NULL일 경우 두 번째 인자를 반환하므로, column_name이 NULL일 경우 ''N/A''가 반환됩니다.'),
    (132, 3, 1, 72, '다음 SQL 쿼리에서 COALESCE의 사용으로 예상되는 결과는 무엇인가요? 
SELECT COALESCE(NULL, ''Hello'', ''World'');', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''Hello''"}, {"id": "B", "text": "''World''"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "''Hello World''"}]', 'A', 'COALESCE는 NULL이 아닌 첫 번째 값을 반환하므로, ''Hello''가 반환됩니다.'),
    (133, 3, 1, 73, 'NULL 값을 다루기 위해 COALESCE와 IFNULL을 모두 사용할 수 있습니다. 올바른 사용 예시를 모두 고르세요. 
SELECT COALESCE(column_name, ''default_value''), IFNULL(column_name, ''N/A'') FROM table_name;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "올바른 사용 예시이다."}, {"id": "B", "text": "COALESCE는 첫 번째 인자에 NULL이 아닌 값이 와야 한다."}, {"id": "C", "text": "IFNULL은 두 개의 인자가 필요하다."}, {"id": "D", "text": "둘 다 NULL 값을 처리하는 함수이다."}]', '["A", "C", "D"]', 'A는 맞고, B는 COALESCE가 NULL을 허용하므로 틀림, C는 IFNULL이 두 개의 인자를 필요로 하므로 맞으며, D는 둘 다 NULL 값을 처리하는 함수이므로 맞습니다.'),
    (134, 3, 1, 74, '다음 SQL 쿼리의 결과로 출력될 수 있는 데이터의 형식은 무엇인가요? 
SELECT a.name, a.age
FROM users a
INNER JOIN orders b ON a.id = b.user_id
WHERE b.amount > (
    SELECT AVG(amount)
    FROM orders
);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이름과 나이가 포함된 테이블 형태의 결과"}, {"id": "B", "text": "사용자 ID와 주문 금액의 리스트"}, {"id": "C", "text": "주문 수량의 평균값"}, {"id": "D", "text": "오류가 발생하여 결과 없음"}]', 'A', 'INNER JOIN을 사용하여 이름과 나이를 출력하기 때문에 결과는 이름과 나이가 포함된 테이블 형태입니다.'),
    (135, 3, 1, 75, '다음 SQL 쿼리에서 ''______'' 부분에 들어갈 올바른 SQL 키워드는 무엇인가요? 
SELECT * FROM table1 ______ table2 ON table1.id = table2.id;', 'SHORT_ANSWER', NULL, 'JOIN', 'table1과 table2를 연결하기 위해 JOIN 키워드를 사용해야 합니다.'),
    (136, 3, 1, 76, 'LEFT JOIN의 특징으로 맞는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "오른쪽 테이블의 모든 데이터만 반환한다."}, {"id": "B", "text": "왼쪽 테이블의 모든 데이터와 일치하는 오른쪽 테이블의 데이터를 반환한다."}, {"id": "C", "text": "두 테이블의 공통 데이터만 반환한다."}, {"id": "D", "text": "모든 데이터가 중복되어 반환된다."}]', 'B', 'LEFT JOIN은 왼쪽 테이블의 모든 데이터와 일치하는 오른쪽 테이블의 데이터를 반환합니다.'),
    (137, 3, 1, 77, '서브쿼리가 사용될 수 있는 경우에 대한 설명으로 맞는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대값을 찾을 때"}, {"id": "B", "text": "데이터를 정렬할 때"}, {"id": "C", "text": "조건에 따른 필터링을 할 때"}, {"id": "D", "text": "테이블을 생성할 때"}]', '["A", "C"]', '서브쿼리는 주로 최대값, 최소값 등의 집계 결과를 찾거나 조건에 따른 데이터 필터링에 사용됩니다.'),
    (138, 3, 1, 78, '다음 중 SQL에서 트랜잭션을 시작하는 명령어는 무엇인가요? 

1. COMMIT
2. ROLLBACK
3. BEGIN
4. SELECT', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "COMMIT"}, {"id": "B", "text": "ROLLBACK"}, {"id": "C", "text": "BEGIN"}, {"id": "D", "text": "SELECT"}]', 'C', '트랜잭션을 시작하는 명령어는 BEGIN입니다.'),
    (139, 3, 1, 79, '다음 SQL 문에서 FOR UPDATE의 역할은 무엇인가요? 

SELECT * FROM products WHERE id = 10 FOR UPDATE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 삭제한다."}, {"id": "B", "text": "다른 트랜잭션의 접근을 막는다."}, {"id": "C", "text": "데이터를 조회한다."}, {"id": "D", "text": "트랜잭션을 시작한다."}]', 'B', 'FOR UPDATE 문은 다른 트랜잭션이 해당 데이터에 접근하지 못하게 락을 겁니다.'),
    (140, 3, 1, 80, '다음 빈칸을 채우세요: 

트랜잭션이 성공적으로 완료되면 __________ 명령어를 사용하여 변경 사항을 확정합니다.', 'SHORT_ANSWER', NULL, 'COMMIT', '트랜잭션이 성공적으로 완료된 후 COMMIT 명령어를 사용하여 변경 사항을 확정합니다.'),
    (141, 3, 1, 81, '다음 중 트랜잭션의 ACID 속성에 포함되지 않는 것은 무엇인가요? (복수 선택 가능)

1. 원자성
2. 일관성
3. 격리성
4. 예외성', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "원자성"}, {"id": "B", "text": "일관성"}, {"id": "C", "text": "격리성"}, {"id": "D", "text": "예외성"}]', '["D"]', 'ACID 속성에는 원자성, 일관성, 격리성이 포함되며 예외성은 포함되지 않습니다.'),
    (142, 3, 1, 82, '다음 SQL 쿼리를 실행했을 때 출력되는 등급은 무엇인가요?

SELECT name, score,
CASE
    WHEN score >= 90 THEN ''A''
    WHEN score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    ELSE ''F''
END AS grade
FROM students;

여기서 students 테이블의 score가 85인 학생의 등급은?', 'SHORT_ANSWER', NULL, 'B', 'score가 85이므로, 80 이상 90 미만에 해당하여 B등급입니다.'),
    (143, 3, 1, 83, '다음 SQL 구문에서 빈칸에 들어갈 적절한 SQL 키워드는 무엇인가요?

SELECT name, score,
CASE
    WHEN score >= 90 THEN ''A''
    _____ score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    ELSE ''F''
END AS grade
FROM students;', 'SHORT_ANSWER', NULL, 'WHEN', '각 조건을 정의할 때 ''WHEN'' 키워드를 사용해야 합니다.'),
    (144, 3, 1, 84, '다음 중 SQL의 CASE WHEN 구문에서 올바른 사용법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CASE WHEN 조건 THEN 결과 END"}, {"id": "B", "text": "CASE 조건 THEN 결과 WHEN 조건 END"}, {"id": "C", "text": "CASE WHEN 조건 END THEN 결과"}, {"id": "D", "text": "CASE 결과 WHEN 조건 THEN END"}]', 'A', 'CASE WHEN 구문의 올바른 형식은 ''CASE WHEN 조건 THEN 결과 END''입니다.'),
    (145, 3, 1, 85, '다음 SQL 쿼리를 통해 얻고자 하는 결과와 일치하는 조건이 모두 무엇인지 선택하세요.

SELECT name, score,
CASE
    WHEN score >= 90 THEN ''A''
    WHEN score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    ELSE ''F''
END AS grade
FROM students;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "조건: score >= 90"}, {"id": "B", "text": "조건: score < 70"}, {"id": "C", "text": "조건: score >= 80"}, {"id": "D", "text": "조건: score = 75"}]', '["A", "B", "C"]', '조건 A, B, C는 CASE WHEN 문에서 사용할 수 있는 조건입니다.'),
    (146, 3, 1, 86, '다음 SQL 쿼리의 결과는 무엇인가요? SELECT COALESCE(NULL, ''hello'', ''world'');', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "hello"}, {"id": "B", "text": "world"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "hello world"}]', 'A', 'COALESCE 함수는 NULL이 아닌 첫 번째 인수를 반환하므로 ''hello''가 결과입니다.'),
    (147, 3, 1, 87, '다음 SQL 쿼리에서 NULL을 다른 값으로 대체하는 올바른 SQL 문은 무엇인가요? SELECT IFNULL(column_name, ''N/A'') FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL을 ''N/A''로 대체"}, {"id": "B", "text": "NULL을 0으로 대체"}, {"id": "C", "text": "NULL을 column_name으로 대체"}, {"id": "D", "text": "NULL을 ''default''로 대체"}]', 'A', 'IFNULL 함수는 첫 번째 인수가 NULL이면 두 번째 인수를 반환하므로 ''N/A''로 대체됩니다.'),
    (148, 3, 1, 88, '다음 코드에서 빈칸에 들어갈 적절한 SQL 집계 함수는 무엇인가요? SELECT ______(column_name) FROM table_name;', 'SHORT_ANSWER', NULL, 'SUM 또는 AVG 또는 COUNT', '빈칸에는 SUM, AVG, COUNT 등과 같은 집계 함수가 들어갈 수 있습니다.'),
    (149, 3, 1, 89, '다음 SQL 쿼리에서 COALESCE 함수를 사용한 올바른 예시는 무엇인가요? SELECT COALESCE(column1, column2, ''default'') FROM table_name;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "column1이 NULL이면 column2 반환"}, {"id": "B", "text": "column2가 NULL일 경우 ''default'' 반환"}, {"id": "C", "text": "column1과 column2 모두 NULL일 경우 ''default'' 반환"}, {"id": "D", "text": "column1이 NULL이면 ''default'' 반환"}]', '["A", "C"]', 'COALESCE 함수는 NULL이 아닐 경우 첫 번째 인수를 반환하며, 모든 인수가 NULL일 경우 마지막 인수를 반환합니다.'),
    (150, 3, 1, 90, 'IFNULL 함수의 일반적인 사용 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NULL 값을 다른 값으로 대체하기 위해', 'IFNULL 함수는 NULL인 경우 지정된 다른 값으로 대체하는 데 사용됩니다.'),
    (151, 3, 1, 91, '다음 SQL 코드에서 CTE의 정의는 무엇인가요? 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)', 'SHORT_ANSWER', NULL, 'CTE는 직원 계층 구조를 재귀적으로 조회하기 위한 쿼리입니다.', 'CTE는 Common Table Expression의 약자로, 이 경우 직원 계층 구조를 재귀적으로 정의하고 조회합니다.'),
    (152, 3, 1, 92, '위 쿼리에서 ''UNION ALL''의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 결과를 포함하여 두 쿼리의 결과를 결합한다."}, {"id": "B", "text": "중복된 결과를 제외하고 두 쿼리의 결과를 결합한다."}, {"id": "C", "text": "CTE의 정의를 마친다는 의미이다."}, {"id": "D", "text": "재귀 쿼리를 종료시키는 역할을 한다."}]', 'A', '''UNION ALL''은 중복된 값을 포함하여 두 쿼리의 결과를 결합합니다.'),
    (153, 3, 1, 93, '빈칸을 채우세요: CTE는 SQL에서 _________을 제공하는 구조적 방법입니다.', 'SHORT_ANSWER', NULL, '명명된 쿼리', 'CTE는 명명된 쿼리를 정의하여 쿼리의 가독성을 향상시킵니다.'),
    (154, 3, 1, 94, 'CTE를 사용할 때, 다음 중 어떤 조건이 필요합니까? (복수 정답 가능)
1. 재귀 쿼리는 반드시 UNION ALL을 포함해야 한다.
2. 쿼리는 WITH 키워드로 시작해야 한다.
3. CTE는 단일 쿼리에서만 사용할 수 있다.
4. CTE는 다른 CTE를 참조할 수 있다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["B", "D"]', 'CTE는 WITH 키워드로 시작해야 하고, 다른 CTE를 참조할 수 있습니다. 재귀 쿼리는 UNION ALL을 사용할 수 있지만 필수 조건은 아닙니다.'),
    (155, 3, 1, 95, 'CTE를 사용하여 직원의 계층 구조를 재귀적으로 조회할 때, 시작 조건은 무엇인가요?', 'SHORT_ANSWER', NULL, 'ManagerID가 NULL인 직원', '최고 경영자(ManagerID가 NULL인 직원)를 시작 조건으로 하여 계층 구조를 조회합니다.'),
    (156, 3, 1, 96, '다음 SQL 쿼리의 실행 계획을 확인하기 위해 사용해야 하는 키워드는 무엇인가? `SELECT * FROM employees WHERE department_id = 5;`', 'SHORT_ANSWER', NULL, 'EXPLAIN', '실행 계획을 확인하기 위해서는 EXPLAIN 키워드를 사용해야 합니다.'),
    (157, 3, 1, 97, '다음 SQL 구문에서 빈칸에 들어갈 알맞은 단어는 무엇인가? `CREATE INDEX index_name ON table_name (____);`', 'SHORT_ANSWER', NULL, 'column_name', '인덱스를 생성할 때 특정 열의 이름을 지정해야 하기 때문입니다.'),
    (158, 3, 1, 98, '인덱스 활용의 장점으로 옳은 것은? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 조회 속도가 빨라진다."}, {"id": "B", "text": "데이터 삽입 성능이 향상된다."}, {"id": "C", "text": "정렬 성능이 좋아진다."}, {"id": "D", "text": "인덱스가 항상 필요한 것이 아니다."}]', '["A", "C", "D"]', '인덱스는 조회 속도를 개선하고, 정렬 성능을 향상시킬 수 있지만, 데이터 삽입 성능은 오히려 저하될 수 있습니다.'),
    (159, 3, 1, 99, '아래 SQL 문이 올바른 인덱스 생성 구문인가? `CREATE INDEX idx_department ON employees (department_name);`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "예, 올바른 구문입니다."}, {"id": "B", "text": "아니요, 테이블 이름이 잘못되었습니다."}, {"id": "C", "text": "아니요, 열 이름이 잘못되었습니다."}, {"id": "D", "text": "예, 하지만 인덱스 이름이 중복됩니다."}]', 'A', '해당 SQL 문은 올바른 인덱스 생성 구문입니다.'),
    (160, 3, 1, 100, 'SQL 쿼리를 최적화하기 위해 가장 먼저 확인해야 하는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 크기"}, {"id": "B", "text": "인덱스의 유무"}, {"id": "C", "text": "쿼리 구조"}, {"id": "D", "text": "모든 옵션 확인"}]', 'B', '인덱스의 유무는 쿼리 성능에 큰 영향을 미치므로, 이를 먼저 확인해야 합니다.'),
    (161, 3, 1, 101, '다음 SQL 구문에서 ''total_sales''는 무엇을 나타내나요? 

 SELECT category, SUM(sales) as total_sales 
 FROM sales_data 
 GROUP BY category 
 HAVING SUM(sales) > 1000;', 'SHORT_ANSWER', NULL, '판매량의 총합', '''total_sales''는 각 카테고리의 판매량 총합을 의미합니다.'),
    (162, 3, 1, 102, '다음 SQL 쿼리에서 사용할 수 없는 집계 함수는 무엇인가요? 

 SELECT category, COUNT(*) as total_count 
 FROM sales_data 
 GROUP BY category 
 HAVING total_count > 10;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "COUNT"}, {"id": "B", "text": "AVG"}, {"id": "C", "text": "SUM"}, {"id": "D", "text": "FILTER"}]', 'D', '''FILTER''는 집계 함수가 아닙니다.'),
    (163, 3, 1, 103, '‘HAVING’ 절을 사용할 때 올바른 조건은 무엇인가요? 

 SELECT category, SUM(sales) as total_sales 
 FROM sales_data 
 GROUP BY category 
 HAVING __________;', 'SHORT_ANSWER', NULL, '조건문(예: SUM(sales) > 1000)', 'HAVING 절에는 집계된 결과에 대한 조건문이 와야 합니다.'),
    (164, 3, 1, 104, '다음 SQL 쿼리에 대한 올바른 결과를 선택하세요: 

 SELECT category, COUNT(*) as total_count 
 FROM sales_data 
 GROUP BY category 
 HAVING COUNT(*) > 5;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "카테고리별 데이터 개수"}, {"id": "B", "text": "1000 이하의 카테고리"}, {"id": "C", "text": "5개 초과의 카테고리"}, {"id": "D", "text": "모든 카테고리"}]', '["A", "C"]', '이 쿼리는 카테고리별 데이터 개수가 5개 초과인 카테고리의 개수를 세는 쿼리입니다.'),
    (165, 3, 1, 105, '다음 SQL 쿼리의 목적은 무엇인가요? 

 SELECT product_id, AVG(price) as average_price 
 FROM products 
 GROUP BY product_id 
 HAVING AVG(price) > 20;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "평균 가격이 20 이하인 제품 찾기"}, {"id": "B", "text": "평균 가격이 20 초과인 제품 찾기"}, {"id": "C", "text": "모든 제품의 평균 가격 찾기"}, {"id": "D", "text": "제품 개수 세기"}]', 'B', '이 쿼리는 평균 가격이 20을 초과하는 제품을 찾는 것입니다.'),
    (166, 3, 1, 106, '다음 SQL 문장은 무엇을 수행하는가? CREATE INDEX idx_employee_name ON employees(name);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "employees 테이블의 name 열에 인덱스를 생성한다."}, {"id": "B", "text": "employees 테이블을 삭제한다."}, {"id": "C", "text": "name 열의 모든 데이터를 업데이트 한다."}, {"id": "D", "text": "새로운 employees 테이블을 생성한다."}]', 'A', '이 SQL 문장은 employees 테이블의 name 열에 인덱스를 생성하여 검색 성능을 향상시킨다.'),
    (167, 3, 1, 107, '다음 SQL 문장을 실행했을 때의 실행 계획을 얻기 위해 어떤 명령어를 사용해야 하는가? SELECT * FROM employees WHERE name = ''John'';', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하여 쿼리의 실행 계획을 확인할 수 있다.'),
    (168, 3, 1, 108, '다음 코드의 빈칸을 채우시오: CREATE _____ idx_employee_age ON employees(age);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "INDEX"}, {"id": "B", "text": "TABLE"}, {"id": "C", "text": "VIEW"}, {"id": "D", "text": "COLUMN"}]', 'A', '인덱스를 생성하기 위해서는 CREATE INDEX 문법을 사용해야 한다.'),
    (169, 3, 1, 109, '인덱스와 관련된 다음 설명 중 올바른 것을 모두 고르시오: 1) 인덱스는 쿼리 성능을 향상시킬 수 있다. 2) 인덱스는 데이터 삽입 시 성능을 저하시킬 수 있다. 3) 모든 컬럼에 인덱스를 생성해야 한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "1과 2"}]', '["A", "B", "D"]', '1번과 2번은 인덱스의 특성을 올바르게 설명하고 있으며, 3번은 모든 컬럼에 인덱스를 생성할 필요가 없다는 점에서 잘못된 설명이다.'),
    (170, 3, 1, 110, '다음 SQL 쿼리의 결과로 반환되는 값은 무엇인가?
SELECT COALESCE(NULL, ''hello'', ''world'') AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''hello''"}, {"id": "B", "text": "''world''"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "''default''"}]', 'A', 'COALESCE 함수는 첫 번째 NULL이 아닌 값을 반환하므로 ''hello''가 출력된다.'),
    (171, 3, 1, 111, 'IFNULL(column_name, ''default_value'') 함수의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL 값을 반환한다."}, {"id": "B", "text": "NULL이 아닐 경우 값을 반환한다."}, {"id": "C", "text": "NULL일 경우 대체 값을 반환한다."}, {"id": "D", "text": "모든 값을 반환한다."}]', 'C', 'IFNULL 함수는 첫 번째 인자가 NULL일 경우 두 번째 인자를 반환한다.'),
    (172, 3, 1, 112, '다음 코드에서 ''result'' 컬럼의 값은 무엇인가?
SELECT IFNULL(NULL, 100) AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL"}, {"id": "B", "text": "0"}, {"id": "C", "text": "100"}, {"id": "D", "text": "''default''"}]', 'C', 'IFNULL 함수를 사용하였고 첫 번째 인자가 NULL이므로 ''100''이 반환된다.'),
    (173, 3, 1, 113, '다음 SQL 쿼리에 대해 올바른 결과를 모두 고르시오.
SELECT COUNT(*) FROM table_name WHERE COALESCE(column_name, ''No Data'') = ''No Data'';', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NULL 값이 있는 행의 수"}, {"id": "B", "text": "column_name이 ''No Data''인 행의 수"}, {"id": "C", "text": "모든 행의 수"}, {"id": "D", "text": "0"}]', '["A", "B"]', 'COALESCE 함수로 NULL 값을 ''No Data''로 처리하여, ''No Data''의 개수를 세게 된다.'),
    (174, 3, 1, 114, 'COALESCE 함수의 사용 예시를 적으시오.', 'SHORT_ANSWER', NULL, 'SELECT COALESCE(column_name, ''default_value'') FROM table_name;', 'COALESCE 함수를 사용하여 NULL 값을 처리하는 예시이다.'),
    (175, 3, 1, 115, '위의 SQL 쿼리에서 ''AVG(salary)''의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '부서별 평균 급여를 계산한다.', '''AVG(salary)'' 함수는 각 부서의 급여의 평균을 계산해준다.'),
    (176, 3, 1, 116, '다음 중 ''HAVING'' 절을 사용한 SQL 쿼리의 장점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''GROUP BY'' 결과에 조건을 적용할 수 있다."}, {"id": "B", "text": "''WHERE'' 절보다 더 많은 데이터를 필터링한다."}, {"id": "C", "text": "서브쿼리를 필요로 한다."}, {"id": "D", "text": "데이터베이스의 성능을 향상시킨다."}]', 'A', '''HAVING'' 절은 ''GROUP BY'' 결과에 조건을 적용하는 데 사용된다.'),
    (177, 3, 1, 117, '다음 SQL 쿼리에서 빈칸에 들어갈 적절한 키워드는 무엇인가요? ''SELECT department, COUNT(*) FROM employees ______ department;''', 'SHORT_ANSWER', NULL, 'GROUP BY', '''GROUP BY'' 키워드를 사용하여 부서별로 행을 그룹화할 수 있다.'),
    (178, 3, 1, 118, '다음 중 ''GROUP BY''와 ''HAVING''을 올바르게 사용하는 SQL 쿼리의 예는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT city, COUNT(*) FROM customers GROUP BY city HAVING COUNT(*) > 10;"}, {"id": "B", "text": "SELECT name, SUM(sales) FROM orders WHERE SUM(sales) > 1000 GROUP BY name;"}, {"id": "C", "text": "SELECT product, MAX(price) FROM products GROUP BY product HAVING MAX(price) < 200;"}, {"id": "D", "text": "SELECT supplier, AVG(rating) FROM suppliers HAVING rating > 4 GROUP BY supplier;"}]', '["A", "C"]', '''A''와 ''C''는 ''GROUP BY''와 ''HAVING''을 적절히 사용한 예이다.'),
    (179, 3, 1, 119, 'SQL에서 ''HAVING'' 절은 언제 사용되나요?', 'SHORT_ANSWER', NULL, '집계 함수의 결과에 조건을 적용할 때 사용된다.', '''HAVING'' 절은 ''GROUP BY''로 그룹화된 데이터를 필터링할 때 사용된다.'),
    (180, 3, 1, 120, '다음 SQL 쿼리의 출력 결과로 가장 알맞은 것은 무엇인가요?

SELECT name,
       CASE 
           WHEN score >= 90 THEN ''A''
           WHEN score >= 80 THEN ''B''
           WHEN score >= 70 THEN ''C''
           ELSE ''F''
       END AS grade
FROM students;

여기서 ''score''가 85인 경우의 출력은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "F"}]', 'B', '''score''가 85인 경우는 80 이상 90 미만이므로 ''B''가 출력됩니다.'),
    (181, 3, 1, 121, '다음 SQL 쿼리에서 빈칸에 들어갈 가장 적절한 것은 무엇인가요?

SELECT name,
       CASE 
           WHEN score >= _____ THEN ''A''
           WHEN score >= 80 THEN ''B''
           WHEN score >= 70 THEN ''C''
           ELSE ''F''
       END AS grade
FROM students;', 'SHORT_ANSWER', NULL, '90', 'A 학점을 부여하기 위한 점수 기준은 90 이상입니다.'),
    (182, 3, 1, 122, 'CASE WHEN을 사용하여 학생의 성적을 등급으로 변환하는 다른 방법이 있다면 어떤 것이 적절한가요?

(중복 선택 가능)
1. CASE WHEN을 사용하지 않고 IF 함수를 사용하는 것
2. SUBSTRING 함수를 사용하여 이름의 길이로 등급을 매기는 것
3. 여러 CASE WHEN을 중첩하여 사용할 수 있다.
4. 조건문을 사용하여 직접적으로 테이블을 수정하는 것', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["C"]', 'CASE WHEN을 중첩하여 사용하면 더 복잡한 조건을 처리할 수 있습니다.'),
    (183, 3, 1, 123, 'CASE WHEN 구문에서 ELSE 절을 생략할 수 있는 경우는 어떤 상황인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 조건이 충족될 때"}, {"id": "B", "text": "일부 조건이 충족되지 않을 때"}, {"id": "C", "text": "모든 가능한 경우를 다 처리할 때"}, {"id": "D", "text": "어떤 조건도 충족되지 않을 때"}]', 'C', '모든 가능한 경우를 다 처리할 수 있을 때 ELSE 절을 생략할 수 있습니다.'),
    (184, 3, 1, 124, '다음 SQL 쿼리에서 ''employee_hierarchy''는 어떤 기능을 수행하는가?

WITH RECURSIVE employee_hierarchy AS (
    SELECT employee_id, manager_id, name
    FROM employees
    WHERE manager_id IS NULL
    UNION ALL
    SELECT e.employee_id, e.manager_id, e.name
    FROM employees e
    INNER JOIN employee_hierarchy eh ON e.manager_id = eh.employee_id
)
SELECT * FROM employee_hierarchy;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원 계층 구조를 생성한다."}, {"id": "B", "text": "직원의 평균 연봉을 계산한다."}, {"id": "C", "text": "데이터베이스를 초기화한다."}, {"id": "D", "text": "직원 수를 세는 쿼리이다."}]', 'A', '''employee_hierarchy''는 직원의 계층 구조를 생성하는 데 사용된다.'),
    (185, 3, 1, 125, '재귀 CTE에서 UNION ALL의 역할은 무엇인가?

WITH RECURSIVE example AS (
    SELECT ...
    UNION ALL
    SELECT ...
)', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "기본 쿼리와 재귀 쿼리를 결합한다."}, {"id": "B", "text": "쿼리의 결과를 정렬한다."}, {"id": "C", "text": "중복된 결과를 제거한다."}, {"id": "D", "text": "조건을 설정한다."}]', 'A', 'UNION ALL은 기본 쿼리와 재귀 쿼리의 결과를 합치는 역할을 한다.'),
    (186, 3, 1, 126, '다음 빈칸을 채우시오: CTE는 _____를 통해 임시 결과 집합을 정의하는 데 사용된다.

WITH CTE_name AS (...)', 'SHORT_ANSWER', NULL, '쿼리', 'CTE는 쿼리를 통해 임시 결과 집합을 정의하는 데 사용된다.'),
    (187, 3, 1, 127, '재귀 CTE를 사용할 때 주의해야 할 점은 무엇인가? (복수 선택 가능)

WITH RECURSIVE example AS (
    SELECT ...
    UNION ALL
    SELECT ...
)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "무한 루프를 방지해야 한다."}, {"id": "B", "text": "적절한 종료 조건을 설정해야 한다."}, {"id": "C", "text": "쿼리 성능을 항상 최적화해야 한다."}, {"id": "D", "text": "사용자 권한을 확인해야 한다."}]', '["A", "B"]', '재귀 CTE는 무한 루프를 방지하고 적절한 종료 조건을 설정해야 한다.'),
    (188, 3, 1, 128, '다음 SQL 코드에서 ROW_NUMBER() 함수는 무엇을 수행하는가? SELECT employee_id, salary, ROW_NUMBER() OVER (ORDER BY salary DESC) AS row_num FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 직원에게 급여에 따라 내림차순으로 순번을 매긴다."}, {"id": "B", "text": "각 직원의 급여를 더한다."}, {"id": "C", "text": "각 직원의 급여를 오름차순으로 정렬한다."}, {"id": "D", "text": "각 직원의 급여를 평균낸다."}]', 'A', 'ROW_NUMBER() 함수는 결과 집합에서 각 행에 고유한 순위를 매기며, 여기서는 급여를 기준으로 내림차순으로 순번을 매긴다.'),
    (189, 3, 1, 129, '다음 SQL 코드의 결과에서 RANK() 함수는 어떤 역할을 하는가? SELECT employee_id, salary, RANK() OVER (ORDER BY salary DESC) AS rank_num FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 직원에게 동일한 급여를 부여한다."}, {"id": "B", "text": "급여에 따라 순위를 매기고, 동일 급여에 대해 같은 순위를 부여한다."}, {"id": "C", "text": "직원의 급여의 최대값을 계산한다."}, {"id": "D", "text": "직원의 급여를 내림차순으로 정렬한다."}]', 'B', 'RANK() 함수는 급여에 따라 순위를 매기고, 동일 급여를 가진 직원들에게 동일한 순위를 부여하며, 다음 순위는 건너뛰기 때문에 유용하다.'),
    (190, 3, 1, 130, '다음 SQL 코드에서 LAG() 함수는 어떤 값을 반환하는가? LAG(salary, 1) OVER (ORDER BY salary) AS prev_salary', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 행의 급여."}, {"id": "B", "text": "이전 행의 급여."}, {"id": "C", "text": "다음 행의 급여."}, {"id": "D", "text": "급여의 평균값."}]', 'B', 'LAG() 함수는 현재 행의 이전 행의 값을 반환하며, 여기서는 이전 직원의 급여를 반환한다.'),
    (191, 3, 1, 131, 'ROW_NUMBER(), RANK(), LAG() 함수의 기능을 복수 선택하시오: 1. ROW_NUMBER()는 각 행에 고유한 번호를 부여한다. 2. RANK()는 동일한 값에 대해 동일한 순위를 매긴다. 3. LAG()는 이후 행의 값을 조회한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 2"}, {"id": "B", "text": "2, 3"}, {"id": "C", "text": "1, 3"}, {"id": "D", "text": "1, 2, 3"}]', '["A", "B"]', 'ROW_NUMBER()는 각 행에 고유한 번호를 부여하고, RANK()는 동일한 값에 대해 동일한 순위를 매긴다. LAG()는 이전 행의 값을 조회하기 때문에 3의 설명은 틀리다.'),
    (192, 3, 1, 132, 'SQL에서 LAG() 함수의 일반적인 사용 사례는 무엇인가?', 'SHORT_ANSWER', NULL, '이전 행의 데이터를 비교하기 위함', 'LAG() 함수는 특정 열의 이전 행의 값을 조회하여 데이터 분석 시 이전 값과의 비교를 용이하게 한다.'),
    (193, 3, 1, 133, '다음 SQL 쿼리의 목적은 무엇인가요? 
WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 직원의 정보를 가져온다."}, {"id": "B", "text": "직원과 그들의 상사 정보를 계층적으로 가져온다."}, {"id": "C", "text": "모든 상사의 정보를 가져온다."}, {"id": "D", "text": "직원 수를 계산한다."}]', 'B', '이 쿼리는 최상위 관리자와 해당 관리자의 하위 직원들을 계층적으로 보여줍니다.'),
    (194, 3, 1, 134, '다음 쿼리에서 빈칸에 무엇이 들어가야 할까요? 
SELECT * FROM EmployeeCTE WHERE __________;', 'SHORT_ANSWER', NULL, 'EmployeeID = 1', 'EmployeeID가 1인 직원의 정보를 조회하기 위해 해당 조건을 추가해야 합니다.'),
    (195, 3, 1, 135, '다음 중 CTE의 주요 이점이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가독성을 높인다."}, {"id": "B", "text": "쿼리의 실행 속도를 항상 증가시킨다."}, {"id": "C", "text": "재사용이 가능하다."}, {"id": "D", "text": "계층 구조를 쉽게 처리한다."}]', 'B', 'CTE는 가독성을 높이고 재사용할 수 있지만, 실행 속도를 항상 증가시키는 것은 아닙니다.'),
    (196, 3, 1, 136, '재귀 쿼리에서 반드시 포함되어야 하는 두 가지 절은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT"}, {"id": "B", "text": "UNION ALL"}, {"id": "C", "text": "WITH RECURSIVE"}, {"id": "D", "text": "FROM"}]', '["B", "C"]', '재귀 쿼리를 작성하려면 UNION ALL과 WITH RECURSIVE를 반드시 포함해야 합니다.'),
    (197, 3, 1, 137, '다음 SQL 쿼리의 결과는 무엇인가요? `SELECT employees.name, departments.department_name FROM employees INNER JOIN departments ON employees.department_id = departments.id;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원 이름과 부서 이름의 조합"}, {"id": "B", "text": "직원 이름만"}, {"id": "C", "text": "부서 이름만"}, {"id": "D", "text": "부서별 직원 수"}]', 'A', 'INNER JOIN을 사용하여 직원과 부서를 연결하므로, 직원 이름과 해당 부서 이름의 조합이 결과로 반환됩니다.'),
    (198, 3, 1, 138, '빈칸을 채우세요: `SELECT name FROM employees WHERE department_id IN (SELECT id FROM departments WHERE department_name = ''___'');`', 'SHORT_ANSWER', NULL, 'Sales', '서브쿼리는 ''Sales'' 부서의 ID를 가져오게 되어 해당 부서의 직원 이름을 반환합니다.'),
    (199, 3, 1, 139, 'JOIN의 종류 중 LEFT JOIN은 어떤 기능을 하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "왼쪽 테이블의 모든 행과 일치하는 오른쪽 테이블의 행을 반환"}, {"id": "B", "text": "오른쪽 테이블의 모든 행을 반환"}, {"id": "C", "text": "두 테이블의 일치하는 행만 반환"}, {"id": "D", "text": "왼쪽 테이블의 행만 반환"}]', 'A', 'LEFT JOIN은 왼쪽 테이블의 모든 행과 조건에 일치하는 오른쪽 테이블의 행을 반환합니다.'),
    (200, 3, 1, 140, 'INNER JOIN과 LEFT JOIN의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "INNER JOIN은 모든 일치하는 행을 반환한다."}, {"id": "B", "text": "LEFT JOIN은 왼쪽 테이블의 모든 행을 반환한다."}, {"id": "C", "text": "LEFT JOIN은 일치하지 않는 오른쪽 행은 NULL로 반환한다."}, {"id": "D", "text": "INNER JOIN은 NULL 값을 허용한다."}]', '["A", "B", "C"]', 'INNER JOIN은 모든 일치하는 행을 반환하고, LEFT JOIN은 왼쪽 테이블의 모든 행을 반환하며, 일치하지 않는 오른쪽 테이블의 행은 NULL로 반환됩니다.'),
    (201, 3, 1, 141, '위 SQL 쿼리에서 ''ManagerID''가 NULL인 직원은 누구를 의미하나요?', 'SHORT_ANSWER', NULL, '최고 관리자', '''ManagerID''가 NULL인 직원은 최고 관리자, 즉 하위 직원이 없는 직원입니다.'),
    (202, 3, 1, 142, '다음 SQL 쿼리에서 잘못된 부분은 무엇인가요? 

WITH RECURSIVE EmployeeHierarchy AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeHierarchy eh ON e.EmployeeID = eh.ManagerID
)
SELECT * FROM EmployeeHierarchy;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "INNER JOIN의 조건이 잘못되었다."}, {"id": "B", "text": "CTE의 이름이 잘못되었다."}, {"id": "C", "text": "SELECT 문이 잘못되었다."}, {"id": "D", "text": "모든 부분이 올바르다."}]', 'A', 'INNER JOIN의 조건에서 e.EmployeeID는 eh.ManagerID와 연결되어야 합니다.'),
    (203, 3, 1, 143, '아래 SQL 쿼리의 결과로 나올 수 있는 EmployeeID의 값들은 무엇인가요? 

WITH RECURSIVE EmployeeHierarchy AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeHierarchy eh ON e.ManagerID = eh.EmployeeID
)
SELECT * FROM EmployeeHierarchy;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "B", "C", "D"]', '모든 직원이 계층 구조에 나타날 수 있기 때문에 모든 EmployeeID가 표시될 수 있습니다.'),
    (204, 3, 1, 144, 'CTE에서 재귀 쿼리를 사용하기 위해서는 어떤 키워드를 사용해야 하나요?', 'SHORT_ANSWER', NULL, 'RECURSIVE', 'CTE에서 재귀 쿼리를 사용하기 위해서는 RECURSIVE 키워드를 사용해야 합니다.'),
    (205, 3, 1, 145, '다음 SQL 쿼리에서 CTE의 정의는 무엇인가요? 

WITH RECURSIVE CategoryTree AS (
    SELECT Id, Name, ParentId
    FROM Categories
    WHERE ParentId IS NULL
    UNION ALL
    SELECT c.Id, c.Name, c.ParentId
    FROM Categories c
    INNER JOIN CategoryTree ct ON ct.Id = c.ParentId
)
SELECT * FROM CategoryTree;', 'SHORT_ANSWER', NULL, 'CategoryTree', 'CTE의 이름은 ''CategoryTree''입니다.'),
    (206, 3, 1, 146, '위 쿼리에서 ParentId가 NULL인 조건은 무엇을 의미하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최상위 카테고리"}, {"id": "B", "text": "하위 카테고리"}, {"id": "C", "text": "모든 카테고리"}, {"id": "D", "text": "해당 쿼리와 관련 없음"}]', 'A', 'ParentId가 NULL인 카테고리는 최상위 카테고리를 의미합니다.'),
    (207, 3, 1, 147, '다음 쿼리의 결과는 무엇인가요? (빈칸에 들어갈 단어를 선택하세요)

SELECT * FROM Categories WHERE Id IN (SELECT Id FROM CategoryTree);

SELECT * FROM Categories WHERE ___;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ParentId IS NULL"}, {"id": "B", "text": "Id IN (SELECT Id FROM CategoryTree)"}, {"id": "C", "text": "Name LIKE ''A%''"}, {"id": "D", "text": "1=1"}]', 'B', '내부 쿼리에서 CategoryTree에 포함된 Id를 가진 카테고리를 선택합니다.'),
    (208, 3, 1, 148, '재귀 CTE에서 UNION ALL의 역할은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최상위 데이터를 선택한다."}, {"id": "B", "text": "하위 데이터를 결합한다."}, {"id": "C", "text": "서브 쿼리의 결과를 필터링한다."}, {"id": "D", "text": "결과를 정렬한다."}]', '["A", "B"]', 'UNION ALL은 최상위 데이터를 선택하고 하위 데이터를 결합하는 역할을 합니다.'),
    (209, 3, 1, 149, '다음 SQL 문에서 인덱스를 생성하는 올바른 문장은 무엇인가? 
`CREATE INDEX ____ ON employees (last_name);`', 'SHORT_ANSWER', NULL, 'idx_name', '인덱스 이름은 사용자가 원하는 이름으로 지정할 수 있으며, 일반적으로 ''idx_'' 접두어를 사용합니다.'),
    (210, 3, 1, 150, '다음 SQL 쿼리의 실행 계획을 확인하기 위해서 사용할 수 있는 명령어는 무엇인가? 
`____ SELECT * FROM employees WHERE last_name = ''Smith'';`', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하면 SQL 쿼리의 실행 계획을 볼 수 있습니다.'),
    (211, 3, 1, 151, '인덱스의 장점으로 설명되지 않는 것은 무엇인가? 
- A: 검색 속도 향상 
- B: 데이터 중복 증가 
- C: 쿼리 성능 개선 
- D: 테이블 정렬 지원', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "검색 속도 향상"}, {"id": "B", "text": "데이터 중복 증가"}, {"id": "C", "text": "쿼리 성능 개선"}, {"id": "D", "text": "테이블 정렬 지원"}]', 'B', '인덱스는 검색 속도와 쿼리 성능을 향상시키지만, 데이터 중복을 증가시키지는 않습니다.'),
    (212, 3, 1, 152, '다음 중 SQL 쿼리의 실행 계획을 개선하기 위한 방법으로 적절한 것은 무엇인가? (복수 선택 가능) 
- A: 인덱스 추가 
- B: 불필요한 데이터 제거 
- C: LEFT JOIN 대신 INNER JOIN 사용 
- D: WHERE 절 최적화', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인덱스 추가"}, {"id": "B", "text": "불필요한 데이터 제거"}, {"id": "C", "text": "LEFT JOIN 대신 INNER JOIN 사용"}, {"id": "D", "text": "WHERE 절 최적화"}]', '["A", "B", "C", "D"]', '모든 선택지는 실행 계획을 개선할 수 있는 방법입니다.'),
    (213, 3, 1, 153, '인덱스는 무엇을 개선하는 데 주로 사용됩니까?', 'SHORT_ANSWER', NULL, '검색 속도', '인덱스는 데이터베이스에서 데이터를 검색하는 속도를 개선하는 데 사용됩니다.'),
    (214, 3, 1, 154, '트랜잭션의 ACID 속성 중 원자성은 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '모든 작업이 성공하거나 실패해야 한다.', '원자성은 트랜잭션 내의 모든 작업이 완료되어야만 데이터베이스 상태가 변경되거나, 하나라도 실패하면 이전 상태로 되돌아가야 함을 의미한다.'),
    (215, 3, 1, 155, '다음 SQL 문에서 FOR UPDATE의 역할은 무엇인가?

SELECT * FROM accounts WHERE account_id = 1 FOR UPDATE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행을 수정할 수 있도록 락을 건다."}, {"id": "B", "text": "행을 삭제할 수 있도록 락을 건다."}, {"id": "C", "text": "행을 조회만 한다."}, {"id": "D", "text": "행을 복사한다."}]', 'A', 'FOR UPDATE는 해당 행에 대해 수정할 수 있도록 락을 걸어 다른 트랜잭션이 접근하지 못하도록 한다.'),
    (216, 3, 1, 156, 'FOR UPDATE를 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 일관성을 유지하기 위해"}, {"id": "B", "text": "쿼리 성능을 높이기 위해"}, {"id": "C", "text": "데이터를 영구적으로 삭제하기 위해"}, {"id": "D", "text": "데이터베이스를 백업하기 위해"}]', 'A', 'FOR UPDATE는 데이터의 일관성을 유지하기 위해 사용되며, 다른 트랜잭션이 해당 데이터를 수정하지 못하게 한다.'),
    (217, 3, 1, 157, '다음 중 트랜잭션을 동시에 실행할 때 발생할 수 있는 문제는 무엇인가요?

1. 더러운 읽기
2. 비반복 가능 읽기
3. 팬텀 읽기

이에 대한 답변을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "더러운 읽기"}, {"id": "B", "text": "비반복 가능 읽기"}, {"id": "C", "text": "팬텀 읽기"}, {"id": "D", "text": "모든 항목이 문제 없음"}]', '["A", "B", "C"]', '더러운 읽기, 비반복 가능 읽기, 팬텀 읽기는 모두 동시에 실행되는 트랜잭션에서 발생할 수 있는 문제들이다.'),
    (218, 3, 1, 158, '트랜잭션이 COMMIT되지 않은 상태에서 다른 트랜잭션이 같은 자원에 접근할 수 없도록 하기 위해 사용하는 SQL 문은 무엇인가요?', 'SHORT_ANSWER', NULL, 'FOR UPDATE', 'FOR UPDATE는 트랜잭션이 COMMIT되지 않은 상태에서 다른 트랜잭션이 같은 자원에 접근하지 못하도록 락을 건다.'),
    (219, 3, 1, 159, '다음 SQL 쿼리의 결과로 출력될 ''total_sales''의 의미는 무엇인가요? 

SELECT category, COUNT(*) as total_sales
FROM sales
GROUP BY category
HAVING COUNT(*) > 10;', 'SHORT_ANSWER', NULL, '각 카테고리의 판매 수', 'total_sales는 각 카테고리별 판매 수를 의미합니다.'),
    (220, 3, 1, 160, '다음 쿼리에서 위의 코드에서 수정해야 하는 부분은 무엇인가요? 

SELECT category, SUM(price) as total_revenue
FROM sales
GROUP BY category
HAVING total_revenue > 1000;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "HAVING 절은 집계 함수로 작성해야 한다."}, {"id": "B", "text": "SUM(price) 대신 COUNT(price)를 사용해야 한다."}, {"id": "C", "text": "total_revenue를 HAVING 절에서 사용할 수 없다."}, {"id": "D", "text": "GROUP BY 절에 price를 추가해야 한다."}]', 'C', 'HAVING 절에서는 집계 함수의 별칭(total_revenue)을 직접 사용할 수 없습니다.'),
    (221, 3, 1, 161, '다음 SQL 쿼리에서 GROUP BY 절이 어떤 데이터를 기반으로 그룹화하는지 설명하시오. 

SELECT category, COUNT(*) as total_sales
FROM sales
GROUP BY category;', 'SHORT_ANSWER', NULL, 'category', 'GROUP BY 절은 category를 기준으로 데이터를 그룹화합니다.'),
    (222, 3, 1, 162, '다음 SQL 구문에서 어떤 조건을 통해 출력 결과를 필터링하나요? 

SELECT category, COUNT(*) as total_sales
FROM sales
GROUP BY category
HAVING COUNT(*) > 10;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "총 판매 수가 10개 이상인 카테고리"}, {"id": "B", "text": "모든 카테고리"}, {"id": "C", "text": "판매 수가 10개 미만인 카테고리"}, {"id": "D", "text": "판매 수가 정확히 10인 카테고리"}]', '["A"]', 'HAVING 절은 총 판매 수가 10개 이상인 카테고리를 필터링합니다.'),
    (223, 3, 1, 163, 'GROUP BY를 사용할 때, 어떤 집계 함수를 사용할 수 있나요? 여러 개를 선택하시오. (복수 정답 가능)

SELECT category, ...
FROM sales
GROUP BY category;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "COUNT()"}, {"id": "B", "text": "SUM()"}, {"id": "C", "text": "AVG()"}, {"id": "D", "text": "LOWER()"}]', '["A", "B", "C"]', 'COUNT(), SUM(), AVG()는 GROUP BY 절과 함께 사용 가능한 집계 함수입니다.'),
    (224, 3, 1, 164, '다음 SQL 쿼리의 출력 예측: SELECT name, CASE WHEN score >= 60 THEN ''Pass'' ELSE ''Fail'' END AS result FROM students; 만약 score가 75일 경우, result는 무엇인가?', 'SHORT_ANSWER', NULL, 'Pass', 'score가 75이므로 60 이상으로 Pass를 반환합니다.'),
    (225, 3, 1, 165, '다음 SQL 쿼리에서 ''result'' 컬럼의 값은 무엇이 될까요? SELECT name, CASE WHEN age < 18 THEN ''Minor'' WHEN age BETWEEN 18 AND 65 THEN ''Adult'' ELSE ''Senior'' END AS result FROM users;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Minor"}, {"id": "B", "text": "Adult"}, {"id": "C", "text": "Senior"}, {"id": "D", "text": "Unknown"}]', 'B', 'age가 18과 65 사이일 경우 ''Adult''로 분류됩니다.'),
    (226, 3, 1, 166, '다음 SQL 쿼리를 완성하세요: SELECT name, CASE WHEN score >= 90 THEN ''A'' WHEN score >= 80 THEN ''B'' WHEN score >= 70 THEN ''C'' ELSE ''D'' END AS grade FROM students; 이 쿼리에서 score가 85일 경우 반환되는 grade는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "D"}]', 'B', 'score가 85이므로 ''B''를 반환합니다.'),
    (227, 3, 1, 167, '다음 SQL 쿼리의 사용 예에서 어떤 결과가 반환될까요? SELECT name, CASE WHEN status IN (''active'', ''pending'') THEN ''In Progress'' ELSE ''Completed'' END AS progress FROM tasks; (status가 ''active''일 경우)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "In Progress"}, {"id": "B", "text": "Completed"}, {"id": "C", "text": "Pending"}, {"id": "D", "text": "Unknown"}]', '["A"]', 'status가 ''active''이므로 ''In Progress''를 반환합니다.'),
    (228, 3, 1, 168, 'SQL의 CASE WHEN 문에서 기본값을 설정하는 키워드는 무엇인가?', 'SHORT_ANSWER', NULL, 'ELSE', 'CASE 문에서 기본값을 설정할 때는 ELSE 키워드를 사용합니다.'),
    (229, 3, 1, 169, '다음 SQL 쿼리는 어떤 결과를 반환합니까?

SELECT department, COUNT(*) as employee_count
FROM employees
GROUP BY department
HAVING COUNT(*) > 10;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원 수가 10명 이상인 부서와 직원 수"}, {"id": "B", "text": "모든 부서와 직원 수"}, {"id": "C", "text": "부서 이름만"}, {"id": "D", "text": "직원 수가 10명 이하인 부서"}]', 'A', 'HAVING 절은 조건을 추가하여 직원 수가 10명 이상인 부서만 결과로 보여줍니다.'),
    (230, 3, 1, 170, 'GROUP BY 절은 어떤 목적으로 사용됩니까?', 'SHORT_ANSWER', NULL, '데이터 집계를 위해 레코드를 그룹화하는 것', 'GROUP BY는 지정된 열을 기준으로 데이터를 그룹화하여 집계 결과를 제공합니다.'),
    (231, 3, 1, 171, '다음 SQL 쿼리를 완성하시오:

SELECT product_name, AVG(sales) as avg_sales
FROM products
GROUP BY product_name
HAVING ___;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AVG(sales) > 5000"}, {"id": "B", "text": "COUNT(*) > 0"}, {"id": "C", "text": "product_name IS NOT NULL"}, {"id": "D", "text": "SUM(sales) < 1000"}]', 'A', 'HAVING 절은 집계 함수의 결과에 조건을 추가합니다. 평균 매출이 5000보다 큰 제품을 찾는 쿼리입니다.'),
    (232, 3, 1, 172, '다음 중 GROUP BY와 HAVING이 동시에 사용될 수 있는 이유는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 그룹화하기 위해"}, {"id": "B", "text": "집계 결과에 조건을 추가하기 위해"}, {"id": "C", "text": "ORDER BY를 사용하기 위해"}, {"id": "D", "text": "모든 그룹을 반환하기 위해"}]', '["A", "B"]', 'GROUP BY는 데이터를 그룹화하고, HAVING은 집계 결과에 조건을 걸어 필터링하기 위해 사용됩니다.'),
    (233, 3, 1, 173, '다음 SQL 코드의 결과로 반환될 첫 번째 행의 EmployeeID는 무엇인가요?

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL  
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'SHORT_ANSWER', NULL, '첫 번째 관리자 ID', '첫 번째 관리자의 EmployeeID가 반환됩니다.'),
    (234, 3, 1, 174, '다음 SQL 문에서 CTE의 이름은 무엇인가요?

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EmployeeCTE"}, {"id": "B", "text": "Employees"}, {"id": "C", "text": "ManagerID"}, {"id": "D", "text": "Name"}]', 'A', 'CTE의 이름은 EmployeeCTE입니다.'),
    (235, 3, 1, 175, '재귀 CTE가 사용되는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스의 성능 향상"}, {"id": "B", "text": "정보의 계층적 구조 처리"}, {"id": "C", "text": "SQL 문법 단순화"}, {"id": "D", "text": "모든 쿼리의 결과를 결합하기 위해"}]', 'B', '재귀 CTE는 계층적 데이터를 처리하기 위해 사용됩니다.'),
    (236, 3, 1, 176, 'CTE의 주된 장점 중 하나는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리의 가독성 향상"}, {"id": "B", "text": "복잡한 SQL 선언 필요 없음"}, {"id": "C", "text": "일시적 테이블 사용 가능"}, {"id": "D", "text": "데이터베이스 크기 감소"}]', '["A", "B", "C"]', 'CTE는 쿼리의 가독성을 높이고 복잡한 SQL 선언을 필요로 하지 않으며, 일시적인 테이블을 생성하여 사용할 수 있는 장점이 있습니다.'),
    (237, 3, 1, 177, '다음 SQL 쿼리의 결과로 출력될 컬럼은 무엇인가요? SELECT a.id, a.name, b.department FROM employees a INNER JOIN departments b ON a.department_id = b.id WHERE a.salary > (SELECT AVG(salary) FROM employees);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "employees 테이블의 id와 name, departments 테이블의 department"}, {"id": "B", "text": "employees 테이블의 id, departments 테이블의 id"}, {"id": "C", "text": "employees 테이블의 name, departments 테이블의 id"}, {"id": "D", "text": "employees의 모든 컬럼"}]', 'A', '쿼리는 employees 테이블에서 id와 name, departments 테이블에서 department 컬럼을 선택합니다.'),
    (238, 3, 1, 178, '다음 SQL 쿼리에 대해 잘못된 부분을 고르세요: SELECT * FROM orders o LEFT JOIN customers c ON o.customer_id = c.id WHERE c.id IS NULL;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LEFT JOIN을 사용하고 있다."}, {"id": "B", "text": "WHERE 절이 잘못됐다."}, {"id": "C", "text": "FROM 절에 SQL 테이블명이 잘못됐다."}, {"id": "D", "text": "JOIN 조건이 잘못됐다."}]', 'B', 'WHERE 절에서 c.id IS NULL은 LEFT JOIN의 결과에서 고객이 없는 주문을 찾는 것이 맞지만, LEFT JOIN을 사용하는 이유를 무색하게 만들 수 있습니다.'),
    (239, 3, 1, 179, '빈칸을 채우세요: SELECT name FROM employees WHERE department_id IN (SELECT id FROM departments WHERE name = ''Sales''); 이 쿼리는 ________ 부서의 직원들을 선택합니다.', 'SHORT_ANSWER', NULL, 'Sales', '서브쿼리는 ''Sales'' 부서의 id를 찾고, 그 id에 해당하는 employees의 name을 선택합니다.'),
    (240, 3, 1, 180, '다음 중 JOIN의 종류가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "INNER JOIN"}, {"id": "B", "text": "OUTER JOIN"}, {"id": "C", "text": "CROSS JOIN"}, {"id": "D", "text": "MIDDLE JOIN"}]', '["B", "D"]', 'OUTER JOIN과 MIDDLE JOIN은 존재하지 않으며, INNER JOIN과 CROSS JOIN은 유효한 JOIN의 종류입니다.'),
    (241, 3, 1, 181, '서브쿼리를 사용하는 이유는 무엇인가요?', 'SHORT_ANSWER', NULL, '복잡한 데이터 요청을 쉽게 처리하기 위해', '서브쿼리는 복잡한 조건을 가진 데이터 요청을 간결하게 만들어줍니다.'),
    (242, 3, 1, 182, '위의 SQL 쿼리에서 ''WITH RECURSIVE EmployeeCTE AS ('' 부분의 목적은 무엇인가?', 'SHORT_ANSWER', NULL, 'CTE를 정의하여 재귀 쿼리를 사용하기 위함입니다.', 'CTE를 정의하여 재귀적으로 쿼리를 생성할 수 있게 합니다.'),
    (243, 3, 1, 183, '위 쿼리의 기본 쿼리는 무엇을 선택합니까? SELECT 구문에서 빈칸에 해당하는 쿼리를 작성하세요: SELECT EmployeeID, ManagerID, Name FROM Employees WHERE _____;', 'SHORT_ANSWER', NULL, 'ManagerID IS NULL', '기본 쿼리는 최상위 관리자를 찾기 위해 ManagerID가 NULL인 직원들만 선택합니다.'),
    (244, 3, 1, 184, '위의 SQL 쿼리에서 ''UNION ALL''의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 쿼리의 결과를 결합합니다."}, {"id": "B", "text": "쿼리에서 중복을 제거합니다."}, {"id": "C", "text": "서브쿼리를 실행합니다."}, {"id": "D", "text": "재귀를 종료합니다."}]', 'A', '''UNION ALL''은 두 개의 쿼리 결과를 결합하여 모두 포함합니다.'),
    (245, 3, 1, 185, '위의 쿼리에서 INNER JOIN은 무엇을 기준으로 두 테이블을 연결합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EmployeeID"}, {"id": "B", "text": "ManagerID"}, {"id": "C", "text": "Name"}, {"id": "D", "text": "DepartmentID"}]', 'B', 'INNER JOIN은 EmployeeCTE의 EmployeeID와 Employees 테이블의 ManagerID를 기준으로 연결합니다.'),
    (246, 3, 1, 186, 'CTE와 재귀 쿼리를 사용하면 어떤 종류의 데이터 관계를 처리하는 데 유리합니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "계층적 데이터"}, {"id": "B", "text": "비계층적 데이터"}, {"id": "C", "text": "그래프 데이터"}, {"id": "D", "text": "정형 데이터"}]', '["A", "C"]', 'CTE와 재귀 쿼리는 계층적 데이터와 그래프 데이터의 탐색에 유리합니다.'),
    (247, 3, 1, 187, '다음 SQL 코드의 목적은 무엇인가요? CREATE INDEX idx_user_age ON users(age);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "users 테이블의 age 컬럼에 인덱스를 생성한다."}, {"id": "B", "text": "users 테이블의 데이터를 삭제한다."}, {"id": "C", "text": "users 테이블에 새로운 데이터를 추가한다."}, {"id": "D", "text": "users 테이블의 모든 데이터를 조회한다."}]', 'A', '이 코드는 users 테이블의 age 컬럼에 인덱스를 생성하여 성능을 향상시키기 위한 목적입니다.'),
    (248, 3, 1, 188, '다음 SQL 쿼리의 실행 계획을 예측할 때, 어떤 인덱스가 사용될까요? SELECT * FROM users WHERE age > 30;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "idx_user_age"}, {"id": "B", "text": "idx_user_name"}, {"id": "C", "text": "idx_user_country"}, {"id": "D", "text": "사용할 인덱스가 없다"}]', 'A', 'age 컬럼에 대한 인덱스가 생성되어 있으므로, 해당 인덱스가 사용될 것입니다.'),
    (249, 3, 1, 189, '빈칸 채우기: SQL 쿼리의 실행 계획을 보기 위해서는 _____ 명령어를 사용할 수 있다.', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하면 SQL 쿼리의 실행 계획을 확인할 수 있습니다.'),
    (250, 3, 1, 190, '다음 중 인덱스의 장점에 해당하는 것은 무엇인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 검색 속도를 향상시킨다."}, {"id": "B", "text": "데이터 삽입 속도를 항상 증가시킨다."}, {"id": "C", "text": "쿼리 성능을 최적화하는 데 도움을 준다."}, {"id": "D", "text": "중복된 데이터를 제거한다."}]', '["A", "C"]', '인덱스는 데이터 검색 속도를 향상시키고 쿼리 성능을 최적화하는 데 도움을 줍니다.'),
    (251, 3, 1, 191, '인덱스를 사용할 때 주의할 점은 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터의 삽입, 삭제, 수정 시 성능 저하가 발생할 수 있다.', '인덱스를 사용하면 데이터 검색 성능은 향상되지만, 데이터 조작 시 성능 저하가 발생할 수 있습니다.'),
    (252, 3, 1, 192, '다음 SQL 쿼리에서 GROUP BY 절의 역할은 무엇인가? 쿼리: SELECT category, COUNT(*) FROM sales_data GROUP BY category;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "category별로 데이터 집계"}, {"id": "B", "text": "전체 데이터 반환"}, {"id": "C", "text": "특정 조건 필터링"}, {"id": "D", "text": "정렬된 데이터 반환"}]', 'A', 'GROUP BY 절은 데이터를 특정 필드 기준으로 그룹화하여 집계합니다.'),
    (253, 3, 1, 193, '아래 SQL 쿼리에서 HAVING 절의 역할은 무엇인가? 쿼리: SELECT category, SUM(sales) as total_sales FROM sales_data GROUP BY category HAVING total_sales > 1000;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "전체 결과 반환"}, {"id": "B", "text": "조건에 맞는 그룹 필터링"}, {"id": "C", "text": "정렬된 데이터 반환"}, {"id": "D", "text": "집계 데이터 추가"}]', 'B', 'HAVING 절은 그룹화된 데이터에 대한 조건을 설정하여 필터링하는 역할을 합니다.'),
    (254, 3, 1, 194, '다음 SQL 쿼리에서 ''SUM(sales)''의 결과가 2000을 초과하는 카테고리는 무엇인가? 쿼리: SELECT category, SUM(sales) as total_sales FROM sales_data GROUP BY category HAVING total_sales > 2000;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 카테고리"}, {"id": "B", "text": "2000 이하 카테고리"}, {"id": "C", "text": "2000 초과 카테고리"}, {"id": "D", "text": "그룹화 없음"}]', 'C', 'HAVING 절은 SUM(sales)의 결과가 2000을 초과하는 카테고리만을 선택합니다.'),
    (255, 3, 1, 195, '다음 쿼리에서 HAVING 절을 사용하지 않으면 어떤 문제가 발생할 수 있는가? 쿼리: SELECT category, COUNT(*) FROM sales_data GROUP BY category;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 카테고리 수 반환"}, {"id": "B", "text": "전체 데이터 필터링"}, {"id": "C", "text": "빈 결과 반환"}, {"id": "D", "text": "조건 필터링 불가"}]', '["A", "D"]', 'HAVING 절이 없으면 모든 카테고리의 수를 반환하며, 조건 필터링이 불가능해집니다.'),
    (256, 3, 1, 196, 'GROUP BY 절을 사용하지 않고 HAVING 절을 사용할 수 있는가? 그렇다면 예를 들어 설명하라.', 'SHORT_ANSWER', NULL, '아니요, GROUP BY 없이는 HAVING 절을 사용할 수 없다.', 'HAVING 절은 GROUP BY로 그룹화된 결과에 대해 조건을 적용하기 때문에, GROUP BY 없이 사용할 수 없습니다.'),
    (257, 3, 1, 197, '다음 SQL 쿼리의 결과로 적절한 데이터는 무엇인가요? SELECT a.name, b.salary FROM employees a INNER JOIN salaries b ON a.id = b.employee_id WHERE b.salary > 50000;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "급여가 50,000을 초과하는 직원의 이름과 급여"}, {"id": "B", "text": "모든 직원의 이름"}, {"id": "C", "text": "급여가 50,000 이하인 직원의 리스트"}, {"id": "D", "text": "신규 직원의 목록"}]', 'A', '해당 쿼리는 급여가 50,000을 초과하는 직원의 이름과 급여 정보를 조회합니다.'),
    (258, 3, 1, 198, '다음 SQL 쿼리에서 빈칸에 들어갈 키워드는 무엇인가요? SELECT name FROM employees WHERE id IN (SELECT employee_id FROM salaries WHERE salary > ____);', 'SHORT_ANSWER', NULL, '50000', '서브쿼리가 급여가 50,000을 초과하는 직원의 ID를 가져오기 때문에 해당 값이 들어가야 합니다.'),
    (259, 3, 1, 199, '다음 SQL 조인에서 LEFT JOIN의 목적은 무엇인가요? SELECT a.name, b.salary FROM employees a LEFT JOIN salaries b ON a.id = b.employee_id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 직원의 정보를 포함하고 급여가 없는 경우 NULL로 표시"}, {"id": "B", "text": "급여가 있는 직원만 표시"}, {"id": "C", "text": "모든 급여 정보만 포함"}, {"id": "D", "text": "직원 수를 세기 위해서"}]', 'A', 'LEFT JOIN은 왼쪽 테이블의 모든 행을 포함하고, 오른쪽 테이블에서 일치하는 행이 없는 경우 NULL을 표시합니다.'),
    (260, 3, 1, 200, '다음 SQL 쿼리에서 INNER JOIN의 결과로 반환될 수 있는 경우는 무엇인가요? SELECT * FROM table1 INNER JOIN table2 ON table1.id = table2.id;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "table1과 table2 모두에 존재하는 id"}, {"id": "B", "text": "table1에만 존재하는 id"}, {"id": "C", "text": "table2에만 존재하는 id"}, {"id": "D", "text": "둘 다 존재하지 않는 id"}]', '["A"]', 'INNER JOIN은 두 테이블에서 모두 일치하는 id를 가진 행을 반환합니다.'),
    (261, 3, 1, 201, '인덱스를 생성하기 위한 SQL 구문은 무엇인가요? 예: CREATE INDEX _____;', 'SHORT_ANSWER', NULL, 'idx_name ON table_name (column_name)', '인덱스를 생성하기 위해서는 ''CREATE INDEX idx_name ON table_name (column_name);'' 구문을 사용합니다.'),
    (262, 3, 1, 202, '다음 중 인덱스의 장점이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 검색 속도를 향상시킴"}, {"id": "B", "text": "데이터베이스 크기를 자동으로 줄임"}, {"id": "C", "text": "중복 데이터 방지"}, {"id": "D", "text": "쿼리 최적화에 도움을 줌"}]', 'B', '인덱스는 데이터 검색 속도를 향상시키지만 데이터베이스 크기를 자동으로 줄이지는 않습니다.'),
    (263, 3, 1, 203, '다음 SQL 쿼리의 실행 계획을 확인하기 위한 구문은 무엇인가요? EXPLAIN _____;', 'SHORT_ANSWER', NULL, 'SELECT * FROM table_name', '실행 계획을 확인하기 위해서는 ''EXPLAIN SELECT * FROM table_name;'' 구문을 사용합니다.'),
    (264, 3, 1, 204, '인덱스의 종류 중 하나로, 데이터가 추가될 때마다 자동으로 업데이트 되는 인덱스는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클러스터형 인덱스"}, {"id": "B", "text": "비클러스터형 인덱스"}, {"id": "C", "text": "유니크 인덱스"}, {"id": "D", "text": "함수 기반 인덱스"}]', 'A', '클러스터형 인덱스는 데이터가 추가될 때마다 자동으로 업데이트 됩니다.'),
    (265, 3, 1, 205, '인덱스를 사용하고 있을 때의 쿼리 최적화 방법 중 하나는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "WHERE 절에서 인덱스를 활용"}, {"id": "B", "text": "모든 열에 인덱스를 생성"}, {"id": "C", "text": "JOIN 조건에서 인덱스를 활용"}, {"id": "D", "text": "서브쿼리 사용을 피하기"}]', '["A", "C"]', 'WHERE 절과 JOIN 조건에서 인덱스를 활용하는 것이 쿼리 최적화에 도움이 됩니다.'),
    (266, 3, 1, 206, '다음 SQL 쿼리의 결과로 반환될 학생의 등급은 무엇인가요? 

SELECT name, score,
CASE 
    WHEN score >= 90 THEN ''A''
    WHEN score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    ELSE ''F''
END AS grade
FROM students;

학생의 점수가 85일 경우?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "B"}, {"id": "B", "text": "C"}, {"id": "C", "text": "A"}, {"id": "D", "text": "F"}]', 'A', '점수가 85이므로, 조건에 따라 ''B'' 등급이 반환됩니다.'),
    (267, 3, 1, 207, '다음 SQL 문에서 빈칸에 들어갈 적절한 키워드는 무엇인가요? 

SELECT name, score,
CASE 
    WHEN score >= 90 THEN ''A''
    WHEN score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    _______ ''F''
END AS grade
FROM students;', 'SHORT_ANSWER', NULL, 'ELSE', 'CASE WHEN 문의 마지막 부분에 기본값을 설정하기 위한 ''ELSE'' 키워드가 필요합니다.'),
    (268, 3, 1, 208, '다음 SQL 쿼리에서 어떤 조건을 추가하면 ''C'' 등급의 학생만 선택할 수 있을까요? 

SELECT name, score,
CASE 
    WHEN score >= 90 THEN ''A''
    WHEN score >= 80 THEN ''B''
    WHEN score >= 70 THEN ''C''
    ELSE ''F''
END AS grade
FROM students WHERE _______;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "score >= 70 AND score < 80"}, {"id": "B", "text": "score >= 70"}, {"id": "C", "text": "score < 70"}, {"id": "D", "text": "score = 75"}]', 'A', '''C'' 등급을 받기 위한 조건은 70 이상 80 미만이므로, ''score >= 70 AND score < 80''가 필요합니다.'),
    (269, 3, 1, 209, '다음 중 ''CASE WHEN'' 구문을 사용하여 여러 조건을 처리하는 방법에 대한 설명으로 올바른 것은 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "다수의 조건을 평가할 수 있다."}, {"id": "B", "text": "단일 조건만 처리할 수 있다."}, {"id": "C", "text": "조건에 따라 다양한 값을 반환할 수 있다."}, {"id": "D", "text": "함수와 함께 사용할 수 없다."}]', '["A", "C"]', '''CASE WHEN'' 구문은 다수의 조건을 평가하고, 조건에 따라 다양한 값을 반환할 수 있습니다.'),
    (270, 3, 1, 210, '다음 SQL 문장의 목적은 무엇인가요? `SELECT * FROM account WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행을 잠그기 위해 사용된다."}, {"id": "B", "text": "모든 행을 삭제한다."}, {"id": "C", "text": "행을 삽입하기 위해 사용된다."}, {"id": "D", "text": "데이터를 읽기 전용으로 가져온다."}]', 'A', '이 SQL 문장은 id가 1인 행을 잠가 다른 세션에서의 수정 시도를 방지하기 위해 사용됩니다.'),
    (271, 3, 1, 211, '트랜잭션이 원자성을 보장하기 위해 필요한 조건 중 어떤 것이 포함되지 않나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 작업이 성공해야 한다."}, {"id": "B", "text": "모든 작업이 동시에 실행되어야 한다."}, {"id": "C", "text": "작업이 성공하지 않으면 모두 롤백해야 한다."}, {"id": "D", "text": "작업이 일관성을 유지해야 한다."}]', 'B', '트랜잭션은 모든 작업이 성공해야 하며, 실패 시 롤백되어야 하지만, 모든 작업이 동시에 실행될 필요는 없습니다.'),
    (272, 3, 1, 212, '다음 SQL 문장에서 빈칸에 들어갈 적절한 키워드로 올바른 것은 무엇인가요? `BEGIN; SELECT * FROM account WHERE id = 1 ____; -- 계좌 잔액 수정 등의 작업 COMMIT;`', 'SHORT_ANSWER', NULL, 'FOR UPDATE', '이 문맥에서는 행을 잠그기 위해 ''FOR UPDATE''가 필요합니다.'),
    (273, 3, 1, 213, '다음 SQL 문장에서 어떤 동작을 수행하는가? `BEGIN; SELECT balance FROM account WHERE id = 1 FOR UPDATE; UPDATE account SET balance = balance - 100 WHERE id = 1; COMMIT;`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "계좌 ID 1의 잔액을 조회한다."}, {"id": "B", "text": "계좌 ID 1의 잔액을 100 감소시킨다."}, {"id": "C", "text": "계좌 ID 1의 행을 삭제한다."}, {"id": "D", "text": "다른 세션에서 계좌 ID 1의 잔액을 수정하지 못하게 잠근다."}]', '["A", "B", "D"]', '이 SQL 문장은 계좌 ID 1의 잔액을 조회하고, 그 잔액을 100 감소시키며, 동시에 다른 세션에서 이 행을 수정하지 못하게 잠그는 역할을 합니다.'),
    (274, 3, 1, 214, '다음 SQL 쿼리의 목적은 무엇인가요? 
WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, Name, ManagerID
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.Name, e.ManagerID
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 직원의 정보를 출력한다."}, {"id": "B", "text": "상위 관리자와 그 직원들을 재귀적으로 출력한다."}, {"id": "C", "text": "직원 수를 계산한다."}, {"id": "D", "text": "상위 직급만을 출력한다."}]', 'B', '이 쿼리는 최상위 관리자와 그 직원들을 재귀적으로 검색하여 출력합니다.'),
    (275, 3, 1, 215, '다음 SQL 쿼리에서 UNION ALL의 역할은 무엇인가요? 
WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, Name, ManagerID
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.Name, e.ManagerID
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복을 제거한다."}, {"id": "B", "text": "결과 집합을 결합한다."}, {"id": "C", "text": "조건을 추가한다."}, {"id": "D", "text": "서브 쿼리를 최적화한다."}]', 'B', 'UNION ALL은 두 개의 결과 집합을 결합하여 재귀적인 결과를 생성합니다.'),
    (276, 3, 1, 216, '빈칸을 채우세요: CTE를 사용하면 쿼리의 ___________을 높일 수 있다.', 'SHORT_ANSWER', NULL, '가독성', 'CTE는 쿼리의 가독성을 높여 복잡한 쿼리를 쉽게 이해할 수 있게 합니다.'),
    (277, 3, 1, 217, '재귀 쿼리에서 사용할 수 있는 CTE의 구조는 무엇인가요? 
____________ AS (
    SELECT ...
    UNION ALL
    SELECT ...
)', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WITH RECURSIVE"}, {"id": "B", "text": "WITH TEMP"}, {"id": "C", "text": "WITH JOIN"}, {"id": "D", "text": "WITH INNER"}]', 'A', '재귀 쿼리에서는 WITH RECURSIVE 구문을 사용하여 CTE를 정의해야 합니다.'),
    (278, 3, 1, 218, '다음 SQL 쿼리의 결과는 무엇인가요? SELECT category, COUNT(*) FROM products GROUP BY category;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "카테고리별 상품 수"}, {"id": "B", "text": "전체 상품 수"}, {"id": "C", "text": "카테고리 목록"}, {"id": "D", "text": "카테고리별 평균 가격"}]', 'A', '이 쿼리는 각 카테고리별로 상품의 수를 세어 반환합니다.'),
    (279, 3, 1, 219, '다음 SQL 쿼리의 빈칸에 들어갈 알맞은 키워드는 무엇인가요? SELECT category, SUM(sales) FROM products ___ category;', 'SHORT_ANSWER', NULL, 'GROUP BY', 'GROUP BY 키워드가 각 카테고리별로 판매 합계를 계산하는 데 필요합니다.'),
    (280, 3, 1, 220, '다음 SQL 쿼리에서 HAVING 절이 필요한 이유는 무엇인가요? SELECT category, AVG(sales) FROM products GROUP BY category HAVING ____;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AVG(sales) > 500"}, {"id": "B", "text": "category = ''Electronics''"}, {"id": "C", "text": "sales > 1000"}, {"id": "D", "text": "COUNT(*) > 5"}]', 'A', 'HAVING 절은 집계된 결과에 조건을 적용하기 위해 사용되므로 AVG(sales) > 500 조건이 필요합니다.'),
    (281, 3, 1, 221, '다음 중 GROUP BY와 HAVING을 모두 사용하는 쿼리는 어떤 것인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT * FROM table GROUP BY column;"}, {"id": "B", "text": "SELECT column, COUNT(*) FROM table GROUP BY column HAVING COUNT(*) > 10;"}, {"id": "C", "text": "SELECT column FROM table WHERE condition;"}, {"id": "D", "text": "SELECT column, AVG(value) FROM table GROUP BY column HAVING AVG(value) < 100;"}]', '["B", "D"]', 'B와 D는 GROUP BY와 HAVING 절을 모두 사용하여 그룹화된 데이터에 조건을 적용합니다.'),
    (282, 3, 1, 222, '다음 SQL 쿼리의 결과로 올바른 것은 무엇인가?

SELECT COALESCE(NULL, ''Hello'', ''World'');', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''Hello''"}, {"id": "B", "text": "''World''"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "''Hello World''"}]', 'A', 'COALESCE 함수는 첫 번째로 NULL이 아닌 ''Hello''를 반환합니다.'),
    (283, 3, 1, 223, '다음 SQL 쿼리의 빈칸을 채우시오:

SELECT IFNULL(column_name, _____) FROM table_name;', 'SHORT_ANSWER', NULL, '''default_value''', 'IFNULL 함수는 column_name이 NULL일 경우 ''default_value''를 반환하도록 설정합니다.'),
    (284, 3, 1, 224, '다음 중 COALESCE 함수의 사용법에 대해 올바른 설명은 무엇인가?

SELECT COALESCE(value1, value2, value3);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 인수가 NULL일 경우 NULL을 반환한다."}, {"id": "B", "text": "''value1''이 NULL일 경우 ''value2''를 반환한다."}, {"id": "C", "text": "첫 번째로 NULL이 아닌 값을 반환한다."}, {"id": "D", "text": "모든 인수를 더한 값을 반환한다."}]', 'C', 'COALESCE는 첫 번째로 NULL이 아닌 값을 반환하는 함수입니다.'),
    (285, 3, 1, 225, '다음 SQL 쿼리 결과에서 반환될 수 있는 값들을 모두 선택하시오:

SELECT COALESCE(NULL, ''A'', NULL, ''B'', NULL);', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "''A''"}, {"id": "B", "text": "''B''"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "''AB''"}]', '["A"]', 'COALESCE는 첫 번째로 NULL이 아닌 ''A''를 반환합니다.'),
    (286, 3, 1, 226, 'IFNULL 함수는 몇 개의 인수를 필요한가?', 'SHORT_ANSWER', NULL, '2', 'IFNULL 함수는 두 개의 인수를 필요로 합니다.'),
    (287, 3, 1, 227, '아래 SQL 쿼리의 결과는 무엇일까요?

SELECT student_name,
    CASE 
        WHEN score >= 90 THEN ''A''
        WHEN score >= 80 THEN ''B''
        WHEN score >= 70 THEN ''C''
        ELSE ''F''
    END AS grade
FROM students;

해당 쿼리가 실행될 때, ''score''가 85인 학생은 어떤 등급을 받게 되나요?', 'SHORT_ANSWER', NULL, 'B', '''score''가 85인 학생은 80 이상이므로 ''B'' 등급을 받습니다.'),
    (288, 3, 1, 228, '다음 중 SQL의 CASE WHEN 구문에서 올바른 사용 예는 무엇인가요?

SELECT student_name,
    CASE 
        WHEN condition1 THEN result1
        WHEN condition2 THEN result2
        ...
    END AS alias_name
FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정상적인 구문입니다."}, {"id": "B", "text": "CASE WHEN 구문은 WHERE 절에서만 사용 가능합니다."}, {"id": "C", "text": "CASE WHEN은 SELECT 절에서 사용할 수 없습니다."}, {"id": "D", "text": "CASE WHEN 구문은 반드시 ELSE 절이 필요합니다."}]', 'A', 'CASE WHEN 구문은 SELECT 절에서 사용할 수 있으며, 정상적인 구문입니다.'),
    (289, 3, 1, 229, '다음 SQL 쿼리에서 ''score''가 75 이상인 경우의 조건을 추가하고 올바른 결과를 보장하기 위해 어떤 내용을 추가해야 할까요?

SELECT student_name,
    CASE 
        WHEN score >= 90 THEN ''A''
        WHEN score >= 80 THEN ''B''
        ELSE ''F''
    END AS grade
FROM students;
', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHEN score >= 75 THEN ''C''"}, {"id": "B", "text": "WHEN score < 70 THEN ''D''"}, {"id": "C", "text": "WHEN score = 80 THEN ''A''"}, {"id": "D", "text": "WHEN score <= 90 THEN ''B''"}]', 'A', '75 이상을 C 등급으로 분류하기 위해서는 ''WHEN score >= 75 THEN ''C''''를 추가해야 합니다.'),
    (290, 3, 1, 230, '다음 SQL 쿼리에서 반환되는 결과가 모두 포함될 수 있는 경우는 무엇인가요?

SELECT student_name,
    CASE 
        WHEN score < 60 THEN ''F''
        WHEN score < 70 THEN ''D''
        WHEN score < 80 THEN ''C''
        WHEN score < 90 THEN ''B''
        ELSE ''A''
    END AS grade
FROM students;
', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "F"}, {"id": "B", "text": "D"}, {"id": "C", "text": "C"}, {"id": "D", "text": "A"}]', '["A", "B", "C", "D"]', '모든 등급 ''F'', ''D'', ''C'', ''A''는 조건을 만족할 수 있습니다.'),
    (291, 3, 1, 231, '다음 SQL 쿼리의 결과로 올바른 것은 무엇인가요? 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상사가 없는 직원과 그 하위 직원 목록"}, {"id": "B", "text": "모든 직원 목록"}, {"id": "C", "text": "상사만 포함된 목록"}, {"id": "D", "text": "하위 직원만 포함된 목록"}]', 'A', '재귀 CTE는 상사가 없는 직원부터 시작하여 하위 직원을 탐색합니다.'),
    (292, 3, 1, 232, '다음 SQL 쿼리에서 빈칸에 들어갈 올바른 키워드는 무엇인가요? 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS ______
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)', 'SHORT_ANSWER', NULL, 'NULL', '상사가 없는 직원을 찾기 위해 ManagerID가 NULL인 경우를 조건으로 합니다.'),
    (293, 3, 1, 233, '재귀 CTE를 사용하여 모든 하위 직원을 찾으려면 어떤 조건을 사용해야 하나요? 

SELECT e.EmployeeID, e.ManagerID, e.Name
FROM Employees e
INNER JOIN EmployeeCTE cte ON e.ManagerID = _______', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "cte.EmployeeID"}, {"id": "B", "text": "e.EmployeeID"}, {"id": "C", "text": "cte.ManagerID"}, {"id": "D", "text": "e.ManagerID"}]', 'A', 'cte.EmployeeID와 e.ManagerID를 매칭하여 하위 직원을 찾습니다.'),
    (294, 3, 1, 234, '다음 중 CTE의 특징으로 올바르지 않은 것은 무엇인가요? ', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "일시적인 결과 집합을 생성한다."}, {"id": "B", "text": "한 쿼리 내에서만 사용할 수 있다."}, {"id": "C", "text": "다른 쿼리에서도 재사용할 수 있다."}, {"id": "D", "text": "재귀적으로 사용할 수 있다."}]', '["B", "C"]', 'CTE는 한 쿼리 내에서만 사용할 수 있으며, 다른 쿼리에서는 재사용할 수 없습니다.'),
    (295, 3, 1, 235, '다음 SQL 쿼리가 반환하는 결과는 무엇인가요? 
SELECT COALESCE(salary, 3000) FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "salary가 NULL일 경우 3000 반환"}, {"id": "B", "text": "salary가 NULL일 경우 NULL 반환"}, {"id": "C", "text": "salary 반환"}, {"id": "D", "text": "3000 반환"}]', 'A', 'COALESCE 함수는 NULL이 아닌 첫 번째 값을 반환하기 때문에 salary가 NULL일 경우 3000을 반환합니다.'),
    (296, 3, 1, 236, '다음 SQL 쿼리를 완성하세요: 
SELECT IFNULL(column_name, ______) FROM table_name;', 'SHORT_ANSWER', NULL, 'default_value', 'IFNULL 함수는 첫 번째 인수가 NULL일 때 두 번째 인수인 ''default_value''를 반환합니다.'),
    (297, 3, 1, 237, '다음 SQL 쿼리의 결과는 무엇일까요? 
SELECT COALESCE(NULL, NULL, ''Hello'', ''World'') AS greeting;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello"}, {"id": "B", "text": "World"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "Hello World"}]', 'A', 'COALESCE는 첫 번째로 NULL이 아닌 값을 찾기 때문에 ''Hello''를 반환합니다.'),
    (298, 3, 1, 238, '다음 SQL 쿼리에서 반환되는 값은 무엇인가요? 
SELECT COUNT(IFNULL(age, 0)) FROM users;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "age가 NULL인 경우 0을 카운트"}, {"id": "B", "text": "age가 NULL인 경우 카운트하지 않음"}, {"id": "C", "text": "모든 age 값을 카운트"}, {"id": "D", "text": "age의 NULL 개수만 카운트"}]', '["A", "C"]', 'IFNULL을 사용하면 NULL이 0으로 대체되므로, 모든 age 값을 카운트하게 됩니다.'),
    (299, 3, 1, 239, 'COALESCE 함수는 어떻게 작동하나요?', 'SHORT_ANSWER', NULL, 'NULL이 아닌 첫 번째 값을 반환합니다.', 'COALESCE 함수는 인수 중에서 NULL이 아닌 첫 번째 값을 찾고 반환하는 함수입니다.'),
    (300, 3, 1, 240, '다음 SQL 쿼리의 출력 결과는 무엇인가요? `EXPLAIN SELECT * FROM employees WHERE name = ''John'';`', 'SHORT_ANSWER', NULL, '쿼리 실행 계획', '이 쿼리는 ''employees'' 테이블에서 ''name'' 컬럼을 기준으로 필터링하는 쿼리의 실행 계획을 보여줍니다.'),
    (301, 3, 1, 241, '다음 SQL 코드에서 인덱스 생성하는 올바른 구문은 무엇인가요? `______ idx_employee_name ON employees(name);`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CREATE INDEX"}, {"id": "B", "text": "ADD INDEX"}, {"id": "C", "text": "MAKE INDEX"}, {"id": "D", "text": "INDEX ON"}]', 'A', '올바른 구문은 ''CREATE INDEX''입니다.'),
    (302, 3, 1, 242, '다음 SQL 문에서 사용되는 인덱스의 장점은 무엇인가요? `SELECT * FROM employees WHERE name = ''John'';`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "속도 증가"}, {"id": "B", "text": "데이터 중복"}, {"id": "C", "text": "메모리 사용 증가"}, {"id": "D", "text": "자동 업데이트"}]', 'A', '인덱스를 사용하면 쿼리의 실행 속도가 증가합니다.'),
    (303, 3, 1, 243, '인덱스를 사용하여 쿼리 성능을 향상시키기 위한 조건으로 올바른 것을 모두 선택하세요. (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "자주 검색되는 컬럼"}, {"id": "B", "text": "데이터가 자주 변경되는 컬럼"}, {"id": "C", "text": "테이블의 크기가 큰 경우"}, {"id": "D", "text": "모든 컬럼에 인덱스 생성"}]', '["A", "C"]', '인덱스는 자주 검색되는 컬럼과 테이블의 크기가 큰 경우에 유용합니다.'),
    (304, 3, 1, 244, '다음 SQL JOIN 쿼리의 결과는 무엇인가요?
SELECT * FROM orders JOIN customers ON orders.customer_id = customers.id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "주문과 고객의 모든 정보를 결합한 결과"}, {"id": "B", "text": "주문 테이블만 보여줌"}, {"id": "C", "text": "고객 테이블만 보여줌"}, {"id": "D", "text": "결과가 없다"}]', 'A', 'JOIN은 두 테이블의 관련 데이터를 결합하여 결과를 출력합니다.'),
    (305, 3, 1, 245, '다음 SQL 서브쿼리의 결과는 무엇인가요?
SELECT * FROM products WHERE id IN (SELECT product_id FROM orders WHERE quantity > 10);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "판매량이 10 이상인 제품"}, {"id": "B", "text": "모든 제품"}, {"id": "C", "text": "판매량이 10 미만인 제품"}, {"id": "D", "text": "결과가 없다"}]', 'A', '서브쿼리는 orders 테이블에서 판매량이 10 이상인 product_id를 찾고, 이를 사용하여 products 테이블에서 해당 id를 가진 제품을 조회합니다.'),
    (306, 3, 1, 246, 'JOIN 쿼리에서 사용할 수 있는 유형이 아닌 것은?
INNER JOIN, LEFT JOIN, RIGHT JOIN, ______', 'SHORT_ANSWER', NULL, 'FULL OUTER JOIN', 'FULL OUTER JOIN은 조인 유형 중 하나입니다.'),
    (307, 3, 1, 247, '다음 SQL 쿼리에서 올바른 결과를 얻기 위해 필요한 JOIN 유형은 무엇인가요?
SELECT * FROM employees e LEFT JOIN departments d ON e.department_id = d.id;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "LEFT JOIN"}, {"id": "B", "text": "INNER JOIN"}, {"id": "C", "text": "RIGHT JOIN"}, {"id": "D", "text": "FULL JOIN"}]', '["A"]', 'LEFT JOIN은 employees 테이블의 모든 행을 반환하고, departments 테이블의 일치하는 행을 반환합니다.'),
    (308, 3, 1, 248, '위의 SQL 쿼리에서 ROW_NUMBER() 함수의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 학생에게 순위를 매긴다."}, {"id": "B", "text": "이전 학생의 점수를 반환한다."}, {"id": "C", "text": "학생의 점수를 평균 낸다."}, {"id": "D", "text": "학생의 점수를 합산한다."}]', 'A', 'ROW_NUMBER() 함수는 각 행에 대해 순위를 매기는 역할을 합니다.'),
    (309, 3, 1, 249, '다음 SQL 문의 결과는 무엇인가요? SELECT id, RANK() OVER (ORDER BY score DESC) AS rank FROM students WHERE id = 1;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생의 점수에 따라 다양한 순위가 매겨진다."}, {"id": "B", "text": "id가 1인 학생의 점수만 보여준다."}, {"id": "C", "text": "모든 학생의 점수를 합산한 결과를 보여준다."}, {"id": "D", "text": "학생의 순위가 1로 고정된다."}]', 'A', 'RANK() 함수는 점수에 따라 순위를 매기며, id가 1인 학생의 점수를 포함한 모든 학생의 순위를 보여줍니다.'),
    (310, 3, 1, 250, 'SQL 문에서 LAG() 함수는 어떤 값을 반환하나요? SELECT id, score, LAG(score) OVER (ORDER BY score) AS previous_score FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 행의 점수를 반환한다."}, {"id": "B", "text": "이전 행의 점수를 반환한다."}, {"id": "C", "text": "모든 행의 평균 점수를 반환한다."}, {"id": "D", "text": "모든 행의 최대 점수를 반환한다."}]', 'B', 'LAG() 함수는 이전 행의 값을 반환합니다.'),
    (311, 3, 1, 251, 'ROW_NUMBER와 RANK의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ROW_NUMBER는 중복값에 대해 고유한 번호를 부여한다."}, {"id": "B", "text": "RANK는 중복값에 대해 동일한 순위를 부여한다."}, {"id": "C", "text": "ROW_NUMBER는 모든 행에 대해 순위를 매길 수 없다."}, {"id": "D", "text": "RANK는 중복값이 있는 경우 다음 순위에 영향을 미친다."}]', '["A", "B", "D"]', 'ROW_NUMBER는 중복값을 허용하지 않으며, RANK는 중복값에 대해 동일한 순위를 매기고, 그 이후 순위에 영향을 미칩니다.'),
    (312, 3, 1, 252, 'LAG() 함수의 기본 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '이전 행의 값을 반환하는 것', 'LAG() 함수는 결과 집합에서 이전 행의 지정된 열 값을 반환하는 기능을 합니다.'),
    (313, 3, 1, 253, 'CTE를 정의할 때 사용하는 키워드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'WITH', 'CTE를 정의할 때 ''WITH'' 키워드를 사용합니다.'),
    (314, 3, 1, 254, '다음 SQL 쿼리의 실행 결과로 옳은 것은 무엇인가요? 

WITH RECURSIVE CTE AS (
    SELECT 1 AS num
    UNION ALL
    SELECT num + 1 FROM CTE WHERE num < 5
)
SELECT * FROM CTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1, 2, 3, 4, 5"}, {"id": "B", "text": "1, 2, 3, 4"}, {"id": "C", "text": "1, 2, 3"}, {"id": "D", "text": "1, 2, 3, 4, 5, 6"}]', 'B', '이 쿼리는 1부터 4까지의 수를 생성합니다.'),
    (315, 3, 1, 255, '재귀 CTE에서 종료 조건은 어떤 부분에 해당하나요? 

WITH RECURSIVE CTE AS (
    SELECT ... 
    UNION ALL
    SELECT ...
    WHERE ...
)', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "SELECT ..."}, {"id": "B", "text": "UNION ALL"}, {"id": "C", "text": "WHERE ..."}, {"id": "D", "text": "CTE AS"}]', 'C', '재귀 CTE에서 종료 조건은 ''WHERE'' 구문에 포함됩니다.'),
    (316, 3, 1, 256, '아래의 SQL 쿼리에서 올바른 EmployeeID를 모두 선택하기 위한 조건을 고르세요. 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, Name, ManagerID
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.Name, e.ManagerID
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT EmployeeID FROM EmployeeCTE WHERE ...;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "EmployeeID IS NOT NULL"}, {"id": "B", "text": "ManagerID IS NULL"}, {"id": "C", "text": "DepartmentID = ''Sales''"}, {"id": "D", "text": "Name LIKE ''A%''"}]', '["A", "B"]', 'EmployeeID는 NULL이 아니어야 하며, 조건에 맞는 직원들을 선택하기 위한 조건입니다.'),
    (317, 3, 1, 257, 'CTE와 재귀 쿼리를 사용하여 계층적 구조의 데이터를 다룰 때의 주의사항은 무엇인가요?', 'SHORT_ANSWER', NULL, '무한 루프를 방지하기 위해 종료 조건을 설정해야 한다.', '재귀 쿼리는 종료 조건이 없으면 무한 루프에 빠질 수 있으므로 반드시 설정해야 합니다.'),
    (318, 3, 1, 258, '다음 SQL 쿼리의 결과는 무엇인가요? SELECT product_id, SUM(quantity) AS total_sales FROM sales GROUP BY product_id;', 'SHORT_ANSWER', NULL, '각 제품의 ID와 총 판매량', '이 쿼리는 각 제품별로 판매량의 총합을 계산하여 보여줍니다.'),
    (319, 3, 1, 259, '다음 SQL 쿼리에서 HAVING 절은 어떤 역할을 하나요? SELECT product_id, SUM(quantity) AS total_sales FROM sales GROUP BY product_id HAVING SUM(quantity) >= 100;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "총 판매량이 100 이상인 제품만 필터링"}, {"id": "B", "text": "모든 제품을 보여준다"}, {"id": "C", "text": "최대 판매량을 구한다"}, {"id": "D", "text": "판매량의 평균을 구한다"}]', 'A', 'HAVING 절은 그룹화된 결과에서 특정 조건을 만족하는 결과만 필터링합니다.'),
    (320, 3, 1, 260, '다음 SQL 쿼리에서 GROUP BY 절에 사용된 컬럼은 무엇인가요? SELECT product_id, SUM(quantity) AS total_sales FROM sales GROUP BY product_id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "product_id"}, {"id": "B", "text": "quantity"}, {"id": "C", "text": "total_sales"}, {"id": "D", "text": "sales"}]', 'A', 'GROUP BY 절에는 데이터를 그룹화하는 기준이 되는 컬럼이 포함됩니다.'),
    (321, 3, 1, 261, '총 판매량이 50 이상인 제품을 찾기 위해 HAVING 절을 사용할 경우 어떤 쿼리가 필요할까? SELECT product_id, SUM(quantity) AS total_sales FROM sales GROUP BY product_id HAVING ___;', 'SHORT_ANSWER', NULL, 'SUM(quantity) >= 50', 'HAVING 절은 그룹화된 데이터의 조건을 지정하는 데 사용됩니다.'),
    (322, 3, 1, 262, '다음 중 HAVING 절을 사용할 수 있는 전제조건은 무엇인가요? SELECT product_id, SUM(quantity) AS total_sales FROM sales GROUP BY product_id HAVING ___;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "GROUP BY가 사용되어야 한다"}, {"id": "B", "text": "WHERE 절이 반드시 있어야 한다"}, {"id": "C", "text": "집계 함수가 포함되어야 한다"}, {"id": "D", "text": "ORDER BY가 필요하다"}]', '["A", "C"]', 'HAVING 절은 GROUP BY로 그룹화된 결과에 조건을 추가하며, 집계 함수와 함께 사용됩니다.'),
    (323, 3, 1, 263, '다음 SQL 쿼리의 주요 목적은 무엇인가? 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, ManagerID, Name
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.ManagerID, e.Name
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하위 직원과 관리자의 관계를 찾기 위해"}, {"id": "B", "text": "모든 직원을 삭제하기 위해"}, {"id": "C", "text": "직원 목록을 정렬하기 위해"}, {"id": "D", "text": "직원 수를 세기 위해"}]', 'A', '이 쿼리는 관리자가 없는 직원부터 시작하여 모든 하위 직원을 재귀적으로 찾는 목적입니다.'),
    (324, 3, 1, 264, '아래 쿼리에서 빈칸에 들어갈 올바른 명령어는 무엇인가?

SELECT * FROM Employees WHERE ManagerID = (SELECT ... FROM EmployeeCTE);', 'SHORT_ANSWER', NULL, 'EmployeeID', '하위 직원을 찾기 위해 상위 직원의 EmployeeID를 사용해야 합니다.'),
    (325, 3, 1, 265, 'CTE의 장점 중 하나는 무엇인가?

A. 성능이 항상 개선된다.
B. 쿼리를 더 간결하고 이해하기 쉽게 만든다.
C. 모든 SQL 서버에서 지원된다.
D. CTE는 데이터베이스 내에서만 사용 가능하다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성능이 항상 개선된다."}, {"id": "B", "text": "쿼리를 더 간결하고 이해하기 쉽게 만든다."}, {"id": "C", "text": "모든 SQL 서버에서 지원된다."}, {"id": "D", "text": "CTE는 데이터베이스 내에서만 사용 가능하다."}]', 'B', 'CTE는 쿼리를 더 간결하고 이해하기 쉽게 만들어 쿼리 작성 시 유용합니다.'),
    (326, 3, 1, 266, '재귀 CTE에서는 어떤 두 가지 쿼리를 사용하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "기본 쿼리"}, {"id": "B", "text": "재귀 쿼리"}, {"id": "C", "text": "종속 쿼리"}, {"id": "D", "text": "서브쿼리"}]', '["A", "B"]', '재귀 CTE는 기본 쿼리와 재귀 쿼리의 조합으로 구성됩니다.'),
    (327, 3, 1, 267, '다음 SQL 쿼리에서 ''FOR UPDATE''의 역할은 무엇인가요? `SELECT * FROM accounts WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해당 행에 대해 업데이트 락을 설정한다."}, {"id": "B", "text": "해당 행을 삭제한다."}, {"id": "C", "text": "해당 행을 읽기 전용으로 설정한다."}, {"id": "D", "text": "해당 행을 복사한다."}]', 'A', '''FOR UPDATE''는 선택된 행에 대해 업데이트 락을 설정하여 다른 트랜잭션이 해당 행을 수정하지 못하도록 합니다.'),
    (328, 3, 1, 268, '아래의 SQL 쿼리에서 누락된 부분을 적으시오. `BEGIN; SELECT * FROM accounts WHERE id = 1 ___; COMMIT;`', 'SHORT_ANSWER', NULL, 'FOR UPDATE', '''FOR UPDATE''를 추가함으로써 해당 행에 대해 업데이트 락을 설정할 수 있습니다.'),
    (329, 3, 1, 269, '다음 중 트랜잭션에서 사용되는 명령어가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "BEGIN"}, {"id": "B", "text": "ROLLBACK"}, {"id": "C", "text": "SELECT"}, {"id": "D", "text": "COMMIT"}]', 'C', 'SELECT는 트랜잭션 명령어가 아니며 데이터 조회에 사용됩니다.'),
    (330, 3, 1, 270, '트랜잭션의 ACID 속성 중에서 ''Consistency''에 관한 설명으로 맞는 것을 모두 고르시오. (복수 선택 가능) 
1. 트랜잭션이 성공하면 데이터베이스는 유효한 상태를 유지해야 한다. 
2. 트랜잭션이 실패하면 데이터는 반드시 롤백되어야 한다. 
3. 트랜잭션 중 데이터는 항상 일관된 상태를 유지해야 한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "1과 3"}]', '["A", "C"]', 'Consistency는 트랜잭션이 데이터베이스를 유효한 상태로 유지해야 함을 의미하며, 그 과정에서 일관성을 보장해야 합니다.'),
    (331, 3, 1, 271, '트랜잭션의 격리 수준 중 하나인 ''READ COMMITTED''의 특징은 무엇인가요?', 'SHORT_ANSWER', NULL, '트랜잭션이 커밋된 데이터만 읽을 수 있다.', '''READ COMMITTED''는 다른 트랜잭션이 커밋한 데이터만 볼 수 있도록 하여 비일관성을 방지합니다.'),
    (332, 3, 1, 272, '다음 SQL 쿼리의 기능은 무엇인가요? 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, Name, ManagerID
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.Name, e.ManagerID
    FROM Employees e
    INNER JOIN EmployeeCTE cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 직원의 목록을 반환한다."}, {"id": "B", "text": "상위 관리자부터 모든 직원과 그들의 상사를 반환한다."}, {"id": "C", "text": "직원의 급여를 계산하여 반환한다."}, {"id": "D", "text": "직원 수를 반환한다."}]', 'B', '이 쿼리는 상위 관리자부터 시작하여 모든 직원과 그들의 상사를 나열합니다.'),
    (333, 3, 1, 273, '다음 코드를 완성하세요. 

WITH RECURSIVE EmployeeCTE AS (
    SELECT EmployeeID, Name, ManagerID
    FROM Employees
    WHERE ManagerID IS NULL
    UNION ALL
    SELECT e.EmployeeID, e.Name, e.ManagerID
    FROM Employees e
    INNER JOIN ______ cte ON e.ManagerID = cte.EmployeeID
)
SELECT * FROM EmployeeCTE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Employees"}, {"id": "B", "text": "EmployeeCTE"}, {"id": "C", "text": "Managers"}, {"id": "D", "text": "TeamMembers"}]', 'B', '재귀 CTE에서는 자기 자신을 참조해야 하므로 EmployeeCTE를 사용해야 합니다.'),
    (334, 3, 1, 274, '재귀 CTE의 주요 구성 요소는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이니셜 쿼리"}, {"id": "B", "text": "재귀 쿼리"}, {"id": "C", "text": "서브쿼리"}, {"id": "D", "text": "그룹화"}]', '["A", "B"]', '재귀 CTE는 이니셜 쿼리와 재귀 쿼리로 구성되어 있습니다.'),
    (335, 3, 1, 275, 'CTE의 장점은 무엇인가요?', 'SHORT_ANSWER', NULL, '쿼리의 가독성을 높이고 복잡한 쿼리를 단순화한다.', ''),
    (336, 3, 1, 276, '다음 SQL 쿼리는 어떤 결과를 반환합니까? SELECT e.name, d.department_name FROM employees e INNER JOIN departments d ON e.department_id = d.id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원 이름과 해당 부서 이름의 리스트"}, {"id": "B", "text": "부서 이름 리스트"}, {"id": "C", "text": "직원 이름만"}, {"id": "D", "text": "부서 성격 설명"}]', 'A', 'INNER JOIN을 사용하여 직원과 해당 부서의 정보를 결합한 결과를 반환합니다.'),
    (337, 3, 1, 277, 'SQL 쿼리에서 LEFT JOIN을 사용하면 어떤 결과가 나올까요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "오른쪽 테이블의 모든 행"}, {"id": "B", "text": "왼쪽 테이블의 모든 행과 일치하는 오른쪽 테이블의 행"}, {"id": "C", "text": "양쪽 테이블의 행이 일치하는 경우만"}, {"id": "D", "text": "왼쪽 테이블의 행이 없으면 결과 없음"}]', 'B', 'LEFT JOIN은 왼쪽 테이블의 모든 행과 오른쪽 테이블의 일치하는 행을 반환합니다.'),
    (338, 3, 1, 278, '다음 SQL 문에서 빈칸에 들어갈 올바른 SQL 키워드를 쓰시오: SELECT name FROM employees WHERE department_id = (SELECT ___ FROM departments WHERE department_name = ''Sales'');', 'SHORT_ANSWER', NULL, 'id', '서브쿼리에서 ''Sales'' 부서의 id를 조회하기 위해 ''id''를 사용해야 합니다.'),
    (339, 3, 1, 279, '다음 중 서브쿼리를 사용하는 쿼리는 어떤 것인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT name FROM employees WHERE department_id = (SELECT id FROM departments WHERE department_name = ''Sales'');"}, {"id": "B", "text": "SELECT d.department_name FROM departments d LEFT JOIN employees e ON d.id = e.department_id;"}, {"id": "C", "text": "SELECT name FROM employees WHERE salary > (SELECT AVG(salary) FROM employees);"}, {"id": "D", "text": "SELECT e.name, d.department_name FROM employees e INNER JOIN departments d ON e.department_id = d.id;"}]', '["A", "C"]', 'A와 C는 서브쿼리를 사용하여 특정 조건에 맞는 데이터를 필터링하는 쿼리입니다.'),
    (340, 3, 1, 280, '다음 SQL 쿼리에서 어떤 인덱스가 사용될 가능성이 가장 높은가? `SELECT * FROM users WHERE name = ''John'';`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "idx_name"}, {"id": "B", "text": "idx_age"}, {"id": "C", "text": "idx_email"}, {"id": "D", "text": "idx_address"}]', 'A', '이 쿼리는 ''name'' 컬럼을 기준으로 검색하므로 ''idx_name'' 인덱스가 가장 적합하다.'),
    (341, 3, 1, 281, '실행 계획을 확인하는 SQL 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EXPLAIN QUERY PLAN"}, {"id": "B", "text": "SHOW PLAN"}, {"id": "C", "text": "DESCRIBE"}, {"id": "D", "text": "ANALYZE"}]', 'A', 'SQL에서 실행 계획을 확인하려면 ''EXPLAIN QUERY PLAN'' 명령어를 사용한다.'),
    (342, 3, 1, 282, '다음 쿼리의 결과를 예측하시오. `SELECT * FROM users WHERE created_at > ''2022-01-01'';` (인덱스가 없는 경우)', 'SHORT_ANSWER', NULL, '전체 테이블 스캔', '인덱스가 없다면 데이터베이스는 전체 테이블을 스캔하여 조건을 만족하는 행을 찾아야 한다.'),
    (343, 3, 1, 283, '인덱스 사용 시 성능 개선에 대한 장점은 무엇인가? 선택하시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "검색 속도 향상"}, {"id": "B", "text": "데이터 삽입 속도 향상"}, {"id": "C", "text": "정렬 속도 향상"}, {"id": "D", "text": "디스크 공간 절약"}]', '["A", "C"]', '인덱스를 사용하면 검색 속도가 향상되며 정렬 작업도 빨라질 수 있지만, 데이터 삽입 속도는 오히려 저하될 수 있다.'),
    (344, 3, 1, 284, '다음 SQL 쿼리에서 ''idx_user_name'' 인덱스는 어떤 목적으로 사용될 수 있습니까? 

SELECT * FROM users WHERE name = ''John'';', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 성능 향상"}, {"id": "B", "text": "데이터 정렬"}, {"id": "C", "text": "데이터 중복 확인"}, {"id": "D", "text": "테이블 삭제"}]', 'A', '인덱스는 쿼리 성능을 향상시키기 위해 사용됩니다.'),
    (345, 3, 1, 285, '다음 SQL 쿼리에서 올바른 인덱스 생성 구문은 무엇인가요? 

___ idx_user_email ON users (email);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CREATE INDEX"}, {"id": "B", "text": "ADD INDEX"}, {"id": "C", "text": "INDEX CREATE"}, {"id": "D", "text": "MAKE INDEX"}]', 'A', '인덱스를 생성할 때는 ''CREATE INDEX'' 구문을 사용해야 합니다.'),
    (346, 3, 1, 286, '다음 SQL 쿼리의 실행 계획을 확인하기 위해 사용해야 하는 구문은 무엇인가요? 

___ SELECT * FROM users WHERE name = ''John'';', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DESCRIBE"}, {"id": "B", "text": "EXPLAIN"}, {"id": "C", "text": "SHOW"}, {"id": "D", "text": "QUERY"}]', 'B', '''EXPLAIN'' 명령어를 사용하여 쿼리 실행 계획을 확인할 수 있습니다.'),
    (347, 3, 1, 287, '다음 중 SQL 인덱스의 장점은 무엇인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "검색 속도 향상"}, {"id": "B", "text": "데이터 무결성 향상"}, {"id": "C", "text": "쓰기 성능 저하"}, {"id": "D", "text": "정렬 기능 제공"}]', '["A", "D"]', '인덱스는 검색 속도를 향상시키고 정렬 기능을 제공합니다. 하지만 인덱스가 많아지면 쓰기 성능이 저하될 수 있습니다.'),
    (348, 3, 1, 288, 'SQL에서 인덱스가 과도하게 많아지면 어떤 문제가 발생할 수 있나요?', 'SHORT_ANSWER', NULL, '쓰기 성능 저하', '인덱스가 과도하게 많아지면 INSERT, UPDATE, DELETE 작업에서 성능 저하가 발생할 수 있습니다.'),
    (349, 3, 1, 289, '다음 SQL 쿼리의 출력에서 ''RANK()'' 함수는 어떤 역할을 하나요? SELECT student_id, score, RANK() OVER (ORDER BY score DESC) AS rank FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생의 점수를 내림차순으로 정렬하여 순위를 매긴다."}, {"id": "B", "text": "학생의 점수를 오름차순으로 정렬하여 순위를 매긴다."}, {"id": "C", "text": "각 학생에게 고유한 ID를 부여한다."}, {"id": "D", "text": "학생의 평균 점수를 계산한다."}]', 'A', '''RANK()'' 함수는 주어진 ORDER BY 조건에 따라 순위를 매깁니다.'),
    (350, 3, 1, 290, '다음 SQL 문에서 ''OVER()'' 절은 어떤 역할을 하나요? SELECT student_id, score, ROW_NUMBER() OVER () AS row_num FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 행에 대해 고유한 번호를 부여한다."}, {"id": "B", "text": "행을 그룹화하여 결과를 반환한다."}, {"id": "C", "text": "행을 단순히 정렬한다."}, {"id": "D", "text": "행의 평균을 계산한다."}]', 'A', '''OVER()'' 절은 윈도우 함수가 작동할 수 있는 범위를 정의하며, ROW_NUMBER()는 전체 결과 집합의 행에 대해 고유 번호를 부여합니다.'),
    (351, 3, 1, 291, '다음 SQL 쿼리에서 ''LAG(score, 1)''의 결과는 무엇인가요? SELECT student_id, score, LAG(score, 1) OVER (ORDER BY score) AS previous_score FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 학생의 점수를 반환한다."}, {"id": "B", "text": "다음 학생의 점수를 반환한다."}, {"id": "C", "text": "현재 행의 점수를 반환한다."}, {"id": "D", "text": "모든 학생의 평균 점수를 반환한다."}]', 'A', '''LAG(score, 1)''는 현재 행의 이전 행의 ''score'' 값을 반환합니다.'),
    (352, 3, 1, 292, '다음 옵션 중 윈도우 함수의 종류가 아닌 것은 무엇인가요? (RANK, ROW_NUMBER, SUM, LAG)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "RANK"}, {"id": "B", "text": "ROW_NUMBER"}, {"id": "C", "text": "SUM"}, {"id": "D", "text": "LAG"}]', '["C"]', '''SUM''은 집계 함수이며 윈도우 함수가 아닙니다.'),
    (353, 3, 1, 293, '윈도우 함수의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '행 간의 관계를 분석하고 특정 행에 대한 계산을 수행하는 것.', '윈도우 함수는 데이터를 그룹화하지 않고도 분석할 수 있게 도와줍니다.'),
    (354, 3, 1, 294, '다음 SQL 쿼리에서 ''salary_category''의 값으로 나올 수 없는 결과는 무엇인가요? 

 SELECT 
    employee_name,
    CASE 
        WHEN salary > 50000 THEN ''High''
        WHEN salary BETWEEN 30000 AND 50000 THEN ''Medium''
        ELSE ''Low''
    END AS salary_category
FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "High"}, {"id": "B", "text": "Medium"}, {"id": "C", "text": "Low"}, {"id": "D", "text": "Very High"}]', 'D', '''Very High''는 CASE문에서 정의되지 않은 범주입니다.'),
    (355, 3, 1, 295, 'CASE문을 사용하여 ''status''라는 열을 추가할 때 반환할 값으로 다음 중 어떤 것이 올 수 있는가? 

 SELECT 
    order_id,
    CASE 
        WHEN total > 100 THEN ''High''
        WHEN total BETWEEN 50 AND 100 THEN ''Medium''
        ELSE ''Low''
    END AS status
FROM orders;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "High"}, {"id": "B", "text": "Medium"}, {"id": "C", "text": "Low"}, {"id": "D", "text": "모두 가능하다"}]', 'D', '모든 범주가 CASE문에서 정의되고 조건에 따라 반환될 수 있습니다.'),
    (356, 3, 1, 296, '다음 SQL 쿼리에서 빈칸을 채우시오. 

 SELECT 
    product_name,
    CASE 
        WHEN price > 200 THEN ''Expensive''
        WHEN price < ____ THEN ''Cheap''
        ELSE ''Affordable''
    END AS price_category
FROM products;', 'SHORT_ANSWER', NULL, '100', '빈칸에는 ''100''을 채워야 ''Cheap'' 카테고리가 정의됩니다.'),
    (357, 3, 1, 297, 'CASE WHEN 문에서 사용할 수 있는 조건은 무엇인지 모두 선택하시오. 

 SELECT 
    student_name,
    CASE 
        WHEN score >= 90 THEN ''A''
        WHEN score >= 80 THEN ''B''
        ELSE ''C''
    END AS grade
FROM students;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "score >= 90"}, {"id": "B", "text": "score < 80"}, {"id": "C", "text": "score >= 80"}, {"id": "D", "text": "score < 70"}]', '["A", "C"]', '정확한 조건은 ''score >= 90''와 ''score >= 80''입니다.'),
    (358, 3, 1, 298, '아래 SQL 쿼리의 결과로 반환되는 ''result'' 컬럼의 값은 무엇인가요? SELECT student_name, score, CASE WHEN score >= 60 THEN ''Pass'' ELSE ''Fail'' END AS result FROM students;', 'SHORT_ANSWER', NULL, 'Pass 또는 Fail', '학생의 점수에 따라 ''Pass'' 또는 ''Fail''이 반환됩니다.'),
    (359, 3, 1, 299, '아래 SQL 쿼리에서 ''score''가 75인 경우 ''result'' 컬럼의 값은 무엇인가요? SELECT student_name, score, CASE WHEN score >= 60 THEN ''Pass'' ELSE ''Fail'' END AS result FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Pass"}, {"id": "B", "text": "Fail"}, {"id": "C", "text": "Incomplete"}, {"id": "D", "text": "Unknown"}]', 'A', 'score가 60 이상이므로 ''Pass''가 반환됩니다.'),
    (360, 3, 1, 300, '다음 SQL 쿼리에서 ''score''가 50일 때 ''result'' 컬럼의 값은 무엇인가요? SELECT student_name, score, CASE WHEN score >= 60 THEN ''Pass'' ELSE ''Fail'' END AS result FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Pass"}, {"id": "B", "text": "Fail"}, {"id": "C", "text": "Pass with conditions"}, {"id": "D", "text": "Failed"}]', 'B', 'score가 60 미만이므로 ''Fail''이 반환됩니다.'),
    (361, 3, 1, 301, '다음 코드의 결과를 맞는 것을 모두 선택하세요. SELECT student_name, score, CASE WHEN score >= 90 THEN ''A'' WHEN score >= 80 THEN ''B'' WHEN score >= 70 THEN ''C'' ELSE ''F'' END AS grade FROM students; condition: score >= 80, score >= 70', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "F"}]', '["B", "C"]', 'score가 80이상일 경우 ''B'', 70이상일 경우 ''C''로 평가됩니다.'),
    (362, 3, 1, 302, '다음 SQL 쿼리의 결과는 무엇인가요? SELECT department, COUNT(*) AS employee_count FROM employees GROUP BY department HAVING COUNT(*) > 5;', 'SHORT_ANSWER', NULL, '부서별로 직원 수가 5명 이상인 부서와 그 수량을 보여준다.', '해당 쿼리는 부서별로 직원을 세고, 5명 이상인 부서만 결과로 반환합니다.'),
    (363, 3, 1, 303, '다음 SQL 쿼리에서 GROUP BY 절의 목적은 무엇인가요? SELECT department, SUM(salary) FROM employees GROUP BY department;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부서별로 급여 합계를 계산하기 위해"}, {"id": "B", "text": "모든 직원의 급여를 나열하기 위해"}, {"id": "C", "text": "부서의 평균 급여를 구하기 위해"}, {"id": "D", "text": "부서 수를 세기 위해"}]', 'A', 'GROUP BY 절은 부서별로 데이터를 그룹화하여 급여 합계를 계산하기 위해 사용됩니다.'),
    (364, 3, 1, 304, 'HAVING 절이 필요한 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "GROUP BY로 그룹화한 데이터에 추가 조건을 적용하기 위해"}, {"id": "B", "text": "모든 데이터를 출력하기 위해"}, {"id": "C", "text": "WHERE 절을 대체하기 위해"}, {"id": "D", "text": "데이터를 정렬하기 위해"}]', 'A', 'HAVING 절은 GROUP BY로 그룹화한 데이터에 추가 필터링 조건을 적용하기 위해 사용됩니다.'),
    (365, 3, 1, 305, '다음 중 GROUP BY 절을 사용할 수 있는 경우는 어떤 것인가요? (복수 선택 가능) SELECT department, AVG(salary) FROM employees;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "부서별 평균 급여를 계산하고자 할 때"}, {"id": "B", "text": "모든 직원 정보를 나열하고자 할 때"}, {"id": "C", "text": "부서별로 총 급여를 계산하고자 할 때"}, {"id": "D", "text": "부서 수를 세고자 할 때"}]', '["A", "C"]', '부서별 평균 급여를 계산하거나 부서별 총 급여를 계산할 때 GROUP BY 절을 사용할 수 있습니다.'),
    (366, 3, 1, 306, '다음 SQL 쿼리에서 빈칸에 들어갈 가장 알맞은 코드를 선택하세요: SELECT customer_id, purchase_amount, CASE WHEN purchase_amount > 1000 THEN ''Gold'' WHEN purchase_amount BETWEEN _____ AND 1000 THEN ''Silver'' ELSE ''Bronze'' END AS customer_tier FROM customers;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "0"}, {"id": "B", "text": "500"}, {"id": "C", "text": "1000"}, {"id": "D", "text": "1500"}]', 'B', 'Silver 등급은 500에서 1000 사이의 구매 금액에 해당하므로 500이 들어가야 합니다.'),
    (367, 3, 1, 307, '다음 SQL 쿼리에서 ''Gold'' 등급의 고객 수를 카운트하려면 어떤 CASE 문을 사용하는 것이 가장 좋은가? SELECT COUNT(*), CASE WHEN purchase_amount > 1000 THEN ''Gold'' END AS gold_count FROM customers;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "COUNT(gold_count)"}, {"id": "B", "text": "COUNT(CASE WHEN purchase_amount > 1000 THEN 1 END)"}, {"id": "C", "text": "SUM(gold_count)"}, {"id": "D", "text": "SUM(CASE WHEN purchase_amount > 1000 THEN 1 END)"}]', 'B', '고객 수를 카운트하기 위해서는 CASE 문 안에서 1을 반환하게 하는 방식이 가장 적합합니다.'),
    (368, 3, 1, 308, '아래 SQL 쿼리의 출력 결과로 예상되는 값은 무엇인가요? SELECT customer_id, purchase_amount, CASE WHEN purchase_amount > 1000 THEN ''Gold'' WHEN purchase_amount BETWEEN 500 AND 1000 THEN ''Silver'' ELSE ''Bronze'' END AS customer_tier FROM (SELECT 1 as customer_id, 1200 as purchase_amount UNION ALL SELECT 2, 750 UNION ALL SELECT 3, 300) AS customers;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Gold, Silver, Bronze"}, {"id": "B", "text": "Silver, Silver, Silver"}, {"id": "C", "text": "Gold, Gold, Bronze"}, {"id": "D", "text": "Gold, Silver, Silver"}]', 'A', '첫 번째 고객은 Gold, 두 번째 고객은 Silver, 세 번째 고객은 Bronze 등급을 가집니다.'),
    (369, 3, 1, 309, '다음 중 ''CASE WHEN'' 구문을 사용하는 SQL 문에서 올바른 예시는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT CASE WHEN x > 10 THEN ''High'' ELSE ''Low'' END FROM table;"}, {"id": "B", "text": "SELECT * FROM table WHERE CASE WHEN x > 10 THEN 1 END;"}, {"id": "C", "text": "SELECT CASE WHEN x > 10 THEN ''High'' WHEN x < 5 THEN ''Low'' END FROM table;"}, {"id": "D", "text": "SELECT CASE WHEN x IS NULL THEN ''Unknown'' ELSE x END FROM table;"}]', '["A", "C", "D"]', 'A, C, D 모두 CASE WHEN 구문을 제대로 사용하고 있습니다.'),
    (370, 3, 1, 310, 'CASE 문에서 조건이 여러 개인 경우, 첫 번째 조건이 만족되지 않으면 어떤 조건이 평가됩니까?', 'SHORT_ANSWER', NULL, '다음 조건이 평가됩니다.', 'CASE 문은 조건을 위에서부터 순서대로 평가하며, 첫 번째 조건이 만족되지 않으면 다음 조건으로 넘어갑니다.'),
    (371, 3, 1, 311, '다음 SQL 쿼리에서 어떤 레코드에 대해 잠금을 걸까요? `SELECT * FROM accounts WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "id가 1인 계정"}, {"id": "B", "text": "id가 2인 계정"}, {"id": "C", "text": "모든 계정"}, {"id": "D", "text": "잠금 없음"}]', 'A', '쿼리는 id가 1인 계정에 대해 잠금을 겁니다.'),
    (372, 3, 1, 312, '다음 쿼리에 대해 올바른 결과를 예측하시오: `SELECT balance FROM accounts WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 잔액을 반환"}, {"id": "B", "text": "모든 계좌 정보를 반환"}, {"id": "C", "text": "id=1에 대한 업데이트를 수행"}, {"id": "D", "text": "오류 발생"}]', 'A', '쿼리는 id가 1인 계정의 현재 잔액을 반환합니다.'),
    (373, 3, 1, 313, '트랜잭션의 원자성을 보장하기 위해, 아래의 빈칸을 채우시오: ''트랜잭션은 ________ 또는 ________ 되어야 한다.''', 'SHORT_ANSWER', NULL, '모두 성공적으로 완료되거나 모두 롤백', '트랜잭션은 원자성이 있어야 하며, 모든 작업이 성공적으로 완료되거나 전부 롤백되어야 합니다.'),
    (374, 3, 1, 314, '다음 SQL 쿼리의 작동 방식에서 어떤 상황이 발생할 수 있을까요? `BEGIN; SELECT * FROM accounts WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "다른 트랜잭션이 id=1을 수정할 수 없음"}, {"id": "B", "text": "쿼리 실행 중 오류 발생"}, {"id": "C", "text": "트랜잭션이 자동으로 커밋됨"}, {"id": "D", "text": "데이터베이스의 일관성이 유지됨"}]', '["A", "D"]', '트랜잭션이 시작되고 레코드에 잠금이 걸리며, 이는 데이터베이스의 일관성을 유지합니다.'),
    (375, 3, 1, 315, '다음 SQL 쿼리의 결과는 무엇인가요? SELECT COALESCE(NULL, ''Default'', ''Value'') AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Default"}, {"id": "B", "text": "Value"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "Error"}]', 'A', 'COALESCE()는 NULL을 만나면 다음 인자를 반환하므로 ''Default''가 결과로 나옵니다.'),
    (376, 3, 1, 316, 'IFNULL() 함수의 사용법은 다음 중 어떤 것이 맞습니까? IFNULL(column_name, default_value)에서 column_name이 NULL이라면?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "default_value를 반환한다."}, {"id": "B", "text": "NULL을 반환한다."}, {"id": "C", "text": "에러가 발생한다."}, {"id": "D", "text": "column_name을 반환한다."}]', 'A', 'IFNULL()는 첫 번째 인자가 NULL일 경우 두 번째 인자를 반환합니다.'),
    (377, 3, 1, 317, '다음 SQL 코드에서 빈칸을 채우세요: SELECT AVG(salary) FROM employees WHERE salary IS NOT NULL;', 'SHORT_ANSWER', NULL, 'NULL', '이 쿼리는 salary가 NULL이 아닌 경우의 평균을 계산합니다.'),
    (378, 3, 1, 318, 'COALESCE()와 IFNULL()은 어떤 상황에서 사용되나요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NULL 값 대체"}, {"id": "B", "text": "데이터 집계"}, {"id": "C", "text": "조건부 연산"}, {"id": "D", "text": "값 선택"}]', '["A", "D"]', 'COALESCE()와 IFNULL()은 주로 NULL 값을 대체하는 데 사용되며, 특정 값을 선택할 때 유용합니다.'),
    (379, 3, 1, 319, '다음 SQL 쿼리의 목적은 무엇인가? `SELECT * FROM accounts WHERE id = 1 FOR UPDATE`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "계좌 정보를 조회하고 잠금 설정"}, {"id": "B", "text": "계좌 정보를 삭제"}, {"id": "C", "text": "계좌 정보를 업데이트"}, {"id": "D", "text": "계좌 정보를 삽입"}]', 'A', '이 쿼리는 id가 1인 계좌의 정보를 조회하면서 해당 행을 잠그어 다른 트랜잭션이 수정할 수 없도록 만듭니다.'),
    (380, 3, 1, 320, '트랜잭션의 ACID 원칙 중 ''Isolation''의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원자성 보장"}, {"id": "B", "text": "일관성 유지"}, {"id": "C", "text": "다른 트랜잭션의 영향으로부터 보호"}, {"id": "D", "text": "영구성 보장"}]', 'C', '''Isolation''은 트랜잭션이 실행되는 동안 다른 트랜잭션의 영향을 받지 않도록 보호하는 것을 의미합니다.'),
    (381, 3, 1, 321, '트랜잭션이 수행되는 동안 다른 트랜잭션이 동일한 데이터를 수정할 수 없도록 하기 위해 사용하는 SQL 키워드는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LOCK"}, {"id": "B", "text": "FOR UPDATE"}, {"id": "C", "text": "BEGIN"}, {"id": "D", "text": "COMMIT"}]', 'B', 'FOR UPDATE는 행을 잠그어 다른 트랜잭션이 동일한 데이터를 수정하려 할 때 대기하도록 만듭니다.'),
    (382, 3, 1, 322, '트랜잭션의 올바른 순서를 선택하세요. 1. `BEGIN TRANSACTION` 2. `UPDATE accounts SET balance = balance - 100 WHERE id = 1` 3. `COMMIT`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 2, 3"}, {"id": "B", "text": "2, 1, 3"}, {"id": "C", "text": "3, 1, 2"}, {"id": "D", "text": "1, 3, 2"}]', '["A"]', '트랜잭션은 BEGIN에서 시작하고, 작업을 수행한 후 COMMIT하여 완료됩니다.'),
    (383, 3, 1, 323, 'SQL 트랜잭션을 시작하는 키워드는 무엇인가?', 'SHORT_ANSWER', NULL, 'BEGIN TRANSACTION', '트랜잭션을 시작하기 위해 ''BEGIN TRANSACTION'' 키워드를 사용합니다.'),
    (384, 3, 1, 324, '다음 SQL 문에서 인덱스를 생성하는 방법은 무엇인가요? `CREATE INDEX __ ON employees(last_name);`', 'SHORT_ANSWER', NULL, 'idx_name', '인덱스의 이름을 ''idx_name''으로 정의해야 합니다.'),
    (385, 3, 1, 325, '아래 SQL 쿼리의 실행 계획을 확인하기 위한 올바른 SQL 문은 무엇인가요? `SELECT * FROM employees WHERE last_name = ''Smith'';`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EXPLAIN SELECT * FROM employees WHERE last_name = ''Smith'';"}, {"id": "B", "text": "SHOW PLAN SELECT * FROM employees WHERE last_name = ''Smith'';"}, {"id": "C", "text": "DESCRIBE SELECT * FROM employees WHERE last_name = ''Smith'';"}, {"id": "D", "text": "ANALYZE SELECT * FROM employees WHERE last_name = ''Smith'';"}]', 'A', '실행 계획을 확인하기 위해 ''EXPLAIN'' 명령어를 사용해야 합니다.'),
    (386, 3, 1, 326, '다음 SQL 문에서 인덱스를 삭제하는 명령어는 무엇인가요? `DROP __ idx_name;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "INDEX"}, {"id": "B", "text": "INDEXES"}, {"id": "C", "text": "INDICES"}, {"id": "D", "text": "DROP INDEXES"}]', 'A', '인덱스를 삭제할 때는 ''DROP INDEX''를 사용해야 합니다.'),
    (387, 3, 1, 327, '인덱스를 활용하여 성능을 향상시킬 수 있는 상황은 무엇인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "대량 데이터에서 특정 값을 검색할 때"}, {"id": "B", "text": "단일 행을 업데이트할 때"}, {"id": "C", "text": "정렬된 결과를 빠르게 얻고자 할 때"}, {"id": "D", "text": "모든 데이터를 삭제할 때"}]', '["A", "C"]', '인덱스는 대량 데이터에서 특정 값을 검색하거나 정렬된 결과를 빠르게 얻을 때 성능을 높입니다.'),
    (388, 3, 1, 328, '다음 SQL 쿼리의 출력 결과는 무엇인가요? SELECT COALESCE(NULL, 5, NULL) AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "5"}, {"id": "B", "text": "NULL"}, {"id": "C", "text": "0"}, {"id": "D", "text": "첫번째 NULL"}]', 'A', 'COALESCE 함수는 첫 번째 NULL이 아닌 값을 반환하므로 5가 출력됩니다.'),
    (389, 3, 1, 329, '다음 SQL 문에서 IFNULL 함수의 결과로 올바른 것은 무엇인가요? SELECT IFNULL(NULL, 10) AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "10"}, {"id": "B", "text": "NULL"}, {"id": "C", "text": "0"}, {"id": "D", "text": "첫번째 NULL"}]', 'A', 'IFNULL 함수는 첫 번째 인자가 NULL일 때 두 번째 인자인 10을 반환합니다.'),
    (390, 3, 1, 330, '아래 SQL에서 COALESCE를 이용해 빈칸을 채우세요: SELECT COALESCE(____, ''N/A'') FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "column_name"}, {"id": "B", "text": "NULL"}, {"id": "C", "text": "0"}, {"id": "D", "text": "DEFAULT"}]', 'A', 'COALESCE 함수는 column_name이 NULL일 경우 ''N/A''를 반환합니다.'),
    (391, 3, 1, 331, 'NULL 값 처리를 위해 사용되는 두 함수는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "COALESCE"}, {"id": "B", "text": "IFNULL"}, {"id": "C", "text": "SUM"}, {"id": "D", "text": "AVG"}]', '["A", "B"]', 'COALESCE와 IFNULL 함수는 NULL 값을 처리하는 데 사용됩니다.'),
    (392, 3, 1, 332, 'COALESCE 함수의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NULL이 아닌 첫 번째 값을 반환하는 것', 'COALESCE 함수는 인자로 받은 값 중에서 NULL이 아닌 첫 번째 값을 반환하는 기능을 가집니다.'),
    (393, 3, 1, 333, '다음 SQL 쿼리의 실행 결과로 올바른 것은 무엇인가요? SELECT COALESCE(NULL, ''test'', ''example'') AS result;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "test"}, {"id": "B", "text": "example"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "error"}]', 'A', 'COALESCE는 첫 번째로 NULL이 아닌 ''test''를 반환합니다.'),
    (394, 3, 1, 334, '다음 SQL 문에서 빈칸에 들어갈 코드는 무엇인가요? SELECT IFNULL(column_name, _____) AS result FROM table;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "0"}, {"id": "B", "text": "NULL"}, {"id": "C", "text": "''default''"}, {"id": "D", "text": "column_name"}]', 'C', 'IFNULL은 NULL일 경우 대체할 값을 지정해야 하므로 ''default''가 적합합니다.'),
    (395, 3, 1, 335, '다음 SQL 쿼리의 목적은 무엇인가요? SELECT COUNT(*) FROM table WHERE column_name IS NOT NULL;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL 값을 세기 위해"}, {"id": "B", "text": "NULL이 아닌 값을 세기 위해"}, {"id": "C", "text": "모든 값을 세기 위해"}, {"id": "D", "text": "중복된 값을 세기 위해"}]', 'B', '이 쿼리는 NULL이 아닌 값의 개수를 세기 위한 것입니다.'),
    (396, 3, 1, 336, 'COALESCE 함수는 몇 개의 인자를 받을 수 있나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1개"}, {"id": "B", "text": "2개"}, {"id": "C", "text": "3개"}, {"id": "D", "text": "무제한"}]', '["B", "D"]', 'COALESCE 함수는 최소 2개 이상의 인자를 필요로 하며, 무제한 인자를 받을 수 있습니다.'),
    (397, 3, 1, 337, 'IFNULL 함수의 기본적인 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NULL 값을 다른 값으로 대체하는 것', 'IFNULL 함수는 NULL일 경우 대체할 값을 지정하는 기능을 합니다.'),
    (398, 3, 1, 338, '트랜잭션에서 ROLLBACK의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '변경 사항을 취소하고 데이터베이스를 이전 상태로 되돌린다.', 'ROLLBACK은 트랜잭션 중 오류가 발생했을 때, 수행된 모든 변경 사항을 취소하여 데이터베이스를 일관된 상태로 되돌리는 역할을 한다.'),
    (399, 3, 1, 339, '다음 SQL 문을 완성하시오: SELECT * FROM accounts WHERE id = 1 _____;', 'SHORT_ANSWER', NULL, 'FOR UPDATE', '''FOR UPDATE''는 해당 행을 수정하기 위해 잠그는 역할을 한다.'),
    (400, 3, 1, 340, '트랜잭션의 ACID 속성 중 하나가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Atomicity"}, {"id": "B", "text": "Consistency"}, {"id": "C", "text": "Isolation"}, {"id": "D", "text": "Scalability"}]', 'D', 'ACID 속성은 Atomicity, Consistency, Isolation, Durability로 구성되며, Scalability는 포함되지 않는다.'),
    (401, 3, 1, 341, '다음 중 FOR UPDATE 구문을 사용할 수 있는 상황은 무엇인가요? (복수 정답 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 읽기만 할 때"}, {"id": "B", "text": "데이터를 수정할 때"}, {"id": "C", "text": "행을 잠그고 싶을 때"}, {"id": "D", "text": "트랜잭션을 종료할 때"}]', '["B", "C"]', 'FOR UPDATE 구문은 데이터 수정 시 해당 행을 잠그고자 할 때 사용하며, 데이터 읽기만 할 때는 필요하지 않다.'),
    (402, 3, 1, 342, '트랜잭션이 완료된 후 데이터를 확정하는 SQL 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ROLLBACK"}, {"id": "B", "text": "COMMIT"}, {"id": "C", "text": "SAVEPOINT"}, {"id": "D", "text": "BEGIN"}]', 'B', 'COMMIT 명령어는 트랜잭션의 변경 사항을 확정하여 데이터베이스에 반영하는 역할을 한다.'),
    (403, 3, 1, 343, '다음 SQL 문을 실행했을 때 출력 결과는 무엇인가요?

SELECT COALESCE(NULL, ''Hello'', ''World'');', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello"}, {"id": "B", "text": "World"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "Error"}]', 'A', 'COALESCE 함수는 NULL인 인수를 건너뛰고 첫 번째 NULL이 아닌 값을 반환합니다.'),
    (404, 3, 1, 344, '다음 SQL 문에서 ''value''가 NULL일 경우 반환되는 값은?

SELECT IFNULL(value, ''N/A'') FROM example_table;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "value"}, {"id": "B", "text": "N/A"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "Error"}]', 'B', 'IFNULL 함수는 첫 번째 인수가 NULL일 때 두 번째 인수를 반환합니다.'),
    (405, 3, 1, 345, '다음 SQL 문에서 빈칸에 들어갈 적절한 함수는 무엇인가요?

SELECT ___(column_name, ''default'') FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "IFNULL"}, {"id": "B", "text": "COALESCE"}, {"id": "C", "text": "CASE"}, {"id": "D", "text": "NULLIF"}]', 'A', '빈칸에는 IFNULL이나 COALESCE가 적합하지만, 여기서는 IFNULL을 사용하여 NULL을 ''default''로 처리할 수 있습니다.'),
    (406, 3, 1, 346, 'NULL 값을 처리하기 위한 SQL의 집계 함수 두 가지를 모두 적으세요.', 'SHORT_ANSWER', NULL, 'COALESCE, IFNULL', 'COALESCE와 IFNULL은 NULL 값을 처리하는 SQL의 주요 함수입니다.'),
    (407, 3, 1, 347, '다음 SQL을 실행할 때 COALESCE가 반환하는 값은?

SELECT COALESCE(NULL, 15, NULL, 25);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL"}, {"id": "B", "text": "15"}, {"id": "C", "text": "25"}, {"id": "D", "text": "Error"}]', 'B', 'COALESCE 함수는 첫 번째 NULL이 아닌 값을 반환합니다. 이 경우 15가 첫 번째로 NULL이 아닌 값입니다.'),
    (408, 3, 1, 348, '다음 SQL 쿼리의 결과로 예상되는 값은 무엇인가? SELECT COALESCE(NULL, ''Hello'', ''World'');', 'SHORT_ANSWER', NULL, 'Hello', 'COALESCE 함수는 NULL이 아닌 첫 번째 값을 반환합니다.'),
    (409, 3, 1, 349, '다음 SQL 쿼리에서 NULL 값을 처리하기 위해 사용된 함수는 무엇인가? SELECT IFNULL(column_name, 0) FROM table_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "IFNULL"}, {"id": "B", "text": "COALESCE"}, {"id": "C", "text": "SUM"}, {"id": "D", "text": "COUNT"}]', 'A', 'IFNULL 함수는 첫 번째 인자가 NULL일 경우 두 번째 인자를 반환합니다.'),
    (410, 3, 1, 350, '다음 SQL 쿼리의 결과를 예측하시오: SELECT SUM(column_name) FROM table_name WHERE column_name IS NOT NULL;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL"}, {"id": "B", "text": "0"}, {"id": "C", "text": "합계"}, {"id": "D", "text": "에러"}]', 'C', 'SUM 함수는 NULL 값을 포함하지 않고 합계를 계산합니다.'),
    (411, 3, 1, 351, '다음 중 COALESCE 함수를 사용한 SQL 쿼리로 적절한 것은? SELECT COALESCE(column1, column2) FROM table_name;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NULL을 반환한다."}, {"id": "B", "text": "column1이 NULL이 아니면 column1을 반환한다."}, {"id": "C", "text": "column2가 항상 반환된다."}, {"id": "D", "text": "column1과 column2 모두 NULL이면 NULL을 반환한다."}]', '["B", "D"]', 'COALESCE 함수는 첫 번째 NULL이 아닌 값을 반환하며, 모든 인자가 NULL일 경우 NULL을 반환합니다.'),
    (412, 3, 1, 352, 'IFNULL 함수의 구문은 무엇인가?', 'SHORT_ANSWER', NULL, 'IFNULL(expression, default_value)', 'IFNULL 함수는 첫 번째 인자가 NULL일 경우 두 번째 인자를 반환하는 함수입니다.'),
    (413, 3, 1, 353, '다음 SQL 쿼리의 결과로 반환되는 값은 무엇인가? 

SELECT employee_id, salary, 
CASE 
    WHEN salary > 50000 THEN ''High'' 
    WHEN salary BETWEEN 30000 AND 50000 THEN ''Medium'' 
    ELSE ''Low'' 
END AS salary_range 
FROM employees;

(직원의 급여가 55000일 경우)', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''High''"}, {"id": "B", "text": "''Medium''"}, {"id": "C", "text": "''Low''"}, {"id": "D", "text": "''Unknown''"}]', 'A', '직원의 급여가 55000이므로 ''High'' 범주에 해당합니다.'),
    (414, 3, 1, 354, '다음 SQL 쿼리에서 ''salary_range''의 값이 ''Medium''이 되기 위해 salary의 범위는 무엇인가? 

CASE 
    WHEN salary > 50000 THEN ''High'' 
    WHEN salary BETWEEN 30000 AND 50000 THEN ''Medium'' 
    ELSE ''Low'' 
END AS salary_range', 'SHORT_ANSWER', NULL, '30000 이상 50000 이하', '급여가 30000 이상 50000 이하일 때 ''Medium'' 범주에 해당합니다.'),
    (415, 3, 1, 355, 'CASE WHEN 문에서 ELSE 절은 언제 사용되며, 여기서 어떤 역할을 하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 경우의 수를 다루기 위해 사용된다."}, {"id": "B", "text": "조건이 만족하지 않는 경우의 기본값을 제공한다."}, {"id": "C", "text": "여러 조건을 동시에 평가하기 위해 사용된다."}, {"id": "D", "text": "없어도 무관하다."}]', 'B', 'ELSE 절은 모든 조건이 만족하지 않을 경우 반환할 기본값을 제공합니다.'),
    (416, 3, 1, 356, '다음 SQL 구문에서 빈칸에 들어갈 알맞은 SQL 키워드는 무엇인가? 

SELECT employee_id, salary, 
CASE 
    WHEN salary > 50000 THEN ''High'' 
    WHEN salary BETWEEN 30000 AND 50000 THEN ''Medium'' 
    ____ ''Low'' 
END AS salary_range 
FROM employees;', 'SHORT_ANSWER', NULL, 'ELSE', 'ELSE 키워드는 모든 조건이 만족하지 않을 때 사용할 기본값을 정의합니다.'),
    (417, 3, 1, 357, '다음 조건을 만족하는 경우를 모두 선택하시오. 

CASE 
    WHEN salary < 30000 THEN ''Very Low'' 
    WHEN salary BETWEEN 30000 AND 60000 THEN ''Medium'' 
    WHEN salary > 60000 THEN ''High'' 
END', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "salary = 25000"}, {"id": "B", "text": "salary = 45000"}, {"id": "C", "text": "salary = 70000"}, {"id": "D", "text": "salary = 35000"}]', '["A", "B", "C", "D"]', '모든 경우가 주어진 CASE 문에서 각각의 조건을 만족합니다.'),
    (418, 3, 1, 358, '다음 SQL 쿼리의 결과는 무엇인가요?

SELECT student_name,
       grade,
       CASE
           WHEN grade >= 90 THEN ''A''
           WHEN grade >= 80 THEN ''B''
           WHEN grade >= 70 THEN ''C''
           WHEN grade >= 60 THEN ''D''
           ELSE ''F''
       END AS grade_letter
FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생의 성적을 등급으로 반환한다"}, {"id": "B", "text": "학생의 성적 순위를 반환한다"}, {"id": "C", "text": "학생의 이름과 합격 여부를 반환한다"}, {"id": "D", "text": "학생의 평균 성적을 반환한다"}]', 'A', '이 쿼리는 학생의 성적을 등급으로 반환하는 CASE 구문을 사용하고 있습니다.'),
    (419, 3, 1, 359, '다음 빈칸에 알맞은 코드를 넣으세요:

SELECT product_name, price,
       CASE
           WHEN price < 1000 THEN ''저가''
           WHEN price BETWEEN 1000 AND 5000 THEN ''중가''
           WHEN price > 5000 THEN ''고가''
           ELSE ''가격 미정''
       END AS price_category
FROM products;', 'SHORT_ANSWER', NULL, 'price', '빈칸에는 ''price''가 들어가야 가격을 기준으로 카테고리화 할 수 있습니다.'),
    (420, 3, 1, 360, '다음 중 복수 정답을 고르세요. SQL의 CASE WHEN 구문을 사용할 수 있는 경우는?

SELECT product_name,
       CASE
           WHEN condition1 THEN ''result1''
           WHEN condition2 THEN ''result2''
           ELSE ''result3''
       END AS result
FROM products;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "판매 가격에 따라 가격 범주를 정할 때"}, {"id": "B", "text": "직원의 연봉 수준을 결정할 때"}, {"id": "C", "text": "학생의 성적을 계산할 때"}, {"id": "D", "text": "데이터를 정렬할 때"}]', '["A", "B", "C"]', 'CASE WHEN 구문은 다양한 조건을 기반으로 값을 결정할 수 있어, 가격, 연봉, 성적 등에 적용할 수 있습니다.'),
    (421, 3, 1, 361, 'CASE WHEN 구문을 사용하여 데이터의 조건에 따라 결과 값이 다르게 설정할 수 있는 SQL의 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '조건 분기', 'CASE WHEN 구문은 조건 분기를 통해 다양한 상황에 맞는 결과를 생성할 수 있습니다.'),
    (422, 3, 1, 362, '아래 SQL 문을 실행할 때 어떤 동작이 발생하는가? `SELECT * FROM accounts WHERE id = 1 FOR UPDATE;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "레코드를 잠금"}, {"id": "B", "text": "레코드를 삭제"}, {"id": "C", "text": "레코드를 업데이트"}, {"id": "D", "text": "레코드를 선택만 한다"}]', 'A', '`FOR UPDATE`는 해당 레코드를 잠글 때 사용되므로, 이 문장은 레코드를 잠금니다.'),
    (423, 3, 1, 363, '트랜잭션에서 `COMMIT`의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "변경 사항을 확정짓고 저장"}, {"id": "B", "text": "변경 사항을 취소"}, {"id": "C", "text": "트랜잭션을 시작"}, {"id": "D", "text": "트랜잭션을 종료"}]', 'A', '`COMMIT`은 트랜잭션 내의 모든 변경 사항을 확정하고 데이터베이스에 저장합니다.'),
    (424, 3, 1, 364, '아래 빈칸을 채우세요: `BEGIN; UPDATE accounts SET balance = balance - 100 WHERE id = 1; ______;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ROLLBACK;"}, {"id": "B", "text": "COMMIT;"}, {"id": "C", "text": "SELECT;"}, {"id": "D", "text": "FOR UPDATE;"}]', 'B', '트랜잭션을 완료하고 변경 사항을 저장하기 위해서는 `COMMIT;`을 사용해야 합니다.'),
    (425, 3, 1, 365, '트랜잭션의 ACID 속성 중 ''C''는 무엇을 의미하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "고립성"}, {"id": "C", "text": "원자성"}, {"id": "D", "text": "지속성"}]', '["A", "B", "C", "D"]', 'ACID는 원자성, 일관성, 고립성, 지속성의 약자입니다. 모든 속성이 트랜잭션에서 중요합니다.'),
    (426, 3, 1, 366, '트랜잭션을 시작하는 SQL 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'BEGIN', '트랜잭션을 시작하기 위해 사용되는 명령어는 `BEGIN`입니다.'),
    (427, 3, 1, 367, '트랜잭션을 시작하는 SQL 구문은 무엇인가요?', 'SHORT_ANSWER', NULL, 'BEGIN TRANSACTION', '트랜잭션을 시작하기 위해 사용하는 SQL 구문은 ''BEGIN TRANSACTION''입니다.'),
    (428, 3, 1, 368, '아래 SQL 문에서 ''FOR UPDATE''의 역할은 무엇인가요?

SELECT * FROM employees WHERE id = 1 FOR UPDATE;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "레코드를 잠근다."}, {"id": "B", "text": "레코드를 삭제한다."}, {"id": "C", "text": "레코드를 조회한다."}, {"id": "D", "text": "레코드의 값을 업데이트한다."}]', 'A', '''FOR UPDATE''는 해당 레코드를 잠궈 다른 트랜잭션에서 수정할 수 없도록 합니다.'),
    (429, 3, 1, 369, '다음 중 트랜잭션의 ACID 속성이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원자성"}, {"id": "B", "text": "일관성"}, {"id": "C", "text": "신뢰성"}, {"id": "D", "text": "지속성"}]', 'C', 'ACID 속성 중 ''신뢰성''은 포함되지 않으며, 원자성, 일관성, 격리성, 지속성이 포함됩니다.'),
    (430, 3, 1, 370, '트랜잭션 중 어떤 SQL 문을 사용하는 것이 가장 적절한가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "BEGIN TRANSACTION"}, {"id": "B", "text": "COMMIT"}, {"id": "C", "text": "ROLLBACK"}, {"id": "D", "text": "SELECT * FROM data"}]', '["A", "B", "C"]', '트랜잭션을 관리하기 위해 ''BEGIN TRANSACTION'', ''COMMIT'', ''ROLLBACK''을 사용합니다.'),
    (431, 3, 1, 371, '락을 사용하지 않은 경우 발생할 수 있는 문제는 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터 무결성 손상', '락을 사용하지 않으면 동시성 문제로 인해 데이터 무결성이 손상될 수 있습니다.'),
    (432, 3, 1, 372, '다음 SQL 쿼리의 출력 결과는 무엇인가요? `SELECT * FROM employees INNER JOIN departments ON employees.department_id = departments.id;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "직원과 부서의 모든 정보가 결합된 테이블"}, {"id": "B", "text": "부서 정보만 출력"}, {"id": "C", "text": "직원 정보만 출력"}, {"id": "D", "text": "결과 없음"}]', 'A', '이 쿼리는 INNER JOIN을 사용하여 employees 테이블과 departments 테이블을 결합하여 관련된 모든 정보를 출력합니다.'),
    (433, 3, 1, 373, '빈칸을 채우십시오: `SELECT name FROM employees WHERE department_id IN (SELECT id FROM ____ WHERE location = ''New York'');`', 'SHORT_ANSWER', NULL, 'departments', '서브쿼리에서 부서의 ID를 가져오기 위해 ''departments'' 테이블을 참조해야 합니다.'),
    (434, 3, 1, 374, 'JOIN의 어떤 유형이 기본적으로 두 테이블의 교집합을 반환합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "INNER JOIN"}, {"id": "B", "text": "LEFT JOIN"}, {"id": "C", "text": "RIGHT JOIN"}, {"id": "D", "text": "FULL OUTER JOIN"}]', 'A', 'INNER JOIN은 두 테이블의 교집합, 즉 조건을 만족하는 레코드만 반환합니다.'),
    (435, 3, 1, 375, '다음 중 JOIN과 서브쿼리에 해당하는 SQL 쿼리의 예시를 모두 고르시오: `A: SELECT * FROM orders INNER JOIN customers ON orders.customer_id = customers.id; B: SELECT * FROM products WHERE price > (SELECT AVG(price) FROM products); C: SELECT * FROM categories; D: SELECT * FROM sales LEFT JOIN products ON sales.product_id = products.id;`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "D"}]', '["A", "B", "D"]', 'A와 D는 JOIN을 사용하고, B는 서브쿼리를 사용하여 조건에 맞는 데이터를 필터링하는 예시입니다.'),
    (436, 3, 1, 376, '다음 SQL 코드는 어떤 값을 반환할까요? SELECT grade, CASE WHEN score >= 90 THEN ''A'' WHEN score >= 80 THEN ''B'' ELSE ''C'' END AS grade_category FROM students; score가 85인 경우.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''B''"}, {"id": "B", "text": "''A''"}, {"id": "C", "text": "''C''"}, {"id": "D", "text": "''D''"}]', 'A', 'score가 85일 때, CASE 조건 중 ''WHEN score >= 80''에 해당하여 ''B''가 반환됩니다.'),
    (437, 3, 1, 377, '다음 SQL 코드에서 결과로 나오는 grade_category의 값은 무엇인가요? SELECT age, CASE WHEN age < 18 THEN ''Minor'' WHEN age BETWEEN 18 AND 65 THEN ''Adult'' ELSE ''Senior'' END AS age_group FROM people; age가 70인 경우.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''Adult''"}, {"id": "B", "text": "''Senior''"}, {"id": "C", "text": "''Minor''"}, {"id": "D", "text": "''Young Adult''"}]', 'B', 'age가 70일 때, CASE 조건 중 ''ELSE''에 해당하여 ''Senior''가 반환됩니다.'),
    (438, 3, 1, 378, '다음 SQL 문에서 빈칸에 들어갈 알맞은 단어는 무엇인가요? SELECT department, COUNT(*) FROM employees GROUP BY department HAVING COUNT(*) > 10 AND CASE WHEN location = ''NY'' THEN ''True'' ELSE ''False'' END = ''True'';', 'SHORT_ANSWER', NULL, 'True', 'CASE WHEN 구문이 ''True''일 때 해당 부서의 카운트가 10을 초과하는 조건을 만족해야 합니다.'),
    (439, 3, 1, 379, '다음 SQL 구문에서 반환될 수 있는 grade_category의 값은 무엇일까요? SELECT score, CASE WHEN score >= 90 THEN ''A'' WHEN score >= 80 THEN ''B'' WHEN score >= 70 THEN ''C'' ELSE ''F'' END AS grade_category FROM scores; score가 75일 때.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "''C''"}, {"id": "B", "text": "''F''"}, {"id": "C", "text": "''A''"}, {"id": "D", "text": "''B''"}]', '["A"]', 'score가 75일 때, ''C'' 조건을 만족하여 ''C''가 반환됩니다.'),
    (440, 3, 1, 380, '다음 SQL 쿼리의 실행 결과로 나올 수 있는 ''rank'' 컬럼의 값은 어떻게 될까요? SELECT employee_id, salary, RANK() OVER (ORDER BY salary DESC) AS rank FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "급여가 높은 순서로 1, 2, 3, ..."}, {"id": "B", "text": "급여가 낮은 순서로 1, 2, 3, ..."}, {"id": "C", "text": "모든 직원이 1로 표시된다."}, {"id": "D", "text": "급여가 같은 직원이 동일한 순위를 가진다."}]', 'D', 'RANK() 함수는 동일한 값을 가진 행에 대해 동일한 순위를 부여하므로, 급여가 같은 직원은 동일한 순위를 가집니다.'),
    (441, 3, 1, 381, '다음 SQL 쿼리에서 ''previous_salary''의 결과는 무엇인가요? SELECT employee_id, salary, LAG(salary) OVER (ORDER BY salary DESC) AS previous_salary FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 행의 급여"}, {"id": "B", "text": "이전 행의 급여"}, {"id": "C", "text": "첫 번째 행의 급여"}, {"id": "D", "text": "임의의 급여"}]', 'B', 'LAG() 함수는 현재 행을 기준으로 이전 행의 값을 참조하므로, ''previous_salary''는 이전 행의 급여를 나타냅니다.'),
    (442, 3, 1, 382, '다음 SQL 쿼리에서 빈칸에 들어갈 가장 적절한 함수는 무엇인가요? SELECT employee_id, salary, ___() OVER (ORDER BY salary DESC) FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ROW_NUMBER"}, {"id": "B", "text": "RANK"}, {"id": "C", "text": "LAG"}, {"id": "D", "text": "SUM"}]', 'A', 'ROW_NUMBER() 함수를 사용하여 각 행에 대해 고유한 번호를 부여할 수 있습니다.'),
    (443, 3, 1, 383, 'RANK, DENSE_RANK의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "동일한 값을 가진 행에 대해 RANK는 중복 순위를 주지만 DENSE_RANK는 주지 않는다."}, {"id": "B", "text": "RANK는 항상 연속된 순위를 가지며 DENSE_RANK는 불연속 순위를 가질 수 있다."}, {"id": "C", "text": "두 함수는 동일한 방식으로 동작한다."}, {"id": "D", "text": "DENSE_RANK는 더 많은 행을 반환할 수 있다."}]', '["A", "B"]', 'RANK는 동일한 값에 대해 중복 순위를 부여하고, 그로 인해 남겨지는 순위가 생길 수 있지만, DENSE_RANK는 중복된 값을 가진 행 모두에 대해 동일한 순위를 부여하고 연속된 순위를 유지합니다.'),
    (444, 3, 1, 384, '윈도우 함수의 주요 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '특정 데이터 집합에 대해 계산을 수행하고, 결과를 각 행에 대한 추가 정보로 반환하는 것', ''),
    (445, 3, 1, 385, '다음 SQL 문장에서 FOR UPDATE 구문의 역할은 무엇인가요?

SELECT * FROM accounts WHERE id = 1 FOR UPDATE;', 'SHORT_ANSWER', NULL, '특정 행을 잠궈 다른 트랜잭션에서 수정할 수 없게 한다.', 'FOR UPDATE는 해당 행에 대한 잠금을 적용하여 다른 트랜잭션이 동시에 수정할 수 없게 합니다.'),
    (446, 3, 1, 386, '아래 SQL 문장에서 어떤 결과를 예상할 수 있나요?

BEGIN;
SELECT * FROM accounts WHERE id = 1 FOR UPDATE;
UPDATE accounts SET balance = balance - 50 WHERE id = 1;
COMMIT;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "id가 1인 계좌의 잔액이 50 감소한다."}, {"id": "B", "text": "id가 1인 계좌의 잔액이 50 증가한다."}, {"id": "C", "text": "트랜잭션이 실패한다."}, {"id": "D", "text": "아무런 변화도 없다."}]', 'A', '위 SQL 문장은 트랜잭션 내에서 id가 1인 계좌의 잔액을 50 감소시키는 작업을 수행합니다.'),
    (447, 3, 1, 387, '다음 중 트랜잭션이 커밋되기 전, 다른 사용자가 해당 데이터를 수정할 수 없도록 하는 SQL 구문은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LOCK TABLE"}, {"id": "B", "text": "FOR UPDATE"}, {"id": "C", "text": "BEGIN TRANSACTION"}, {"id": "D", "text": "ROLLBACK"}]', 'B', 'FOR UPDATE 구문은 특정 행을 잠궈 다른 트랜잭션에서 해당 데이터를 수정할 수 없도록 합니다.'),
    (448, 3, 1, 388, '트랜잭션에서 동시에 여러 행을 잠그려면 어떤 SQL 구문을 사용해야 하나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SELECT * FROM table_name FOR UPDATE"}, {"id": "B", "text": "SELECT column_name FROM table_name"}, {"id": "C", "text": "SELECT * FROM table_name WHERE condition FOR UPDATE"}, {"id": "D", "text": "UPDATE table_name SET column_name = value"}]', '["A", "C"]', '여러 행을 잠그려면 FOR UPDATE를 사용하는 SELECT 문을 통해 해당 행들을 선택해야 합니다.'),
    (449, 3, 1, 389, '다음 SQL 쿼리의 목적은 무엇인가요? WITH RECURSIVE EmployeeHierarchy AS ( SELECT EmployeeID, ManagerID, Name FROM Employees WHERE ManagerID IS NULL UNION ALL SELECT e.EmployeeID, e.ManagerID, e.Name FROM Employees e INNER JOIN EmployeeHierarchy eh ON e.ManagerID = eh.EmployeeID ) SELECT * FROM EmployeeHierarchy;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최상위 관리자부터 모든 직원의 계층 구조를 조회하기 위함"}, {"id": "B", "text": "모든 직원의 이름을 변경하기 위함"}, {"id": "C", "text": "직원 수를 세기 위함"}, {"id": "D", "text": "직원 정보를 삭제하기 위함"}]', 'A', '이 쿼리는 모든 직원의 계층 구조를 최상위 관리자부터 조회하는 목적입니다.'),
    (450, 3, 1, 390, '다음 SQL의 빈칸을 채우시오: SELECT e.EmployeeID, e.ManagerID, e.Name FROM Employees e INNER JOIN ______ eh ON e.ManagerID = eh.EmployeeID', 'SHORT_ANSWER', NULL, 'EmployeeHierarchy', '빈칸에는 재귀 CTE의 이름인 EmployeeHierarchy가 들어가야 합니다.'),
    (451, 3, 1, 391, 'CTE의 정의는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 결과를 임시로 정의하여 사용할 수 있는 SQL 구문"}, {"id": "B", "text": "데이터베이스의 물리적 구조"}, {"id": "C", "text": "SQL의 데이터 삽입 명령어"}, {"id": "D", "text": "서브쿼리의 한 형태"}]', 'A', 'CTE는 쿼리 결과를 임시로 정의하여 사용할 수 있는 SQL 구문입니다.'),
    (452, 3, 1, 392, '재귀 CTE를 사용할 때, 기본 쿼리와 함께 필요한 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "UNION ALL"}, {"id": "B", "text": "JOIN"}, {"id": "C", "text": "GROUP BY"}, {"id": "D", "text": "ORDER BY"}]', '["A"]', '재귀 CTE를 사용할 때는 기본 쿼리와 함께 UNION ALL이 필요합니다.'),
    (453, 3, 1, 393, '다음 SQL 쿼리의 결과는 무엇인가? 

SELECT A.name, B.grade 
FROM Students A 
INNER JOIN Grades B ON A.id = B.student_id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생 이름과 성적 데이터"}, {"id": "B", "text": "학생 이름만"}, {"id": "C", "text": "성적 데이터만"}, {"id": "D", "text": "오류 발생"}]', 'A', 'INNER JOIN을 사용하여 관련된 두 테이블의 데이터를 조합하여 학생 이름과 성적을 반환합니다.'),
    (454, 3, 1, 394, '다음 SQL 쿼리에서 ''LEFT JOIN''의 결과는 무엇을 의미하는가? 

SELECT A.name, B.grade 
FROM Students A 
LEFT JOIN Grades B ON A.id = B.student_id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 학생의 이름과 해당 성적"}, {"id": "B", "text": "성적이 있는 학생만"}, {"id": "C", "text": "성적이 없는 학생은 제외됨"}, {"id": "D", "text": "모든 성적 데이터"}]', 'A', 'LEFT JOIN은 Students 테이블의 모든 데이터를 포함하고, Grades 테이블의 일치하는 데이터를 포함하여 성적이 없는 학생의 경우 NULL 값을 반환합니다.'),
    (455, 3, 1, 395, '다음 SQL 쿼리에서 빈칸에 들어갈 SQL 키워드는 무엇인가? 

SELECT * FROM Students A 
WHERE A.id IN (SELECT B.student_id FROM Grades B);', 'SHORT_ANSWER', NULL, 'IN', '서브쿼리의 결과가 포함된 학생 ID를 필터링하는 데 ''IN'' 키워드를 사용합니다.'),
    (456, 3, 1, 396, '다음 중 SQL JOIN을 사용하는 경우에 해당하는 것은 무엇인가? 

SELECT * FROM Employees JOIN Departments ON Employees.dept_id = Departments.id;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "두 개 이상의 테이블에서 관련된 데이터를 가져올 때"}, {"id": "B", "text": "하나의 테이블에서만 데이터를 가져올 때"}, {"id": "C", "text": "데이터를 합치지 않고 비교할 때"}, {"id": "D", "text": "조건에 따라 데이터를 필터링할 때"}]', '["A", "D"]', 'JOIN은 여러 테이블 간에 관련된 데이터를 가져오고 조건에 따라 데이터를 필터링하는 데 사용됩니다.'),
    (457, 3, 1, 397, '다음 SQL 구문에서 직원 급여에 따라 ''Low'', ''Medium'', ''High'' 등급을 반환하는 부분을 올바르게 작성하세요: SELECT employee_id, salary, CASE WHEN salary < 30000 THEN ''Low'' _______ ''Medium'' THEN ''Medium'' ELSE ''High'' END AS salary_grade FROM employees;', 'SHORT_ANSWER', NULL, 'WHEN salary BETWEEN 30000 AND 60000', '''CASE'' 문에서 중간 급여를 처리하기 위한 조건이므로 ''WHEN salary BETWEEN 30000 AND 60000''가 필요하다.'),
    (458, 3, 1, 398, '다음 SQL 쿼리에서 ''CASE WHEN'' 문을 사용하여 특정 조건을 처리하는 지점은? SELECT department_id, COUNT(employee_id), _______ FROM employees GROUP BY department_id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CASE WHEN COUNT(employee_id) > 10 THEN ''Many'' ELSE ''Few'' END AS employee_count_status"}, {"id": "B", "text": "AVG(salary) AS average_salary"}, {"id": "C", "text": "SUM(salary) AS total_salary"}, {"id": "D", "text": "MAX(salary) AS max_salary"}]', 'A', '''CASE WHEN'' 문은 특정 조건에 따라 결과를 나누는 데 적합하므로 ''A''가 정답이다.'),
    (459, 3, 1, 399, '아래 SQL 쿼리 중 급여에 따라 ''Low'', ''Medium'', ''High''를 반환하는 부분이 잘못된 것은 무엇인가요? SELECT employee_id, salary, CASE WHEN salary < 30000 THEN ''Low'' WHEN salary > 60000 THEN ''High'' _______ END AS salary_grade FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHEN salary BETWEEN 30000 AND 60000 THEN ''Medium''"}, {"id": "B", "text": "WHEN salary >= 30000 AND salary <= 60000 THEN ''Medium''"}, {"id": "C", "text": "WHEN salary >= 30000 AND salary <= 60000 THEN ''High''"}, {"id": "D", "text": "WHEN salary BETWEEN 30000 AND 60000 THEN ''Low''"}]', 'C', '''High''를 반환하기 위한 조건은 적합하지 않으므로 ''C''가 정답이다.'),
    (460, 3, 1, 400, '아래 쿼리에서 COUNT와 CASE를 조합하여 조건별 employee 수를 세는 쿼리를 완성하세요: SELECT COUNT(CASE WHEN salary < 30000 THEN employee_id END) AS low_salary_count, COUNT(CASE WHEN salary _______ THEN employee_id END) AS medium_salary_count FROM employees;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "BETWEEN 30000 AND 60000"}, {"id": "B", "text": ">= 30000 AND <= 60000"}, {"id": "C", "text": "BETWEEN 60001 AND 100000"}, {"id": "D", "text": ">= 60000"}]', '["A", "B"]', '''Medium'' 급여를 세기 위해서는 ''BETWEEN 30000 AND 60000'' 또는 ''>= 30000 AND <= 60000'' 조건을 사용해야 한다.'),
    (461, 3, 1, 401, '다음 SQL 쿼리의 결과로 출력되는 필드는 무엇인가요? SELECT a.name, b.salary FROM employees a INNER JOIN salaries b ON a.id = b.employee_id WHERE b.salary > (SELECT AVG(salary) FROM salaries);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "employees 테이블의 이름과 급여"}, {"id": "B", "text": "employees 테이블의 이름만"}, {"id": "C", "text": "salaries 테이블의 급여만"}, {"id": "D", "text": "모든 직원의 정보"}]', 'A', '쿼리는 employees 테이블의 이름과 salaries 테이블의 급여를 선택합니다.'),
    (462, 3, 1, 402, 'INNER JOIN을 사용할 때 두 테이블의 어떤 조건이 참일 때만 결과가 반환되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 조건"}, {"id": "B", "text": "첫 번째 테이블의 모든 행"}, {"id": "C", "text": "두 번째 테이블의 모든 행"}, {"id": "D", "text": "JOIN 조건이 일치하는 경우"}]', 'D', 'INNER JOIN은 JOIN 조건이 일치하는 경우에만 결과를 반환합니다.'),
    (463, 3, 1, 403, '서브쿼리의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서브쿼리는 항상 메인 쿼리보다 먼저 실행된다."}, {"id": "B", "text": "서브쿼리는 데이터를 조작하는 데 사용된다."}, {"id": "C", "text": "서브쿼리는 메인 쿼리의 결과를 필터링하는 데 사용된다."}, {"id": "D", "text": "서브쿼리는 새로운 테이블을 생성한다."}]', 'C', '서브쿼리는 메인 쿼리의 결과를 필터링하는 데 사용됩니다.'),
    (464, 3, 1, 404, 'JOIN과 서브쿼리의 주된 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "JOIN은 테이블을 결합하고, 서브쿼리는 데이터를 반환한다."}, {"id": "B", "text": "JOIN은 서브쿼리보다 항상 빠르다."}, {"id": "C", "text": "서브쿼리는 독립적인 쿼리로 실행될 수 있다."}, {"id": "D", "text": "JOIN은 항상 두 개의 테이블만 사용해야 한다."}]', '["A", "C"]', 'JOIN은 테이블을 결합하고, 서브쿼리는 독립적인 쿼리로 실행될 수 있습니다.'),
    (465, 3, 1, 405, 'INNER JOIN을 사용하여 테이블 결합할 때, ON 키워드는 어떤 역할을 하나요?', 'SHORT_ANSWER', NULL, '결합 조건을 지정한다.', 'ON 키워드는 두 테이블 간의 결합 조건을 지정하는 데 사용됩니다.'),
    (466, 3, 1, 406, '다음 SQL 쿼리의 결과로 출력되는 데이터는 무엇일까요?

SELECT * FROM orders JOIN customers ON orders.customer_id = customers.id;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 주문과 해당 고객 정보"}, {"id": "B", "text": "모든 고객 정보"}, {"id": "C", "text": "모든 주문 정보"}, {"id": "D", "text": "존재하지 않는 데이터"}]', 'A', '이 쿼리는 orders 테이블과 customers 테이블을 customer_id를 기준으로 결합하여 모든 주문과 해당 고객 정보를 반환합니다.'),
    (467, 3, 1, 407, '빈칸을 채우세요: SELECT * FROM customers WHERE id IN (SELECT customer_id FROM ______ WHERE total > 100);', 'SHORT_ANSWER', NULL, 'orders', '빈칸에는 고객의 주문을 확인하기 위한 테이블 이름인 ''orders''가 들어가야 합니다.'),
    (468, 3, 1, 408, '다음 중 JOIN과 서브쿼리의 주요 차이점으로 옳지 않은 것은?

A) JOIN은 두 테이블의 데이터를 결합하고, 서브쿼리는 결과를 활용한다.
B) JOIN은 항상 더 빠르다.
C) 서브쿼리는 더 유연한 조건을 처리할 수 있다.
D) JOIN은 테이블 간의 관계를 명확히 한다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "JOIN은 두 테이블의 데이터를 결합하고, 서브쿼리는 결과를 활용한다."}, {"id": "B", "text": "JOIN은 항상 더 빠르다."}, {"id": "C", "text": "서브쿼리는 더 유연한 조건을 처리할 수 있다."}, {"id": "D", "text": "JOIN은 테이블 간의 관계를 명확히 한다."}]', 'B', 'JOIN이 항상 더 빠르다는 것은 잘못된 설명입니다. 쿼리의 구조와 데이터 양에 따라 성능 차이가 있을 수 있습니다.'),
    (469, 3, 1, 409, 'SELECT customer_id FROM orders WHERE total > 100; 의 결과는 어떤 유형의 데이터인가요?', 'SHORT_ANSWER', NULL, 'customer_id 목록', '이 쿼리는 주문 총액이 100을 초과하는 고객의 ID 목록을 반환합니다.'),
    (470, 3, 1, 410, '다음 SQL 쿼리의 결과로 어떤 데이터가 출력될까요?

SELECT * FROM orders WHERE customer_id IN (SELECT id FROM customers WHERE name = ''John'');', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "John이라는 고객의 모든 주문"}, {"id": "B", "text": "모든 고객의 주문"}, {"id": "C", "text": "존재하지 않는 데이터"}, {"id": "D", "text": "모든 주문"}]', 'A', '이 쿼리는 고객 이름이 ''John''인 고객의 모든 주문을 반환합니다.'),
    (471, 3, 1, 411, '다음 SQL 쿼리를 실행했을 때, ''result'' 컬럼의 값은 무엇인가요?

SELECT name,
       CASE 
           WHEN score >= 60 THEN ''합격''
           ELSE ''불합격''
       END AS result
FROM students;

(학생의 score가 75인 경우를 가정)', 'SHORT_ANSWER', NULL, '합격', 'score가 60 이상인 경우 ''합격''을 반환합니다.'),
    (472, 3, 1, 412, '다음 SQL 쿼리에서 ''score''가 50 이하일 때 출력되는 값을 고르세요.

SELECT name,
       CASE 
           WHEN score > 75 THEN ''A''
           WHEN score > 50 THEN ''B''
           ELSE ''C''
       END AS grade
FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "D"}]', 'C', 'score가 50 이하인 경우 ELSE 절로 인해 ''C''를 반환합니다.'),
    (473, 3, 1, 413, '다음 SQL 쿼리에서 score가 60, 70인 학생에 대해 ''result'' 컬럼의 값을 고르세요.

SELECT name,
       CASE 
           WHEN score >= 60 THEN ''합격''
           ELSE ''불합격''
       END AS result
FROM students;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "합격"}, {"id": "B", "text": "불합격"}]', '["A"]', '60 이상인 학생은 ''합격''으로 반환됩니다.'),
    (474, 3, 1, 414, '다음 SQL 쿼리에서 ''score''가 각각 80, 40인 경우의 출력 결과를 설명하세요.

SELECT name,
       CASE 
           WHEN score >= 90 THEN ''A+''
           WHEN score >= 75 THEN ''A''
           WHEN score >= 60 THEN ''B''
           ELSE ''C''
       END AS grade
FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "A+, A"}, {"id": "B", "text": "A, C"}, {"id": "C", "text": "B, C"}, {"id": "D", "text": "C, C"}]', 'A', '80은 ''A''로, 40은 ''C''로 반환되어 ''A+, A''가 됩니다.'),
    (475, 3, 1, 415, '다음 SQL 문에서 생성되는 인덱스의 이름은 무엇인가요? `CREATE INDEX idx_name ON employees(name);`', 'SHORT_ANSWER', NULL, 'idx_name', 'SQL 문에서 ''idx_name''이 인덱스의 이름이다.'),
    (476, 3, 1, 416, '다음 쿼리의 실행 계획을 확인하기 위해 어떤 SQL 문을 사용해야 할까요? `SELECT * FROM employees WHERE name = ''John'';`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EXPLAIN SELECT * FROM employees WHERE name = ''John'';"}, {"id": "B", "text": "SHOW PLAN SELECT * FROM employees WHERE name = ''John'';"}, {"id": "C", "text": "ANALYZE SELECT * FROM employees WHERE name = ''John'';"}, {"id": "D", "text": "DESCRIBE SELECT * FROM employees WHERE name = ''John'';"}]', 'A', '실행 계획을 확인하기 위해 ''EXPLAIN''을 사용해야 한다.'),
    (477, 3, 1, 417, '다음 중 인덱스를 사용할 때의 장점이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "검색 속도 향상"}, {"id": "B", "text": "데이터 삽입 속도 향상"}, {"id": "C", "text": "정렬 및 필터링 성능 향상"}, {"id": "D", "text": "쿼리 최적화 가능성 향상"}]', 'B', '인덱스는 검색 속도를 향상시키지만, 데이터 삽입 속도는 오히려 저하시킬 수 있다.'),
    (478, 3, 1, 418, '다음 쿼리에서 인덱스가 사용될 수 있는 조건을 모두 선택하세요: `SELECT * FROM employees WHERE age > 30 AND department = ''Sales'';`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "age 열에 인덱스가 있을 때"}, {"id": "B", "text": "department 열에 인덱스가 있을 때"}, {"id": "C", "text": "employees 테이블이 작은 경우"}, {"id": "D", "text": "age와 department 둘 다 인덱스가 있을 때"}]', '["A", "B", "D"]', 'age와 department 열에 인덱스가 있다면 쿼리 성능이 향상될 수 있다.'),
    (479, 3, 1, 419, '다음 SQL 쿼리에서 cte_name의 초기 조건이 잘못된 경우, 어떤 결과를 얻게 될까요? 

 WITH RECURSIVE cte_name AS (
     SELECT initial_columns
     FROM initial_table
     WHERE initial_condition
     UNION ALL
     SELECT columns
     FROM cte_name
     JOIN another_table ON some_condition
 )
 SELECT * FROM cte_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "결과가 빈 테이블이 반환된다."}, {"id": "B", "text": "에러가 발생한다."}, {"id": "C", "text": "무한 루프에 빠진다."}, {"id": "D", "text": "잘못된 데이터가 반환된다."}]', 'A', '초기 조건이 없으면 재귀가 실행되지 않아 빈 테이블이 반환됩니다.'),
    (480, 3, 1, 420, '다음 코드에서 빈칸에 들어갈 적절한 내용을 고르세요: 

 WITH RECURSIVE cte_example AS (
    SELECT id, name
    FROM employees
    WHERE manager_id IS NULL
    UNION ALL
    SELECT e.id, e.name
    FROM employees e
    JOIN cte_example c ON e.manager_id = c.id
 )
 SELECT * FROM cte_example;', 'SHORT_ANSWER', NULL, 'manager_id IS NULL', '초기 조건에서 상위 관리자(최상위 노드)를 선택해야 하므로 manager_id IS NULL이 들어가야 합니다.'),
    (481, 3, 1, 421, '재귀 CTE를 사용하여 하위 부서의 모든 직원 정보를 가져오기 위한 쿼리는 어떤 구조를 가지고 있나요? 

 WITH RECURSIVE cte_name AS ( 
     SELECT initial_columns
     FROM initial_table
     WHERE initial_condition
     UNION ALL
     SELECT columns
     FROM __________ ON some_condition
 )
 SELECT * FROM cte_name;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "cte_name JOIN another_table"}, {"id": "B", "text": "employees JOIN cte_name"}, {"id": "C", "text": "cte_name JOIN cte_name"}, {"id": "D", "text": "another_table JOIN another_table"}]', 'A', '재귀 CTE는 자신을 참조하기 위해 cte_name과 다른 테이블을 JOIN하여 하위 데이터를 가져옵니다.'),
    (482, 3, 1, 422, '다음 중 CTE에 대한 설명으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "CTE는 쿼리 내에서 재사용 가능하다."}, {"id": "B", "text": "CTE는 항상 재귀적이다."}, {"id": "C", "text": "CTE는 성능을 향상시킬 수 있다."}, {"id": "D", "text": "CTE는 뷰와 유사한 역할을 한다."}]', '["A", "C", "D"]', 'CTE는 쿼리 내에서 재사용 가능하고, 뷰와 유사한 역할을 하며, 적절히 사용하면 성능을 향상시킬 수 있습니다. 하지만 CTE가 항상 재귀적인 것은 아닙니다.'),
    (483, 3, 1, 423, 'CTE에서 재귀적 쿼리를 구현하기 위한 주요 키워드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'RECURSIVE', '재귀적 쿼리를 구현하기 위해 CTE 정의 시 ''RECURSIVE'' 키워드를 사용해야 합니다.'),
    (484, 3, 1, 424, '다음 SQL 쿼리의 결과로 예상되는 average_salary 값은 무엇인가요?

SELECT department, AVG(salary) AS average_salary
FROM employees
GROUP BY department
HAVING AVG(salary) > 50000;', 'SHORT_ANSWER', NULL, '부서당 평균 급여가 50,000을 초과하는 값들', 'HAVING 절의 조건을 만족하는 부서의 평균 급여 값이 결과로 출력됩니다.'),
    (485, 3, 1, 425, '다음 SQL 쿼리에서 GROUP BY 절의 역할은 무엇인가요?

SELECT department, COUNT(*)
FROM employees
GROUP BY department;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부서를 기준으로 데이터를 그룹화한다."}, {"id": "B", "text": "부서별 평균 급여를 계산한다."}, {"id": "C", "text": "모든 직원의 데이터를 단일 행으로 출력한다."}, {"id": "D", "text": "직원 수를 계산하는 것이 목적이다."}]', 'A', 'GROUP BY 절은 부서를 기준으로 데이터를 그룹화하여 부서별로 COUNT(*)를 계산합니다.'),
    (486, 3, 1, 426, 'HAVING 절을 사용하는 이유는 무엇인가요?

SELECT department, SUM(salary)
FROM employees
GROUP BY department
HAVING SUM(salary) > 100000;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 필터링하여 특정 조건을 만족하는 그룹만 선택한다."}, {"id": "B", "text": "모든 데이터를 출력하기 위해 사용된다."}, {"id": "C", "text": "데이터를 정렬하는 기능을 제공한다."}, {"id": "D", "text": "중복된 데이터를 제거하기 위해 사용된다."}]', 'A', 'HAVING 절은 GROUP BY로 생성된 그룹에 조건을 적용하여 특정 조건을 만족하는 그룹만을 선택합니다.'),
    (487, 3, 1, 427, 'SELECT department, COUNT(*) FROM employees GROUP BY department;
해당 쿼리에서 COUNT(*)의 결과로 어떤 값들이 출력될까요? (복수정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "부서의 총 직원 수"}, {"id": "B", "text": "부서 이름"}, {"id": "C", "text": "각 부서의 평균 급여"}, {"id": "D", "text": "부서의 고용된 직원과 해고된 직원 수"}]', '["A", "B"]', 'COUNT(*)는 부서별 총 직원 수를 세고, GROUP BY 절에 의해 부서 이름과 함께 출력됩니다.'),
    (488, 3, 1, 428, '다음 SQL 쿼리에서 GROUP BY와 HAVING이 없으면 어떤 결과가 나올까요?

SELECT department, AVG(salary)
FROM employees;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "전체 직원의 평균 급여가 출력된다."}, {"id": "B", "text": "부서별 평균 급여가 출력된다."}, {"id": "C", "text": "SQL 오류가 발생한다."}, {"id": "D", "text": "출력이 없다."}]', 'A', 'GROUP BY가 없으면 전체 직원의 평균 급여가 출력됩니다.'),
    (489, 3, 1, 429, '다음 SQL 쿼리를 실행했을 때 출력될 결과는 무엇인가? 

SELECT name, CASE 
    WHEN score >= 90 THEN ''A'' 
    WHEN score >= 80 THEN ''B'' 
    ELSE ''C'' 
END as grade 
FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생 이름과 A, B, C 등급이 출력된다."}, {"id": "B", "text": "모든 학생의 점수가 90점 이상으로 A 등급만 출력된다."}, {"id": "C", "text": "학생 이름만 출력된다."}, {"id": "D", "text": "에러가 발생한다."}]', 'A', '이 쿼리는 학생 이름과 점수에 따른 등급을 출력합니다.'),
    (490, 3, 1, 430, '다음 SQL 쿼리에서 잘못된 부분은 무엇인가? 

SELECT name, CASE 
    WHEN score >= 90 THEN ''A'' 
    WHEN score >= 80 ''
    ELSE ''C'' 
END as grade 
FROM students;', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHEN 조건의 문법이 잘못됐다."}, {"id": "B", "text": "CASE 문이 닫히지 않았다."}, {"id": "C", "text": "ELSE 문이 잘못됐다."}, {"id": "D", "text": "SQL 문법에 문제가 없다."}]', 'A', 'WHEN 문의 조건 뒤에 THEN이 있어야 하는데, 아포스트로피가 잘못 사용되었습니다.'),
    (491, 3, 1, 431, '다음 중 CASE WHEN 문을 사용할 수 있는 상황이 아닌 것은? 

CASE 
    WHEN score >= 60 THEN ''합격'' 
    ELSE ''불합격'' 
END', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "학생의 점수를 기준으로 합격 여부 판단"}, {"id": "B", "text": "날씨에 따른 우산 필요 여부 판단"}, {"id": "C", "text": "판매량에 따라 보너스 지급 여부 결정"}, {"id": "D", "text": "이름의 길이에 따라 등급 매기기"}]', '["B", "D"]', '날씨와 이름의 길이는 CASE WHEN 문을 사용하여 평가하기에 적합하지 않습니다.'),
    (492, 3, 1, 432, 'CASE WHEN 문에서 기본 구조의 ''ELSE'' 부분이 없으면 어떻게 되는가?', 'SHORT_ANSWER', NULL, '조건이 모두 false일 때 NULL이 반환된다.', 'ELSE가 없으면 모든 조건이 false일 경우 NULL이 반환됩니다.'),
    (493, 3, 1, 433, '다음 SQL 문은 무엇을 수행하는가? CREATE INDEX idx_name ON employees(name);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "employees 테이블의 name 열에 인덱스를 생성한다."}, {"id": "B", "text": "employees 테이블을 삭제한다."}, {"id": "C", "text": "employees 테이블의 모든 데이터를 업데이트한다."}, {"id": "D", "text": "employees 테이블을 선택한다."}]', 'A', '이 SQL 문은 employees 테이블의 name 열에 인덱스를 생성하여 검색 성능을 향상시킵니다.'),
    (494, 3, 1, 434, '다음 SQL 쿼리의 실행 계획을 확인하기 위해 사용할 수 있는 명령어는 무엇인가? SELECT * FROM employees WHERE name = ''John'';', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EXPLAIN SELECT * FROM employees WHERE name = ''John'';"}, {"id": "B", "text": "SHOW PLAN SELECT * FROM employees WHERE name = ''John'';"}, {"id": "C", "text": "PLAN SELECT * FROM employees WHERE name = ''John'';"}, {"id": "D", "text": "DESCRIBE SELECT * FROM employees WHERE name = ''John'';"}]', 'A', 'EXPLAIN 명령어를 사용하면 해당 쿼리의 실행 계획을 확인할 수 있습니다.'),
    (495, 3, 1, 435, '다음 SQL 문에서 빈칸에 들어갈 알맞은 키워드는 무엇인가? ___ INDEX idx_age ON employees(age);', 'SHORT_ANSWER', NULL, 'CREATE', 'CREATE 키워드는 새로운 인덱스를 생성하는데 사용됩니다.'),
    (496, 3, 1, 436, '인덱스를 생성할 때 고려해야 할 요소는 무엇인가? 다음 중 올바른 것을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 읽기 성능"}, {"id": "B", "text": "데이터의 쓰기 성능"}, {"id": "C", "text": "인덱스의 크기"}, {"id": "D", "text": "네트워크 속도"}]', '["A", "B", "C"]', '인덱스를 생성할 때 데이터의 읽기 성능, 쓰기 성능, 그리고 인덱스의 크기를 고려해야 합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 데이터베이스 > 정규화와 설계 (137문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (497, 3, 2, 1, '비클러스터드 인덱스의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "물리적 데이터 순서와 관계없이 별도로 저장된다."}, {"id": "B", "text": "데이터가 물리적으로 정렬된다."}, {"id": "C", "text": "인덱스가 없으면 쿼리가 수행되지 않는다."}, {"id": "D", "text": "B+Tree 구조가 사용되지 않는다."}]', 'A', '비클러스터드 인덱스는 물리적 데이터의 순서와 관계없이 별도의 스토리지에 인덱스를 저장하여 효율적인 검색을 가능하게 합니다.'),
    (498, 3, 2, 2, '커버링 인덱스의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리를 인덱스만으로 처리할 수 있다."}, {"id": "B", "text": "모든 데이터를 풀 스캔하게 한다."}, {"id": "C", "text": "쿼리 성능이 항상 저하된다."}, {"id": "D", "text": "인덱스의 크기가 감소한다."}]', 'A', '커버링 인덱스는 쿼리에 필요한 모든 데이터를 인덱스에 포함시켜, 테이블을 검색하지 않고 인덱스만 이용하여 쿼리를 처리할 수 있도록 합니다.'),
    (499, 3, 2, 3, '쿼리 튜닝에서 실행 계획을 분석하는 이유는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리의 성능을 개선하기 위해."}, {"id": "B", "text": "테이블 구조를 변경하기 위해."}, {"id": "C", "text": "인덱스를 삭제하기 위해."}, {"id": "D", "text": "데이터를 백업하기 위해."}]', 'A', '실행 계획을 분석하는 것은 쿼리의 성능을 향상시키고 비효율적인 접근 방식을 식별하기 위해 필수적입니다.'),
    (500, 3, 2, 4, '다음 중 복합 인덱스의 특징으로 올바른 것은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "두 개 이상의 열로 구성된다."}, {"id": "B", "text": "단일 열 인덱스보다 성능이 항상 낮다."}, {"id": "C", "text": "특정 쿼리에 대한 성능을 향상시킬 수 있다."}, {"id": "D", "text": "인덱스를 통해 데이터 전체를 검색할 수 있다."}]', '["A", "C"]', '복합 인덱스는 두 개 이상의 열로 구성되어 있으며, 특정 쿼리의 성능을 향상시키는 데 유용합니다.'),
    (501, 3, 2, 5, 'B+Tree 구조의 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '빠른 검색과 정렬을 지원한다.', 'B+Tree 구조는 데이터의 검색 및 정렬을 빠르게 수행할 수 있게 하여 인덱싱에 매우 효과적입니다.'),
    (502, 3, 2, 6, 'CTE의 주요 이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리의 가독성을 높인다."}, {"id": "B", "text": "데이터베이스의 속도를 증가시킨다."}, {"id": "C", "text": "데이터를 영구적으로 저장한다."}, {"id": "D", "text": "중복된 데이터를 제거한다."}]', 'A', 'CTE는 쿼리 내에서 재사용 가능하며, 가독성을 높여 복잡한 쿼리를 간단하게 표현할 수 있도록 도와준다.'),
    (503, 3, 2, 7, 'LAG 함수의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 값을 참조하는 것"}, {"id": "B", "text": "우리 행의 값을 변경하는 것"}, {"id": "C", "text": "행을 삭제하는 것"}, {"id": "D", "text": "행의 순서를 변경하는 것"}]', 'A', 'LAG 함수는 현재 행의 바로 이전 행의 값을 가져와 데이터 분석에 유용하게 사용된다.'),
    (504, 3, 2, 8, '정규표현식은 주로 어떤 작업에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스의 성능을 향상시키기 위해"}, {"id": "B", "text": "문자열에서 특정 패턴을 찾기 위해"}, {"id": "C", "text": "데이터를 암호화하기 위해"}, {"id": "D", "text": "쿼리의 실행 속도를 측정하기 위해"}]', 'B', '정규표현식은 문자열 처리 및 특정 패턴 검색에 유용하게 사용된다.'),
    (505, 3, 2, 9, '어떤 SQL 기능을 사용하여 데이터를 균등하게 나누는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "LAG"}, {"id": "B", "text": "NTILE"}, {"id": "C", "text": "PARTITION BY"}, {"id": "D", "text": "JOIN"}]', '["B", "C"]', 'NTILE 함수는 데이터를 균등하게 나누는 데 사용되며, PARTITION BY는 이를 위한 그룹화와 집계를 가능하게 한다.'),
    (506, 3, 2, 10, '성능 튜닝에서 가장 중요한 요소 중 하나는 무엇인가?', 'SHORT_ANSWER', NULL, '쿼리 최적화', '성능 튜닝에서는 주로 쿼리의 실행 속도를 개선하기 위한 최적화가 중요하다.'),
    (507, 3, 2, 11, '풀 스캔이란 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "전체 테이블을 검색하는 방식"}, {"id": "B", "text": "인덱스를 사용하여 검색하는 방식"}, {"id": "C", "text": "쿼리를 최적화하는 과정"}, {"id": "D", "text": "데이터를 정렬하는 방법"}]', 'A', '풀 스캔은 전체 테이블을 검색하는 방식으로, 성능 저하의 원인이 될 수 있습니다.'),
    (508, 3, 2, 12, '커버링 인덱스의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 필요 정보를 포함하여 인덱스만으로 결과 반환 가능"}, {"id": "B", "text": "인덱스 스캔 속도를 증가시킨다"}, {"id": "C", "text": "비용이 적게 든다"}, {"id": "D", "text": "쿼리 계획을 자동으로 최적화한다"}]', 'A', '커버링 인덱스는 쿼리에서 필요한 모든 정보를 포함해 인덱스만으로 결과를 반환할 수 있어 성능을 향상시킵니다.'),
    (509, 3, 2, 13, '클러스터드 인덱스와 비클러스터드 인덱스의 차이는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "클러스터드 인덱스는 데이터의 물리적 순서를 보관한다."}, {"id": "B", "text": "비클러스터드 인덱스는 데이터의 물리적 순서를 보관한다."}, {"id": "C", "text": "클러스터드 인덱스는 테이블 당 하나만 존재할 수 있다."}, {"id": "D", "text": "비클러스터드 인덱스는 여러 개가 존재할 수 있다."}]', '["A", "C", "D"]', '클러스터드 인덱스는 데이터의 물리적 순서를 보관하고, 하나만 존재할 수 있으며, 비클러스터드 인덱스는 여러 개 존재할 수 있습니다.'),
    (510, 3, 2, 14, '슬로우 쿼리를 개선하기 위해 사용할 수 있는 방법은?', 'SHORT_ANSWER', NULL, '쿼리 튜닝과 인덱스 최적화', '슬로우 쿼리 개선을 위해서는 쿼리 튜닝과 인덱스 최적화가 필요합니다.'),
    (511, 3, 2, 15, '클러스터드 인덱스의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 실제로 저장되는 순서를 결정한다."}, {"id": "B", "text": "해시 알고리즘을 사용한다."}, {"id": "C", "text": "복합 인덱스를 지원하지 않는다."}, {"id": "D", "text": "쿼리 튜닝에 영향을 미치지 않는다."}]', 'A', '클러스터드 인덱스는 데이터가 실제로 저장되는 순서를 결정하여 쿼리 성능에 큰 영향을 미칩니다.'),
    (512, 3, 2, 16, '인덱스를 사용할 때의 장점이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "검색 속도가 빨라진다."}, {"id": "B", "text": "디스크 공간이 절약된다."}, {"id": "C", "text": "쿼리 성능이 향상된다."}, {"id": "D", "text": "정렬 작업이 더 빨라진다."}]', 'B', '인덱스는 오히려 추가적인 디스크 공간을 소모할 수 있습니다.'),
    (513, 3, 2, 17, '다음 중 인덱스 스캔을 활용하여 성능을 최적화할 수 있는 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해시 인덱스를 사용하는 것"}, {"id": "B", "text": "복합 인덱스를 사용하는 것"}, {"id": "C", "text": "커버링 인덱스를 사용하는 것"}, {"id": "D", "text": "쿼리를 아주 복잡하게 만드는 것"}]', 'C', '커버링 인덱스는 필요한 모든 데이터를 인덱스에서 직접 읽을 수 있게 해줍니다.'),
    (514, 3, 2, 18, '인덱스의 유형 중 해시 인덱스가 적합하지 않은 경우는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "정확한 값 검색"}, {"id": "B", "text": "범위 검색"}, {"id": "C", "text": "고유 값 검색"}, {"id": "D", "text": "다수의 조건을 포함하는 검색"}]', '["B"]', '해시 인덱스는 정확한 값 검색에 적합하지만 범위 검색에는 적합하지 않습니다.'),
    (515, 3, 2, 19, '쿼리 최적화를 통해 성능을 향상시키는 방법 중 하나는 무엇인가요?', 'SHORT_ANSWER', NULL, '실행 계획을 분석하고 조정하는 것', '실행 계획을 분석하고 조정하는 것은 쿼리 성능을 크게 향상시키는 방법입니다.'),
    (516, 3, 2, 20, 'PIVOT 기능은 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 행에서 열로 변환"}, {"id": "B", "text": "데이터를 필터링"}, {"id": "C", "text": "데이터를 정렬"}, {"id": "D", "text": "데이터를 합산"}]', 'A', 'PIVOT은 데이터를 행에서 열로 변환하여 분석할 수 있도록 돕는 기능입니다.'),
    (517, 3, 2, 21, 'LATERAL JOIN의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하나의 테이블에서만 데이터를 가져온다."}, {"id": "B", "text": "서브쿼리를 사용하는 경우에 사용된다."}, {"id": "C", "text": "두 테이블을 결합할 때 필수이다."}, {"id": "D", "text": "데이터를 정렬하는 기능을 포함한다."}]', 'B', 'LATERAL JOIN은 서브쿼리를 사용하여 각 행에 대해 다른 데이터를 가져올 수 있도록 돕는 JOIN 방식입니다.'),
    (518, 3, 2, 22, 'LEAD와 LAG 함수의 공통된 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행을 삭제한다."}, {"id": "B", "text": "행의 이전 또는 이후 값을 반환한다."}, {"id": "C", "text": "데이터를 그룹화한다."}, {"id": "D", "text": "데이터를 집계한다."}]', 'B', 'LEAD와 LAG 함수는 각각 특정 행의 다음 또는 이전 값을 반환하여 시간에 따른 데이터 분석을 가능하게 합니다.'),
    (519, 3, 2, 23, '인덱스 설계의 장점을 고르세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리 성능 향상"}, {"id": "B", "text": "데이터 중복 방지"}, {"id": "C", "text": "데이터 정렬 가능"}, {"id": "D", "text": "데이터 접근 속도 향상"}]', '["A", "D"]', '인덱스 설계는 쿼리 성능을 향상시키고 데이터 접근 속도를 빠르게 하는 장점이 있습니다.'),
    (520, 3, 2, 24, '정규 표현식의 주요 사용 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '문자열 검색 및 데이터 검증', '정규 표현식은 특정 패턴에 맞는 문자열을 검색하거나 검증하는 데 사용됩니다.'),
    (521, 3, 2, 25, '슬로우 쿼리를 식별하는 데 사용되는 SQL 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하면 쿼리의 실행 계획을 분석하여 슬로우 쿼리를 식별할 수 있습니다.'),
    (522, 3, 2, 26, 'B+Tree의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬된 상태로 유지한다."}, {"id": "B", "text": "데이터 중복을 허용한다."}, {"id": "C", "text": "인덱스가 아닌 모든 데이터를 저장한다."}, {"id": "D", "text": "데이터베이스를 암호화한다."}]', 'A', 'B+Tree는 데이터를 정렬된 상태로 유지하여 검색 성능을 향상시킵니다.'),
    (523, 3, 2, 27, '커버링 인덱스의 장점으로 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 성능을 향상시킬 수 있다."}, {"id": "B", "text": "다수의 열을 포함할 수 있다."}, {"id": "C", "text": "쿼리 계획을 단순화할 수 있다."}, {"id": "D", "text": "인덱스 크기를 줄인다."}]', 'D', '커버링 인덱스는 쿼리 성능을 향상시킬 수 있지만 인덱스 크기를 반드시 줄이지는 않습니다.'),
    (524, 3, 2, 28, '복합 인덱스에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "여러 열을 조합하여 인덱스를 생성한다."}, {"id": "B", "text": "모든 쿼리에서 사용해야 한다."}, {"id": "C", "text": "단일 열 인덱스보다 성능이 좋을 수 있다."}, {"id": "D", "text": "인덱스의 유지 관리가 더 복잡하다."}]', '["A", "C", "D"]', '복합 인덱스는 여러 열을 조합하여 생성되며, 성능 개선이 가능하지만 유지 관리가 복잡할 수 있습니다.'),
    (525, 3, 2, 29, '삭제 이상이 발생하는 경우는 어떤 상황인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 중복될 때"}, {"id": "B", "text": "외래키 제약조건이 없을 때"}, {"id": "C", "text": "기본키가 설정되어 있지 않을 때"}, {"id": "D", "text": "정규화가 적용되지 않았을 때"}]', 'A', '삭제 이상은 데이터가 중복되어 있을 때 발생하여, 일부 데이터를 삭제할 경우 관련된 다른 데이터도 함께 삭제되는 문제를 일으킵니다.'),
    (526, 3, 2, 30, '다음 중 기본키의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유일성을 가져야 한다"}, {"id": "B", "text": "NULL 값을 가질 수 있다"}, {"id": "C", "text": "변경될 수 없다"}, {"id": "D", "text": "각 행을 고유하게 식별한다"}]', 'B', '기본키는 유일성을 유지해야 하므로 NULL 값을 가질 수 없습니다.'),
    (527, 3, 2, 31, '아래 속성 중 후보키의 예로 적절하지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "학생ID"}, {"id": "B", "text": "이메일 주소"}, {"id": "C", "text": "전화번호"}, {"id": "D", "text": "학생 이름"}]', 'D', '학생 이름은 중복될 수 있으므로 후보키로 적절하지 않습니다.'),
    (528, 3, 2, 32, '정규화 과정에서 3NF의 조건은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 속성이 기본키에 종속되어야 한다."}, {"id": "B", "text": "이행적 종속이 없어야 한다."}, {"id": "C", "text": "모든 속성이 원자값이어야 한다."}, {"id": "D", "text": "서로 다른 테이블 간에 외래키 관계가 있어야 한다."}]', '["A", "B", "C"]', '3NF의 조건은 모든 속성이 기본키에 종속되고, 이행적 종속이 없어야 하며, 모든 속성이 원자값이어야 한다는 것입니다.'),
    (529, 3, 2, 33, '슈퍼키의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '테이블 내에서 모든 튜플을 유일하게 식별할 수 있는 속성 집합', ''),
    (530, 3, 2, 34, 'EXPLAIN 명령어의 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '쿼리의 실행 계획을 분석하기 위해', 'EXPLAIN 명령어는 데이터베이스의 쿼리가 어떻게 실행되는지를 보여주어 최적화를 돕습니다.'),
    (531, 3, 2, 35, '비클러스터드 인덱스의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 물리적 순서를 변경하지 않는다."}, {"id": "B", "text": "테이블의 모든 열을 포함한다."}, {"id": "C", "text": "인덱스가 테이블과 같은 구조를 가진다."}, {"id": "D", "text": "쿼리의 성능을 항상 향상시킨다."}]', 'A', '비클러스터드 인덱스는 데이터의 물리적 순서를 변경하지 않고 별도의 구조로 저장됩니다.'),
    (532, 3, 2, 36, '커버링 인덱스에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리에 필요한 모든 데이터를 인덱스에서 가져올 수 있다."}, {"id": "B", "text": "인덱스는 오직 하나의 열만 포함할 수 있다."}, {"id": "C", "text": "데이터베이스의 크기를 증가시킨다."}, {"id": "D", "text": "풀 스캔을 사용해야 한다."}]', 'A', '커버링 인덱스는 필요한 모든 데이터가 인덱스에 포함되어 있어, 테이블에 접근할 필요가 없습니다.'),
    (533, 3, 2, 37, '쿼리 최적화에서 풀 스캔 대신 인덱스 스캔을 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "성능을 향상시킬 수 있다."}, {"id": "B", "text": "메모리 사용량이 줄어든다."}, {"id": "C", "text": "쿼리 결과의 정확도가 높아진다."}, {"id": "D", "text": "인덱스가 없는 테이블에서는 사용할 수 없다."}]', '["A", "B"]', '인덱스 스캔은 필요 없는 데이터를 불러오지 않아 성능을 향상시키고 메모리 사용량도 줄일 수 있습니다.'),
    (534, 3, 2, 38, '커버링 인덱스란 무엇인가?', 'SHORT_ANSWER', NULL, '쿼리에서 요청하는 모든 열이 인덱스에 포함되어 데이터를 직접 가져올 수 있는 인덱스', '커버링 인덱스는 특정 쿼리에서 모든 필요한 데이터를 인덱스에서 직접 읽어올 수 있게 해 주므로 성능을 향상시킵니다.'),
    (535, 3, 2, 39, '복합 인덱스는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 열의 조합으로 인덱스를 구성하는 것"}, {"id": "B", "text": "복잡한 쿼리를 수행하는 데 필요 없는 인덱스"}, {"id": "C", "text": "하나의 열만 사용하는 인덱스"}, {"id": "D", "text": "인덱스 없이 쿼리를 수행하는 것"}]', 'A', '복합 인덱스는 여러 열을 조합하여 하나의 인덱스를 형성해 특정 쿼리의 성능을 개선하는데 도움을 줍니다.'),
    (536, 3, 2, 40, '슬로우 쿼리를 개선하기 위한 방법으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "적절한 인덱스 추가"}, {"id": "B", "text": "EXPLAIN을 사용하여 실행 계획 분석"}, {"id": "C", "text": "인덱스를 모두 제거"}, {"id": "D", "text": "쿼리 튜닝 시도"}]', 'C', '슬로우 쿼리를 개선하기 위해 인덱스를 모두 제거하는 것은 오히려 성능 저하를 초래할 수 있습니다.'),
    (537, 3, 2, 41, '다음 중 옵티마이저의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최적의 쿼리 실행 계획 선택"}, {"id": "B", "text": "모든 쿼리를 무조건 빠르게 실행"}, {"id": "C", "text": "쾌적한 사용자 경험 보장"}, {"id": "D", "text": "쿼리 성능 분석 및 개선"}]', '["A", "D"]', '옵티마이저는 쿼리의 실행 계획을 최적화하고 성능을 분석하여 가장 효율적인 방법을 선택하는 역할을 합니다.'),
    (538, 3, 2, 42, '정규화의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복과 이상 현상 제거"}, {"id": "B", "text": "데이터를 압축하기 위해"}, {"id": "C", "text": "데이터의 시각화를 위해"}, {"id": "D", "text": "데이터의 암호화를 위해"}]', 'A', '정규화의 목적은 데이터의 중복을 줄이고 이상 현상을 제거하여 데이터베이스의 무결성을 높이는 것입니다.'),
    (539, 3, 2, 43, 'BCNF에서 모든 함수적 종속은 무엇에 의존해야 하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "슈퍼키"}, {"id": "B", "text": "일반키"}, {"id": "C", "text": "임의의 속성"}, {"id": "D", "text": "비밀번호"}]', 'A', 'BCNF(보이스-코드 정규형)는 모든 함수적 종속이 슈퍼키에 의존해야 한다고 규정합니다.'),
    (540, 3, 2, 44, '비정규화의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성능 개선"}, {"id": "B", "text": "데이터 무결성 강화"}, {"id": "C", "text": "정규화 진행"}, {"id": "D", "text": "사용자 인터페이스 개선"}]', 'A', '비정규화는 데이터베이스의 성능을 개선하기 위해 중복을 허용하는 과정입니다.'),
    (541, 3, 2, 45, '함수적 종속의 예시로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "학생 ID -> 학생 이름"}, {"id": "B", "text": "학생 이름 -> 학생 ID"}, {"id": "C", "text": "과목 코드 -> 과목명"}, {"id": "D", "text": "과목명 -> 과목 코드"}]', '["A", "C"]', '학생 ID는 학생 이름을 결정하며, 과목 코드는 과목명을 결정하는 등 올바른 함수적 종속 관계입니다.'),
    (542, 3, 2, 46, '후보키의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '모든 속성이 유일성을 갖는 최소한의 속성 집합', '후보키는 테이블에서 각 행을 고유하게 식별할 수 있는 최소한의 속성 집합을 의미합니다.'),
    (543, 3, 2, 47, 'PARTITION BY는 무엇을 위해 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 나누어 집계하는 용도"}, {"id": "B", "text": "테이블을 조인하는 용도"}, {"id": "C", "text": "데이터를 삽입하는 용도"}, {"id": "D", "text": "데이터를 삭제하는 용도"}]', 'A', 'PARTITION BY는 데이터를 특정 기준으로 나누어 집계할 때 사용되며, 윈도우 함수를 사용하여 각 파티션 내에서 계산을 수행합니다.'),
    (544, 3, 2, 48, 'UNPIVOT 연산의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행 데이터를 열로 변환하는 것"}, {"id": "B", "text": "열 데이터를 행으로 변환하는 것"}, {"id": "C", "text": "문자열을 검색하는 것"}, {"id": "D", "text": "데이터를 정렬하는 것"}]', 'B', 'UNPIVOT은 열 데이터를 행 데이터로 변환하여 데이터의 형식을 변경하는 데 사용됩니다.'),
    (545, 3, 2, 49, 'LATERAL JOIN의 주된 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "조건 없이 모든 열을 결합할 수 있다"}, {"id": "B", "text": "서브쿼리에 외부 쿼리의 열을 사용할 수 있다"}, {"id": "C", "text": "강력한 성능을 제공한다"}, {"id": "D", "text": "정확한 쿼리 플랜을 보장한다"}]', 'B', 'LATERAL JOIN은 서브쿼리가 외부 쿼리의 열을 활용할 수 있도록 하여 더 유연한 쿼리 작성을 가능하게 합니다.'),
    (546, 3, 2, 50, 'JSON 함수의 주된 사용 사례는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "비정형 데이터를 다루기 위해"}, {"id": "B", "text": "관계형 데이터베이스에서 조인하기 위해"}, {"id": "C", "text": "데이터 변환 및 처리에 용이하기 위해"}, {"id": "D", "text": "정규식 처리를 위해"}]', '["A", "C"]', 'JSON 함수는 비정형 데이터를 효과적으로 다루고, 데이터를 변환 및 처리하는 데 용이함으로써 다양하게 활용됩니다.'),
    (547, 3, 2, 51, 'SQL 쿼리 플랜을 분석하는 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '쿼리 성능을 최적화하고 실행 계획을 이해하기 위해', '쿼리 플랜 분석은 쿼리의 성능을 높이고 문제점을 파악하여 최적화하는 데 필수적입니다.'),
    (548, 3, 2, 52, 'WITH RECURSIVE를 사용하여 작성할 수 있는 쿼리의 종류는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단순 쿼리"}, {"id": "B", "text": "재귀 쿼리"}, {"id": "C", "text": "조인 쿼리"}, {"id": "D", "text": "서브쿼리"}]', 'B', 'WITH RECURSIVE는 재귀 쿼리를 작성하는 데 사용됩니다.'),
    (549, 3, 2, 53, 'PIVOT 기능을 사용하는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬하기 위해"}, {"id": "B", "text": "데이터를 변환하여 가시성을 높이기 위해"}, {"id": "C", "text": "데이터를 삭제하기 위해"}, {"id": "D", "text": "데이터를 결합하기 위해"}]', 'B', 'PIVOT은 데이터의 형태를 변환하여 가시성을 높이는 데 사용됩니다.'),
    (550, 3, 2, 54, 'PARTITION BY 절은 주로 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 분할하여 처리하기 위해"}, {"id": "B", "text": "데이터를 집계하기 위해"}, {"id": "C", "text": "데이터를 정렬하기 위해"}, {"id": "D", "text": "데이터의 고유성을 보장하기 위해"}]', 'B', 'PARTITION BY 절은 데이터 그룹화 및 집계에 사용됩니다.'),
    (551, 3, 2, 55, 'SQL에서 성능 튜닝을 위해 고려해야 할 요소는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리 플랜"}, {"id": "B", "text": "인덱스 사용"}, {"id": "C", "text": "데이터 타입"}, {"id": "D", "text": "테이블 크기"}]', '["A", "B", "C", "D"]', '쿼리 플랜, 인덱스 사용, 데이터 타입, 테이블 크기 모두 성능 튜닝에 영향을 미치는 요소입니다.'),
    (552, 3, 2, 56, 'PARTITION BY와 ORDER BY의 차이점은 무엇인가?', 'SHORT_ANSWER', NULL, 'PARTITION BY는 데이터의 그룹화를 통해 집계를 수행하고, ORDER BY는 결과 집합의 정렬 순서를 지정한다.', ''),
    (553, 3, 2, 57, 'EXPLAIN 명령어의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 실행 계획을 분석하기 위해"}, {"id": "B", "text": "데이터를 삭제하기 위해"}, {"id": "C", "text": "데이터를 삽입하기 위해"}, {"id": "D", "text": "서버의 성능을 모니터링하기 위해"}]', 'A', 'EXPLAIN 명령어는 데이터베이스 쿼리의 실행 계획을 분석하여 성능 최적화를 도와줍니다.'),
    (554, 3, 2, 58, '클러스터드 인덱스와 비클러스터드 인덱스의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클러스터드는 데이터 순서를 기준으로 한다."}, {"id": "B", "text": "비클러스터드는 데이터 순서를 기준으로 한다."}, {"id": "C", "text": "둘 다 동일하게 동작한다."}, {"id": "D", "text": "클러스터드는 성능이 더 좋다."}]', 'A', '클러스터드 인덱스는 데이터의 물리적 순서를 기준으로 인덱스를 구성하는 반면, 비클러스터드는 별도의 자료구조에서 인덱스를 유지합니다.'),
    (555, 3, 2, 59, '다음 중 복합 인덱스의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 컬럼을 동시에 인덱싱 할 수 있다."}, {"id": "B", "text": "단일 컬럼 인덱스보다 항상 빠르다."}, {"id": "C", "text": "모든 쿼리에 사용할 수 있다."}, {"id": "D", "text": "인덱스 크기가 더 작아진다."}]', 'A', '복합 인덱스는 여러 컬럼을 기준으로 인덱스를 생성하여 특정 쿼리를 더 빠르게 처리할 수 있게 합니다.'),
    (556, 3, 2, 60, '클러스터드 인덱스와 비클러스터드 인덱스 중에서 B+Tree 구조를 사용하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "클러스터드 인덱스"}, {"id": "B", "text": "비클러스터드 인덱스"}, {"id": "C", "text": "둘 다 사용한다."}, {"id": "D", "text": "둘 다 사용하지 않는다."}]', '["A", "B"]', 'B+Tree 구조는 클러스터드 인덱스와 비클러스터드 인덱스 모두에서 사용됩니다.'),
    (557, 3, 2, 61, '쿼리 튜닝의 주된 목표는 무엇인가?', 'SHORT_ANSWER', NULL, '데이터베이스 성능 향상', '쿼리 튜닝은 인덱스와 옵티마이저의 기능을 최대한 활용하여 데이터베이스 성능을 향상시키는 과정입니다.'),
    (558, 3, 2, 62, '정규화의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "데이터 전송 속도 증가"}, {"id": "C", "text": "테이블 수 증가"}, {"id": "D", "text": "사용자 인터페이스 개선"}]', 'A', '정규화는 데이터의 중복을 최소화하고 데이터 무결성을 유지하는 것이 주된 목적입니다.'),
    (559, 3, 2, 63, '1NF에서 요구되는 조건은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 값이 원자적이어야 한다"}, {"id": "B", "text": "복합 키를 사용할 수 있어야 한다"}, {"id": "C", "text": "각 테이블이 최소한 하나의 외래 키를 가지고 있어야 한다"}, {"id": "D", "text": "정수형 데이터만 사용할 수 있다"}]', 'A', '1NF는 각 컬럼이 원자적 값을 가져야 함을 요구합니다.'),
    (560, 3, 2, 64, '삭제 이상과 삽입 이상은 어떤 문제를 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 무결성 유지 문제"}, {"id": "B", "text": "플라스크와 장고의 호환성 문제"}, {"id": "C", "text": "데이터 전송 속도 문제"}, {"id": "D", "text": "시스템의 보안 문제"}]', 'A', '삭제 이상과 삽입 이상은 데이터의 무결성을 유지하는 데 문제를 초래합니다.'),
    (561, 3, 2, 65, '정규화 과정에서 후보키의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 고유성을 보장한다"}, {"id": "B", "text": "테이블의 관계를 정의한다"}, {"id": "C", "text": "중복 데이터를 제거한다"}, {"id": "D", "text": "테이블에 외래 키를 추가한다"}]', '["A", "C"]', '후보키는 데이터의 고유성을 보장하고 중복 데이터를 제거하는 데 중요한 역할을 합니다.'),
    (562, 3, 2, 66, '정규화 과정에서 함수적 종속이란 무엇인가?', 'SHORT_ANSWER', NULL, '한 속성이 다른 속성을 결정하는 관계', ''),
    (563, 3, 2, 67, 'LAG 함수의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '이전 행의 값을 반환한다.', 'LAG 함수는 현재 행 이전의 데이터를 가져올 수 있어, 시간에 따른 변화나 이전 상태 비교에 유용하다.'),
    (564, 3, 2, 68, '다음 중 JSON 함수를 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 구조화하여 저장하기 위해"}, {"id": "B", "text": "쿼리 성능을 높이기 위해"}, {"id": "C", "text": "보안 강화를 위해"}, {"id": "D", "text": "인덱스 생성을 위해"}]', 'A', 'JSON 함수는 비정형 데이터를 구조화하여 효율적으로 저장하고 처리하기 위해 사용된다.'),
    (565, 3, 2, 69, 'PIVOT과 UNPIVOT의 주요 차이점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "PIVOT은 행을 열로 변환하고, UNPIVOT은 열을 행으로 변환한다."}, {"id": "B", "text": "둘 다 데이터 구조를 변화시키는 방법이다."}, {"id": "C", "text": "PIVOT은 집계 함수가 필요하고, UNPIVOT은 필요하지 않다."}, {"id": "D", "text": "각각 다른 데이터베이스에서만 사용된다."}]', 'A', 'PIVOT은 데이터를 가로형으로 변환하고, UNPIVOT은 세로형으로 변환하는 기능을 한다.'),
    (566, 3, 2, 70, 'CTE(Common Table Expressions)의 장점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리의 가독성을 높여준다."}, {"id": "B", "text": "재귀 쿼리를 쉽게 작성할 수 있다."}, {"id": "C", "text": "쿼리 성능을 항상 향상시킨다."}, {"id": "D", "text": "복잡한 쿼리를 간단하게 표현할 수 있다."}]', '["A", "B", "D"]', 'CTE를 사용하면 쿼리 구조를 보다 간결하게 만들고, 재귀적으로 데이터를 처리할 수 있어 가독성과 유용성이 높아진다.'),
    (567, 3, 2, 71, '정규화의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 제거와 무결성 유지"}, {"id": "B", "text": "데이터 삭제 용이성"}, {"id": "C", "text": "데이터 복사 확산"}, {"id": "D", "text": "데이터 시각화 개선"}]', 'A', '정규화의 주된 목적은 데이터 중복을 최소화하고 무결성을 유지하는 것입니다.'),
    (568, 3, 2, 72, '1NF의 조건은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원자성 유지"}, {"id": "B", "text": "부분 함수 종속 제거"}, {"id": "C", "text": "이행적 종속 제거"}, {"id": "D", "text": "주키의 정의"}]', 'A', '1NF의 조건은 데이터의 원자성을 유지하는 것입니다.'),
    (569, 3, 2, 73, '후보키는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 데이터"}, {"id": "B", "text": "레코드를 고유하게 식별하는 속성의 집합"}, {"id": "C", "text": "정규화된 상태"}, {"id": "D", "text": "관계형 데이터베이스의 모든 키"}]', 'B', '후보키는 데이터베이스에서 각 레코드를 고유하게 식별할 수 있는 속성의 집합을 의미합니다.'),
    (570, 3, 2, 74, '정규화 과정에서 제거되는 이상 현상은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "삽입 이상"}, {"id": "B", "text": "갱신 이상"}, {"id": "C", "text": "삭제 이상"}, {"id": "D", "text": "변경 이상"}]', '["A", "B", "C"]', '정규화는 삽입 이상, 갱신 이상, 삭제 이상 등을 제거하여 데이터베이스의 무결성을 높입니다.'),
    (571, 3, 2, 75, '2NF의 조건은 무엇인가?', 'SHORT_ANSWER', NULL, '부분 함수 종속이 제거되어야 한다.', '2NF는 모든 비주요 속성이 기본키에 완전 함수 종속해야 하며, 부분 함수 종속을 제거해야 합니다.'),
    (572, 3, 2, 76, 'LAG 함수의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 값을 참조하기 위함"}, {"id": "B", "text": "행의 총합을 계산하기 위함"}, {"id": "C", "text": "새로운 행을 추가하기 위함"}, {"id": "D", "text": "데이터를 정렬하기 위함"}]', 'A', 'LAG 함수는 현재 행의 이전 행에 있는 값을 참조하는 데 사용됩니다.'),
    (573, 3, 2, 77, 'PARTITION BY 절의 주된 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 그룹화하여 집계함"}, {"id": "B", "text": "쿼리 성능을 높임"}, {"id": "C", "text": "데이터를 정렬함"}, {"id": "D", "text": "데이터를 변환함"}]', 'A', 'PARTITION BY 절은 데이터 집합을 특정 기준으로 나누어 분석할 수 있도록 합니다.'),
    (574, 3, 2, 78, '다음 중 UNPIVOT의 기능이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "열을 행으로 변환함"}, {"id": "B", "text": "행을 열로 변환함"}, {"id": "C", "text": "데이터 구조를 변경함"}, {"id": "D", "text": "데이터 집계에 사용됨"}]', 'B', 'UNPIVOT은 열을 행으로 변환하는 데 사용되며, 행을 열로 변환하는 기능은 PIVOT입니다.'),
    (575, 3, 2, 79, 'LATERAL JOIN의 목적은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "서브쿼리와 외부 쿼리를 결합하기 위함"}, {"id": "B", "text": "데이터를 집계하기 위함"}, {"id": "C", "text": "JSON 데이터를 처리하기 위함"}, {"id": "D", "text": "업데이트된 데이터를 조회하기 위함"}]', '["A", "C"]', 'LATERAL JOIN은 서브쿼리 결과를 외부 쿼리에서 사용할 수 있게 하여, JSON 데이터와 결합할 때 유용합니다.'),
    (576, 3, 2, 80, 'SQL에서 쿼리 플랜이란 무엇인가?', 'SHORT_ANSWER', NULL, '쿼리 실행 계획을 의미하며, 쿼리가 실행될 때 데이터베이스가 선택하는 접근 방법과 순서를 나타냅니다.', '쿼리 플랜은 SQL 쿼리가 수행되는 방식을 세부적으로 설명하며, 성능 최적화에 중요한 역할을 합니다.'),
    (577, 3, 2, 81, '함수적 종속이란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '한 속성이 다른 속성을 결정하는 관계', '함수적 종속은 한 속성이 다른 속성의 값에 따라 결정되는 관계로, 데이터베이스에서 키를 정의하는 데 중요한 역할을 합니다.'),
    (578, 3, 2, 82, '정규화의 목적 중 하나는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 중복 최소화"}, {"id": "B", "text": "데이터의 비정상적 증가"}, {"id": "C", "text": "데이터 저장 용량 증가"}, {"id": "D", "text": "소프트웨어 성능 저하"}]', 'A', '정규화의 주요 목적 중 하나는 데이터의 중복을 최소화하여 무결성을 유지하는 것입니다.'),
    (579, 3, 2, 83, '다음 중 비정규화의 이유로 적절하지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성능 향상"}, {"id": "B", "text": "데이터 무결성 증가"}, {"id": "C", "text": "복잡한 쿼리 단순화"}, {"id": "D", "text": "데이터 접근 속도 증가"}]', 'B', '비정규화는 주로 성능 향상이나 데이터 접근 속도 증가를 위해 사용되며, 데이터 무결성을 증가시키기 위한 것은 아닙니다.'),
    (580, 3, 2, 84, '다음 중 후보키에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 속성이 포함되어야 한다."}, {"id": "B", "text": "한 테이블에서 유일해야 한다."}, {"id": "C", "text": "최소한의 속성으로 구성되어야 한다."}, {"id": "D", "text": "외래 키로 사용될 수 있다."}]', '["B", "C"]', '후보키는 한 테이블에서 유일해야 하며, 최소한의 속성으로 구성되어야 다른 후보키와 구별될 수 있습니다.'),
    (581, 3, 2, 85, 'SQL에서 UNPIVOT의 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "열을 행으로 변환한다."}, {"id": "B", "text": "행을 열로 변환한다."}, {"id": "C", "text": "데이터를 정렬한다."}, {"id": "D", "text": "데이터를 집계한다."}]', 'A', 'UNPIVOT은 열을 행으로 변환하여 데이터의 형식을 변경하는 기능을 제공합니다.'),
    (582, 3, 2, 86, 'WITH RECURSIVE 구문을 사용할 때 주로 어떤 문제를 해결할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단순한 집계 문제"}, {"id": "B", "text": "재귀적인 데이터 구조 탐색"}, {"id": "C", "text": "정렬된 데이터 생성"}, {"id": "D", "text": "다중 테이블 조인"}]', 'B', 'WITH RECURSIVE 구문은 재귀적인 데이터 구조를 탐색하는 데 유용합니다.'),
    (583, 3, 2, 87, 'LAG 함수의 주된 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 행의 데이터를 집계한다."}, {"id": "B", "text": "이전 행의 데이터를 참조한다."}, {"id": "C", "text": "행을 정렬한다."}, {"id": "D", "text": "행을 필터링한다."}]', 'B', 'LAG 함수는 현재 행의 데이터를 기준으로 이전 행의 데이터를 참조할 수 있게 해줍니다.'),
    (584, 3, 2, 88, '다음 중 인덱스 설계의 장점이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "검색 성능 향상"}, {"id": "B", "text": "데이터 삽입 성능 저하"}, {"id": "C", "text": "중복 데이터 감소"}, {"id": "D", "text": "쿼리 최적화"}]', '["B", "C"]', '인덱스 설계는 검색 성능을 향상시키지만, 데이터 삽입 성능을 저하시킬 수 있으며 중복 데이터를 줄이는 것과는 관련이 없습니다.'),
    (585, 3, 2, 89, 'SQL에서 LATERAL JOIN의 주 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '서브쿼리와 함께 열을 추가적으로 참조하기 위해 사용된다.', 'LATERAL JOIN은 서브쿼리에서 참조한 행을 기반으로 추가적인 열을 가져오기 위해 사용됩니다.'),
    (586, 3, 2, 90, '정규화의 주 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 중복성 최소화 및 무결성 확보', '정규화는 데이터의 중복성을 줄이고 데이터 무결성을 높이기 위한 과정입니다.'),
    (587, 3, 2, 91, '2NF에서 제거해야 하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 종속"}, {"id": "B", "text": "전체 종속"}, {"id": "C", "text": "이행적 종속"}, {"id": "D", "text": "삭제 이상"}]', 'A', '2NF에서는 부분 종속을 제거하는 것이 중요합니다.'),
    (588, 3, 2, 92, '다음 중 3NF의 정의로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 속성이 기본키에 전적으로 의존해야 함"}, {"id": "B", "text": "부분 종속이 존재해야 함"}, {"id": "C", "text": "기본키가 필요하지 않음"}, {"id": "D", "text": "삭제 이상을 허용함"}]', 'A', '3NF는 모든 비주요 속성이 기본키에 전적으로 의존해야 한다는 정의를 가지고 있습니다.'),
    (589, 3, 2, 93, '정규화의 장점과 단점을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "성능 저하"}, {"id": "C", "text": "무결성 증가"}, {"id": "D", "text": "설계 복잡성 증가"}]', '["A", "B", "C", "D"]', '정규화의 장점은 데이터 중복을 최소화하고 무결성을 증가시키지만, 성능 저하와 설계 복잡성을 초래할 수 있습니다.'),
    (590, 3, 2, 94, '1NF(제1정규형)의 주요 요구사항은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 열이 원자 값을 가져야 한다."}, {"id": "B", "text": "모든 열이 숫자여야 한다."}, {"id": "C", "text": "각 테이블에 최소한 하나의 외래키가 있어야 한다."}, {"id": "D", "text": "모든 데이터가 정렬되어 있어야 한다."}]', 'A', '1NF의 주요 요구사항은 각 열이 원자 값을 가져야 한다는 것입니다.'),
    (591, 3, 2, 95, 'BCNF(보이스-코드 정규형)에서 요구하는 조건은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 데이터가 정렬되어 있어야 한다."}, {"id": "B", "text": "모든 함수적 종속이 후보키에 의존해야 한다."}, {"id": "C", "text": "각 테이블에 최소한 두 개의 후보키가 있어야 한다."}, {"id": "D", "text": "데이터가 정규화 되어 있지 않아도 된다."}]', 'B', 'BCNF에서는 모든 함수적 종속이 후보키에 의존해야 한다는 조건이 있습니다.'),
    (592, 3, 2, 96, '데이터베이스에서 갱신 이상이란 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 중복되어 발생하는 문제이다."}, {"id": "B", "text": "데이터가 손실되는 현상이다."}, {"id": "C", "text": "테이블의 레코드가 잘못 연결되는 현상이다."}, {"id": "D", "text": "데이터가 무결성을 잃는 현상이다."}]', 'A', '갱신 이상은 데이터가 중복되어 발생하는 문제로, 정규화를 통해 해결할 수 있습니다.'),
    (593, 3, 2, 97, '정규화의 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 중복을 줄이기 위함."}, {"id": "B", "text": "데이터베이스의 성능을 높이기 위함."}, {"id": "C", "text": "데이터의 무결성을 향상시키기 위함."}, {"id": "D", "text": "사용자 접근성을 높이기 위함."}]', '["A", "C"]', '정규화의 주요 목적은 데이터의 중복을 줄이고 데이터의 무결성을 향상시키기 위함입니다.'),
    (594, 3, 2, 98, '후보키란 무엇인가?', 'SHORT_ANSWER', NULL, '테이블에서 각 행을 고유하게 식별할 수 있는 최소한의 속성 집합', '후보키는 테이블에서 각 행을 고유하게 식별할 수 있는 최소한의 속성 집합을 의미합니다.'),
    (595, 3, 2, 99, 'B+Tree 인덱스의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 정렬된 상태로 유지된다."}, {"id": "B", "text": "해시 인덱스보다 낮은 공간을 차지한다."}, {"id": "C", "text": "단순한 키-값 쿼리만 지원한다."}, {"id": "D", "text": "모든 쿼리에 대해 최적의 성능을 보인다."}]', 'A', 'B+Tree 인덱스는 데이터를 정렬된 상태로 유지함으로써 범위 검색에 최적화되어 있습니다.'),
    (596, 3, 2, 100, 'EXPLAIN 명령어의 주된 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 결과를 직접 출력한다."}, {"id": "B", "text": "쿼리 실행 계획을 보여준다."}, {"id": "C", "text": "인덱스를 생성한다."}, {"id": "D", "text": "데이터를 삭제한다."}]', 'B', 'EXPLAIN 명령어는 SQL 쿼리의 실행 계획을 보여주어 성능 분석에 도움을 줍니다.'),
    (597, 3, 2, 101, '인덱스 스캔과 테이블 스캔의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인덱스 스캔은 모든 데이터를 읽는 것이고, 테이블 스캔은 일부만 읽는다."}, {"id": "B", "text": "인덱스 스캔은 인덱스를 사용하여 데이터를 찾고, 테이블 스캔은 모든 행을 읽는다."}, {"id": "C", "text": "인덱스 스캔은 느리고, 테이블 스캔은 빠르다."}, {"id": "D", "text": "인덱스 스캔은 항상 성공하고, 테이블 스캔은 실패할 수 있다."}]', 'B', '인덱스 스캔은 인덱스를 사용하여 필요한 데이터를 찾는 반면, 테이블 스캔은 모든 행을 차례대로 읽습니다.'),
    (598, 3, 2, 102, '커버링 인덱스가 무엇인지 설명하시오.', 'SHORT_ANSWER', NULL, '커버링 인덱스는 쿼리에서 필요한 모든 데이터를 인덱스만으로 가져올 수 있는 인덱스입니다.', ''),
    (599, 3, 2, 103, '슬로우 쿼리를 식별하기 위한 방법은 무엇이 있는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "EXPLAIN 사용"}, {"id": "B", "text": "쿼리 캐시 확인"}, {"id": "C", "text": "모든 쿼리를 로그로 기록"}, {"id": "D", "text": "인덱스 재구성"}]', '["A", "C"]', '슬로우 쿼리는 EXPLAIN을 사용하여 실행 계획을 분석하거나, 쿼리를 로그로 기록하여 성능을 체크함으로써 식별할 수 있습니다.'),
    (600, 3, 2, 104, '정규화 단계 중 갱신 이상을 방지하기 위해 필요한 단계는 무엇인가요?', 'SHORT_ANSWER', NULL, '3NF', '3NF는 모든 비주요 속성이 기본키에만 의존하도록 하여 갱신 이상을 방지합니다.'),
    (601, 3, 2, 105, '다음 중 외래키의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다른 테이블의 기본키를 참조하는 속성이다."}, {"id": "B", "text": "테이블의 모든 속성을 포함하는 집합이다."}, {"id": "C", "text": "기본키 후보를 정의하는 속성이다."}, {"id": "D", "text": "데이터베이스 설계의 최종 결과물이다."}]', 'A', '외래키는 다른 테이블의 기본키를 참조하여 관계를 형성하는 속성입니다.'),
    (602, 3, 2, 106, '다음 중 정규화의 단계가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1NF"}, {"id": "B", "text": "2NF"}, {"id": "C", "text": "3NF"}, {"id": "D", "text": "비정규화"}]', 'D', '비정규화는 정규화의 반대 과정으로, 정규화의 단계가 아닙니다.'),
    (603, 3, 2, 107, '정규화의 목적에 해당하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "무결성 유지"}, {"id": "C", "text": "성능 향상"}, {"id": "D", "text": "갱신 이상 방지"}]', '["A", "B", "D"]', '정규화의 주목적은 데이터 중복 최소화, 무결성 유지, 갱신 이상 방지입니다.'),
    (604, 3, 2, 108, '정규화 과정에서 해결하고자 하는 문제 중 하나가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "갱신 이상"}, {"id": "B", "text": "삭제 이상"}, {"id": "C", "text": "데이터 암호화"}, {"id": "D", "text": "삽입 이상"}]', 'C', '정규화의 목적은 데이터 중복을 줄이고 무결성을 높이는 것이며, 데이터 암호화는 정규화와는 관련이 없는 개념입니다.'),
    (605, 3, 2, 109, '3NF(세 번째 정규형)의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 비주요 속성이 기본키에 완전 종속되어야 한다."}, {"id": "B", "text": "모든 속성이 유일해야 한다."}, {"id": "C", "text": "부분 종속이 없어야 한다."}, {"id": "D", "text": "이행 종속이 없어야 한다."}]', 'D', '3NF에서 요구되는 것은 이행 종속이 없어야 한다는 것입니다.'),
    (606, 3, 2, 110, '다음 중 데이터베이스에서 외래키의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 유일성을 보장한다."}, {"id": "B", "text": "두 테이블 간의 관계를 설정한다."}, {"id": "C", "text": "데이터의 크기를 줄인다."}, {"id": "D", "text": "데이터를 암호화한다."}]', 'B', '외래키는 두 테이블 간의 관계를 설정하여 참조 무결성을 유지하는 역할을 합니다.'),
    (607, 3, 2, 111, '정규화의 목적 중 올바르지 않은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "갱신 이상 방지"}, {"id": "C", "text": "쿼리 성능 향상"}, {"id": "D", "text": "데이터 무결성 강화"}]', '["C"]', '정규화의 주요 목적은 데이터 중복을 최소화하고 무결성을 강화하는 것이며, 쿼리 성능 향상은 항상 보장되지 않습니다.'),
    (608, 3, 2, 112, '반정규화의 주된 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '성능 향상', '반정규화는 데이터베이스의 성능을 향상시키기 위해 중복을 허용하는 과정입니다.'),
    (609, 3, 2, 113, 'LAG 함수의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 값을 반환한다."}, {"id": "B", "text": "다음 행의 값을 반환한다."}, {"id": "C", "text": "중복된 값을 제거한다."}, {"id": "D", "text": "데이터를 정렬한다."}]', 'A', 'LAG 함수는 주어진 행의 이전 행의 값을 반환하는 분석 함수입니다.'),
    (610, 3, 2, 114, 'CTE는 무엇의 약자이며, 어떤 목적으로 사용하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Common Table Expressions, 쿼리의 가독성을 높인다."}, {"id": "B", "text": "Complex Table Expressions, 복잡한 데이터를 처리한다."}, {"id": "C", "text": "Centralized Table Expressions, 중앙 집중형 테이블을 만든다."}, {"id": "D", "text": "Conditional Table Expressions, 조건부 테이블을 생성한다."}]', 'A', 'CTE는 Common Table Expressions의 약자로, 쿼리를 더 간결하고 가독성 있게 작성하는 데 도움을 줍니다.'),
    (611, 3, 2, 115, '다음 중 JSON 함수에 대한 설명으로 옳지 않은 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "JSON 데이터를 삽입할 수 있다."}, {"id": "B", "text": "JSON 데이터를 필터링할 수 있다."}, {"id": "C", "text": "JSON 데이터를 암호화할 수 있다."}, {"id": "D", "text": "JSON 데이터를 파싱할 수 있다."}]', 'C', 'JSON 함수는 JSON 데이터를 삽입, 필터링, 파싱할 수 있지만 암호화 기능은 지원하지 않습니다.'),
    (612, 3, 2, 116, '쿼리 플랜을 최적화하는 방법에는 어떤 것들이 있나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인덱스 사용"}, {"id": "B", "text": "불필요한 CTE 제거"}, {"id": "C", "text": "JOIN을 단순화"}, {"id": "D", "text": "INNER JOIN만 사용"}]', '["A", "B", "C"]', '쿼리 플랜 최적화를 위해 인덱스 사용, 불필요한 CTE 제거, JOIN 단순화 등이 효과적입니다.'),
    (613, 3, 2, 117, 'UNPIVOT의 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터를 열에서 행으로 변환하는 기능입니다.', 'UNPIVOT은 데이터의 형식을 변경하여 열을 행으로 변환하는 기능을 제공합니다.'),
    (614, 3, 2, 118, '커버링 인덱스의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 성능을 향상시킬 수 있다."}, {"id": "B", "text": "데이터를 중복 저장할 수 있다."}, {"id": "C", "text": "데이터베이스를 쉽게 복원할 수 있다."}, {"id": "D", "text": "쿼리의 결과를 캐싱할 수 있다."}]', 'A', '커버링 인덱스는 쿼리에서 필요한 모든 데이터를 인덱스 내에서 찾을 수 있게 해 주어 성능을 향상시킵니다.'),
    (615, 3, 2, 119, 'EXPLAIN 명령어의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 삭제하는 데 사용된다."}, {"id": "B", "text": "쿼리의 실행 계획을 보여준다."}, {"id": "C", "text": "인덱스를 만드는 데 사용된다."}, {"id": "D", "text": "데이터베이스를 백업하는 데 사용된다."}]', 'B', 'EXPLAIN 명령어는 쿼리의 실행 계획을 보여주어, 최적화에 유용합니다.'),
    (616, 3, 2, 120, '복합 인덱스의 주된 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하나의 열만 인덱싱할 수 있다."}, {"id": "B", "text": "여러 열을 조합하여 검색할 때 성능이 향상된다."}, {"id": "C", "text": "데이터의 중복성을 줄여준다."}, {"id": "D", "text": "데이터를 자동으로 정렬해준다."}]', 'B', '복합 인덱스는 여러 열을 조합하여 검색할 때 성능을 향상시킵니다.'),
    (617, 3, 2, 121, '클러스터드 인덱스의 특징 중 하나는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터가 물리적으로 정렬되어 저장된다."}, {"id": "B", "text": "여러 개를 만들 수 있다."}, {"id": "C", "text": "인덱스의 키 값이 데이터와 일치한다."}, {"id": "D", "text": "인덱스의 크기가 항상 작다."}]', '["A", "C"]', '클러스터드 인덱스는 데이터가 물리적으로 정렬되어 저장되며, 인덱스의 키 값이 데이터와 일치합니다.'),
    (618, 3, 2, 122, 'B+Tree의 주된 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '높은 검색 속도와 효율적인 공간 사용', ''),
    (619, 3, 2, 123, 'LEAD 함수의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다음 행의 값을 조회하는 것"}, {"id": "B", "text": "행을 정렬하는 것"}, {"id": "C", "text": "행을 삭제하는 것"}, {"id": "D", "text": "열을 추가하는 것"}]', 'A', 'LEAD 함수는 현재 행의 다음 행 값을 조회하여 분석할 수 있게 해줍니다.'),
    (620, 3, 2, 124, '재귀 CTE의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "계층적 데이터 처리"}, {"id": "B", "text": "데이터 정렬"}, {"id": "C", "text": "데이터 저장"}, {"id": "D", "text": "데이터 삭제"}]', 'A', '재귀 CTE는 계층 구조를 가진 데이터를 효율적으로 처리하는 데 사용됩니다.'),
    (621, 3, 2, 125, 'UNPIVOT 연산의 기능 중 어떤 것이 아닌가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행을 열로 변환"}, {"id": "B", "text": "열을 행으로 변환"}, {"id": "C", "text": "데이터 구조 변경"}, {"id": "D", "text": "데이터 형태 변환"}]', 'A', 'UNPIVOT은 열을 행으로 변환하는 작업을 수행합니다.'),
    (622, 3, 2, 126, '다음 중 SQL 성능 튜닝과 관련된 기법이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인덱스 사용"}, {"id": "B", "text": "쿼리 플랜 분석"}, {"id": "C", "text": "데이터 중복 저장"}, {"id": "D", "text": "JOIN 최적화"}]', '["C"]', '데이터 중복 저장은 성능 튜닝 기법과 관련이 없습니다.'),
    (623, 3, 2, 127, 'NTILE 함수는 주로 무엇에 사용되는가?', 'SHORT_ANSWER', NULL, '데이터를 균등하게 나누어 그룹을 만드는 것', 'NTILE 함수는 데이터를 N개의 그룹으로 나누어 각각의 그룹을 생성하는 데 사용됩니다.'),
    (624, 3, 2, 128, '쿼리 튜닝의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 검색 속도 향상"}, {"id": "B", "text": "데이터 백업"}, {"id": "C", "text": "데이터 암호화"}, {"id": "D", "text": "데이터 삭제"}]', 'A', '쿼리 튜닝은 데이터베이스에서 쿼리의 성능을 최적화하여 데이터 검색 속도를 향상시키는 것을 목표로 합니다.'),
    (625, 3, 2, 129, '클러스터드 인덱스가 하는 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 실제 데이터를 정렬"}, {"id": "B", "text": "추가적인 데이터를 저장"}, {"id": "C", "text": "데이터를 암호화"}, {"id": "D", "text": "인덱스를 생성하지 않는다"}]', 'A', '클러스터드 인덱스는 테이블의 실제 데이터를 정렬하여 저장하는 역할을 합니다.'),
    (626, 3, 2, 130, 'B+Tree와 B-Tree의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "B+Tree는 리프 노드에 모든 데이터를 저장한다"}, {"id": "B", "text": "B-Tree는 리프 노드가 아니다"}, {"id": "C", "text": "B+Tree는 성능이 더 떨어진다"}, {"id": "D", "text": "B-Tree는 인덱스 스캔을 지원하지 않는다"}]', 'A', 'B+Tree는 리프 노드에 모든 데이터를 저장하고, 내부 노드는 포인터만 포함합니다. 반면, B-Tree는 모든 노드에 데이터를 저장할 수 있습니다.'),
    (627, 3, 2, 131, '인덱스 타입 중 해시 인덱스의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "해시 함수를 사용하여 값을 검색한다"}, {"id": "B", "text": "정렬된 데이터를 저장한다"}, {"id": "C", "text": "빠른 검색을 지원한다"}, {"id": "D", "text": "인덱스 스캔을 지원한다"}]', '["A", "C"]', '해시 인덱스는 해시 함수를 사용하여 특정 값을 빠르게 찾을 수 있도록 지원하며, 빠른 검색을 가능하게 합니다.'),
    (628, 3, 2, 132, 'B-Tree의 주된 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '균형을 유지하여 검색 성능을 보장한다', 'B-Tree는 데이터베이스에서 균형을 유지하여 검색 성능을 보장하는 구조입니다.'),
    (629, 3, 2, 133, '쿼리 플랜은 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리를 최적화하기 위한 실행 계획"}, {"id": "B", "text": "데이터베이스의 백업 전략"}, {"id": "C", "text": "사용자 권한 관리에 대한 계획"}, {"id": "D", "text": "서버의 하드웨어 사양"}]', 'A', '쿼리 플랜은 SQL 쿼리의 실행 방법을 최적화하기 위해 데이터베이스가 생성하는 계획을 의미합니다.'),
    (630, 3, 2, 134, '정규표현식이 주로 사용되는 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스 백업"}, {"id": "B", "text": "문자열 검색 및 처리"}, {"id": "C", "text": "파일 압축"}, {"id": "D", "text": "데이터베이스 인덱스 생성"}]', 'B', '정규표현식은 문자열에서 특정 패턴을 검색하거나 문자열을 처리하는 데 주로 사용됩니다.'),
    (631, 3, 2, 135, 'LATERAL JOIN의 가장 큰 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서브쿼리의 결과를 메인 쿼리에서 사용할 수 있음"}, {"id": "B", "text": "더 빠른 인덱스 검색"}, {"id": "C", "text": "데이터를 직접 수정할 수 있음"}, {"id": "D", "text": "복잡한 연산을 단순화할 수 있음"}]', 'A', 'LATERAL JOIN은 서브쿼리의 결과를 메인 쿼리의 각 행에 대해 사용할 수 있게 해줍니다.'),
    (632, 3, 2, 136, 'UNPIVOT 기능의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "열을 행으로 변환하기 위해"}, {"id": "B", "text": "데이터를 압축하기 위해"}, {"id": "C", "text": "제약 조건을 설정하기 위해"}, {"id": "D", "text": "쿼리 성능을 향상시키기 위해"}]', '["A"]', 'UNPIVOT은 데이터를 행 방향으로 변환하여 분석이나 보고서 작성에 유용하도록 만드는 기능입니다.'),
    (633, 3, 2, 137, 'WITH RECURSIVE 구문은 어떤 목적으로 사용되는가?', 'SHORT_ANSWER', NULL, '재귀 쿼리를 작성하여 계층 구조의 데이터를 조회하기 위해 사용된다.', 'WITH RECURSIVE는 재귀적 쿼리를 사용하여 계층적으로 연결된 데이터를 효과적으로 가져오기 위해 사용됩니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 데이터베이스 > 트랜잭션과 동시성 (123문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (634, 3, 3, 1, 'CAP 이론에서 참조하는 세 가지 요소는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성, 가용성, 분할 허용성"}, {"id": "B", "text": "일관성, 유연성, 신뢰성"}, {"id": "C", "text": "가용성, 성능, 유연성"}, {"id": "D", "text": "일관성, 성능, 분할 허용성"}]', 'A', 'CAP 이론은 Consistency, Availability, Partition Tolerance의 세 가지 요소를 설명합니다.'),
    (635, 3, 3, 2, '수평 파티셔닝과 해시 파티셔닝의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 여러 서버에 분산 저장한다."}, {"id": "B", "text": "데이터의 일관성을 보장한다."}, {"id": "C", "text": "트랜잭션을 단일 서버에서 처리한다."}, {"id": "D", "text": "양쪽 모두 단일 지점을 갖는다."}]', 'A', '수평 파티셔닝과 해시 파티셔닝은 데이터를 여러 서버에 분산 저장하는 방법입니다.'),
    (636, 3, 3, 3, '2PC 프로토콜의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 마이닝을 위한 최적화"}, {"id": "B", "text": "분산 트랜잭션의 일관성을 보장"}, {"id": "C", "text": "쿼리 성능 향상"}, {"id": "D", "text": "데이터 백업 관리"}, {"id": "B", "text": "분산 트랜잭션의 일관성을 보장"}]', 'B', '2PC 프로토콜은 분산 트랜잭션에서 일관성을 보장하는 것이 주요 목적입니다.'),
    (637, 3, 3, 4, '다음 중 분산 데이터베이스의 일관성을 보장하는 방법으로 적절한 것은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "레플리케이션"}, {"id": "B", "text": "캐시 사용"}, {"id": "C", "text": "쿼럼 설정"}, {"id": "D", "text": "데이터 복제"}]', '["A", "C", "D"]', '레플리케이션, 쿼럼 설정, 데이터 복제는 모두 일관성을 보장하는 데 중요한 방법입니다.'),
    (638, 3, 3, 5, '강한 일관성의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '모든 트랜잭션이 완료된 후 모든 노드에서 동일한 데이터 상태를 유지하는 것', '강한 일관성은 모든 트랜잭션이 완료된 후 모든 노드에서 동일한 데이터 상태를 유지하는 것을 의미합니다.'),
    (639, 3, 3, 6, '트랜잭션의 ACID 속성 중 ''지속성''이 의미하는 것은 무엇인가?', 'SHORT_ANSWER', NULL, '트랜잭션이 완료된 후 그 결과가 영구적으로 저장됨을 보장', ''),
    (640, 3, 3, 7, '다음 중 MVCC의 장점으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동시성 향상"}, {"id": "B", "text": "데이터 복구"}, {"id": "C", "text": "단순한 설계"}, {"id": "D", "text": "불필요한 락 방지"}]', 'A', 'MVCC는 여러 버전을 유지하여 동시성을 높이는 데 기여합니다.'),
    (641, 3, 3, 8, '비관적 락과 배타 락의 차이에 대한 설명으로 맞는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비관적 락은 항상 잠금을 사용한다."}, {"id": "B", "text": "배타 락은 여러 트랜잭션이 동시에 접근할 수 있도록 허용한다."}, {"id": "C", "text": "비관적 락은 자원을 잠글 위험을 최소화한다."}, {"id": "D", "text": "배타 락은 한 트랜잭션이 자원을 사용할 때 다른 트랜잭션의 접근을 막는다."}]', 'D', '배타 락은 한 트랜잭션이 자원을 사용할 때 다른 트랜잭션의 접근을 차단합니다.'),
    (642, 3, 3, 9, 'READ UNCOMMITTED 격리 수준에서 발생할 수 있는 현상은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "더티 리드"}, {"id": "B", "text": "비직렬 가능성"}, {"id": "C", "text": "팬텀 리드"}, {"id": "D", "text": "논리적 오류"}]', '["A", "B"]', 'READ UNCOMMITTED는 더티 리드와 비직렬 가능성을 초래할 수 있습니다.'),
    (643, 3, 3, 10, 'CAP 이론에서 설명하는 세 가지 요소 중 어떤 것이 데이터의 일관성을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Consistency"}, {"id": "B", "text": "Availability"}, {"id": "C", "text": "Partition Tolerance"}, {"id": "D", "text": "Scalability"}]', 'A', 'CAP 이론에서 ''C''는 Consistency를 의미하며, 데이터의 일관성을 유지하는 것을 나타냅니다.'),
    (644, 3, 3, 11, '분산 데이터베이스에서 수직 파티셔닝의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 행을 기준으로 나누는 것"}, {"id": "B", "text": "테이블의 열을 기준으로 나누는 것"}, {"id": "C", "text": "데이터를 시간 순으로 나누는 것"}, {"id": "D", "text": "데이터를 지역적으로 나누는 것"}]', 'B', '수직 파티셔닝은 테이블의 열을 기준으로 나누어 데이터베이스의 성능을 향상시키는 기법입니다.'),
    (645, 3, 3, 12, 'Eventual Consistency의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "즉각적인 데이터 일관성을 보장한다"}, {"id": "B", "text": "데이터는 시간이 지나면서 일관성을 가진다"}, {"id": "C", "text": "모든 데이터는 항상 일관성을 유지한다"}, {"id": "D", "text": "데이터베이스가 항상 가용성을 유지한다"}]', 'B', 'Eventual Consistency는 모든 업데이트가 시간이 지나면 일관성을 가지게 되는 모델입니다.'),
    (646, 3, 3, 13, '다음 중 분산 데이터베이스의 장점이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "높은 가용성"}, {"id": "B", "text": "향상된 성능"}, {"id": "C", "text": "복잡한 쿼리 처리"}, {"id": "D", "text": "데이터 손실 방지"}]', '["C"]', '분산 데이터베이스는 높은 가용성과 성능을 제공하지만, 복잡한 쿼리 처리는 오히려 어렵고 성능 저하를 유발할 수 있습니다.'),
    (647, 3, 3, 14, '분산 데이터베이스에서 샤딩의 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터의 분산 저장과 성능 향상', '샤딩은 데이터베이스의 데이터를 여러 샤드로 나누어 저장하여 시스템의 성능을 향상시키고 부하를 분산시키기 위한 기법입니다.'),
    (648, 3, 3, 15, '데이터 레이크와 데이터 웨어하우스의 주요 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 레이크는 비정형 데이터를 저장하고, 데이터 웨어하우스는 구조화된 데이터를 저장한다."}, {"id": "B", "text": "둘 다 같은 방식으로 데이터를 저장한다."}, {"id": "C", "text": "데이터 웨어하우스는 실시간 데이터 처리에 최적화되어 있다."}, {"id": "D", "text": "데이터 레이크는 항상 더 안전하다."}]', 'A', '데이터 레이크는 비정형 데이터를 그대로 저장할 수 있고, 데이터 웨어하우스는 정형 데이터를 처리하는 데 최적화되어 있다.'),
    (649, 3, 3, 16, '스트림 처리와 배치 처리의 주된 차이는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스트림 처리는 실시간 데이터, 배치 처리는 정기적인 데이터 처리이다."}, {"id": "B", "text": "둘 다 실시간 데이터 처리 방식이다."}, {"id": "C", "text": "배치 처리는 데이터의 양에 관계없이 항상 느리다."}, {"id": "D", "text": "스트림 처리는 데이터의 양에 관계없이 항상 빠르다."}]', 'A', '스트림 처리는 실시간으로 데이터를 처리하는 반면, 배치 처리는 일정한 간격으로 데이터를 처리한다.'),
    (650, 3, 3, 17, 'Apache Flink의 주요 기능 중 하나는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "실시간 데이터 스트림 처리"}, {"id": "B", "text": "정형 데이터 저장"}, {"id": "C", "text": "데이터 시각화"}, {"id": "D", "text": "기계 학습 알고리즘 제공"}]', 'A', 'Apache Flink는 실시간 데이터 스트림 처리를 지원하는 강력한 프레임워크이다.'),
    (651, 3, 3, 18, 'ETL 파이프라인에서 사용되는 두 가지 스키마 접근 방식은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스키마 온 라이트"}, {"id": "B", "text": "스키마 온 리드"}, {"id": "C", "text": "스키마 온 더 플라이"}, {"id": "D", "text": "스키마 온 스토리지"}]', '["A", "B"]', 'ETL 파이프라인에서는 스키마 온 라이트와 스키마 온 리드 두 가지 접근 방식이 사용된다.'),
    (652, 3, 3, 19, 'ETL 프로세스를 자동화하는 도구는?', 'SHORT_ANSWER', NULL, 'Airflow', ''),
    (653, 3, 3, 20, '파티셔닝의 주요 방식에는 어떤 것이 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "수직 파티셔닝"}, {"id": "B", "text": "수평 파티셔닝"}, {"id": "C", "text": "수직 및 수평 파티셔닝"}, {"id": "D", "text": "모든 보기"}]', 'C', '파티셔닝은 데이터를 수직 및 수평으로 나눌 수 있으며, 두 가지 모두 사용될 수 있습니다.'),
    (654, 3, 3, 21, 'CAP 이론에서 ''A''는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "가용성"}, {"id": "C", "text": "파티셔닝 허용성"}, {"id": "D", "text": "속도"}]', 'B', '''A''는 ''가용성(Availability)''을 의미하며, 시스템이 항상 요청에 응답할 수 있는 능력을 나타냅니다.'),
    (655, 3, 3, 22, '2PC(2-Phase Commit)의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 복제"}, {"id": "B", "text": "트랜잭션 관리"}, {"id": "C", "text": "데이터 파티셔닝"}, {"id": "D", "text": "쿼럼 설정"}]', 'B', '2PC는 분산 트랜잭션을 관리하고, 모든 참여 노드가 트랜잭션의 커밋 여부에 대해 동의하도록 합니다.'),
    (656, 3, 3, 23, '분산 DB의 가용성을 높이기 위해 사용하는 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "샤딩"}, {"id": "B", "text": "쿼럼 설정"}, {"id": "C", "text": "2PC 사용"}, {"id": "D", "text": "복제"}]', '["A", "D"]', '샤딩과 데이터의 복제는 모두 분산 DB의 가용성을 높이는 데 기여하는 방법입니다.'),
    (657, 3, 3, 24, '쿼럼의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '특정 작업을 수행하기 위한 최소한의 노드 수', ''),
    (658, 3, 3, 25, '분산 데이터베이스의 특징 중 하나가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "높은 가용성"}, {"id": "B", "text": "서버 간 데이터 중복"}, {"id": "C", "text": "단일 실패 지점"}, {"id": "D", "text": "확장성"}]', 'C', '분산 데이터베이스는 단일 실패 지점이 아니라 여러 서버에 데이터를 분산하여 고가용성을 제공하기 때문에 C가 정답입니다.'),
    (659, 3, 3, 26, 'CAP 이론에서 ''Partition Tolerance''란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 항상 일관되게 유지되는 것"}, {"id": "B", "text": "네트워크 분할 상황에서도 시스템이 작동하는 것"}, {"id": "C", "text": "시스템이 항상 사용 가능해야 하는 것"}, {"id": "D", "text": "데이터 저장 공간을 최적화하는 것"}]', 'B', '''Partition Tolerance''는 네트워크 분할 상황에서도 시스템이 계속 작동할 수 있는 것을 의미합니다.'),
    (660, 3, 3, 27, '강한 일관성과 Eventual Consistency의 차이는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "강한 일관성은 즉각적인 일관성을 보장한다."}, {"id": "B", "text": "Eventual Consistency는 데이터를 완전히 동기화한다."}, {"id": "C", "text": "강한 일관성은 높은 가용성을 제공한다."}, {"id": "D", "text": "Eventual Consistency는 모든 노드가 동시에 업데이트된다."}]', 'A', '강한 일관성은 모든 노드가 즉각적으로 동일한 데이터를 제공해야 함을 의미합니다.'),
    (661, 3, 3, 28, '해시 파티셔닝과 수직 파티셔닝의 공통점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 분산하여 저장한다."}, {"id": "B", "text": "데이터의 일관성을 보장한다."}, {"id": "C", "text": "데이터를 효율적으로 관리한다."}, {"id": "D", "text": "데이터의 가용성을 높인다."}]', '["A", "C", "D"]', '두 파티셔닝 방법 모두 데이터를 분산하여 저장하고, 효율적으로 관리하며 가용성을 높이는 특징이 있습니다.'),
    (662, 3, 3, 29, '3PC 프로토콜에서 3PC는 무엇의 약자인가?', 'SHORT_ANSWER', NULL, 'Three-Phase Commit', '3PC는 ''Three-Phase Commit''의 약자로, 분산 트랜잭션의 일관성을 보장하기 위한 프로토콜입니다.'),
    (663, 3, 3, 30, '파티셔닝의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 여러 조각으로 나누어 저장하는 방법이다."}, {"id": "B", "text": "데이터를 하나의 노드에만 저장하는 방법이다."}, {"id": "C", "text": "데이터베이스의 성능을 저하시키는 방법이다."}, {"id": "D", "text": "데이터의 백업을 위한 절차이다."}]', 'A', '파티셔닝은 데이터를 여러 조각으로 나누어 저장하는 방법으로, 데이터 접근성을 높이기 위함이다.'),
    (664, 3, 3, 31, '분산 데이터베이스의 마스터-마스터 구조의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드가 읽기만 가능하다."}, {"id": "B", "text": "모든 노드가 동시에 데이터를 쓸 수 있다."}, {"id": "C", "text": "한 노드만 데이터에 접근할 수 있다."}, {"id": "D", "text": "데이터가 모두 중앙 집중식으로 관리된다."}]', 'B', '마스터-마스터 구조는 모든 노드가 동시에 데이터를 쓸 수 있는 구조이다.'),
    (665, 3, 3, 32, '다음 중 CAP 이론의 요소가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "가용성"}, {"id": "C", "text": "성능"}, {"id": "D", "text": "파티션 허용성"}]', 'C', 'CAP 이론의 요소는 일관성, 가용성, 파티션 허용성으로 성능은 포함되지 않는다.'),
    (666, 3, 3, 33, '수직 파티셔닝의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 검색 속도를 향상시키기 위해"}, {"id": "B", "text": "데이터 저장 공간을 줄이기 위해"}, {"id": "C", "text": "데이터의 일관성을 높이기 위해"}, {"id": "D", "text": "데이터 접근성을 높이기 위해"}]', '["A", "D"]', '수직 파티셔닝은 데이터 검색 속도를 향상시키고 데이터 접근성을 높이기 위한 방법이다.'),
    (667, 3, 3, 34, '해시 파티셔닝의 원리는 무엇인가?', 'SHORT_ANSWER', NULL, '데이터의 해시 값을 기반으로 데이터를 분리하는 원리이다.', '해시 파티셔닝은 데이터의 해시 값을 기반으로 데이터를 여러 파티션으로 나누어 저장하는 방법이다.'),
    (668, 3, 3, 35, '3단계 커밋 프로토콜(3PC)의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "강한 일관성을 유지하기 위해"}, {"id": "B", "text": "데이터를 암호화하기 위해"}, {"id": "C", "text": "데이터를 압축하기 위해"}, {"id": "D", "text": "데이터를 시각화하기 위해"}]', 'A', '3PC는 분산 트랜잭션에서 강한 일관성을 유지하기 위해 설계된 프로토콜입니다.'),
    (669, 3, 3, 36, 'Eventual Consistency란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 데이터가 즉시 일관성 있게 반영됨"}, {"id": "B", "text": "데이터가 시간이 지남에 따라 일관성을 갖게 됨"}, {"id": "C", "text": "데이터가 절대 일관성을 유지해야 함"}, {"id": "D", "text": "데이터가 한 번에 모든 노드에 반영됨"}]', 'B', 'Eventual Consistency는 데이터가 시간이 지나면서 일관성을 회복하게 되는 모델입니다.'),
    (670, 3, 3, 37, 'CAP 이론에서 어떤 세 가지 특성을 다루는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성, 가용성, 분산내구성"}, {"id": "B", "text": "속도, 규모, 안전성"}, {"id": "C", "text": "유연성, 신뢰성, 일관성"}, {"id": "D", "text": "가용성, 속도, 보안"}]', 'A', 'CAP 이론은 일관성(Consistency), 가용성(Availability), 분산내구성(Partition Tolerance) 간의 트레이드오프를 설명합니다.'),
    (671, 3, 3, 38, '다음 중 해시 파티셔닝과 관련된 것은 무엇인가? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 고르게 분산시킨다."}, {"id": "B", "text": "데이터의 순서를 유지한다."}, {"id": "C", "text": "특정 키를 기반으로 데이터를 나눈다."}, {"id": "D", "text": "데이터를 동일한 크기로 나눈다."}]', '["A", "C"]', '해시 파티셔닝은 특정 키를 기반으로 데이터를 나누고, 이를 통해 데이터를 고르게 분산시킵니다.'),
    (672, 3, 3, 39, '샤딩의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '대량의 데이터를 효율적으로 처리하기 위해', '샤딩은 대량의 데이터를 여러 데이터베이스 인스턴스로 나누어 처리 효율성을 높이기 위한 방법입니다.'),
    (673, 3, 3, 40, '분산 데이터베이스에서 마스터-슬레이브 구조의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "읽기 전용 슬레이브가 존재한다."}, {"id": "B", "text": "모든 노드가 쓰기 작업을 수행한다."}, {"id": "C", "text": "데이터가 샤딩 방식으로 분산된다."}, {"id": "D", "text": "트랜잭션이 항상 강한 일관성을 유지한다."}]', 'A', '마스터-슬레이브 구조에서는 마스터 노드가 쓰기 작업을 처리하고, 슬레이브 노드는 읽기 전용으로 사용되는 것이 일반적이다.'),
    (674, 3, 3, 41, 'CAP 이론에서 동시에 만족할 수 없는 요소가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성(Consistency)"}, {"id": "B", "text": "가용성(Availability)"}, {"id": "C", "text": "파티션 내성(Partition Tolerance)"}, {"id": "D", "text": "속도(Speed)"}]', 'D', 'CAP 이론에서는 일관성, 가용성, 파티션 내성의 세 가지 요소를 동시에 만족할 수 없음을 설명한다.'),
    (675, 3, 3, 42, '샤딩에서 데이터가 나누어지는 기준은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 크기"}, {"id": "B", "text": "데이터의 범위 또는 키 값"}, {"id": "C", "text": "데이터의 타입"}, {"id": "D", "text": "트랜잭션의 수"}]', 'B', '샤딩은 데이터의 범위 또는 키 값에 따라 데이터를 여러 조각으로 나누는 방법이다.'),
    (676, 3, 3, 43, '2PC와 3PC의 차이점 중 가장 중요한 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "3PC는 2PC보다 더 빠르다."}, {"id": "B", "text": "3PC는 장애 발생 시 더욱 안전하다."}, {"id": "C", "text": "2PC는 트랜잭션을 보장하지 않는다."}, {"id": "D", "text": "3PC는 추가적인 단계가 있다."}]', '["B", "D"]', '3PC는 장애 발생 시 더욱 안전하며, 2PC에 비해 추가적인 단계가 있어 더 많은 안정성을 제공한다.'),
    (677, 3, 3, 44, '강한 일관성의 정의는?', 'SHORT_ANSWER', NULL, '모든 트랜잭션이 완료된 후 모든 노드에서 동일한 데이터 상태를 유지하는 것', '강한 일관성은 시스템의 모든 노드가 동일한 상태를 유지하여 데이터의 정확성을 보장하는 특성이다.'),
    (678, 3, 3, 45, 'ETL의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '추출, 변환, 적재', 'ETL은 Extract, Transform, Load의 약자로, 데이터 웨어하우스에 데이터를 통합하기 위한 과정입니다.'),
    (679, 3, 3, 46, 'Apache Spark와 Flink의 공통점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스트림 처리 지원"}, {"id": "B", "text": "데이터베이스 관리 시스템"}, {"id": "C", "text": "ETL 전용 도구"}, {"id": "D", "text": "웹 서버 기능 내장"}]', 'A', 'Apache Spark와 Flink는 모두 스트림 처리를 지원하는 데이터 처리 플랫폼입니다.'),
    (680, 3, 3, 47, 'Hadoop은 주로 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "대량 데이터 저장"}, {"id": "B", "text": "단일 데이터베이스 관리"}, {"id": "C", "text": "웹 페이지 호스팅"}, {"id": "D", "text": "소셜 미디어 분석"}]', 'A', 'Hadoop은 대량의 데이터를 저장하고 처리하기 위한 분산 컴퓨팅 플랫폼입니다.'),
    (681, 3, 3, 48, '스키마 온 라이트 방식의 장점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "성능 최적화"}, {"id": "B", "text": "데이터 일관성 보장"}, {"id": "C", "text": "유연한 데이터 처리"}, {"id": "D", "text": "데이터 접근 속도 향상"}]', '["A", "B", "D"]', '스키마 온 라이트 방식은 성능 최적화, 데이터 일관성 보장 및 데이터 접근 속도 향상의 장점을 제공합니다.'),
    (682, 3, 3, 49, 'ETL 과정에서 데이터가 변환되는 단계는 어디에 위치하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "추출 후"}, {"id": "B", "text": "로딩 후"}, {"id": "C", "text": "저장 전"}, {"id": "D", "text": "저장 후"}]', 'A', 'ETL 과정에서 데이터는 먼저 추출된 후 변환됩니다.'),
    (683, 3, 3, 50, 'Hadoop의 데이터 처리 모델은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "MapReduce"}, {"id": "B", "text": "ETL"}, {"id": "C", "text": "DAG"}, {"id": "D", "text": "Spark"}]', 'A', 'Hadoop은 MapReduce 모델을 사용하여 대량의 데이터를 처리합니다.'),
    (684, 3, 3, 51, '스키마 온 라이트(Schema on Write)의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 저장 시 정의된 스키마 사용"}, {"id": "B", "text": "데이터 로드 후 스키마 정의"}, {"id": "C", "text": "스키마 없이 데이터 저장"}, {"id": "D", "text": "동적 스키마 지원"}]', 'A', '스키마 온 라이트는 데이터가 저장될 때 미리 정의된 스키마를 사용하는 방식입니다.'),
    (685, 3, 3, 52, '다음 중 Apache Spark의 특징으로 올바르지 않은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인메모리 데이터 처리"}, {"id": "B", "text": "서버리스 아키텍처 지원"}, {"id": "C", "text": "빠른 데이터 처리"}, {"id": "D", "text": "실시간 데이터 처리"}]', '["B"]', 'Apache Spark는 인메모리 데이터 처리를 지원하지만 서버리스 아키텍처를 직접적으로 지원하지 않습니다.'),
    (686, 3, 3, 53, 'DAG의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, 'Directed Acyclic Graph', 'DAG는 Directed Acyclic Graph의 약자로, 방향성이 있는 비순환 그래프를 의미합니다.'),
    (687, 3, 3, 54, '트랜잭션의 ACID 속성 중 지속성(Persistence)의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '트랜잭션이 성공적으로 완료되면 그 결과가 영구적으로 저장된다.', '지속성은 트랜잭션이 완료된 후 그 결과가 데이터베이스에 영구적으로 남아야 한다는 것을 의미합니다.'),
    (688, 3, 3, 55, 'READ COMMITTED 격리 수준의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "커밋된 데이터만 읽을 수 있다."}, {"id": "B", "text": "읽은 데이터는 수정할 수 있다."}, {"id": "C", "text": "다른 트랜잭션의 데이터를 항상 읽을 수 있다."}, {"id": "D", "text": "데이터의 잠금을 사용하지 않는다."}]', 'A', 'READ COMMITTED는 커밋된 데이터만 읽을 수 있도록 하는 격리 수준입니다.'),
    (689, 3, 3, 56, '비관적 락의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 즉시 잠근다."}, {"id": "B", "text": "트랜잭션 완료 후에 잠근다."}, {"id": "C", "text": "잠금 없이 모든 트랜잭션을 허용한다."}, {"id": "D", "text": "수정된 데이터는 즉시 다른 트랜잭션에서 접근 가능하다."}]', 'A', '비관적 락은 데이터에 수정을 시도하기 전에 즉시 잠금하여 다른 트랜잭션의 접근을 차단합니다.'),
    (690, 3, 3, 57, 'READ UNCOMMITTED와 READ COMMITTED의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "READ UNCOMMITTED는 커밋되지 않은 데이터를 읽을 수 있다."}, {"id": "B", "text": "READ COMMITTED는 항상 최신 데이터를 읽을 수 있다."}, {"id": "C", "text": "READ UNCOMMITTED는 데드락 발생 가능성이 높다."}, {"id": "D", "text": "READ COMMITTED는 데이터 잠금을 사용한다."}]', '["A", "C", "D"]', 'READ UNCOMMITTED는 커밋되지 않은 데이터를 읽을 수 있으며, 데드락 발생 가능성이 높고 데이터 잠금을 사용하지 않습니다. 반면 READ COMMITTED는 커밋된 데이터만 읽을 수 있습니다.'),
    (691, 3, 3, 58, '트랜잭션의 지속성(Persistence)의 의미는 무엇인가?', 'SHORT_ANSWER', NULL, '완료된 트랜잭션의 데이터가 영구적으로 저장된다.', '지속성은 트랜잭션이 완료된 후 그 결과가 데이터베이스에 반영되어 영구적으로 저장됨을 의미합니다.'),
    (692, 3, 3, 59, '다음 중 트랜잭션의 격리성을 설명하는 방법으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트랜잭션 간의 영향을 최소화한다."}, {"id": "B", "text": "데이터를 무조건 삭제한다."}, {"id": "C", "text": "트랜잭션을 사용하지 않는다."}, {"id": "D", "text": "모든 트랜잭션이 동시에 실행된다."}]', 'A', '격리성은 여러 트랜잭션이 동시에 실행될 때 서로 간섭하지 않도록 보장하는 특성입니다.'),
    (693, 3, 3, 60, '다음 중 배타 락과 공유 락의 차이점은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배타 락은 독점적인 접근을 허용한다."}, {"id": "B", "text": "공유 락은 독점적인 접근을 허용한다."}, {"id": "C", "text": "둘 다 동시에 사용할 수 있다."}, {"id": "D", "text": "배타 락은 읽기 전용이다."}]', 'A', '배타 락은 특정 데이터에 대해 독점적인 접근을 허용하는 반면, 공유 락은 여러 트랜잭션이 동시에 읽을 수 있도록 합니다.'),
    (694, 3, 3, 61, '낙관적 락의 특징으로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "수정 전 데이터 변경이 없다는 가정 하에 수행된다."}, {"id": "B", "text": "수정된 데이터를 즉시 반영한다."}, {"id": "C", "text": "가장 높은 격리 수준이다."}, {"id": "D", "text": "동시성 문제가 발생하지 않는다."}]', '["A"]', '낙관적 락은 데이터 수정 전에 다른 트랜잭션의 변경이 없다고 가정하고 작업을 수행하는 방식입니다.'),
    (695, 3, 3, 62, '샤딩(sharding)의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 확장성과 성능 향상"}, {"id": "B", "text": "데이터의 백업"}, {"id": "C", "text": "데이터 일관성 유지"}, {"id": "D", "text": "트랜잭션 처리 속도 증가"}]', 'A', '샤딩은 데이터베이스의 데이터를 여러 개의 샤드로 나누어 성능과 확장성을 높이는 기법입니다.'),
    (696, 3, 3, 63, '마스터-슬레이브 구조에서 마스터 노드의 주 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "읽기 전용 요청 처리"}, {"id": "B", "text": "쓰기 요청 처리"}, {"id": "C", "text": "백업 수행"}, {"id": "D", "text": "데이터 복구"}]', 'B', '마스터 노드는 분산 DB에서 주로 쓰기 요청을 처리하며, 슬레이브 노드는 마스터의 복제를 통해 읽기 요청을 처리합니다.'),
    (697, 3, 3, 64, 'Eventual Consistency의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "즉각적인 일관성을 보장한다."}, {"id": "B", "text": "최종적으로 일관된 상태에 도달한다."}, {"id": "C", "text": "모든 노드가 항상 일관된 상태를 유지한다."}, {"id": "D", "text": "트랜잭션이 항상 성공한다."}]', 'B', 'Eventual Consistency는 시스템이 최종적으로 일관된 상태에 도달하게 보장하지만, 일시적으로 불일치가 발생할 수 있습니다.'),
    (698, 3, 3, 65, '다음 중 분산 데이터베이스 시스템에서 파티셔닝 기법에 해당하지 않는 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "수직 파티셔닝"}, {"id": "B", "text": "레플리케이션"}, {"id": "C", "text": "레인지 파티셔닝"}, {"id": "D", "text": "샤딩"}]', '["B"]', '레플리케이션은 데이터를 여러 노드에 복제하는 과정이며, 파티셔닝은 데이터 분할을 의미합니다.'),
    (699, 3, 3, 66, '2PC(two-phase commit) 프로토콜의 주목적은 무엇인가?', 'SHORT_ANSWER', NULL, '트랜잭션의 원자성 보장', '2PC는 분산 트랜잭션에서 모든 참여자가 성공적으로 커밋하거나 모두 롤백하도록 보장하여 원자성을 유지합니다.'),
    (700, 3, 3, 67, 'Airflow는 주로 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 파이프라인을 관리하고 자동화하기 위해"}, {"id": "B", "text": "데이터 저장을 위해"}, {"id": "C", "text": "데이터 분석을 위해"}, {"id": "D", "text": "데이터 시각화를 위해"}]', 'A', 'Airflow는 데이터 파이프라인의 스케줄링과 모니터링을 자동화하는 도구입니다.'),
    (701, 3, 3, 68, '데이터 웨어하우스와 데이터 레이크의 주요 차이는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 웨어하우스는 구조화된 데이터를, 데이터 레이크는 비구조화된 데이터를 저장한다."}, {"id": "B", "text": "데이터 웨어하우스는 실시간 데이터 처리에 최적화되어 있다."}, {"id": "C", "text": "데이터 레이크는 데이터의 일관성을 보장한다."}, {"id": "D", "text": "두 개념은 동일하다."}]', 'A', '데이터 웨어하우스는 주로 구조화된 데이터를 저장하고 분석하는 데 사용되며, 데이터 레이크는 다양한 형태의 비구조화된 데이터를 저장합니다.'),
    (702, 3, 3, 69, '스키마 온 라이트(Schema on Write) 방식의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 저장하기 전에 스키마를 정의한다."}, {"id": "B", "text": "데이터를 저장한 후에 스키마를 정의한다."}, {"id": "C", "text": "비구조화된 데이터를 저장한다."}, {"id": "D", "text": "데이터를 실시간으로 분석한다."}]', 'A', '스키마 온 라이트 방식은 데이터를 저장하기 전에 스키마를 정의하고, 이 구조에 맞춰 데이터를 저장하는 방법입니다.'),
    (703, 3, 3, 70, 'ELT의 전체 과정에서 변환 과정은 어디에서 이루어지나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 웨어하우스 내에서"}, {"id": "B", "text": "소스 시스템에서"}, {"id": "C", "text": "데이터 레이크 내에서"}, {"id": "D", "text": "실시간 처리 시스템에서"}]', '["A", "C"]', 'ELT 과정에서는 데이터를 먼저 로드하고, 이후 데이터 웨어하우스나 데이터 레이크 내에서 변환이 이루어집니다.'),
    (704, 3, 3, 71, 'Flink는 주로 어떤 용도로 사용되나요?', 'SHORT_ANSWER', NULL, '실시간 데이터 처리', 'Flink는 스트리밍 데이터와 배치 데이터를 모두 처리할 수 있는 분산 데이터 처리 엔진으로, 주로 실시간 데이터 처리에 사용됩니다.'),
    (705, 3, 3, 72, 'CAP 이론에서 세 가지 특성 중 동시에 만족할 수 없는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "가용성"}, {"id": "C", "text": "파티셔닝 허용성"}, {"id": "D", "text": "모든 특성"}]', 'D', 'CAP 이론에 따르면, 분산 시스템은 일관성, 가용성, 파티셔닝 허용성 중 세 가지를 동시에 만족할 수 없습니다.'),
    (706, 3, 3, 73, '다음 중 2PC(2-Phase Commit)의 특징으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 단계로 이루어진다."}, {"id": "B", "text": "모든 참가자가 반드시 응답해야 한다."}, {"id": "C", "text": "단일 실패 지점이 있다."}, {"id": "D", "text": "비동기식 처리가 가능하다."}]', 'D', '2PC는 동기식 방법으로, 모든 참가자가 반드시 응답해야 하므로 비동기식 처리가 불가능합니다.'),
    (707, 3, 3, 74, '레인지 파티셔닝의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 클러스터링"}, {"id": "B", "text": "데이터의 효율적인 분산"}, {"id": "C", "text": "데이터의 중복성 증가"}, {"id": "D", "text": "데이터의 일관성 유지"}]', 'B', '레인지 파티셔닝은 데이터를 효율적으로 분산하기 위한 방법입니다.'),
    (708, 3, 3, 75, '분산 데이터베이스에서 강한 일관성의 주된 이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 최신 상태 유지"}, {"id": "B", "text": "성능 향상"}, {"id": "C", "text": "데이터 무결성 보장"}, {"id": "D", "text": "신속한 데이터 접근"}]', '["A", "C"]', '강한 일관성은 데이터의 최신 상태를 유지하고 데이터 무결성을 보장하는 데 기여합니다.'),
    (709, 3, 3, 76, '3PC의 전체 이름은 무엇인가?', 'SHORT_ANSWER', NULL, '3-Phase Commit', '3PC의 전체 이름은 3-Phase Commit입니다.'),
    (710, 3, 3, 77, 'ETL과 ELT의 주요 차이는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ETL은 데이터 변환 후 로드하고, ELT는 로드 후 변환한다."}, {"id": "B", "text": "ETL은 데이터 저장소에 저장하지 않고 사용하고, ELT는 저장한다."}, {"id": "C", "text": "ETL은 배치 처리만 지원하고, ELT는 스트림 처리만 지원한다."}, {"id": "D", "text": "ETL은 모든 데이터 처리 방식에 적용 가능하고, ELT는 일부에만 적용 가능하다."}]', 'A', 'ETL은 데이터를 추출한 후 변환하여 저장소에 로드하지만, ELT는 먼저 데이터를 로드한 후 변환 과정을 거칩니다.'),
    (711, 3, 3, 78, '스키마 온 라이트(Schema on Write)의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 저장하기 전에 스키마를 정의해야 한다."}, {"id": "B", "text": "데이터가 쓸 때마다 스키마가 자동으로 생성된다."}, {"id": "C", "text": "스키마는 데이터 처리 후에 적용된다."}, {"id": "D", "text": "비구조화 데이터를 쉽게 처리할 수 있다."}]', 'A', '스키마 온 라이트는 데이터가 저장되기 전에 스키마를 정의해야 하는 접근 방식입니다.'),
    (712, 3, 3, 79, 'Flink는 어떤 유형의 데이터 처리에 주로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배치 처리"}, {"id": "B", "text": "데이터 시각화"}, {"id": "C", "text": "실시간 스트림 처리"}, {"id": "D", "text": "데이터 웨어하우징"}]', 'C', 'Flink는 실시간 스트림 처리에 최적화된 데이터 처리 프레임워크입니다.'),
    (713, 3, 3, 80, '데이터 파이프라인을 구축하기 위해 필요한 요소는 무엇인가요? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 수집 도구"}, {"id": "B", "text": "데이터 변환 및 처리 도구"}, {"id": "C", "text": "데이터 시각화 도구"}, {"id": "D", "text": "저장소 시스템"}]', '["A", "B", "D"]', '데이터 파이프라인을 구축하기 위해서는 데이터 수집 도구, 변환 및 처리 도구, 그리고 저장소 시스템이 필요합니다.'),
    (714, 3, 3, 81, 'Hadoop의 기본 구성 요소는 무엇인가요?', 'SHORT_ANSWER', NULL, 'HDFS와 MapReduce', 'Hadoop의 기본 구성 요소는 HDFS(Hadoop Distributed File System)와 MapReduce 프레임워크입니다.'),
    (715, 3, 3, 82, 'ETL의 기본 단계가 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "적재"}, {"id": "B", "text": "변환"}, {"id": "C", "text": "저장"}, {"id": "D", "text": "추출"}]', 'C', 'ETL의 기본 단계는 추출, 변환, 적재이며, 저장은 포함되지 않습니다.'),
    (716, 3, 3, 83, 'Apache Spark의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "대규모 데이터 처리"}, {"id": "B", "text": "정적 데이터만 처리 가능"}, {"id": "C", "text": "SQL만 지원"}, {"id": "D", "text": "고정된 메모리 사용"}]', 'A', 'Apache Spark는 대규모 데이터 처리를 위한 분산 처리 프레임워크입니다.'),
    (717, 3, 3, 84, '스키마 온 리드(Schema on Read)와 스키마 온 라이트(Schema on Write)의 차이를 설명하시오.', 'SHORT_ANSWER', NULL, '스키마 온 리드는 데이터를 읽을 때 스키마를 적용하는 것이고, 스키마 온 라이트는 데이터를 저장할 때 스키마를 적용하는 것이다.', ''),
    (718, 3, 3, 85, '다음 중 데이터 레이크의 특징으로 옳은 것을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구조화된 데이터만 저장 가능"}, {"id": "B", "text": "다양한 형식의 원시 데이터를 저장 가능"}, {"id": "C", "text": "분석을 위해 데이터 변환 필요"}, {"id": "D", "text": "저렴한 저장 비용"}]', '["B", "D"]', '데이터 레이크는 다양한 형식의 원시 데이터를 저장할 수 있으며, 저장 비용이 저렴한 특징이 있습니다.'),
    (719, 3, 3, 86, 'CAP 정리에서 설명하는 세 가지 요소는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성, 가용성, 파티션 허용성"}, {"id": "B", "text": "가용성, 성능, 확장성"}, {"id": "C", "text": "신뢰성, 일관성, 성능"}, {"id": "D", "text": "확장성, 일관성, 응답 시간"}]', 'A', 'CAP 정리는 일관성, 가용성, 파티션 허용성의 세 가지 요소를 설명합니다.'),
    (720, 3, 3, 87, '다음 중 수평 파티셔닝의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 열 단위로 나누는 방법"}, {"id": "B", "text": "데이터를 행 단위로 나누는 방법"}, {"id": "C", "text": "데이터를 파일로 나누는 방법"}, {"id": "D", "text": "데이터를 서버로 나누는 방법"}]', 'B', '수평 파티셔닝은 데이터를 행 단위로 나누어 저장하는 방법입니다.'),
    (721, 3, 3, 88, '다음 중 2단계 커밋(2PC)의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 참여자가 트랜잭션을 동기적으로 커밋해야 한다"}, {"id": "B", "text": "트랜잭션은 비동기적으로 처리된다"}, {"id": "C", "text": "단일 노드에서만 작동한다"}, {"id": "D", "text": "트랜잭션의 일관성은 보장되지 않는다"}]', 'A', '2단계 커밋(2PC)에서는 모든 참여자가 트랜잭션을 동기적으로 커밋해야 합니다.'),
    (722, 3, 3, 89, '마스터-마스터 레플리케이션의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "여러 노드에서 쓰기 작업이 가능하다"}, {"id": "B", "text": "단일 노드에서만 쓰기 작업이 가능하다"}, {"id": "C", "text": "고가용성을 제공한다"}, {"id": "D", "text": "신뢰성이 낮다"}]', '["A", "C"]', '마스터-마스터 레플리케이션은 여러 노드에서 쓰기 작업이 가능하고, 고가용성을 제공하는 특징이 있습니다.'),
    (723, 3, 3, 90, '3단계 커밋(3PC)의 주요 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '상황에 따라 트랜잭션의 실패를 줄일 수 있다.', '3단계 커밋(3PC)은 상황에 따라 트랜잭션의 실패를 줄일 수 있는 장점이 있습니다.'),
    (724, 3, 3, 91, '트랜잭션의 원자성을 보장하기 위해 사용하는 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "공유 락"}, {"id": "B", "text": "사전 락"}, {"id": "C", "text": "락"}, {"id": "D", "text": "트리거"}]', 'C', '트랜잭션의 원자성을 보장하기 위해서 데이터에 대한 락을 사용하여 동시 접근을 방지합니다.'),
    (725, 3, 3, 92, 'READ COMMITTED 격리 수준의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 데이터 변경이 롤백 된다"}, {"id": "B", "text": "다른 트랜잭션이 커밋한 데이터만 읽을 수 있다"}, {"id": "C", "text": "데이터는 항상 일관되게 보인다"}, {"id": "D", "text": "트랜잭션이 시작된 이후 데이터가 변경되지 않는다"}]', 'B', 'READ COMMITTED는 다른 트랜잭션이 커밋한 데이터만 읽을 수 있도록 하여 비일관성을 줄입니다.'),
    (726, 3, 3, 93, '낙관적 락의 기본적인 가정은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트랜잭션 충돌이 자주 발생한다"}, {"id": "B", "text": "트랜잭션 충돌이 발생하지 않을 것이라고 가정한다"}, {"id": "C", "text": "모든 트랜잭션은 즉시 실행되어야 한다"}, {"id": "D", "text": "락을 사용하여 항상 데이터의 무결성을 보장한다"}]', 'B', '낙관적 락은 트랜잭션 충돌이 발생하지 않을 것이라고 가정하고 수행하며, 필요 시에만 충돌을 해결합니다.'),
    (727, 3, 3, 94, '트랜잭션의 격리 수준을 나열하시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "READ UNCOMMITTED"}, {"id": "B", "text": "READ COMMITTED"}, {"id": "C", "text": "REPEATABLE READ"}, {"id": "D", "text": "SERIALIZABLE"}]', '["A", "B", "C", "D"]', '트랜잭션의 격리 수준에는 READ UNCOMMITTED, READ COMMITTED, REPEATABLE READ, SERIALIZABLE 등이 있습니다.'),
    (728, 3, 3, 95, '트랜잭션이 실패했을 때 원래 상태로 복구하는 과정을 무엇이라 하는가?', 'SHORT_ANSWER', NULL, '롤백', '트랜잭션이 실패했을 때 원래 상태로 복구하는 과정을 롤백이라고 합니다.'),
    (729, 3, 3, 96, 'Apache Spark와 Flink의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "대규모 데이터 처리"}, {"id": "B", "text": "데이터베이스 관리"}, {"id": "C", "text": "웹 개발"}, {"id": "D", "text": "시스템 모니터링"}]', 'A', 'Apache Spark와 Flink는 대규모 데이터 처리를 위한 오픈 소스 프레임워크입니다.'),
    (730, 3, 3, 97, '스키마 온 라이트의 가장 큰 장점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 무결성 확보"}, {"id": "B", "text": "저렴한 저장 비용"}, {"id": "C", "text": "즉각적인 데이터 접근"}, {"id": "D", "text": "빠른 처리 속도"}]', 'A', '스키마 온 라이트 접근 방식은 데이터를 적재할 때 스키마를 정의하므로 데이터의 무결성을 확보할 수 있습니다.'),
    (731, 3, 3, 98, '다음 중 ETL 과정에서 포함되지 않는 단계는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "추출"}, {"id": "B", "text": "분석"}, {"id": "C", "text": "변환"}, {"id": "D", "text": "적재"}]', 'B', 'ETL 과정은 주로 추출, 변환, 적재의 세 단계로 구성되며, 분석은 포함되지 않습니다.'),
    (732, 3, 3, 99, '다음 중 ETL을 구성하는 세 가지 단계는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "추출"}, {"id": "B", "text": "변환"}, {"id": "C", "text": "저장"}, {"id": "D", "text": "적재"}]', '["A", "B", "D"]', 'ETL은 추출(Extract), 변환(Transform), 적재(Load)의 세 가지 단계로 구성됩니다.'),
    (733, 3, 3, 100, 'HDFS의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '분산 파일 저장', ''),
    (734, 3, 3, 101, 'ETL에서 ''L''은 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, 'Load', '''L''은 Load를 의미하며, 데이터를 저장하는 과정을 나타냅니다.'),
    (735, 3, 3, 102, '다음 중 데이터 웨어하우스의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비즈니스 인사이트 제공"}, {"id": "B", "text": "데이터의 실시간 처리"}, {"id": "C", "text": "대량의 데이터 저장"}, {"id": "D", "text": "데이터 분석 용이성"}]', 'B', '데이터 웨어하우스는 주로 배치 처리에 적합하며, 실시간 처리 기능은 데이터 레이크와 같은 다른 기술들이 더 잘 수행합니다.'),
    (736, 3, 3, 103, 'DAG는 어떤 목적으로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 저장"}, {"id": "B", "text": "작업 의존성 관리"}, {"id": "C", "text": "데이터 시각화"}, {"id": "D", "text": "실시간 처리"}]', 'B', 'DAG는 작업의 의존성을 관리하여 실행 순서를 명확히 하는 데 사용됩니다.'),
    (737, 3, 3, 104, '다음 중 복수의 정답을 선택하세요: ETL과 ELT의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ETL은 데이터를 변환 후 저장하고, ELT는 저장 후 변환한다."}, {"id": "B", "text": "ETL은 배치 처리에 적합하고, ELT는 실시간 처리에 적합하다."}, {"id": "C", "text": "ETL은 데이터 마트에, ELT는 데이터 웨어하우스에 적합하다."}, {"id": "D", "text": "ETL은 주로 데이터 레이크에 사용되고, ELT는 데이터 웨어하우스에 사용된다."}]', '["A", "B"]', 'ETL은 데이터를 변환한 후 저장하는 반면, ELT는 데이터를 저장한 후 변환합니다. 또한 ETL은 일반적으로 배치 처리에 적합합니다.'),
    (738, 3, 3, 105, 'CAP 이론에서 ''C''는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "가용성"}, {"id": "C", "text": "분할 허용성"}, {"id": "D", "text": "상태 저장"}]', 'A', '''C''는 Consistency(일관성)을 의미하며, 데이터베이스가 모든 노드에서 동일한 데이터를 반환해야 함을 나타냅니다.'),
    (739, 3, 3, 106, 'Eventual Consistency의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "즉각적인 일관성 보장"}, {"id": "B", "text": "시간이 지나면서 일관성이 보장됨"}, {"id": "C", "text": "일관성을 전혀 보장하지 않음"}, {"id": "D", "text": "읽기와 쓰기가 동시에 가능함"}]', 'B', 'Eventual Consistency는 데이터가 시간이 경과함에 따라 일관성을 유지하게 되는 모델로, 초기에는 일관성이 보장되지 않지만 결국 모든 복제본이 동일해진다는 특징이 있습니다.'),
    (740, 3, 3, 107, '다음 중 분산 데이터베이스의 샤딩(sharding)에 대한 설명으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 성능을 향상시킨다."}, {"id": "B", "text": "데이터를 여러 서버에 분산 저장한다."}, {"id": "C", "text": "모든 데이터가 단일 서버에 저장된다."}, {"id": "D", "text": "각 샤드에 대해 별도 쿼리를 처리 가능하다."}]', 'C', '샤딩은 데이터를 여러 서버에 분산 저장하는 기법이므로, 모든 데이터를 단일 서버에 저장한다는 설명은 옳지 않습니다.'),
    (741, 3, 3, 108, '2PC와 3PC의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "3PC는 더 많은 메시지를 필요로 한다."}, {"id": "B", "text": "2PC는 장애 발생 시 데이터 손실의 위험이 있다."}, {"id": "C", "text": "3PC는 더 빠른 트랜잭션 처리 속도를 가진다."}, {"id": "D", "text": "2PC는 트랜잭션 중단 시 복구가 어렵다."}]', '["A", "B", "D"]', '3PC는 2PC보다 더 많은 메시지를 주고받으며, 2PC는 장애 발생 시 데이터 손실의 위험이 크고 복구가 어렵기 때문에 이러한 차이점이 있습니다.'),
    (742, 3, 3, 109, '분할 허용성(Partition Tolerance)란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '네트워크 분할 상황에서도 시스템이 계속 동작할 수 있는 능력', '분할 허용성이란 네트워크가 분할되더라도 데이터베이스 시스템이 계속 작동할 수 있는 능력을 의미합니다.'),
    (743, 3, 3, 110, 'CAP 이론에서 설명하는 세 가지 요소가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성"}, {"id": "B", "text": "가용성"}, {"id": "C", "text": "신뢰성"}, {"id": "D", "text": "파티셔닝 내구성"}]', 'C', 'CAP 이론은 일관성, 가용성, 파티셔닝 내구성의 세 가지 요소로 구성되어 있습니다.'),
    (744, 3, 3, 111, 'Eventual Consistency의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "즉각적인 일관성을 보장한다."}, {"id": "B", "text": "최종적으로 일관성을 보장하나 즉각적이지 않다."}, {"id": "C", "text": "데이터를 항상 동일하게 유지한다."}, {"id": "D", "text": "모든 트랜잭션을 원자적으로 수행한다."}]', 'B', 'Eventual Consistency는 최종적으로 데이터의 일관성을 보장하지만 즉각적인 일관성을 요구하지 않습니다.'),
    (745, 3, 3, 112, '수평 파티셔닝과 관련된 용어가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "샤딩"}, {"id": "B", "text": "해시 파티셔닝"}, {"id": "C", "text": "수직 파티셔닝"}, {"id": "D", "text": "데이터 분산"}]', 'C', '수직 파티셔닝은 데이터베이스의 열을 분산하는 방식으로, 수평 파티셔닝과는 다릅니다.'),
    (746, 3, 3, 113, '수평 파티셔닝과 해시 파티셔닝의 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "수평 파티셔닝은 데이터의 행을 나누고, 해시 파티셔닝은 키를 기반으로 나눈다."}, {"id": "B", "text": "수평 파티셔닝은 즉각적인 일관성을 요구하고, 해시 파티셔닝은 요구하지 않는다."}, {"id": "C", "text": "수평 파티셔닝은 모든 데이터베이스에 적용할 수 있지만, 해시 파티셔닝은 특정 경우에만 적용 가능하다."}]', '["A"]', '수평 파티셔닝은 데이터의 행을 여러 서버에 분산하고, 해시 파티셔닝은 특정 키를 기반으로 데이터를 분산하는 방식입니다.'),
    (747, 3, 3, 114, '분산 트랜잭션의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '여러 데이터베이스에 걸쳐 일관성을 유지하는 것', '분산 트랜잭션은 여러 데이터베이스에 분산되어 있는 데이터의 일관성을 유지하는 것을 목표로 합니다.'),
    (748, 3, 3, 115, '분산 데이터베이스에서 레인지 파티셔닝의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "조회 성능 향상"}, {"id": "B", "text": "데이터 일관성 보장"}, {"id": "C", "text": "데이터 복제"}, {"id": "D", "text": "서버 비용 절감"}]', 'A', '레인지 파티셔닝은 데이터를 특정 범위에 따라 나누어 조회 성능을 향상시키는 방법입니다.'),
    (749, 3, 3, 116, 'CAP 이론에서 동시성, 가용성, 파티셔닝 내성 중 선택할 수 없는 두 가지 특성은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일관성 및 가용성"}, {"id": "B", "text": "일관성 및 파티셔닝 내성"}, {"id": "C", "text": "가용성 및 파티셔닝 내성"}, {"id": "D", "text": "모든 세 가지"}]', 'B', 'CAP 이론에 따르면, 일관성(Consistency)과 파티셔닝 내성(Partition Tolerance)은 동시에 최대한 유지할 수 없는 특성입니다.'),
    (750, 3, 3, 117, '마스터-슬레이브 아키텍처에서 발생할 수 있는 주요 문제는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "네트워크 지연"}, {"id": "B", "text": "일관성 문제"}, {"id": "C", "text": "데이터 손실"}, {"id": "D", "text": "서버 다운"}]', 'B', '마스터-슬레이브 아키텍처에서는 데이터 일관성을 유지하는 데 어려움이 있을 수 있습니다.'),
    (751, 3, 3, 118, '강한 일관성과 Eventual Consistency의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "강한 일관성은 즉각적인 일관성을 보장한다."}, {"id": "B", "text": "Eventual Consistency는 시간이 지남에 따라 일관성을 보장한다."}, {"id": "C", "text": "강한 일관성은 파티셔닝 내성에 중점을 둔다."}, {"id": "D", "text": "Eventual Consistency는 쓰기 충돌을 허용한다."}]', '["A", "B"]', '강한 일관성은 즉각적인 일관성을 보장하고, Eventual Consistency는 시간이 지남에 따라 일관성을 보장합니다.'),
    (752, 3, 3, 119, '마스터-마스터 아키텍처의 장점 중 하나는 무엇인가?', 'SHORT_ANSWER', NULL, '동시 쓰기 가능성', '마스터-마스터 아키텍처는 여러 노드가 동시에 쓰기 작업을 수행할 수 있어 장점이 있습니다.'),
    (753, 3, 3, 120, '트랜잭션의 ACID 속성 중 ''일관성''이 의미하는 것은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터베이스가 유효한 상태로 항상 유지되어야 한다.', '일관성은 트랜잭션이 성공적으로 완료되면 데이터베이스가 일관된 상태로 있어야 함을 의미합니다.'),
    (754, 3, 3, 121, '다음 중 데이터베이스의 격리 수준 중 하나가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "READ UNCOMMITTED"}, {"id": "B", "text": "STATIC READ"}, {"id": "C", "text": "READ COMMITTED"}, {"id": "D", "text": "SERIALIZABLE"}]', 'B', 'STATIC READ는 데이터베이스의 격리 수준 중 하나가 아닙니다.'),
    (755, 3, 3, 122, 'MVCC의 주된 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "작성 성능 향상"}, {"id": "B", "text": "읽기 성능 향상"}, {"id": "C", "text": "데이터 안전성 증가"}, {"id": "D", "text": "스냅샷 제공"}]', 'B', 'MVCC는 읽기와 쓰기의 동시성을 향상시켜 읽기 성능을 증가시킵니다.'),
    (756, 3, 3, 123, '비관적 락과 낙관적 락의 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "비관적 락은 항상 락을 거는 방식이다."}, {"id": "B", "text": "낙관적 락은 충돌을 가정하지 않는 방식이다."}, {"id": "C", "text": "비관적 락은 성능이 낮다."}, {"id": "D", "text": "낙관적 락은 데이터베이스 접근이 적은 경우에 유리하다."}]', '["A", "B", "D"]', '비관적 락은 항상 락을 거는 방식이고, 낙관적 락은 충돌을 가정하지 않으며, 접근량이 적을 때 성능상 이점이 있습니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 알고리즘과 자료구조 > 탐색과 정렬 (210문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (757, 4, 1, 1, '버블 정렬의 시간 복잡도는 무엇인가요?', 'SHORT_ANSWER', NULL, 'O(n^2)', '버블 정렬은 인접한 요소를 비교하고 교환하는 방식으로 동작하여, 최악의 경우 O(n^2)의 시간 복잡도를 가집니다.'),
    (758, 4, 1, 2, '아래 알고리즘 중 불안정 정렬에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "퀵 정렬"}, {"id": "B", "text": "카운팅 정렬"}, {"id": "C", "text": "삽입 정렬"}, {"id": "D", "text": "버블 정렬"}]', 'B', '카운팅 정렬은 안정 정렬로, 동일한 키 값을 가진 요소의 순서가 유지됩니다.'),
    (759, 4, 1, 3, '삽입 정렬의 최선의 경우 시간 복잡도는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "O(n)"}, {"id": "B", "text": "O(n log n)"}, {"id": "C", "text": "O(n^2)"}, {"id": "D", "text": "O(k)"}]', 'A', '삽입 정렬은 최선의 경우 이미 정렬된 상태에서 O(n)의 시간 복잡도를 가집니다.'),
    (760, 4, 1, 4, '다음 중 안정 정렬 알고리즘은 모두 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "카운팅 정렬"}, {"id": "B", "text": "퀵 정렬"}, {"id": "C", "text": "삽입 정렬"}, {"id": "D", "text": "병합 정렬"}]', '["A", "C", "D"]', '카운팅 정렬, 삽입 정렬, 병합 정렬은 모두 동일한 키 값을 가진 요소의 상대적 순서를 유지하는 안정 정렬입니다.'),
    (761, 4, 1, 5, '우선순위 큐의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "우선순위에 따라 요소를 처리한다."}, {"id": "B", "text": "항상 FIFO 방식으로 작동한다."}, {"id": "C", "text": "크기가 고정된 배열만 사용할 수 있다."}, {"id": "D", "text": "모든 요소의 우선순위가 같다."}]', 'A', '우선순위 큐는 요소의 우선순위에 따라 처리하는 자료구조입니다.'),
    (762, 4, 1, 6, '덱(Deque)의 특성이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "양쪽 끝에서 삽입과 삭제가 가능하다."}, {"id": "B", "text": "LIFO 방식으로만 작동한다."}, {"id": "C", "text": "FIFO 방식으로도 작동할 수 있다."}, {"id": "D", "text": "큐와 스택의 특성을 모두 가진다."}]', 'B', '덱은 LIFO 방식으로만 작동하지 않으며, FIFO 방식으로도 작동할 수 있습니다.'),
    (763, 4, 1, 7, '링크드 리스트의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정된 크기를 가진다."}, {"id": "B", "text": "임의 접근이 빠르다."}, {"id": "C", "text": "삽입과 삭제가 효율적이다."}, {"id": "D", "text": "메모리를 항상 연속적으로 사용한다."}]', 'C', '링크드 리스트는 삽입과 삭제가 효율적인 장점이 있습니다.'),
    (764, 4, 1, 8, '다음 중 동적 배열의 특성에 해당하지 않는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "크기를 동적으로 조절할 수 있다."}, {"id": "B", "text": "고정된 메모리 블록을 사용한다."}, {"id": "C", "text": "임의 접근이 가능하다."}, {"id": "D", "text": "메모리 사용이 비효율적일 수 있다."}]', '["B", "D"]', '동적 배열은 크기를 동적으로 조절할 수 있으며, 고정된 메모리 블록을 사용하지 않습니다.'),
    (765, 4, 1, 9, 'pop 연산이 주로 사용되는 자료구조는?', 'SHORT_ANSWER', NULL, '스택', 'pop 연산은 주로 스택에서 마지막 요소를 삭제하는 데 사용됩니다.'),
    (766, 4, 1, 10, 'BFS는 어떤 방식의 탐색 기법인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "레벨 탐색"}, {"id": "B", "text": "깊이 탐색"}, {"id": "C", "text": "무작위 탐색"}, {"id": "D", "text": "이진 탐색"}]', 'A', 'BFS는 너비 우선 탐색으로, 노드를 레벨 단위로 탐색하는 방식입니다.'),
    (767, 4, 1, 11, '후위 표기법의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "괄호 없이 수식을 표현할 수 있다."}, {"id": "B", "text": "연산자의 우선순위를 무시한다."}, {"id": "C", "text": "변수를 쉽게 정의할 수 있다."}, {"id": "D", "text": "계산 속도가 매우 빠르다."}]', 'A', '후위 표기법은 괄호 없이도 수식을 명확하게 표현할 수 있어 계산에 용이합니다.'),
    (768, 4, 1, 12, 'Min Stack의 주목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소값을 O(1)로 추적"}, {"id": "B", "text": "스택의 크기를 줄이기 위해"}, {"id": "C", "text": "스택의 정렬을 용이하게 하기 위해"}, {"id": "D", "text": "메모리 사용량을 줄이기 위해"}]', 'A', 'Min Stack은 최소값을 O(1) 시간 복잡도로 추적하는 것이 주요 목적입니다.'),
    (769, 4, 1, 13, '중위 표기법과 후위 표기법의 관계는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "후위 표기법은 중위 표기법의 변형이다."}, {"id": "B", "text": "중위 표기법은 후위 표기법보다 효율적이다."}, {"id": "C", "text": "둘 다 수식을 표현하는 방법이다."}, {"id": "D", "text": "후위 표기법은 계산에 더 유리하다."}]', '["A", "C", "D"]', '후위 표기법은 중위 표기법의 변형으로, 둘 다 수식을 표현하지만 후위 표기법이 계산에 더 유리합니다.'),
    (770, 4, 1, 14, '양방향 큐는 어떤 기능을 제공하는가?', 'SHORT_ANSWER', NULL, '앞과 뒤에서 모두 삽입과 삭제가 가능하다.', '양방향 큐는 앞과 뒤에서 모두 삽입과 삭제를 할 수 있는 자료구조입니다.'),
    (771, 4, 1, 15, '머지 정렬의 시간 복잡도는 무엇인가?', 'SHORT_ANSWER', NULL, 'O(n log n)', '머지 정렬은 데이터를 반으로 나누어 정렬한 후 다시 합치는 방식으로, 평균과 최악의 경우 모두 O(n log n)의 시간 복잡도를 가집니다.'),
    (772, 4, 1, 16, '다음 중 안정 정렬에 해당하는 알고리즘은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "머지 정렬"}, {"id": "B", "text": "버블 정렬"}, {"id": "C", "text": "선택 정렬"}, {"id": "D", "text": "힙 정렬"}]', '["A", "B"]', '머지 정렬과 버블 정렬은 안정 정렬 알고리즘으로, 동일한 키를 가진 데이터의 상대적인 순서를 유지합니다.'),
    (773, 4, 1, 17, '특정 상황에서 정렬 알고리즘의 성능이 달라질 수 있는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 크기와 특성"}, {"id": "B", "text": "정렬 알고리즘의 이름"}, {"id": "C", "text": "코드의 길이"}, {"id": "D", "text": "프로그래밍 언어"}]', 'A', '정렬 알고리즘의 성능은 데이터의 크기와 특성에 따라 크게 영향을 받습니다. 같은 알고리즘이라도 입력 데이터의 형태에 따라 최적의 성능을 발휘할 수 있습니다.'),
    (774, 4, 1, 18, '카운팅 정렬의 시간 복잡도가 O(n + k)에서 k는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬할 데이터의 개수"}, {"id": "B", "text": "데이터의 최대값과 최소값의 차이"}, {"id": "C", "text": "정렬에 사용되는 메모리 크기"}, {"id": "D", "text": "정렬 알고리즘의 단계 수"}]', 'B', '카운팅 정렬에서 k는 데이터의 최대값과 최소값의 차이를 의미하며, 이는 정렬할 데이터의 범위를 나타냅니다.'),
    (775, 4, 1, 19, 'O(n²) 복잡도를 가진 알고리즘의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기가 증가할 때, 실행 시간이 제곱으로 증가한다."}, {"id": "B", "text": "입력 크기가 증가할 때, 실행 시간이 로그로 증가한다."}, {"id": "C", "text": "입력 크기가 증가해도 실행 시간은 변하지 않는다."}, {"id": "D", "text": "입력 크기에 상관없이 일정한 시간을 소요한다."}]', 'A', 'O(n²) 복잡도를 가진 알고리즘은 입력 크기가 증가할 때 실행 시간이 제곱으로 증가하는 특징을 가집니다.'),
    (776, 4, 1, 20, '빅오 표기법에서 O(n log n)은 어떤 경우에 해당하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "선택 정렬과 같은 비효율적인 정렬 알고리즘."}, {"id": "B", "text": "합병 정렬과 같은 효율적인 정렬 알고리즘."}, {"id": "C", "text": "최악의 경우를 고려하지 않는 알고리즘."}, {"id": "D", "text": "입력 크기와 상관없이 실행 시간이 일정한 알고리즘."}]', 'B', 'O(n log n)은 합병 정렬과 같은 효율적인 정렬 알고리즘의 시간 복잡도를 나타냅니다.'),
    (777, 4, 1, 21, '시간 복잡도를 분석할 때 주로 고려하는 경우는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최악의 경우."}, {"id": "B", "text": "평균 케이스."}, {"id": "C", "text": "최선의 경우."}, {"id": "D", "text": "모든 경우."}]', 'A', '시간 복잡도를 분석할 때 주로 최악의 경우를 고려하여 알고리즘의 성능을 평가합니다.'),
    (778, 4, 1, 22, '시간과 공간 복잡도 분석에서 중요한 요소는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "입력 크기."}, {"id": "B", "text": "알고리즘의 종류."}, {"id": "C", "text": "실행 환경."}, {"id": "D", "text": "프로그래밍 언어."}]', '["A", "B"]', '시간과 공간 복잡도 분석에서 입력 크기와 알고리즘의 종류가 중요한 요소입니다.'),
    (779, 4, 1, 23, '시간 복잡도가 O(1)인 알고리즘의 특징은 무엇인가요?', 'SHORT_ANSWER', NULL, '입력 크기와 관계없이 항상 일정한 시간에 실행된다.', 'O(1)인 알고리즘은 입력 크기와 관계없이 항상 일정한 시간에 실행됩니다.'),
    (780, 4, 1, 24, '중위 표기법을 후위 표기법으로 변환할 때 주로 사용하는 자료구조는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "리스트"}, {"id": "D", "text": "트리"}]', 'A', '중위 표기법을 후위 표기법으로 변환할 때는 연산자의 우선순위를 관리하기 위해 스택을 사용합니다.'),
    (781, 4, 1, 25, '단조 스택의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최댓값/최솟값 찾기"}, {"id": "B", "text": "정렬"}, {"id": "C", "text": "데이터 저장"}, {"id": "D", "text": "그래프 탐색"}]', 'A', '단조 스택은 특정 조건을 만족하는 최댓값이나 최솟값을 효율적으로 찾기 위해 사용됩니다.'),
    (782, 4, 1, 26, '우선순위 큐의 특징으로 맞는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "항상 FIFO 방식으로 작동한다."}, {"id": "B", "text": "각 요소는 우선순위가 있다."}, {"id": "C", "text": "항상 최솟값을 제공한다."}, {"id": "D", "text": "스택처럼 LIFO 방식으로 작동한다."}]', 'B', '우선순위 큐에서는 각 요소가 우선순위를 가지며, 가장 높은 우선순위를 가진 요소가 먼저 처리됩니다.'),
    (783, 4, 1, 27, '괄호 검사를 할 때 가장 적합한 자료구조는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "배열"}, {"id": "D", "text": "연결 리스트"}]', '["A"]', '괄호 검사는 스택을 사용하여 여는 괄호와 닫는 괄호의 쌍을 확인함으로써 수행됩니다.'),
    (784, 4, 1, 28, '원형 큐의 주된 장점은 무엇인가요?', 'SHORT_ANSWER', NULL, '메모리 효율성을 높이고, 데이터의 순환 처리를 가능하게 한다.', '원형 큐는 사용하지 않는 메모리 공간을 재활용하여 효율적인 데이터 처리를 할 수 있습니다.'),
    (785, 4, 1, 29, '이분 그래프의 정의는 무엇인가요?', 'SHORT_ANSWER', NULL, '두 개의 집합으로 나눌 수 있는 그래프', '이분 그래프는 정점들을 두 개의 서로 다른 집합으로 나눌 수 있고, 같은 집합의 정점끼리는 간선이 연결되어 있지 않습니다.'),
    (786, 4, 1, 30, '밀집 그래프에 적합한 그래프 표현 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인접 행렬"}, {"id": "B", "text": "인접 리스트"}, {"id": "C", "text": "DAG"}, {"id": "D", "text": "완전 그래프"}]', 'A', '밀집 그래프는 정점의 수에 비해 간선의 수가 많은 경우로, 인접 행렬이 모든 정점 쌍에 대한 간선 존재 여부를 쉽게 표현할 수 있어 적합합니다.'),
    (787, 4, 1, 31, '희소 그래프에 가장 적합한 표현 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인접 행렬"}, {"id": "B", "text": "인접 리스트"}, {"id": "C", "text": "완전 그래프"}, {"id": "D", "text": "이분 그래프"}]', 'B', '희소 그래프는 간선의 수가 적기 때문에 인접 리스트로 표현하는 것이 메모리를 효율적으로 사용할 수 있습니다.'),
    (788, 4, 1, 32, 'DAG의 특징 중 올바르지 않은 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "사이클이 없다."}, {"id": "B", "text": "방향성이 있다."}, {"id": "C", "text": "완전 그래프이다."}, {"id": "D", "text": "유향 그래프이다."}]', '["C"]', 'DAG는 사이클이 없는 유향 그래프이며, 모든 정점이 서로 연결된 완전 그래프가 아닙니다.'),
    (789, 4, 1, 33, '시간복잡도를 나타내는 Big O 표기법에서 O(n log n)의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기 n에 비례하여 로그 증가하는 시간 복잡도를 가짐"}, {"id": "B", "text": "상수 시간 복잡도를 가짐"}, {"id": "C", "text": "입력 크기 n에 비례하여 선형적으로 증가하는 시간 복잡도를 가짐"}, {"id": "D", "text": "입력 크기 n의 제곱에 비례하여 증가하는 시간 복잡도를 가짐"}]', 'A', 'O(n log n)은 입력 크기 n에 비례하여 로그 증가하는 성격을 나타냅니다.'),
    (790, 4, 1, 34, 'P vs NP 문제는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문제를 해결하는 것이 어려운지 여부를 결정하는 것"}, {"id": "B", "text": "모든 NP 문제는 다항시간 내에 해결 가능하다"}, {"id": "C", "text": "모든 P 문제는 NP 문제에 포함된다"}, {"id": "D", "text": "해결방법이 주어지면 그것이 정답인지 검증할 수 있는 문제"}]', 'D', 'P vs NP 문제는 해결방법이 주어지면 그것이 정답인지 검증할 수 있는 NP 문제의 성격을 다룹니다.'),
    (791, 4, 1, 35, '재귀 시간복잡도를 분석할 때 주로 사용하는 방법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "점근적 분석"}, {"id": "B", "text": "선형 회귀"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "그래프 이론"}]', 'A', '재귀 시간복잡도를 분석할 때는 점근적 분석을 주로 사용합니다.'),
    (792, 4, 1, 36, 'O(1)의 시간복잡도를 가진 알고리즘의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "입력 크기에 관계없이 일정한 시간 소요"}, {"id": "B", "text": "입력 크기가 커질수록 시간이 증가함"}, {"id": "C", "text": "고정된 작업 수를 수행함"}, {"id": "D", "text": "정렬 알고리즘에만 해당됨"}]', '["A", "C"]', 'O(1)은 입력 크기에 관계없이 일정한 시간을 소요하며, 고정된 작업 수를 수행하는 알고리즘을 의미합니다.'),
    (793, 4, 1, 37, 'NP-완전 문제의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '모든 NP 문제를 다항시간 내에 해결할 수 있는 문제', ''),
    (794, 4, 1, 38, 'Big O 표기법에서 O(n²)의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "선형 시간 복잡도"}, {"id": "B", "text": "로그 선형 시간 복잡도"}, {"id": "C", "text": "2차 시간 복잡도"}, {"id": "D", "text": "상수 시간 복잡도"}]', 'C', 'O(n²)는 입력 크기 n에 대해 알고리즘의 실행 시간이 n²에 비례함을 의미합니다.'),
    (795, 4, 1, 39, 'NP 문제의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항식 시간 내에 해결 가능한 문제"}, {"id": "B", "text": "다항식 시간 내에 검증 가능한 문제"}, {"id": "C", "text": "상수 시간 내에 해결 가능한 문제"}, {"id": "D", "text": "로그 시간 내에 검증 가능한 문제"}]', 'B', 'NP 문제는 다항식 시간 내에 검증이 가능한 문제입니다.'),
    (796, 4, 1, 40, 'O(log n) 복잡도를 가지는 알고리즘의 예는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "버블 정렬"}, {"id": "B", "text": "이진 탐색"}, {"id": "C", "text": "선형 탐색"}, {"id": "D", "text": "세그먼트 트리"}]', 'B', '이진 탐색 알고리즘은 정렬된 배열에서 목표 값을 찾는 데 O(log n) 시간이 걸립니다.'),
    (797, 4, 1, 41, '다음 중 시간복잡도가 O(n log n)인 알고리즘은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "합병 정렬"}, {"id": "B", "text": "버블 정렬"}, {"id": "C", "text": "힙 정렬"}, {"id": "D", "text": "선형 탐색"}]', '["A", "C"]', '합병 정렬과 힙 정렬은 모두 O(n log n) 시간복잡도를 갖습니다.'),
    (798, 4, 1, 42, '시간 복잡도의 최악의 경우를 나타내는데 일반적으로 사용되는 표기법은?', 'SHORT_ANSWER', NULL, 'Big O', '시간 복잡도의 최악의 경우를 나타내기 위해 Big O 표기법을 사용합니다.'),
    (799, 4, 1, 43, '무방향 그래프의 특성으로 옳은 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점 간의 관계가 방향성이 없다."}, {"id": "B", "text": "정점이 서로 연결되지 않는다."}, {"id": "C", "text": "모든 정점이 서로 연결되어 있다."}, {"id": "D", "text": "사이클이 존재하지 않는다."}]', 'A', '무방향 그래프는 정점 간의 관계가 방향성이 없는 그래프입니다.'),
    (800, 4, 1, 44, 'DAG의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Directed Acyclic Graph"}, {"id": "B", "text": "Double Acyclic Graph"}, {"id": "C", "text": "Directional Acquaintance Graph"}, {"id": "D", "text": "Directed and Graphical"}]', 'A', 'DAG는 Directed Acyclic Graph의 약자로, 방향성이 있는 비순환 그래프를 의미합니다.'),
    (801, 4, 1, 45, '아래 중 사이클 검출이 필요한 경우는 어떤 경우인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DAG에서"}, {"id": "B", "text": "완전 그래프에서"}, {"id": "C", "text": "무방향 그래프에서"}, {"id": "D", "text": "사이클이 있는 방향 그래프에서"}]', 'D', '사이클 검출은 사이클이 존재하는 방향 그래프에서 필요한 기법입니다.'),
    (802, 4, 1, 46, '그래프의 차수와 진출 차수에 해당하는 것들을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "차수"}, {"id": "B", "text": "정점"}, {"id": "C", "text": "진출 차수"}, {"id": "D", "text": "간선"}]', '["A", "C"]', '차수는 정점에 연결된 간선의 수, 진출 차수는 특정 정점에서 나가는 간선의 수를 의미합니다.'),
    (803, 4, 1, 47, '희소 그래프의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '정점의 수에 비해 간선의 수가 적은 그래프', '희소 그래프는 정점의 수에 비해 간선의 수가 적은 그래프를 의미하며, 메모리 효율성이 높습니다.'),
    (804, 4, 1, 48, '동적 배열의 특성 중 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "크기를 동적으로 조절할 수 있다."}, {"id": "B", "text": "고정된 크기를 가진다."}, {"id": "C", "text": "요소의 접근 시간이 O(1)이다."}, {"id": "D", "text": "다른 배열보다 유연하다."}]', 'B', '동적 배열은 크기를 동적으로 조절할 수 있어 고정된 크기를 가지지 않습니다.'),
    (805, 4, 1, 49, '스택의 작동 원리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "선입선출(FIFO)이다."}, {"id": "B", "text": "후입선출(LIFO)이다."}, {"id": "C", "text": "랜덤 접근 방식이다."}, {"id": "D", "text": "이중 연결 방식이다."}]', 'B', '스택은 후입선출(LIFO) 원칙에 따라 작동하며, 마지막에 추가된 요소가 가장 먼저 제거됩니다.'),
    (806, 4, 1, 50, '우선순위 큐의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "항목의 삽입 순서에 따라 처리된다."}, {"id": "B", "text": "항목의 우선순위에 따라 처리된다."}, {"id": "C", "text": "연결 리스트로만 구현된다."}, {"id": "D", "text": "FIFO 원칙을 따른다."}]', 'B', '우선순위 큐는 항목의 우선순위에 따라 처리되므로, 우선순위가 높은 항목이 먼저 삭제됩니다.'),
    (807, 4, 1, 51, '다음 중 배열과 관련된 설명으로 옳지 않은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "배열은 고정된 크기를 가진다."}, {"id": "B", "text": "배열은 인덱스를 통해 요소에 접근한다."}, {"id": "C", "text": "배열은 삽입과 삭제가 용이하다."}, {"id": "D", "text": "배열의 요소는 연속된 메모리 위치에 저장된다."}]', '["C"]', '배열은 연속된 메모리 위치에 저장되므로, 중간에 요소를 삽입하거나 삭제하는 것은 비용이 많이 드는 작업입니다.'),
    (808, 4, 1, 52, '이중 연결 리스트의 주요 이점은 무엇인가?', 'SHORT_ANSWER', NULL, '노드의 삽입과 삭제가 용이하다.', '이중 연결 리스트는 각 노드가 이전 및 다음 노드를 가리키므로, 노드의 삽입과 삭제가 상대적으로 용이합니다.'),
    (809, 4, 1, 53, '스택의 작동 방식은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "FIFO"}, {"id": "B", "text": "LIFO"}, {"id": "C", "text": "FILO"}, {"id": "D", "text": "LILO"}]', 'B', '스택은 LIFO(Last In First Out) 방식으로 작동합니다.'),
    (810, 4, 1, 54, '링크드 리스트의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정된 크기"}, {"id": "B", "text": "노드가 다음 노드를 가리킴"}, {"id": "C", "text": "순차적으로 접근 가능"}, {"id": "D", "text": "메모리 할당이 정적"}]', 'B', '링크드 리스트는 각 노드가 다음 노드를 가리키는 형태로 구성되어 있습니다.'),
    (811, 4, 1, 55, '다음 중 원형 큐의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "FIFO 방식"}, {"id": "B", "text": "메모리 공간을 효율적으로 사용"}, {"id": "C", "text": "끝 점이 없다"}, {"id": "D", "text": "경계가 없다"}]', 'C', '원형 큐는 끝 점이 있지만, 큐의 앞과 뒤가 연결되어 있어 순환하는 구조입니다.'),
    (812, 4, 1, 56, '스택에서 가장 위의 요소를 확인하는 메소드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'peek', '스택에서 가장 위의 요소를 확인할 때는 peek 메소드를 사용합니다.'),
    (813, 4, 1, 57, '스택과 큐의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스택은 LIFO, 큐는 FIFO"}, {"id": "B", "text": "스택은 순차적 접근, 큐는 비순차적 접근"}, {"id": "C", "text": "스택은 push, 큐는 enqueue"}, {"id": "D", "text": "스택은 링크드 리스트로만 구현 가능"}]', '["A", "C"]', '스택은 LIFO 방식으로 작동하고 push 메소드를 사용하며, 큐는 FIFO 방식으로 작동하고 enqueue 메소드를 사용합니다.'),
    (814, 4, 1, 58, '후위 표기법을 사용하여 수식을 평가할 때 어떤 자료구조가 가장 적합한가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "리스트"}, {"id": "D", "text": "트리"}]', 'A', '후위 표기법은 연산의 우선순위를 고려하지 않고 스택을 사용하여 수식을 평가하는 데 효율적입니다.'),
    (815, 4, 1, 59, 'Min Stack의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택의 크기를 줄이기 위해"}, {"id": "B", "text": "스택에서 최솟값을 O(1) 시간에 반환하기 위해"}, {"id": "C", "text": "스택의 정렬을 유지하기 위해"}, {"id": "D", "text": "스택의 메모리 사용량을 줄이기 위해"}]', 'B', 'Min Stack은 스택의 최솟값을 효율적으로 추적하여 O(1) 시간에 반환할 수 있도록 설계되었습니다.'),
    (816, 4, 1, 60, '두 스택을 사용하여 큐를 구현할 때의 주요 단계는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 요소를 두 번째 스택으로 옮기기"}, {"id": "B", "text": "스택1에서 요소를 제거하기"}, {"id": "C", "text": "큐의 크기를 측정하기"}, {"id": "D", "text": "스택1에 새로운 요소 추가하기"}]', 'A', '두 스택을 사용하여 큐를 구현할 때, 첫 번째 스택에서 요소를 두 번째 스택으로 옮기면 큐의 FIFO 특성을 유지할 수 있습니다.'),
    (817, 4, 1, 61, '스택을 활용한 괄호 검사의 필요 조건은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 여는 괄호가 닫히는 괄호와 쌍을 이뤄야 한다."}, {"id": "B", "text": "괄호의 종류가 같아야 한다."}, {"id": "C", "text": "여는 괄호는 닫히기 전에 반드시 스택에 들어가야 한다."}, {"id": "D", "text": "모든 닫는 괄호는 스택에 여는 괄호가 있어야 한다."}]', '["A", "C", "D"]', '괄호 검사는 여는 괄호가 닫히는 괄호와 쌍을 이루고, 닫는 괄호를 만나기 전에 여는 괄호가 반드시 스택에 있어야 합니다.'),
    (818, 4, 1, 62, '원형 큐의 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '원형 큐는 선형 큐에서 발생하는 메모리 낭비를 줄이기 위해 큐의 끝이 다시 시작으로 연결되어 있는 구조입니다.', ''),
    (819, 4, 1, 63, 'BFS 알고리즘의 주된 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "레벨 순서로 노드를 탐색한다."}, {"id": "B", "text": "가장 깊은 노드를 먼저 탐색한다."}, {"id": "C", "text": "모든 노드를 랜덤하게 탐색한다."}, {"id": "D", "text": "가장 가까운 노드부터 탐색한다."}]', 'A', 'BFS는 너비 우선 탐색으로, 레벨 순서로 노드를 탐색합니다.'),
    (820, 4, 1, 64, 'A* 알고리즘이 사용하는 주요 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "순차 탐색"}, {"id": "B", "text": "휴리스틱 함수 사용"}, {"id": "C", "text": "다익스트라 알고리즘"}, {"id": "D", "text": "DFS"}]', 'B', 'A* 알고리즘은 최적 경로 탐색을 위해 휴리스틱 함수를 사용합니다.'),
    (821, 4, 1, 65, '다익스트라 알고리즘과 벨만-포드 알고리즘의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다익스트라는 음의 가중치를 지원하지 않는다."}, {"id": "B", "text": "벨만-포드는 음의 가중치를 지원한다."}, {"id": "C", "text": "다익스트라는 모든 노드를 탐색한다."}, {"id": "D", "text": "모두 동일하다."}]', 'A', '다익스트라 알고리즘은 음의 가중치를 지원하지 않고, 벨만-포드는 이를 처리할 수 있습니다.'),
    (822, 4, 1, 66, '다음 중 그래프 탐색 알고리즘에 해당하는 것은 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "BFS"}, {"id": "B", "text": "A* 알고리즘"}, {"id": "C", "text": "순차 탐색"}, {"id": "D", "text": "다익스트라"}]', '["A", "B", "D"]', 'BFS, A* 알고리즘, 다익스트라는 모두 그래프 탐색 알고리즘입니다.'),
    (823, 4, 1, 67, '순차 탐색의 시간 복잡도는 무엇인가요?', 'SHORT_ANSWER', NULL, 'O(n)', '순차 탐색의 시간 복잡도는 O(n)입니다.'),
    (824, 4, 1, 68, 'Min Stack의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최솟값을 O(1) 시간에 찾을 수 있다."}, {"id": "B", "text": "최댓값을 O(1) 시간에 찾을 수 있다."}, {"id": "C", "text": "모든 원소를 정렬할 수 있다."}, {"id": "D", "text": "중복된 원소를 허용하지 않는다."}]', 'A', 'Min Stack은 최솟값을 O(1) 시간에 찾을 수 있는 스택 구조입니다.'),
    (825, 4, 1, 69, '괄호 검사 문제에서 사용되는 자료구조는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "큐"}, {"id": "B", "text": "스택"}, {"id": "C", "text": "링크드 리스트"}, {"id": "D", "text": "배열"}]', 'B', '괄호 검사는 스택을 사용하여 구현할 수 있습니다.'),
    (826, 4, 1, 70, '모노톤 스택이 사용되는 대표적인 문제는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열 찾기"}, {"id": "B", "text": "최대 직사각형 면적 계산"}, {"id": "C", "text": "최솟값 찾기"}, {"id": "D", "text": "괄호 검사"}]', 'B', '모노톤 스택은 히스토그램의 최대 직사각형 면적을 찾는 데 사용됩니다.'),
    (827, 4, 1, 71, '후위 표기법에서 연산을 수행할 때 사용하는 데이터 구조는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "배열"}, {"id": "D", "text": "트리"}]', '["A"]', '후위 표기법에서 연산을 수행할 때 스택을 활용합니다.'),
    (828, 4, 1, 72, '최솟값 스택의 구현 시 어떤 추가 구조가 필요합니까?', 'SHORT_ANSWER', NULL, '추가 스택', ''),
    (829, 4, 1, 73, '다음 중 O(n log n)의 시간 복잡도를 가지는 정렬 알고리즘은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "머지 정렬"}, {"id": "B", "text": "선택 정렬"}, {"id": "C", "text": "버블 정렬"}, {"id": "D", "text": "삽입 정렬"}]', 'A', '머지 정렬은 분할 정복 방식을 사용하여 O(n log n) 시간 복잡도를 가지며, 효율적인 정렬 알고리즘입니다.'),
    (830, 4, 1, 74, '안정 정렬의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동일한 값의 요소의 상대적 순서가 유지된다."}, {"id": "B", "text": "항상 O(n) 시간 복잡도를 가진다."}, {"id": "C", "text": "모든 정렬 알고리즘은 안정 정렬이다."}, {"id": "D", "text": "정렬 후 중복값이 제거된다."}]', 'A', '안정 정렬 알고리즘은 같은 키를 가진 요소들이 정렬 후에도 원래의 순서를 유지하는 특징이 있습니다.'),
    (831, 4, 1, 75, 'Tim sort는 어떤 특징을 가지고 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비교 기반 정렬 알고리즘이다."}, {"id": "B", "text": "O(n^2) 시간 복잡도를 가진다."}, {"id": "C", "text": "불안정한 정렬 알고리즘이다."}, {"id": "D", "text": "정렬을 수행하지 않는다."}]', 'A', 'Tim sort는 비교 기반 정렬 알고리즘으로, 효율성과 안정성을 모두 갖춘 현대적인 정렬 알고리즘입니다.'),
    (832, 4, 1, 76, '정렬 알고리즘의 최선, 최악, 평균 경우 성능 분석에서 가장 큰 의미가 있는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "각 알고리즘의 효율성을 비교할 수 있다."}, {"id": "B", "text": "모든 알고리즘이 동일한 성능을 보인다."}, {"id": "C", "text": "특정 데이터에 대한 알고리즘의 성능을 예측할 수 있다."}, {"id": "D", "text": "비교 기반 정렬만 분석할 수 있다."}]', '["A", "C"]', '최선, 최악, 평균 경우 성능 분석은 각 알고리즘의 효율성을 비교하고 특정 데이터에 대한 성능을 예측하는 데 큰 의미가 있습니다.'),
    (833, 4, 1, 77, '선택 정렬의 시간 복잡도는?', 'SHORT_ANSWER', NULL, 'O(n^2)', '선택 정렬은 두 개의 중첩된 반복문을 사용하여 정렬을 수행하므로 시간 복잡도는 O(n^2)입니다.'),
    (834, 4, 1, 78, 'O(n²) 알고리즘의 시간 복잡도는 입력 크기 n에 대해 어떻게 증가하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "제곱에 비례하여 증가한다."}, {"id": "B", "text": "선형에 비례하여 증가한다."}, {"id": "C", "text": "로그에 비례하여 증가한다."}, {"id": "D", "text": "상수로 일정하게 유지된다."}]', 'A', 'O(n²) 시간 복잡도는 입력 크기 n의 제곱에 비례하여 실행 시간이 증가합니다.'),
    (835, 4, 1, 79, 'NP-완전 문제의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항식 시간 안에 해결할 수 있는 문제이다."}, {"id": "B", "text": "해답을 검증하는 데는 다항식 시간이 소요된다."}, {"id": "C", "text": "무조건 최적의 해결책을 찾을 수 있다."}, {"id": "D", "text": "선형적으로 해결 가능하다."}]', 'B', 'NP-완전 문제는 효율적인 해결책이 존재하지 않지만, 그 해답을 검증하는 데는 다항식 시간이 걸리는 문제입니다.'),
    (836, 4, 1, 80, '아모타이즈드 분석의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "특정 작업의 최악의 경우 성능을 평가한다."}, {"id": "B", "text": "평균적인 성능을 평가한다."}, {"id": "C", "text": "무작위 성능을 평가한다."}, {"id": "D", "text": "상수 시간 성능을 추정한다."}]', 'B', '아모타이즈드 분석은 특정 작업이 드물게 발생할 때 전체적인 평균 성능을 평가하기 위한 기법입니다.'),
    (837, 4, 1, 81, '다음 중 O(1)의 시간 복잡도를 갖는 알고리즘의 예시는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "배열의 특정 인덱스 접근"}, {"id": "B", "text": "배열의 모든 요소를 탐색"}, {"id": "C", "text": "스택에서 요소 추가"}, {"id": "D", "text": "재귀 호출로 피보나치 수 계산"}]', '["A", "C"]', 'O(1)의 시간 복잡도는 배열의 특정 인덱스 접근과 스택에서 요소 추가처럼 입력 크기와 상관없이 일정한 시간 안에 수행됩니다.'),
    (838, 4, 1, 82, '재귀 시간 복잡도를 분석하는 방법은 무엇이라고 하는가?', 'SHORT_ANSWER', NULL, '재귀 관계식', '재귀 시간 복잡도를 분석하는 방법은 주로 재귀 관계식을 세우고 이를 해결하는 방식입니다.'),
    (839, 4, 1, 83, 'O(n²) 시간복잡도를 가지는 알고리즘의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기 n이 증가함에 따라 실행 시간이 제곱 비례로 증가한다."}, {"id": "B", "text": "입력 크기 n이 증가함에 따라 실행 시간이 선형 비례로 증가한다."}, {"id": "C", "text": "주로 재귀적으로 실행된다."}, {"id": "D", "text": "상수 시간 복잡도를 가진다."}]', 'A', 'O(n²)는 입력 크기 n이 증가할 때 실행 시간이 n의 제곱에 비례하여 증가함을 의미합니다.'),
    (840, 4, 1, 84, '재귀 알고리즘의 시간복잡도를 분석하는 데 유용한 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "빅오 표기법"}, {"id": "B", "text": "마스터 정리"}, {"id": "C", "text": "최악의 경우 분석"}, {"id": "D", "text": "평균 사례 분석"}]', 'B', '재귀 알고리즘의 시간복잡도는 주로 마스터 정리를 통해 분석할 수 있습니다.'),
    (841, 4, 1, 85, 'NP-완전 문제의 특징으로 알맞은 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항 시간 내에 해결할 수 있다."}, {"id": "B", "text": "해결할 수 있는 알고리즘이 존재한다."}, {"id": "C", "text": "모든 다항 시간 문제로 줄일 수 있다."}, {"id": "D", "text": "다항 시간으로 검증할 수 있는 문제이다."}]', 'D', 'NP-완전 문제는 다항 시간 내에 검증할 수 있는 문제로 정의됩니다.'),
    (842, 4, 1, 86, '시간복잡도를 분석할 때, O(n log n) 시간복잡도의 알고리즘은 어떤 경우에 주로 나타나나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "정렬 알고리즘"}, {"id": "B", "text": "탐색 알고리즘"}, {"id": "C", "text": "재귀 알고리즘"}, {"id": "D", "text": "그래프 알고리즘"}]', '["A", "C"]', 'O(n log n) 시간복잡도는 주로 정렬 알고리즘(예: 퀵소트, 병합정렬)이나 재귀적으로 나뉘는 문제에서 나타납니다.'),
    (843, 4, 1, 87, '점근적 분석에서 ''빅오''(Big O) 표기는 어떤 의미인가요?', 'SHORT_ANSWER', NULL, '알고리즘의 최악의 경우 성능을 나타내는 표기법입니다.', '빅오 표기는 알고리즘의 시간복잡도가 입력 크기가 무한히 커질 때 어떤 형태로 증가하는지를 나타냅니다.'),
    (844, 4, 1, 88, '스택을 활용한 괄호 검사는 주로 어떤 목적으로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "괄호의 짝이 맞는지 확인하기 위해"}, {"id": "B", "text": "최솟값을 찾기 위해"}, {"id": "C", "text": "수식을 계산하기 위해"}, {"id": "D", "text": "리스트를 정렬하기 위해"}]', 'A', '스택은 LIFO 구조로, 괄호의 짝을 맞추는 데 매우 유용합니다.'),
    (845, 4, 1, 89, '후위 표기법을 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연산자의 우선순위를 고려할 필요가 없어서"}, {"id": "B", "text": "괄호가 필요해서"}, {"id": "C", "text": "모든 수식을 정렬하기 위해"}, {"id": "D", "text": "자료구조를 간단히 하기 위해"}]', 'A', '후위 표기법은 연산자의 순서를 명시적으로 표현하므로 우선순위를 고려할 필요가 없습니다.'),
    (846, 4, 1, 90, 'Min Stack을 구현하기 위해서는 어떤 자료구조를 사용하는 것이 가장 효과적인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단조 스택"}, {"id": "B", "text": "일반 스택"}, {"id": "C", "text": "큐"}, {"id": "D", "text": "리스트"}]', 'A', 'Min Stack은 단조 스택을 활용하여 최솟값을 효율적으로 가져올 수 있습니다.'),
    (847, 4, 1, 91, 'BFS의 주요 특징 중 하나는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "너비 우선 탐색"}, {"id": "B", "text": "깊이 우선 탐색과 동일하다"}, {"id": "C", "text": "레벨 탐색이 가능하다"}, {"id": "D", "text": "스택을 사용한다"}]', '["A", "C"]', 'BFS는 너비 우선 탐색으로 레벨 단위로 탐색하는 특징이 있습니다.'),
    (848, 4, 1, 92, '단조 스택의 주요 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '최솟값을 O(1) 시간에 찾는 기능', ''),
    (849, 4, 1, 93, '인접 리스트의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 정점마다 연결된 정점들을 리스트로 저장한다."}, {"id": "B", "text": "모든 간선을 리스트로 저장한다."}, {"id": "C", "text": "각 정점 사이의 거리를 기록한다."}, {"id": "D", "text": "간선의 개수에 비례하여 메모리를 사용한다."}]', 'A', '인접 리스트는 각 정점마다 연결된 정점들을 리스트로 저장하여 그래프 구조를 표현한다.'),
    (850, 4, 1, 94, '가중치 그래프의 특징으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 간선에 가중치가 할당되어 있다."}, {"id": "B", "text": "모든 정점이 동일한 가중치를 가진다."}, {"id": "C", "text": "무방향 그래프만을 의미한다."}, {"id": "D", "text": "진입 차수와는 무관하다."}]', 'A', '가중치 그래프는 각 간선에 가중치가 할당되어 있어, 거리나 비용 같은 추가 정보를 포함할 수 있다.'),
    (851, 4, 1, 95, '플래너 그래프의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "교차하지 않고 평면에서 그릴 수 있는 그래프다."}, {"id": "B", "text": "모든 간선이 방향을 가진 그래프다."}, {"id": "C", "text": "정점 수가 간선 수와 동일한 그래프다."}, {"id": "D", "text": "모든 간선이 가중치를 가지는 그래프다."}]', 'A', '플래너 그래프는 교차하지 않고 평면에서 그릴 수 있는 그래프를 의미한다.'),
    (852, 4, 1, 96, '무방향 그래프의 특성 중 하나는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "간선에 방향이 없다."}, {"id": "B", "text": "진입 차수와 진출 차수가 같다."}, {"id": "C", "text": "모든 정점은 연결될 수 있다."}, {"id": "D", "text": "가중치가 부여된 간선이 있다."}]', '["A", "B"]', '무방향 그래프는 간선에 방향이 없으며, 각 정점의 진입 차수와 진출 차수가 같다는 특성이 있다.'),
    (853, 4, 1, 97, '진입 차수란 무엇인가?', 'SHORT_ANSWER', NULL, '특정 정점으로 들어오는 간선의 수', '진입 차수는 특정 정점으로 들어오는 간선의 수를 나타내며, 그래프의 구조를 이해하는 데 중요한 요소이다.'),
    (854, 4, 1, 98, 'DFS(Depth-First Search) 알고리즘의 기본적인 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드를 깊게 탐색한다."}, {"id": "B", "text": "모든 노드를 넓게 탐색한다."}, {"id": "C", "text": "모든 노드를 한 번만 방문한다."}, {"id": "D", "text": "최단 경로를 항상 찾는다."}]', 'A', 'DFS는 그래프의 모든 노드를 깊게 탐색하는 방식입니다.'),
    (855, 4, 1, 99, '플로이드-워셜 알고리즘의 주요 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 쌍의 최단 경로를 찾는 것"}, {"id": "B", "text": "단일 출발지에서 최단 경로를 찾는 것"}, {"id": "C", "text": "그래프를 정렬하는 것"}, {"id": "D", "text": "최대 유량을 계산하는 것"}]', 'A', '플로이드-워셜 알고리즘은 모든 쌍의 최단 경로를 계산하는 알고리즘입니다.'),
    (856, 4, 1, 100, '위상 정렬은 어떤 종류의 그래프에 적용할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "무방향 그래프"}, {"id": "B", "text": "순환 그래프"}, {"id": "C", "text": "비순환 방향 그래프(DAG)"}, {"id": "D", "text": "모든 그래프"}]', 'C', '위상 정렬은 비순환 방향 그래프(DAG)에 적용할 수 있습니다.'),
    (857, 4, 1, 101, '다음 중 경로 탐색 알고리즘에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DFS"}, {"id": "B", "text": "BFS"}, {"id": "C", "text": "다익스트라 알고리즘"}, {"id": "D", "text": "퀵 정렬"}]', '["A", "B", "C"]', 'DFS, BFS, 다익스트라 알고리즘 모두 경로 탐색 알고리즘에 해당합니다.'),
    (858, 4, 1, 102, '미로 탐색 문제를 해결하는 방법 중 하나는 무엇인가요?', 'SHORT_ANSWER', NULL, 'DFS 또는 BFS를 사용하여 경로를 탐색한다.', '미로 탐색 문제는 DFS 또는 BFS를 사용하여 출구까지의 경로를 탐색하는 방법으로 해결할 수 있습니다.'),
    (859, 4, 1, 103, 'LinkedList의 주요 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '동적으로 크기를 조절할 수 있다.', 'LinkedList는 각 요소가 다음 요소에 대한 참조를 가지며, 크기를 동적으로 조절할 수 있는 특징이 있다.'),
    (860, 4, 1, 104, '스택에서 데이터를 추가하는 연산은 무엇이라고 하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "push"}, {"id": "B", "text": "pop"}, {"id": "C", "text": "enqueue"}, {"id": "D", "text": "dequeue"}]', 'A', '스택에서 데이터를 추가하는 연산은 ''push''라고 한다.'),
    (861, 4, 1, 105, '큐의 특징으로 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "FIFO 구조이다."}, {"id": "B", "text": "LIFO 구조이다."}, {"id": "C", "text": "먼저 들어온 데이터가 먼저 나간다."}, {"id": "D", "text": "데이터의 삽입과 삭제가 양쪽 끝에서 이루어진다."}]', 'B', '큐는 FIFO 구조이므로 ''LIFO 구조이다.''라는 설명은 올바르지 않다.'),
    (862, 4, 1, 106, '다음 중 선형 자료구조로 사용하는 것이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "Queue"}, {"id": "B", "text": "Tree"}, {"id": "C", "text": "Stack"}, {"id": "D", "text": "LinkedList"}]', '["B"]', 'Tree는 비선형 자료구조로 선형 자료구조가 아니다.'),
    (863, 4, 1, 107, '원형 큐의 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '공간 효율성을 높일 수 있다.', '원형 큐는 큐의 끝이 시작과 연결되어 있어 사용하지 않는 공간을 줄여 공간 효율성을 높인다.'),
    (864, 4, 1, 108, '시간 복잡도의 최악 시간 복잡도를 분석할 때 주로 고려하는 경우는 어떤 것인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 입력이 최악인 경우"}, {"id": "B", "text": "모든 입력이 최선인 경우"}, {"id": "C", "text": "무작위 입력"}, {"id": "D", "text": "입력이 없을 때"}]', 'A', '최악 시간 복잡도는 알고리즘이 수행되는 데 가장 많은 시간이 걸리는 상황을 의미하기 때문에 모든 입력이 최악인 경우를 고려한다.'),
    (865, 4, 1, 109, 'P vs NP 문제에서 NP 문제란 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항 시간 내에 해결할 수 있는 문제"}, {"id": "B", "text": "해결 방법이 다항 시간 내에 검증 가능한 문제"}, {"id": "C", "text": "해결할 수 없는 문제"}, {"id": "D", "text": "모든 문제를 해결하는 문제"}]', 'B', 'NP 문제는 그 해답이 주어졌을 때, 다항 시간 내에 검증할 수 있는 문제를 말한다.'),
    (866, 4, 1, 110, '재귀적 알고리즘의 시간 복잡도를 구하는 데 유용한 정리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유한 상태 기계"}, {"id": "B", "text": "다이나믹 프로그래밍"}, {"id": "C", "text": "마스터 정리"}, {"id": "D", "text": "분할 정복"}]', 'C', '마스터 정리는 재귀적 알고리즘의 시간 복잡도를 구하는 데 유용한 도구이다.'),
    (867, 4, 1, 111, '시간 복잡도의 평균 및 최악 시간 복잡도는 어떤 상황에 따라 다르게 분석되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "입력의 분포"}, {"id": "B", "text": "알고리즘의 구현 방식"}, {"id": "C", "text": "입력의 크기"}, {"id": "D", "text": "알고리즘의 최적화 여부"}]', '["A", "B", "C"]', '시간 복잡도의 평균 및 최악 시간 복잡도는 입력의 분포, 알고리즘의 구현 방식, 입력의 크기에 따라 다르게 분석된다.'),
    (868, 4, 1, 112, '시간 복잡도의 최선 척도는 무엇을 측정하는가?', 'SHORT_ANSWER', NULL, '최선의 경우에 소요되는 시간', '최선 시간 복잡도는 알고리즘이 수행되는 데 걸리는 최적의 시간, 즉 최선의 경우에 소요되는 시간을 측정한다.'),
    (869, 4, 1, 113, '삽입 정렬의 시간 복잡도는 무엇인가?', 'SHORT_ANSWER', NULL, 'O(n^2)', '삽입 정렬은 최악의 경우 O(n^2)의 시간 복잡도를 가집니다.'),
    (870, 4, 1, 114, '버블 정렬은 어떤 방식으로 작동하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인접한 두 요소를 비교하고 교환한다."}, {"id": "B", "text": "리스트를 반으로 나누어 정렬한다."}, {"id": "C", "text": "최댓값을 찾아서 마지막으로 이동한다."}, {"id": "D", "text": "재귀적으로 리스트를 나눈다."}]', 'A', '버블 정렬은 인접한 두 요소를 비교하고 필요시 교환하여 정렬합니다.'),
    (871, 4, 1, 115, '퀵 정렬의 기본 원리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "기준값을 정해 리스트를 나눈다."}, {"id": "B", "text": "모두 정렬된 상태를 유지한다."}, {"id": "C", "text": "정렬 과정에서 반복을 사용하지 않는다."}, {"id": "D", "text": "리스트의 중간값을 항상 사용한다."}]', 'A', '퀵 정렬은 기준값(pivot)을 정하여 리스트를 두 부분으로 나누는 방식으로 작동합니다.'),
    (872, 4, 1, 116, '다음 중 비교 기반 정렬 알고리즘은 무엇인가? (복수 선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "퀵 정렬"}, {"id": "B", "text": "기수 정렬"}, {"id": "C", "text": "삽입 정렬"}, {"id": "D", "text": "Tim sort"}]', '["A", "C", "D"]', '퀵 정렬, 삽입 정렬, Tim sort는 모두 비교 기반 정렬 알고리즘입니다. 기수 정렬은 비교 기반이 아닙니다.'),
    (873, 4, 1, 117, 'O(1) 시간 복잡도를 가지는 알고리즘은 어떤 특징이 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기에 관계없이 일정한 시간이 걸린다."}, {"id": "B", "text": "입력 크기가 증가함에 따라 시간이 선형적으로 증가한다."}, {"id": "C", "text": "반복문을 사용해야 한다."}, {"id": "D", "text": "공간 복잡도가 항상 O(1)이다."}]', 'A', 'O(1)은 입력 크기와 무관하게 일정한 시간이 걸리는 알고리즘을 의미합니다.'),
    (874, 4, 1, 118, '다음 중 NP-완전 문제의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해결하기 어려운 문제이다."}, {"id": "B", "text": "다항 시간 안에 해결이 가능하다."}, {"id": "C", "text": "모든 NP 문제는 다항 시간으로 해결할 수 있다."}, {"id": "D", "text": "다른 NP 문제로 변환할 수 있다."}]', 'B', 'NP-완전 문제는 해결하기 어려운 문제로, 반드시 다항 시간 안에 해결할 수 있는 것은 아닙니다.'),
    (875, 4, 1, 119, '다음 중 O(n log n) 시간 복잡도를 가지는 알고리즘은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "버블 정렬"}, {"id": "B", "text": "합병 정렬"}, {"id": "C", "text": "선택 정렬"}, {"id": "D", "text": "퀵 정렬"}]', 'B', '합병 정렬은 O(n log n) 시간 복잡도를 가지는 정렬 알고리즘입니다.'),
    (876, 4, 1, 120, '시간 복잡도가 O(n)인 알고리즘은 어떤 특징이 있나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "입력 크기를 n이라고 할 때, 시간은 n에 비례한다."}, {"id": "B", "text": "시간 복잡도가 일정하다."}, {"id": "C", "text": "모든 경우에서 가장 빠른 성능을 발휘한다."}, {"id": "D", "text": "반복문이 n번 실행된다."}]', '["A", "D"]', 'O(n) 시간 복잡도는 입력 크기 n에 비례하여, 일반적으로 n번 반복문이 실행됨을 의미합니다.'),
    (877, 4, 1, 121, 'Big O 표기법의 주 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '알고리즘의 효율성을 표현하고, 시간 및 공간 복잡도를 비교하기 위함입니다.', 'Big O 표기법은 알고리즘의 효율성을 표현하고, 다른 알고리즘과의 시간 및 공간 복잡도를 비교하기 위해 사용됩니다.'),
    (878, 4, 1, 122, '빅오 표기법에서 O(n log n)은 어떤 상황에서 사용될까요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "분할 정복 알고리즘"}, {"id": "B", "text": "선형 검색 알고리즘"}, {"id": "C", "text": "정렬 알고리즘"}, {"id": "D", "text": "플로이드 워셜 알고리즘"}]', 'C', 'O(n log n)은 주로 병합 정렬, 퀵 정렬 등의 정렬 알고리즘에서 발생합니다.'),
    (879, 4, 1, 123, 'P vs NP 문제는 무엇을 다루고 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 알고리즘의 존재"}, {"id": "B", "text": "무한급수의 수렴"}, {"id": "C", "text": "프로그래밍 언어의 성능"}, {"id": "D", "text": "네트워크 트래픽 최적화"}]', 'A', 'P vs NP 문제는 효율적인 알고리즘이 존재하는지 여부를 다루는 이론적 질문입니다.'),
    (880, 4, 1, 124, '재귀 알고리즘의 시간 복잡도를 분석할 때 주로 사용하는 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "마스터 정리"}, {"id": "B", "text": "속도 정리"}, {"id": "C", "text": "복잡도 정리"}, {"id": "D", "text": "재귀 정리"}]', 'A', '재귀 알고리즘의 시간 복잡도를 분석할 때는 주로 마스터 정리를 사용합니다.'),
    (881, 4, 1, 125, '최선 복잡도를 알고리즘에서 정의하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최선의 경우에서의 성능"}, {"id": "B", "text": "최악의 경우에서의 성능"}, {"id": "C", "text": "평균적인 경우에서의 성능"}, {"id": "D", "text": "입력 크기에 따른 성능"}]', '["A", "C"]', '최선 복잡도는 최선의 경우와 평균적인 경우에서의 성능을 정의합니다.'),
    (882, 4, 1, 126, '공간 복잡도란 무엇인가요?', 'SHORT_ANSWER', NULL, '알고리즘이 실행되는 동안 사용되는 메모리 공간의 양', ''),
    (883, 4, 1, 127, '다음 중 시간 복잡도가 O(nlogn)인 정렬 알고리즘은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "머지 정렬"}, {"id": "B", "text": "선택 정렬"}, {"id": "C", "text": "버블 정렬"}, {"id": "D", "text": "삽입 정렬"}]', 'A', '머지 정렬은 분할 정복 방식을 사용하여 O(nlogn)의 시간 복잡도를 가지는 알고리즘입니다.'),
    (884, 4, 1, 128, '안정 정렬의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동일한 키의 요소 순서 유지"}, {"id": "B", "text": "최악의 경우 O(n^2)"}, {"id": "C", "text": "힙 자료구조 사용"}, {"id": "D", "text": "비교 기반이 아님"}]', 'A', '안정 정렬은 동일한 키를 가진 요소의 상대적 순서를 유지하는 정렬 방식입니다.'),
    (885, 4, 1, 129, '비교 기반 정렬 알고리즘에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "머지 정렬"}, {"id": "B", "text": "선택 정렬"}, {"id": "C", "text": "계수 정렬"}, {"id": "D", "text": "힙 정렬"}]', 'C', '계수 정렬은 비비교 기반 정렬 알고리즘입니다.'),
    (886, 4, 1, 130, '다음 중 불안정 정렬 알고리즘은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "힙 정렬"}, {"id": "B", "text": "머지 정렬"}, {"id": "C", "text": "버블 정렬"}, {"id": "D", "text": "선택 정렬"}]', '["A", "D"]', '힙 정렬과 선택 정렬은 모두 불안정 정렬 알고리즘입니다.'),
    (887, 4, 1, 131, '머지 정렬의 평균 시간 복잡도는?', 'SHORT_ANSWER', NULL, 'O(nlogn)', '머지 정렬의 평균 시간 복잡도는 O(nlogn)입니다.'),
    (888, 4, 1, 132, '스택의 기본 구조는 어떤 방식인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LIFO"}, {"id": "B", "text": "FIFO"}, {"id": "C", "text": "이중 연결 리스트"}, {"id": "D", "text": "해시 테이블"}]', 'A', '스택은 Last In First Out(LIFO) 방식으로 작동합니다.'),
    (889, 4, 1, 133, '링크드 리스트의 특징으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동적 메모리 할당이 가능하다"}, {"id": "B", "text": "노드가 이전 노드와 다음 노드에 대한 포인터를 가진다"}, {"id": "C", "text": "배열과 같은 연속적인 메모리 공간을 요구한다"}, {"id": "D", "text": "삽입과 삭제가 용이하다"}]', 'C', '링크드 리스트는 연속적인 메모리 공간을 필요로 하지 않고 동적으로 메모리를 사용합니다.'),
    (890, 4, 1, 134, 'peek 메소드는 어떤 기능을 수행하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택의 최상단 값을 제거한다"}, {"id": "B", "text": "스택의 최상단 값을 반환한다"}, {"id": "C", "text": "스택을 초기화한다"}, {"id": "D", "text": "스택의 길이를 반환한다"}]', 'B', 'peek 메소드는 스택의 최상단 값을 제거하지 않고 반환하는 기능을 수행합니다.'),
    (891, 4, 1, 135, '다음 중 스택의 주요 연산이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "push"}, {"id": "B", "text": "pop"}, {"id": "C", "text": "enqueue"}, {"id": "D", "text": "peek"}]', '["C"]', 'enqueue는 큐의 주요 연산이며, 스택에서는 사용되지 않습니다.'),
    (892, 4, 1, 136, 'FIFO의 의미는 무엇인가?', 'SHORT_ANSWER', NULL, 'First In First Out', 'FIFO는 ''First In First Out''의 약자로, 가장 먼저 들어온 데이터가 가장 먼저 나가도록 하는 구조를 의미합니다.'),
    (893, 4, 1, 137, 'Big O 표기법에서 O(n)은 무엇을 의미하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기 n에 따라 실행 시간이 선형적으로 증가한다."}, {"id": "B", "text": "입력 크기 n에 관계없이 일정한 시간이다."}, {"id": "C", "text": "입력 크기 n의 제곱에 비례한다."}, {"id": "D", "text": "입력 크기가 증가할수록 실행 시간이 감소한다."}]', 'A', 'O(n)은 알고리즘 실행 시간이 입력 크기 n에 비례하여 선형적으로 증가함을 나타냅니다.'),
    (894, 4, 1, 138, '재귀 알고리즘의 시간 복잡도를 분석할 때 사용하는 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그리디 알고리즘"}, {"id": "B", "text": "점근적 분석"}, {"id": "C", "text": "동적 프로그래밍"}, {"id": "D", "text": "브루트포스"}]', 'B', '재귀 알고리즘의 시간 복잡도를 분석할 때는 점근적 분석이 일반적으로 사용됩니다.'),
    (895, 4, 1, 139, 'NP 문제의 특성으로 알맞은 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항식 시간 내에 해결할 수 있다."}, {"id": "B", "text": "해답이 주어졌을 때, 검증이 다항식 시간 내에 가능하다."}, {"id": "C", "text": "모든 문제는 해결책이 존재한다."}, {"id": "D", "text": "해결책이 항상 유일하다."}]', 'B', 'NP 문제는 해답이 주어졌을 때 그 해답이 올바른지 검증하는 것이 다항식 시간 내에 가능하다는 특성을 가집니다.'),
    (896, 4, 1, 140, '최악의 경우 시간 복잡도를 고려할 때, 다음 중 어떤 표현이 일반적으로 사용되나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "O(n)"}, {"id": "B", "text": "O(1)"}, {"id": "C", "text": "O(n^2)"}, {"id": "D", "text": "O(log n)"}]', '["A", "C"]', '최악의 경우 시간 복잡도를 나타내기 위해 O(n)과 O(n^2)와 같은 표현들이 사용됩니다.'),
    (897, 4, 1, 141, '시간 복잡도의 최선, 최악 분석에서 중요한 역할을 하는 용어는 무엇인가요?', 'SHORT_ANSWER', NULL, '점근적 분석', ''),
    (898, 4, 1, 142, '큐의 데이터 처리 방식은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "FIFO"}, {"id": "B", "text": "LIFO"}, {"id": "C", "text": "FILO"}, {"id": "D", "text": "Random Access"}]', 'A', '큐는 FIFO(First In First Out) 방식으로 요소가 처리됩니다.'),
    (899, 4, 1, 143, 'ArrayList의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정 크기"}, {"id": "B", "text": "동적 크기 조정"}, {"id": "C", "text": "선형 검색만 가능"}, {"id": "D", "text": "저장소가 제한적"}]', 'B', 'ArrayList는 동적 배열로, 필요에 따라 크기가 자동으로 조정될 수 있습니다.'),
    (900, 4, 1, 144, '다음 중 덱(Deque)의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "양쪽 끝에서 삽입/삭제 가능"}, {"id": "B", "text": "FIFO 방식만 지원"}, {"id": "C", "text": "LIFO 방식 지원"}, {"id": "D", "text": "스택과 큐의 특성을 모두 가짐"}]', 'B', '덱은 FIFO와 LIFO 모두 지원하며, 양쪽 끝에서 삽입 및 삭제가 가능합니다.'),
    (901, 4, 1, 145, '선형 자료구조에서 push 연산을 사용할 수 있는 자료구조는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "원형 큐"}, {"id": "D", "text": "배열"}]', '["A", "C"]', 'push 연산은 일반적으로 스택과 원형 큐에서 요소를 추가할 때 사용됩니다.'),
    (902, 4, 1, 146, 'FIFO의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, 'First In First Out', 'FIFO는 먼저 들어온 데이터가 먼저 나가도록 하는 처리 방식을 의미합니다.'),
    (903, 4, 1, 147, '시간 복잡도는 무엇을 측정하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "알고리즘이 수행하는 연산의 수"}, {"id": "B", "text": "메모리 사용량"}, {"id": "C", "text": "입력 데이터의 양"}, {"id": "D", "text": "프로그램의 실행 시간"}]', 'A', '시간 복잡도는 알고리즘이 수행하는 기본 연산의 수를 측정합니다.'),
    (904, 4, 1, 148, 'O(n²) 시간 복잡도를 가지는 알고리즘의 일반적인 예는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "버블 정렬"}, {"id": "B", "text": "이진 탐색"}, {"id": "C", "text": "퀵 정렬"}, {"id": "D", "text": "선형 탐색"}]', 'A', '버블 정렬은 O(n²) 시간 복잡도를 가지며, 두 개의 반복문을 사용하여 정렬합니다.'),
    (905, 4, 1, 149, '다음 중 NP 문제에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다항식 시간 내에 해결할 수 있는 문제"}, {"id": "B", "text": "비결정론적 알고리즘으로 해결할 수 있는 문제"}, {"id": "C", "text": "모든 경우의 수를 대입하여 해결해야 하는 문제"}, {"id": "D", "text": "항상 최적해를 보장하는 문제"}]', 'B', 'NP 문제는 비결정론적 튜링 기계로 해결할 수 있는 문제군을 의미합니다.'),
    (906, 4, 1, 150, '다음 중 시간 복잡도가 O(1)인 알고리즘의 예시를 모두 선택하십시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "배열의 첫 번째 요소 접근"}, {"id": "B", "text": "배열 정렬"}, {"id": "C", "text": "변수의 값을 설정"}, {"id": "D", "text": "최대값 찾기"}]', '["A", "C"]', '배열의 첫 번째 요소에 접근하거나 변수의 값을 설정하는 것은 O(1) 시간 복잡도를 가집니다.'),
    (907, 4, 1, 151, '최악의 경우 시간 복잡도를 나타내는 표기법은 무엇인가?', 'SHORT_ANSWER', NULL, '빅오 표기법', '최악의 경우 시간 복잡도를 나타내는 표기법은 ''빅오 표기법''입니다.'),
    (908, 4, 1, 152, '머지 정렬의 시간 복잡도는 무엇인가?', 'SHORT_ANSWER', NULL, 'O(n log n)', '머지 정렬은 분할 정복 전략을 사용하여 O(n log n)의 시간 복잡도를 가집니다.'),
    (909, 4, 1, 153, '다음 중 안정 정렬에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "머지 정렬"}, {"id": "B", "text": "삽입 정렬"}, {"id": "C", "text": "버블 정렬"}, {"id": "D", "text": "기수 정렬"}]', 'D', '기수 정렬은 불안정 정렬로, 동일한 키 값을 가진 요소들의 상대적인 순서를 유지하지 않습니다.'),
    (910, 4, 1, 154, '버블 정렬과 삽입 정렬의 공통점으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "O(n log n) 시간 복잡도를 가짐"}, {"id": "B", "text": "단순하고 쉽게 구현 가능함"}, {"id": "C", "text": "항상 평균보다 나은 성능을 보임"}, {"id": "D", "text": "모두 안정 정렬임"}]', 'B', '버블 정렬과 삽입 정렬은 모두 구현이 간단하고 직관적입니다.'),
    (911, 4, 1, 155, '정렬 알고리즘의 최악의 경우 시간 복잡도를 나타내는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "O(n^2)"}, {"id": "B", "text": "O(n log n)"}, {"id": "C", "text": "O(n)"}, {"id": "D", "text": "O(log n)"}]', '["A", "B"]', '정렬 알고리즘의 최악의 경우 시간 복잡도는 O(n^2) 또는 O(n log n)일 수 있습니다.'),
    (912, 4, 1, 156, '우선순위 큐에서 삭제되는 요소의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "우선순위가 가장 높은 요소"}, {"id": "B", "text": "가장 먼저 삽입된 요소"}, {"id": "C", "text": "가장 마지막에 삽입된 요소"}, {"id": "D", "text": "무작위 요소"}]', 'A', '우선순위 큐는 각 요소가 우선순위를 가지며, 우선순위가 높은 요소가 먼저 삭제됩니다.'),
    (913, 4, 1, 157, '이중 연결 리스트의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 삽입과 삭제"}, {"id": "B", "text": "데이터 중복 방지"}, {"id": "C", "text": "메모리 사용 최소화"}, {"id": "D", "text": "정렬된 데이터를 보장"}]', 'A', '이중 연결 리스트는 각 노드가 앞뒤 노드를 참조하여 효율적인 삽입과 삭제를 가능하게 합니다.'),
    (914, 4, 1, 158, 'ArrayList의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정 크기 배열"}, {"id": "B", "text": "동적 크기 조절"}, {"id": "C", "text": "LIFO 구조"}, {"id": "D", "text": "FIFO 구조"}]', 'B', 'ArrayList는 동적으로 크기가 조절되는 배열로, 데이터의 추가 및 삭제 시 효율성을 제공합니다.'),
    (915, 4, 1, 159, '큐(Queue)와 스택(Stack)의 작동 원리는 각각 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "큐는 LIFO 구조"}, {"id": "B", "text": "스택은 FIFO 구조"}, {"id": "C", "text": "큐는 FIFO 구조"}, {"id": "D", "text": "스택은 LIFO 구조"}]', '["C", "D"]', '큐는 FIFO(First In First Out) 구조를, 스택은 LIFO(Last In First Out) 구조를 가집니다.'),
    (916, 4, 1, 160, 'peek 연산의 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '최상위 또는 앞쪽 요소를 확인한다.', 'peek 연산은 데이터 구조에서 최상위 또는 앞쪽 요소를 확인하지만 삭제하지 않습니다.'),
    (917, 4, 1, 161, '스택의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LIFO 구조를 가진다."}, {"id": "B", "text": "FIFO 구조를 가진다."}, {"id": "C", "text": "양쪽 끝에서 추가/제거 가능하다."}, {"id": "D", "text": "동적 크기를 가진다."}]', 'A', '스택은 LIFO(Last In First Out) 구조로, 마지막에 추가된 데이터가 가장 먼저 제거되는 특징이 있습니다.'),
    (918, 4, 1, 162, 'ArrayList의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정적 크기를 가진다."}, {"id": "B", "text": "크기를 동적으로 조정할 수 있다."}, {"id": "C", "text": "데이터 접근 속도가 느리다."}, {"id": "D", "text": "추가/삭제가 느리다."}]', 'B', 'ArrayList는 동적으로 크기를 조정할 수 있어, 필요한 만큼의 용량을 효율적으로 사용할 수 있습니다.'),
    (919, 4, 1, 163, '원형 큐의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정된 크기의 배열을 사용한다."}, {"id": "B", "text": "메모리 공간을 효율적으로 사용할 수 있다."}, {"id": "C", "text": "항상 비어있을 수 있다."}, {"id": "D", "text": "데이터 접근 속도가 빠르다."}]', 'B', '원형 큐는 고정된 크기의 배열을 사용해 메모리 공간을 효율적으로 사용할 수 있습니다.'),
    (920, 4, 1, 164, '스택에서 데이터를 추가하는 메서드는 무엇인가?', 'SHORT_ANSWER', NULL, 'push', '스택에서 데이터를 추가하는 메서드는 ''push''입니다.'),
    (921, 4, 1, 165, '스택과 큐의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "스택은 LIFO 구조이다."}, {"id": "B", "text": "큐는 FIFO 구조이다."}, {"id": "C", "text": "스택은 양쪽에서 접근 가능하다."}, {"id": "D", "text": "큐는 한쪽에서만 접근 가능하다."}]', '["A", "B"]', '스택은 LIFO(Last In First Out) 구조이고, 큐는 FIFO(First In First Out) 구조로 이 두 자료구조는 접근 방식이 다릅니다.'),
    (922, 4, 1, 166, '벨만-포드 알고리즘은 어떤 유형의 문제를 해결하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최단 경로 문제"}, {"id": "B", "text": "최대 유량 문제"}, {"id": "C", "text": "정렬 문제"}, {"id": "D", "text": "순차 탐색 문제"}]', 'A', '벨만-포드 알고리즘은 가중치가 있는 그래프에서 최단 경로를 찾는 데 사용된다.'),
    (923, 4, 1, 167, '이진 탐색의 시간 복잡도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "O(n)"}, {"id": "B", "text": "O(log n)"}, {"id": "C", "text": "O(n log n)"}, {"id": "D", "text": "O(1)"}]', 'B', '이진 탐색의 시간 복잡도는 O(log n)이다.'),
    (924, 4, 1, 168, '다음 중 BFS의 특징이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "큐를 사용한다"}, {"id": "B", "text": "모든 정점을 먼저 탐색한다"}, {"id": "C", "text": "비선형 자료 구조를 사용한다"}, {"id": "D", "text": "최단 경로를 보장한다"}]', 'C', 'BFS는 주로 그래프와 트리와 같은 비선형 자료 구조에서 사용되며, 큐를 사용해 탐색한다.'),
    (925, 4, 1, 169, '다익스트라 알고리즘과 벨만-포드 알고리즘의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "벨만-포드는 음수 가중치를 처리할 수 있다."}, {"id": "B", "text": "다익스트라는 모든 경로를 따져야 한다."}, {"id": "C", "text": "두 알고리즘 모두 최단 경로를 찾는다."}, {"id": "D", "text": "다익스트라는 BFS와 연관이 있다."}]', '["A", "C"]', '벨만-포드는 음수 가중치를 처리할 수 있는 반면, 다익스트라는 일반적으로 음수 가중치에 적용할 수 없다.'),
    (926, 4, 1, 170, 'A* 알고리즘에서 사용하는 평가는 무엇인가?', 'SHORT_ANSWER', NULL, '휴리스틱 함수', 'A* 알고리즘은 목적지까지의 예상 비용을 계산하는 휴리스틱 함수를 사용한다.'),
    (927, 4, 1, 171, '밀집 그래프의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "많은 간선을 가진 그래프이다."}, {"id": "B", "text": "모든 노드가 연결되어 있다."}, {"id": "C", "text": "노드의 수가 적다."}, {"id": "D", "text": "간선의 수가 적다."}]', 'A', '밀집 그래프는 간선의 수가 노드의 수에 비해 상대적으로 많은 그래프를 의미합니다.'),
    (928, 4, 1, 172, '이분 그래프의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 개의 집합으로 나눌 수 있다."}, {"id": "B", "text": "모든 간선이 무방향이다."}, {"id": "C", "text": "자기 자신과 연결되는 간선이 있다."}, {"id": "D", "text": "한 쪽 집합의 모든 노드가 다른 쪽 집합과 연결되어 있다."}]', 'A', '이분 그래프는 두 개의 노드 집합으로 나눌 수 있는 그래프로, 각 간선이 서로 다른 집합의 노드만 연결됩니다.'),
    (929, 4, 1, 173, '차수와 진입 차수의 차이는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "차수는 노드의 간선 수, 진입 차수는 들어오는 간선 수다."}, {"id": "B", "text": "둘 다 노드의 연결 상태를 의미한다."}, {"id": "C", "text": "진입 차수는 노드의 간선 수, 차수는 들어오는 간선 수다."}, {"id": "D", "text": "차수는 간선의 수, 진입 차수는 노드의 수다."}]', 'A', '차수는 특정 노드에 연결된 간선의 수를 의미하고, 진입 차수는 특정 노드로 들어오는 간선의 수를 의미합니다.'),
    (930, 4, 1, 174, '그래프의 간선 리스트 표현 방식에서 무엇을 포함하나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "각 간선의 시작 노드와 끝 노드"}, {"id": "B", "text": "노드의 차수 정보"}, {"id": "C", "text": "간선의 가중치 정보"}, {"id": "D", "text": "노드의 연결 상태"}]', '["A", "C"]', '간선 리스트는 각 간선의 시작 노드와 끝 노드, 그리고 경우에 따라 간선의 가중치 정보를 포함합니다.'),
    (931, 4, 1, 175, '무방향 그래프란 무엇인가요?', 'SHORT_ANSWER', NULL, '간선이 방향성이 없는 그래프이다.', '무방향 그래프는 노드 사이의 간선이 양방향으로 연결되어 있어, 한 쪽에서 다른 쪽으로의 이동이 자유로운 구조를 갖습니다.'),
    (932, 4, 1, 176, 'O(1) 시간 복잡도의 알고리즘은 어떤 특징을 가지고 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 크기와 관계없이 일정한 시간을 소요한다."}, {"id": "B", "text": "입력 크기가 커질수록 시간이 증가한다."}, {"id": "C", "text": "입력 크기와 비례하여 시간이 증가한다."}, {"id": "D", "text": "로그arithmic 시간 복잡도를 가진다."}]', 'A', 'O(1)은 입력 크기와 관계없이 항상 일정한 시간을 소요하는 알고리즘을 의미합니다.'),
    (933, 4, 1, 177, 'O(n²) 복잡도를 가진 알고리즘의 예는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "퀵 정렬"}, {"id": "B", "text": "버블 정렬"}, {"id": "C", "text": "이진 탐색"}, {"id": "D", "text": "합병 정렬"}]', 'B', '버블 정렬은 O(n²) 시간 복잡도를 가지며, 이는 두 개의 중첩 루프가 사용되기 때문입니다.'),
    (934, 4, 1, 178, '다음 중 O(n log n) 복잡도를 가진 알고리즘은 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "버블 정렬"}, {"id": "B", "text": "합병 정렬"}, {"id": "C", "text": "선택 정렬"}, {"id": "D", "text": "탐욕 알고리즘"}]', 'B', '합병 정렬은 O(n log n) 시간 복잡도를 가진 알고리즘으로, 효율적인 정렬 방법입니다.'),
    (935, 4, 1, 179, '다음 중 시간 복잡도가 O(n)인 알고리즘은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "단순 탐색"}, {"id": "B", "text": "버블 정렬"}, {"id": "C", "text": "이진 탐색"}, {"id": "D", "text": "해시 테이블 검색"}]', '["A", "D"]', '단순 탐색과 해시 테이블 검색은 O(n) 시간 복잡도를 가진 알고리즘입니다.'),
    (936, 4, 1, 180, 'Big O 표기법에서 O(2^n)의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '지수 시간 복잡도를 의미하며, 입력 크기가 증가함에 따라 실행 시간이 기하급수적으로 증가함을 나타냅니다.', 'O(2^n)은 입력 크기 n에 대해 실행 시간이 2의 n제곱으로 증가하는 지수 시간 복잡도를 의미합니다.'),
    (937, 4, 1, 181, '완전 그래프의 정의는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점이 서로 연결되어 있는 그래프"}, {"id": "B", "text": "사이클이 없는 방향 그래프"}, {"id": "C", "text": "정점의 수가 간선의 수보다 많은 그래프"}, {"id": "D", "text": "정점이 두 개의 집합으로 나뉘는 그래프"}]', 'A', '완전 그래프는 모든 정점이 서로 연결되어 있는 그래프를 의미합니다.'),
    (938, 4, 1, 182, 'DAG의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점이 연결되어 있다"}, {"id": "B", "text": "사이클이 존재할 수 있다"}, {"id": "C", "text": "방향성이 있으며 사이클이 없다"}, {"id": "D", "text": "정점이 두 집합으로 나뉜다"}]', 'C', 'DAG는 방향 그래프이면서 사이클이 없는 그래프의 특성을 지닙니다.'),
    (939, 4, 1, 183, '다음 중 희소 그래프의 정의에 해당하는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점에 비해 간선의 수가 적은 그래프"}, {"id": "B", "text": "모든 정점이 서로 연결되어 있는 그래프"}, {"id": "C", "text": "모든 정점 사이에 간선이 존재하는 그래프"}, {"id": "D", "text": "사이클이 없는 그래프"}]', 'A', '희소 그래프는 정점에 비해 간선의 수가 적은 그래프를 말합니다.'),
    (940, 4, 1, 184, '다음 중 그래프의 종류가 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이분 그래프"}, {"id": "B", "text": "순환 그래프"}, {"id": "C", "text": "무방향 그래프"}, {"id": "D", "text": "방향 그래프"}]', '["B"]', '순환 그래프는 일반적인 그래프의 종류가 아니며, 그래프는 이분, 무방향, 방향 그래프로 나눌 수 있습니다.'),
    (941, 4, 1, 185, '그래프에서 진입 차수란 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, '특정 정점으로 들어오는 간선의 수', '진입 차수는 특정 정점으로 들어오는 간선의 수를 의미합니다.'),
    (942, 4, 1, 186, '간선 리스트로 그래프를 표현할 때, 각 간선은 무엇으로 구성되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점 쌍"}, {"id": "B", "text": "정점의 값"}, {"id": "C", "text": "간선의 가중치"}, {"id": "D", "text": "정점의 차수"}]', 'A', '간선 리스트는 그래프의 간선을 정점의 쌍으로 나타내어 표현합니다.'),
    (943, 4, 1, 187, 'DAG의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사이클이 존재한다"}, {"id": "B", "text": "모든 간선은 방향이 있다"}, {"id": "C", "text": "정점 수가 항상 짝수이다"}, {"id": "D", "text": "정점은 연결 필수"}]', 'B', 'DAG는 방향성이 있는 그래프이며 사이클이 존재하지 않는 것이 주요 특징입니다.'),
    (944, 4, 1, 188, '밀집 그래프와 희소 그래프의 주요 차이는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점의 수에 따라 결정된다"}, {"id": "B", "text": "간선의 수에 따라 결정된다"}, {"id": "C", "text": "모든 정점이 연결되어야 한다"}, {"id": "D", "text": "방향성이 필요하다"}]', 'B', '밀집 그래프는 많은 간선이 존재하고, 희소 그래프는 상대적으로 적은 간선으로 구성됩니다.'),
    (945, 4, 1, 189, '사이클 검출을 통해 어떤 그래프의 특성을 파악할 수 있는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DAG 여부"}, {"id": "B", "text": "정점의 차수"}, {"id": "C", "text": "그래프의 연결성"}, {"id": "D", "text": "간선의 가중치"}]', '["A", "C"]', '사이클 검출을 통해 그래프가 DAG인지 여부와 연결성을 판단할 수 있습니다.'),
    (946, 4, 1, 190, '그래프의 진출 차수란 무엇인가?', 'SHORT_ANSWER', NULL, '특정 정점에서 나가는 간선의 수', '진출 차수는 정점에서 나가는 간선의 수를 의미합니다.'),
    (947, 4, 1, 191, '원형 큐의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정 크기의 배열을 이용하여 데이터를 순환적으로 저장한다."}, {"id": "B", "text": "데이터를 LIFO 방식으로 저장한다."}, {"id": "C", "text": "각 요소가 이전과 다음 요소에 대한 참조를 가진다."}, {"id": "D", "text": "동적으로 크기를 변경할 수 있다."}]', 'A', '원형 큐는 고정 크기의 배열을 사용하여 데이터를 순환적으로 저장하는 자료구조입니다.'),
    (948, 4, 1, 192, '스택에서 peek 연산의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 최근에 삽입된 데이터를 제거한다."}, {"id": "B", "text": "가장 최근에 삽입된 데이터를 확인한다."}, {"id": "C", "text": "모든 데이터를 출력한다."}, {"id": "D", "text": "데이터를 오름차순으로 정렬한다."}]', 'B', 'peek 연산은 스택에서 가장 최근에 삽입된 데이터를 확인하는 역할을 합니다.'),
    (949, 4, 1, 193, '다음 중 우선순위 큐에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 FIFO 방식으로 처리한다."}, {"id": "B", "text": "각 요소에 우선순위를 부여하여 처리 순서를 결정한다."}, {"id": "C", "text": "모든 요소가 같은 우선순위를 가진다."}, {"id": "D", "text": "연결 리스트만 사용할 수 있다."}]', 'B', '우선순위 큐는 각 요소에 우선순위를 부여하여 높은 우선순위를 가진 요소가 먼저 처리되는 구조입니다.'),
    (950, 4, 1, 194, '스택의 주요 연산으로 pop과 peek 외에 어떤 것이 있을까요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "push"}, {"id": "B", "text": "enqueue"}, {"id": "C", "text": "dequeue"}, {"id": "D", "text": "size"}]', '["A", "D"]', '스택의 주요 연산으로는 push(데이터 추가)와 size(스택의 크기 확인)가 있습니다.'),
    (951, 4, 1, 195, '동적 배열의 가장 큰 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '크기가 동적으로 변경될 수 있다.', '동적 배열은 필요에 따라 크기를 조정할 수 있어 메모리 사용의 유연성이 큰 장점입니다.'),
    (952, 4, 1, 196, '플로이드-워셜 알고리즘의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점 쌍 간의 최단 경로 찾기"}, {"id": "B", "text": "가장 긴 경로 찾기"}, {"id": "C", "text": "최대 유량 계산"}, {"id": "D", "text": "위상 정렬 수행"}]', 'A', '플로이드-워셜 알고리즘은 모든 정점 간의 최단 경로를 찾기 위한 알고리즘입니다.'),
    (953, 4, 1, 197, '다익스트라 알고리즘은 어떤 조건에서 사용할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "양의 가중치 그래프"}, {"id": "B", "text": "음의 가중치 그래프"}, {"id": "C", "text": "비가중치 그래프"}, {"id": "D", "text": "순환 그래프"}]', 'A', '다익스트라 알고리즘은 음의 가중치가 없는 그래프에서 최단 경로를 찾는 알고리즘입니다.'),
    (954, 4, 1, 198, '너비 우선 탐색(BFS)과 깊이 우선 탐색(DFS)의 주요 차이점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "BFS는 스택을 사용하고, DFS는 큐를 사용한다."}, {"id": "B", "text": "BFS는 큐를 사용하고, DFS는 스택을 사용한다."}, {"id": "C", "text": "두 방식은 동일하다."}, {"id": "D", "text": "BFS는 그래프를 순회하지 않는다."}]', 'B', '너비 우선 탐색(BFS)은 큐를 사용하여, 깊이 우선 탐색(DFS)은 스택을 사용하여 탐색을 진행합니다.'),
    (955, 4, 1, 199, '다음 중 경로 탐색 알고리즘의 예시는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "다익스트라"}, {"id": "B", "text": "플로이드-워셜"}, {"id": "C", "text": "미로 탐색"}, {"id": "D", "text": "이진 탐색"}]', '["A", "B", "C"]', '다익스트라, 플로이드-워셜, 미로 탐색은 모두 경로 탐색 알고리즘입니다.'),
    (956, 4, 1, 200, '위상 정렬은 어떤 종류의 그래프에서 주로 사용되나요?', 'SHORT_ANSWER', NULL, '방향 그래프', '위상 정렬은 방향 그래프에서 선행 관계를 유지하며 정점을 나열하기 위한 방법입니다.'),
    (957, 4, 1, 201, 'LIFO는 어떤 자료구조의 특징을 설명하는 용어인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "링크드 리스트"}, {"id": "D", "text": "우선순위 큐"}]', 'A', 'LIFO(Last In First Out)는 스택의 동작 원리로, 나중에 들어온 데이터가 먼저 나가는 구조입니다.'),
    (958, 4, 1, 202, '덱(Deque)에서 지원하지 않는 연산은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "양쪽 끝에서 삽입"}, {"id": "B", "text": "양쪽 끝에서 삭제"}, {"id": "C", "text": "특정 인덱스에서 삭제"}, {"id": "D", "text": "FIFO 방식 처리"}]', 'C', '덱은 양쪽 끝에서 삽입 및 삭제를 지원하지만, 특정 인덱스에서 삭제하는 기능은 기본적으로 제공하지 않습니다.'),
    (959, 4, 1, 203, '원형 큐의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 메모리 사용"}, {"id": "B", "text": "노드 탐색 속도"}, {"id": "C", "text": "데이터 중복 방지"}, {"id": "D", "text": "단방향 탐색"}]', 'A', '원형 큐는 배열의 끝이 시작점과 연결되어 있어 메모리를 효율적으로 사용할 수 있습니다.'),
    (960, 4, 1, 204, '이중 연결 리스트에서 각 노드는 몇 개의 포인터를 가지는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["B"]', '이중 연결 리스트에서 각 노드는 이전 노드와 다음 노드를 가리키는 2개의 포인터를 가집니다.'),
    (961, 4, 1, 205, 'peek 연산의 주 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '스택이나 큐에서 맨 위 또는 맨 앞의 데이터를 확인하는 것', 'peek 연산은 스택이나 큐에서 데이터를 제거하지 않고도 가장 위나 앞에 있는 데이터를 확인할 수 있게 해줍니다.'),
    (962, 4, 1, 206, '너비 우선 탐색(BFS)에서 사용되는 자료구조는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "링크드 리스트"}, {"id": "D", "text": "배열"}]', 'B', '너비 우선 탐색(BFS)은 큐를 사용하여 탐색을 진행합니다.'),
    (963, 4, 1, 207, '벨만-포드 알고리즘의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최단 경로 찾기"}, {"id": "B", "text": "정렬"}, {"id": "C", "text": "탐색"}, {"id": "D", "text": "조합 찾기"}]', 'A', '벨만-포드 알고리즘은 가중치가 있는 그래프에서 최단 경로를 찾는 데 사용됩니다.'),
    (964, 4, 1, 208, '다음 중 DFS에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "큐를 사용하여 탐색한다."}, {"id": "B", "text": "스택을 사용하여 탐색한다."}, {"id": "C", "text": "최단 경로를 보장한다."}, {"id": "D", "text": "모든 경로를 탐색하지 않는다."}]', 'B', 'DFS(깊이 우선 탐색)는 스택을 사용하여 탐색하는 알고리즘입니다.'),
    (965, 4, 1, 209, '어떤 알고리즘이 위상 정렬을 사용하여 해결할 수 있는 문제에 해당하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "과목 수강 순서"}, {"id": "B", "text": "최단 경로 문제"}, {"id": "C", "text": "작업 스케줄링"}, {"id": "D", "text": "정렬 문제"}]', '["A", "C"]', '위상 정렬은 DAG에서 노드의 순서를 결정하는 데 유용하며, 과목 수강 순서와 작업 스케줄링 문제에 적용됩니다.'),
    (966, 4, 1, 210, '순차 탐색의 시간 복잡도는 어떻게 되는가?', 'SHORT_ANSWER', NULL, 'O(n)', '순차 탐색은 최악의 경우 모든 요소를 검색해야 하므로 시간 복잡도는 O(n)입니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 알고리즘과 자료구조 > DP와 그리디 (188문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (967, 4, 2, 1, '다이나믹 프로그래밍에서 점화식의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문제를 단계별로 나누는 규칙 제공"}, {"id": "B", "text": "입출력을 위한 함수 정의"}, {"id": "C", "text": "메모리 관리를 최적화하는 방법"}, {"id": "D", "text": "재귀 호출을 막는 알고리즘"}]', 'A', '점화식은 문제를 단계별로 나누어 해결하는 규칙을 제공하여 다이나믹 프로그래밍이 가능하게 합니다.'),
    (968, 4, 2, 2, '최장 공통 부분수열(LCS) 문제에서 DP를 사용하는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 부분 수열을 직접 계산하기 위해"}, {"id": "B", "text": "중복 부분 문제를 피하기 위해"}, {"id": "C", "text": "문자열의 길이를 증가시키기 위해"}, {"id": "D", "text": "단순한 문자 비교를 위해"}]', 'B', 'LCS 문제에서 DP를 사용하면 중복 되는 부분 문제를 피함으로써 효율적으로 문제를 해결할 수 있습니다.'),
    (969, 4, 2, 3, '계단 오르기 문제에서 메모이제이션 기법은 무엇을 위한 것인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "계단을 쉽게 오르기 위해"}, {"id": "B", "text": "이미 계산된 결과를 저장하여 중복 계산을 피하기 위해"}, {"id": "C", "text": "계단의 개수를 줄이기 위해"}, {"id": "D", "text": "재귀 호출을 증가시키기 위해"}]', 'B', '메모이제이션은 이미 계산된 결과를 저장하여 중복 계산을 피하기 위해 사용됩니다.'),
    (970, 4, 2, 4, '다이나믹 프로그래밍의 핵심 개념 중 하나로, 중복되는 문제를 해결하는 기법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "점화식"}, {"id": "B", "text": "메모이제이션"}, {"id": "C", "text": "탑다운 접근법"}, {"id": "D", "text": "그리디 알고리즘"}]', '["A", "B", "C"]', '점화식과 메모이제이션, 그리고 탑다운 접근법은 모두 중복되는 문제를 효율적으로 해결하기 위한 다이나믹 프로그래밍의 핵심 개념입니다.'),
    (971, 4, 2, 5, '피보나치 수열을 다이나믹 프로그래밍으로 해결할 때 얻을 수 있는 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '중복 계산을 피하고 시간 복잡도를 줄일 수 있다.', '피보나치 수열을 DP로 해결하면 중복 계산을 피하고 시간 복잡도를 줄일 수 있습니다.'),
    (972, 4, 2, 6, '소인수분해란 무엇인가?', 'SHORT_ANSWER', NULL, '모든 정수를 소수의 곱으로 표현하는 방법', '소인수분해는 주어진 정수를 소수들의 곱으로 표현하는 것을 의미합니다.'),
    (973, 4, 2, 7, '유클리드 호제법은 무엇을 구하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최대공약수(GCD)"}, {"id": "B", "text": "최소공배수(LCM)"}, {"id": "C", "text": "소수판별"}, {"id": "D", "text": "조합의 수"}]', 'A', '유클리드 호제법은 두 수의 최대공약수(GCD)를 구하는 데 사용됩니다.'),
    (974, 4, 2, 8, '페르마 소정리는 어떤 상황에서 유용한가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모듈로 연산"}, {"id": "B", "text": "소수 판별"}, {"id": "C", "text": "행렬 연산"}, {"id": "D", "text": "조합 계산"}]', 'A', '페르마 소정리는 소수와 관련된 모듈로 연산에서 유용하게 사용됩니다.'),
    (975, 4, 2, 9, '다음 중 파스칼 삼각형에서 4C2의 값을 고르세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "6"}, {"id": "B", "text": "4"}, {"id": "C", "text": "8"}, {"id": "D", "text": "2"}]', '["A"]', '4C2는 파스칼 삼각형에서 4번째 행의 2번째 값을 나타내며, 그 값은 6입니다.'),
    (976, 4, 2, 10, '중국인 나머지 정리는 무엇을 해결하는 데 쓰이는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 동시 방정식"}, {"id": "B", "text": "최대공약수"}, {"id": "C", "text": "소인수 찾기"}, {"id": "D", "text": "확률 계산"}]', 'A', '중국인 나머지 정리는 여러 개의 나머지를 갖는 동시 방정식을 해결할 때 사용됩니다.'),
    (977, 4, 2, 11, '유클리드 호제법은 무엇을 구하기 위한 알고리즘인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최대 공약수(GCD)"}, {"id": "B", "text": "최소 공배수(LCM)"}, {"id": "C", "text": "소수 판별"}, {"id": "D", "text": "모듈러 역원"}]', 'A', '유클리드 호제법은 두 수의 최대 공약수(GCD)를 구하기 위한 효율적인 알고리즘입니다.'),
    (978, 4, 2, 12, '모듈러 연산의 주된 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "나머지를 계산하는 연산"}, {"id": "B", "text": "소수를 찾는 연산"}, {"id": "C", "text": "행렬을 다루는 연산"}, {"id": "D", "text": "조합을 계산하는 연산"}]', 'A', '모듈러 연산은 특정 수로 나눈 나머지를 계산하는 연산입니다.'),
    (979, 4, 2, 13, '중국인 나머지 정리를 적용할 수 있는 조건은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 수가 서로 소일 때"}, {"id": "B", "text": "모든 수가 짝수일 때"}, {"id": "C", "text": "모든 수가 소수일 때"}, {"id": "D", "text": "모든 수가 서로 음수일 때"}]', 'A', '중국인 나머지 정리는 서로 소인 두 수에 대해 적용할 수 있는 정리입니다.'),
    (980, 4, 2, 14, '파스칼 삼각형에서 nCk를 구하는 방법은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "n번째 행에서 k번째 숫자 찾기"}, {"id": "B", "text": "n! / (k! * (n-k)!) 계산"}, {"id": "C", "text": "k를 더한 행과 열의 합 찾기"}, {"id": "D", "text": "소인수분해 후 조합 찾기"}]', '["A", "B"]', '파스칼 삼각형에서 nCk는 n번째 행에서 k번째 숫자를 찾거나, n! / (k! * (n-k)!)를 계산하여 구할 수 있습니다.'),
    (981, 4, 2, 15, '최대 공약수(GCD)의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '두 수의 공통 약수 중에서 가장 큰 수입니다.', '최대 공약수(GCD)는 두 수의 모든 공통 약수 중 가장 큰 값을 의미합니다.'),
    (982, 4, 2, 16, '다이나믹 프로그래밍에서 피보나치 수열을 계산할 때 사용하는 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "탑다운"}, {"id": "B", "text": "브루트포스"}, {"id": "C", "text": "정렬"}, {"id": "D", "text": "구간 합"}]', 'A', '탑다운 방식은 메모이제이션을 활용하여 재귀적으로 문제를 해결하는 방법으로, 피보나치 수열을 효율적으로 계산할 수 있습니다.'),
    (983, 4, 2, 17, '계단 오르기 문제를 다룰 때, 한 번에 몇 칸을 오를 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1칸 또는 2칸"}, {"id": "B", "text": "1칸 또는 3칸"}, {"id": "C", "text": "2칸 또는 3칸"}, {"id": "D", "text": "1칸, 2칸 또는 3칸"}]', 'A', '계단 오르기 문제에서는 한 번에 1칸 또는 2칸을 오를 수 있습니다.'),
    (984, 4, 2, 18, '다음 중 배낭 문제의 정의에 포함되지 않는 요소는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "물건의 무게"}, {"id": "B", "text": "물건의 가치"}, {"id": "C", "text": "물건의 색상"}, {"id": "D", "text": "최대 용량"}]', 'C', '배낭 문제는 물건의 무게와 가치, 그리고 최대 용량을 고려하는 문제이며, 색상은 포함되지 않습니다.'),
    (985, 4, 2, 19, 'LIS 문제에서 찾는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최장 감소 부분 수열"}, {"id": "B", "text": "최장 증가 부분 수열"}, {"id": "C", "text": "최소 증가 부분 수열"}, {"id": "D", "text": "최대 감소 부분 수열"}]', '["B"]', 'LIS(최장 증가 부분 수열) 문제는 주어진 수열에서 가장 긴 증가하는 부분 수열의 길이를 찾는 것입니다.'),
    (986, 4, 2, 20, 'LCS 문제에서 ''LCS''는 무엇의 약자입니까?', 'SHORT_ANSWER', NULL, 'Longest Common Subsequence', 'LCS는 ''Longest Common Subsequence''의 약자로, 두 수열에서 공통적으로 나타나는 가장 긴 부분 수열을 찾는 문제입니다.'),
    (987, 4, 2, 21, '그리디 알고리즘의 기본 원리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 상황에서 최선의 선택을 반복하는 것"}, {"id": "B", "text": "모든 경우의 수를 고려하는 것"}, {"id": "C", "text": "무작위로 선택하는 것"}, {"id": "D", "text": "최대값만 선택하는 것"}]', 'A', '그리디 알고리즘은 현재 상황에서 최적의 선택을 반복적으로 하여 문제를 해결하는 전략입니다.'),
    (988, 4, 2, 22, '허프만 코딩은 주로 무엇을 위해 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 압축"}, {"id": "B", "text": "데이터 암호화"}, {"id": "C", "text": "모델 학습"}, {"id": "D", "text": "데이터 분석"}]', 'A', '허프만 코딩은 데이터 압축을 위해 자주 사용되는 알고리즘입니다.'),
    (989, 4, 2, 23, 'MST를 찾기 위한 크루스칼 알고리즘의 주요 단계는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "간선을 정렬하고 선택하는 것"}, {"id": "B", "text": "노드를 정렬하는 것"}, {"id": "C", "text": "비용을 최소화하는 것"}, {"id": "D", "text": "사이클을 만드는 것"}]', 'A', '크루스칼 알고리즘은 네트워크의 최소 신장 트리를 찾기 위해 간선을 정렬하고 가장 작은 간선을 선택하는 방법입니다.'),
    (990, 4, 2, 24, '그리디 알고리즘의 특징 중 어떤 경우에 전역 최적해를 보장하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "지역 최적해가 전역 최적해가 될 때"}, {"id": "B", "text": "모든 경우의 수를 검토할 때"}, {"id": "C", "text": "문제가 단순할 때"}, {"id": "D", "text": "문제가 그래프 구조일 때"}]', '["A", "C"]', '그리디 알고리즘은 지역 최적해가 전역 최적해가 되는 경우에만 전역 최적해를 찾을 수 있습니다.'),
    (991, 4, 2, 25, '거스름돈 문제에서 그리디 알고리즘이 효과적인 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '화폐 단위가 기준에 맞춰져 있어서 작은 단위부터 최적 선택이 가능하기 때문입니다.', '거스름돈 문제에서는 큰 화폐 단위부터 선택하여 최소 개수의 동전을 만드는 것이 가능하기 때문에 그리디 알고리즘이 효과적입니다.'),
    (992, 4, 2, 26, '최장 증가 부분수열 문제에서 DP 테이블의 각 원소는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최장 증가 부분수열의 길이"}, {"id": "B", "text": "부분 수열의 인덱스"}, {"id": "C", "text": "현재 원소의 값"}, {"id": "D", "text": "동적 프로그래밍의 메모이제이션 여부"}]', 'A', 'DP 테이블의 각 원소는 해당 인덱스까지의 최장 증가 부분수열의 길이를 저장합니다.'),
    (993, 4, 2, 27, '계단 오르기 문제를 풀 때 사용할 수 있는 점화식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "dp[n] = dp[n-1] + dp[n-2]"}, {"id": "B", "text": "dp[n] = dp[n-2] + dp[n-3]"}, {"id": "C", "text": "dp[n] = dp[n-1] * dp[n-2]"}, {"id": "D", "text": "dp[n] = dp[n] - 1"}]', 'A', '계단 오르기 문제에서 n번째 계단에 도달하는 방법은 (n-1)번째 계단에서 오르거나 (n-2)번째 계단에서 한 번에 두 계단을 오르는 경우의 수를 합한 것입니다.'),
    (994, 4, 2, 28, '다음 중 메모이제이션(Memoization)의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중복 계산을 방지한다."}, {"id": "B", "text": "재귀 호출을 사용한다."}, {"id": "C", "text": "DP 테이블을 사용하지 않는다."}, {"id": "D", "text": "문제를 바텀업 방식으로 해결한다."}]', '["A", "B"]', '메모이제이션은 중복 계산을 방지하기 위해 재귀 호출을 사용하여 계산한 결과를 저장하는 방법입니다.'),
    (995, 4, 2, 29, '최장 공통 부분수열을 구할 때 사용하는 알고리즘의 기본 원칙은 무엇인가?', 'SHORT_ANSWER', NULL, '두 문자열의 마지막 문자가 같은지 비교하여, 같으면 이전 부분 수열의 길이에 1을 더하고, 다르면 두 경우의 최댓값을 선택한다.', ''),
    (996, 4, 2, 30, '동전 교환 문제에서 주어진 동전의 값을 활용하여 특정 금액을 만드는 경우의 수를 구하는 데 사용하는 DP 테이블의 기본 구조는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "화폐 단위에 대한 DP 테이블"}, {"id": "B", "text": "목표 금액에 대한 DP 테이블"}, {"id": "C", "text": "주어진 동전의 수에 대한 DP 테이블"}, {"id": "D", "text": "각 동전의 가치를 합산하는 DP 테이블"}]', 'B', '동전 교환 문제에서는 목표 금액을 만들기 위해 각 금액에 대해 가능한 방법의 수를 저장하는 DP 테이블을 사용합니다.'),
    (997, 4, 2, 31, '다이나믹 프로그래밍에서 주로 사용하는 기법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "탑다운 방식"}, {"id": "B", "text": "브루트 포스"}, {"id": "C", "text": "정렬"}, {"id": "D", "text": "그리디 알고리즘"}]', 'A', 'DP는 주로 탑다운 방식과 바텀업 방식으로 구현됩니다.'),
    (998, 4, 2, 32, '최장 증가 부분수열(LIS) 문제에서 요구되는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 긴 연속 부분수열"}, {"id": "B", "text": "가장 긴 증가하는 부분수열"}, {"id": "C", "text": "모든 부분수열"}, {"id": "D", "text": "가장 긴 감소하는 부분수열"}]', 'B', 'LIS는 주어진 수열에서 가장 긴 증가하는 부분수열을 찾는 문제입니다.'),
    (999, 4, 2, 33, '최장 공통 부분수열(LCS)의 정의는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 문자열의 가장 긴 연속 부분수열"}, {"id": "B", "text": "두 문자열의 가장 긴 증가 부분수열"}, {"id": "C", "text": "두 문자열의 가장 긴 공통 부분수열"}, {"id": "D", "text": "두 문자열의 모든 부분수열"}]', 'C', 'LCS는 두 개의 문자열에서 가장 긴 공통 부분수열을 찾는 문제입니다.'),
    (1000, 4, 2, 34, '다이나믹 프로그래밍의 가장 큰 장점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중복 계산을 피할 수 있다."}, {"id": "B", "text": "모든 문제를 해결할 수 있다."}, {"id": "C", "text": "문제를 더 쉽게 이해할 수 있다."}, {"id": "D", "text": "시간 복잡도를 줄일 수 있다."}]', '["A", "D"]', 'DP는 중복 계산을 피함으로써 시간 복잡도를 줄이는 장점이 있습니다.'),
    (1001, 4, 2, 35, '계단 오르기 문제의 DP 테이블은 어떤 값을 저장하나요?', 'SHORT_ANSWER', NULL, '각 계단까지 오르는데 필요한 최댓값', ''),
    (1002, 4, 2, 36, '다이나믹 프로그래밍의 탑다운 방식은 어떤 접근 방식인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "재귀적 방법으로 문제를 해결하는 방식"}, {"id": "B", "text": "반복문을 사용하여 문제를 해결하는 방식"}, {"id": "C", "text": "브루트 포스 방식으로 문제를 해결하는 방식"}, {"id": "D", "text": "랜덤 접근으로 문제를 해결하는 방식"}]', 'A', '탑다운 방식은 재귀적 방법으로 문제를 해결하는 방식입니다.'),
    (1003, 4, 2, 37, '최장 증가 부분수열(LIS) 문제의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 수열의 원소들이 증가하는 순서를 유지해야 한다."}, {"id": "B", "text": "모든 원소를 포함해야 한다."}, {"id": "C", "text": "원소의 순서를 변경할 수 있다."}, {"id": "D", "text": "최대 원소의 수를 구해야 한다."}]', 'A', '최장 증가 부분수열 문제는 부분 수열의 원소들이 증가하는 순서를 유지해야 합니다.'),
    (1004, 4, 2, 38, '다이나믹 프로그래밍에서 메모이제이션의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "결과를 저장하여 중복 계산을 방지하는 것"}, {"id": "B", "text": "임의의 값을 생성하는 것"}, {"id": "C", "text": "입력값을 변형하는 것"}, {"id": "D", "text": "실행 속도를 느리게 하는 것"}]', 'A', '메모이제이션은 결과를 저장하여 중복 계산을 방지하는 역할을 합니다.'),
    (1005, 4, 2, 39, '다음 중 최적 부분 구조를 가진 문제는 무엇인가? (복수정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "피보나치 수열"}, {"id": "B", "text": "최댓값 문제"}, {"id": "C", "text": "계단 오르기"}, {"id": "D", "text": "탐욕 알고리즘 문제"}]', '["A", "C"]', '최적 부분 구조를 가진 문제는 문제의 최적 해가 부분 문제의 최적 해로 구성되는 문제로, 피보나치 수열과 계단 오르기가 해당됩니다.'),
    (1006, 4, 2, 40, '최장 공통 부분 수열(LCS)을 구하기 위한 기본적인 접근 방법은 무엇인가?', 'SHORT_ANSWER', NULL, '다이나믹 프로그래밍', '최장 공통 부분 수열(LCS)은 다이나믹 프로그래밍을 통해 구할 수 있습니다.'),
    (1007, 4, 2, 41, '트리 DP의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리 구조에서 최적 부분 구조를 이용함"}, {"id": "B", "text": "모든 노드를 동시에 업데이트함"}, {"id": "C", "text": "DFS만 사용한다"}, {"id": "D", "text": "반복문만 활용한다"}]', 'A', '트리 DP는 트리 구조에서 자식 노드를 이용하여 부모 노드를 최적화하는 방식을 사용합니다.'),
    (1008, 4, 2, 42, '자릿수 DP가 주로 사용되는 문제 유형은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 비용 경로"}, {"id": "B", "text": "숫자의 자리수 조건을 갖는 문제"}, {"id": "C", "text": "그래프 탐색 문제"}, {"id": "D", "text": "조합 문제"}]', 'B', '자릿수 DP는 숫자의 각 자리수를 상태로 구성하여 문제를 해결하는 기법입니다.'),
    (1009, 4, 2, 43, 'Knuth 최적화의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DP 문제의 공간 복잡도를 줄이는 것"}, {"id": "B", "text": "DP 문제의 시간 복잡도를 줄이는 것"}, {"id": "C", "text": "문제의 해설법을 단순화하는 것"}, {"id": "D", "text": "최소 비용을 최대화하는 것"}]', 'B', 'Knuth 최적화는 특정 DP 문제에서 시간 복잡도를 줄이기 위한 기법입니다.'),
    (1010, 4, 2, 44, '구간 DP 문제에 해당하는 것은 무엇인가? (복수정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대 곱 구하기"}, {"id": "B", "text": "팰린드롬 부분 문자열 찾기"}, {"id": "C", "text": "최소 편집 거리"}, {"id": "D", "text": "최소 비용 경로 찾기"}]', '["A", "B"]', '구간 DP는 특정 구간의 값을 고려하여 최적해를 구하는 문제에 주로 사용됩니다.'),
    (1011, 4, 2, 45, '편집 거리의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '두 문자열을 서로 변환하기 위해 필요한 최소 연산 수', '편집 거리는 문자열을 일치시키기 위한 최소한의 삽입, 삭제, 교체 횟수를 의미합니다.'),
    (1012, 4, 2, 46, '계단 오르기 문제에서 최적의 경로를 찾기 위한 기본 접근법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동적 계획법"}, {"id": "B", "text": "그리디 알고리즘"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "백트래킹"}]', 'A', '계단 오르기 문제는 특정 단계에서 다음 단계로의 경로를 최적화하기 위해 동적 계획법을 이용합니다.'),
    (1013, 4, 2, 47, '최장 증가 부분 수열(LIS)을 구하기 위한 일반적인 DP 접근법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이진 탐색"}, {"id": "B", "text": "메모이제이션"}, {"id": "C", "text": "바텀업 방식"}, {"id": "D", "text": "탑다운 방식"}]', 'C', 'LIS 문제는 보통 바텀업 방식으로 해결하며, 각 요소의 이전 요소들과 비교하여 증가하는 수열의 길이를 업데이트합니다.'),
    (1014, 4, 2, 48, '다음 중 동전 교환 문제를 해결할 때 주로 사용하는 접근법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "탑다운 방식"}, {"id": "B", "text": "최소 신장 트리"}, {"id": "C", "text": "완전 탐색"}, {"id": "D", "text": "바텀업 방식"}]', 'D', '동전 교환 문제는 주어진 동전으로 목표 금액을 만들기 위해 바텀업 방식을 통해 문제를 해결합니다.'),
    (1015, 4, 2, 49, '다음 중 LCS 문제를 해결하기 위해 필요한 기법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모이제이션"}, {"id": "B", "text": "재귀"}, {"id": "C", "text": "탑다운 방식"}, {"id": "D", "text": "바텀업 방식"}]', '["A", "C"]', 'LCS 문제는 메모이제이션과 탑다운 방식을 이용하여 중복 계산을 피하고 문제를 해결합니다.'),
    (1016, 4, 2, 50, '다이나믹 프로그래밍에서 메모이제이션의 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '중복 계산을 피하고 성능을 향상시키기 위해 이미 계산된 결과를 저장하는 것이다.', '메모이제이션은 이미 계산된 결과를 저장하여 같은 문제를 다시 계산할 필요가 없도록 하여 성능을 효율적으로 개선합니다.'),
    (1017, 4, 2, 51, '그리디 알고리즘의 기본 원리는 무엇인가?', 'SHORT_ANSWER', NULL, '매 단계에서 가장 좋은 선택을 하는 것', '그리디 알고리즘은 현재 시점에서 최적의 선택을 하여 문제를 해결하는 접근 방식입니다.'),
    (1018, 4, 2, 52, '최소 신장 트리를 찾는 알고리즘이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "크루스칼 알고리즘"}, {"id": "B", "text": "프림 알고리즘"}, {"id": "C", "text": "다익스트라 알고리즘"}, {"id": "D", "text": "벨만-포드 알고리즘"}]', 'D', '벨만-포드 알고리즘은 최단 경로 문제를 해결하는 알고리즘으로, 최소 신장 트리와는 관련이 없습니다.'),
    (1019, 4, 2, 53, '다음 중 거스름돈 문제에 적합한 접근 방식은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그리디 알고리즘"}, {"id": "B", "text": "동적 프로그래밍"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "백트래킹"}]', 'A', '거스름돈 문제는 그리디 알고리즘을 사용하여 최소의 동전을 선택하는 방식으로 해결할 수 있습니다.'),
    (1020, 4, 2, 54, '최소 신장 트리를 찾기 위한 알고리즘 두 개를 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "크루스칼 알고리즘"}, {"id": "B", "text": "프림 알고리즘"}, {"id": "C", "text": "다익스트라 알고리즘"}, {"id": "D", "text": "Kruskal 알고리즘"}]', '["A", "B"]', '크루스칼 알고리즘과 프림 알고리즘은 모두 최소 신장 트리를 찾기 위한 그리디 알고리즘입니다.'),
    (1021, 4, 2, 55, '그리디 알고리즘에서 가장 핵심적인 접근 방식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매 단계에서 최적의 선택을 하는 것"}, {"id": "B", "text": "모든 경우의 수를 고려하는 것"}, {"id": "C", "text": "모든 하위 문제를 해결하는 것"}, {"id": "D", "text": "결과를 저장하여 재사용하는 것"}]', 'A', '그리디 알고리즘은 매 단계에서 최적의 선택을 통해 문제를 해결하는 방식입니다.'),
    (1022, 4, 2, 56, '프림 알고리즘과 크루스칼 알고리즘의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모두 최소 신장 트리를 찾는 알고리즘이다."}, {"id": "B", "text": "모두 그리디 알고리즘을 사용한다."}, {"id": "C", "text": "모두 동적 프로그래밍을 기반으로 한다."}, {"id": "D", "text": "모두 분할 정복 알고리즘이다."}]', 'A', '프림 알고리즘과 크루스칼 알고리즘 모두 최소 신장 트리를 찾기 위한 알고리즘입니다.'),
    (1023, 4, 2, 57, '회의실 배정 문제에 가장 적합한 알고리즘은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그리디 알고리즘"}, {"id": "B", "text": "동적 프로그래밍"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "브루트 포스"}]', 'A', '회의실 배정 문제는 그리디 알고리즘을 사용하여 최적의 회의 스케줄을 결정할 수 있습니다.'),
    (1024, 4, 2, 58, '그리디 알고리즘과 동적 프로그래밍의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "그리디는 매 단계 최적 선택, DP는 하위 문제 해결"}, {"id": "B", "text": "그리디는 항상 최적해를 보장, DP는 그렇지 않음"}, {"id": "C", "text": "DP는 메모리 사용이 더 많다."}, {"id": "D", "text": "그리디는 반복문, DP는 재귀 사용"}]', '["A", "C"]', '그리디 알고리즘은 매 단계에서 최적의 선택을 하며, DP는 하위 문제를 해결하여 결과를 저장하여 사용합니다. 또한 DP는 메모리를 더 많이 사용할 수 있습니다.'),
    (1025, 4, 2, 59, '거스름돈 문제에서 가장 먼저 선택해야 할 동전의 단위는 무엇인가?', 'SHORT_ANSWER', NULL, '가장 큰 단위의 동전', '거스름돈 문제에서 그리디 알고리즘은 가장 큰 단위의 동전을 우선적으로 선택합니다.'),
    (1026, 4, 2, 60, '그리디 알고리즘의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매 단계에서 현재 최선의 선택을 한다."}, {"id": "B", "text": "모든 경우의 수를 고려한다."}, {"id": "C", "text": "무조건 최적해를 보장한다."}, {"id": "D", "text": "하나의 최적해만 존재한다."}]', 'A', '그리디 알고리즘은 매 단계에서 현재 최선의 선택을 통해 문제를 해결합니다.'),
    (1027, 4, 2, 61, '다음 중 그리디 알고리즘이 최적해를 보장하는 문제는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "거스름돈 문제"}, {"id": "B", "text": "0-1 배낭 문제"}, {"id": "C", "text": "최장 증가 부분 수열"}, {"id": "D", "text": "행렬 곱셈 카라테로의 곱"}]', 'A', '거스름돈 문제는 그리디 알고리즘을 사용하여 최적해를 찾을 수 있는 대표적인 문제입니다.'),
    (1028, 4, 2, 62, '프림 알고리즘은 어떤 목적으로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 신장 트리 찾기"}, {"id": "B", "text": "최단 경로 찾기"}, {"id": "C", "text": "정렬 알고리즘"}, {"id": "D", "text": "최대 유량 문제"}]', 'A', '프림 알고리즘은 그래프에서 최소 신장 트리를 찾는 데 사용되는 그리디 알고리즘입니다.'),
    (1029, 4, 2, 63, '그리디 알고리즘에서 최적해를 구하기 위해 필요한 조건은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최적 부분 구조"}, {"id": "B", "text": "중복 부분 문제"}, {"id": "C", "text": "부분 문제의 최적해가 전체 문제의 최적해를 구성해야 한다."}, {"id": "D", "text": "해가 유일해야 한다."}]', '["A", "C"]', '그리디 알고리즘은 최적 부분 구조와 부분 문제의 최적해가 전체 문제의 최적해를 구성하는 경우에 적용할 수 있습니다.'),
    (1030, 4, 2, 64, '허프만 코딩에서 주로 사용되는 전략은?', 'SHORT_ANSWER', NULL, '그리디 알고리즘', '허프만 코딩은 그리디 알고리즘을 사용하여 최적의 이진 트리를 구성합니다.'),
    (1031, 4, 2, 65, '다이나믹 프로그래밍에서 점화식의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '문제를 정의하고 하위 문제 간의 관계를 나타내는 데 사용된다.', '점화식은 문제를 재귀적으로 해결하기 위한 공식을 제공하며, DP의 핵심 요소입니다.'),
    (1032, 4, 2, 66, '최장 증가 부분수열(LIS) 문제를 해결하기 위한 알고리즘의 접근 방식은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "바텀업 방식"}, {"id": "B", "text": "탑다운 방식"}, {"id": "C", "text": "브루트 포스"}, {"id": "D", "text": "그리디 알고리즘"}]', 'A', 'LIS 문제는 바텀업 방식으로 DP 테이블을 사용하여 해결합니다.'),
    (1033, 4, 2, 67, '피보나치 수열을 메모이제이션 기법을 사용하여 계산할 때 어떤 장점이 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시간 복잡도가 O(N)으로 감소한다."}, {"id": "B", "text": "메모리 사용량이 증가한다."}, {"id": "C", "text": "재귀 호출의 깊이가 줄어든다."}, {"id": "D", "text": "결과가 항상 정수로만 나온다."}]', 'A', '메모이제이션은 중복 계산을 피함으로써 시간 복잡도를 O(N)으로 감소시킵니다.'),
    (1034, 4, 2, 68, '최장 공통 부분수열 문제를 해결할 때 사용할 수 있는 방법은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DP 테이블 사용"}, {"id": "B", "text": "그리디 알고리즘 사용"}, {"id": "C", "text": "재귀 호출 사용"}, {"id": "D", "text": "바텀업 접근"}]', '["A", "C", "D"]', 'LCS 문제는 DP 테이블을 사용하거나 재귀 호출 및 바텀업 접근 방식으로 해결할 수 있습니다.'),
    (1035, 4, 2, 69, 'Knuth 최적화 기법은 주로 어떤 문제에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DP 문제"}, {"id": "B", "text": "그래프 문제"}, {"id": "C", "text": "정렬 문제"}, {"id": "D", "text": "탐색 문제"}]', 'A', 'Knuth 최적화는 주로 DP 문제에서 최적해를 찾기 위해 사용됩니다.'),
    (1036, 4, 2, 70, '편집 거리 문제는 무엇을 계산하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 문자열 간의 최소 변환 비용"}, {"id": "B", "text": "문자열의 길이"}, {"id": "C", "text": "문자열의 동등성"}, {"id": "D", "text": "문자열의 발생 빈도"}]', 'A', '편집 거리 문제는 두 문자열 간의 최소 변환 비용을 계산하는 문제입니다.'),
    (1037, 4, 2, 71, '다음 중 Digit DP의 활용 예시가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자릿수의 합을 구하는 문제"}, {"id": "B", "text": "최소 경로 문제"}, {"id": "C", "text": "특정 자릿수의 숫자 세기"}, {"id": "D", "text": "숫자로 이루어진 문자열의 길이"}]', 'D', 'Digit DP는 주로 자릿수에 의존하는 문제에 사용되며, 문자열의 길이는 해당하지 않습니다.'),
    (1038, 4, 2, 72, '확률 DP에서 주로 다루는 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "불확실한 사건"}, {"id": "B", "text": "확정적인 사건"}, {"id": "C", "text": "기대값"}, {"id": "D", "text": "결정적 문제"}]', '["A", "C"]', '확률 DP는 불확실한 사건과 기대값을 다루는 기법입니다.'),
    (1039, 4, 2, 73, '행렬 곱셈 순서에서 최적의 곱셈 비용을 찾기 위한 알고리즘은 무엇인가?', 'SHORT_ANSWER', NULL, '동적 프로그래밍', '행렬 곱셈 순서 문제는 동적 프로그래밍을 사용하여 최적의 곱셈 비용을 찾습니다.'),
    (1040, 4, 2, 74, '볼록 껍질 트릭은 어떤 유형의 문제에 주로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최적화 문제"}, {"id": "B", "text": "그래프 탐색"}, {"id": "C", "text": "문자열 처리"}, {"id": "D", "text": "정렬 문제"}]', 'A', '볼록 껍질 트릭은 주로 DP의 최적화 문제에 사용되며, 가장 효율적인 해결책을 찾는 데 도움을 줍니다.'),
    (1041, 4, 2, 75, 'Knuth 최적화는 어떤 조건에서 적용할 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비용이 증가하는 경우"}, {"id": "B", "text": "비용이 감소하는 경우"}, {"id": "C", "text": "비용이 무작위인 경우"}, {"id": "D", "text": "비용이 상관없는 경우"}]', 'A', 'Knuth 최적화는 DP의 상태 전이에서 비용이 증가하는 경우에 적용됩니다.'),
    (1042, 4, 2, 76, '트리 DP의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리 구조를 기반으로 한다"}, {"id": "B", "text": "배열에서만 사용 가능하다"}, {"id": "C", "text": "정렬이 필요하다"}, {"id": "D", "text": "최소 경로를 찾아야 한다"}]', 'A', '트리 DP는 트리 구조를 기반으로 하여 문제를 해결하는 데 사용됩니다.'),
    (1043, 4, 2, 77, '편집 거리 계산에 사용되는 알고리즘은 어떤 방법론을 기반으로 하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "동적 프로그래밍"}, {"id": "B", "text": "탐욕적 방법"}, {"id": "C", "text": "브루트 포스"}, {"id": "D", "text": "분할 정복"}]', '["A"]', '편집 거리는 동적 프로그래밍을 사용하여 두 문자열 간의 최소 변환 횟수를 계산하는 방법입니다.'),
    (1044, 4, 2, 78, '확률 DP의 주요 활용 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '불확실한 상황에서 최적의 결정을 내리기 위함입니다.', '확률 DP는 확률적인 사건을 고려하여 최적의 결정을 내리기 위해 사용됩니다.'),
    (1045, 4, 2, 79, '비트마스크 DP의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상태를 비트로 표현하여 여러 선택을 동시에 고려할 수 있다."}, {"id": "B", "text": "무조건 최적의 해를 보장한다."}, {"id": "C", "text": "메모리 사용량이 항상 적다."}, {"id": "D", "text": "단순히 반복문을 사용하는 것과 같다."}]', 'A', '비트마스크 DP는 상태를 비트로 표현하여 다양한 선택을 동시에 고려할 수 있는 기법입니다.'),
    (1046, 4, 2, 80, 'Knuth 최적화를 사용하는 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시간 복잡도를 줄이기 위해서이다."}, {"id": "B", "text": "문제를 단순화하기 위해서이다."}, {"id": "C", "text": "메모리 사용량을 줄이기 위해서이다."}, {"id": "D", "text": "재귀 호출을 이용하기 위해서이다."}]', 'A', 'Knuth 최적화는 DP 문제에서 시간 복잡도를 줄이기 위해 사용되는 기법입니다.'),
    (1047, 4, 2, 81, '편집 거리 문제에서 사용할 수 있는 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "동적 프로그래밍"}, {"id": "B", "text": "그리디 알고리즘"}, {"id": "C", "text": "브루트 포스"}, {"id": "D", "text": "분할 정복"}]', '["A", "D"]', '편집 거리 문제는 동적 프로그래밍과 분할 정복 방법으로 해결할 수 있습니다.'),
    (1048, 4, 2, 82, '외판원 문제의 주요 목표는 무엇인가?', 'SHORT_ANSWER', NULL, '모든 도시를 한 번씩 방문하고 원래 도시로 돌아오는 가장 짧은 경로를 찾는 것이다.', '외판원 문제는 모든 도시를 한 번씩 방문한 후 원래 도시로 돌아오는 가장 최단 경로를 계산하는 문제입니다.'),
    (1049, 4, 2, 83, '최장 공통 부분수열(LCS)의 정의는 무엇인가요?', 'SHORT_ANSWER', NULL, '두 문자열에서 순서를 유지하며 공통적으로 포함되는 가장 긴 부분수열', 'LCS는 두 문자열의 공통된 부분수열 중에서 가장 긴 것을 찾아내는 문제입니다.'),
    (1050, 4, 2, 84, '다이나믹 프로그래밍에서 ''탑다운'' 접근 방식은 어떤 방식인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "재귀를 사용하여 문제를 해결하는 방식"}, {"id": "B", "text": "반복문을 사용하여 문제를 해결하는 방식"}, {"id": "C", "text": "문제를 해결하기 위해 하위 문제를 생성하지 않는 방식"}, {"id": "D", "text": "모든 하위 문제를 미리 구해서 활용하는 방식"}]', 'A', '''탑다운'' 접근 방식은 주어진 문제를 재귀적으로 해결하며, 하위 문제의 결과를 저장하여 중복 계산을 방지하는 방식입니다.'),
    (1051, 4, 2, 85, '최장 증가 부분수열(LIS) 문제의 시간 복잡도는 최악의 경우 몇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "O(n)"}, {"id": "B", "text": "O(n^2)"}, {"id": "C", "text": "O(n log n)"}, {"id": "D", "text": "O(2^n)"}]', 'C', 'LIS를 이진 탐색을 활용하여 해결할 경우 시간 복잡도는 O(n log n)입니다.'),
    (1052, 4, 2, 86, '다음 중 다이나믹 프로그래밍의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "문제를 하위 문제로 나눌 수 있다."}, {"id": "B", "text": "모든 하위 문제는 서로 독립적이다."}, {"id": "C", "text": "최적 부분 구조를 가진다."}, {"id": "D", "text": "중복 계산을 최소화한다."}]', '["B"]', '다이나믹 프로그래밍에서 하위 문제는 종종 서로 의존적이며, 이러한 의존성을 이해하는 것이 중요합니다.'),
    (1053, 4, 2, 87, '소인수분해란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정수를 소수의 곱으로 표현하는 것"}, {"id": "B", "text": "정수를 2의 거듭제곱으로 표현하는 것"}, {"id": "C", "text": "정수의 제곱근을 찾는 것"}, {"id": "D", "text": "정수의 최대공약수를 찾는 것"}]', 'A', '소인수분해는 주어진 정수를 소수의 곱으로 표현하는 것으로, 이는 정수론의 기초 개념이다.'),
    (1054, 4, 2, 88, '유클리드 호제법의 주목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최대공약수를 구하는 것"}, {"id": "B", "text": "최소공배수를 구하는 것"}, {"id": "C", "text": "소수를 찾는 것"}, {"id": "D", "text": "정수의 제곱을 계산하는 것"}]', 'A', '유클리드 호제법은 두 수의 최대공약수를 구하는 알고리즘으로, 효율적으로 계산할 수 있도록 돕는다.'),
    (1055, 4, 2, 89, '다음 중 페르마 소정리에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정수에 대해 성립한다."}, {"id": "B", "text": "소수 p에 대해 특정 조건을 만족하는 경우 성립한다."}, {"id": "C", "text": "임의의 정수에 대해 항상 참이다."}, {"id": "D", "text": "모든 소수에 대한 합을 구하는 법칙이다."}]', 'B', '페르마 소정리는 소수 p에 대해 특정 조건을 만족하는 경우에만 성립하는 정리이다.'),
    (1056, 4, 2, 90, '아래 중 확장 유클리드 알고리즘의 사용 목적은 무엇인가? (복수 정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대공약수 계산"}, {"id": "B", "text": "선형 방정식의 해 찾기"}, {"id": "C", "text": "소수 판별"}, {"id": "D", "text": "다항식의 근 찾기"}]', '["A", "B"]', '확장 유클리드 알고리즘은 두 수의 최대공약수를 구하는 것뿐만 아니라, 선형 방정식의 해를 찾는 데에도 사용된다.'),
    (1057, 4, 2, 91, '빠른 거듭제곱 알고리즘의 주요 이점은 무엇인가?', 'SHORT_ANSWER', NULL, '효율적인 거듭제곱 계산을 통해 계산 시간을 단축할 수 있다.', '빠른 거듭제곱 알고리즘은 큰 수의 거듭제곱을 효율적으로 계산하는 방법으로, 시간 복잡도를 줄이는 데 큰 기여를 한다.'),
    (1058, 4, 2, 92, '팰린드롬 분할 문제는 무엇을 해결하는 기법인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소한의 팰린드롬 조각으로 문자열을 나누기"}, {"id": "B", "text": "문자열의 가장 긴 팰린드롬 찾기"}, {"id": "C", "text": "모든 팰린드롬 조각을 나열하기"}, {"id": "D", "text": "팰린드롬을 찾는지 여부 확인하기"}]', 'A', '팰린드롬 분할 문제는 주어진 문자열을 최소한의 팰린드롬 조각으로 나누는 방법을 찾는 것입니다.'),
    (1059, 4, 2, 93, 'Digit DP 기법은 주로 어떤 상황에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자릿수를 고려하는 문제 해결"}, {"id": "B", "text": "배열 정렬"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "문자열 비교"}]', 'A', 'Digit DP 기법은 자릿수를 고려하여 숫자 관련 문제를 해결하는 데 주로 사용됩니다.'),
    (1060, 4, 2, 94, '다음 중 외판원 문제(TSP)의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 도시를 방문하는 최단 경로 찾기"}, {"id": "B", "text": "가장 긴 경로 찾기"}, {"id": "C", "text": "특정 도시에서 출발하는 경로 찾기"}, {"id": "D", "text": "가장 많은 도시 방문하기"}]', 'A', '외판원 문제(TSP)는 모든 도시를 한 번씩 방문하고, 출발 도시로 돌아오는 최단 경로를 찾는 문제입니다.'),
    (1061, 4, 2, 95, '편집 거리 문제에서 중요한 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "두 문자열 간의 최소 변환 작업"}, {"id": "B", "text": "문자열의 길이"}, {"id": "C", "text": "문자열의 알파벳 순서"}, {"id": "D", "text": "문자열 비교 결과"}]', '["A", "B"]', '편집 거리 문제는 두 문자열 간의 최소 변환 작업을 찾는 것으로, 문자열의 길이도 중요한 요소입니다.'),
    (1062, 4, 2, 96, '트리 DP란 무엇인가?', 'SHORT_ANSWER', NULL, '트리 구조에서 최적화 문제를 해결하는 동적 프로그래밍 기법입니다.', '트리 DP는 트리 구조를 가지는 문제에 대해 동적 프로그래밍을 사용하여 최적의 해를 찾는 방법을 의미합니다.'),
    (1063, 4, 2, 97, '그리디 알고리즘의 기본 원리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "지역 최적해 선택"}, {"id": "B", "text": "모든 경우의 수 탐색"}, {"id": "C", "text": "동적 프로그래밍 활용"}, {"id": "D", "text": "구간을 나누어 문제 해결"}]', 'A', '그리디 알고리즘은 각 단계에서 지역 최적해를 선택하여 최종 문제를 해결하는 방식입니다.'),
    (1064, 4, 2, 98, '크루스칼 알고리즘은 어떤 문제를 해결하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 신장 트리"}, {"id": "B", "text": "최단 경로"}, {"id": "C", "text": "정렬 문제"}, {"id": "D", "text": "최대 유량"}]', 'A', '크루스칼 알고리즘은 그래프에서 최소 신장 트리를 찾는 알고리즘입니다.'),
    (1065, 4, 2, 99, '거스름돈 문제에 적합한 알고리즘은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그리디 알고리즘"}, {"id": "B", "text": "다이나믹 프로그래밍"}, {"id": "C", "text": "브루트 포스"}, {"id": "D", "text": "백트래킹"}]', 'A', '거스름돈 문제는 그리디 알고리즘을 사용하여 최소한의 동전 개수를 찾는 데 적합합니다.'),
    (1066, 4, 2, 100, '그리디 알고리즘에 대한 설명으로 옳은 것을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 상황에서 최적해를 보장하지는 않는다."}, {"id": "B", "text": "지역 최적해를 반복적으로 선택한다."}, {"id": "C", "text": "다이나믹 프로그래밍과 유사한 방식이다."}, {"id": "D", "text": "문제의 구조를 이해해야 한다."}]', '["A", "B", "D"]', '그리디 알고리즘은 특정 경우에만 최적해를 보장하며, 지역 최적해를 선택하고 문제의 구조를 이해해야 합니다.'),
    (1067, 4, 2, 101, '최소 신장 트리(MST)의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '모든 정점을 포함하면서 가중치의 합이 최소인 트리', '최소 신장 트리는 그래프의 모든 정점을 포함하고, 가중치의 합이 최소가 되도록 하는 트리를 의미합니다.'),
    (1068, 4, 2, 102, '에라토스테네스의 체는 무엇을 찾기 위한 알고리즘인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수"}, {"id": "B", "text": "합성수"}, {"id": "C", "text": "소인수"}, {"id": "D", "text": "최대공약수"}]', 'A', '에라토스테네스의 체는 주어진 범위 내의 모든 소수를 찾기 위한 알고리즘입니다.'),
    (1069, 4, 2, 103, '확장 유클리드 알고리즘의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최대공약수 계산"}, {"id": "B", "text": "소수 판별"}, {"id": "C", "text": "소인수분해"}, {"id": "D", "text": "최소공배수 계산"}]', 'A', '확장 유클리드 알고리즘은 두 정수의 최대공약수를 계산하는 데 사용됩니다.'),
    (1070, 4, 2, 104, '소인수분해의 결과로 나타나는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수의 곱"}, {"id": "B", "text": "합성수"}, {"id": "C", "text": "최대공약수"}, {"id": "D", "text": "최소공배수"}]', 'A', '소인수분해는 주어진 수를 소수의 곱으로 나타내는 과정입니다.'),
    (1071, 4, 2, 105, '다음 중 페르마 소정리에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "a^p ≡ a (mod p)"}, {"id": "B", "text": "a^n + b^n = c^n"}, {"id": "C", "text": "gcd(a, b) = 1"}, {"id": "D", "text": "LCM(a, b) = (a*b) / GCD(a, b)"}]', '["A"]', '페르마 소정리는 a^p ≡ a (mod p)를 만족하는 모든 정수 a와 소수 p에 대해 성립합니다.'),
    (1072, 4, 2, 106, 'LCM(12, 15)의 결과는 무엇인가?', 'SHORT_ANSWER', NULL, '60', '12와 15의 최소공배수는 60입니다.'),
    (1073, 4, 2, 107, '트리 DP에서 주로 사용되는 접근 방식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상위 노드에서 하위 노드로 정보 전파"}, {"id": "B", "text": "하위 노드에서 상위 노드로 정보 전파"}, {"id": "C", "text": "모든 노드를 한 번에 처리"}, {"id": "D", "text": "깊이 우선 탐색을 사용하지 않는다"}]', 'A', '트리 DP는 상위 노드에서 하위 노드로 정보를 전파하여 문제를 해결하는 방식입니다.'),
    (1074, 4, 2, 108, '비트마스크 DP의 주된 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분집합의 상태 관리"}, {"id": "B", "text": "정렬 문제 해결"}, {"id": "C", "text": "최소 경로 찾기"}, {"id": "D", "text": "문자열 비교"}]', 'A', '비트마스크 DP는 부분집합을 비트로 표현하여 상태를 관리하는 데 유용합니다.'),
    (1075, 4, 2, 109, '편집 거리 계산에서 사용하는 DP 배열의 크기는 어떻게 결정되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열의 길이 x 문자열의 길이"}, {"id": "B", "text": "문자열의 길이 + 1"}, {"id": "C", "text": "문자열의 길이 - 1"}, {"id": "D", "text": "상수로 결정된다"}]', 'A', '편집 거리 DP 배열은 두 문자열의 길이 곱으로 결정됩니다.'),
    (1076, 4, 2, 110, 'Knuth 최적화가 적용되는 경우는 어떤 경우인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "선형 DP"}, {"id": "B", "text": "비선형 DP"}, {"id": "C", "text": "특정 조건을 만족하는 문제"}, {"id": "D", "text": "모든 DP 문제"}]', '["A", "C"]', 'Knuth 최적화는 주로 선형 DP에 적용되며, 특정 조건을 만족하는 경우에 유용합니다.'),
    (1077, 4, 2, 111, 'Digit DP에서 주로 다루는 개념은 무엇인가?', 'SHORT_ANSWER', NULL, '자릿수에 따른 조건 만족하는 수 세기', ''),
    (1078, 4, 2, 112, 'Digit DP의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "숫자의 범위에서 조건을 만족하는 경우의 수 구하기"}, {"id": "B", "text": "문자열에서 팰린드롬 찾기"}, {"id": "C", "text": "확률론적 문제 해결"}, {"id": "D", "text": "행렬 곱셈 최적화"}]', 'A', 'Digit DP는 자릿수를 기준으로 조건을 만족하는 경우의 수를 구하는 데 유용한 기법입니다.'),
    (1079, 4, 2, 113, '확률 DP란 무엇을 다루는 기법인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 문제 해결"}, {"id": "B", "text": "동시에 여러 결과를 고려한 기댓값 계산"}, {"id": "C", "text": "최적의 경로 찾기"}, {"id": "D", "text": "특정 DP 형태 최적화"}]', 'B', '확률 DP는 여러 선택의 기댓값을 최대화하는 문제를 해결하는 기법입니다.'),
    (1080, 4, 2, 114, '구간 DP를 활용하는 경우는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행렬 곱셈 순서 결정"}, {"id": "B", "text": "문자열 팰린드롬 분할"}, {"id": "C", "text": "구간을 기준으로 최적 해 찾기"}, {"id": "D", "text": "숫자 조합 문제 해결"}]', 'C', '구간 DP는 특정 구간을 기준으로 최적의 해를 찾는 기법입니다.'),
    (1081, 4, 2, 115, '다음 중 Knuth 최적화를 사용하는 DP 문제는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최소 비용 구간 DP 문제"}, {"id": "B", "text": "행렬 곱셈 순서 문제"}, {"id": "C", "text": "최대 기댓값 DP 문제"}, {"id": "D", "text": "일반적인 DP 문제"}]', '["A", "C"]', 'Knuth 최적화는 특정 DP 문제에서 시간 복잡도를 줄이는 데 유용하며, 일반적으로 최소 비용 구간 DP나 최대 기댓값 DP 문제에 적용됩니다.'),
    (1082, 4, 2, 116, 'Digit DP에서 자릿수의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '숫자의 각 자리수를 나타내며, 자릿수를 기준으로 조건을 설정하여 경우의 수를 계산한다.', 'Digit DP는 숫자의 자릿수를 기반으로 문제를 해결하는 기법으로, 각 자리수를 고려하여 조건을 설정합니다.'),
    (1083, 4, 2, 117, '트리 DP의 주된 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리 구조의 최적화 문제 해결"}, {"id": "B", "text": "정렬 알고리즘 구현"}, {"id": "C", "text": "그래프의 최단 경로 찾기"}, {"id": "D", "text": "문자열 검색 최적화"}]', 'A', '트리 DP는 주로 트리 구조에서 최적화 문제를 해결하는 데 사용됩니다.'),
    (1084, 4, 2, 118, 'Knuth 최적화는 어떤 경우에 효과적일까요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "리니어 DP 문제에서"}, {"id": "B", "text": "그래프 이론 문제에서"}, {"id": "C", "text": "이진 탐색 문제에서"}, {"id": "D", "text": "무작위 알고리즘에서"}]', 'A', 'Knuth 최적화는 주로 리니어 DP 문제에서 효과적으로 사용됩니다.'),
    (1085, 4, 2, 119, '자릿수 DP의 적용 예제로 좋은 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "수의 범위 내에서 조건 만족하는 수의 개수 세기"}, {"id": "B", "text": "그래프의 간선 가중치 최적화"}, {"id": "C", "text": "정렬된 배열 생성"}, {"id": "D", "text": "문자열 복원"}]', 'A', '자릿수 DP는 수의 자릿수를 기반으로 조건을 만족하는 수의 개수를 세는 데 유용합니다.'),
    (1086, 4, 2, 120, '외판원 문제에서 필요한 조건은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 도시를 정확히 한 번 방문해야 한다"}, {"id": "B", "text": "시작 도시와 종료 도시가 같아야 한다"}, {"id": "C", "text": "도시 간의 거리는 모두 동일해야 한다"}, {"id": "D", "text": "경로의 비용을 최소화해야 한다"}]', '["A", "B", "D"]', '외판원 문제는 모든 도시를 정확히 한 번 방문하고, 시작과 끝이 같은 경로를 만들며, 비용을 최소화하는 조건을 가지고 있습니다.'),
    (1087, 4, 2, 121, '볼록 껍질 트릭의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'DP의 최적화', '볼록 껍질 트릭은 DP에서 최적화 과정을 효과적으로 수행하는 기법입니다.'),
    (1088, 4, 2, 122, '확률 DP의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "확률적인 상황에서 최적화된 해를 찾기 위함"}, {"id": "B", "text": "단순한 DP 문제를 해결하기 위함"}, {"id": "C", "text": "정수 계산을 최적화하기 위함"}, {"id": "D", "text": "메모리 사용량을 줄이기 위함"}]', 'A', '확률 DP는 확률적인 요소가 있는 문제에서 최적의 해를 찾기 위한 기법입니다.'),
    (1089, 4, 2, 123, '비트마스크 DP의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상태 표현이 간결하여 다양한 집합 문제를 쉽게 해결할 수 있다"}, {"id": "B", "text": "코드 작성이 매우 간단하다"}, {"id": "C", "text": "항상 최적의 해를 보장한다"}, {"id": "D", "text": "메모리를 절약할 수 있다"}]', 'A', '비트마스크 DP는 상태를 비트로 표현하며, 다양한 집합 문제를 간결하게 해결하는 데 유리합니다.'),
    (1090, 4, 2, 124, 'Digit DP는 어떤 문제를 주로 해결하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열의 길이를 찾는 문제"}, {"id": "B", "text": "자연수의 자릿수를 고려하는 문제"}, {"id": "C", "text": "최소 경로 문제"}, {"id": "D", "text": "그래프 순회 문제"}]', 'B', 'Digit DP는 주어진 조건을 만족하는 자연수의 자릿수를 고려하여 문제를 해결하는 데 사용됩니다.'),
    (1091, 4, 2, 125, '다음 중 구간 DP에 해당하는 경우는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대 부분 배열 합 문제"}, {"id": "B", "text": "서브 문자열의 최대 팰린드롬 길이 문제"}, {"id": "C", "text": "자연수의 조합 문제"}, {"id": "D", "text": "구간 합 쿼리 문제"}]', '["A", "B", "D"]', '구간 DP는 특정 구간의 최적화를 다루며, 최대 부분 배열 합, 서브 문자열의 최대 팰린드롬 길이, 구간 합 쿼리 등이 해당합니다.'),
    (1092, 4, 2, 126, '볼록 껍질 트릭의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, 'DP와 결합하여 최적화를 효율적으로 만드는 것', '볼록 껍질 트릭은 DP를 사용하여 최적화를 더 효율적으로 수행하도록 돕는 기법입니다.'),
    (1093, 4, 2, 127, '확률과 기댓값의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '확률은 특정 사건이 발생할 가능성을 나타내는 수치이며, 기댓값은 모든 가능한 결과의 평균값을 나타낸다.', '확률은 0과 1 사이의 값으로 표현되며, 기댓값은 확률 분포에 따라 각 결과의 가중 평균이다.'),
    (1094, 4, 2, 128, '에라토스테네스의 체는 무엇을 구하는 데 사용되는 알고리즘인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수"}, {"id": "B", "text": "최소공배수"}, {"id": "C", "text": "최대공약수"}, {"id": "D", "text": "피보나치 수"}]', 'A', '에라토스테네스의 체는 주어진 범위 내의 소수를 효율적으로 찾기 위한 알고리즘이다.'),
    (1095, 4, 2, 129, '중국인 나머지 정리가 주로 해결하는 문제의 유형은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동시 방정식"}, {"id": "B", "text": "최대공약수"}, {"id": "C", "text": "소수 판별"}, {"id": "D", "text": "순열 계산"}]', 'A', '중국인 나머지 정리는 서로 다른 모듈로 나누었을 때 동시 방정식의 해를 구하는 데 사용된다.'),
    (1096, 4, 2, 130, '다음 중 유클리드 호제법의 사용 목적이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대공약수 구하기"}, {"id": "B", "text": "소수 판별하기"}, {"id": "C", "text": "LCM 구하기"}, {"id": "D", "text": "다항식의 인수 분해"}]', '["A", "C"]', '유클리드 호제법은 최대공약수를 구하는 데 사용되며, LCM은 다른 방법으로 구한다.'),
    (1097, 4, 2, 131, '소인수분해란 무엇을 의미합니까?', 'SHORT_ANSWER', NULL, '모든 정수를 소수의 곱으로 표현하는 것', '소인수분해는 정수를 소수로 나누어 그 곱으로 표현하는 과정입니다.'),
    (1098, 4, 2, 132, '확장 유클리드 알고리즘은 어떤 목적으로 사용됩니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최대공약수를 계산하기 위해"}, {"id": "B", "text": "소수를 판별하기 위해"}, {"id": "C", "text": "모듈러 연산을 수행하기 위해"}, {"id": "D", "text": "확률을 계산하기 위해"}]', 'A', '확장 유클리드 알고리즘은 두 정수의 최대공약수를 계산하는 데 사용됩니다.'),
    (1099, 4, 2, 133, '중국인 나머지 정리의 주요 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수를 판별하는 것"}, {"id": "B", "text": "여러 나머지를 동시에 해결하는 것"}, {"id": "C", "text": "확률을 계산하는 것"}, {"id": "D", "text": "최대공약수를 찾는 것"}]', 'B', '중국인 나머지 정리는 두 개 이상의 서로 소인 정수의 나머지를 동시에 해결하는 방법입니다.'),
    (1100, 4, 2, 134, '모듈러 연산을 사용할 때 어떤 기본적인 성질을 이용하나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "a ≡ b (mod m)일 때 a와 b는 m에 대해 동치이다."}, {"id": "B", "text": "모든 정수는 소수이다."}, {"id": "C", "text": "a + b ≡ c (mod m)일 때 a, b, c는 모두 m으로 나누어 떨어진다."}, {"id": "D", "text": "모듈러 연산의 결과는 항상 0이다."}]', '["A"]', '모듈러 연산의 기본 성질 중 하나는 동치 관계를 성립시키며, 이는 계산에 중요합니다.'),
    (1101, 4, 2, 135, '에라토스테네스의 체는 어떤 문제를 해결하기 위한 알고리즘인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정수의 최대공약수 계산"}, {"id": "B", "text": "소수 찾기"}, {"id": "C", "text": "모듈러 연산"}, {"id": "D", "text": "거듭제곱 계산"}]', 'B', '에라토스테네스의 체는 주어진 범위 내의 모든 소수를 찾기 위한 알고리즘입니다.'),
    (1102, 4, 2, 136, '다이나믹 프로그래밍의 주요 기술 중 하나로, 이미 계산한 결과를 저장하고 재사용하는 방법은 무엇인가?', 'SHORT_ANSWER', NULL, '메모이제이션', '메모이제이션은 동적 프로그래밍에서 이미 계산된 값을 저장하여 중복 계산을 피하는 기법입니다.'),
    (1103, 4, 2, 137, '다음 중 동적 프로그래밍의 활용 예시로 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동전 교환 문제"}, {"id": "B", "text": "최장 증가 부분수열"}, {"id": "C", "text": "선형 탐색"}, {"id": "D", "text": "배낭 문제"}]', 'C', '선형 탐색은 동적 프로그래밍과 관련이 없는 알고리즘입니다.'),
    (1104, 4, 2, 138, '다이나믹 프로그래밍에서 사용하는 DP 테이블은 주로 어떤 형태로 구성되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1차원 배열"}, {"id": "B", "text": "2차원 배열"}, {"id": "C", "text": "3차원 배열"}, {"id": "D", "text": "변형된 해시 테이블"}]', 'B', 'DP 테이블은 문제에 따라 1차원 또는 2차원 배열로 구성되며, 많은 DP 문제는 2차원 배열을 사용합니다.'),
    (1105, 4, 2, 139, '다음 중 동적 프로그래밍 문제를 해결하기 위해 세우는 식으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "f(n) = f(n-1) + f(n-2)"}, {"id": "B", "text": "f(n) = min(f(n-1), f(n-2), ..., f(n-k)) + cost(n)"}, {"id": "C", "text": "f(n) = f(n-1) * f(n-2)"}, {"id": "D", "text": "f(n) = f(n-1) + n"}]', '["A", "B", "D"]', 'A, B, D는 모두 동적 프로그래밍에서 사용되는 점화식의 예시입니다.'),
    (1106, 4, 2, 140, '빠른 거듭제곱 알고리즘의 주된 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시간 복잡도가 O(log n)이다."}, {"id": "B", "text": "공간 복잡도가 O(n)이다."}, {"id": "C", "text": "결과가 항상 정수로 나온다."}, {"id": "D", "text": "모두 양수로 계산된다."}]', 'A', '빠른 거듭제곱 알고리즘은 거듭제곱 연산을 O(log n) 시간에 수행할 수 있어 효율적입니다.'),
    (1107, 4, 2, 141, '에라토스테네스의 체에서 무엇을 이용해 소수를 찾는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배수 제거"}, {"id": "B", "text": "소인수분해"}, {"id": "C", "text": "사칙연산"}, {"id": "D", "text": "확률 분포"}]', 'A', '에라토스테네스의 체는 소수들의 배수를 제거하여 소수를 찾는 방법입니다.'),
    (1108, 4, 2, 142, '중국인 나머지 정리를 사용하여 무엇을 할 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "한 개의 모듈러 식을 풀 수 있다."}, {"id": "B", "text": "여러 개의 모듈러 식을 동시에 풀 수 있다."}, {"id": "C", "text": "모듈러 연산을 수행할 수 없다."}, {"id": "D", "text": "소수를 찾을 수 있다."}]', 'B', '중국인 나머지 정리는 여러 개의 모듈러 식을 동시에 만족하는 해를 찾는 데 사용됩니다.'),
    (1109, 4, 2, 143, '최대공약수를 구하는 방법 중 하나는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "유클리드 호제법"}, {"id": "B", "text": "소인수분해"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "히스토그램"}]', '["A", "B"]', '최대공약수를 구하는 방법으로 유클리드 호제법과 소인수분해를 사용할 수 있습니다.'),
    (1110, 4, 2, 144, '모듈러 연산에서 ''a mod m''의 값은 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, 'a를 m으로 나눈 나머지', '모듈러 연산 ''a mod m''은 a를 m으로 나눈 나머지를 의미합니다.'),
    (1111, 4, 2, 145, '최대공약수(GCD)와 최소공배수(LCM)의 관계는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "GCD(a, b) * LCM(a, b) = a * b"}, {"id": "B", "text": "GCD(a, b) + LCM(a, b) = a + b"}, {"id": "C", "text": "GCD(a, b) - LCM(a, b) = 0"}, {"id": "D", "text": "GCD(a, b) / LCM(a, b) = 1"}]', 'A', '최대공약수와 최소공배수는 서로의 곱이 두 수의 곱과 같다는 성질이 있습니다.'),
    (1112, 4, 2, 146, '페르마 소정리에 따르면, p가 소수일 때 어떤 식이 성립하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "a^(p-1) ≡ 1 (mod p)"}, {"id": "B", "text": "a^(p) ≡ a (mod p)"}, {"id": "C", "text": "a * b ≡ 1 (mod p)"}, {"id": "D", "text": "a^(p+1) ≡ 1 (mod p)"}]', 'A', '페르마의 소정리에 따르면, p가 소수이고 a가 p로 나누어떨어지지 않으면 a^(p-1) ≡ 1 (mod p)입니다.'),
    (1113, 4, 2, 147, '에라토스테네스의 체는 무엇을 구하는 데 사용되는 알고리즘인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수 구하기"}, {"id": "B", "text": "최대공약수 구하기"}, {"id": "C", "text": "소인수분해"}, {"id": "D", "text": "거듭제곱 계산"}]', 'A', '에라토스테네스의 체는 주어진 범위 내의 소수를 효율적으로 찾기 위한 알고리즘입니다.'),
    (1114, 4, 2, 148, '소인수분해에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 자연수는 소인수분해할 수 있다."}, {"id": "B", "text": "소인수분해는 유일하게 이루어진다."}, {"id": "C", "text": "소인수분해는 항상 1과 자기 자신으로 이루어진다."}, {"id": "D", "text": "소인수분해는 정수론에서 중요한 기초 개념이다."}]', '["A", "B", "D"]', '모든 자연수는 소인수분해가 가능하며, 소인수분해는 유일하게 이루어지며 정수론에서 중요한 기초 개념입니다.'),
    (1115, 4, 2, 149, '파스칼 삼각형에서 n번째 줄의 k번째 값은 무엇을 나타내나요?', 'SHORT_ANSWER', NULL, '조합 C(n, k)', '파스칼 삼각형의 n번째 줄의 k번째 값은 n개 중 k개를 선택하는 조합의 수를 나타냅니다.'),
    (1116, 4, 2, 150, '그리디 알고리즘은 어떤 접근 방식을 사용하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 상황에서 최적의 선택"}, {"id": "B", "text": "모든 가능한 경우를 탐색"}, {"id": "C", "text": "하위 문제를 해결하여 전체 문제 해결"}, {"id": "D", "text": "무작위로 선택"}]', 'A', '그리디 알고리즘은 문제를 해결하는 과정에서 현재 상황에서 최적의 선택을 하는 방식입니다.'),
    (1117, 4, 2, 151, '어떤 문제에서 그리디 알고리즘이 유용하게 사용될 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "거스름돈 문제"}, {"id": "B", "text": "최단 경로 문제"}, {"id": "C", "text": "배낭 문제"}, {"id": "D", "text": "모든 경우의 수를 찾는 문제"}]', 'A', '거스름돈 문제는 그리디 알고리즘을 사용하여 효율적으로 해결할 수 있는 전형적인 사례입니다.'),
    (1118, 4, 2, 152, '최소 신장 트리를 구하는 알고리즘은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "크루스칼 알고리즘"}, {"id": "B", "text": "다익스트라 알고리즘"}, {"id": "C", "text": "벨만 포드 알고리즘"}, {"id": "D", "text": "DFS 알고리즘"}]', 'A', '크루스칼 알고리즘은 최소 신장 트리를 구하는 데 사용되는 그리디 알고리즘입니다.'),
    (1119, 4, 2, 153, '그리디 알고리즘이 보장하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최적해"}, {"id": "B", "text": "지역 최적해"}, {"id": "C", "text": "구현의 용이성"}, {"id": "D", "text": "모든 문제에 대한 해결책"}]', '["B", "C"]', '그리디 알고리즘은 지역 최적해를 보장하며 구현이 간단하다는 장점이 있습니다.'),
    (1120, 4, 2, 154, '활동 선택 문제의 최적해를 찾기 위한 접근 방식은?', 'SHORT_ANSWER', NULL, '그리디 알고리즘', '활동 선택 문제는 그리디 알고리즘을 사용하여 해결할 수 있습니다.'),
    (1121, 4, 2, 155, '빠른 거듭제곱 알고리즘의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "계산 속도를 높인다."}, {"id": "B", "text": "단순성을 제공한다."}, {"id": "C", "text": "메모리 사용량을 줄인다."}, {"id": "D", "text": "소수를 찾는 데 사용된다."}]', 'A', '빠른 거듭제곱 알고리즘은 거듭제곱을 효율적으로 계산함으로써 계산 속도를 높이는 장점을 가지고 있습니다.'),
    (1122, 4, 2, 156, '확장 유클리드 알고리즘은 무엇을 계산하는데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소공배수"}, {"id": "B", "text": "최대공약수 및 선형 결합"}, {"id": "C", "text": "소수 판별"}, {"id": "D", "text": "조합의 계수"}]', 'B', '확장 유클리드 알고리즘은 최대공약수(GCD)를 계산하며, 두 수의 선형 결합을 찾는 데도 사용됩니다.'),
    (1123, 4, 2, 157, '파스칼 삼각형에서 n 번째 줄의 k 번째 원소는 무엇을 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "n!/(k!(n-k)!)"}, {"id": "B", "text": "n + k"}, {"id": "C", "text": "k/n"}, {"id": "D", "text": "k!"}]', 'A', '파스칼 삼각형의 n 번째 줄의 k 번째 원소는 조합의 계수로 n!/(k!(n-k)!)를 나타냅니다.'),
    (1124, 4, 2, 158, 'GCD(48, 18)의 값을 구하시오.', 'SHORT_ANSWER', NULL, '6', '48과 18의 최대공약수는 6입니다.'),
    (1125, 4, 2, 159, '다음 중 중국인 나머지 정리를 사용할 수 있는 상황은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "여러 모듈로 나뉘어진 방정식을 해결할 때"}, {"id": "B", "text": "단순한 선형 방정식을 해결할 때"}, {"id": "C", "text": "소수를 찾을 때"}, {"id": "D", "text": "확률을 계산할 때"}]', '["A"]', '중국인 나머지 정리는 여러 모듈로 나뉘어진 방정식을 동시에 해결할 때 유용하게 사용됩니다.'),
    (1126, 4, 2, 160, '그리디 알고리즘의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매 단계에서 최적의 선택을 한다."}, {"id": "B", "text": "모든 경우의 수를 고려한다."}, {"id": "C", "text": "복잡한 문제를 빠르게 해결할 수 있다."}, {"id": "D", "text": "항상 최적해를 보장한다."}]', 'A', '그리디 알고리즘은 매 단계에서 가장 유리한 선택을 하여 문제를 해결하는 방식입니다.'),
    (1127, 4, 2, 161, '다음 중 분할 가능 배낭 문제에 적용되는 알고리즘은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프림 알고리즘"}, {"id": "B", "text": "크루스칼 알고리즘"}, {"id": "C", "text": "허프만 코딩"}, {"id": "D", "text": "그리디 알고리즘"}]', 'D', '분할 가능 배낭 문제는 그리디 알고리즘을 사용하여 최적의 해를 찾습니다.'),
    (1128, 4, 2, 162, '다음 중 그리디 알고리즘을 사용하는 문제는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 스패닝 트리"}, {"id": "B", "text": "Fibonacci 수열"}, {"id": "C", "text": "최장 공통 부분 수열"}, {"id": "D", "text": "최단 경로"}]', 'A', '최소 스패닝 트리 문제는 프림 또는 크루스칼 알고리즘을 사용하여 해결할 수 있는 그리디 문제입니다.'),
    (1129, 4, 2, 163, '그리디 알고리즘과 DP의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "그리디는 최적해를 항상 보장한다."}, {"id": "B", "text": "DP는 중복 문제를 해결할 수 있다."}, {"id": "C", "text": "그리디는 매 단계에서 최적의 선택을 한다."}, {"id": "D", "text": "DP는 모든 경우의 수를 탐색한다."}]', '["B", "C", "D"]', '그리디는 매 단계에서 최적의 선택을 하지만, 항상 최적해를 보장하지는 않으며, DP는 중복 문제를 해결하고 모든 경우의 수를 탐색합니다.'),
    (1130, 4, 2, 164, '회의실 배정 문제를 해결할 때 사용되는 기본 전략은 무엇인가?', 'SHORT_ANSWER', NULL, '회의 종료 시간을 기준으로 정렬하여 다음 회의를 선택하는 것', '회의실 배정 문제에서는 회의 종료 시간을 기준으로 정렬하여 가능한 최대 회의 수를 배정합니다.'),
    (1131, 4, 2, 165, '에라토스테네스의 체는 무엇을 구하는 알고리즘인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소수"}, {"id": "B", "text": "합"}, {"id": "C", "text": "최대 공약수"}, {"id": "D", "text": "최소 공배수"}]', 'A', '에라토스테네스의 체는 주어진 범위 내의 모든 소수를 구하는 알고리즘입니다.'),
    (1132, 4, 2, 166, '조합론에서 이항 계수는 무엇을 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "주어진 수의 소인수"}, {"id": "B", "text": "집합에서 선택할 수 있는 방법의 수"}, {"id": "C", "text": "확률의 합"}, {"id": "D", "text": "최대 공약수"}]', 'B', '이항 계수는 특정 집합에서 특정 개수를 선택하는 방법의 수를 나타냅니다.'),
    (1133, 4, 2, 167, '페르마 소정리에 따르면, p가 소수일 때 어떤 관계가 성립하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "a^p ≡ a (mod p)"}, {"id": "B", "text": "a^p ≡ 1 (mod p)"}, {"id": "C", "text": "a^p ≡ 0 (mod p)"}, {"id": "D", "text": "a^p ≡ a^2 (mod p)"}]', 'A', '페르마 소정리에 따르면, p가 소수일 때 a^p ≡ a (mod p) 관계가 성립합니다.'),
    (1134, 4, 2, 168, '다음 중 소인수분해에 대한 설명으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 정수는 소수의 곱으로 표현될 수 있다."}, {"id": "B", "text": "소인수분해는 항상 유일하다."}, {"id": "C", "text": "소인수분해는 소수의 순서를 고려해야 한다."}, {"id": "D", "text": "소수는 1을 포함한다."}]', '["A", "B"]', '모든 정수는 소수의 곱으로 유일하게 표현될 수 있으며, 이는 소인수분해의 기본 성질입니다.'),
    (1135, 4, 2, 169, '확률의 기댓값이란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '확률변수가 취할 수 있는 값의 평균', ''),
    (1136, 4, 2, 170, '그리디 알고리즘의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 선택이 최적의 해를 보장한다."}, {"id": "B", "text": "매 순간 그리디 선택을 한다."}, {"id": "C", "text": "최적해를 반드시 찾는다."}, {"id": "D", "text": "모든 경우의 수를 고려한다."}]', 'B', '그리디 알고리즘은 매 순간 최적의 선택을 하는 방식을 채택합니다.'),
    (1137, 4, 2, 171, '프림 알고리즘과 크루스칼 알고리즘의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그래프의 모든 정점을 포함한다."}, {"id": "B", "text": "가중치가 없는 그래프에서만 작동한다."}, {"id": "C", "text": "최소 신장 트리를 찾는다."}, {"id": "D", "text": "모두 다이나믹 프로그래밍이다."}]', 'C', '두 알고리즘 모두 최소 신장 트리를 찾는 데 사용됩니다.'),
    (1138, 4, 2, 172, '허프만 코딩은 어떤 목적으로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 복구"}, {"id": "B", "text": "데이터 압축"}, {"id": "C", "text": "네트워크 라우팅"}, {"id": "D", "text": "암호화"}]', 'B', '허프만 코딩은 데이터 압축을 위한 알고리즘입니다.'),
    (1139, 4, 2, 173, '그리디 알고리즘을 사용할 수 있는 예시를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "거스름돈 문제"}, {"id": "B", "text": "최소 신장 트리"}, {"id": "C", "text": "최단 경로 찾기"}, {"id": "D", "text": "허프만 코딩"}]', '["A", "B", "D"]', '거스름돈 문제, 최소 신장 트리, 허프만 코딩은 그리디 알고리즘을 활용한 사례입니다.'),
    (1140, 4, 2, 174, '최소 신장 트리는 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '가장 적은 가중치의 간선으로 모든 정점을 연결하는 트리', '최소 신장 트리는 그래프의 모든 정점을 포함하면서 가중치를 최소화하는 트리입니다.'),
    (1141, 4, 2, 175, '다이나믹 프로그래밍에서 최적 부분 구조란 무엇인가?', 'SHORT_ANSWER', NULL, '문제를 최적화하기 위해 하위 문제의 최적 해를 이용할 수 있는 속성', '최적 부분 구조는 큰 문제를 해결하기 위해 그 문제의 하위 문제들을 최적화하여 해결할 수 있는 성질을 의미합니다.'),
    (1142, 4, 2, 176, '최장 증가 부분수열(LIS)의 점화식은 무엇일까요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "LIS[i] = max(LIS[j]) + 1 (j < i, arr[j] < arr[i])"}, {"id": "B", "text": "LIS[i] = arr[i] + LIS[i-1]"}, {"id": "C", "text": "LIS[i] = LIS[i-1] + LIS[i-2]"}, {"id": "D", "text": "LIS[i] = min(LIS[j]) + 1 (j < i, arr[j] < arr[i])"}]', 'A', '최장 증가 부분수열의 점화식은 현재 위치 이전의 증가하는 부분수열의 최대 길이에 1을 더하는 형태입니다.'),
    (1143, 4, 2, 177, '동전 교환 문제에서 바텀업 접근법을 사용할 때의 장점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 사용량이 적다"}, {"id": "B", "text": "모든 경우의 수를 고려할 필요가 없다"}, {"id": "C", "text": "문제를 쉽게 시각화할 수 있다"}, {"id": "D", "text": "점화식을 만들 필요가 없다"}]', 'B', '바텀업 접근법은 작은 문제부터 해결하기 때문에 중복 계산을 피할 수 있으며, 모든 경우의 수를 고려하지 않고도 문제를 해결할 수 있습니다.'),
    (1144, 4, 2, 178, '메모이제이션이란 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "계산 결과를 저장하여 중복 계산을 피하는 기법"}, {"id": "B", "text": "문제를 하위 문제로 나누는 방식"}, {"id": "C", "text": "하위 문제의 결과를 반복적으로 계산하는 방식"}, {"id": "D", "text": "문제를 바텀업으로 해결하는 방법"}]', '["A", "B"]', '메모이제이션은 계산한 결과를 저장하여 중복 계산을 피하는 기법으로, 문제를 하위 문제로 나누어 해결하는 방식과 함께 사용됩니다.'),
    (1145, 4, 2, 179, 'Digit DP에서 주로 다루는 문제의 유형은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "숫자 관련 문제"}, {"id": "B", "text": "그래프 탐색 문제"}, {"id": "C", "text": "최소 비용 문제"}, {"id": "D", "text": "문자열 패턴 매칭 문제"}]', 'A', 'Digit DP는 숫자를 구성하는 각 자릿수를 고려하여 다양한 문제를 해결하는 데 사용됩니다.'),
    (1146, 4, 2, 180, '편집 거리 문제를 해결하기 위해 사용하는 기본적인 접근 방식은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동적 계획법"}, {"id": "B", "text": "탐욕 알고리즘"}, {"id": "C", "text": "분할 정복"}, {"id": "D", "text": "브루트 포스"}]', 'A', '편집 거리 문제는 동적 계획법을 이용하여 두 문자열 간의 최소 변환 작업을 계산합니다.'),
    (1147, 4, 2, 181, '트리 DP에서 주로 사용하는 트리의 성질은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사이클이 존재한다"}, {"id": "B", "text": "모든 노드는 하나의 부모를 가진다"}, {"id": "C", "text": "모든 노드는 모든 다른 노드와 연결된다"}, {"id": "D", "text": "모든 노드는 독립적이다"}]', 'B', '트리 구조에서 모든 노드는 하나의 부모를 가지며, 이를 통해 DP를 사용할 수 있습니다.'),
    (1148, 4, 2, 182, '확률 DP에서 주로 계산하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "기댓값"}, {"id": "B", "text": "최소 비용"}, {"id": "C", "text": "최대 이익"}, {"id": "D", "text": "경로 최적화"}]', '["A", "C"]', '확률 DP는 기댓값과 최대 이익을 계산하는 데 사용됩니다.'),
    (1149, 4, 2, 183, '볼록 껍질 트릭을 주로 사용하는 문제 유형은 무엇인가요?', 'SHORT_ANSWER', NULL, '선형 최적화 문제', '볼록 껍질 트릭은 주로 선형 최적화 문제를 해결하는 데 사용됩니다.'),
    (1150, 4, 2, 184, '다이나믹 프로그래밍에서 문제를 해결하는 기본적인 접근 방식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하위 문제로 나누기"}, {"id": "B", "text": "그리디 방식 사용"}, {"id": "C", "text": "완전 탐색"}, {"id": "D", "text": "구현 방식으로 해결"}]', 'A', '다이나믹 프로그래밍은 복잡한 문제를 하위 문제로 나누어 해결하는 방식입니다.'),
    (1151, 4, 2, 185, '최장 증가 부분수열 문제에서 DP 테이블의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분문제의 최적해를 저장"}, {"id": "B", "text": "입력값을 정렬"}, {"id": "C", "text": "문제를 난이도별로 분류"}, {"id": "D", "text": "결과를 출력하는 기능"}]', 'A', 'DP 테이블은 부분문제의 최적해를 저장하여, 중복 계산을 방지하고 효율성을 높입니다.'),
    (1152, 4, 2, 186, '다음 중 동전 교환 문제에서 사용할 수 없는 접근 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "탑다운 방식"}, {"id": "B", "text": "그리디 알고리즘"}, {"id": "C", "text": "피보나치 수열"}, {"id": "D", "text": "바텀업 방식"}]', 'C', '동전 교환 문제는 피보나치 수열과는 관련이 없으며, 주로 그리디 알고리즘이나 DP를 사용합니다.'),
    (1153, 4, 2, 187, '최장 공통 부분수열 문제는 어떤 방식으로 해결할 수 있는가? (복수 정답 선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DP 테이블 사용"}, {"id": "B", "text": "탑다운 방식"}, {"id": "C", "text": "그리디 방식"}, {"id": "D", "text": "바텀업 방식"}]', '["A", "D"]', '최장 공통 부분수열 문제는 DP 테이블을 사용하여 바텀업 방식으로 해결할 수 있습니다.'),
    (1154, 4, 2, 188, '피보나치 수열을 다이나믹 프로그래밍 방식으로 계산할 때, 어떤 기법을 주로 사용하는가?', 'SHORT_ANSWER', NULL, '점화식', '피보나치 수열을 계산할 때는 점화식을 사용하여 이전 값들을 기반으로 현재 값을 계산합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;
    
-- 알고리즘과 자료구조 > 고급 자료구조와 기법 (262문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (1155, 4, 3, 1, '세그먼트 트리의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 쿼리 처리"}, {"id": "B", "text": "그래프 탐색"}, {"id": "C", "text": "정렬 알고리즘"}, {"id": "D", "text": "해시 테이블 구현"}]', 'A', '세그먼트 트리는 구간 쿼리 처리에 최적화된 자료구조입니다.'),
    (1156, 4, 3, 2, '펜윅 트리의 다른 이름은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "세그먼트 트리"}, {"id": "B", "text": "BIT"}, {"id": "C", "text": "AVL 트리"}, {"id": "D", "text": "B-트리"}]', 'B', '펜윅 트리는 BIT(Binary Indexed Tree)로도 알려져 있습니다.'),
    (1157, 4, 3, 3, '퍼시스턴트 세그먼트 트리의 특징은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변경 이력을 저장할 수 있다"}, {"id": "B", "text": "구간 쿼리 속도가 느리다"}, {"id": "C", "text": "데이터 구조의 크기가 고정된다"}, {"id": "D", "text": "불변성을 유지한다"}]', '["A", "D"]', '퍼시스턴트 세그먼트 트리는 변경 이력을 저장할 수 있고, 데이터 구조의 불변성을 유지합니다.'),
    (1158, 4, 3, 4, '트리의 지름을 찾기 위해 일반적으로 사용하는 기법은 무엇인가요?', 'SHORT_ANSWER', NULL, '오일러 투어', '트리의 지름을 찾기 위해 오일러 투어 기법을 사용할 수 있습니다.'),
    (1159, 4, 3, 5, '라빈-카프 알고리즘에서 사용하는 주요 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 해싱"}, {"id": "B", "text": "정규표현식"}, {"id": "C", "text": "Suffix Array"}, {"id": "D", "text": "회문 판별"}]', 'A', '라빈-카프 알고리즘은 문자열 해싱을 사용하여 패턴을 효율적으로 검색합니다.'),
    (1160, 4, 3, 6, 'KMP 알고리즘의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열을 정렬한다."}, {"id": "B", "text": "패턴의 중복을 피한다."}, {"id": "C", "text": "회문을 판별한다."}, {"id": "D", "text": "정규표현식을 사용한다."}]', 'B', 'KMP 알고리즘은 패턴의 중복을 피하여 검색 효율을 높이는 방식으로 작동합니다.'),
    (1161, 4, 3, 7, 'Suffix Array의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패턴 찾기"}, {"id": "B", "text": "문자열 정렬"}, {"id": "C", "text": "접미사 정렬"}, {"id": "D", "text": "회문 검증"}]', 'C', 'Suffix Array는 모든 접미사를 정렬하여 효율적인 검색을 가능하게 합니다.'),
    (1162, 4, 3, 8, '다음 중 문자열 해싱 알고리즘에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "라빈-카프"}, {"id": "B", "text": "KMP"}, {"id": "C", "text": "BM"}, {"id": "D", "text": "Trie"}]', '["A", "C"]', '라빈-카프 알고리즘과 BM 알고리즘은 문자열 해싱 기법을 사용하여 패턴을 찾습니다.'),
    (1163, 4, 3, 9, '회문이란 무엇인가?', 'SHORT_ANSWER', NULL, '앞뒤가 같은 문자열', '회문은 앞에서 읽으나 뒤에서 읽으나 동일한 문자열을 의미합니다.'),
    (1164, 4, 3, 10, '강한 연결 성분(SCC)의 정의는 무엇인가요?', 'SHORT_ANSWER', NULL, '정점 간의 경로가 서로 존재하는 서브그래프', 'SCC는 그래프 내의 모든 정점 쌍 사이에 경로가 존재하는 부분 그래프를 의미합니다.'),
    (1165, 4, 3, 11, '다익스트라 알고리즘에서 우선순위 큐를 사용하는 이유는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 짧은 경로를 효율적으로 찾기 위해"}, {"id": "B", "text": "모든 정점을 동시에 방문하기 위해"}, {"id": "C", "text": "그래프의 모든 경로를 탐색하기 위해"}, {"id": "D", "text": "정점의 개수를 줄이기 위해"}]', 'A', '우선순위 큐는 현재까지 발견한 최단 경로를 기반으로 가장 짧은 경로를 가진 정점을 효율적으로 선택하기 위해 사용됩니다.'),
    (1166, 4, 3, 12, '위상 정렬은 어떤 경우에 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사이클이 없는 방향 그래프에서"}, {"id": "B", "text": "모든 그래프에서"}, {"id": "C", "text": "비방향 그래프에서"}, {"id": "D", "text": "음수 가중치 그래프에서"}]', 'A', '위상 정렬은 사이클이 없는 방향 그래프에서 정점들을 선형으로 정렬하는 방법입니다.'),
    (1167, 4, 3, 13, '다음 중 단절점에 해당하는 조건은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "그 정점을 제거했을 때 그래프의 연결성이 깨질 때"}, {"id": "B", "text": "해당 정점이 리프 노드일 때"}, {"id": "C", "text": "해당 정점이 모서리의 수가 적을 때"}, {"id": "D", "text": "그래프의 모든 경로가 그 정점을 포함할 때"}]', '["A", "D"]', '단절점은 해당 정점을 제거했을 때 그래프의 연결성이 깨지며, 모든 경로가 그 정점을 포함할 경우 단절점으로 작용합니다.'),
    (1168, 4, 3, 14, '세그먼트 트리는 어떤 종류의 쿼리를 효율적으로 처리하는 데 사용되는가?', 'SHORT_ANSWER', NULL, '구간 쿼리', '세그먼트 트리는 구간 쿼리를 효율적으로 처리하기 위해 설계된 자료구조이다.'),
    (1169, 4, 3, 15, 'B-Tree의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 시스템에서의 데이터 관리"}, {"id": "B", "text": "정렬된 배열의 구현"}, {"id": "C", "text": "그래프 탐색 알고리즘"}, {"id": "D", "text": "연결 리스트 구현"}]', 'A', 'B-Tree는 주로 데이터베이스와 파일 시스템에서 효율적인 데이터 관리를 위해 사용된다.'),
    (1170, 4, 3, 16, '최대 힙의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부모 노드가 자식 노드보다 항상 크다"}, {"id": "B", "text": "부모 노드가 자식 노드보다 항상 작다"}, {"id": "C", "text": "모든 노드가 같은 값을 가진다"}, {"id": "D", "text": "트리가 반드시 완전 이진 트리다"}]', 'A', '최대 힙에서는 각 부모 노드가 자식 노드보다 항상 큰 값을 가지도록 유지된다.'),
    (1171, 4, 3, 17, '다음 중 비선형 자료구조에 해당하는 것은 무엇인가? (복수 정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이진 탐색 트리(BST)"}, {"id": "B", "text": "배열"}, {"id": "C", "text": "세그먼트 트리"}, {"id": "D", "text": "힙"}]', '["A", "C", "D"]', '이진 탐색 트리(BST), 세그먼트 트리, 힙은 모두 비선형 자료구조에 해당한다.'),
    (1172, 4, 3, 18, 'Z 알고리즘의 주요 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열의 접미사를 정렬하는 것"}, {"id": "B", "text": "문자열 내에서 패턴을 찾는 것"}, {"id": "C", "text": "문자열을 해싱하는 것"}, {"id": "D", "text": "회문을 판별하는 것"}]', 'B', 'Z 알고리즘은 문자열 내에서 특정 패턴을 효율적으로 찾기 위한 알고리즘입니다.'),
    (1173, 4, 3, 19, '아호-코라식 알고리즘은 어떤 문제를 해결하기 위해 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정규 표현식 작성"}, {"id": "B", "text": "여러 패턴을 동시에 검색"}, {"id": "C", "text": "문자열 정렬"}, {"id": "D", "text": "문자열 해싱"}]', 'B', '아호-코라식 알고리즘은 여러 패턴을 동시에 효율적으로 검색하기 위해 사용됩니다.'),
    (1174, 4, 3, 20, '다음 중 회문을 판별하는 방법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열을 뒤집어서 비교하기"}, {"id": "B", "text": "모든 문자 조합을 생성하기"}, {"id": "C", "text": "양쪽 끝에서부터 비교하기"}, {"id": "D", "text": "정규 표현식 사용하기"}]', 'B', '모든 문자 조합을 생성하는 것은 회문 판별의 일반적인 방법이 아닙니다.'),
    (1175, 4, 3, 21, '문자열 해싱의 장점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "빠른 검색 속도"}, {"id": "B", "text": "메모리 절약"}, {"id": "C", "text": "데이터의 무결성 보장"}, {"id": "D", "text": "정렬된 데이터 유지"}]', '["A", "B", "C"]', '문자열 해싱은 빠른 검색 속도와 메모리 절약을 제공하며, 무결성을 보장하는 데도 도움이 됩니다.'),
    (1176, 4, 3, 22, '회문 판별을 위한 간단한 알고리즘을 설명하시오.', 'SHORT_ANSWER', NULL, '문자열을 뒤집어서 원래 문자열과 비교한다.', '회문 판별은 문자열을 뒤집은 후 원래 문자열과 동일한지 비교하는 간단한 방법입니다.'),
    (1177, 4, 3, 23, '해시 테이블의 로드 팩터란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '사용된 슬롯 수와 전체 슬롯 수의 비율', '로드 팩터는 해시 테이블에서 사용된 슬롯 수와 전체 슬롯 수의 비율을 나타내며, 성능과 관련이 깊다.'),
    (1178, 4, 3, 24, '다음 중 해시 충돌을 해결하기 위한 방법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "리해싱"}, {"id": "C", "text": "이진 검색"}, {"id": "D", "text": "개방 주소법"}]', 'C', '이진 검색은 해시 충돌 해결 방법이 아닌 검색 알고리즘이다.'),
    (1179, 4, 3, 25, '해시셋의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 값을 허용한다."}, {"id": "B", "text": "객체의 순서를 유지한다."}, {"id": "C", "text": "유니크한 값을 저장한다."}, {"id": "D", "text": "데이터 검색 속도가 느리다."}]', 'C', '해시셋은 유니크한 값만 저장하며 중복값을 허용하지 않는다.'),
    (1180, 4, 3, 26, '해시 함수의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 암호화한다."}, {"id": "B", "text": "데이터를 인덱스화한다."}, {"id": "C", "text": "데이터를 저장소에 분산시킨다."}, {"id": "D", "text": "데이터를 정렬한다."}]', '["B", "C"]', '해시 함수는 데이터를 인덱스화하여 해시 테이블에 저장하고, 이를 통해 데이터의 저장소를 효율적으로 분산시킨다.'),
    (1181, 4, 3, 27, '이진 탐색 트리에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드의 왼쪽 자식은 노드보다 작다."}, {"id": "B", "text": "모든 노드의 오른쪽 자식은 노드보다 크지 않다."}, {"id": "C", "text": "노드의 자식 개수는 항상 2개이다."}, {"id": "D", "text": "모든 노드는 균형을 유지해야 한다."}]', 'A', '이진 탐색 트리는 왼쪽 자식은 항상 부모 노드보다 작고, 오른쪽 자식은 클 수 있도록 구성됩니다.'),
    (1182, 4, 3, 28, '레드-블랙 트리의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드는 레드 또는 블랙이다."}, {"id": "B", "text": "루트 노드는 항상 레드이다."}, {"id": "C", "text": "모든 리프 노드는 블랙이다."}, {"id": "D", "text": "레드 노드는 연속될 수 없다."}]', 'B', '레드-블랙 트리에서 루트 노드는 항상 블랙이어야 합니다.'),
    (1183, 4, 3, 29, '그래프의 인접 리스트 표현 방식의 장점은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 사용이 절약된다."}, {"id": "B", "text": "모든 간선을 쉽게 찾을 수 있다."}, {"id": "C", "text": "그래프의 모든 노드를 정렬할 수 있다."}, {"id": "D", "text": "트리 구조로 변환할 수 있다."}]', 'A', '인접 리스트는 그래프의 간선이 적을 때 메모리 사용이 효율적입니다.'),
    (1184, 4, 3, 30, '세그먼트 트리를 사용하여 해결할 수 있는 문제는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구간 합 쿼리"}, {"id": "B", "text": "최대값 쿼리"}, {"id": "C", "text": "최소값 쿼리"}, {"id": "D", "text": "정렬된 배열 만들기"}]', '["A", "B", "C"]', '세그먼트 트리는 구간 합, 최대값 및 최소값 쿼리를 효율적으로 처리할 수 있습니다.'),
    (1185, 4, 3, 31, '최대 힙에서 부모 노드는 자식 노드보다 어떤 관계를 가져야 하는가?', 'SHORT_ANSWER', NULL, '부모 노드는 자식 노드보다 크거나 같다.', '최대 힙의 특징은 부모 노드가 자식 노드보다 항상 크거나 같다는 것입니다.'),
    (1186, 4, 3, 32, '백트래킹 기법의 주된 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "재귀를 사용하여 모든 경우를 탐색한다."}, {"id": "B", "text": "항상 최적의 해를 보장한다."}, {"id": "C", "text": "주어진 문제를 나누어 푸는 방식이다."}, {"id": "D", "text": "정렬된 배열에서만 사용된다."}]', 'A', '백트래킹은 재귀적인 방법으로 가능한 모든 경우를 탐색하여 최적의 해를 찾기 위한 기법입니다.'),
    (1187, 4, 3, 33, '분할 정복 기법의 주요 단계는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문제를 나누고 해결한 후 합친다."}, {"id": "B", "text": "모든 경우를 나열한다."}, {"id": "C", "text": "계산된 값을 저장하여 재사용한다."}, {"id": "D", "text": "일정한 간격으로 데이터를 필터링한다."}]', 'A', '분할 정복은 문제를 여러 개의 하위 문제로 나누고, 각 문제를 해결한 후 그 결과를 합치는 방식으로 동작합니다.'),
    (1188, 4, 3, 34, '누적합 기법의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열의 모든 부분합을 빠르게 계산할 수 있다."}, {"id": "B", "text": "메모리를 절약할 수 있다."}, {"id": "C", "text": "정렬된 데이터를 유지할 수 있다."}, {"id": "D", "text": "모든 경우의 수를 탐색할 수 있다."}]', 'A', '누적합은 배열의 부분합을 미리 계산해 두어 빠르게 값을 구하는 데 효율적입니다.'),
    (1189, 4, 3, 35, '슬라이딩 윈도우 기법은 어떤 상황에서 주로 사용되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "고정된 크기의 구간에서 문제를 해결할 때."}, {"id": "B", "text": "정렬이 필요한 경우."}, {"id": "C", "text": "동적 프로그래밍 문제."}, {"id": "D", "text": "부분 배열의 최대값을 찾을 때."}]', '["A", "D"]', '슬라이딩 윈도우 기법은 고정된 크기의 구간에서 문제를 해결할 때와 부분 배열의 최대값을 찾을 때 주로 사용됩니다.'),
    (1190, 4, 3, 36, '좌표 압축이 주로 사용되는 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '메모리 사용을 줄이기 위해서입니다.', '좌표 압축은 넓은 범위의 좌표를 작은 범위로 변환하여 메모리 사용을 줄이는 기술입니다.'),
    (1191, 4, 3, 37, '해시 충돌이란 무엇인가요?', 'SHORT_ANSWER', NULL, '서로 다른 데이터가 동일한 해시 값을 가질 때 발생하는 현상입니다.', '해시 충돌은 해시 기반 자료구조에서 기본적으로 발생할 수 있는 문제로, 이를 잘 관리해야 데이터의 효율적인 접근이 가능합니다.'),
    (1192, 4, 3, 38, '다음 중 체이닝 방식의 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해시 버킷에 연결 리스트를 사용하는 방법입니다."}, {"id": "B", "text": "해시 버킷의 빈 공간을 찾아 데이터를 저장하는 방법입니다."}, {"id": "C", "text": "리해싱을 통해 해시 테이블의 크기를 증가시키는 방법입니다."}, {"id": "D", "text": "해시 값을 직접 비교하여 데이터를 찾는 방법입니다."}]', 'A', '체이닝은 해시 버킷에 동일한 해시 값을 가진 데이터를 연결 리스트로 저장하여 충돌을 처리하는 방식입니다.'),
    (1193, 4, 3, 39, 'HashSet의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 값을 허용합니다."}, {"id": "B", "text": "순서가 보장됩니다."}, {"id": "C", "text": "해시 함수를 사용하여 데이터에 접근합니다."}, {"id": "D", "text": "리스트 형태로 데이터를 저장합니다."}]', 'C', 'HashSet은 해시 함수를 기반으로 하여 데이터를 저장하고 접근하며, 중복된 값을 허용하지 않습니다.'),
    (1194, 4, 3, 40, '해시 기반 자료구조에서 충돌 해결 방법으로 올바른 것을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 어드레싱"}, {"id": "C", "text": "정렬"}, {"id": "D", "text": "리해싱"}]', '["A", "B", "D"]', '체이닝, 오픈 어드레싱, 리해싱은 모두 해시 충돌을 해결하기 위한 방법입니다. 정렬은 해시 기반 자료구조와 관련이 없습니다.'),
    (1195, 4, 3, 41, '리해싱의 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬하는 것"}, {"id": "B", "text": "해시 테이블의 크기를 조정하여 성능을 개선하는 것"}, {"id": "C", "text": "중복 데이터를 제거하는 것"}, {"id": "D", "text": "데이터를 암호화하는 것"}]', 'B', '리해싱은 해시 테이블의 크기를 조정하여 해시 충돌을 줄이고 성능을 개선하는 것을 목적으로 합니다.'),
    (1196, 4, 3, 42, '백트래킹에서 가장 주로 사용되는 문제 유형은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "조합 문제"}, {"id": "B", "text": "정렬 문제"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "동적 프로그래밍"}]', 'A', '백트래킹은 가능한 모든 경우를 탐색하여 조건을 만족하는 해를 찾는 방법으로 주로 조합 문제에 사용됩니다.'),
    (1197, 4, 3, 43, '슬라이딩 윈도우 기법이 사용되는 경우는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속된 부분 배열의 합"}, {"id": "B", "text": "정렬된 배열의 탐색"}, {"id": "C", "text": "그래프의 최단 경로"}, {"id": "D", "text": "문자열 검색"}]', 'A', '슬라이딩 윈도우 기법은 연속된 데이터의 부분 배열을 다루는 문제에서 효율적으로 최적의 해를 구하는 데 사용됩니다.'),
    (1198, 4, 3, 44, '다음 중 누적합의 주요 장점이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 합을 빠르게 계산할 수 있다"}, {"id": "B", "text": "메모리 사용량이 적다"}, {"id": "C", "text": "사전 처리 과정이 필요하다"}, {"id": "D", "text": "성능 개선에 기여한다"}]', 'B', '누적합은 부분 합을 빠르게 계산할 수 있도록 도와주지만, 배열을 추가적으로 저장해야 하므로 메모리 사용량이 늘어날 수 있습니다.'),
    (1199, 4, 3, 45, '이분 탐색을 적용할 수 있는 조건은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "배열이 정렬되어 있어야 한다"}, {"id": "B", "text": "배열의 크기가 작아야 한다"}, {"id": "C", "text": "중복된 값이 없어야 한다"}, {"id": "D", "text": "탐색 대상이 명확해야 한다"}]', '["A", "D"]', '이분 탐색은 배열이 정렬되어 있어야 하며, 탐색 대상이 명확해야 효과적으로 작동합니다.'),
    (1200, 4, 3, 46, '비트마스킹의 주된 활용 방식은 무엇인가요?', 'SHORT_ANSWER', NULL, '상태 관리 및 조합 표현', '비트마스킹은 비트 연산을 활용하여 상태를 관리하거나 조합을 표현하는 데 주로 사용됩니다.'),
    (1201, 4, 3, 47, '트라이는 무엇을 주로 사용하는 자료구조인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열의 접두사 탐색"}, {"id": "B", "text": "정수 배열의 정렬"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "트리 구조의 최단 경로"}]', 'A', '트라이는 문자열의 접두사 탐색 및 서브 문자열 검색에 주로 사용하는 자료구조입니다.'),
    (1202, 4, 3, 48, 'Z 알고리즘은 어떤 작업에 주로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패턴 매칭"}, {"id": "B", "text": "정수 덧셈"}, {"id": "C", "text": "그래프 최단 경로"}, {"id": "D", "text": "배열의 역순 정렬"}]', 'A', 'Z 알고리즘은 문자열 내에서 패턴을 찾는 데 주로 사용되는 알고리즘입니다.'),
    (1203, 4, 3, 49, '아호-코라식 알고리즘의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정확한 패턴 매칭을 보장한다"}, {"id": "B", "text": "단일 패턴만 찾을 수 있다"}, {"id": "C", "text": "시간 복잡도가 O(n^2)이다"}, {"id": "D", "text": "문자열을 정렬하는데 사용된다"}]', 'A', '아호-코라식 알고리즘은 정확한 패턴 매칭을 보장하는 효율적인 방법입니다.'),
    (1204, 4, 3, 50, '다음 중 LCP 배열을 구성하는 요소는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "문자열의 길이"}, {"id": "B", "text": "접두사 길이"}, {"id": "C", "text": "문자열의 발생 빈도"}, {"id": "D", "text": "문자열의 정렬 위치"}]', '["B", "D"]', 'LCP 배열은 문자열의 접두사 사이의 최대 공통 접두사 길이를 저장하며, Suffix Array의 정렬 위치와 관련이 있습니다.'),
    (1205, 4, 3, 51, '정규 표현식의 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '문자열 패턴 매칭 및 검색', '정규 표현식은 문자열에서 특정 패턴을 매칭하고 검색하는 데 사용됩니다.'),
    (1206, 4, 3, 52, '이진 인덱스 트리의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 빠른 범위 쿼리 수행"}, {"id": "B", "text": "데이터를 정렬하는 것"}, {"id": "C", "text": "트리의 깊이를 계산하는 것"}, {"id": "D", "text": "최소 공통 조상을 찾는 것"}]', 'A', '이진 인덱스 트리는 데이터의 빠른 범위 쿼리를 수행하기 위한 자료구조입니다.'),
    (1207, 4, 3, 53, '세그먼트 트리의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 업데이트를 지원하지 않는다"}, {"id": "B", "text": "구간 쿼리와 업데이트에 효율적이다"}, {"id": "C", "text": "항상 정렬된 형태로 데이터를 저장한다"}, {"id": "D", "text": "최소 공통 조상을 찾는 데 사용된다"}]', 'B', '세그먼트 트리는 구간 쿼리와 업데이트에 효율적인 자료구조입니다.'),
    (1208, 4, 3, 54, 'HLD(Heavy Light Decomposition)의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리를 분할하여 경로 쿼리를 최적화한다"}, {"id": "B", "text": "트리를 정렬하는 것이다"}, {"id": "C", "text": "트리의 깊이를 최소화하는 것이다"}, {"id": "D", "text": "구간 쿼리를 처리하는 것만을 목적으로 한다"}]', 'A', 'HLD의 주된 목적은 트리를 분할하여 경로 쿼리를 최적화하는 것입니다.'),
    (1209, 4, 3, 55, '세그먼트 트리와 관련된 기법 중 구간 쿼리와 업데이트 작업을 지원하는 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "세그먼트 트리"}, {"id": "B", "text": "이진 인덱스 트리"}, {"id": "C", "text": "스플레이 트리"}, {"id": "D", "text": "머지 소트 트리"}]', '["A", "B"]', '세그먼트 트리와 이진 인덱스 트리는 모두 구간 쿼리와 업데이트 작업을 지원하는 기법입니다.'),
    (1210, 4, 3, 56, '최소 공통 조상(LCA)을 찾기 위한 일반적인 방법은 무엇인가?', 'SHORT_ANSWER', NULL, '오일러 투어와 세그먼트 트리 또는 LCA 알고리즘을 사용한다.', '최소 공통 조상을 찾기 위해 오일러 투어와 세그먼트 트리 또는 LCA 알고리즘을 사용할 수 있습니다.'),
    (1211, 4, 3, 57, '슬라이딩 윈도우 기법의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속된 부분 집합의 최적 결과를 찾기 위해"}, {"id": "B", "text": "모든 가능한 조합을 탐색하기 위해"}, {"id": "C", "text": "데이터를 정렬하기 위해"}, {"id": "D", "text": "이진 탐색을 수행하기 위해"}]', 'A', '슬라이딩 윈도우 기법은 연속된 부분 집합을 다루는 데 최적의 성능을 발휘합니다.'),
    (1212, 4, 3, 58, '투 포인터 기법은 주로 무엇을 목적으로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서 두 수의 합을 찾기 위해"}, {"id": "B", "text": "그래프를 탐색하기 위해"}, {"id": "C", "text": "데이터를 압축하기 위해"}, {"id": "D", "text": "비트 연산을 수행하기 위해"}]', 'A', '투 포인터 기법은 주로 정렬된 배열에서 두 수의 합을 찾는 데 효과적입니다.'),
    (1213, 4, 3, 59, '아래 중 좌표 압축을 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 사용을 최적화하기 위해"}, {"id": "B", "text": "시간 복잡도를 줄이기 위해"}, {"id": "C", "text": "데이터를 정렬하기 위해"}, {"id": "D", "text": "특정 범위의 값을 다루기 위해"}]', '["A", "D"]', '좌표 압축은 메모리 사용을 최적화하고 특정 범위의 값을 다루는 데 효과적입니다.'),
    (1214, 4, 3, 60, '유니온 파인드의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '집합의 조합을 효율적으로 관리하기 위해', ''),
    (1215, 4, 3, 61, '다익스트라 알고리즘에서 사용하는 자료구조는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "우선순위 큐"}, {"id": "B", "text": "스택"}, {"id": "C", "text": "큐"}, {"id": "D", "text": "리스트"}]', 'A', '다익스트라 알고리즘은 최단 경로를 구하기 위해 우선순위 큐를 사용하여 현재까지의 최단 거리 정보를 관리합니다.'),
    (1216, 4, 3, 62, '이분 그래프는 어떻게 정의되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 개의 독립적인 집합으로 나눌 수 있는 그래프"}, {"id": "B", "text": "모든 정점이 연결된 그래프"}, {"id": "C", "text": "사이클이 없는 그래프"}, {"id": "D", "text": "모든 정점의 차수가 홀수인 그래프"}]', 'A', '이분 그래프는 정점을 두 개의 집합으로 나눌 수 있으며, 같은 집합의 정점끼리는 간선으로 연결되지 않는 그래프입니다.'),
    (1217, 4, 3, 63, '최소 신장 트리를 찾기 위한 알고리즘 중 크루스칼 알고리즘의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 작은 가중치의 간선부터 선택하여 트리를 구축"}, {"id": "B", "text": "트리의 깊이를 우선 고려하여 간선 선택"}, {"id": "C", "text": "정점의 수를 기준으로 간선 선택"}, {"id": "D", "text": "윗쪽에서 아래쪽으로 간선을 선택"}]', 'A', '크루스칼 알고리즘은 가중치가 가장 작은 간선부터 선택하여 최소 신장 트리를 구성하는 방식입니다.'),
    (1218, 4, 3, 64, '다음 중 강한 연결 성분(SCC) 알고리즘에 해당하는 것은 무엇인가? ', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "타잔 알고리즘"}, {"id": "B", "text": "크루스칼 알고리즘"}, {"id": "C", "text": "코사라주 알고리즘"}, {"id": "D", "text": "다익스트라 알고리즘"}]', '["A", "C"]', '타잔 알고리즘과 코사라주 알고리즘 모두 강한 연결 성분을 찾기 위한 알고리즘입니다.'),
    (1219, 4, 3, 65, '0-1 BFS의 가장 큰 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '가중치가 0 또는 1인 그래프에서 최단 경로를 찾는 특수한 BFS 방법이다.', '0-1 BFS는 간선의 가중치가 0 또는 1인 경우에 최단 경로를 효율적으로 찾기 위해 사용되는 BFS의 변형입니다.'),
    (1220, 4, 3, 66, '세그먼트 트리는 주로 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 쿼리 처리"}, {"id": "B", "text": "정렬"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "문자열 검색"}]', 'A', '세그먼트 트리는 구간 쿼리 처리에 매우 효율적이다.'),
    (1221, 4, 3, 67, '좌표 압축의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 최적화"}, {"id": "B", "text": "속도 향상"}, {"id": "C", "text": "코드 간결성"}, {"id": "D", "text": "데이터 정렬"}]', 'A', '좌표 압축은 큰 범위의 값을 작은 값으로 변환하여 메모리 사용을 최적화하는 기법이다.'),
    (1222, 4, 3, 68, '다음 중 투 포인터 기법을 사용하는 경우는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열에서 합이 특정 값인 쌍 찾기"}, {"id": "B", "text": "모든 조합 생성"}, {"id": "C", "text": "최대값 찾기"}, {"id": "D", "text": "정수 정렬"}]', 'A', '투 포인터 기법은 배열에서 특정 조건에 맞는 쌍을 찾는 데 유용하다.'),
    (1223, 4, 3, 69, '스위핑 기법과 관련된 알고리즘은 어떤 것들이 있는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구간 합"}, {"id": "B", "text": "최소 공통 조상"}, {"id": "C", "text": "중복 없는 부분 집합"}, {"id": "D", "text": "최대 직사각형"}]', '["A", "D"]', '스위핑 기법은 구간 합과 최대 직사각형 문제를 해결하는 데 사용될 수 있다.'),
    (1224, 4, 3, 70, '이분 탐색을 응용하면 어떤 문제를 쉽게 해결할 수 있는가?', 'SHORT_ANSWER', NULL, '정렬된 배열에서 특정 값의 존재 여부 확인', '이분 탐색은 정렬된 데이터에서 값을 빠르게 찾는 데 사용된다.'),
    (1225, 4, 3, 71, '2-3 트리의 주요 특성은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드가 2개 또는 3개의 자식을 가질 수 있다."}, {"id": "B", "text": "모든 노드가 2개의 자식을 가진다."}, {"id": "C", "text": "노드의 값은 항상 정렬되어 있다."}, {"id": "D", "text": "트리는 단순히 연결된 리스트로 구성된다."}]', 'A', '2-3 트리는 각 노드가 2개 또는 3개의 자식을 가질 수 있는 균형 잡힌 트리입니다.'),
    (1226, 4, 3, 72, 'HLD의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 텍스트 검색을 위한 기법이다."}, {"id": "B", "text": "트리의 쿼리 성능을 최적화하기 위한 기법이다."}, {"id": "C", "text": "데이터를 정렬하는 기법이다."}, {"id": "D", "text": "그래프의 경로를 찾기 위한 기법이다."}]', 'B', 'HLD는 트리에서 경로 쿼리를 효율적으로 처리하기 위한 기법입니다.'),
    (1227, 4, 3, 73, '펜윅 트리는 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 공통 조상을 찾기 위해 사용된다."}, {"id": "B", "text": "구간 합 쿼리를 효율적으로 처리하기 위해 사용된다."}, {"id": "C", "text": "트리의 지름을 계산하기 위해 사용된다."}, {"id": "D", "text": "트리를 정렬하기 위해 사용된다."}]', 'B', '펜윅 트리는 특정 구간의 합을 효율적으로 계산하기 위해 사용되는 자료구조입니다.'),
    (1228, 4, 3, 74, '최소 공통 조상(LCA) 문제를 해결하기 위해 사용할 수 있는 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "DFS 탐색을 이용한 방법"}, {"id": "B", "text": "스플레이 트리 이용"}, {"id": "C", "text": "세그먼트 트리 이용"}, {"id": "D", "text": "이진 트리의 깊이를 이용한 방법"}]', '["A", "D"]', 'LCA 문제는 DFS 탐색이나 이진 트리의 깊이를 이용해 해결할 수 있습니다.'),
    (1229, 4, 3, 75, '스플레이 트리의 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '자주 접근되는 노드를 루트로 이동시키는 성질을 가진다.', '스플레이 트리는 자주 참조되는 노드를 루트로 올려 성능을 최적화하는 트리입니다.'),
    (1230, 4, 3, 76, '분할 정복 기법은 어떤 방식으로 문제를 해결하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문제를 더 작은 문제로 나누어 해결한 후 결과를 결합한다."}, {"id": "B", "text": "모든 경우를 시도하여 답을 찾는다."}, {"id": "C", "text": "데이터를 정렬한 후 이분 검색을 한다."}, {"id": "D", "text": "최적의 연속 부분을 찾는다."}]', 'A', '분할 정복 기법은 문제를 더 작은 문제로 나누고, 각각을 해결한 후 그 결과를 합쳐 최종 답을 도출하는 방식입니다.'),
    (1231, 4, 3, 77, '슬라이딩 윈도우 기법은 주로 어떤 문제에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서 특정 값을 찾는 문제."}, {"id": "B", "text": "연속적인 데이터의 부분 집합을 찾는 문제."}, {"id": "C", "text": "그래프의 경로를 찾는 문제."}, {"id": "D", "text": "모든 경우를 시도하는 문제."}]', 'B', '슬라이딩 윈도우 기법은 연속적인 데이터의 부분 집합을 효율적으로 관리하며 주로 배열이나 문자열 문제에서 사용됩니다.'),
    (1232, 4, 3, 78, '이분 탐색의 응용으로 맞는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 데이터에서 특정 값을 찾는 것."}, {"id": "B", "text": "모든 조합을 시도하는 것."}, {"id": "C", "text": "비순차적인 데이터의 최댓값을 찾는 것."}, {"id": "D", "text": "부모와 자식 노드를 관리하는 것."}]', 'A', '이분 탐색은 정렬된 데이터에서 특정 값을 효율적으로 찾는 데 사용되는 알고리즘입니다.'),
    (1233, 4, 3, 79, '다음 중 좌표 압축의 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 사용을 최적화하기 위함."}, {"id": "B", "text": "정렬된 배열을 만들기 위함."}, {"id": "C", "text": "데이터의 범위를 줄이기 위함."}, {"id": "D", "text": "계산 속도를 증가시키기 위함."}]', '["A", "C"]', '좌표 압축은 큰 범위의 숫자를 더 작은 범위로 변환하여 메모리 사용을 최적화하고 데이터의 범위를 줄이는 데 주로 사용됩니다.'),
    (1234, 4, 3, 80, '투 포인터 기법의 주된 사용 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '배열에서 조건을 만족하는 부분 집합을 찾기 위함이다.', '투 포인터 기법은 두 개의 포인터를 이용해 배열 내에서 특정 조건에 맞는 부분을 찾아내는 데 유용합니다.'),
    (1235, 4, 3, 81, '회문 판별이 가능한 문자열의 예는?', 'SHORT_ANSWER', NULL, 'abba', '회문은 앞뒤가 같아야 하므로 ''abba''와 같은 형태가 회문입니다.'),
    (1236, 4, 3, 82, '아호-코라식 알고리즘의 주된 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 일치를 활용한다."}, {"id": "B", "text": "모든 문자를 순차적으로 비교한다."}, {"id": "C", "text": "문자열을 정렬한다."}, {"id": "D", "text": "길이가 짧은 문자열에만 적용된다."}]', 'A', '아호-코라식 알고리즘은 부분 일치를 활용하여 검색 속도를 높입니다.'),
    (1237, 4, 3, 83, '보이어-무어 알고리즘은 무엇에 가장 효과적인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "짧은 패턴 검색에 효과적이다."}, {"id": "B", "text": "긴 패턴 검색에 효과적이다."}, {"id": "C", "text": "모든 패턴 검색에 동일한 성능을 보인다."}, {"id": "D", "text": "정규 표현식 처리에 효과적이다."}]', 'B', '보이어-무어 알고리즘은 긴 패턴 검색에 효과적이며, 특수한 스킵 조건을 제공합니다.'),
    (1238, 4, 3, 84, '다음 중 문자열 매칭에 사용되는 알고리즘이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "KMP 알고리즘"}, {"id": "B", "text": "아호-코라식"}, {"id": "C", "text": "퀵 정렬"}, {"id": "D", "text": "보이어-무어"}]', '["C"]', '퀵 정렬은 문자열 매칭이 아닌 정렬 알고리즘입니다.'),
    (1239, 4, 3, 85, 'AVL 트리의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자가 균형 이진 검색 트리이다."}, {"id": "B", "text": "자기 참조 구조이다."}, {"id": "C", "text": "최소 힙 구조를 가진다."}, {"id": "D", "text": "그래프 형태를 가진다."}]', 'A', 'AVL 트리는 각 노드의 왼쪽 서브트리와 오른쪽 서브트리의 높이 차이가 1 이하로 유지되는 자가 균형 이진 검색 트리입니다.'),
    (1240, 4, 3, 86, '힙(Heap) 구조의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열 생성"}, {"id": "B", "text": "우선순위 큐 구현"}, {"id": "C", "text": "그래프 탐색 알고리즘"}, {"id": "D", "text": "이진 탐색 수행"}]', 'B', '힙은 우선순위 큐를 효율적으로 구현하는 데 매우 유용합니다.'),
    (1241, 4, 3, 87, '세그먼트 트리의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다차원 데이터 저장"}, {"id": "B", "text": "구간 쿼리 처리"}, {"id": "C", "text": "정렬된 리스트 생성"}, {"id": "D", "text": "그래프 표현"}]', 'B', '세그먼트 트리는 구간 쿼리 처리를 효율적으로 수행하는 데 사용됩니다.'),
    (1242, 4, 3, 88, '비선형 자료구조의 일종으로 많은 종류의 노드를 가질 수 있는 자료구조는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "트리"}, {"id": "B", "text": "그래프"}, {"id": "C", "text": "배열"}, {"id": "D", "text": "링크드 리스트"}]', '["A", "B"]', '트리와 그래프는 비선형 구조로 다수의 노드를 가질 수 있습니다.'),
    (1243, 4, 3, 89, '이진 탐색 트리(BST)의 삽입 연산의 시간 복잡도는 대체로 어떻게 되는가?', 'SHORT_ANSWER', NULL, 'O(log n)', '이진 탐색 트리에서의 삽입 연산은 평균적으로 O(log n)의 시간 복잡도를 가집니다.'),
    (1244, 4, 3, 90, '해시맵에서 로드 팩터란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해시맵의 현재 요소 수와 배열의 크기의 비율"}, {"id": "B", "text": "해시 충돌이 발생하는 비율"}, {"id": "C", "text": "리해싱이 발생하는 주기"}, {"id": "D", "text": "해시맵의 메모리 사용량"}]', 'A', '로드 팩터는 해시맵의 현재 요소 수와 배열의 크기의 비율로, 성능에 영향을 미칩니다.'),
    (1245, 4, 3, 91, '해시 충돌 방지 기법 중 하나가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 어드레싱"}, {"id": "C", "text": "모듈로 연산"}, {"id": "D", "text": "리해싱"}]', 'C', '모듈로 연산은 해시 함수를 정의하는 방법이지 해시 충돌 방지 기법이 아닙니다.'),
    (1246, 4, 3, 92, '해시셋이 지원하는 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복 요소 허용"}, {"id": "B", "text": "순서 유지"}, {"id": "C", "text": "중복 요소 불허"}, {"id": "D", "text": "리스트 형태 제공"}]', 'C', '해시셋은 중복 요소를 허용하지 않는 특성을 가지고 있습니다.'),
    (1247, 4, 3, 93, '해시맵에서 리해싱이 필요한 경우는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "로드 팩터가 일정 비율을 초과할 때"}, {"id": "B", "text": "데이터의 검색 속도가 느려질 때"}, {"id": "C", "text": "해시 함수가 변경될 때"}, {"id": "D", "text": "삭제 작업이 수행될 때"}]', '["A", "B"]', '리해싱은 로드 팩터가 일정 비율을 초과하거나 데이터의 검색 속도가 느려질 때 필요합니다.'),
    (1248, 4, 3, 94, '해시맵에서 충돌이 발생하면 어떻게 해결할 수 있는가?', 'SHORT_ANSWER', NULL, '체이닝 또는 오픈 어드레싱 기법을 사용하여 해결한다.', '해시맵에서 충돌이 발생하면 체이닝이나 오픈 어드레싱 기법을 통해 해결할 수 있습니다.'),
    (1249, 4, 3, 95, 'AVL 트리의 주된 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '균형 잡힌 이진 검색 트리', 'AVL 트리는 각 노드의 높이 차이가 1을 넘지 않도록 유지하는 균형잡힌 이진 검색 트리입니다.'),
    (1250, 4, 3, 96, '트라이(Trie)의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 검색"}, {"id": "B", "text": "그래프 탐색"}, {"id": "C", "text": "정렬 알고리즘"}, {"id": "D", "text": "리스트 관리"}]', 'A', '트라이는 문자열 검색에 최적화된 자료구조로, 공통 접두사를 가진 문자열들을 효율적으로 저장하고 탐색하는 데 사용됩니다.'),
    (1251, 4, 3, 97, '최대 힙과 최소 힙의 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최대 힙은 부모 노드가 자식 노드보다 크다."}, {"id": "B", "text": "최소 힙은 부모 노드가 자식 노드보다 작다."}, {"id": "C", "text": "최대 힙은 우선순위 큐를 구현할 수 없다."}, {"id": "D", "text": "최소 힙은 최댓값을 빠르게 찾을 수 있다."}]', '["A", "B"]', '최대 힙은 부모 노드가 자식 노드보다 크고, 최소 힙은 부모 노드가 자식 노드보다 작은 구조입니다.'),
    (1252, 4, 3, 98, '무방향 그래프에서 두 정점 간의 경로는 어떻게 정의되나?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점 간의 간선이 방향성 있다."}, {"id": "B", "text": "정점 간의 간선은 방향이 없다."}, {"id": "C", "text": "정점 간의 경로는 간선이 없는 경우만 포함한다."}, {"id": "D", "text": "정점 간의 경로는 항상 긴다."}]', 'B', '무방향 그래프에서 두 정점 간의 경로는 방향성이 없는 간선으로 연결되어 있습니다.'),
    (1253, 4, 3, 99, 'LCP 배열의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열의 공통 접두사 길이를 저장하는 것"}, {"id": "B", "text": "문자열을 역순으로 만드는 것"}, {"id": "C", "text": "정규 표현식을 생성하는 것"}, {"id": "D", "text": "회문을 판별하는 것"}]', 'A', 'LCP 배열은 문자열에서 공통 접두사의 길이를 저장하여 효율적인 문자열 탐색에 사용됩니다.'),
    (1254, 4, 3, 100, '다음 중 KMP 알고리즘의 주요 이점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 문자에 대해 탐색을 수행한다"}, {"id": "B", "text": "불필요한 비교를 줄여준다"}, {"id": "C", "text": "정규 표현식을 사용한다"}, {"id": "D", "text": "해싱 기법을 사용한다"}]', 'B', 'KMP 알고리즘은 패턴과 텍스트를 비교할 때 불필요한 비교를 줄여주는 특성을 가지고 있습니다.'),
    (1255, 4, 3, 101, '정규 표현식에서 ''.*''의 의미는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 문자 0개 이상"}, {"id": "B", "text": "특정 문자 1개"}, {"id": "C", "text": "모든 숫자 1개"}, {"id": "D", "text": "특정 기호 0개 이상"}]', 'A', '정규 표현식에서 ''.*''는 모든 문자가 0개 이상 포함될 수 있음을 의미합니다.'),
    (1256, 4, 3, 102, '다음 중 회문을 판별하는 방법은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "문자열을 역순으로 생성하여 원본과 비교"}, {"id": "B", "text": "정규 표현식을 사용하여 검색"}, {"id": "C", "text": "LCP 배열을 생성하여 비교"}, {"id": "D", "text": "문자열 해싱을 통해 비교"}]', '["A", "C"]', '회문을 판별하는 일반적인 방법으로는 문자열을 역순으로 생성하여 원본과 비교하거나, LCP 배열을 통해 효율적으로 비교하는 방식이 있습니다.'),
    (1257, 4, 3, 103, 'KMP 알고리즘의 주요 기능은 무엇인가요?', 'SHORT_ANSWER', NULL, '패턴 문자열 검색 시 불필요한 비교를 줄인다.', 'KMP 알고리즘은 패턴 문자열을 효율적으로 검색하기 위해 이전에 일치한 부분을 활용하여 불필요한 비교를 줄이는 방식으로 작동합니다.'),
    (1258, 4, 3, 104, '해시셋(HashSet)의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 요소를 허용하지 않는다."}, {"id": "B", "text": "요소의 순서를 유지한다."}, {"id": "C", "text": "배열 기반으로 구현된다."}, {"id": "D", "text": "값의 중복을 허용한다."}]', 'A', 'HashSet은 중복된 요소를 허용하지 않는 자료구조입니다.'),
    (1259, 4, 3, 105, '로드 팩터(Load Factor)는 무엇을 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 총 크기"}, {"id": "B", "text": "사용 중인 버킷의 비율"}, {"id": "C", "text": "해시 알고리즘의 성능"}, {"id": "D", "text": "충돌 발생 비율"}]', 'B', '로드 팩터는 사용 중인 버킷의 비율을 나타내며, 해시 테이블의 효율성을 결정하는 중요한 요소입니다.'),
    (1260, 4, 3, 106, '해시 테이블에서 충돌 해결 방법으로 ''오픈 어드레싱''이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "선형 탐사"}, {"id": "C", "text": "이차 탐사"}, {"id": "D", "text": "이진 검색"}]', 'D', '오픈 어드레싱의 방법에는 선형 탐사와 이차 탐사가 포함되지만, 이진 검색은 해당되지 않습니다.'),
    (1261, 4, 3, 107, '해시 테이블의 성능을 높이기 위해 리해싱을 수행할 때 고려해야 하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "새로운 해시 함수 선택"}, {"id": "B", "text": "버킷의 크기 증가"}, {"id": "C", "text": "충돌 수 감소"}, {"id": "D", "text": "값의 정렬"}]', '["A", "B", "C"]', '리해싱 시 새로운 해시 함수 선택, 버킷 크기 증가, 그리고 충돌 수 감소가 중요합니다.'),
    (1262, 4, 3, 108, 'HashMap에서 키는 어떻게 처리되는가?', 'SHORT_ANSWER', NULL, '해시 함수를 통해 인덱스를 생성하여 저장된다.', 'HashMap에서는 키를 해시 함수를 통해 인덱스를 생성하여 해당 위치에 값을 저장합니다.'),
    (1263, 4, 3, 109, '최소 공통 조상(LCA)란 무엇인가요?', 'SHORT_ANSWER', NULL, '두 노드의 공통 조상을 찾는 기법', 'LCA는 두 노드의 가장 가까운 조상을 찾는 알고리즘입니다.'),
    (1264, 4, 3, 110, '세그먼트 트리는 어떤 목적으로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 쿼리 처리"}, {"id": "B", "text": "트리의 지름 구하기"}, {"id": "C", "text": "최소 공통 조상 찾기"}, {"id": "D", "text": "정렬 알고리즘 구현"}]', 'A', '세그먼트 트리는 주로 구간 쿼리를 빠르게 처리하기 위해 사용됩니다.'),
    (1265, 4, 3, 111, 'Heavy-Light Decomposition의 주 목적인 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리를 효율적으로 분할하기 위해"}, {"id": "B", "text": "최소 공통 조상 계산을 위해"}, {"id": "C", "text": "머지 소트 트리 구현을 위해"}, {"id": "D", "text": "스플레이 트리 성능 향상을 위해"}]', 'A', 'Heavy-Light Decomposition은 경로 쿼리를 효율적으로 처리하기 위해 트리를 분할하는 기법입니다.'),
    (1266, 4, 3, 112, '다음 중 세그먼트 트리의 특징으로 올바른 것은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구간 업데이트가 가능하다"}, {"id": "B", "text": "트리의 구조가 고정되어 있다"}, {"id": "C", "text": "정적 배열과 유사하게 동작한다"}, {"id": "D", "text": "구간 쿼리가 효율적이다"}]', '["A", "D"]', '세그먼트 트리는 구간 업데이트와 구간 쿼리 처리에 효율적입니다.'),
    (1267, 4, 3, 113, '퍼시스턴트 세그먼트 트리란 무엇인가?', 'SHORT_ANSWER', NULL, '시간에 따른 상태를 유지하는 세그먼트 트리', '퍼시스턴트 세그먼트 트리는 이전 상태를 유지하면서 변경을 기록할 수 있는 특성을 가진 세그먼트 트리입니다.'),
    (1268, 4, 3, 114, '슬라이딩 윈도우 기법의 주된 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속된 데이터의 합 또는 평균을 계산하는 것"}, {"id": "B", "text": "정렬된 배열에서 값을 찾는 것"}, {"id": "C", "text": "최적의 해를 찾는 것"}, {"id": "D", "text": "집합을 관리하는 것"}]', 'A', '슬라이딩 윈도우 기법은 연속된 데이터에서 특정 구간의 합이나 평균을 효율적으로 계산하는 데 사용됩니다.'),
    (1269, 4, 3, 115, '다음 중 유니온 파인드의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "집합의 합을 구하는 것"}, {"id": "B", "text": "집합을 효율적으로 관리하는 것"}, {"id": "C", "text": "정렬된 배열에서 이진 탐색하는 것"}, {"id": "D", "text": "문제의 최적 해를 구하는 것"}]', 'B', '유니온 파인드는 서로소 집합을 효율적으로 관리하고 쿼리를 처리하는 알고리즘입니다.'),
    (1270, 4, 3, 116, '스위핑 기법은 어떤 경우에 주로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서 이진 탐색할 때"}, {"id": "B", "text": "데이터의 경계나 관련된 상태를 추적할 때"}, {"id": "C", "text": "구간의 합을 빠르게 계산할 때"}, {"id": "D", "text": "두 개의 포인터를 사용할 때"}]', 'B', '스위핑 기법은 데이터의 경계나 관련된 상태를 추적하면서 문제를 해결하는 방법입니다.'),
    (1271, 4, 3, 117, '매개변수 탐색이 가장 적합한 문제 유형은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최적화 문제"}, {"id": "B", "text": "조합 문제"}, {"id": "C", "text": "정렬 문제"}, {"id": "D", "text": "경로 문제"}]', '["A", "D"]', '매개변수 탐색은 최적화 문제와 경로 문제와 같이 매개변수를 변경하며 해를 찾는 데 적합합니다.'),
    (1272, 4, 3, 118, '이분 탐색의 기본적인 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '정렬된 데이터에서 특정 값을 찾기 위해 데이터를 반으로 나누어 탐색하는 것', '이분 탐색은 정렬된 데이터에서 특정 값을 찾기 위해 데이터를 반으로 나누어 탐색하는 기법입니다.'),
    (1273, 4, 3, 119, '해시셋(HashSet)의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 요소를 허용하지 않는다."}, {"id": "B", "text": "키-값 쌍으로 데이터를 저장한다."}, {"id": "C", "text": "정렬된 데이터를 저장한다."}, {"id": "D", "text": "고정된 크기의 배열을 사용한다."}]', 'A', '해시셋은 중복된 요소를 저장할 수 없는 자료구조입니다.'),
    (1274, 4, 3, 120, '리해싱(rehashing)의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬하기 위해"}, {"id": "B", "text": "충돌을 해결하기 위해"}, {"id": "C", "text": "성능을 개선하기 위해"}, {"id": "D", "text": "메모리를 절약하기 위해"}]', 'C', '리해싱은 해시 테이블의 로드 팩터가 높을 때, 성능을 개선하기 위해 새로운 해시 테이블로 데이터를 재배치하는 과정입니다.'),
    (1275, 4, 3, 121, '해시 테이블에서 충돌이 발생했을 때 사용할 수 있는 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 어드레싱"}, {"id": "C", "text": "체크섬"}, {"id": "D", "text": "A와 B를 모두 사용"}]', 'D', '충돌 해결에는 체이닝과 오픈 어드레싱 두 가지 방법을 사용할 수 있습니다.'),
    (1276, 4, 3, 122, '해시 함수의 주된 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "입력 데이터를 고정된 크기로 변환한다."}, {"id": "B", "text": "데이터를 정렬한다."}, {"id": "C", "text": "충돌을 해결한다."}, {"id": "D", "text": "메모리 사용을 최적화한다."}]', '["A", "C"]', '해시 함수는 입력 데이터를 고정된 크기의 해시 값으로 변환하며, 충돌을 줄이는 데 중요한 역할을 합니다.'),
    (1277, 4, 3, 123, '해시 테이블의 로드 팩터란 무엇인가?', 'SHORT_ANSWER', NULL, '해시 테이블에서 저장된 요소의 수와 해시 버킷의 수의 비율', ''),
    (1278, 4, 3, 124, '해시맵의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 빠르게 조회하기 위해"}, {"id": "B", "text": "데이터를 정렬하기 위해"}, {"id": "C", "text": "데이터를 압축하기 위해"}, {"id": "D", "text": "데이터를 파일에 저장하기 위해"}]', 'A', '해시맵은 데이터를 빠르게 조회하기 위해 설계된 자료구조입니다.'),
    (1279, 4, 3, 125, '오픈 어드레싱에서 해시 충돌을 해결할 때 사용하는 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다음 빈 슬롯을 찾는다"}, {"id": "B", "text": "해시 함수를 변경한다"}, {"id": "C", "text": "데이터를 삭제한다"}, {"id": "D", "text": "새로운 해시 테이블을 생성한다"}]', 'A', '오픈 어드레싱은 충돌이 발생했을 때 다음 빈 슬롯을 찾는 방법으로 해결합니다.'),
    (1280, 4, 3, 126, '로드 팩터가 높아질 경우 어떤 문제가 발생할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "검색 성능 저하"}, {"id": "B", "text": "메모리 과다 사용"}, {"id": "C", "text": "데이터 손실"}, {"id": "D", "text": "해시함수 오류"}]', 'A', '로드 팩터가 높아지면 충돌이 빈번해져 검색 성능이 저하될 수 있습니다.'),
    (1281, 4, 3, 127, '해시셋이란 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중복된 데이터를 허용하지 않는 자료구조"}, {"id": "B", "text": "키-값 쌍으로 데이터를 저장하는 자료구조"}, {"id": "C", "text": "해시 함수를 사용하는 자료구조"}, {"id": "D", "text": "데이터를 정렬한 상태로 유지하는 자료구조"}]', '["A", "C"]', '해시셋은 중복된 데이터를 허용하지 않으며, 해시 함수를 사용하여 데이터를 저장합니다.'),
    (1282, 4, 3, 128, '해시 함수의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터를 해시값으로 변환하여 해시 테이블에 저장하기 위한 것', ''),
    (1283, 4, 3, 129, '이진 탐색 트리(BST)의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "왼쪽 서브트리는 항상 작은 값을 가진다."}, {"id": "B", "text": "모든 노드는 두 개의 자식 노드를 가진다."}, {"id": "C", "text": "모든 노드는 한 개의 부모 노드를 가진다."}, {"id": "D", "text": "모든 노드는 키 값이 고유해야 한다."}]', 'A', 'BST에서는 왼쪽 서브트리에 있는 모든 노드는 부모 노드보다 작은 값을 가집니다.'),
    (1284, 4, 3, 130, 'AVL 트리에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "높이 균형을 유지하는 이진 탐색 트리이다."}, {"id": "B", "text": "모든 노드는 세 개의 자식을 가진다."}, {"id": "C", "text": "리스프 노드만 존재한다."}, {"id": "D", "text": "노드 삽입과 삭제가 불가능하다."}]', 'A', 'AVL 트리는 삽입과 삭제 후에도 높이 균형을 유지하는 이진 탐색 트리입니다.'),
    (1285, 4, 3, 131, '그래프의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정점과 간선으로 구성된다."}, {"id": "B", "text": "노드 간의 관계를 표현할 수 있다."}, {"id": "C", "text": "모든 그래프는 사이클을 포함한다."}, {"id": "D", "text": "유향 그래프와 무향 그래프가 있다."}]', 'C', '그래프는 사이클이 있는 경우와 없는 경우 모두 존재할 수 있습니다.'),
    (1286, 4, 3, 132, '비선형 자료구조 중 문자열 검색에 가장 적합한 자료구조는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "Trie"}, {"id": "B", "text": "BST"}, {"id": "C", "text": "AVL 트리"}, {"id": "D", "text": "최소 힙"}]', '["A", "B"]', 'Trie는 문자열 검색에 최적화되어 있으며, BST도 문자열을 키로 하여 검색이 가능합니다.'),
    (1287, 4, 3, 133, 'B-Tree의 주요 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '데이터베이스와 파일 시스템에서 자료 검색을 효율적으로 수행하기 위해 사용된다.', 'B-Tree는 대량의 데이터를 효율적으로 검색하고, 삽입 및 삭제 작업을 지원하도록 설계된 자료구조입니다.'),
    (1288, 4, 3, 134, '정규표현식의 주된 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 검색 및 조작"}, {"id": "B", "text": "숫자 계산"}, {"id": "C", "text": "파일 저장"}, {"id": "D", "text": "네트워크 통신"}]', 'A', '정규표현식은 문자열 내에서 특정 패턴을 찾고 조작하는 데 유용한 도구입니다.'),
    (1289, 4, 3, 135, 'KMP 알고리즘의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 일치 테이블을 사용한다"}, {"id": "B", "text": "재귀적으로 작동한다"}, {"id": "C", "text": "정렬된 문자열을 필요로 한다"}, {"id": "D", "text": "최대 O(n^2) 시간 복잡도를 가진다"}]', 'A', 'KMP 알고리즘은 부분 일치 테이블을 이용해 같은 문자를 여러 번 비교하지 않도록 최적화합니다.'),
    (1290, 4, 3, 136, '아호-코라식 알고리즘은 어느 경우에 효과적인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 패턴을 동시에 검색할 때"}, {"id": "B", "text": "단일 패턴을 검색할 때"}, {"id": "C", "text": "랜덤 문자열 처리"}, {"id": "D", "text": "정렬된 문자열 처리"}]', 'A', '아호-코라식 알고리즘은 다수의 패턴을 동시에 검색하는 데 매우 효과적입니다.'),
    (1291, 4, 3, 137, '다음 중 팰린드롬을 확인하는 방법으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "앞에서부터 항상 같은 문자인지 비교"}, {"id": "B", "text": "문자열을 거꾸로 뒤집어 비교"}, {"id": "C", "text": "문자를 정렬한 후 비교"}, {"id": "D", "text": "중복된 문자를 제거한 후 비교"}]', '["A", "B"]', '팰린드롬은 문자열을 앞에서부터와 뒤에서부터 비교하여 확인할 수 있습니다.'),
    (1292, 4, 3, 138, '트라이는 주로 어떤 목적으로 사용되는가?', 'SHORT_ANSWER', NULL, '문자열 검색 및 자동 완성 기능', '트라이는 문자열 검색 및 자동 완성 기능을 제공하는데 효율적인 데이터 구조입니다.'),
    (1293, 4, 3, 139, '이분 탐색의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서의 특정 값 찾기"}, {"id": "B", "text": "모든 경우의 수를 탐색하기"}, {"id": "C", "text": "최소 구간 합을 찾기"}, {"id": "D", "text": "임의의 배열을 정렬하기"}]', 'A', '이분 탐색은 정렬된 배열에서 특정 값의 위치를 효율적으로 찾기 위해 사용됩니다.'),
    (1294, 4, 3, 140, '구간합을 계산하기 위해 주로 사용하는 자료구조는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "누적합 배열"}, {"id": "D", "text": "해시맵"}]', 'C', '구간합을 효율적으로 계산하기 위해서는 누적합 배열을 사용하는 것이 일반적입니다.'),
    (1295, 4, 3, 141, '다음 중 슬라이딩 윈도우 기법의 사용 예가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최장 연속 부분 수열 찾기"}, {"id": "B", "text": "모든 조합 탐색"}, {"id": "C", "text": "최소/최대 구간 합 찾기"}, {"id": "D", "text": "특정 길이의 부분 배열 합 계산하기"}]', 'B', '슬라이딩 윈도우 기법은 연속된 데이터에서 특정 범위를 다루는 데 유용하지만, 모든 조합을 탐색하는 데는 사용되지 않습니다.'),
    (1296, 4, 3, 142, '투 포인터 기법을 사용할 수 있는 문제의 예를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "정렬된 배열에서 두 숫자의 합 찾기"}, {"id": "B", "text": "문자열에서 특정 패턴 찾기"}, {"id": "C", "text": "최장 반복 부분 문자열 찾기"}, {"id": "D", "text": "두 개의 리스트에서 공통 원소 찾기"}]', '["A", "D"]', '투 포인터 기법은 정렬된 배열이나 두 개의 리스트에서 특정 조건을 만족하는 조합을 찾는 데 유용하게 사용됩니다.'),
    (1297, 4, 3, 143, '좌표 압축의 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '메모리 절약 및 연산 효율성 향상', '좌표 압축은 큰 범위의 수를 작은 범위로 매핑하여 메모리를 절약하고 연산의 효율성을 높이는 기법입니다.'),
    (1298, 4, 3, 144, '브루트포스 기법의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 경우의 수를 시도하여 정답을 찾는다."}, {"id": "B", "text": "정렬된 배열을 사용하여 검색 속도를 높인다."}, {"id": "C", "text": "조건에 맞지 않는 경로를 사전에 차단한다."}, {"id": "D", "text": "구간 쿼리를 효율적으로 처리한다."}]', 'A', '브루트포스 기법은 모든 가능한 경우를 시도하여 정답을 찾는 방식으로, 단순하고 직관적이지만 시간이 많이 걸릴 수 있습니다.'),
    (1299, 4, 3, 145, '투 포인터 기법이 주로 사용되는 경우는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열의 특정 합을 찾을 때."}, {"id": "B", "text": "모든 조합을 생성할 때."}, {"id": "C", "text": "데이터베이스 쿼리를 수행할 때."}, {"id": "D", "text": "큰 데이터에서 특정 값의 개수를 세는 경우."}]', 'A', '투 포인터 기법은 주로 정렬된 배열에서 특정 합을 찾는데 효과적이며, 배열의 두 포인터를 이동시켜 문제를 해결합니다.'),
    (1300, 4, 3, 146, '백트래킹 기법의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 경우의 수를 탐색하되, 불가능한 경우는 조기에 차단한다."}, {"id": "B", "text": "정렬된 데이터를 사용하여 탐색 속도를 높인다."}, {"id": "C", "text": "다양한 방향으로 동시에 탐색한다."}, {"id": "D", "text": "매번 새로운 값을 생성하여 문제를 해결한다."}]', 'A', '백트래킹은 모든 가능한 조합을 탐색하되, 유효하지 않은 경로는 조기에 제거함으로써 효율성을 높이는 접근 방식입니다.'),
    (1301, 4, 3, 147, '누적합을 사용하는 주된 이유는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구간 합을 빠르게 계산하기 위해."}, {"id": "B", "text": "메모리 사용량을 줄이기 위해."}, {"id": "C", "text": "정렬된 데이터를 관리하기 위해."}, {"id": "D", "text": "상태를 기록하기 위해."}]', '["A", "B"]', '누적합은 구간 합을 빠르게 계산할 수 있도록 도와주며, 큰 범위의 데이터를 다룰 때 메모리 사용을 최적화하는 데 유용합니다.'),
    (1302, 4, 3, 148, '세그먼트 트리의 주요 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '구간 쿼리를 효율적으로 처리하는 것', '세그먼트 트리는 구간 쿼리와 업데이트를 효율적으로 수행할 수 있는 자료구조로, 특히 빈번한 쿼리와 업데이트가 필요한 경우에 유용합니다.'),
    (1303, 4, 3, 149, '세그먼트 트리는 주로 어떤 용도로 사용됩니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 쿼리 처리"}, {"id": "B", "text": "그래프 탐색"}, {"id": "C", "text": "정렬"}, {"id": "D", "text": "해시 테이블 구현"}]', 'A', '세그먼트 트리는 주어진 배열의 구간 쿼리를 효율적으로 처리하는 데 사용됩니다.'),
    (1304, 4, 3, 150, 'HLD(Heavy-Light Decomposition)의 주된 목적은 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리를 분할하여 성능 향상"}, {"id": "B", "text": "트리를 정렬하기 위해"}, {"id": "C", "text": "그래프를 이진 트리로 변환"}, {"id": "D", "text": "데이터베이스 쿼리 최적화"}]', 'A', 'HLD는 트리를 두 개의 부분으로 나누어 쿼리의 성능을 향상시키기 위한 기법입니다.'),
    (1305, 4, 3, 151, '다음 중 2-3 트리의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 노드는 2개 또는 3개의 자식을 가질 수 있다."}, {"id": "B", "text": "노드가 1개 이하의 자식을 가질 수 있다."}, {"id": "C", "text": "균형 잡힌 자료구조이다."}, {"id": "D", "text": "이진 탐색 트리의 일종이다."}]', 'B', '2-3 트리는 모든 노드가 2개 또는 3개의 자식을 가져야 하므로, 1개 이하의 자식을 가질 수는 없습니다.'),
    (1306, 4, 3, 152, '세그먼트 트리와 관련된 자료구조를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "퍼시스턴트 세그먼트 트리"}, {"id": "B", "text": "스플레이 트리"}, {"id": "C", "text": "이진 인덱스 트리"}, {"id": "D", "text": "펜윅 트리"}]', '["A", "C", "D"]', '퍼시스턴트 세그먼트 트리, 이진 인덱스 트리, 펜윅 트리는 모두 구간 쿼리 처리와 관련된 자료구조입니다.'),
    (1307, 4, 3, 153, '오일러 투리는 무엇을 위한 방법인가요?', 'SHORT_ANSWER', NULL, '트리의 노드와 간선을 순회하기 위한 방법입니다.', '오일러 투리는 트리의 모든 간선을 두 번씩 통과하여 노드와 간선을 순회하는 방법입니다.'),
    (1308, 4, 3, 154, '레드-블랙 트리의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 경로에서 같은 수의 검은 노드를 가진다."}, {"id": "B", "text": "부모 노드가 항상 자식 노드보다 작다."}, {"id": "C", "text": "모든 노드는 최대 3개의 자식 노드를 가진다."}, {"id": "D", "text": "단일 링크드 리스트로 구현된다."}]', 'A', '레드-블랙 트리는 모든 경로에서 같은 수의 검은 노드를 가져야 하는 성질을 가지고 있습니다.'),
    (1309, 4, 3, 155, '다음 중 그래프를 표현하는 방법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인접 행렬"}, {"id": "B", "text": "인접 리스트"}, {"id": "C", "text": "레드-블랙 트리"}, {"id": "D", "text": "모서리 목록"}]', 'C', '레드-블랙 트리는 그래프를 표현하는 방식이 아니라 자가 균형 이진 탐색 트리입니다.'),
    (1310, 4, 3, 156, '최소 힙의 특징으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부모 노드가 자식 노드보다 크다."}, {"id": "B", "text": "모든 노드가 정렬되어 있다."}, {"id": "C", "text": "부모 노드가 자식 노드보다 작거나 같다."}, {"id": "D", "text": "비선형 구조가 아니다."}]', 'C', '최소 힙에서는 부모 노드가 자식 노드보다 작거나 같은 값을 가져야 합니다.'),
    (1311, 4, 3, 157, '다음 중 비선형 자료구조에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이진 트리"}, {"id": "B", "text": "단일 링크드 리스트"}, {"id": "C", "text": "그래프"}, {"id": "D", "text": "레드-블랙 트리"}]', '["A", "C", "D"]', '이진 트리, 그래프, 레드-블랙 트리는 모두 비선형 자료구조입니다.'),
    (1312, 4, 3, 158, '트라이(Trie)의 주 용도는 무엇인가요?', 'SHORT_ANSWER', NULL, '문자열 검색', '트라이는 문자열 검색에 효율적인 데이터 구조입니다.'),
    (1313, 4, 3, 159, '해시 테이블에서 충돌을 해결하는 방법 중 하나로, 요소를 동일한 인덱스에 저장하고 그 다음 인덱스를 탐색하는 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 어드레싱"}, {"id": "C", "text": "로드 팩터"}, {"id": "D", "text": "해시셋"}]', 'B', '오픈 어드레싱은 충돌이 발생했을 때 다음 인덱스를 탐색하여 빈 슬롯에 저장하는 방법입니다.'),
    (1314, 4, 3, 160, '해시셋(HashSet)의 특성으로 옳지 않은 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 값을 허용하지 않는다."}, {"id": "B", "text": "순서를 보장한다."}, {"id": "C", "text": "해시 테이블을 기반으로 한다."}, {"id": "D", "text": "자동적으로 크기가 조절된다."}]', 'B', 'HashSet은 중복된 값을 허용하지 않지만, 순서를 보장하지 않습니다.'),
    (1315, 4, 3, 161, '로드 팩터가 높을 경우 해시 테이블의 성능은 어떻게 되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "성능이 저하된다."}, {"id": "B", "text": "충돌이 증가한다."}, {"id": "C", "text": "메모리 사용량이 감소한다."}, {"id": "D", "text": "재해시가 필요할 수 있다."}]', '["A", "B", "D"]', '로드 팩터가 높으면 충돌이 증가하고 성능이 저하되며, 필요에 따라 재해시가 필요할 수 있습니다.'),
    (1316, 4, 3, 162, '해시 테이블에 데이터를 저장할 때 사용되는 함수는 무엇인가?', 'SHORT_ANSWER', NULL, '해시 함수', '해시 함수는 키를 해시 값으로 변환하여 데이터를 저장할 인덱스를 결정합니다.'),
    (1317, 4, 3, 163, '해시 테이블에서 로드 팩터란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '현재 저장된 항목 수와 테이블의 크기 비율', '로드 팩터는 해시 테이블에 현재 저장된 항목 수와 테이블의 크기의 비율을 의미하여, 성능을 분석하는 데 중요한 지표입니다.'),
    (1318, 4, 3, 164, '해시 충돌을 해결하는 방법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 주소법"}, {"id": "C", "text": "해시 함수 수정"}, {"id": "D", "text": "리해싱"}]', 'C', '해시 충돌을 해결하기 위해서는 체이닝이나 오픈 주소법 같은 방법을 사용해야 하며, 해시 함수를 수정하는 것은 직접적인 해결책이 아닙니다.'),
    (1319, 4, 3, 165, 'HashMap에서 데이터가 저장되는 방식은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열과 연결 리스트의 조합"}, {"id": "B", "text": "단일 연결 리스트"}, {"id": "C", "text": "정렬된 배열"}, {"id": "D", "text": "트리 구조"}]', 'A', 'HashMap은 내부적으로 배열과 연결 리스트의 조합으로 데이터를 저장하여 해시 충돌을 해결합니다.'),
    (1320, 4, 3, 166, '다음 중 해시 기반 자료구조에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "HashMap"}, {"id": "B", "text": "ArrayList"}, {"id": "C", "text": "Dictionary"}, {"id": "D", "text": "Stack"}]', '["A", "C"]', 'HashMap과 Dictionary는 모두 해시 기반 자료구조로 키-값 쌍을 저장하는 데 사용됩니다.'),
    (1321, 4, 3, 167, 'B+Tree의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 자식 노드가 정렬된 값으로 연결되어 있다."}, {"id": "B", "text": "각 노드는 최대 4개의 자식을 가진다."}, {"id": "C", "text": "루트 노드는 항상 자식 노드를 가진다."}, {"id": "D", "text": "중복된 값을 허용한다."}]', 'A', 'B+Tree는 모든 자식 노드가 정렬된 값으로 연결되어 있어, 검색의 효율성을 높인다.'),
    (1322, 4, 3, 168, 'Heavy-Light Decomposition의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리를 이진 트리로 변환한다."}, {"id": "B", "text": "트리의 경로 쿼리를 효율적으로 처리하기 위해 트리를 분해한다."}, {"id": "C", "text": "모든 노드를 같은 깊이로 만들기 위함이다."}, {"id": "D", "text": "메모리 사용을 최소화하기 위함이다."}]', 'B', 'Heavy-Light Decomposition은 트리의 경로 쿼리를 효율적으로 처리하기 위해 트리를 분해하는 기법이다.'),
    (1323, 4, 3, 169, '다음 중 아동의 수가 2개 또는 3개인 트리는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "B+Tree"}, {"id": "B", "text": "스플레이 트리"}, {"id": "C", "text": "2-3 트리"}, {"id": "D", "text": "세그먼트 트리"}]', 'C', '2-3 트리는 각 노드가 2개 또는 3개의 자식을 가질 수 있는 균형 이진 트리이다.'),
    (1324, 4, 3, 170, '퍼시스턴트 세그먼트 트리는 어떤 기능을 지원하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이전 버전의 데이터 보존"}, {"id": "B", "text": "빠른 검색 성능"}, {"id": "C", "text": "노드의 동적 추가 및 삭제"}, {"id": "D", "text": "하나의 트리에서 모든 쿼리 처리"}]', '["A", "B"]', '퍼시스턴트 세그먼트 트리는 이전 버전의 데이터를 보존하고, 또한 검색 성능이 뛰어난 특징이 있다.'),
    (1325, 4, 3, 171, '최소 공통 조상을 찾는 데 사용되는 알고리즘은 무엇인가?', 'SHORT_ANSWER', NULL, 'LCA 알고리즘', '최소 공통 조상(LCA) 문제를 해결하기 위해 사용되는 알고리즘.'),
    (1326, 4, 3, 172, 'B-Tree의 주요 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '다수의 자식을 가질 수 있는 자가 균형 이진 검색 트리', 'B-Tree는 다수의 자식을 가질 수 있는 자가 균형 이진 검색 트리로, 주로 데이터베이스와 파일 시스템에서 사용됩니다.'),
    (1327, 4, 3, 173, 'AVL 트리의 주요 성질은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자기 균형 이진 검색 트리이다."}, {"id": "B", "text": "모든 노드는 최대 세 개의 자식을 가진다."}, {"id": "C", "text": "배열로 구현된다."}, {"id": "D", "text": "최대 높이 차이는 3이다."}]', 'A', 'AVL 트리는 자기 균형 이진 검색 트리로, 각 노드의 높이 차이가 1 이하로 유지됩니다.'),
    (1328, 4, 3, 174, '다음 중 가중치 그래프의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 엣지에 가중치가 할당된다."}, {"id": "B", "text": "모든 엣지는 동일한 가중치를 가진다."}, {"id": "C", "text": "최단 경로 문제를 해결하는 데 사용된다."}, {"id": "D", "text": "엣지의 방향이 있을 수 있다."}]', 'B', '가중치 그래프는 각 엣지에 가중치가 할당되지만, 모든 엣지가 동일한 가중치를 가질 필요는 없습니다.'),
    (1329, 4, 3, 175, '그래프의 종류 중 방향 그래프와 무방향 그래프의 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "방향 그래프는 엣지에 방향이 있다."}, {"id": "B", "text": "무방향 그래프는 엣지에 방향이 없다."}, {"id": "C", "text": "방향 그래프는 사이클을 허용하지 않는다."}, {"id": "D", "text": "무방향 그래프는 모든 엣지가 대칭적이다."}]', '["A", "B", "D"]', '방향 그래프는 엣지에 방향이 있어 한 방향으로만 이동할 수 있으며, 무방향 그래프는 엣지에 방향이 없어 양방향 이동이 가능합니다.'),
    (1330, 4, 3, 176, '이진 탐색 트리(BST)의 특징은 무엇인가요?', 'SHORT_ANSWER', NULL, '좌측 서브트리는 부모 노드보다 작고, 우측 서브트리는 부모 노드보다 크다.', 'BST는 노드의 정렬된 특성을 통해 효율적인 검색을 가능하게 합니다.'),
    (1331, 4, 3, 177, '최대 힙의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부모 노드는 항상 자식 노드보다 크다."}, {"id": "B", "text": "부모 노드는 항상 자식 노드보다 작다."}, {"id": "C", "text": "모든 노드는 두 개의 자식을 가진다."}, {"id": "D", "text": "최대 힙은 항상 완전 이진 트리이다."}]', 'A', '최대 힙은 부모 노드가 자식 노드보다 항상 크거나 같은 성질을 가집니다.'),
    (1332, 4, 3, 178, '세그먼트 트리의 주된 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 데이터 검색"}, {"id": "B", "text": "구간 합 쿼리 처리"}, {"id": "C", "text": "문자열 검색"}, {"id": "D", "text": "그래프 탐색"}]', 'B', '세그먼트 트리는 구간의 합이나 최댓값 등을 빠르게 처리하기 위해 사용됩니다.'),
    (1333, 4, 3, 179, '다음 중 비선형 자료구조에 해당하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "트리"}, {"id": "B", "text": "리스트"}, {"id": "C", "text": "그래프"}, {"id": "D", "text": "스택"}]', '["A", "C"]', '트리와 그래프는 비선형 자료구조이며, 리스트와 스택은 선형 자료구조입니다.'),
    (1334, 4, 3, 180, 'B-Tree의 주요 특징은 무엇인가요?', 'SHORT_ANSWER', NULL, '다수의 자식을 가지며, 데이터베이스에서 효율적인 검색과 삽입을 가능하게 한다.', 'B-Tree는 균형 잡힌 자료구조로, 디스크 기반 데이터베이스에서 매우 효과적입니다.'),
    (1335, 4, 3, 181, '강한 연결 요소(SCC)는 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, '모든 정점 간에 도달 가능성이 있는 집합.', '강한 연결 요소는 방향 그래프에서 모든 정점 간의 도달 가능성이 있는 정점들의 집합을 의미합니다.'),
    (1336, 4, 3, 182, '크루스칼 알고리즘을 사용할 때 어떤 자료구조가 주로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유니온-파인드"}, {"id": "B", "text": "스택"}, {"id": "C", "text": "큐"}, {"id": "D", "text": "해시맵"}]', 'A', '크루스칼 알고리즘은 최소 신장 트리를 만들기 위해 유니온-파인드 자료구조를 사용하여 사이클을 방지합니다.'),
    (1337, 4, 3, 183, '단절선은 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그래프의 두 정점을 연결하는 간선"}, {"id": "B", "text": "그래프에서 정점의 제거로 연결 성분이 증가하는 간선"}, {"id": "C", "text": "완전 그래프의 간선"}, {"id": "D", "text": "사이클이 있는 그래프의 간선"}]', 'B', '단절선은 그래프에서 특정 간선을 제거했을 때 연결 성분의 수가 증가하는 간선을 의미합니다.'),
    (1338, 4, 3, 184, '벨만-포드 알고리즘이 해결할 수 있는 문제는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "음수 사이클"}, {"id": "B", "text": "최단 경로"}, {"id": "C", "text": "최대 유량"}, {"id": "D", "text": "최소 신장 트리"}]', '["A", "B"]', '벨만-포드 알고리즘은 음수 가중치를 가진 그래프에서의 최단 경로를 찾고, 음수 사이클의 존재 여부를 확인할 수 있습니다.'),
    (1339, 4, 3, 185, '0-1 BFS가 일반 BFS와 다른 점은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가중치가 있는 간선을 사용한다."}, {"id": "B", "text": "간선 가중치가 0이나 1만 허용된다."}, {"id": "C", "text": "DFS와 같은 방식으로 작동한다."}, {"id": "D", "text": "모든 경로를 탐색한다."}]', 'B', '0-1 BFS는 간선의 가중치가 0이나 1인 그래프에서 최단 경로를 찾기 위해 사용되는 알고리즘입니다.'),
    (1340, 4, 3, 186, 'KMP 알고리즘에서 사용하는 주요 개념은 무엇인가?', 'SHORT_ANSWER', NULL, '부분 일치 테이블', 'KMP 알고리즘은 부분 일치 테이블을 사용하여 검색 속도를 향상시킵니다.'),
    (1341, 4, 3, 187, '보이어-무어 알고리즘의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패턴이 긴 경우 효율적이다."}, {"id": "B", "text": "정확한 문자열을 항상 찾는다."}, {"id": "C", "text": "공백을 자동으로 처리한다."}, {"id": "D", "text": "단일 비교만 수행한다."}]', 'A', '보이어-무어 알고리즘은 패턴이 긴 경우 불필요한 비교를 줄여 효율적입니다.'),
    (1342, 4, 3, 188, '다음 중 문자열이 팰린드롬인지 확인하는 방법으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열을 역순으로 만든 후 비교한다."}, {"id": "B", "text": "정렬한 후 비교한다."}, {"id": "C", "text": "아스키 값을 비교한다."}, {"id": "D", "text": "문자열의 길이를 측정한다."}]', 'A', '문자열을 역순으로 만든 후 원래 문자열과 비교하여 팰린드롬 여부를 확인할 수 있습니다.'),
    (1343, 4, 3, 189, '아래 중 팰린드롬을 찾기에 적합한 알고리즘은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "KMP"}, {"id": "B", "text": "트라이"}, {"id": "C", "text": "보이어-무어"}, {"id": "D", "text": "Z 알고리즘"}]', '["A", "D"]', 'KMP와 Z 알고리즘은 모두 문자열 패턴 매칭을 위해 설계되어 있어 팰린드롬을 찾는데 적합합니다.'),
    (1344, 4, 3, 190, '문자열 검색에서 정규 표현식의 주요 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '패턴 매칭', '정규 표현식은 문자열에서 특정 패턴을 찾아내는 데 사용됩니다.'),
    (1345, 4, 3, 191, '해시셋(HashSet)의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 값을 허용한다."}, {"id": "B", "text": "중복된 값을 허용하지 않는다."}, {"id": "C", "text": "순서를 유지한다."}, {"id": "D", "text": "자동으로 정렬된다."}]', 'B', '해시셋은 중복된 값을 허용하지 않는 특징을 가지고 있습니다.'),
    (1346, 4, 3, 192, '해시 함수의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬한다."}, {"id": "B", "text": "입력 데이터를 해시값으로 변환한다."}, {"id": "C", "text": "데이터를 암호화한다."}, {"id": "D", "text": "저장 공간을 최적화한다."}]', 'B', '해시 함수는 입력 데이터를 해시값으로 변환하여 저장 위치를 결정하는 역할을 합니다.'),
    (1347, 4, 3, 193, '로드 팩터가 높은 경우, 어떤 문제가 발생할 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 저장 공간이 부족해진다."}, {"id": "B", "text": "해시 충돌이 증가할 가능성이 높아진다."}, {"id": "C", "text": "데이터 검색 속도가 빨라진다."}, {"id": "D", "text": "자료구조의 용량이 자동으로 늘어난다."}]', 'B', '로드 팩터가 높아질수록 해시 충돌의 발생 가능성이 커집니다.'),
    (1348, 4, 3, 194, '해시 충돌을 해결하는 방법 중 하나로 체이닝이 사용된다. 이 방법의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "각 해시값에 연결 리스트를 사용한다."}, {"id": "B", "text": "고정된 크기의 배열을 사용한다."}, {"id": "C", "text": "해시충돌을 방지하는 데 최적화되어 있다."}, {"id": "D", "text": "충돌 발생 시 다른 해시 함수를 사용한다."}]', '["A"]', '체이닝은 각 해시값에 연결 리스트를 사용하여 충돌을 해결하는 방법입니다.'),
    (1349, 4, 3, 195, 'Dictionary 자료구조에서 데이터를 저장하는 방식은 무엇인가?', 'SHORT_ANSWER', NULL, '키-값 쌍', 'Dictionary는 키-값 쌍으로 데이터를 저장하는 자료구조입니다.'),
    (1350, 4, 3, 196, '슬라이딩 윈도우 기법은 주로 어떤 문제를 해결하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속적인 데이터의 합"}, {"id": "B", "text": "정렬된 데이터의 탐색"}, {"id": "C", "text": "비트 연산"}, {"id": "D", "text": "재귀적인 문제 해결"}]', 'A', '슬라이딩 윈도우 기법은 주로 연속적인 데이터의 합이나 특정 조건을 만족하는 부분 배열을 찾는 데 사용됩니다.'),
    (1351, 4, 3, 197, '투 포인터 기법이 주로 활용되는 문제 유형은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서의 이분 탐색"}, {"id": "B", "text": "배열의 두 부분의 합 비교"}, {"id": "C", "text": "문자열의 회문 판별"}, {"id": "D", "text": "그래프의 최단 경로 탐색"}]', 'B', '투 포인터 기법은 주로 배열의 두 부분의 합이나 조건을 비교하는 문제에 자주 활용됩니다.'),
    (1352, 4, 3, 198, '유니온 파인드(Union-Find) 구조의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최단 경로 탐색"}, {"id": "B", "text": "집합의 생성 및 관리"}, {"id": "C", "text": "재귀적 문제 해결"}, {"id": "D", "text": "이분 탐색"}]', 'B', '유니온 파인드는 여러 개의 집합을 효율적으로 관리하고, 집합의 연결 관계를 찾는 데 주요 목적이 있습니다.'),
    (1353, 4, 3, 199, '비트마스킹을 사용하여 특정 문제를 해결할 수 있는 기법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "조합 생성"}, {"id": "B", "text": "배열의 정렬"}, {"id": "C", "text": "하위 집합의 존재 확인"}, {"id": "D", "text": "그래프 순회"}]', '["A", "C"]', '비트마스킹은 조합 생성 및 하위 집합의 존재 확인과 같은 문제를 해결하는 데 유용하게 사용됩니다.'),
    (1354, 4, 3, 200, '백트래킹 기법의 핵심 원리는 무엇인가?', 'SHORT_ANSWER', NULL, '후보 해를 점진적으로 구성하고 유효성 검사 후 백트래킹하는 것', '백트래킹 기법은 후보 해를 점진적으로 구성하고, 조건을 만족하지 않으면 이전 단계로 되돌아가는 과정을 반복하여 해를 찾는 기법입니다.'),
    (1355, 4, 3, 201, '이분 탐색을 사용할 수 있는 경우는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 배열에서의 검색"}, {"id": "B", "text": "비정렬된 배열에서의 검색"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "모든 경우에 사용 가능"}]', 'A', '이분 탐색은 정렬된 배열에서 특정 값을 찾는 효율적인 방법입니다.'),
    (1356, 4, 3, 202, '유니온 파인드를 사용하는 상황은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 신장 트리"}, {"id": "B", "text": "정렬된 배열 검색"}, {"id": "C", "text": "구간 합 계산"}, {"id": "D", "text": "비밀번호 해시"}]', 'A', '유니온 파인드는 주로 연결된 컴포넌트를 관리하고 최소 신장 트리를 구하는 데 사용됩니다.'),
    (1357, 4, 3, 203, '다음 중 스위핑 기법의 적용 예시가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 합 문제"}, {"id": "B", "text": "정렬된 두 배열의 합"}, {"id": "C", "text": "최소 신장 트리 구하기"}, {"id": "D", "text": "가장 가까운 두 점 찾기"}]', 'C', '스위핑 기법은 주로 구간 문제에 적용되며, 최소 신장 트리 구하기에는 유니온 파인드나 다른 알고리즘이 사용됩니다.'),
    (1358, 4, 3, 204, '투 포인터 기법을 사용할 수 있는 문제 유형은? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "정렬된 배열에서 두 수의 합 찾기"}, {"id": "B", "text": "그래프 최단 경로 찾기"}, {"id": "C", "text": "구간 합 계산"}, {"id": "D", "text": "문자열 내 회문 판별"}]', '["A", "C"]', '투 포인터 기법은 정렬된 배열에서 두 수의 합을 찾거나 특정 구간을 계산하는 데 유용합니다.'),
    (1359, 4, 3, 205, '세그먼트 트리는 주로 어떤 목적으로 사용되나요?', 'SHORT_ANSWER', NULL, '구간 쿼리 처리', '세그먼트 트리는 구간 합, 최댓값, 최솟값 등의 쿼리를 효율적으로 처리하는 데 사용됩니다.'),
    (1360, 4, 3, 206, '해시맵을 사용하여 데이터를 저장할 때, 어떤 구조를 사용하여 키-값 쌍을 저장합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열"}, {"id": "B", "text": "연결 리스트"}, {"id": "C", "text": "트리"}, {"id": "D", "text": "해시 테이블"}]', 'D', '해시맵은 해시 테이블을 사용하여 키-값 쌍을 저장합니다.'),
    (1361, 4, 3, 207, '체이닝 방식을 사용하는 해시맵에서 충돌이 발생할 경우, 어떻게 해결하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "새로운 해시 함수를 사용한다."}, {"id": "B", "text": "연결 리스트에 추가한다."}, {"id": "C", "text": "데이터를 삭제한다."}, {"id": "D", "text": "해시 테이블의 크기를 늘린다."}]', 'B', '체이닝에서는 충돌이 발생한 데이터를 연결 리스트에 추가하여 해결합니다.'),
    (1362, 4, 3, 208, '로드 팩터가 너무 높을 때 어떤 문제가 발생할 수 있습니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 누수"}, {"id": "B", "text": "검색 속도 저하"}, {"id": "C", "text": "데이터 손실"}, {"id": "D", "text": "중복 데이터"}, {"id": "E", "text": "데이터 정렬 실패"}]', 'B', '로드 팩터가 너무 높으면 해시 테이블의 검색 속도가 저하될 수 있습니다.'),
    (1363, 4, 3, 209, '해시셋의 내부 구조는 무엇을 기반으로 하고 있습니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "해시맵"}, {"id": "B", "text": "연결 리스트"}, {"id": "C", "text": "배열"}, {"id": "D", "text": "트리"}]', '["A"]', '해시셋은 내부적으로 해시맵을 사용하여 구현됩니다.'),
    (1364, 4, 3, 210, '해시 함수의 주요 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '키를 해시 값으로 변환하여 저장할 위치를 결정하는 것', '해시 함수는 키를 해시 값으로 변환하여 데이터를 저장할 위치를 결정합니다.'),
    (1365, 4, 3, 211, '세그먼트 트리의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구간 쿼리와 업데이트 처리"}, {"id": "B", "text": "데이터 정렬"}, {"id": "C", "text": "그래프 탐색"}, {"id": "D", "text": "문자열 검색"}]', 'A', '세그먼트 트리는 구간 쿼리와 업데이트를 효율적으로 처리할 수 있도록 설계된 데이터 구조입니다.'),
    (1366, 4, 3, 212, 'LCA 문제를 해결하기 위해 사용되는 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "오일러 투어"}, {"id": "B", "text": "레이지 프로파게이션"}, {"id": "C", "text": "DFS"}, {"id": "D", "text": "B+Tree"}]', 'A', 'LCA(최저 공통 조상) 문제는 오일러 투어 기법을 사용하여 효율적으로 해결할 수 있습니다.'),
    (1367, 4, 3, 213, '다음 중 B+Tree의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 리프 노드가 동일한 깊이를 가진다."}, {"id": "B", "text": "내부 노드가 키와 포인터를 가질 수 있다."}, {"id": "C", "text": "데이터가 내부 노드에 저장된다."}, {"id": "D", "text": "리프 노드가 데이터만 저장한다."}]', 'C', 'B+Tree는 내부 노드에는 키만 저장하고, 실제 데이터는 리프 노드에만 저장됩니다.'),
    (1368, 4, 3, 214, '레이지 프로파게이션의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "구간 업데이트의 효율성 향상"}, {"id": "B", "text": "트리의 크기 감소"}, {"id": "C", "text": "업데이트를 지연시키기"}, {"id": "D", "text": "탐색 속도 향상"}]', '["A", "C"]', '레이지 프로파게이션은 구간 업데이트를 지연시켜 효율성을 높이며, 업데이트를 한 번에 처리할 수 있도록 합니다.'),
    (1369, 4, 3, 215, '스플레이 트리는 주로 어떤 목적으로 사용되는가?', 'SHORT_ANSWER', NULL, '자주 접근되는 요소를 빠르게 탐색하기 위해 사용된다.', '스플레이 트리는 접근 빈도가 높은 요소를 빠르게 찾기 위해 구조를 재구성하는 특성을 가지고 있습니다.'),
    (1370, 4, 3, 216, '비트마스킹이 주로 사용되는 경우는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상태를 표현할 때"}, {"id": "B", "text": "정렬할 때"}, {"id": "C", "text": "데이터베이스 관리 시"}, {"id": "D", "text": "네트워크 연결할 때"}]', 'A', '비트마스킹은 특정 비트를 사용하여 다양한 상태를 표현하는 데 유용합니다.'),
    (1371, 4, 3, 217, '좌표 압축의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 사용을 줄이기 위해"}, {"id": "B", "text": "데이터를 암호화하기 위해"}, {"id": "C", "text": "속도를 높이기 위해"}, {"id": "D", "text": "데이터를 정렬하기 위해"}]', 'A', '좌표 압축은 큰 범위를 가진 좌표를 더 작은 범위로 변환하여 메모리 사용을 줄이는 데 사용됩니다.'),
    (1372, 4, 3, 218, '누적합과 슬라이딩 윈도우의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속적인 부분합을 계산한다"}, {"id": "B", "text": "두 개의 포인터를 사용한다"}, {"id": "C", "text": "정렬된 데이터를 필요로 한다"}, {"id": "D", "text": "비트 연산을 한다"}]', 'A', '두 기법 모두 연속적인 부분합을 효율적으로 계산하는 데 사용됩니다.'),
    (1373, 4, 3, 219, '다음 중 이분 탐색의 활용 예시는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "정렬된 배열에서 특정 값을 찾기"}, {"id": "B", "text": "모든 경우의 수를 탐색하기"}, {"id": "C", "text": "최소값 또는 최대값 찾기"}, {"id": "D", "text": "소수 판별하기"}]', '["A", "C"]', '이분 탐색은 정렬된 배열에서 특정 값을 찾거나, 최댓값 또는 최솟값을 찾는 데 유용합니다.'),
    (1374, 4, 3, 220, '세그먼트 트리는 주로 어떤 문제에 사용되는가?', 'SHORT_ANSWER', NULL, '구간 쿼리 문제', '세그먼트 트리는 구간 쿼리 문제에 대해 효율적인 응답을 제공하기 위해 사용됩니다.'),
    (1375, 4, 3, 221, '이진 탐색 트리(BST)의 특징으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "왼쪽 서브트리는 부모보다 작고, 오른쪽 서브트리는 부모보다 크다."}, {"id": "B", "text": "모든 노드는 두 개의 자식 노드를 가진다."}, {"id": "C", "text": "부모 노드와 자식 노드의 값은 항상 같다."}, {"id": "D", "text": "트리의 모든 노드가 서로 연결되어 있다."}]', 'A', 'BST는 왼쪽 서브트리의 모든 노드는 부모보다 작고, 오른쪽 서브트리의 모든 노드는 부모보다 큰 구조로 정의됩니다.'),
    (1376, 4, 3, 222, '최대 힙의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부모 노드는 자식 노드보다 작거나 같다."}, {"id": "B", "text": "부모 노드는 자식 노드보다 크거나 같다."}, {"id": "C", "text": "모든 노드는 반드시 두 개의 자식 노드를 가져야 한다."}, {"id": "D", "text": "트리는 반드시 완전 이진 트리여야 한다."}]', 'B', '최대 힙에서는 부모 노드가 자식 노드보다 크거나 같은 값을 유지해야 합니다.'),
    (1377, 4, 3, 223, '세그먼트 트리가 주로 사용되는 용도는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 검색."}, {"id": "B", "text": "구간 쿼리 처리."}, {"id": "C", "text": "그래프 탐색."}, {"id": "D", "text": "정렬."}]', 'B', '세그먼트 트리는 주로 배열의 구간 쿼리를 효율적으로 처리하기 위해 사용됩니다.'),
    (1378, 4, 3, 224, '트리의 종류 중, 각 노드가 최대 두 개의 자식 노드를 가지는 구조는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이진 트리"}, {"id": "B", "text": "세그먼트 트리"}, {"id": "C", "text": "트라이"}, {"id": "D", "text": "그래프"}]', '["A"]', '이진 트리는 각 노드가 최대 두 개의 자식 노드를 가질 수 있는 트리 구조입니다.'),
    (1379, 4, 3, 225, '그래프의 기본 구성 요소는 무엇인가?', 'SHORT_ANSWER', NULL, '노드와 간선', '그래프는 노드(또는 정점)와 그 노드들을 연결하는 간선으로 구성됩니다.'),
    (1380, 4, 3, 226, '단절점은 그래프의 어떤 속성을 결정하는데 중요한 역할을 하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그래프의 연결성"}, {"id": "B", "text": "그래프의 가중치"}, {"id": "C", "text": "그래프의 밀도"}, {"id": "D", "text": "그래프의 중심성"}]', 'A', '단절점은 그래프에서 특정 정점을 제거했을 때 연결성이 어떻게 변화하는지를 나타내므로 중요하다.'),
    (1381, 4, 3, 227, '크루스칼 알고리즘에서 사용되는 데이터 구조는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스택"}, {"id": "B", "text": "큐"}, {"id": "C", "text": "유니온 파인드"}, {"id": "D", "text": "해시 테이블"}]', 'C', '크루스칼 알고리즘은 최소 신장 트리를 찾기 위해 유니온 파인드 자료구조를 사용한다.'),
    (1382, 4, 3, 228, '다음 중 타잔 알고리즘의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최단 경로 찾기"}, {"id": "B", "text": "강한 연결 성분 찾기"}, {"id": "C", "text": "최소 신장 트리 찾기"}, {"id": "D", "text": "위상 정렬 수행"}]', 'B', '타잔 알고리즘은 그래프에서 강한 연결 성분(SCC)을 찾기 위해 사용된다.'),
    (1383, 4, 3, 229, '이분 그래프의 정의는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 정점이 두 그룹으로 나눌 수 있다."}, {"id": "B", "text": "모든 정점이 연결되어 있다."}, {"id": "C", "text": "두 정점 간의 모든 연결이 서로 다른 그룹에 속한다."}, {"id": "D", "text": "사이클이 없다."}]', '["A", "C"]', '이분 그래프는 모든 정점을 두 그룹으로 나눌 수 있으며, 두 그룹에 속한 정점 간에만 간선이 존재한다.'),
    (1384, 4, 3, 230, '코사라주 알고리즘의 주된 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '강한 연결 성분을 찾기 위해 사용된다.', '코사라주 알고리즘은 그래프에서 강한 연결 성분을 효율적으로 찾기 위해 설계되었다.'),
    (1385, 4, 3, 231, '크루스칼 알고리즘에서 사용되는 자료구조는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유니온 파인드"}, {"id": "B", "text": "최소 힙"}, {"id": "C", "text": "배열"}, {"id": "D", "text": "링크드 리스트"}]', 'A', '크루스칼 알고리즘은 최소 신장 트리를 생성하기 위해 유니온 파인드 자료구조를 사용하여 사이클을 방지합니다.'),
    (1386, 4, 3, 232, '플로이드-워셜 알고리즘의 주요 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 신장 트리 찾기"}, {"id": "B", "text": "모든 쌍 최단 경로 찾기"}, {"id": "C", "text": "그래프의 위상 정렬"}, {"id": "D", "text": "강한 연결 요소 찾기"}]', 'B', '플로이드-워셜 알고리즘은 모든 쌍의 최단 경로를 계산하는 데 사용됩니다.'),
    (1387, 4, 3, 233, 'BFS를 이용할 때 최단 경로를 찾기 위한 조건은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "양방향 그래프이어야 한다."}, {"id": "B", "text": "간선 가중치가 모두 동일해야 한다."}, {"id": "C", "text": "그래프가 유향이어야 한다."}, {"id": "D", "text": "그래프가 완전 그래프여야 한다."}]', 'B', 'BFS는 간선 가중치가 모두 동일한 경우에 최단 경로를 보장합니다.'),
    (1388, 4, 3, 234, '다익스트라 알고리즘에서 사용하는 자료구조는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "우선순위 큐"}, {"id": "B", "text": "스택"}, {"id": "C", "text": "해시맵"}, {"id": "D", "text": "배열"}]', '["A", "D"]', '다익스트라 알고리즘에서는 우선순위 큐와 배열을 사용하여 최소 비용 경로를 탐색합니다.'),
    (1389, 4, 3, 235, '타잔 알고리즘은 주로 어떤 문제를 해결하기 위해 사용되나요?', 'SHORT_ANSWER', NULL, '강한 연결 요소 찾기', '타잔 알고리즘은 그래프에서 강한 연결 요소를 찾는 데 사용됩니다.'),
    (1390, 4, 3, 236, '프림 알고리즘은 어떤 목적으로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최소 신장 트리"}, {"id": "B", "text": "최단 경로"}, {"id": "C", "text": "네트워크 플로우"}, {"id": "D", "text": "강한 연결 요소"}]', 'A', '프림 알고리즘은 그래프에서 최소 신장 트리를 찾기 위해 사용됩니다.'),
    (1391, 4, 3, 237, '0-1 BFS는 어떤 그래프에서 최단 경로를 찾기 위해 사용하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가중치가 0과 1인 그래프"}, {"id": "B", "text": "가중치가 양수인 그래프"}, {"id": "C", "text": "가중치가 음수인 그래프"}, {"id": "D", "text": "비가중치 그래프"}]', 'A', '0-1 BFS는 가중치가 0과 1인 그래프에서 최단 경로를 찾기 위해 사용됩니다.'),
    (1392, 4, 3, 238, '타잔 알고리즘은 무엇을 찾기 위한 알고리즘인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최단 경로"}, {"id": "B", "text": "최대 유량"}, {"id": "C", "text": "강한 연결 요소"}, {"id": "D", "text": "이분 그래프 여부"}]', 'C', '타잔 알고리즘은 그래프에서 강한 연결 요소(SCC)를 찾기 위한 알고리즘입니다.'),
    (1393, 4, 3, 239, '최대 유량 문제 해결에 사용되는 알고리즘을 모두 고르세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "포드-풀커슨 알고리즘"}, {"id": "B", "text": "크루스칼 알고리즘"}, {"id": "C", "text": "에드몬드-카프 알고리즘"}, {"id": "D", "text": "다익스트라 알고리즘"}]', '["A", "C"]', '최대 유량 문제 해결에 주로 사용되는 알고리즘은 포드-풀커슨 알고리즘과 에드몬드-카프 알고리즘입니다.'),
    (1394, 4, 3, 240, '이분 그래프란 무엇인가요?', 'SHORT_ANSWER', NULL, '정점들이 두 개의 집합으로 나뉘고, 서로 다른 집합에 있는 정점들 간에만 간선이 존재하는 그래프입니다.', '이분 그래프는 정점들이 두 개의 집합으로 나뉘며, 한 집합의 정점과 다른 집합의 정점 간에만 간선이 존재하는 그래프입니다.'),
    (1395, 4, 3, 241, 'LCP 배열의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부분 문자열 탐색 시 효율성을 높인다"}, {"id": "B", "text": "문자열을 해싱하는 알고리즘이다"}, {"id": "C", "text": "정규 표현식과 관련이 있다"}, {"id": "D", "text": "회문 판별에 사용된다"}]', 'A', 'LCP 배열은 접미사 배열을 기반으로 하여, 부분 문자열 탐색의 효율성을 높이는 데 사용됩니다.'),
    (1396, 4, 3, 242, 'KMP 알고리즘의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 문자에 대해 재탐색하지 않는다"}, {"id": "B", "text": "문자열을 정렬하여 검색한다"}, {"id": "C", "text": "해시 테이블을 사용한다"}, {"id": "D", "text": "문자열을 분할하여 비교한다"}]', 'A', 'KMP 알고리즘은 패턴과 텍스트를 비교할 때 이미 일치한 부분을 이용해 재탐색을 피하는 특징이 있습니다.'),
    (1397, 4, 3, 243, '다음 중 regex의 용도로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단어의 길이를 측정하기 위해"}, {"id": "B", "text": "문자열 패턴을 매칭하기 위해"}, {"id": "C", "text": "문자열을 정렬하기 위해"}, {"id": "D", "text": "해시 값을 생성하기 위해"}]', 'B', 'regex는 문자열 내에서 특정 패턴을 찾고 매칭하기 위해 사용되는 도구입니다.'),
    (1398, 4, 3, 244, '회문을 판별하는 알고리즘에서 어떤 조건을 확인해야 하나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "문자열이 그대로 뒤집힌다"}, {"id": "B", "text": "문자열의 길이가 짝수이어야 한다"}, {"id": "C", "text": "모든 문자가 동일해야 한다"}, {"id": "D", "text": "앞과 뒤의 문자가 일치해야 한다"}]', '["A", "D"]', '회문을 판별하기 위해서는 문자열이 그대로 뒤집혔을 때와 원래 문자열이 동일해야 하며, 앞뒤의 문자가 일치해야 합니다.'),
    (1399, 4, 3, 245, 'Sufix Array의 주요 사용 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '문자열의 부분 문자열 탐색을 빠르게 하기 위해 사용된다.', 'Sufix Array는 접미사를 정렬하여 문자열의 부분 문자열 탐색을 빠르게 하는 데 사용됩니다.'),
    (1400, 4, 3, 246, '최단 경로 알고리즘 중 다익스트라 알고리즘에서 사용하는 자료구조는 무엇인가?', 'SHORT_ANSWER', NULL, '우선순위 큐', '다익스트라 알고리즘은 최소 비용을 가진 정점을 빠르게 찾기 위해 우선순위 큐를 사용한다.'),
    (1401, 4, 3, 247, '플로이드-워셜 알고리즘의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점 간의 최단 경로를 구할 수 있다."}, {"id": "B", "text": "단일 출발점에서 최단 경로만 구한다."}, {"id": "C", "text": "그래프가 비순환일 필요가 있다."}, {"id": "D", "text": "모든 간선의 가중치는 동일해야 한다."}]', 'A', '플로이드-워셜 알고리즘은 모든 정점 간의 최단 경로를 구하는 데 사용된다.'),
    (1402, 4, 3, 248, '위상 정렬을 수행할 때 사용할 수 있는 그래프 탐색 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "DFS"}, {"id": "B", "text": "BFS"}, {"id": "C", "text": "다익스트라"}, {"id": "D", "text": "프림"}]', 'A', '위상 정렬은 DFS를 사용하여 구현할 수 있다.'),
    (1403, 4, 3, 249, '다음 중 단절점과 단절선에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "단절점은 그래프에서 해당 정점을 제거하면 연결성이 떨어지는 점이다."}, {"id": "B", "text": "단절선은 두 정점을 연결하는 간선으로, 이를 제거하면 그래프의 연결성이 떨어진다."}, {"id": "C", "text": "단절점과 단절선은 그래프 이론에서 최단 경로 계산에만 관련된다."}, {"id": "D", "text": "단절점은 항상 리프 노드에 해당한다."}]', '["A", "B"]', '단절점은 해당 정점을 제거했을 때 그래프의 연결성이 떨어지는 점이며, 단절선은 두 정점을 연결하는 간선으로, 이를 제거하면 연결성이 떨어진다.'),
    (1404, 4, 3, 250, '해시 테이블의 주된 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '빠른 데이터 검색', '해시 테이블은 키를 해시 함수로 변환하여 빠른 검색 속도를 제공하는 자료구조입니다.'),
    (1405, 4, 3, 251, '해시 충돌을 해결하는 방법으로 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "소트하기"}, {"id": "C", "text": "오픈 어드레싱"}, {"id": "D", "text": "리해싱"}]', 'B', '소트하기는 해시 충돌을 해결하는 방법이 아닙니다.'),
    (1406, 4, 3, 252, 'HashMap에서 충돌을 해결하기 위한 기법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "리해싱"}, {"id": "C", "text": "해시 함수 재설계"}, {"id": "D", "text": "이진 검색"}]', 'D', '이진 검색은 해시 충돌 해결과 관련된 기법이 아닙니다.'),
    (1407, 4, 3, 253, '다음 중 해시 충돌 해결 방법으로 적절한 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "체이닝"}, {"id": "B", "text": "오픈 어드레싱"}, {"id": "C", "text": "다이렉트 어드레싱"}, {"id": "D", "text": "리해싱"}]', '["A", "B", "D"]', '체이닝, 오픈 어드레싱, 그리고 리해싱은 해시 충돌을 해결하는 방법입니다.'),
    (1408, 4, 3, 254, 'AVL 트리의 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '자가 균형 이진 탐색 트리', 'AVL 트리는 삽입 및 삭제 시 트리의 균형을 유지하여 빠른 검색 성능을 제공합니다.'),
    (1409, 4, 3, 255, '가중치 그래프에서 간선에 대해 무엇이 부여되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가중치"}, {"id": "B", "text": "정점 이름"}, {"id": "C", "text": "형태"}, {"id": "D", "text": "연결성"}]', 'A', '가중치 그래프는 각 간선에 가중치를 부여하여 다양한 길 찾기 알고리즘에 활용됩니다.'),
    (1410, 4, 3, 256, 'B-Tree의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다수의 자식을 가질 수 있다."}, {"id": "B", "text": "단일 자식만 가진다."}, {"id": "C", "text": "오직 이진탐색만 가능하다."}, {"id": "D", "text": "균형이 필요하지 않다."}]', 'A', 'B-Tree는 다수의 자식을 가질 수 있도록 설계되어 대량의 데이터를 효과적으로 관리합니다.'),
    (1411, 4, 3, 257, '다음 중 인접 리스트의 특징으로 옳은 것은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 효율성이 높다."}, {"id": "B", "text": "모든 간선이 연속적으로 저장된다."}, {"id": "C", "text": "간선의 수에 따라 크기가 변한다."}, {"id": "D", "text": "순차 접근이 빠르다."}]', '["A", "C"]', '인접 리스트는 간선의 수에 따라 메모리 크기가 변하고 메모리 효율성이 높습니다.'),
    (1412, 4, 3, 258, '펜윅 트리의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "범위 합 쿼리"}, {"id": "B", "text": "최소 공통 조상 구하기"}, {"id": "C", "text": "트리의 지름 구하기"}, {"id": "D", "text": "이진 탐색 수행"}]', 'A', '펜윅 트리는 효율적인 범위 합 쿼리를 지원하며, 데이터의 합을 빠르게 계산할 수 있습니다.'),
    (1413, 4, 3, 259, 'HLD(Heavy Light Decomposition)의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "트리를 정렬하기 위해"}, {"id": "B", "text": "쿼리 처리의 최적화"}, {"id": "C", "text": "이진 탐색 수행"}, {"id": "D", "text": "노드 개수 카운트"}]', 'B', 'HLD는 트리를 여러 개의 경량 부분으로 나누어 쿼리 처리를 최적화하는 기법입니다.'),
    (1414, 4, 3, 260, '다음 중 B+트리의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 리프 노드가 같은 깊이에 있다."}, {"id": "B", "text": "데이터가 리프 노드에만 저장된다."}, {"id": "C", "text": "내부 노드는 데이터 저장이 가능하다."}, {"id": "D", "text": "균형을 유지한다."}]', 'C', 'B+트리는 데이터가 리프 노드에만 저장되며, 내부 노드는 오직 키 값만을 저장합니다.'),
    (1415, 4, 3, 261, '트리의 지름을 정의하세요.', 'SHORT_ANSWER', NULL, '두 노드 사이의 최대 거리', '트리의 지름은 두 노드 사이의 최대 거리를 의미합니다.'),
    (1416, 4, 3, 262, '오일러 투어를 통해 어떤 정보를 쉽게 구할 수 있는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "최소 공통 조상"}, {"id": "B", "text": "트리의 깊이"}, {"id": "C", "text": "트리의 사이즈"}, {"id": "D", "text": "트리의 높이"}]', '["A", "B"]', '오일러 투어는 트리를 순회하여 노드를 배열 형태로 나열하고, 이를 통해 최소 공통 조상과 트리의 깊이를 쉽게 구할 수 있습니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- Java와 Spring > Java 기본과 심화 (508문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (1417, 5, 1, 1, 'Java에서 OOP의 주요 개념이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다형성"}, {"id": "B", "text": "추상화"}, {"id": "C", "text": "가비지 컬렉션"}, {"id": "D", "text": "상속"}]', 'C', '가비지 컬렉션은 메모리 관리와 관련된 기능으로 OOP의 개념이 아닙니다.'),
    (1418, 5, 1, 2, 'JVM의 역할은 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Java 코드를 컴파일하는 것"}, {"id": "B", "text": "Java 애플리케이션을 실행하는 것"}, {"id": "C", "text": "Java의 버전을 관리하는 것"}, {"id": "D", "text": "Java 프로그램을 디버깅하는 것"}]', 'B', 'JVM은 Java 애플리케이션을 실행하는 환경을 제공합니다.'),
    (1419, 5, 1, 3, '아래 중에서 Java에서 final 키워드의 사용이 잘못된 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "final 변수를 변경할 수 있다."}, {"id": "B", "text": "final 메서드는 오버라이드할 수 없다."}, {"id": "C", "text": "final 클래스는 상속할 수 없다."}, {"id": "D", "text": "final 변수는 한 번만 초기화 가능하다."}]', 'A', 'final 변수는 한 번 초기화되면 변경할 수 없으므로 잘못된 선택입니다.'),
    (1420, 5, 1, 4, 'Java에서 null을 대체하기 위해 사용하는 클래스는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "Optional"}, {"id": "B", "text": "ArrayList"}, {"id": "C", "text": "HashMap"}, {"id": "D", "text": "String"}]', '["A"]', 'Optional 클래스는 null 대신 사용할 수 있는 컨테이너로 NullPointerException을 방지하는 데 유용합니다.'),
    (1421, 5, 1, 5, 'Java에서 가비지 컬렉션의 주 목적은 무엇입니까?', 'SHORT_ANSWER', NULL, '사용하지 않는 객체를 자동으로 회수하여 메모리를 관리하는 것', ''),
    (1422, 5, 1, 6, '접근 제어자의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터의 접근을 제어하여 보호한다.', '접근 제어자는 클래스 멤버의 visibility를 조절하여 외부에서 직접 접근할 수 없도록 함으로써 데이터 보호를 강화합니다.'),
    (1423, 5, 1, 7, '다음 중 Java에서 상속의 장점이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드 재사용성 증가"}, {"id": "B", "text": "프로그램의 복잡성 증가"}, {"id": "C", "text": "유지보수 용이"}, {"id": "D", "text": "다형성 제공"}]', 'B', '상속은 코드의 재사용성과 유지보수성을 높여주지만, 잘못 사용될 경우 프로그램의 복잡성을 증가시킬 수 있습니다.'),
    (1424, 5, 1, 8, '어노테이션의 사용 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메타데이터 제공"}, {"id": "B", "text": "코드 실행 속도 향상"}, {"id": "C", "text": "메소드 오버로딩 지원"}, {"id": "D", "text": "클래스 로딩 최적화"}]', 'A', '어노테이션은 코드에 메타데이터를 추가하여, 컴파일러나 런타임에 특정 처리를 할 수 있도록 합니다.'),
    (1425, 5, 1, 9, '다음 중 Java에서 캡슐화의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 보호"}, {"id": "B", "text": "코드 재사용"}, {"id": "C", "text": "내부 구현 숨기기"}, {"id": "D", "text": "상속 허용"}]', '["A", "C"]', '캡슐화는 데이터 보호와 내부 구현을 숨김으로써 객체지향 프로그래밍의 핵심 원칙 중 하나입니다.'),
    (1426, 5, 1, 10, 'Java에서 클래스 로더의 주된 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클래스 파일을 메모리에 로드한다."}, {"id": "B", "text": "객체의 메모리를 해제한다."}, {"id": "C", "text": "메서드의 실행 속도를 향상시킨다."}, {"id": "D", "text": "상속 구조를 관리한다."}]', 'A', '클래스 로더는 Java 애플리케이션이 실행되는 동안 필요한 클래스 파일을 메모리에 로드하는 역할을 합니다.'),
    (1427, 5, 1, 11, 'final 키워드가 적용된 변수의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "값을 변경할 수 없다."}, {"id": "B", "text": "값을 자유롭게 변경할 수 있다."}, {"id": "C", "text": "자동으로 메모리에서 해제된다."}, {"id": "D", "text": "상속을 통해 변경된다."}]', 'A', 'final 키워드는 변수가 한 번 초기화된 후 그 값을 변경할 수 없게 합니다.'),
    (1428, 5, 1, 12, '다음 중 Java의 가비지 컬렉션에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리를 수동으로 관리해야 한다."}, {"id": "B", "text": "더 이상 참조되지 않는 객체를 자동으로 정리한다."}, {"id": "C", "text": "객체의 메모리 누수를 증가시킨다."}, {"id": "D", "text": "모든 객체를 즉시 삭제한다."}]', 'B', '가비지 컬렉션은 더 이상 사용되지 않는 객체를 자동으로 메모리에서 제거하여 메모리 관리를 효율적으로 수행합니다.'),
    (1429, 5, 1, 13, 'Java에서 추상 클래스와 인터페이스의 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "추상 클래스는 메서드의 구현을 가질 수 있다."}, {"id": "B", "text": "인터페이스는 다중 상속을 지원한다."}, {"id": "C", "text": "추상 클래스는 인스턴스를 만들 수 있다."}, {"id": "D", "text": "인터페이스는 상태를 가질 수 있다."}]', '["A", "B"]', '추상 클래스는 일부 메서드에 구현을 가질 수 있고 인스턴스를 만들 수 없으며, 인터페이스는 다중 상속을 지원하지만 상태를 가질 수 없습니다.'),
    (1430, 5, 1, 14, 'Java의 Enum은 어떤 용도로 사용되나요?', 'SHORT_ANSWER', NULL, '상수 집합을 정의하기 위해 사용된다.', 'Enum은 특정 상수 집합을 정의하여 코드의 가독성과 유지보수성을 높이는 데 사용됩니다.'),
    (1431, 5, 1, 15, '''static'' 키워드를 사용하면 어떤 특성을 가집니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클래스의 모든 인스턴스에서 공유된다."}, {"id": "B", "text": "인스턴스별로 다르게 작동한다."}, {"id": "C", "text": "메서드 오버라이드를 지원한다."}, {"id": "D", "text": "정적 메모리 할당을 하지 않는다."}]', 'A', '''static'' 키워드는 클래스의 모든 인스턴스에서 공유되는 특성을 나타냅니다.'),
    (1432, 5, 1, 16, '캡슐화의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드 재사용."}, {"id": "B", "text": "데이터 보호."}, {"id": "C", "text": "성능 향상."}, {"id": "D", "text": "목록 정렬."}]', 'B', '캡슐화의 주된 목적은 객체의 상태를 보호하고 불필요한 외부 접근을 제한하는 것입니다.'),
    (1433, 5, 1, 17, 'Java에서 ''final'' 키워드가 사용될 수 있는 위치는 어디인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변수"}, {"id": "B", "text": "메서드"}, {"id": "C", "text": "클래스"}, {"id": "D", "text": "인터페이스"}]', '["A", "B", "C"]', '''final'' 키워드는 변수, 메서드, 클래스에 적용될 수 있으며, 이를 통해 변경 불가능성을 나타냅니다.'),
    (1434, 5, 1, 18, 'Java에서 Optional 클래스의 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NullPointerException 방지', 'Optional 클래스는 null을 안전하게 처리하여 NullPointerException을 방지하는 데 도움을 줍니다.'),
    (1435, 5, 1, 19, 'Java에서 객체는 어느 메모리에 저장되나요?', 'SHORT_ANSWER', NULL, '힙 메모리', 'Java에서 생성된 객체는 힙 메모리에 할당됩니다.'),
    (1436, 5, 1, 20, 'Java에서 스택 메모리는 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "지역 변수 및 매개변수를 저장하기 위해"}, {"id": "B", "text": "전역 변수를 저장하기 위해"}, {"id": "C", "text": "클래스를 정의하기 위해"}, {"id": "D", "text": "객체를 생성하기 위해"}]', 'A', '스택 메모리는 함수 호출 시 생성되는 지역 변수와 매개변수를 저장하는 용도로 사용됩니다.'),
    (1437, 5, 1, 21, '캡슐화의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 보호"}, {"id": "B", "text": "상속 증대"}, {"id": "C", "text": "코드 길이 단축"}, {"id": "D", "text": "객체 생성 속도 향상"}]', 'A', '캡슐화는 데이터를 보호하고 외부 접근을 제한하는 것이 주된 목적입니다.'),
    (1438, 5, 1, 22, '다음 중 Java의 접근 제어자에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "public"}, {"id": "B", "text": "private"}, {"id": "C", "text": "static"}, {"id": "D", "text": "protected"}]', 'C', 'static은 접근 제어자가 아니라 멤버의 속성을 정의하는 키워드입니다.'),
    (1439, 5, 1, 23, 'Java의 추상화 개념에 해당하는 것들은 무엇인가요? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "추상 클래스"}, {"id": "B", "text": "인터페이스"}, {"id": "C", "text": "구현 클래스"}, {"id": "D", "text": "일반 클래스"}]', '["A", "B"]', '추상 클래스와 인터페이스는 Java에서 추상화를 실현하는 주요 요소입니다.'),
    (1440, 5, 1, 24, 'Optional 클래스의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'null 안전 처리', 'Optional 클래스는 null 값을 안전하게 처리하기 위한 방법을 제공합니다.'),
    (1441, 5, 1, 25, '람다 표현식을 사용하기 위해 필요한 인터페이스는 무엇인가?', 'SHORT_ANSWER', NULL, '함수형 인터페이스', '람다 표현식은 반드시 하나의 추상 메서드를 가진 함수형 인터페이스와 함께 사용해야 합니다.'),
    (1442, 5, 1, 26, 'Comparator 인터페이스는 주로 어떤 작업에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체 정렬"}, {"id": "B", "text": "객체 비교"}, {"id": "C", "text": "객체 생성"}, {"id": "D", "text": "객체 삭제"}]', 'A', 'Comparator 인터페이스는 두 객체를 비교하여 순서를 결정하는 데 사용됩니다.'),
    (1443, 5, 1, 27, 'HashMap의 내부 구조에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열과 링크드 리스트를 조합한 구조이다."}, {"id": "B", "text": "모든 요소를 배열에 연속적으로 저장한다."}, {"id": "C", "text": "해시 테이블을 기반으로 한다."}, {"id": "D", "text": "구조가 단일 연결 리스트로 되어 있다."}]', 'C', 'HashMap은 해시 테이블을 기반으로 하여 데이터를 저장하고 검색하는 구조를 가지고 있습니다.'),
    (1444, 5, 1, 28, '다음 중 Lambda 표현식의 특징이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "간결한 코드 작성"}, {"id": "B", "text": "상태를 저장할 필요가 있다."}, {"id": "C", "text": "함수형 프로그래밍 스타일 지원"}, {"id": "D", "text": "메서드 레퍼런스와 함께 사용 가능"}]', '["B"]', 'Lambda 표현식은 상태를 저장하지 않고 익명 함수 형태로 사용되며 간결하고 함수형 프로그래밍 스타일을 지원합니다.'),
    (1445, 5, 1, 29, '람다 표현식의 주요 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드를 간결하게 만든다"}, {"id": "B", "text": "메모리 사용량을 증가시킨다"}, {"id": "C", "text": "코드의 복잡성을 높인다"}, {"id": "D", "text": "가독성을 낮춘다"}]', 'A', '람다 표현식은 코드를 간결하게 만들어 주며, 함수형 프로그래밍을 가능하게 합니다.'),
    (1446, 5, 1, 30, 'ConcurrentHashMap의 특징으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동기화된 모든 메서드를 가진다"}, {"id": "B", "text": "스레드 안전성을 제공한다"}, {"id": "C", "text": "정렬된 데이터를 가진다"}, {"id": "D", "text": "단일 스레드에서만 사용 가능하다"}]', 'B', 'ConcurrentHashMap은 스레드 안전성을 제공하여 여러 스레드가 동시에 접근해도 안전합니다.'),
    (1447, 5, 1, 31, 'HashMap의 내부 구조에서 해시 충돌이 발생할 때 어떻게 처리되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "체이닝을 사용한다"}, {"id": "B", "text": "오버플로우를 발생시킨다"}, {"id": "C", "text": "무시한다"}, {"id": "D", "text": "데이터를 삭제한다"}]', 'A', 'HashMap은 해시 충돌이 발생할 때 체이닝 기법을 사용하여 데이터를 저장합니다.'),
    (1448, 5, 1, 32, '다음 중 동시성 프로그래밍에서 사용할 수 있는 클래스들은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "AtomicInteger"}, {"id": "B", "text": "HashMap"}, {"id": "C", "text": "synchronized"}, {"id": "D", "text": "ConcurrentHashMap"}]', '["A", "D"]', 'AtomicInteger와 ConcurrentHashMap은 동시성 프로그래밍에서 사용되는 클래스입니다.'),
    (1449, 5, 1, 33, 'volatile 키워드의 주된 역할은 무엇인가?', 'SHORT_ANSWER', NULL, '변수의 가시성을 보장한다', 'volatile 키워드는 변수의 가시성을 보장하여 여러 스레드가 접근할 때 일관성을 유지하게 합니다.'),
    (1450, 5, 1, 34, '다음 중 Java에서 캡슐화의 정의로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 내부 상태를 숨기고 외부에서 접근을 제한하는 기법"}, {"id": "B", "text": "여러 클래스가 동일한 메서드를 가질 수 있도록 하는 기법"}, {"id": "C", "text": "객체의 형식을 변경할 수 있는 기법"}, {"id": "D", "text": "상속을 통해 새로운 클래스를 만드는 기법"}]', 'A', '캡슐화는 객체의 내부 상태를 숨기고, 외부에서 직접 접근하지 못하도록 제한하는 OOP의 기본 원칙입니다.'),
    (1451, 5, 1, 35, '다형성이란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하나의 객체가 여러 형태를 가질 수 있는 능력"}, {"id": "B", "text": "클래스가 다른 클래스를 상속하는 것"}, {"id": "C", "text": "변수를 static으로 선언하는 것"}, {"id": "D", "text": "메서드의 오버로딩을 의미하는 것"}]', 'A', '다형성은 하나의 객체가 여러 형태를 가질 수 있는 능력으로, OOP의 중요한 개념입니다.'),
    (1452, 5, 1, 36, 'Java에서 Optional 클래스의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "null을 안전하게 처리하기 위해"}, {"id": "B", "text": "메모리 관리를 효율적으로 하기 위해"}, {"id": "C", "text": "데이터베이스 연결을 쉽게 하기 위해"}, {"id": "D", "text": "객체 간의 상속 관계를 정의하기 위해"}]', 'A', 'Optional 클래스는 null 값을 안전하게 처리하기 위해 도입된 클래스입니다.'),
    (1453, 5, 1, 37, 'Java에서 사용할 수 있는 어노테이션의 예를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@Override"}, {"id": "B", "text": "@SuppressWarnings"}, {"id": "C", "text": "@Entity"}, {"id": "D", "text": "@Static"}]', '["A", "B", "C"]', 'Java에서 @Override, @SuppressWarnings, @Entity는 모두 사용 가능한 어노테이션입니다.'),
    (1454, 5, 1, 38, 'Java 가상 머신(JVM)의 역할은 무엇인가?', 'SHORT_ANSWER', NULL, 'Java 바이트코드를 실행하는 환경을 제공하는 것', 'JVM은 Java 프로그램을 실행할 수 있도록 Java 바이트코드를 해석하고 실행하는 환경을 제공합니다.'),
    (1455, 5, 1, 39, '스트림 API를 사용하면 어떤 이점을 얻을 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드의 가독성을 높인다"}, {"id": "B", "text": "메모리 사용량이 항상 줄어든다"}, {"id": "C", "text": "성능이 항상 향상된다"}, {"id": "D", "text": "서버에 직접 접근할 수 있다"}]', 'A', '스트림 API를 사용하면 반복문을 줄이고, 함수형 접근 방식으로 코드를 구성하여 가독성을 높일 수 있습니다.'),
    (1456, 5, 1, 40, 'CompletableFuture의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비동기 프로그래밍"}, {"id": "B", "text": "동기화 처리"}, {"id": "C", "text": "직렬화"}, {"id": "D", "text": "객체 비교"}]', 'A', 'CompletableFuture는 비동기 프로그래밍을 지원하여 여러 작업을 동시에 처리할 수 있게 해줍니다.'),
    (1457, 5, 1, 41, 'synchronized 키워드의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 직렬화를 돕기 위해"}, {"id": "B", "text": "스레드의 동기화를 위해"}, {"id": "C", "text": "객체의 정렬을 위해"}, {"id": "D", "text": "람다 표현식을 위해"}]', 'B', 'synchronized 키워드는 여러 스레드가 공유 자원에 동시에 접근하지 못하도록 해 동기화를 보장합니다.'),
    (1458, 5, 1, 42, '람다 표현식의 장점을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "코드의 간결함"}, {"id": "B", "text": "불변성을 보장"}, {"id": "C", "text": "함수형 프로그래밍 지원"}, {"id": "D", "text": "객체 지향 프로그래밍 지원"}]', '["A", "C"]', '람다 표현식은 코드를 간결하게 만들고 함수형 프로그래밍을 지원하여 유연한 코딩을 가능하게 합니다.'),
    (1459, 5, 1, 43, 'ThreadLocal의 주된 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '스레드마다 독립적인 변수를 제공하는 것', 'ThreadLocal은 각 스레드가 자신만의 변수를 가지고 작업할 수 있도록 하여 동시성 문제를 해결하는 데 유용합니다.'),
    (1460, 5, 1, 44, 'Java에서 JRE의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Java 프로그램을 실행하는 환경을 제공한다."}, {"id": "B", "text": "Java 코드를 작성하는 IDE이다."}, {"id": "C", "text": "Java의 버전을 관리하는 툴이다."}, {"id": "D", "text": "Java 프로그램을 컴파일하는 역할을 한다."}]', 'A', 'JRE는 Java Runtime Environment의 약자로, Java 프로그램이 실행될 수 있는 환경을 제공합니다.'),
    (1461, 5, 1, 45, 'final 키워드를 사용하는 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "변수, 메소드, 클래스를 변경 불가능하게 만든다."}, {"id": "B", "text": "변수의 값을 증가시키기 위해 사용한다."}, {"id": "C", "text": "메소드의 오버로딩을 허용한다."}, {"id": "D", "text": "클래스의 상속을 제한한다."}]', 'A', 'final 키워드는 변수, 메소드, 클래스를 변경 불가능하게 만들어, 재정의나 수정이 불가능합니다.'),
    (1462, 5, 1, 46, '다음 중 OOP의 기본 개념이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "추상화"}, {"id": "B", "text": "상속"}, {"id": "C", "text": "스레드"}, {"id": "D", "text": "다형성"}]', 'C', '스레드는 OOP의 기본 개념이 아니며, OOP는 추상화, 상속, 다형성 등을 포함합니다.'),
    (1463, 5, 1, 47, '다음 중 Java에서 Optional을 사용하는 주된 이유는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NullPointerException을 방지하기 위해"}, {"id": "B", "text": "메소드의 오버로딩을 단순화하기 위해"}, {"id": "C", "text": "유연한 API 설계를 위해"}, {"id": "D", "text": "코드 가독성을 높이기 위해"}]', '["A", "C", "D"]', 'Optional은 null 값을 방지하고, 유연한 API 설계를 가능하게 하며, 코드 가독성을 높이기 위해 사용됩니다.'),
    (1464, 5, 1, 48, 'Java에서 인터페이스의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '다양한 클래스 간의 계약을 정의하여 다형성을 제공한다.', '인터페이스는 다양한 클래스가 동일한 메소드를 구현하도록 하여 다형성을 지원합니다.'),
    (1465, 5, 1, 49, 'Java의 JDK는 무엇을 포함하고 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "컴파일러와 라이브러리"}, {"id": "B", "text": "데이터베이스"}, {"id": "C", "text": "웹 서버"}, {"id": "D", "text": "네트워크 도구"}]', 'A', 'JDK는 Java 프로그램을 개발하기 위한 컴파일러와 필요한 라이브러리를 포함합니다.'),
    (1466, 5, 1, 50, '다음 중 접근 제어자에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "private"}, {"id": "B", "text": "public"}, {"id": "C", "text": "protected"}, {"id": "D", "text": "static"}]', 'D', 'static은 접근 제어자가 아니라 메서드나 변수의 속성을 나타내는 키워드입니다.'),
    (1467, 5, 1, 51, '다형성을 설명하는 올바른 진술은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하나의 인터페이스를 통해 여러 클래스의 메서드를 호출할 수 있다."}, {"id": "B", "text": "한 클래스가 여러 부모 클래스를 가질 수 있다."}, {"id": "C", "text": "모든 클래스는 추상 클래스를 상속해야 한다."}, {"id": "D", "text": "변수의 타입에 따라 객체의 기능이 고정된다."}]', 'A', '다형성은 하나의 인터페이스를 통해 여러 클래스의 메서드를 호출할 수 있는 기능을 의미합니다.'),
    (1468, 5, 1, 52, 'Java에서 가비지 컬렉션의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 누수 방지"}, {"id": "B", "text": "객체를 수동으로 삭제"}, {"id": "C", "text": "프로그램 실행 속도 향상"}, {"id": "D", "text": "사용되지 않는 객체의 메모리 해제"}]', '["A", "D"]', '가비지 컬렉션은 메모리 누수를 방지하고 사용되지 않는 객체의 메모리를 자동으로 해제하는 역할을 합니다.'),
    (1469, 5, 1, 53, 'Optional 클래스는 어떤 용도로 사용되는가?', 'SHORT_ANSWER', NULL, 'null이 될 수 있는 객체를 안전하게 처리하기 위해 사용된다.', 'Optional 클래스는 null을 안전하게 처리할 수 있는 기능을 제공합니다.'),
    (1470, 5, 1, 54, 'Java에서 접근 제어자가 포함되지 않은 경우, 기본적으로 어떤 접근 수준이 적용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "private"}, {"id": "B", "text": "protected"}, {"id": "C", "text": "public"}, {"id": "D", "text": "default"}]', 'D', '기본 접근 제어자는 접근 제어자가 명시되지 않은 경우 ''default''로 설정되어, 같은 패키지 내에서만 접근할 수 있습니다.'),
    (1471, 5, 1, 55, '인터페이스와 추상 클래스의 차이점으로 맞는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인터페이스는 인스턴스를 가질 수 있지만, 추상 클래스는 가질 수 없다."}, {"id": "B", "text": "추상 클래스는 필드를 가질 수 있지만, 인터페이스는 가질 수 없다."}, {"id": "C", "text": "인터페이스는 다중 상속을 지원하지만, 추상 클래스는 그렇지 않다."}, {"id": "D", "text": "추상 클래스는 모든 메서드를 추상 메서드로 정의해야 한다."}]', 'C', '인터페이스는 클래스가 여러 개의 인터페이스를 구현할 수 있어 다중 상속을 지원하지만, 추상 클래스는 단일 상속만 가능합니다.'),
    (1472, 5, 1, 56, '다음 중 Java의 가비지 컬렉션에 대한 설명으로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "가비지 컬렉션은 수동으로 메모리를 관리해야 한다."}, {"id": "B", "text": "가비지 컬렉터는 사용하지 않는 객체를 자동으로 메모리에서 제거한다."}, {"id": "C", "text": "가비지 컬렉션은 메모리 누수를 방지하는 데 도움을 준다."}, {"id": "D", "text": "가비지 컬렉션은 객체의 생명주기를 제어한다."}]', '["B", "C"]', '가비지 컬렉션은 사용하지 않는 객체를 자동으로 제거하며, 메모리 누수를 방지하는 데 도움을 줍니다.'),
    (1473, 5, 1, 57, 'Java에서 Optional 클래스를 사용하는 주된 이유는 무엇인가?', 'SHORT_ANSWER', NULL, 'null 값으로 인한 NullPointerException 방지', 'Optional 클래드는 null 값을 안전하게 처리하기 위해 도입되었으며, NullPointerException을 방지하는 데 큰 도움이 됩니다.'),
    (1474, 5, 1, 58, '다음 중 JPA Repository에서 CRUD 작업을 위한 기본 인터페이스는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "JpaRepository"}, {"id": "B", "text": "CrudRepository"}, {"id": "C", "text": "Repository"}, {"id": "D", "text": "JPARepository"}]', 'A', 'JpaRepository는 CRUD 작업을 위한 기본 인터페이스입니다.'),
    (1475, 5, 1, 59, '아래 코드에서 빈칸에 들어갈 메서드는 무엇인가요? 
 `public interface UserRepository extends JpaRepository<User, Long> { 
 List<User> ____(String lastName); 
 }`', 'SHORT_ANSWER', NULL, 'findByLastName', 'findByLastName 메서드는 LastName으로 사용자 목록을 조회하는 쿼리 메서드입니다.'),
    (1476, 5, 1, 60, '다음 중 JPA Repository 쿼리 메서드에 대한 설명으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메서드 이름으로 SQL 쿼리를 생성한다."}, {"id": "B", "text": "단순한 CRUD 작업만 지원한다."}, {"id": "C", "text": "복잡한 쿼리 메서드를 정의할 수 있다."}, {"id": "D", "text": "조건에 따라 다양한 데이터를 조회할 수 있다."}]', 'B', 'JPA Repository는 단순한 CRUD 작업 외에도 복잡한 쿼리 메서드를 지원합니다.'),
    (1477, 5, 1, 61, '다음 중 JPA Repository의 쿼리 메서드를 사용하는 방법에 대해 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메서드 이름에 findBy를 포함해야 한다."}, {"id": "B", "text": "SQL 쿼리를 직접 작성해야 한다."}, {"id": "C", "text": "메서드를 호출하여 데이터베이스에 접근할 수 있다."}, {"id": "D", "text": "반드시 @Query 어노테이션을 사용해야 한다."}]', '["A", "C"]', 'JPA Repository의 쿼리 메서드는 메서드 이름에 ''findBy''를 포함해야 하고, 호출을 통해 데이터베이스에 접근할 수 있습니다.'),
    (1478, 5, 1, 62, '위 코드에서 `Animal` 인터페이스의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동물의 소리를 정의하는 청사진"}, {"id": "B", "text": "비행 기능을 정의하는 청사진"}, {"id": "C", "text": "새의 행동을 정의하는 청사진"}, {"id": "D", "text": "모든 동물에서 사용할 수 있는 기능"}]', 'A', 'Animal 인터페이스는 동물의 소리 기능을 정의하는 청사진입니다.'),
    (1479, 5, 1, 63, '추상 클래스 `Bird`의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 메서드가 구현되어 있다"}, {"id": "B", "text": "하나 이상의 추상 메서드를 가질 수 있다"}, {"id": "C", "text": "다중 상속이 가능하다"}, {"id": "D", "text": "인스턴스를 생성할 수 있다"}]', 'B', '추상 클래스 `Bird`는 하나 이상의 추상 메서드를 가질 수 있는 특징이 있습니다.'),
    (1480, 5, 1, 64, '다음 코드의 빈칸을 채우세요:

class __ extends Bird {
    void sound() {
        System.out.println("Chirp");
    }
    void fly() {
        System.out.println("Sparrow is flying");
    }
}', 'SHORT_ANSWER', NULL, 'Sparrow', 'Sparrow 클래스가 Bird를 상속하여 sound 메서드와 fly 메서드를 구현합니다.'),
    (1481, 5, 1, 65, '다음 중 인터페이스와 추상 클래스의 차이점으로 올바른 것은 무엇인가요? (복수 선택 가능)
- (1) 인터페이스는 다중 상속을 지원한다.
- (2) 추상 클래스는 모든 메서드가 구현되어야 한다.
- (3) 인터페이스는 메서드의 구현을 제공하지 않는다.
- (4) 추상 클래스는 인스턴스를 생성할 수 있다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "1", "text": "인터페이스는 다중 상속을 지원한다."}, {"id": "2", "text": "추상 클래스는 모든 메서드가 구현되어야 한다."}, {"id": "3", "text": "인터페이스는 메서드의 구현을 제공하지 않는다."}, {"id": "4", "text": "추상 클래스는 인스턴스를 생성할 수 있다."}]', '["1", "3", "4"]', '인터페이스는 다중 상속을 지원하고 메서드의 구현을 제공하지 않으며, 추상 클래스는 인스턴스를 생성할 수 없습니다.'),
    (1482, 5, 1, 66, 'Optional을 사용하여 값을 생성하는 올바른 방법은 무엇인가요? 예: Optional 객체 생성 코드

Optional< String > optionalName = Optional.__________(name);', 'SHORT_ANSWER', NULL, 'ofNullable', 'ofNullable 메서드를 사용하면 값이 null일 수 있는 경우 Optional 객체를 생성할 수 있습니다.'),
    (1483, 5, 1, 67, '다음 중 Optional 객체의 값이 존재하는지 확인하는 메서드는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "isPresent()"}, {"id": "B", "text": "exists()"}, {"id": "C", "text": "ifPresent()"}, {"id": "D", "text": "isEmpty()"}]', 'A', 'isPresent() 메서드는 Optional 객체에 값이 존재하는지 여부를 반환합니다.'),
    (1484, 5, 1, 68, '다음 코드의 출력 결과는 무엇인가요?

Optional< String > optional = Optional.of("Hello");
System.out.println(optional.orElse("Default"));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello"}, {"id": "B", "text": "Default"}, {"id": "C", "text": "null"}, {"id": "D", "text": "Optional.empty()"}]', 'A', 'optional 객체에 값이 존재하므로 orElse()는 "Hello"를 반환합니다.'),
    (1485, 5, 1, 69, '다음 중 Optional 객체에서 값을 안전하게 처리하기 위한 방법으로 올바른 것은 무엇인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "get()"}, {"id": "B", "text": "ifPresent()"}, {"id": "C", "text": "orElse()"}, {"id": "D", "text": "map()"}]', '["B", "C", "D"]', 'ifPresent(), orElse(), map()는 값이 존재하는 경우 안전하게 처리하는 방법입니다.'),
    (1486, 5, 1, 70, 'Optional 클래스의 주된 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'null을 방지하고 코드의 가독성을 높이는 것', 'Optional 클래스는 null을 방지하여 NullPointerException을 피하고, 코드의 가독성을 높이는 데 도움을 줍니다.'),
    (1487, 5, 1, 71, '다음 코드의 Bean 스코프는 무엇인가요?

@Bean
@Scope("singleton")
public MyBean myBean() {
    return new MyBean();
}
', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "singleton"}, {"id": "B", "text": "prototype"}, {"id": "C", "text": "request"}, {"id": "D", "text": "session"}]', 'A', '이 코드는 singleton 스코프로 설정되어 있어 애플리케이션 전체에서 동일한 Bean 인스턴스가 사용됩니다.'),
    (1488, 5, 1, 72, 'Spring Bean 생명주기에서 초기화 메서드를 지정하는 애노테이션은 무엇인가요?', 'SHORT_ANSWER', NULL, '@PostConstruct', '@PostConstruct 애노테이션은 Bean이 초기화될 때 실행할 메서드를 지정합니다.'),
    (1489, 5, 1, 73, '다음 코드의 실행 결과는 어떻게 될까요?

@Bean
@Scope("prototype")
public MyBean myBean() {
    return new MyBean();
}
MyBean bean1 = myBean();
MyBean bean2 = myBean();

// bean1과 bean2의 주소가 같을까요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "같다"}, {"id": "B", "text": "다르다"}, {"id": "C", "text": "예측할 수 없다"}, {"id": "D", "text": "오류가 발생한다"}]', 'B', 'Prototype 스코프에서는 새로운 Bean 인스턴스가 매번 생성되므로, bean1과 bean2의 주소는 다릅니다.'),
    (1490, 5, 1, 74, '다음 중 Spring Bean의 생명주기 메서드로 사용될 수 있는 애노테이션은 어떤 것들이 있나요?
1. @PostConstruct
2. @PreDestroy
3. @Autowired
4. @Component', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@PostConstruct"}, {"id": "B", "text": "@PreDestroy"}, {"id": "C", "text": "@Autowired"}, {"id": "D", "text": "@Component"}]', '["A", "B"]', '@PostConstruct와 @PreDestroy는 각각 초기화 및 소멸 시 실행할 메서드를 지정하는 애노테이션입니다.'),
    (1491, 5, 1, 75, '다음 중 JPA에서 엔티티를 정의할 때 사용하는 어노테이션은 무엇인가요? @_____', 'SHORT_ANSWER', NULL, 'Entity', '@Entity 어노테이션은 JPA에서 엔티티 클래스를 정의하기 위해 사용됩니다.'),
    (1492, 5, 1, 76, '다음 코드에서 Author 클래스의 연관관계를 나타내는 어노테이션은 무엇인가요? `@_____(mappedBy = "author")`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "OneToMany"}, {"id": "B", "text": "ManyToOne"}, {"id": "C", "text": "ManyToMany"}, {"id": "D", "text": "JoinColumn"}]', 'A', '@OneToMany 어노테이션은 Author 클래스가 여러 Book을 가질 수 있음을 나타냅니다.'),
    (1493, 5, 1, 77, 'Book 클래스에서 Author와의 연관관계를 매핑하는 어노테이션은 무엇인가요? `@_____`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "OneToMany"}, {"id": "B", "text": "ManyToOne"}, {"id": "C", "text": "ManyToMany"}, {"id": "D", "text": "Entity"}]', 'B', '@ManyToOne 어노테이션은 Book 클래스가 하나의 Author에 속함을 나타냅니다.'),
    (1494, 5, 1, 78, '다음 중 Author와 Book 간의 연관관계를 올바르게 설명하는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "한 Author는 여러 Book을 가질 수 있다."}, {"id": "B", "text": "한 Book은 여러 Author에 속할 수 있다."}, {"id": "C", "text": "Author와 Book은 일대다 관계이다."}, {"id": "D", "text": "Book은 반드시 Author를 가져야 한다."}]', '["A", "C", "D"]', 'Author와 Book 간의 관계는 한 Author가 여러 Book을 가질 수 있는 일대다 관계입니다. 또한, 각 Book은 Author를 반드시 가져야 합니다.'),
    (1495, 5, 1, 79, 'JPA에서 연관관계를 매핑하기 위해 사용하는 방법이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "JoinColumn"}, {"id": "B", "text": "Cascade"}, {"id": "C", "text": "MappedBy"}, {"id": "D", "text": "FetchType"}]', 'B', 'Cascade는 연관관계 매핑과 직접적인 관련이 없는 속성으로, 엔티티의 상태 전이를 관리하는 용도로 사용됩니다.'),
    (1496, 5, 1, 80, '다음 중 제네릭을 사용하는 올바른 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "List<String> list = new List<>();"}, {"id": "B", "text": "List<String> list = new ArrayList<>();"}, {"id": "C", "text": "ArrayList<String> list = new List<>();"}, {"id": "D", "text": "List<String> list = new List<String>();"}]', 'B', 'List는 인터페이스이며, ArrayList는 그 구현체입니다. 따라서 List<String> list = new ArrayList<>();가 올바른 문법입니다.'),
    (1497, 5, 1, 81, '다음 코드를 실행했을 때 출력 결과는 무엇인가? 

List<Object> list = new ArrayList<>(); 
list.add("Hello"); 
list.add(10); 
System.out.println(list.get(0));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello"}, {"id": "B", "text": "10"}, {"id": "C", "text": "Error"}, {"id": "D", "text": "null"}]', 'A', 'list.get(0)에서 첫 번째 요소는 ''Hello'' 문자열이므로 출력 결과는 ''Hello''입니다.'),
    (1498, 5, 1, 82, '다음 코드의 빈칸에 알맞은 코드를 채우세요. 

public static <T> void addItem(List<? super T> list, T item) { 
    __________; 
}', 'SHORT_ANSWER', NULL, 'list.add(item)', '제네릭 메소드에서 주어진 리스트에 아이템을 추가하기 위해서는 list.add(item)과 같이 작성해야 합니다.'),
    (1499, 5, 1, 83, '제네릭에서 와일드카드를 사용하는 이유는 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "타입 안정성을 제공하기 위해"}, {"id": "B", "text": "다양한 타입을 수용하기 위해"}, {"id": "C", "text": "메모리 효율성을 높이기 위해"}, {"id": "D", "text": "코드 가독성을 높이기 위해"}]', '["A", "B"]', '와일드카드는 다양한 타입을 수용할 수 있고, 타입 안정성을 제공하기 위해 사용됩니다.'),
    (1500, 5, 1, 84, '제네릭의 기본적인 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '타입 안정성과 코드 재사용성을 증가시키기 위함입니다.', '제네릭은 다양한 데이터 타입을 다루면서도 컴파일 타임에 타입 체크를 가능하게 하기 때문에 타입 안정성과 코드 재사용성을 증가시킵니다.'),
    (1501, 5, 1, 85, 'Spring Security의 인증 및 인가 설정은 주로 어떤 클래스를 상속받아 이루어지는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WebSecurityConfigurerAdapter"}, {"id": "B", "text": "SecurityConfigurerAdapter"}, {"id": "C", "text": "AuthorizationConfigurerAdapter"}, {"id": "D", "text": "HttpSecurity"}]', 'A', 'Spring Security의 인증 및 인가 설정은 주로 WebSecurityConfigurerAdapter 클래스를 상속받아 이루어진다.'),
    (1502, 5, 1, 86, '다음 코드의 빈칸에 들어갈 적절한 메서드는 무엇인가? http.authorizeRequests().____().permitAll()', 'SHORT_ANSWER', NULL, 'antMatchers', '빈칸에 들어갈 메서드는 ''antMatchers''로, 특정 요청에 대한 접근 권한을 설정한다.'),
    (1503, 5, 1, 87, '위 코드에서, 모든 요청에 대해 인증을 요구하는 설정은 어떤 메서드를 통해 이루어지는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "permitAll()"}, {"id": "B", "text": "authenticated()"}, {"id": "C", "text": "permitAuthenticated()"}, {"id": "D", "text": "denyAll()"}]', 'B', '모든 요청에 대해 인증을 요구하는 설정은 ''authenticated()'' 메서드를 통해 이루어진다.'),
    (1504, 5, 1, 88, '다음 중 Spring Security의 보안 기능으로 제공되지 않는 것은 무엇인가? (복수 답변 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "CSRF 보호"}, {"id": "B", "text": "세션 관리"}, {"id": "C", "text": "API 버전 관리"}, {"id": "D", "text": "인증 및 인가"}]', '["C", "D"]', 'API 버전 관리는 Spring Security의 기본 보안 기능이 아니다.'),
    (1505, 5, 1, 89, 'Spring Security에서 사용자 정의 로그인 페이지를 설정하기 위해 사용되는 메서드는 무엇인가?', 'SHORT_ANSWER', NULL, 'loginPage', '사용자 정의 로그인 페이지를 설정하기 위해 ''loginPage'' 메서드를 사용한다.'),
    (1506, 5, 1, 90, '위 코드에서 ''fruits.get(1)''의 출력 결과는 무엇인가요?', 'SHORT_ANSWER', NULL, 'Banana', '''fruits.get(1)''은 두 번째 요소인 ''Banana''를 반환합니다.'),
    (1507, 5, 1, 91, 'Collections 프레임워크에서 중복된 요소를 허용하지 않는 컬렉션은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Set"}, {"id": "B", "text": "List"}, {"id": "C", "text": "Map"}, {"id": "D", "text": "ArrayList"}]', 'A', 'Set 인터페이스는 중복된 요소를 허용하지 않습니다.'),
    (1508, 5, 1, 92, '다음 중 HashMap의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "키-값 쌍으로 저장"}, {"id": "B", "text": "중복 키를 허용"}, {"id": "C", "text": "해시 함수를 사용하여 데이터 접근"}, {"id": "D", "text": "빠른 검색 속도"}]', 'B', 'HashMap은 중복 키를 허용하지 않습니다.'),
    (1509, 5, 1, 93, '다음 중 List 인터페이스의 구현 클래스는 무엇인가요? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ArrayList"}, {"id": "B", "text": "HashSet"}, {"id": "C", "text": "LinkedList"}, {"id": "D", "text": "TreeMap"}]', '["A", "C"]', 'ArrayList와 LinkedList는 List 인터페이스의 구현 클래스입니다.'),
    (1510, 5, 1, 94, '다음 코드에서 ''@NotNull'' 어노테이션의 역할은 무엇인가요? 
public class UserDTO {
    @NotNull
    private String name;
    // getter와 setter
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "name 필드가 null이 아닌지 검사한다."}, {"id": "B", "text": "name 필드를 자동으로 초기화한다."}, {"id": "C", "text": "name 필드의 길이를 검사한다."}, {"id": "D", "text": "name 필드의 형식을 검사한다."}]', 'A', '''@NotNull'' 어노테이션은 해당 필드가 null이 아닌지를 검사하는 역할을 합니다.'),
    (1511, 5, 1, 95, '다음 중 DTO를 사용하는 이유로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "비즈니스 로직을 포함하기 위해"}, {"id": "B", "text": "데이터 전송을 효율적으로 하기 위해"}, {"id": "C", "text": "보안 강화를 위해"}, {"id": "D", "text": "UI 디자인을 쉽게 하기 위해"}]', 'B', 'DTO는 데이터 전송을 효율적으로 하기 위해 사용됩니다.'),
    (1512, 5, 1, 96, '다음 코드에서 @Email 어노테이션의 역할은 무엇인가요?
public class UserDTO {
    @Email
    private String email;
    // getter와 setter
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "email 필드가 null인지 검사한다."}, {"id": "B", "text": "email 필드가 유효한 이메일 형식인지 검사한다."}, {"id": "C", "text": "email 필드의 길이를 검사한다."}, {"id": "D", "text": "email 필드를 자동으로 초기화한다."}]', 'B', '''@Email'' 어노테이션은 해당 필드가 유효한 이메일 형식인지 검사하는 역할을 합니다.'),
    (1513, 5, 1, 97, 'Spring Validation에서 사용되는 어노테이션 중 두 가지를 모두 고르세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@Valid"}, {"id": "B", "text": "@NotBlank"}, {"id": "C", "text": "@Autowired"}, {"id": "D", "text": "@Transactional"}]', '["A", "B"]', 'Spring Validation에서 @Valid와 @NotBlank 어노테이션은 유효성 검증에 사용됩니다.'),
    (1514, 5, 1, 98, 'DTO란 무엇의 약자이며, 주로 어떤 목적으로 사용되나요?', 'SHORT_ANSWER', NULL, 'Data Transfer Object, 데이터 전송을 위한 객체', 'DTO는 Data Transfer Object의 약자로, 주로 데이터 전송을 위한 객체로 사용됩니다.'),
    (1515, 5, 1, 99, '다음 코드를 실행했을 때 출력될 값은 무엇인가요? Box<Integer> box = new Box<>(); box.setItem(10); printBox(box);', 'SHORT_ANSWER', NULL, '10', 'Box<Integer>에 10을 설정하고 printBox를 호출하면 10이 출력됩니다.'),
    (1516, 5, 1, 100, '다음 중 제네릭을 사용하는 이유로 적절하지 않은 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드 재사용성"}, {"id": "B", "text": "타입 안전성"}, {"id": "C", "text": "성능 최적화"}, {"id": "D", "text": "컴파일 타임 오류 방지"}]', 'C', '제네릭은 성능 최적화의 이유로 사용되지 않습니다.'),
    (1517, 5, 1, 101, '와일드카드에서 ''? extends T''는 어떤 의미인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "T 타입의 객체만 허용한다."}, {"id": "B", "text": "T 타입과 T의 서브타입을 허용한다."}, {"id": "C", "text": "T 타입과 T의 슈퍼타입을 허용한다."}, {"id": "D", "text": "모든 타입을 허용한다."}]', 'B', '''? extends T''는 T의 서브타입을 의미합니다.'),
    (1518, 5, 1, 102, '다음 중 제네릭 타입을 정의할 때 사용하는 구문은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "List<T>"}, {"id": "B", "text": "List[]"}, {"id": "C", "text": "List<?> "}, {"id": "D", "text": "List<T extends Number>"}]', '["A", "C", "D"]', 'List<T>, List<?> 및 List<T extends Number>는 모두 유효한 제네릭 타입 정의입니다.'),
    (1519, 5, 1, 103, '다음 코드의 출력 결과는 무엇인가요?

public class Main {
    public static void main(String[] args) {
        List<Integer> numbers = new ArrayList<>();
        numbers.add(1);
        numbers.add(2);
        printList(numbers);
    }

    public static void printList(List<?> list) {
        for (Object obj : list) {
            System.out.println(obj);
        }
    }
}', 'SHORT_ANSWER', NULL, '1
2', 'printList 메서드가 리스트의 모든 요소를 출력하기 때문입니다.'),
    (1520, 5, 1, 104, '다음 코드에서 T의 타입은 무엇인가요?

public static <T> void printArray(T[] array) {
    for (T element : array) {
        System.out.println(element);
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "제네릭 타입"}, {"id": "B", "text": "정수형"}, {"id": "C", "text": "문자열"}, {"id": "D", "text": "리스트"}]', 'A', 'T는 제네릭 타입으로, 메서드 호출 시에 결정됩니다.'),
    (1521, 5, 1, 105, '다음 중 와일드카드를 사용하는 올바른 예는 무엇인가요?

A. List<? extends Number> list;
B. List<Integer> list;
C. List<Object> list;
D. List<?> list;', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "D"}]', '["A", "D"]', 'A와 D는 와일드카드를 사용하는 적절한 예입니다.'),
    (1522, 5, 1, 106, 'List에 대한 제네릭 타입을 정의할 때의 규칙으로 틀린 것은?

A. List<String>은 문자열만 포함하는 리스트
B. List<?>는 모든 타입을 포함할 수 있다.
C. List<Object>는 제네릭 타입으로 사용된다.
D. List<T>는 T의 모든 하위 타입을 포함해야 한다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "보기1"}, {"id": "B", "text": "보기2"}, {"id": "C", "text": "보기3"}, {"id": "D", "text": "보기4"}]', 'C', 'List<Object>는 제네릭 타입으로 사용되지 않고, 모든 객체를 포함할 수 있습니다.'),
    (1523, 5, 1, 107, '다음 중 JUnit5에서 테스트 메소드를 정의하기 위해 사용하는 어노테이션은 무엇인가요? 
 1) @Test 
 2) @Main 
 3) @Execute 
 4) @Function', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@Test"}, {"id": "B", "text": "@Main"}, {"id": "C", "text": "@Execute"}, {"id": "D", "text": "@Function"}]', 'A', '@Test 어노테이션은 JUnit5에서 테스트 메소드를 정의하기 위해 사용됩니다.'),
    (1524, 5, 1, 108, '아래 코드의 빈칸에 들어갈 적절한 내용을 작성하시오: 

@Test 
void subtractTest() { 
    Calculator calculator = new Calculator(); 
    assertEquals(____, calculator.subtract(5, 3)); 
}', 'SHORT_ANSWER', NULL, '2', 'subtract 메소드는 5에서 3을 빼므로 결과는 2입니다.'),
    (1525, 5, 1, 109, '다음 중 JUnit5에서 Assertions 클래스를 통한 검증 메소드가 아닌 것은 무엇인가요? 
 1) assertEquals 
 2) assertTrue 
 3) assertNull 
 4) assertFail', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "assertEquals"}, {"id": "B", "text": "assertTrue"}, {"id": "C", "text": "assertNull"}, {"id": "D", "text": "assertFail"}]', 'D', 'assertFail는 JUnit5의 Assertions 클래스에 존재하지 않는 메소드입니다.'),
    (1526, 5, 1, 110, 'JUnit5의 @BeforeEach와 @AfterEach 어노테이션의 용도는 무엇인가요? (여러 개 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "테스트 메소드 실행 전 초기화 작업"}, {"id": "B", "text": "테스트 메소드 실행 후 정리 작업"}, {"id": "C", "text": "테스트 메소드 실행 중 예외 처리"}, {"id": "D", "text": "테스트 메소드 실행 자체를 방지"}]', '["A", "B"]', '@BeforeEach는 테스트 메소드 실행 전 초기화 작업을 수행하고, @AfterEach는 테스트 메소드 실행 후 정리 작업을 수행합니다.'),
    (1527, 5, 1, 111, 'JUnit5에서 테스트를 실행하기 위한 기본 메소드는 어떤 어노테이션으로 정의하나요?', 'SHORT_ANSWER', NULL, '@Test', '@Test 어노테이션으로 테스트 메소드를 정의합니다.'),
    (1528, 5, 1, 112, '위 코드에서 ''list''에 저장된 요소들은 어떤 타입인가요?', 'SHORT_ANSWER', NULL, 'String', '''list''는 String 타입의 요소를 저장하는 ArrayList입니다.'),
    (1529, 5, 1, 113, '다음 코드의 출력 결과로 올바른 것은? 
List: [Apple, Banana, Orange]
Set: __________
Map: {Apple=5, Banana=6, Orange=6}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "[Apple, Banana, Orange]"}, {"id": "B", "text": "[Apple, Orange, Banana]"}, {"id": "C", "text": "[Banana, Apple, Orange]"}, {"id": "D", "text": "[Apple, Banana, Orange, Orange]"}]', 'A', 'Set은 중복을 허용하지 않지만 삽입 순서는 보장하지 않으므로 출력 순서는 달라질 수 있습니다.'),
    (1530, 5, 1, 114, '다음 중 Set의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "중복된 요소를 허용하지 않는다."}, {"id": "B", "text": "요소의 순서를 보장한다."}, {"id": "C", "text": "고유한 요소로 저장된다."}, {"id": "D", "text": "HashSet으로 구현할 수 있다."}]', 'B', 'Set은 중복된 요소를 허용하지 않으며, 요소의 순서를 보장하지 않습니다.'),
    (1531, 5, 1, 115, '다음 중 List와 Set의 차이로 옳은 것을 모두 고르세요. 
1) List는 중복을 허용한다. 
2) Set은 순서를 보장한다. 
3) List는 인덱스를 사용해 요소에 접근할 수 있다. 
4) Set은 요소의 개수를 제한한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 3"}, {"id": "B", "text": "1, 2"}, {"id": "C", "text": "2, 4"}, {"id": "D", "text": "1, 3, 4"}]', '["A"]', 'List는 중복을 허용하고 인덱스를 사용해 접근 가능하지만, Set은 순서를 보장하지 않으며 개수를 제한하지 않습니다.'),
    (1532, 5, 1, 116, 'Spring MVC Controller에서 요청을 처리하는 메소드는 어떤 어노테이션으로 정의할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@GetMapping"}, {"id": "B", "text": "@PostMapping"}, {"id": "C", "text": "@RequestMapping"}, {"id": "D", "text": "@ResponseBody"}]', 'A', 'GET 요청을 처리하는 메소드는 @GetMapping 어노테이션을 사용하여 정의합니다.'),
    (1533, 5, 1, 117, '다음 코드를 빈칸에 적절히 채우세요: @RequestMapping("/greeting") public class _______ { ... }', 'SHORT_ANSWER', NULL, 'GreetingController', '이 클래스는 GreetingController로 명명되어야 합니다.'),
    (1534, 5, 1, 118, 'Spring MVC에서 Controller가 클라이언트 요청을 받아 적절한 서비스를 호출한 후 어떤 방식으로 결과를 반환하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "string"}, {"id": "B", "text": "뷰 이름"}, {"id": "C", "text": "JSON"}, {"id": "D", "text": "XML"}]', 'C', 'Controller는 주로 JSON 형식으로 응답을 반환하여 클라이언트와 데이터를 주고받습니다.'),
    (1535, 5, 1, 119, 'Controller 클래스의 메소드는 여러 종류의 요청을 처리할 수 있습니다. 이 중 적절한 매핑 방식은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@GetMapping"}, {"id": "B", "text": "@PostMapping"}, {"id": "C", "text": "@PutMapping"}, {"id": "D", "text": "@DeleteMapping"}]', '["A", "B", "C", "D"]', 'Controller 메소드는 GET, POST, PUT, DELETE 요청을 처리하기 위해 다양한 매핑 어노테이션을 사용할 수 있습니다.'),
    (1536, 5, 1, 120, '다음 코드의 출력 결과는 무엇입니까? 
Box<Integer> integerBox = new Box<>();
integerBox.setItem(10);
System.out.println(integerBox.getItem());', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "10"}, {"id": "B", "text": "null"}, {"id": "C", "text": "오류 발생"}, {"id": "D", "text": "기타"}]', 'A', 'Box에 Integer 타입을 설정하고 10을 저장했기 때문에 출력 결과는 10입니다.'),
    (1537, 5, 1, 121, '제네릭 클래스 Box<T>에서 T는 무엇을 의미합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "리턴 타입"}, {"id": "B", "text": "타입 변수"}, {"id": "C", "text": "정수"}, {"id": "D", "text": "상수"}]', 'B', 'T는 타입 변수를 의미하며, Box 클래스가 다양한 타입을 가질 수 있게 해줍니다.'),
    (1538, 5, 1, 122, '다음 코드에서 빈칸에 들어갈 적절한 제네릭 타입은 무엇입니까? 
List<____> numbers = new ArrayList<>();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Integer"}, {"id": "B", "text": "String"}, {"id": "C", "text": "Object"}, {"id": "D", "text": "Double"}]', 'A', 'numbers라는 리스트에 Integer 타입의 값을 저장할 것이므로 빈칸에 들어갈 타입은 Integer입니다.'),
    (1539, 5, 1, 123, '무제한 와일드카드 ''List<?>''의 사용 용도는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 타입의 리스트를 받을 수 있다."}, {"id": "B", "text": "특정 타입으로 제한할 수 있다."}, {"id": "C", "text": "타입 안정성을 보장한다."}, {"id": "D", "text": "입력 값이 null일 수 있다."}]', '["A", "C"]', '무제한 와일드카드를 사용하면 모든 타입의 리스트를 받을 수 있고, 타입 안정성을 보장합니다.'),
    (1540, 5, 1, 124, '제네릭이 제공하는 주요 이점은 무엇인가요?', 'SHORT_ANSWER', NULL, '타입 안전성과 코드 재사용성 증가', '제네릭을 사용하면 컴파일 시간에 타입 검사가 이루어져 타입 안전성이 높아지고, 다양한 타입에 대해 재사용할 수 있는 코드 작성이 가능합니다.'),
    (1541, 5, 1, 125, '다음 코드에서 Enum ''Day''의 값 중 하나를 선택할 때 어떤 값이 올바른가? 

 public enum Day {
    _____
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "MONDAY"}, {"id": "B", "text": "WEEKDAY"}, {"id": "C", "text": "MORNING"}, {"id": "D", "text": "FIRSTDAY"}]', 'A', '''MONDAY''는 정의된 Enum 값 중 하나로, 올바른 선택입니다.'),
    (1542, 5, 1, 126, '다음 코드의 switch 문에서 ''SATURDAY''와 ''SUNDAY''에 해당하는 출력은 무엇인가? 

 switch (day) {
    // ...
    case SATURDAY: case SUNDAY:
        System.out.println("_____.");
        break;
    // ...
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Weekdays are boring."}, {"id": "B", "text": "Weekends are best."}, {"id": "C", "text": "Back to work."}, {"id": "D", "text": "Almost weekend!"}]', 'B', 'SATURDAY와 SUNDAY에 해당하는 출력은 ''Weekends are best.''입니다.'),
    (1543, 5, 1, 127, '다음 코드에서 ''day'' 변수의 값이 ''FRIDAY''일 때 출력되는 메시지는 무엇인가? 

 public void tellItLikeItIs() {
    switch (day) {
        case MONDAY:
            System.out.println("Mondays are bad.");
            break;
        case FRIDAY:
            _____;
            break;
        // ...
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Weekend is coming."}, {"id": "B", "text": "Fridays are better."}, {"id": "C", "text": "Friday is here."}, {"id": "D", "text": "Almost weekend!"}]', 'B', 'FRIDAY일 때 출력되는 메시지는 ''Fridays are better.''입니다.'),
    (1544, 5, 1, 128, 'Enum을 사용하여 요일을 정의하는 코드에서 적절한 Enum 이름은 무엇인가? (예: public enum _____)', 'SHORT_ANSWER', NULL, 'Day', '올바른 Enum 이름은 ''Day''입니다.'),
    (1545, 5, 1, 129, '다음 코드에서 사용할 수 있는 요일 값으로 적절한 것은 무엇인가? 

 public enum Day {
    SUNDAY, MONDAY, TUESDAY, _____, THURSDAY, FRIDAY, SATURDAY
}', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "WEDNESDAY"}, {"id": "B", "text": "FRIDAY"}, {"id": "C", "text": "WEEKDAY"}, {"id": "D", "text": "HOLIDAY"}]', '["A", "B"]', 'WEDNESDAY와 FRIDAY는 Enum으로 정의된 요일 값입니다.'),
    (1546, 5, 1, 130, '다음 코드에서 `equals()` 메소드의 주된 목적은 무엇인가? 
@Override
public boolean equals(Object obj) {
    if (this == obj) return true;
    if (obj == null || getClass() != obj.getClass()) return false;
    MyClass myClass = (MyClass) obj;
    return Objects.equals(field1, myClass.field1) &&
           Objects.equals(field2, myClass.field2);
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 주요 속성을 비교하기 위함"}, {"id": "B", "text": "해시 코드를 생성하기 위함"}, {"id": "C", "text": "객체의 메모리 주소를 비교하기 위함"}, {"id": "D", "text": "객체의 생성자를 호출하기 위함"}]', 'A', 'equals() 메소드는 두 객체의 주요 속성이 같은지를 비교하는 것이 주 목적입니다.'),
    (1547, 5, 1, 131, '다음 코드에서 `hashCode()` 메소드의 반환 값은 무엇으로 결정되는가? 
@Override
public int hashCode() {
    return Objects.hash(field1, field2);
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "field1의 해시 코드"}, {"id": "B", "text": "field2의 해시 코드"}, {"id": "C", "text": "field1과 field2의 조합 해시 코드"}, {"id": "D", "text": "상수 값"}]', 'C', 'hashCode() 메소드는 field1과 field2의 조합 해시 코드를 반환합니다.'),
    (1548, 5, 1, 132, 'equals()와 hashCode()를 오버라이딩할 때의 규칙 중 옳은 것은? 
@Override
public boolean equals(Object obj) {
    // 구현
}

@Override
public int hashCode() {
    // 구현
}', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "equals()는 반드시 hashCode()와 함께 오버라이딩해야 한다."}, {"id": "B", "text": "hashCode()는 equals()와 무관하게 오버라이딩해도 된다."}, {"id": "C", "text": "같은 객체는 항상 같은 해시 코드를 가져야 한다."}, {"id": "D", "text": "equals()는 주소 비교만으로도 충분하다."}]', '["A", "C"]', 'equals()가 오버라이딩되면 hashCode()도 반드시 오버라이딩해야 하며, 같은 객체는 항상 같은 해시 코드를 가져야 합니다.'),
    (1549, 5, 1, 133, 'equals()와 hashCode() 메소드를 오버라이딩할 때 주의해야 할 점은 무엇인가?', 'SHORT_ANSWER', NULL, 'equals()와 hashCode()는 일관되게 구현되어야 한다.', 'equals()와 hashCode()는 서로 일관되게 구현되어야 하며, equals()가 같다고 판단하는 두 객체는 hashCode()에서도 같은 값을 반환해야 합니다.'),
    (1550, 5, 1, 134, '다음 코드에서, `MyClass`의 두 인스턴스가 같으려면 어떤 조건을 만족해야 하는가? 
@Override
public boolean equals(Object obj) {
    if (this == obj) return true;
    if (obj == null || getClass() != obj.getClass()) return false;
    MyClass myClass = (MyClass) obj;
    return Objects.equals(field1, myClass.field1) &&
           Objects.equals(field2, myClass.field2);
}', 'SHORT_ANSWER', NULL, 'field1과 field2의 값이 같아야 한다.', 'MyClass의 두 인스턴스가 같기 위해서는 field1과 field2의 값이 같아야 합니다.'),
    (1551, 5, 1, 135, '다음 코드에서 ''@Email'' 어노테이션이 적용된 필드는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "name"}, {"id": "B", "text": "email"}, {"id": "C", "text": "phone"}, {"id": "D", "text": "address"}]', 'B', '''@Email'' 어노테이션은 email 필드에 적용되어 이메일 형식의 유효성을 검사합니다.'),
    (1552, 5, 1, 136, 'UserDTO 클래스에서 유효성 검사를 위해 사용되는 어노테이션이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@NotNull"}, {"id": "B", "text": "@Size"}, {"id": "C", "text": "@Email"}, {"id": "D", "text": "@Autowired"}]', 'D', '''@Autowired''는 의존성 주입에 사용되는 어노테이션으로, 유효성 검사와는 관련이 없습니다.'),
    (1553, 5, 1, 137, '다음 코드에서 BindingResult의 역할은 무엇인가? (코드: public String register(@Valid @ModelAttribute UserDTO userDTO, BindingResult bindingResult) {...})', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입력 데이터를 저장한다."}, {"id": "B", "text": "유효성 검사 결과를 담는다."}, {"id": "C", "text": "에러 메시지를 보여준다."}, {"id": "D", "text": "데이터베이스에 저장한다."}]', 'B', 'BindingResult는 유효성 검사 결과를 담고, 이를 통해 에러 메시지 등을 처리할 수 있습니다.'),
    (1554, 5, 1, 138, 'DTO에서 유효성 검사를 수행하기 위해 사용해야 하는 어노테이션의 종류를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@NotNull"}, {"id": "B", "text": "@Email"}, {"id": "C", "text": "@Min"}, {"id": "D", "text": "@Autowired"}]', '["A", "B", "C"]', '유효성 검사에 사용되는 어노테이션은 @NotNull, @Email, @Min 등이 있으며, @Autowired는 관련이 없습니다.'),
    (1555, 5, 1, 139, 'Spring Validation을 사용하기 위해 DTO 클래스에 추가해야 하는 어노테이션은 무엇인가?', 'SHORT_ANSWER', NULL, '@Valid', '''@Valid'' 어노테이션을 사용하여 DTO 클래스에서 유효성 검사를 수행할 수 있습니다.'),
    (1556, 5, 1, 140, 'Comparable 인터페이스를 구현하는 메서드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'compareTo', 'Comparable 인터페이스는 compareTo 메서드를 통해 객체 자신을 기준으로 비교합니다.'),
    (1557, 5, 1, 141, '다음 코드에서 compareTo 메서드는 어떤 기준으로 두 객체를 비교하나요? 

class Person implements Comparable<Person> {
    String name;
    int age;

    @Override
    public int compareTo(Person other) {
        return this.age - other.age;
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "나이 기준"}, {"id": "B", "text": "이름 기준"}, {"id": "C", "text": "주소 기준"}, {"id": "D", "text": "키 기준"}]', 'A', 'compareTo 메서드는 this의 age와 other의 age를 비교하므로 나이를 기준으로 정렬됩니다.'),
    (1558, 5, 1, 142, 'Comparator 인터페이스를 사용하여 객체를 정렬할 때 필요한 메서드는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "compare"}, {"id": "B", "text": "compareTo"}, {"id": "C", "text": "equals"}, {"id": "D", "text": "sort"}]', 'A', 'Comparator 인터페이스는 compare 메서드를 통해 두 객체를 비교합니다.'),
    (1559, 5, 1, 143, '다음 중 Comparable과 Comparator의 차이점으로 올바른 것은 무엇인가요? (복수 선택 가능)
1. Comparable은 객체 자신을 기준으로 비교하고, Comparator는 외부 기준으로 비교한다.
2. Comparable은 compareTo 메서드를 사용하며, Comparator는 비교 시 compare 메서드를 사용한다.
3. Comparable은 정렬할 수 없고, Comparator만 정렬할 수 있다.
4. Comparable과 Comparator는 모두 Java의 컬렉션을 정렬하는 데 사용된다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "B", "D"]', '1, 2, 4번이 맞는 설명입니다. Comparable은 객체 자신을 기준으로 비교하고, Comparator는 외부 기준으로 비교합니다.'),
    (1560, 5, 1, 144, '다음 코드에서 PersonComparator 클래스의 compare 메서드는 어떤 기준으로 두 Person 객체를 비교하나요? 

class PersonComparator implements Comparator<Person> {
    @Override
    public int compare(Person p1, Person p2) {
        return p1.name.compareTo(p2.name);
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "나이 기준"}, {"id": "B", "text": "이름 기준"}, {"id": "C", "text": "주소 기준"}, {"id": "D", "text": "키 기준"}]', 'B', 'compare 메서드는 p1과 p2의 name을 비교하므로 이름을 기준으로 정렬합니다.'),
    (1561, 5, 1, 145, '다음 코드의 기능은 무엇인가요? public static <T> void printList(List<T> list) { for (T element : list) { System.out.println(element); } }', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "리스트의 모든 요소를 출력한다."}, {"id": "B", "text": "리스트의 길이를 반환한다."}, {"id": "C", "text": "리스트를 초기화한다."}, {"id": "D", "text": "리스트의 첫 번째 요소를 반환한다."}]', 'A', '이 코드는 제네릭 메서드 printList를 정의하고, 주어진 리스트의 모든 요소를 출력하는 기능을 수행합니다.'),
    (1562, 5, 1, 146, '다음 코드 중 제네릭을 사용할 수 있는 올바른 예시는 무엇인가요? List<T> list = new ArrayList<>();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "List<String> list = new ArrayList<>();"}, {"id": "B", "text": "List<> list = new ArrayList<>();"}, {"id": "C", "text": "List<Object> list = new ArrayList<>();"}, {"id": "D", "text": "List<T> list = new ArrayList<T>();"}]', 'A', '제네릭 타입 T를 사용한 예시는 잘못된 사용을 반영하므로, 올바른 예시는 List<String> list = new ArrayList<>(); 입니다.'),
    (1563, 5, 1, 147, '다음 중 와일드카드의 올바른 사용 예시는 무엇인가요? List<?> list = new ArrayList<>();', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "List<Integer> list = new ArrayList<>();"}, {"id": "B", "text": "List<String> list = new ArrayList<>();"}, {"id": "C", "text": "List<?> list = new ArrayList<>();"}, {"id": "D", "text": "List<Object> list = new ArrayList<>();"}]', '["C"]', 'List<?>는 어떤 타입의 리스트도 받을 수 있어, 올바른 사용 예시입니다.'),
    (1564, 5, 1, 148, '제네릭을 정의하는 키워드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'T', '제네릭을 정의할 때 주로 사용하는 타입 파라미터는 ''T''입니다.'),
    (1565, 5, 1, 149, '이 DTO에서 username 필드에 적용된 검증 어노테이션은 무엇인가?', 'SHORT_ANSWER', NULL, 'NotNull, Size', 'username 필드는 @NotNull과 @Size 어노테이션으로 검증됩니다.'),
    (1566, 5, 1, 150, 'UserDTO 클래스에서 username의 최소 길이는 몇 글자인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "3"}, {"id": "B", "text": "5"}, {"id": "C", "text": "10"}, {"id": "D", "text": "15"}]', 'A', 'username 필드는 @Size 어노테이션에 의해 최소 길이가 3글자로 설정되어 있습니다.'),
    (1567, 5, 1, 151, '다음 중 UserDTO 클래스의 password 필드에 적용되는 검증 어노테이션은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NotNull"}, {"id": "B", "text": "Size"}, {"id": "C", "text": "Email"}, {"id": "D", "text": "Pattern"}]', '["A"]', 'password 필드는 @NotNull 어노테이션만 적용되어 있습니다.'),
    (1568, 5, 1, 152, 'UserDTO의 필드 중 필수 입력 사항인 필드는 몇 개인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "0"}]', 'B', 'username과 password 필드는 모두 필수 입력 사항으로 설정되어 있습니다.'),
    (1569, 5, 1, 153, '위 코드를 사용하면 어떤 경로에 대해 접근이 허용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "/home"}, {"id": "B", "text": "/admin"}, {"id": "C", "text": "/profile"}, {"id": "D", "text": "/settings"}]', 'A', '/home 경로는 permitAll()에 의해 접근이 허용됩니다.'),
    (1570, 5, 1, 154, 'configure 메서드 내에서 사용되는 메서드 체인 중 ''formLogin()''의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "로그인 페이지 설정"}, {"id": "B", "text": "사용자 정보 저장"}, {"id": "C", "text": "로그아웃 설정"}, {"id": "D", "text": "비밀번호 복잡성 요구"}]', 'A', '''formLogin()''은 사용자에게 로그인 페이지를 설정하는 역할을 합니다.'),
    (1571, 5, 1, 155, '다음 코드에서 빈칸에 들어갈 적절한 메서드를 입력하세요: http.authorizeRequests().___().permitAll()', 'SHORT_ANSWER', NULL, 'antMatchers', 'antMatchers 메서드로 특정 경로에 대한 접근 권한을 설정합니다.'),
    (1572, 5, 1, 156, 'Spring Security의 주요 기능 중 어떤 것들이 있나요? (복수정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인증"}, {"id": "B", "text": "로그인 실패 횟수 제한"}, {"id": "C", "text": "세션 관리"}, {"id": "D", "text": "데이터베이스 접근 관리"}]', '["A", "B", "C"]', 'Spring Security의 주요 기능으로 인증, 로그인 실패 횟수 제한, 세션 관리가 포함됩니다.'),
    (1573, 5, 1, 157, 'Optional을 사용하여 null이 아닌 문자열의 길이를 출력하기 위한 코드에서, 아래 코드의 빈칸에 들어갈 적절한 메서드를 선택하세요. 
Optional<String> optionalString = Optional.ofNullable(getString()); 
optionalString.____(s -> System.out.println(s.length()));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ifPresent"}, {"id": "B", "text": "map"}, {"id": "C", "text": "filter"}, {"id": "D", "text": "orElse"}]', 'A', 'ifPresent 메서드는 Optional이 값을 가지고 있을 경우, 주어진 람다 표현식을 실행합니다.'),
    (1574, 5, 1, 158, '아래 코드는 Optional을 사용하여 문자열을 처리하는 코드입니다. getString()이 null을 반환할 때 출력되는 내용은 무엇인가요? 
Optional<String> optionalString = Optional.ofNullable(getString()); 
optionalString.ifPresent(s -> System.out.println(s.length()));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "0"}, {"id": "B", "text": "null"}, {"id": "C", "text": "Length not available"}, {"id": "D", "text": "아무것도 출력되지 않는다"}]', 'D', 'getString()이 null을 반환하면, ifPresent는 실행되지 않으므로 아무것도 출력되지 않습니다.'),
    (1575, 5, 1, 159, 'Optional을 사용할 때, 값이 없을 경우 기본값을 제공하는 메서드는 무엇인가요? 
optionalString.orElse(____);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "\\"기본값\\""}, {"id": "B", "text": "null"}, {"id": "C", "text": "Optional.empty()"}, {"id": "D", "text": "getString()"}]', 'A', 'orElse 메서드는 Optional이 값이 없을 경우 제공할 기본값을 설정합니다.'),
    (1576, 5, 1, 160, 'Optional에서 값을 필터링하기 위해 사용하는 메서드는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "map"}, {"id": "B", "text": "filter"}, {"id": "C", "text": "flatMap"}, {"id": "D", "text": "ifPresent"}]', '["B"]', 'filter 메서드는 Optional의 값이 특정 조건을 만족할 때만 값이 존재하도록 필터링합니다.'),
    (1577, 5, 1, 161, 'Optional 클래스를 사용하여 null을 안전하게 처리하는 주된 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NullPointerException 방지', 'Optional 클래스는 null 대신 사용하여 NullPointerException을 방지하는 것을 목적으로 합니다.'),
    (1578, 5, 1, 162, '위 코드에서 허용된 공개 URL 패턴은 무엇인가요?', 'SHORT_ANSWER', NULL, '/public/**', '코드에서 .antMatchers(''/public/**'').permitAll()을 통해 ''/public/'' 경로에 접근하는 요청은 인증 없이 허용됩니다.'),
    (1579, 5, 1, 163, 'HttpSecurity의 어떤 메서드를 호출하여 인증되지 않은 요청을 제한하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "authorizeRequests()"}, {"id": "B", "text": "permitAll()"}, {"id": "C", "text": "authenticated()"}, {"id": "D", "text": "formLogin()"}]', 'C', 'authenticated() 메서드는 인증된 사용자만 요청을 처리할 수 있도록 제한합니다.'),
    (1580, 5, 1, 164, 'SecurityConfig 클래스는 어떤 클래스를 상속하고 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WebSecurityConfigurerAdapter"}, {"id": "B", "text": "HttpSecurity"}, {"id": "C", "text": "EnableWebSecurity"}, {"id": "D", "text": "SecurityConfigurer"}]', 'A', 'SecurityConfig 클래스는 WebSecurityConfigurerAdapter를 상속받아 Spring Security의 설정을 정의합니다.'),
    (1581, 5, 1, 165, 'Spring Security에서 로그인을 위한 설정 메서드는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "formLogin()"}, {"id": "B", "text": "logout()"}, {"id": "C", "text": "authorizeRequests()"}, {"id": "D", "text": "httpBasic()"}]', '["A", "B"]', 'formLogin() 메서드는 로그인 양식 설정을, logout() 메서드는 로그아웃을 위한 설정을 제공합니다.'),
    (1582, 5, 1, 166, 'Spring Security의 로그인 양식을 허용하는 메서드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'formLogin()', 'formLogin() 메서드를 사용하여 로그인 양식을 설정하고 사용자의 인증을 관리합니다.'),
    (1583, 5, 1, 167, '다음 코드의 역할은 무엇인가요?

@Override
protected void configure(HttpSecurity http) throws Exception {
    http
        .authorizeRequests()
            .antMatchers("/public/**").permitAll()
            .anyRequest().authenticated()
            .and()
        .formLogin()
            .loginPage("/login")
            .permitAll()
            .and()
        .logout()
            .permitAll();
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 URL에 대해 인증을 요구한다."}, {"id": "B", "text": "특정 URL은 누구나 접근 가능하게 한다."}, {"id": "C", "text": "로그인 페이지를 설정한다."}, {"id": "D", "text": "모든 요청을 허용한다."}]', 'B', '이 코드는 ''/public/**''로 시작하는 URL에 대해 인증을 요구하지 않도록 설정하고, 다른 모든 요청은 인증을 요구합니다.'),
    (1584, 5, 1, 168, '다음 빈칸에 들어갈 코드는 무엇인가요? 

@Override
protected void configure(HttpSecurity http) throws Exception {
    http
        .authorizeRequests()
            .antMatchers("/public/**")._____()
            .anyRequest().authenticated();
}', 'SHORT_ANSWER', NULL, 'permitAll', '빈칸에는 ''permitAll''이 들어가야 합니다.'),
    (1585, 5, 1, 169, 'Spring Security에서 로그아웃 설정을 어떻게 하나요?
다음 중 올바른 코드는 무엇인가요?

    .logout()
        ._____();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "permitAll"}, {"id": "B", "text": "authenticated"}, {"id": "C", "text": "denyAll"}, {"id": "D", "text": "authorize"}]', 'A', '로그아웃 설정에서는 ''permitAll''을 사용하여 모든 사용자에게 로그아웃을 허용할 수 있습니다.'),
    (1586, 5, 1, 170, '다음 중 Spring Security 설정에서 인증을 요구하는 설정을 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "anyRequest().authenticated()"}, {"id": "B", "text": "antMatchers(\\"/public/**\\").permitAll()"}, {"id": "C", "text": "formLogin()"}, {"id": "D", "text": "logout()"}]', '["A", "C"]', 'anyRequest().authenticated()는 모든 요청에 대해 인증을 요구하고, formLogin()은 로그인 처리에 관련된 설정이므로 인증을 요구합니다.'),
    (1587, 5, 1, 171, '다음 코드의 출력 결과는 무엇인가? 
Optional<String> optionalString = Optional.ofNullable(getString()); 
optionalString.ifPresent(s -> System.out.println(s.length()));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "문자열 길이 출력"}, {"id": "B", "text": "null 출력"}, {"id": "C", "text": "예외 발생"}, {"id": "D", "text": "아무것도 출력하지 않음"}]', 'A', 'getString()이 null이 아닐 경우 문자열의 길이를 출력합니다.'),
    (1588, 5, 1, 172, 'Optional 객체를 생성하는 방법 중 틀린 것은?
1. Optional.of(value)
2. Optional.ofNullable(value)
3. Optional.create(value)
4. Optional.empty()', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Optional.of(value)"}, {"id": "B", "text": "Optional.ofNullable(value)"}, {"id": "C", "text": "Optional.create(value)"}, {"id": "D", "text": "Optional.empty()"}]', 'C', 'Optional.create()는 존재하지 않는 메서드입니다.'),
    (1589, 5, 1, 173, 'Optional 객체가 값이 존재하는지를 확인하는 메서드는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "isPresent()"}, {"id": "B", "text": "hasValue()"}, {"id": "C", "text": "exists()"}, {"id": "D", "text": "isAvailable()"}]', 'A', 'isPresent() 메서드는 값의 존재 여부를 확인합니다.'),
    (1590, 5, 1, 174, 'Optional을 사용할 때의 장점을 모두 고르시오.
1. null 체크를 수동으로 하지 않아도 된다.
2. 더 많은 메모리를 사용한다.
3. 값이 없을 경우에도 안전하게 처리할 수 있다.
4. 코드를 더 복잡하게 만든다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "C"]', 'Optional을 사용하면 null 체크가 필요 없어지고, 값이 없을 경우도 안전하게 처리할 수 있습니다.'),
    (1591, 5, 1, 175, 'Optional 클래스를 사용하여 빈 Optional 객체를 생성하는 메서드는 무엇인가?', 'SHORT_ANSWER', NULL, 'Optional.empty()', 'Optional.empty() 메서드로 빈 Optional 객체를 생성할 수 있습니다.'),
    (1592, 5, 1, 176, '위의 코드에서 ''sayHello'' 메소드는 어떤 HTTP 요청을 처리하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "GET 요청"}, {"id": "B", "text": "POST 요청"}, {"id": "C", "text": "PUT 요청"}, {"id": "D", "text": "DELETE 요청"}]', 'A', 'sayHello 메소드는 @GetMapping 애너테이션이 붙어 있으므로 GET 요청을 처리합니다.'),
    (1593, 5, 1, 177, 'Controller에서 반환할 뷰 이름은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "helloView"}, {"id": "B", "text": "helloPage"}, {"id": "C", "text": "index"}, {"id": "D", "text": "home"}]', 'A', 'Controller에서 반환된 뷰 이름은 ''helloView''입니다.'),
    (1594, 5, 1, 178, '다음 중 Spring MVC Controller의 주요 역할이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "요청 처리"}, {"id": "B", "text": "모델 업데이트"}, {"id": "C", "text": "뷰 생성"}, {"id": "D", "text": "데이터베이스 연결"}]', 'D', 'Controller의 주요 역할은 요청 처리, 모델 업데이트, 뷰 생성이며, 데이터베이스 연결은 다른 컴포넌트의 역할입니다.'),
    (1595, 5, 1, 179, 'Spring MVC에서 Controller를 정의할 때 사용하는 애너테이션은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@Controller"}, {"id": "B", "text": "@Service"}, {"id": "C", "text": "@RestController"}, {"id": "D", "text": "@Component"}]', '["A", "C"]', 'Spring MVC에서 Controller는 @Controller 또는 @RestController 애너테이션으로 정의할 수 있습니다.'),
    (1596, 5, 1, 180, 'Controller에서 클라이언트에게 보여줄 메시지는 어떤 메소드를 통해 추가되나요?', 'SHORT_ANSWER', NULL, 'addAttribute', 'Controller에서 클라이언트에게 보여줄 메시지는 Model 객체의 addAttribute 메소드를 통해 추가됩니다.'),
    (1597, 5, 1, 181, '다음 코드에서 getMessage() 메소드는 어떤 요일의 메시지를 반환할까요? Day day = Day.WEDNESDAY; String message = day.getMessage();', 'SHORT_ANSWER', NULL, '수요일입니다.', 'getMessage() 메소드는 WEDNESDAY에 대해 ''수요일입니다.''라는 메시지를 반환합니다.'),
    (1598, 5, 1, 182, '다음 코드에서 SUNDAY에 대한 getMessage() 호출의 결과는 무엇인가요? Day day = Day.SUNDAY; String message = day.getMessage();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일요일입니다."}, {"id": "B", "text": "월요일입니다."}, {"id": "C", "text": "화요일입니다."}, {"id": "D", "text": "잘못된 요일입니다."}]', 'A', 'SUNDAY의 getMessage() 메소드는 ''일요일입니다.''를 반환합니다.'),
    (1599, 5, 1, 183, '다음 코드의 빈칸을 채우세요: public enum Day { SUNDAY, MONDAY, ___, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY; }', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "TUESDAY"}, {"id": "B", "text": "SATURDAY"}, {"id": "C", "text": "THURSDAY"}, {"id": "D", "text": "FRIDAY"}]', 'A', '빈칸에 들어갈 정확한 요일은 TUESDAY입니다.'),
    (1600, 5, 1, 184, 'Enum을 활용하여 정의할 수 있는 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "상수 집합"}, {"id": "B", "text": "메소드"}, {"id": "C", "text": "변수"}, {"id": "D", "text": "클래스"}]', '["A", "B"]', 'Enum은 상수 집합과 메소드를 정의할 수 있습니다.'),
    (1601, 5, 1, 185, '다음 코드에서 출력되는 결과는 무엇인가요? 

public enum Day {
    SUNDAY, MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY
}

Day day = Day.FRIDAY;
System.out.println(day);
', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "FRIDAY"}, {"id": "B", "text": "SUNDAY"}, {"id": "C", "text": "SATURDAY"}, {"id": "D", "text": "MONDAY"}]', 'A', 'Enum의 toString 메서드가 호출되어 ''FRIDAY''가 출력됩니다.'),
    (1602, 5, 1, 186, '다음 코드에서 빈칸에 들어갈 올바른 키워드는 무엇인가요? 

public enum Day {
    SUNDAY, MONDAY, TUESDAY, __________
}
', 'SHORT_ANSWER', NULL, 'WEDNESDAY', '요일을 정의하기 위해 WEDNESDAY가 필요합니다.'),
    (1603, 5, 1, 187, 'Enum을 사용할 때 switch 문에서 잘못된 사용 예는 무엇인가요? 

Day day = Day.TUESDAY;
switch (day) {
    case MONDAY:
        System.out.println("It''s Monday!");
        break;
    case ________:
        System.out.println("It''s Tuesday!");
        break;
}
', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "TUESDAY"}, {"id": "B", "text": "WEDNESDAY"}, {"id": "C", "text": "THURSDAY"}, {"id": "D", "text": "FRIDAY"}]', 'B', 'MONDAY와 TUESDAY만 switch 문에 사용되어야 합니다.'),
    (1604, 5, 1, 188, 'Enum을 통해 요일에 해당하는 근무 여부를 정의하고 싶습니다. 아래의 선택지 중 올바른 Enum 정의는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "public enum Day { SUNDAY(true), MONDAY(false); }"}, {"id": "B", "text": "public enum Day { SUNDAY, MONDAY; }"}, {"id": "C", "text": "public enum Day { SUNDAY, MONDAY; private boolean workday; }"}, {"id": "D", "text": "public enum Day { SUNDAY(false), MONDAY(true); }"}]', '["A", "D"]', 'A와 D는 각 요일에 대해 근무 여부를 설정하는 방식이므로 올바른 정의입니다.'),
    (1605, 5, 1, 189, '다음 코드에서 ''MyBean'' 클래스가 singleton 스코프로 생성되도록 설정된 어노테이션은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@Scope(\\"singleton\\")"}, {"id": "B", "text": "@Singleton"}, {"id": "C", "text": "@Bean"}, {"id": "D", "text": "@Component"}]', 'A', '''@Scope("singleton")''은 MyBean이 singleton 스코프로 관리되도록 설정합니다.'),
    (1606, 5, 1, 190, 'Spring Bean의 생명주기에서 Bean이 생성된 후 호출되는 메서드는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "destroy()"}, {"id": "B", "text": "init()"}, {"id": "C", "text": "create()"}, {"id": "D", "text": "start()"}]', 'B', 'Bean이 생성된 후 호출되는 초기화 메서드는 ''init()''입니다.'),
    (1607, 5, 1, 191, '다음 중 Spring의 Bean 스코프에 포함되지 않는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "singleton"}, {"id": "B", "text": "prototype"}, {"id": "C", "text": "group"}, {"id": "D", "text": "session"}]', 'C', '''group''은 Spring의 Bean 스코프에 포함되지 않습니다.'),
    (1608, 5, 1, 192, 'Spring Bean의 생명주기 중 초기화 후 수행되어야 하는 작업을 모두 선택하세요. (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "리소스 할당"}, {"id": "B", "text": "듀티 사이클 관리"}, {"id": "C", "text": "이벤트 리스너 등록"}, {"id": "D", "text": "오류 처리"}]', '["A", "C"]', '초기화 후에는 리소스 할당 및 이벤트 리스너 등록과 같은 작업이 수행될 수 있습니다.'),
    (1609, 5, 1, 193, 'Spring Bean의 기본 스코프는 무엇인가?', 'SHORT_ANSWER', NULL, 'singleton', 'Spring Bean의 기본 스코프는 singleton입니다.'),
    (1610, 5, 1, 194, '다음 중 JPA Repository에서 메서드 이름 규칙을 따르는 쿼리 메서드는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "findByLastName(String lastName)"}, {"id": "B", "text": "getUserByLastName(String lastName)"}, {"id": "C", "text": "selectUserByLastName(String lastName)"}, {"id": "D", "text": "fetchByLastName(String lastName)"}]', 'A', 'JPA Repository는 메서드 이름을 기반으로 쿼리를 생성하는데, ''findBy''로 시작하는 이름이 규칙에 맞습니다.'),
    (1611, 5, 1, 195, '다음 코드에서 빈칸에 들어갈 올바른 메서드 이름은 무엇인가요? `User find___ByEmail(String email);`', 'SHORT_ANSWER', NULL, 'First', 'JPA Repository에서 ''findFirstByEmail'' 메서드는 주어진 이메일을 가진 사용자를 가장 먼저 찾는 메서드입니다.'),
    (1612, 5, 1, 196, '아래 메서드의 반환 타입은 무엇인가요? `List<User> findByAgeGreaterThan(int age);`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "User"}, {"id": "B", "text": "List<User>"}, {"id": "C", "text": "Optional<User>"}, {"id": "D", "text": "int"}]', 'B', '이 메서드는 주어진 나이보다 큰 모든 사용자를 포함한 리스트를 반환합니다.'),
    (1613, 5, 1, 197, '다음 중 JPA 메서드 이름 규칙에 부합하는 메서드를 모두 선택하세요. 
1. findByFirstName(String firstName) 
2. retrieveUserById(Long id) 
3. findByEmail(String email) 
4. getByAgeLessThan(int age)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "C"]', '메서드 이름은 ''findBy''와 같은 패턴을 따라야 하므로, 1번과 3번이 JPA의 규칙에 맞습니다.'),
    (1614, 5, 1, 198, '위의 코드에서 ''filter'' 메서드는 어떤 역할을 합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "짝수만 선택한다."}, {"id": "B", "text": "모든 숫자를 선택한다."}, {"id": "C", "text": "숫자를 정렬한다."}, {"id": "D", "text": "숫자를 제거한다."}]', 'A', '''filter'' 메서드는 주어진 조건에 맞는 요소만을 선택하는 역할을 하므로 짝수만 선택한다.'),
    (1615, 5, 1, 199, '다음 코드에서 빈칸에 들어갈 코드는 무엇입니까?

int sum = numbers.stream()
                 .filter(n -> n % 2 == 0)
                 .______
                 .sum();', 'SHORT_ANSWER', NULL, 'mapToInt(Integer::intValue)', '빈칸에는 ''mapToInt(Integer::intValue)''가 들어가야 한다.'),
    (1616, 5, 1, 200, 'Stream API를 사용하여 컬렉션에서 데이터를 처리할 때 어떤 이점을 누릴 수 있습니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "코드의 가독성이 향상된다."}, {"id": "B", "text": "성능이 항상 향상된다."}, {"id": "C", "text": "병렬 처리 지원이 가능하다."}, {"id": "D", "text": "코드의 길이가 항상 줄어든다."}]', '["A", "C"]', 'Stream API는 코드의 가독성을 향상시키고 병렬 처리를 지원하지만, 성능 향상이 항상 보장되지는 않는다.'),
    (1617, 5, 1, 201, '다음 중 Lambda 표현식의 올바른 예시는 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "(x) -> x * x"}, {"id": "B", "text": "x => x * x"}, {"id": "C", "text": "function(x) { return x * x; }"}, {"id": "D", "text": "lambda x: x * x"}]', 'A', 'Java에서 Lambda 표현식은 ''(x) -> x * x''와 같은 형식을 사용한다.'),
    (1618, 5, 1, 202, 'Java의 Stream API를 사용하여 데이터를 처리하는 방법을 간단히 설명하시오.', 'SHORT_ANSWER', NULL, 'Stream을 생성한 후 다양한 연산(예: filter, map, reduce 등)을 체이닝하여 데이터를 변환하거나 집계한다.', 'Stream을 생성하고 체이닝하여 데이터를 처리하는 방식이 핵심이다.'),
    (1619, 5, 1, 203, '다음 중 `equals()` 메서드의 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 동등성을 비교한다."}, {"id": "B", "text": "객체의 해시 값을 반환한다."}, {"id": "C", "text": "객체를 정렬한다."}, {"id": "D", "text": "객체를 복사한다."}]', 'A', '`equals()` 메서드는 두 객체가 동일한지를 비교하는 데 사용됩니다.'),
    (1620, 5, 1, 204, '다음 코드에서 `hashCode()` 메서드는 무엇을 반환하나요? `return Objects.hash(field);`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 문자열 표현"}, {"id": "B", "text": "객체의 필드 값에 기반한 해시 코드"}, {"id": "C", "text": "객체의 클래스 이름"}, {"id": "D", "text": "0"}]', 'B', '`hashCode()` 메서드는 주어진 필드 값에 기반한 해시 코드를 반환합니다.'),
    (1621, 5, 1, 205, '다음 코드에서 `equals()` 메서드는 어떤 조건을 확인하나요? `if (this == obj) return true;`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "obj가 null인지 확인"}, {"id": "B", "text": "서로 다른 객체인지 확인"}, {"id": "C", "text": "동일한 객체인지 확인"}, {"id": "D", "text": "서로 같은 클래스인지 확인"}]', 'C', '`this == obj` 코드는 두 객체가 동일한 메모리 주소를 가리키는지를 확인합니다.'),
    (1622, 5, 1, 206, '다음 중 `equals()`와 `hashCode()`를 오버라이딩할 때 고려해야 할 점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "`hashCode()`는 같은 객체에 대해 항상 동일해야 한다."}, {"id": "B", "text": "`equals()`는 hashCode와 별개로 동작해야 한다."}, {"id": "C", "text": "`equals()`는 null 체크를 반드시 포함해야 한다."}, {"id": "D", "text": "`equals()`와 `hashCode()`는 서로의 결과에 일관성을 가져야 한다."}]', '["A", "C", "D"]', '`equals()`와 `hashCode()`는 객체의 동등성 및 해시 기반 컬렉션의 올바른 작동을 위해 서로의 결과와 일관성을 유지해야 하며, null 체크도 포함해야 합니다.'),
    (1623, 5, 1, 207, '`MyClass`의 `equals()` 메서드에서 `this`와 `obj`가 같은 객체일 때 어떤 값을 반환하나요?', 'SHORT_ANSWER', NULL, 'true', '`this`와 `obj`가 같은 객체일 경우 `equals()` 메서드는 true를 반환합니다.'),
    (1624, 5, 1, 208, '다음 코드에서 ''optionalValue''의 값이 null인 경우 출력될 내용은 무엇인가요?

Optional<String> optionalValue = Optional.ofNullable(getValue());
optionalValue.ifPresent(value -> System.out.println(value));
optionalValue.orElse("기본값");', 'SHORT_ANSWER', NULL, '기본값', 'optionalValue가 null일 경우 orElse 메소드가 호출되어 기본값인 ''기본값''이 출력됩니다.'),
    (1625, 5, 1, 209, '다음 코드에서 ''getValue()'' 메소드의 반환값이 null이라면 ifPresent가 실행될까요?

Optional<String> optionalValue = Optional.ofNullable(getValue());
optionalValue.ifPresent(value -> System.out.println(value));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "예, 실행된다."}, {"id": "B", "text": "아니오, 실행되지 않는다."}, {"id": "C", "text": "오류가 발생한다."}, {"id": "D", "text": "결과는 알 수 없다."}]', 'B', 'ifPresent는 값이 존재할 때만 실행되므로, getValue()가 null이라면 실행되지 않습니다.'),
    (1626, 5, 1, 210, 'Optional을 사용하여 null 체크를 할 때, 아래 빈칸에 들어갈 올바른 메소드는 무엇인가요?

Optional<String> optionalValue = Optional.ofNullable(getValue());
optionalValue.____(value -> System.out.println(value));', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ifPresent"}, {"id": "B", "text": "orElse"}, {"id": "C", "text": "get"}, {"id": "D", "text": "isPresent"}]', 'A', 'ifPresent 메소드는 Optional에 값이 존재할 경우 주어진 작업을 수행하는 메소드입니다.'),
    (1627, 5, 1, 211, '다음 중 Optional을 사용할 때 맞는 선택지를 모두 고르세요.

1. NullPointerException을 방지할 수 있다.
2. Optional은 항상 값을 가지고 있어야 한다.
3. Optional.empty()로 빈 값을 표현할 수 있다.
4. Optional 객체는 null 값을 가질 수 있다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 2"}, {"id": "B", "text": "1, 3"}, {"id": "C", "text": "2, 4"}, {"id": "D", "text": "3, 4"}]', '["B"]', '1번과 3번이 맞습니다. Optional은 null을 방지하는 데 유용하고, Optional.empty()로 빈 상태를 표현할 수 있습니다.'),
    (1628, 5, 1, 212, 'Optional의 기본 사용법은 어떤 메소드를 사용하여 값을 가져올 수 있는가?

Optional<String> optionalValue = Optional.ofNullable(getValue());
____', 'SHORT_ANSWER', NULL, 'get', 'get 메소드를 사용하여 Optional에 저장된 값을 가져올 수 있습니다. 다만, 값이 없을 경우 NoSuchElementException이 발생할 수 있습니다.'),
    (1629, 5, 1, 213, '위 코드에서 ''/public/**'' 경로는 어떤 접근 권한을 가지고 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모두 접근 가능"}, {"id": "B", "text": "인증된 사용자만 접근 가능"}, {"id": "C", "text": "관리자만 접근 가능"}, {"id": "D", "text": "접근 불가능"}]', 'A', '''/public/**'' 경로는 permitAll() 메서드에 의해 모든 사용자가 접근 가능하게 설정되어 있습니다.'),
    (1630, 5, 1, 214, '다음 중 Spring Security에서 인증되지 않은 사용자가 접근할 수 있는 페이지를 설정하는 메서드는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "permitAll()"}, {"id": "B", "text": "authenticated()"}, {"id": "C", "text": "denyAll()"}, {"id": "D", "text": "access()"}]', 'A', 'permitAll() 메서드는 인증되지 않은 사용자도 접근할 수 있도록 허용합니다.'),
    (1631, 5, 1, 215, '다음 코드의 빈칸을 채우세요: @Override protected void configure(HttpSecurity http) throws Exception { http .authorizeRequests() .antMatchers("/public/**"). ________ .anyRequest().authenticated(); }', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "permitAll()"}, {"id": "B", "text": "authenticated()"}, {"id": "C", "text": "denyAll()"}, {"id": "D", "text": "permitNone()"}]', 'A', '빈칸에는 permitAll()이 들어가야 하며, 해당 경로는 모두 접근할 수 있도록 허용합니다.'),
    (1632, 5, 1, 216, 'Spring Security에서 사용자 정의 로그인 페이지를 설정하는 메서드는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "formLogin()"}, {"id": "B", "text": "loginPage()"}, {"id": "C", "text": "authorizeRequests()"}, {"id": "D", "text": "logout()"}]', '["A", "B"]', '사용자 정의 로그인 페이지는 formLogin() 메서드와 loginPage() 메서드를 통해 설정할 수 있습니다.'),
    (1633, 5, 1, 217, 'Spring Security의 주 기능 중 두 가지를 작성하세요.', 'SHORT_ANSWER', NULL, '인증, 인가', 'Spring Security의 주 기능은 사용자 인증과 접근 권한 인가입니다.'),
    (1634, 5, 1, 218, 'Spring Bean 생명주기에서 초기화 메소드를 지정하기 위한 어노테이션은 무엇인가요?', 'SHORT_ANSWER', NULL, '@PostConstruct', '@PostConstruct 어노테이션은 Bean이 초기화될 때 호출되는 메소드를 정의하는 데 사용됩니다.'),
    (1635, 5, 1, 219, '아래의 코드를 실행했을 때 출력될 내용은 무엇인가요? 

public class MyBean {
    @PostConstruct
    public void init() {
        System.out.println("Bean is initialized");
    }
    
    @PreDestroy
    public void destroy() {
        System.out.println("Bean is destroyed");
    }
}

', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Bean is initialized"}, {"id": "B", "text": "Bean is destroyed"}, {"id": "C", "text": "둘 다 출력된다"}, {"id": "D", "text": "아무것도 출력되지 않는다"}]', 'A', 'init 메소드는 Bean이 생성될 때 호출되어 "Bean is initialized"가 출력됩니다.'),
    (1636, 5, 1, 220, 'Spring Bean의 스코프 중 하나로, 요청할 때마다 새로운 인스턴스를 만드는 스코프는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "singleton"}, {"id": "B", "text": "prototype"}, {"id": "C", "text": "session"}, {"id": "D", "text": "globalSession"}]', 'B', 'prototype 스코프는 요청할 때마다 새로운 Bean 인스턴스를 생성합니다.'),
    (1637, 5, 1, 221, 'Spring Bean의 스코프 중 어떤 것들이 존재하는지 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "singleton"}, {"id": "B", "text": "prototype"}, {"id": "C", "text": "request"}, {"id": "D", "text": "thread"}]', '["A", "B", "C"]', 'singleton, prototype, request 스코프는 Spring에서 제공하는 스코프입니다. thread 스코프는 제공되지 않습니다.'),
    (1638, 5, 1, 222, 'Controller에서 클라이언트의 요청을 처리하기 위해 사용되는 어노테이션은 무엇인가요? 
 A. @Service 
 B. @Repository 
 C. @Controller 
 D. @Component', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@Service"}, {"id": "B", "text": "@Repository"}, {"id": "C", "text": "@Controller"}, {"id": "D", "text": "@Component"}]', 'C', '@Controller 어노테이션은 Spring MVC에서 Controller 클래스를 정의하는 데 사용됩니다.'),
    (1639, 5, 1, 223, '다음 중 @RequestMapping 어노테이션의 역할은 무엇인가요? 
 A. 스프링 빈 등록 
 B. URL 경로와 메소드 매핑 
 C. 데이터베이스 접근 
 D. 뷰 템플릿 처리', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "스프링 빈 등록"}, {"id": "B", "text": "URL 경로와 메소드 매핑"}, {"id": "C", "text": "데이터베이스 접근"}, {"id": "D", "text": "뷰 템플릿 처리"}]', 'B', '@RequestMapping 어노테이션은 HTTP 요청을 특정 메소드에 매핑하는 역할을 합니다.'),
    (1640, 5, 1, 224, '아래 코드를 완성하세요. 
 @Controller
 public class MyController {
 	 @RequestMapping("/greet")
 	 public String greet(Model model) {
 	 	 model.addAttribute("message", "______");
 	 	 return "greeting";
 	 }
 }', 'SHORT_ANSWER', NULL, 'Hello, World!', '빈칸에 들어갈 내용은 반환하려는 메시지로, ''Hello, World!''가 적합합니다.'),
    (1641, 5, 1, 225, '다음 중 Controller에서 사용할 수 있는 HTTP 메소드 유형은 무엇인가요? 
 A. GET 
 B. POST 
 C. PUT 
 D. 모두 해당', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "GET"}, {"id": "B", "text": "POST"}, {"id": "C", "text": "PUT"}, {"id": "D", "text": "모두 해당"}]', '["A", "B", "C", "D"]', 'Controller 메소드는 GET, POST, PUT 등 다양한 HTTP 메소드 유형으로 요청을 처리할 수 있습니다.'),
    (1642, 5, 1, 226, '다음 코드에서 AOP를 사용하여 메소드 실행 전에 로깅을 추가하는 조각(Aspect)을 올바르게 구현한 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@Before(\\"execution(* com.example.service.*.*(..))\\")"}, {"id": "B", "text": "@After(\\"execution(* com.example.controller.*.*(..))\\")"}, {"id": "C", "text": "@Around(\\"execution(* com.example.repository.*.*(..))\\")"}, {"id": "D", "text": "@Pointcut(\\"execution(* com.example.service.*.*(..))\\")"}]', 'A', 'A는 메소드 실행 전에 로깅을 추가하기 위한 어노테이션으로 적절합니다.'),
    (1643, 5, 1, 227, '다음은 AOP에서 사용되는 어노테이션입니다. 이 어노테이션의 역할은 무엇인가요? @Aspect', 'SHORT_ANSWER', NULL, 'Aspect 지정을 통해 AOP 기능을 사용할 수 있게 해준다.', 'AOP의 핵심 구성 요소 중 하나로, 해당 클래스가 Aspect임을 나타냅니다.'),
    (1644, 5, 1, 228, '다음 의 코드를 완성하시오. @Before("execution(* com.example.service.*.*(..))") public void logBefore(JoinPoint joinPoint) { System.out.println("Executing: " + joinPoint.getSignature().getName()); } // 빈칸: _____', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "public void logAfter()"}, {"id": "B", "text": "public void logBefore()"}, {"id": "C", "text": "public void logEnd()"}, {"id": "D", "text": "public void logAround()"}]', 'B', 'logBefore 메소드의 정의가 올바르게 시작하기 위해서는 B의 형태가 필요합니다.'),
    (1645, 5, 1, 229, 'AOP의 여러 공통 관심사를 처리하기 위해 사용할 수 있는 어노테이션들 중 어떤 것들이 있는가? (복수 선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@Before"}, {"id": "B", "text": "@After"}, {"id": "C", "text": "@Around"}, {"id": "D", "text": "@RequestMapping"}]', '["A", "B", "C"]', 'AOP에서 사용되는 어노테이션으로 @Before, @After, @Around이 맞습니다.'),
    (1646, 5, 1, 230, '다음 중 Spring MVC Controller에 대한 설명으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클라이언트 요청을 처리하여 적절한 뷰를 반환한다."}, {"id": "B", "text": "데이터베이스와 직접 상호작용한다."}, {"id": "C", "text": "HTML 파일을 생성하는 역할을 한다."}, {"id": "D", "text": "클라이언트 요청을 로그로 남긴다."}]', 'A', 'Spring MVC Controller는 클라이언트의 요청을 처리하고 적절한 뷰를 반환하는 역할을 한다.'),
    (1647, 5, 1, 231, '다음 코드에서 빈칸에 들어갈 적절한 애너테이션은 무엇인가요? @______', 'SHORT_ANSWER', NULL, 'Controller', '@Controller 애너테이션은 클래스를 Spring MVC Controller로 지정하는 역할을 한다.'),
    (1648, 5, 1, 232, 'Spring MVC에서 @RequestMapping 애너테이션의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "HTTP 요청을 메서드에 매핑하는 것"}, {"id": "B", "text": "데이터베이스 연결 설정"}, {"id": "C", "text": "모델 속성 설정"}, {"id": "D", "text": "뷰의 이름을 설정하는 것"}]', 'A', '@RequestMapping 애너테이션은 특정 URL 요청을 메서드에 매핑하는 역할을 한다.'),
    (1649, 5, 1, 233, '다음 중 Spring MVC Controller에서 사용할 수 있는 요청 방식으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "GET"}, {"id": "B", "text": "POST"}, {"id": "C", "text": "PUT"}, {"id": "D", "text": "DELETE"}]', '["A", "B", "C", "D"]', 'Spring MVC Controller는 GET, POST, PUT, DELETE와 같은 다양한 HTTP 요청 방식을 지원한다.'),
    (1650, 5, 1, 234, '모델에 데이터를 추가하기 위해 사용하는 메서드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'addAttribute', '모델에 데이터를 추가하기 위해 사용되는 메서드는 addAttribute이다.'),
    (1651, 5, 1, 235, '위의 코드에서 Bird 클래스의 메서드는 어떤 유형인가요?', 'SHORT_ANSWER', NULL, '추상 메서드', 'Bird 클래스의 fly() 메서드는 추상 메서드로 정의되어 있습니다.'),
    (1652, 5, 1, 236, 'Sparrow 클래스의 sound() 메서드는 어떤 인터페이스를 구현하고 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Animal"}, {"id": "B", "text": "Bird"}, {"id": "C", "text": "Mammal"}, {"id": "D", "text": "Reptile"}]', 'A', 'Sparrow 클래스는 Animal 인터페이스를 구현하고 있습니다.'),
    (1653, 5, 1, 237, '아래 코드의 출력 결과는 무엇인가요?

Sparrow sparrow = new Sparrow();
sparrow.fly();
sparrow.sound();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Sparrow flies\\nChirp"}, {"id": "B", "text": "Chirp\\nSparrow flies"}, {"id": "C", "text": "Chirp\\nChirp"}, {"id": "D", "text": "Sparrow flies\\nSparrow flies"}]', 'A', 'fly()와 sound() 메서드가 호출되어 ''Sparrow flies''와 ''Chirp''가 출력됩니다.'),
    (1654, 5, 1, 238, 'Animal 인터페이스에서 정의된 메서드는 몇 개 이상 구현할 수 있나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "0"}, {"id": "B", "text": "1"}, {"id": "C", "text": "2"}, {"id": "D", "text": "N개"}]', '["B", "D"]', '인터페이스는 최소 1개 이상의 메서드를 구현해야 하며, 여러 개도 가능합니다.'),
    (1655, 5, 1, 239, '다음 코드의 실행 결과는 무엇인가?
List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
List<Integer> squaresOfEvenNumbers = numbers.stream()
    .filter(n -> n % 2 == 0)
    .map(n -> n * n)
    .collect(Collectors.toList());
System.out.println(squaresOfEvenNumbers);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "[4, 16]"}, {"id": "B", "text": "[2, 4, 6, 8, 10]"}, {"id": "C", "text": "[1, 4, 9, 16, 25]"}, {"id": "D", "text": "[1, 2, 3, 4, 5]"}]', 'A', '이 코드는 짝수인 2와 4를 필터링하여 각각 제곱한 4와 16을 포함하는 리스트를 반환합니다.'),
    (1656, 5, 1, 240, 'Stream API의 filter() 메서드는 어떤 기능을 수행하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "요소를 변환한다."}, {"id": "B", "text": "특정 조건에 맞는 요소를 선택한다."}, {"id": "C", "text": "요소를 정렬한다."}, {"id": "D", "text": "요소를 그룹화한다."}]', 'B', 'filter() 메서드는 스트림의 요소 중 특정 조건을 만족하는 요소만을 선택하는 역할을 합니다.'),
    (1657, 5, 1, 241, '다음 코드에서 빈 칸에 들어갈 올바른 코드는?
List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
List<Integer> result = numbers.stream()
    .map(n -> n * n)
    ._______(Collectors.toList());', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "collect"}, {"id": "B", "text": "filter"}, {"id": "C", "text": "reduce"}, {"id": "D", "text": "forEach"}]', 'A', 'collect() 메서드는 스트림의 결과를 수집하여 리스트와 같은 컬렉션으로 변환하는 데 사용됩니다.'),
    (1658, 5, 1, 242, 'Stream API를 사용할 때, 중간 연산과 최종 연산의 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "중간 연산은 새로운 스트림을 반환하고, 최종 연산은 결과를 반환한다."}, {"id": "B", "text": "중간 연산은 부작용을 가질 수 있고, 최종 연산은 항상 부작용이 없다."}, {"id": "C", "text": "중간 연산은 데이터를 필터링하고, 최종 연산은 데이터를 변환한다."}, {"id": "D", "text": "중간 연산은 스트림을 종료시키고, 최종 연산은 스트림을 계속 유지한다."}]', '["A", "B"]', '중간 연산은 새로운 스트림을 반환하고, 최종 연산은 최종 결과를 반환합니다. 중간 연산은 부작용을 가질 수 있지만, 최종 연산은 일반적으로 부작용이 없습니다.'),
    (1659, 5, 1, 243, 'Java의 Stream API에서 람다 표현식이 무엇인가요?', 'SHORT_ANSWER', NULL, '람다 표현식은 함수를 간결하게 정의하는 문법으로, 익명 함수를 표현할 때 사용된다.', '람다 표현식은 주로 함수형 인터페이스의 인스턴스를 간단하게 생성하기 위해 쓰이며, Stream API와 함께 효과적으로 데이터 처리를 수행하는 데 사용됩니다.'),
    (1660, 5, 1, 244, 'JUnit5에서 테스트 메소드를 정의할 때 사용하는 애너테이션은 무엇인가요? 
 1) @BeforeAll 
 2) @Test 
 3) @AfterEach 
 4) @DisplayName', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@BeforeAll"}, {"id": "B", "text": "@Test"}, {"id": "C", "text": "@AfterEach"}, {"id": "D", "text": "@DisplayName"}]', 'B', 'JUnit5에서는 ''@Test'' 애너테이션을 사용하여 테스트 메소드를 정의합니다.'),
    (1661, 5, 1, 245, '다음 코드의 실행 결과는 무엇인가요? 

 Assertions.assertEquals(5, calculator.add(2, 3)); 

 1) 2 
 2) 3 
 3) 5 
 4) AssertionError', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "2"}, {"id": "B", "text": "3"}, {"id": "C", "text": "5"}, {"id": "D", "text": "AssertionError"}]', 'C', '이 코드는 두 숫자를 더한 결과가 예상값과 일치하는지 검증하므로, 결과는 5입니다.'),
    (1662, 5, 1, 246, '빈 칸에 들어갈 적절한 애너테이션을 채우세요. 

 @____ 
 void tearDown() { 
     calculator = null; 
 } 

 1) BeforeEach 
 2) AfterEach 
 3) Test 
 4) BeforeAll', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "BeforeEach"}, {"id": "B", "text": "AfterEach"}, {"id": "C", "text": "Test"}, {"id": "D", "text": "BeforeAll"}]', 'B', '여기서는 테스트 메소드가 끝난 후에 실행되는 코드이므로 ''@AfterEach'' 애너테이션을 사용합니다.'),
    (1663, 5, 1, 247, 'JUnit5에서 테스트 클래스의 메소드 전후에 실행할 코드를 정의하기 위한 애너테이션은 무엇인가요? 

 (여러 개 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@BeforeEach"}, {"id": "B", "text": "@AfterEach"}, {"id": "C", "text": "@Test"}, {"id": "D", "text": "@BeforeAll"}]', '["A", "B"]', '테스트 메소드 전후에 실행할 코드는 ''@BeforeEach''와 ''@AfterEach'' 애너테이션을 사용하여 정의합니다.'),
    (1664, 5, 1, 248, 'JUnit5에서 Assertions를 사용하여 두 값을 비교하는 메소드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'assertEquals', 'Assertions 클래스의 assertEquals 메소드를 사용하여 두 값을 비교합니다.'),
    (1665, 5, 1, 249, '다음 코드에서 increment 메소드는 어떤 키워드를 사용하고 있나요? 
 public synchronized void increment() {
 count++;
 }', 'SHORT_ANSWER', NULL, 'synchronized', 'increment 메소드는 synchronized 키워드를 사용하여 스레드 간의 접근을 제어합니다.'),
    (1666, 5, 1, 250, 'volatile 키워드가 사용된 변수를 올바르게 이해하기 위한 다음 설명 중 틀린 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "volatile 변수는 항상 메인 메모리에서 읽는다."}, {"id": "B", "text": "volatile 변수는 스레드 간의 캐시 일관성을 보장한다."}, {"id": "C", "text": "volatile 변수는 동기화되지 않는다."}, {"id": "D", "text": "volatile 변수는 반드시 synchronized 키워드와 함께 사용해야 한다."}]', 'D', 'volatile 변수는 반드시 synchronized와 함께 사용해야 하는 것은 아닙니다.'),
    (1667, 5, 1, 251, '다음의 코드 조각에서, 어떤 키워드가 빈칸을 채워야 할까요? 
 private ____ boolean isActive = true;', 'SHORT_ANSWER', NULL, 'volatile', '여기서는 isActive 변수를 volatile로 선언해 여러 스레드에서 일관되게 접근하게 할 수 있습니다.'),
    (1668, 5, 1, 252, '아래 코드 조각에서 어떤 키워드가 빠져있나요? 
 public ____ void display() {
 System.out.println("Hello, World!");
 }', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "synchronized"}, {"id": "B", "text": "volatile"}, {"id": "C", "text": "static"}, {"id": "D", "text": "final"}]', 'A', 'display 메소드가 동기화를 필요로 할 경우 synchronized 키워드가 필요합니다.'),
    (1669, 5, 1, 253, '멀티스레드 환경에서 shared 자원의 일관성을 보장하기 위해 사용되는 기법은 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "synchronized"}, {"id": "B", "text": "volatile"}, {"id": "C", "text": "static"}, {"id": "D", "text": "final"}]', '["A", "B"]', 'synchronized와 volatile 키워드는 모두 멀티스레드 환경에서 shared 자원의 일관성을 보장하기 위해 사용됩니다.'),
    (1670, 5, 1, 254, '다음 코드에서 ''Box'' 클래스의 제네릭 타입 T는 무엇을 의미하나요?

public class Box<T> {
    private T item;

    public void setItem(T item) {
        this.item = item;
    }

    public T getItem() {
        return item;
    }
}', 'SHORT_ANSWER', NULL, '임의의 데이터 타입', '''T''는 클래스가 인스턴스화될 때 지정될 임의의 데이터 타입을 의미합니다.'),
    (1671, 5, 1, 255, '아래 코드에서 ''?''의 역할은 무엇인가요?

public void printBoxItems(List<? extends Number> box) {
    for (Number number : box) {
        System.out.println(number);
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정확한 데이터 타입을 지정하기 위해 사용된다."}, {"id": "B", "text": "어떤 타입의 리스트도 처리할 수 있도록 유연성을 제공한다."}, {"id": "C", "text": "리스트의 크기를 제한하기 위해 사용된다."}, {"id": "D", "text": "메소드의 반환 타입을 지정하기 위해 사용된다."}]', 'B', '''?''는 제네릭 타입에 유연성을 제공하여 Number를 상속하는 모든 타입을 처리할 수 있게 해줍니다.'),
    (1672, 5, 1, 256, '다음 코드에서 ''setItem'' 메소드의 파라미터 타입을 수정하려고 합니다. ''T'' 대신 어떤 타입을 사용할 수 있나요?

public void setItem(T item) {
    this.item = item;
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Number"}, {"id": "B", "text": "Object"}, {"id": "C", "text": "String"}, {"id": "D", "text": "모든 타입"}]', 'B', '제네릭을 사용하지 않는다면 Object 타입으로 모든 객체를 받을 수 있습니다.'),
    (1673, 5, 1, 257, '제네릭을 사용할 수 있는 이유는 무엇인가요? 다음 중 올바른 설명을 모두 선택하세요.

1. 타입 안전성을 제공한다.
2. 코드의 가독성을 높인다.
3. 성능을 향상시킨다.
4. 객체 지향 프로그래밍을 지원한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 2"}, {"id": "B", "text": "1, 3"}, {"id": "C", "text": "2, 4"}, {"id": "D", "text": "1, 2, 4"}]', '["A", "D"]', '제네릭을 사용하면 타입 안전성을 제공하고 코드의 가독성을 높이며 객체 지향 프로그래밍을 지원합니다.'),
    (1674, 5, 1, 258, '위의 코드에서 equals() 메서드는 무엇을 비교하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이름과 나이"}, {"id": "B", "text": "이름만"}, {"id": "C", "text": "나이만"}, {"id": "D", "text": "객체의 주소"}]', 'A', 'equals() 메서드는 이름과 나이를 기준으로 두 Person 객체의 동등성을 비교합니다.'),
    (1675, 5, 1, 259, 'hashCode() 메서드는 어떤 값을 반환하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체의 주소값"}, {"id": "B", "text": "해시 코드"}, {"id": "C", "text": "객체의 내용을 문자열로 변환한 값"}, {"id": "D", "text": "정수 타입의 무작위 숫자"}]', 'B', 'hashCode() 메서드는 객체의 해시 코드를 반환합니다.'),
    (1676, 5, 1, 260, '다음 중 equals()와 hashCode()를 함께 오버라이드해야 하는 이유로 알맞은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성능 향상"}, {"id": "B", "text": "동등성 보장"}, {"id": "C", "text": "객체를 복사하기 위해"}, {"id": "D", "text": "상속을 위해"}]', 'B', 'equals()와 hashCode()를 함께 오버라이드하여 객체의 동등성을 보장해야 합니다.'),
    (1677, 5, 1, 261, '다음 코드에서 어떤 메서드가 불려질 때 Person 객체의 비교가 일어날까요? `person1.equals(person2)`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "equals()"}, {"id": "B", "text": "hashCode()"}, {"id": "C", "text": "toString()"}, {"id": "D", "text": "compareTo()"}]', '["A"]', 'equals() 메서드가 호출되어 person1과 person2의 비교가 일어납니다.'),
    (1678, 5, 1, 262, 'equals() 메서드를 오버라이드할 때 어떤 조건을 명시해야 하나요?', 'SHORT_ANSWER', NULL, '동일한 객체는 true를 반환하고, null이나 다른 클래스의 객체와 비교시 false를 반환해야 한다.', ''),
    (1679, 5, 1, 263, '위의 Person 클래스에서 equals() 메서드는 어떤 조건을 기준으로 두 객체를 동등하다고 판단하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이름과 나이가 같을 때"}, {"id": "B", "text": "이름이 같을 때"}, {"id": "C", "text": "나이가 같을 때"}, {"id": "D", "text": "이름과 나이가 다를 때"}]', 'A', 'equals() 메서드는 두 객체의 이름과 나이가 모두 같을 때 true를 반환합니다.'),
    (1680, 5, 1, 264, 'hashCode() 메서드에서 ''31 * result''는 무엇을 의미하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "해시 충돌을 줄이기 위한 계산"}, {"id": "B", "text": "객체의 메모리 주소를 반환하기 위한 계산"}, {"id": "C", "text": "객체의 크기를 계산하기 위한 방법"}, {"id": "D", "text": "equals() 메서드를 오버라이드하기 위한 조건"}]', 'A', '31을 사용하여 해시 값을 계산함으로써 해시 충돌을 줄이는 효과를 얻습니다.'),
    (1681, 5, 1, 265, '다음 중 equals() 메서드를 오버라이딩할 때 고려해야 할 중요한 점은 무엇인가요?

public boolean equals(Object obj) {
    // 여기에 올바른 코드를 작성하세요.
}', 'SHORT_ANSWER', NULL, 'this == obj를 먼저 체크해야 한다.', 'equals() 메서드를 오버라이드할 때는 먼저 객체의 참조가 동일한지를 확인해야 합니다.'),
    (1682, 5, 1, 266, '다음 두 객체가 equals() 메서드를 사용하여 비교할 때 결과는 true입니까? Person p1 = new Person("John", 30);
Person p2 = new Person("John", 30);', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "true"}, {"id": "B", "text": "false"}]', '["A"]', 'p1과 p2는 이름과 나이가 동일하므로 equals() 메서드는 true를 반환합니다.'),
    (1683, 5, 1, 267, '다음 코드의 출력 결과는 무엇인가요?

List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
List<Integer> evenNumbers = numbers.stream().filter(n -> n % 2 == 0).collect(Collectors.toList());
System.out.println(evenNumbers);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "[2, 4]"}, {"id": "B", "text": "[1, 3, 5]"}, {"id": "C", "text": "[1, 2, 3]"}, {"id": "D", "text": "[1, 2, 3, 4, 5]"}]', 'A', 'filter를 사용하여 짝수만 남기므로 결과는 [2, 4]입니다.'),
    (1684, 5, 1, 268, '다음 빈칸에 들어갈 코드는 무엇인가요?

List<String> names = Arrays.asList("Alice", "Bob", "Charlie");

names.stream().map(name -> _______).forEach(System.out::println);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "name.toUpperCase()"}, {"id": "B", "text": "name.toLowerCase()"}, {"id": "C", "text": "name.length()"}, {"id": "D", "text": "name"}]', 'A', 'toUpperCase()를 사용하면 이름을 대문자로 변환합니다.'),
    (1685, 5, 1, 269, '다음 중 Stream API의 특징이 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "지연적 처리"}, {"id": "B", "text": "상태를 유지한다"}, {"id": "C", "text": "병렬 처리 가능"}, {"id": "D", "text": "함수형 프로그래밍 지원"}]', 'B', 'Stream은 상태를 유지하지 않고, 지연적 처리와 병렬 처리가 가능합니다.'),
    (1686, 5, 1, 270, '다음 중 Stream API를 사용하여 짝수의 합을 구하는 올바른 방법은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "numbers.stream().filter(n -> n % 2 == 0).reduce(0, Integer::sum);"}, {"id": "B", "text": "numbers.stream().map(n -> n * 2).sum();"}, {"id": "C", "text": "numbers.stream().filter(n -> n % 2 != 0).reduce(0, Integer::sum);"}, {"id": "D", "text": "numbers.stream().collect(Collectors.summingInt(n -> n));"}]', '["A", "D"]', 'A는 짝수를 필터링하고 합산하며, D는 모든 숫자의 합을 구합니다.'),
    (1687, 5, 1, 271, 'Stream API와 Lambda의 주요 목적은 무엇인가요?', 'SHORT_ANSWER', NULL, '코드의 가독성과 효율성을 높이기 위해서입니다.', 'Stream API와 Lambda 표현식을 사용하여 데이터 처리 방식이 간결하고 효율적으로 개선됩니다.'),
    (1688, 5, 1, 272, '다음 코드의 출력 결과는 무엇인가? 

public static void main(String[] args) {
    Integer[] intArray = {1, 2, 3};
    printArray(intArray);
}

public static <T> void printArray(T[] array) {
    for (T element : array) {
        System.out.println(element);
    }
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1\\n2\\n3"}, {"id": "B", "text": "1\\n2"}, {"id": "C", "text": "3\\n2\\n1"}, {"id": "D", "text": "에러 발생"}]', 'A', 'printArray 메서드는 주어진 배열을 순회하며 각 요소를 출력하므로 1, 2, 3이 차례로 출력됩니다.'),
    (1689, 5, 1, 273, '다음 코드를 완성하시오: 

public static void printList(List<? ____ Number> list) {
    for (Number number : list) {
        System.out.println(number);
    }
}', 'SHORT_ANSWER', NULL, 'extends', '와일드카드에서 ?는 상한 경계를 설정하기 위해 ''extends'' 키워드를 사용해야 합니다.'),
    (1690, 5, 1, 274, '제네릭의 장점으로 올바르지 않은 것은 무엇인가? 

1. 코드의 재사용성 증가 
2. 런타임 타입 검사 강화 
3. 타입 안전성 제공 
4. 컴파일 타임에 타입 오류 발견', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', 'B', '제네릭은 컴파일 타임에 타입을 검증하기 때문에 런타임 타입 검사는 강화하지 않습니다.'),
    (1691, 5, 1, 275, '다음 중 와일드카드를 사용한 제네릭 메서드에 대한 설명으로 올바른 것을 고르시오: 

1. List<?>는 어떤 타입의 리스트를 의미한다. 
2. List<? super Number>는 Number의 하위 타입을 포함할 수 있다. 
3. List<? extends String>는 String의 모든 하위 타입을 포함할 수 있다. 
4. List<? super Object>는 Object의 모든 상위 타입을 포함할 수 있다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "B", "C"]', '1, 2, 3은 모두 올바른 설명입니다. 그러나 4는 잘못된 설명으로, Object의 모든 상위 타입은 존재하지 않습니다.'),
    (1692, 5, 1, 276, '제네릭을 사용하는 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '타입 안전성과 코드 재사용성을 높이기 위해', '제네릭은 코드의 타입 안전성을 보장하고, 중복된 코드를 줄여 재사용성을 높이는 데 목적이 있습니다.'),
    (1693, 5, 1, 277, '다음 코드에서, /home URL에 대한 접근 권한은 어떻게 설정되어 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 사용자에게 허용된다."}, {"id": "B", "text": "인증된 사용자만 허용된다."}, {"id": "C", "text": "관리자만 허용된다."}, {"id": "D", "text": "허용되지 않는다."}]', 'A', '/home URL은 permitAll() 메서드에 의해 모든 사용자에게 허용됩니다.'),
    (1694, 5, 1, 278, '다음 코드의 빈칸에 들어갈 알맞은 메서드는 무엇인가요? http.authorizeRequests().___().anyRequest().authenticated();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "antMatchers(\\"/\\", \\"/home\\").permitAll()"}, {"id": "B", "text": "denyAll()"}, {"id": "C", "text": "authenticated()"}, {"id": "D", "text": "permitAll()"}]', 'A', 'antMatchers() 메서드는 특정 URL에 대한 권한을 설정하는 데 사용됩니다.'),
    (1695, 5, 1, 279, '다음 중 Spring Security에서 인증을 위한 로그인 페이지를 설정하는 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "loginPage(\\"/login\\").permitAll()"}, {"id": "B", "text": "permitAll().loginPage(\\"/login\\")"}, {"id": "C", "text": "security.loginPage(\\"/login\\")"}, {"id": "D", "text": "setLoginPage(\\"/login\\")"}]', 'A', 'loginPage() 메서드는 커스텀 로그인 페이지를 설정하는 데 사용됩니다.'),
    (1696, 5, 1, 280, 'Spring Security에서 기본 사용자 저장소를 메모리로 설정할 때 사용하는 메서드는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "inMemoryAuthentication()"}, {"id": "B", "text": "jdbcAuthentication()"}, {"id": "C", "text": "customUserDetailsService()"}, {"id": "D", "text": "userDetailsService()"}]', '["A"]', 'inMemoryAuthentication() 메서드는 메모리 기반 사용자 저장소를 설정하는 데 사용됩니다.'),
    (1697, 5, 1, 281, 'Spring Security의 인증 방식 중 하나인 Form Login에 대한 설정을 설명하시오.', 'SHORT_ANSWER', NULL, 'Form Login은 사용자에게 로그인 페이지를 제공하고, 사용자 인증 정보를 받아와서 인증을 처리하는 방식입니다.', 'Form Login은 사용자가 입력한 로그인 정보를 통해 인증을 수행하는 방식입니다.'),
    (1698, 5, 1, 282, 'Spring Bean의 기본 스코프 중 하나로, 애플리케이션 전체에서 단 하나의 인스턴스만 존재하는 스코프는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Singleton"}, {"id": "B", "text": "Prototype"}, {"id": "C", "text": "Request"}, {"id": "D", "text": "Session"}]', 'A', 'Singleton 스코프는 애플리케이션 내에서 단 하나의 Bean 인스턴스를 생성하여 사용합니다.'),
    (1699, 5, 1, 283, '다음 코드에서 MyBean 클래스의 초기화 메서드로 올바른 애노테이션은 무엇인가? 

 @____
 public void init() {
     System.out.println("MyBean is initialized");
 }', 'SHORT_ANSWER', NULL, '@PostConstruct', '@PostConstruct 애노테이션은 Bean 초기화 메서드를 정의하는 데 사용됩니다.'),
    (1700, 5, 1, 284, 'Prototype 스코프의 Bean은 어떤 특성을 가지고 있나요? 다음 중 맞는 것을 모두 고르세요. 
1. 매 요청 시 새로운 인스턴스가 생성된다. 
2. 애플리케이션 전체에서 공유된다. 
3. 요청이 끝나면 메모리에서 소멸된다. 
4. 단일 인스턴스가 여러 곳에서 재사용된다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "C"]', 'Prototype 스코프는 매 요청 시 새로운 인스턴스를 생성하며, 요청이 끝나면 메모리에서 소멸됩니다.'),
    (1701, 5, 1, 285, 'Bean의 소멸 시 호출되는 메서드에 사용하는 애노테이션은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "@PreDestroy"}, {"id": "B", "text": "@PostConstruct"}, {"id": "C", "text": "@Bean"}, {"id": "D", "text": "@Component"}]', 'A', '@PreDestroy 애노테이션은 Bean 소멸 시 호출되는 메서드를 정의하는 데 사용됩니다.'),
    (1702, 5, 1, 286, 'Spring에서 Bean의 생명주기를 관리하는 방법 중 하나로, ''초기화''와 ''소멸'' 시 특정 메서드를 호출하는 기능을 제공하는 애노테이션은 무엇인가?', 'SHORT_ANSWER', NULL, '@PostConstruct 및 @PreDestroy', '@PostConstruct와 @PreDestroy 애노테이션은 각각 초기화 및 소멸 시 호출되는 메서드를 정의하는 데 사용됩니다.'),
    (1703, 5, 1, 287, '다음 코드의 출력 결과는 무엇인가? 

String name = null;
Optional<String> optionalName = Optional.ofNullable(name);
optionalName.ifPresent(n -> System.out.println("Name: " + n));
String result = optionalName.orElse("Default Name");
System.out.println(result);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Name: null\\nDefault Name"}, {"id": "B", "text": "Name: \\nDefault Name"}, {"id": "C", "text": "Name: null\\nName: Default Name"}, {"id": "D", "text": "Default Name"}]', 'D', 'optionalName에 값이 없으므로, ifPresent()는 실행되지 않고, orElse()가 호출되어 "Default Name"이 출력됩니다.'),
    (1704, 5, 1, 288, 'Optional<String> optionalName = Optional.ofNullable(name);에서 name이 null일 경우, optionalName은 어떤 상태인가?', 'SHORT_ANSWER', NULL, '빈 Optional 객체가 된다.', ''),
    (1705, 5, 1, 289, 'Optional 사용 시, 값이 존재할 경우의 처리를 무엇이라고 할 수 있는가? 

optionalName.ifPresent(n -> ...);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "값이 존재할 때 처리"}, {"id": "B", "text": "값이 없을 때 처리"}, {"id": "C", "text": "값을 변형하는 처리"}, {"id": "D", "text": "값을 삭제하는 처리"}]', 'A', 'ifPresent()는 값이 존재할 때 그 값을 처리하는 메서드입니다.'),
    (1706, 5, 1, 290, 'orElse() 메서드는 어떤 역할을 수행하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "Optional이 비어있을 때 대체 값을 리턴"}, {"id": "B", "text": "Optional이 비어있을 때 예외를 발생"}, {"id": "C", "text": "Optional이 값이 있을 때 그 값을 리턴"}, {"id": "D", "text": "Optional의 모든 값을 삭제"}]', '["A", "C"]', 'orElse()는 Optional이 비어있을 때 대체 값을 리턴하고, 값이 있을 경우 그 값을 리턴합니다.'),
    (1707, 5, 1, 291, '다음 코드의 빈칸을 채우시오: 

Optional<String> optionalName = Optional.ofNullable(name);
optionalName.ifPresent(n -> System.out.println("Name: " + n));
String result = optionalName.orElse("___");
System.out.println(result);', 'SHORT_ANSWER', NULL, 'Default Name', ''),
    (1708, 5, 1, 292, '다음 중 Animal 클래스의 sound() 메서드를 구현한 클래스는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Dog"}, {"id": "B", "text": "Cat"}, {"id": "C", "text": "Pet"}, {"id": "D", "text": "Animal"}]', 'A', 'Dog 클래스가 Animal 클래스의 sound() 메서드를 구현했습니다.'),
    (1709, 5, 1, 293, '다음 코드의 출력 결과는 무엇인가요?

Dog dog = new Dog();
dog.sound();', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Woof"}, {"id": "B", "text": "Meow"}, {"id": "C", "text": "Bark"}, {"id": "D", "text": "Animal Sound"}]', 'A', 'Dog 클래스의 sound() 메서드가 호출되어 ''Woof''가 출력됩니다.'),
    (1710, 5, 1, 294, '다음 코드에서 빈칸에 들어갈 올바른 키워드는 무엇인가요?

