        System.out.println("Executing: " + joinPoint.getSignature().getName());
    }
}', 'SHORT_ANSWER', NULL, '@Aspect', '@Aspect 어노테이션으로 이 클래스가 Aspect임을 정의합니다.'),
    (1715, 5, 1, 299, '다음 중 @Before 어노테이션이 하는 일은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메서드 실행 전 코드 실행"}, {"id": "B", "text": "메서드 실행 후 코드 실행"}, {"id": "C", "text": "메서드를 스킵"}, {"id": "D", "text": "메서드의 반환 값을 변경"}]', 'A', '@Before 어노테이션은 지정된 메서드가 실행되기 전에 특정 코드를 실행하는 데 사용됩니다.'),
    (1716, 5, 1, 300, 'Spring AOP에서 공통 관심사를 설정할 때 사용할 수 있는 어노테이션을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "@Before"}, {"id": "B", "text": "@Around"}, {"id": "C", "text": "@Transactional"}, {"id": "D", "text": "@After"}]', '["A", "B", "D"]', '공통 관심사를 설정할 때 @Before, @Around, @After 어노테이션을 사용할 수 있습니다.'),
    (1717, 5, 1, 301, 'Spring AOP를 사용하면 어떤 이점을 얻을 수 있나요?', 'SHORT_ANSWER', NULL, '비즈니스 로직과 공통 관심사를 분리하여 유지보수성을 높이고 코드 중복을 줄인다.', 'AOP를 통해 코드의 중복을 줄이고, 관심사 분리를 통해 유지보수성을 개선할 수 있습니다.'),
    (1718, 5, 1, 302, '다음 코드에서 ''/admin/**'' 경로에 대한 접근 권한은 어떻게 설정되어 있습니까? 

@Override
protected void configure(HttpSecurity http) throws Exception {
    http
        .authorizeRequests()
            .antMatchers("/admin/**").authenticated()
            .antMatchers("/public/**").permitAll()
            .anyRequest().denyAll()
            .and()
        .formLogin();
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인증된 사용자만 접근 가능"}, {"id": "B", "text": "모든 사용자 접근 가능"}, {"id": "C", "text": "관리자만 접근 가능"}, {"id": "D", "text": "접근 거부"}]', 'A', '''/admin/**'' 경로는 authenticated() 메서드에 의해 인증된 사용자만 접근 가능하도록 설정되어 있습니다.'),
    (1719, 5, 1, 303, '다음 코드에서 ''/public/**'' 경로에 대한 접근 권한은 어떻게 설정되어 있습니까? 

@Override
protected void configure(HttpSecurity http) throws Exception {
    http
        .authorizeRequests()
            .antMatchers("/admin/**").authenticated()
            .antMatchers("/public/**").permitAll()
            .anyRequest().denyAll()
            .and()
        .formLogin();
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인증된 사용자만 접근 가능"}, {"id": "B", "text": "모든 사용자 접근 가능"}, {"id": "C", "text": "관리자만 접근 가능"}, {"id": "D", "text": "접근 거부"}]', 'B', '''/public/**'' 경로는 permitAll() 메서드에 의해 모든 사용자가 접근 가능하도록 설정되어 있습니다.'),
    (1720, 5, 1, 304, '다음 중 Spring Security에서 URL 패턴에 대한 접근 제어를 설정하는 메서드는 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "configure(HttpSecurity http)"}, {"id": "B", "text": "setSecurityContext()"}, {"id": "C", "text": "authorizeRequests()"}, {"id": "D", "text": "configureGlobal()"}]', 'C', 'authorizeRequests() 메서드는 URL 패턴에 대한 접근 제어를 설정하는 데 사용됩니다.'),
    (1721, 5, 1, 305, 'Spring Security에서 사용자의 권한을 설정하는 데 사용되는 메서드는 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "grantRole()"}, {"id": "B", "text": "hasRole()"}, {"id": "C", "text": "authenticated()"}, {"id": "D", "text": "permitAll()"}]', '["B", "C"]', 'hasRole() 메서드는 특정 역할을 가진 사용자의 접근을 허용하고, authenticated() 메서드는 인증된 사용자만 접근하도록 설정합니다.'),
    (1722, 5, 1, 306, 'Spring Security의 기본 로그인 방식을 설정하는 메서드는 무엇인가요?', 'SHORT_ANSWER', NULL, 'formLogin()', 'formLogin() 메서드는 Spring Security에서 기본 로그인 방식을 설정하는 메서드입니다.'),
    (1723, 5, 1, 307, '다음 코드에서 equals() 메소드는 어떤 조건들을 검사하고 있나요? 
@Override
public boolean equals(Object obj) {
    if (this == obj) return true;
    if (obj == null || getClass() != obj.getClass()) return false;
    MyClass myClass = (MyClass) obj;
    return Objects.equals(field, myClass.field);
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 객체가 동일한 참조인지 검사한다."}, {"id": "B", "text": "두 객체의 모든 필드를 비교한다."}, {"id": "C", "text": "객체가 null인지 검사한다."}, {"id": "D", "text": "동일 클래스인지 확인한다."}]', 'A', 'equals() 메소드는 먼저 두 객체가 동일한 참조인지 확인하고, 그 다음 null과 클래스 타입을 검사합니다.'),
    (1724, 5, 1, 308, 'hashCode() 메소드에서 반환되는 값은 무엇을 기반으로 계산되나요?', 'SHORT_ANSWER', NULL, '객체의 필드 값', 'hashCode()는 equals()에서 비교한 필드와 같은 필드를 이용하여 해시 코드를 계산합니다.'),
    (1725, 5, 1, 309, '다음 중 equals()와 hashCode()를 오버라이드 할 때 반드시 지켜야 할 규칙은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "equals()가 true를 반환하는 경우 hashCode()는 같은 값을 반환해야 한다."}, {"id": "B", "text": "hashCode()는 항상 0을 반환해야 한다."}, {"id": "C", "text": "equals()에서 사용하는 필드를 hashCode()에서도 사용해야 한다."}, {"id": "D", "text": "equals()와 hashCode()는 반드시 함께 오버라이드해야 한다."}]', '["A", "C"]', 'equals()가 true를 반환하면 hashCode()는 같은 값을 반환해야 하며, hashCode()는 equals()에서 사용하는 필드를 기반으로 계산해야 합니다.'),
    (1726, 5, 1, 310, '다음 코드를 분석하고, equals()와 hashCode()를 모두 오버라이드 했을 때의 성능 이점은 무엇인가요? 
