    (4671, 15, 1, 25, '자식 클래스가 부모 클래스의 메소드를 재정의하는 것을 무엇이라고 하나요?', 'SHORT_ANSWER', NULL, '오버라이드', '자식 클래스가 부모 클래스의 메소드를 재정의하는 것을 오버라이드라고 합니다.'),
    (4672, 15, 1, 26, '다음 코드의 출력 결과는 무엇인가요?

name = "Alice"
