    # 코드 작성
except _________:
    # 예외 처리 코드', 'SHORT_ANSWER', NULL, '예외 종류', '예외 처리 구문에서 except 뒤에는 발생할 수 있는 예외의 종류를 명시해야 합니다.'),
    (5068, 15, 1, 422, '다음 코드에서 finally 블록의 역할은 무엇인가요?

try:
    # 코드 작성
