    myMap[3] = "Three";
    std::cout << myMap[2];
    return 0;
}', 'SHORT_ANSWER', NULL, '2', '키 2를 사용하여 ''Two''를 출력할 수 있습니다.'),
    (6503, 22, 1, 208, '위 코드에서 구조체 ''Vehicle''의 ''drive'' 변수는 어떤 타입인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "int"}, {"id": "B", "text": "char[]"}, {"id": "C", "text": "void (*)()"}, {"id": "D", "text": "struct"}]', 'C', '''drive''는 함수 포인터로서, ''void (*)()'' 타입이다.'),
    (6504, 22, 1, 209, '위 코드에서 ''myCar.drive()''를 호출하면 어떤 출력이 나타나는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Vehicle Name: MyCar"}, {"id": "B", "text": "Driving a car!"}, {"id": "C", "text": "Car structure is empty."}, {"id": "D", "text": "Compilation Error"}]', 'B', '''myCar.drive()''가 호출되면 ''Driving a car!''가 출력된다.'),
    (6505, 22, 1, 210, '아래 코드를 완성하시오: ''myCar.drive = ________;'' ', 'SHORT_ANSWER', NULL, 'carDrive', '''myCar.drive''는 ''carDrive''라는 함수 포인터로 설정되어야 한다.'),
    (6506, 22, 1, 211, '구조체와 함수 포인터를 사용하여 차량의 여러 주행 방식을 구현할 때, 어떤 방식이 가장 적합한가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "각 주행 방식에 대해 별도의 함수 정의"}, {"id": "B", "text": "조건문을 사용하여 주행 방식 결정"}, {"id": "C", "text": "함수 포인터 배열 사용"}, {"id": "D", "text": "모든 주행 방식을 하나의 함수로 합치기"}]', '["A", "C"]', '각 주행 방식에 대해 별도의 함수를 정의하고 함수 포인터 배열을 사용하면 유연하게 구현할 수 있다.'),
    (6507, 22, 1, 212, '위 코드에서 ''execute'' 함수가 호출되는 시점에서 ''printPoint''는 어떤 역할을 하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Point 구조체의 정보를 출력한다."}, {"id": "B", "text": "Point 구조체를 초기화한다."}, {"id": "C", "text": "Point 구조체를 비교한다."}, {"id": "D", "text": "Point 구조체를 반환한다."}]', 'A', '''printPoint'' 함수는 인자로 전달된 ''Point'' 구조체의 정보를 출력하는 역할을 한다.'),
    (6508, 22, 1, 213, '다음 코드의 빈칸을 채우시오: ''typedef struct { int x; int y; } _____;'' (구조체 이름)', 'SHORT_ANSWER', NULL, 'Point', '구조체는 ''Point''라는 이름을 가지고 정의된다.'),
    (6509, 22, 1, 214, '아래 코드의 실행 결과는 무엇일까요? ''Point p = {5, 15}; execute(p, printPoint);'' ', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Point(5, 15)"}, {"id": "B", "text": "Point(10, 20)"}, {"id": "C", "text": "Point(0, 0)"}, {"id": "D", "text": "에러가 발생한다."}]', 'A', '주어진 ''Point p''의 값이 ''5''와 ''15''로 설정되어 ''printPoint'' 함수에 의해 출력된다.'),
    (6510, 22, 1, 215, '다음 중 함수 포인터의 사용 목적은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "동적으로 함수를 호출하기 위해"}, {"id": "B", "text": "메모리 효율성을 높이기 위해"}, {"id": "C", "text": "함수의 반환 값을 저장하기 위해"}, {"id": "D", "text": "여러 함수 중 하나를 선택하기 위해"}]', '["A", "D"]', '함수 포인터는 동적으로 함수를 선택하여 호출할 수 있게 하며, 여러 함수 중 하나를 선택할 수 있도록 한다.'),
    (6511, 22, 1, 216, '다음 템플릿 함수의 반환 타입은 무엇인가? 

 template <typename T> 
 T add(T a, T b) { 
     return a + b; 
 }', 'SHORT_ANSWER', NULL, 'T', '템플릿 함수의 반환 타입은 템플릿에서 정의한 타입 T입니다.'),
    (6512, 22, 1, 217, '다음 코드의 출력 결과는 무엇인가? 

 template <typename T> 
 void print(T value) { 
     std::cout << value; 
 } 

 int main() { 
     print(5); 
     return 0; 
 }', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "5"}, {"id": "B", "text": "없음"}, {"id": "C", "text": "에러 발생"}, {"id": "D", "text": "5.0"}]', 'A', '템플릿 함수는 정수형 5를 받아 해당 값을 출력하기 때문에 출력 결과는 5입니다.'),
    (6513, 22, 1, 218, '다음 코드에서 제네릭한 스택 클래스를 정의할 때 빈칸에 들어갈 적절한 키워드는 무엇인가? 

 template <typename T> 
 class Stack { 
     std::vector<T> elements; 
 public: 
     void push(T const& element) { 
         elements.push_back(element); 
     } 
     T pop() { 
         _______ 
     } 
 };', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "return elements.back();"}, {"id": "B", "text": "return elements.front();"}, {"id": "C", "text": "return elements[0];"}, {"id": "D", "text": "return elements.size();"}]', 'A', '스택의 pop() 메서드는 가장 끝에 있는 요소를 반환해야 하므로 elements.back()을 사용해야 합니다.'),
    (6514, 22, 1, 219, '다음 중 템플릿 클래스를 사용하는 이유로 올바른 것은 무엇인가? (복수 선택 가능) 

 1. 코드 재사용성 향상 
 2. 모든 타입에 대해 같은 구현을 사용 가능 
 3. 컴파일 시간 단축 
 4. 타입 안전성 확보', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["A", "B", "D"]', '템플릿 클래스를 사용하면 코드의 재사용성과 타입 안전성을 높일 수 있으며, 다양한 타입에 대해 같은 구현을 사용할 수 있습니다.'),
    (6515, 22, 1, 220, '템플릿을 사용하여 생성한 벡터의 크기를 가져오는 방법은 무엇인가?', 'SHORT_ANSWER', NULL, 'vector.size()', '템플릿 클래스를 사용하여 생성한 벡터의 크기를 가져오는 방법은 vector.size()를 호출하는 것입니다.'),
    (6516, 22, 1, 221, '다음 코드의 실행 결과로 읽어올 데이터는 무엇인가요?
`fread(readData, sizeof(int), 5, file);`', 'SHORT_ANSWER', NULL, '1, 2, 3, 4, 5', '파일에 기록된 데이터는 1, 2, 3, 4, 5이기 때문입니다.'),
    (6517, 22, 1, 222, '다음 코드에서 `fopen` 함수의 두 번째 인자로 주어진 모드는 무엇을 의미하나요?
`file = fopen("data.bin", "wb");`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쓰기 모드 (binary)"}, {"id": "B", "text": "읽기 모드 (text)"}, {"id": "C", "text": "쓰기 모드 (text)"}, {"id": "D", "text": "읽기 모드 (binary)"}]', 'A', '모드 ''wb''는 바이너리 모드로 파일을 쓰기 위한 것임을 의미합니다.'),
    (6518, 22, 1, 223, '다음 코드의 빈칸에 들어갈 내용은 무엇인가요?
`file = fopen("data.bin", "___");`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "rb"}, {"id": "B", "text": "wb"}, {"id": "C", "text": "ab"}, {"id": "D", "text": "rt"}]', 'A', '''rb''는 바이너리 읽기 모드로 파일을 열기 위한 것입니다.'),
    (6519, 22, 1, 224, '파일에 여러 정수를 기록할 때 사용하는 함수는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "fwrite"}, {"id": "B", "text": "fread"}, {"id": "C", "text": "fprintf"}, {"id": "D", "text": "fputs"}]', '["A"]', '여러 정수를 기록하는 함수는 fwrite입니다.'),
    (6520, 22, 1, 225, '파일을 닫기 위해 사용하는 함수의 이름은 무엇인가요?', 'SHORT_ANSWER', NULL, 'fclose', '파일을 닫기 위해서는 fclose 함수를 사용합니다.'),
    (6521, 22, 1, 226, '위 코드에서 ''fopen'' 함수의 첫 번째 매개변수의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''numbers.bin''이라는 파일을 지정한다."}, {"id": "B", "text": "파일에서 읽어올 데이터를 지정한다."}, {"id": "C", "text": "파일의 크기를 설정한다."}, {"id": "D", "text": "파일 모드를 설정한다."}]', 'A', '''fopen'' 함수에서 첫 번째 매개변수는 열고자 하는 파일의 이름을 지정합니다.'),
    (6522, 22, 1, 227, '아래 코드에서 빈칸에 들어갈 적절한 함수는 무엇인가요? FILE *file; ... file = fopen("numbers.bin", "__");', 'SHORT_ANSWER', NULL, 'wb', '"wb"는 이진 파일 쓰기 모드를 의미합니다.'),
    (6523, 22, 1, 228, '위 코드에서 ''fread''와 ''fwrite''가 수행하는 작업은 각각 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "''fwrite''는 데이터를 파일에 쓴다."}, {"id": "B", "text": "''fread''는 데이터를 파일에서 읽는다."}, {"id": "C", "text": "''fwrite''는 파일을 열기 위한 함수이다."}, {"id": "D", "text": "''fread''는 파일을 닫기 위한 함수이다."}]', '["A", "B"]', '''fwrite''는 데이터를 파일에 쓰고, ''fread''는 파일에서 데이터를 읽는 함수입니다.'),
    (6524, 22, 1, 229, '위 코드에서 ''fclose'' 함수의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리를 해제한다."}, {"id": "B", "text": "파일을 닫고 자원을 반환한다."}, {"id": "C", "text": "파일의 데이터를 초기화한다."}, {"id": "D", "text": "파일의 내용을 출력한다."}]', 'B', '''fclose'' 함수는 열린 파일을 닫고 해당 자원을 운영 체제에 반환합니다.'),
    (6525, 22, 1, 230, '위 코드의 출력 결과는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1 2 3 4 5 "}, {"id": "B", "text": "0 0 0 0 0 "}, {"id": "C", "text": "파일을 찾을 수 없습니다."}, {"id": "D", "text": "읽기 오류 발생"}]', 'A', '파일에 저장된 정수 배열이 정상적으로 읽혀져서 출력되기 때문에 1 2 3 4 5가 출력됩니다.'),
    (6526, 22, 1, 231, '다음 코드의 출력은 무엇인가요?

#include <iostream>
#include <memory>

void uniquePtrExample() {
    std::unique_ptr<int> ptr1(new int(10));
    std::cout << *ptr1 << std::endl; // 10
    // std::unique_ptr<int> ptr2 = ptr1; // 오류 발생 (복사 불가)
}
int main() {
    uniquePtrExample();
    return 0;
}', 'SHORT_ANSWER', NULL, '10', 'unique_ptr는 소유한 메모리를 출력하므로 10이 출력됩니다.'),
    (6527, 22, 1, 232, '다음 코드의 주석을 제거하면 어떤 오류가 발생하나요?

#include <iostream>
#include <memory>

void uniquePtrExample() {
    std::unique_ptr<int> ptr1(new int(10));
    // std::unique_ptr<int> ptr2 = ptr1; // 오류 발생 (복사 불가)
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "복사 불가 오류"}, {"id": "B", "text": "메모리 해제 오류"}, {"id": "C", "text": "리턴 오류"}, {"id": "D", "text": "NULL 오류"}]', 'A', 'unique_ptr은 복사할 수 없기 때문에 ''복사 불가'' 오류가 발생합니다.'),
    (6528, 22, 1, 233, 'shared_ptr의 참조 카운트는 어떻게 증가하나요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "복사 생성자 사용"}, {"id": "B", "text": "move 사용"}, {"id": "C", "text": "reset 사용"}, {"id": "D", "text": "대입 연산자 사용"}]', '["A"]', 'shared_ptr의 참조 카운트는 복사 생성자를 통해 증가합니다.'),
    (6529, 22, 1, 234, '다음 코드의 결과는 무엇인가요?

#include <iostream>
#include <memory>

void sharedPtrExample() {
    std::shared_ptr<int> ptr1(new int(20));
    {
        std::shared_ptr<int> ptr2 = ptr1;
    }
    std::cout << *ptr1 << std::endl;
}
int main() {
    sharedPtrExample();
    return 0;
}', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "20"}, {"id": "B", "text": "0"}, {"id": "C", "text": "nullptr"}, {"id": "D", "text": "메모리 오류"}]', 'A', 'ptr2가 scope를 벗어나도 ptr1이 여전히 메모리를 관리하므로 20이 출력됩니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 컴퓨터 구조 > 메모리 체계 (45문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (6530, 22, 2, 1, 'RAM의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "휘발성이 있으며 빠른 접근 속도를 가진다."}, {"id": "B", "text": "비휘발성이며 느린 접근 속도를 가진다."}, {"id": "C", "text": "휘발성이며 느린 접근 속도를 가진다."}, {"id": "D", "text": "비휘발성이며 빠른 접근 속도를 가진다."}]', 'A', 'RAM은 휘발성 메모리로서 전원이 꺼지면 데이터가 사라지지만, 상대적으로 빠른 속도로 데이터를 처리할 수 있습니다.'),
    (6531, 22, 2, 2, '가상 메모리의 주 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "실제 메모리보다 더 큰 프로그램 실행 가능"}, {"id": "B", "text": "데이터의 물리적 위치를 변경한다."}, {"id": "C", "text": "CPU의 성능을 낮춘다."}, {"id": "D", "text": "메모리의 모든 데이터를 휘발성으로 만든다."}]', 'A', '가상 메모리는 시스템이 실제 메모리 용량을 초과하는 프로그램을 실행할 수 있도록 지원합니다.'),
    (6532, 22, 2, 3, 'TLB의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 주소 변환 속도 향상"}, {"id": "B", "text": "데이터를 영구적으로 저장"}, {"id": "C", "text": "CPU의 클럭 속도 증가"}, {"id": "D", "text": "입출력 장치와의 연결을 최적화"}, {"id": "E", "text": "메모리의 데이터를 암호화"}]', 'A', 'TLB는 페이지 테이블에서 주소 변환을 캐시하여 메모리 접근 속도를 높이는 역할을 합니다.'),
    (6533, 22, 2, 4, '메모리 시스템에서 페이지 테이블과 TLB의 차이를 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "페이지 테이블은 하드웨어적으로 구현된다."}, {"id": "B", "text": "TLB는 메모리 접근 속도를 높이는 데 사용된다."}, {"id": "C", "text": "페이지 테이블은 전체 메모리 매핑 정보를 가진다."}, {"id": "D", "text": "TLB는 모든 메모리 주소를 관리한다."}]', '["B", "C"]', 'TLB는 메모리 접근 속도를 향상시키는 캐시이며, 페이지 테이블은 전체 메모리 매핑 정보를 관리합니다.'),
    (6534, 22, 2, 5, '빅 엔디안이 무엇인가?', 'SHORT_ANSWER', NULL, '데이터의 저장 순서가 최상위 바이트부터 시작하는 방식', '빅 엔디안은 메모리에 데이터를 저장할 때 최상위 바이트를 먼저 저장하는 방식을 의미합니다.'),
    (6535, 22, 2, 6, '리틀 엔디안에서 데이터의 바이트 순서는 어떻게 저장되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 작은 바이트가 가장 낮은 주소에 저장된다."}, {"id": "B", "text": "가장 큰 바이트가 가장 낮은 주소에 저장된다."}, {"id": "C", "text": "모든 바이트가 동일한 주소에 저장된다."}, {"id": "D", "text": "주소에 관계없이 임의로 저장된다."}]', 'A', '리틀 엔디안 방식에서는 가장 작은 바이트가 가장 낮은 주소에 저장됩니다.'),
    (6536, 22, 2, 7, 'RAM의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "휘발성 메모리이다."}, {"id": "B", "text": "비휘발성 메모리이다."}, {"id": "C", "text": "읽기 전용이다."}, {"id": "D", "text": "데이터를 영구적으로 저장한다."}]', 'A', 'RAM은 휘발성 메모리로, 전원이 꺼지면 데이터가 사라집니다.'),
    (6537, 22, 2, 8, '가상 메모리는 주로 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "물리적 메모리의 확장을 위해"}, {"id": "B", "text": "CPU의 속도를 높이기 위해"}, {"id": "C", "text": "장치 드라이버를 저장하기 위해"}, {"id": "D", "text": "네트워크 연결을 위해"}]', 'A', '가상 메모리는 물리적 메모리를 확장하여 더 많은 프로그램을 실행할 수 있도록 지원합니다.'),
    (6538, 22, 2, 9, '다음 중 벡터 인터럽트의 역할은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "CPU가 처리해야 할 작업의 주소를 저장한다."}, {"id": "B", "text": "데이터 전송 속도를 증가시킨다."}, {"id": "C", "text": "메모리 오류를 처리한다."}, {"id": "D", "text": "네트워크 요청을 처리한다."}]', '["A"]', '벡터 인터럽트는 특정 이벤트가 발생했을 때 CPU가 처리해야 할 작업의 주소를 저장하는 방식입니다.'),
    (6539, 22, 2, 10, '시스템 버스의 구성 요소 중 하나는 무엇인가요?', 'SHORT_ANSWER', NULL, '데이터 버스', '시스템 버스는 CPU와 다른 장치 간 데이터 전송을 담당하는 데이터 버스를 포함합니다.'),
    (6540, 22, 2, 11, 'DRAM의 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정기적인 새로 고침이 필요하다."}, {"id": "B", "text": "전원이 꺼져도 데이터가 유지된다."}, {"id": "C", "text": "속도가 매우 빠르다."}, {"id": "D", "text": "비용이 가장 비싸다."}]', 'A', 'DRAM은 데이터를 저장하기 위해 정기적인 새로 고침이 필요한 메모리 유형입니다.'),
    (6541, 22, 2, 12, '페이지 테이블의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가상 메모리 주소를 물리적 주소로 변환하는 것"}, {"id": "B", "text": "데이터를 영구적으로 저장하는 것"}, {"id": "C", "text": "CPU의 클럭 속도를 조절하는 것"}, {"id": "D", "text": "입출력을 관리하는 것"}]', 'A', '페이지 테이블은 가상 메모리 주소를 물리적 주소로 변환하는 데 사용됩니다.'),
    (6542, 22, 2, 13, '다음 중 TLB에 대한 설명으로 맞는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "페이지 테이블을 대체하는 장치이다."}, {"id": "B", "text": "페이지 테이블의 성능을 높이기 위한 캐시이다."}, {"id": "C", "text": "모든 데이터를 영구적으로 저장한다."}, {"id": "D", "text": "입출력을 처리하는 장치이다."}]', 'B', 'TLB는 페이지 테이블의 성능을 높이기 위한 고속 캐시 메모리입니다.'),
    (6543, 22, 2, 14, '다음 중 폴링의 특징으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "주기적으로 장치 상태를 검사한다."}, {"id": "B", "text": "데이터 전송 속도가 빠르다."}, {"id": "C", "text": "입출력 장치의 상태를 비동기적으로 처리한다."}, {"id": "D", "text": "장치의 상태 변화가 있을 때만 반응한다."}]', '["A"]', '폴링은 주기적으로 장치의 상태를 검사하여 입출력을 수행하는 방식입니다.'),
    (6544, 22, 2, 15, '주소 버스의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '메모리 주소를 전송하는 통로 역할을 한다.', '주소 버스는 메모리 주소를 CPU와 메모리 간에 전송하는 역할을 합니다.'),
    (6545, 22, 2, 16, 'DRAM의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "휘발성 메모리이다."}, {"id": "B", "text": "비휘발성 메모리이다."}, {"id": "C", "text": "데이터 전송 속도가 매우 느리다."}, {"id": "D", "text": "사용자가 직접 데이터 복구가 가능하다."}]', 'A', 'DRAM은 휘발성 메모리로, 전원이 꺼지면 저장된 데이터가 사라집니다.'),
    (6546, 22, 2, 17, '빅 엔디안 방식에서 가장 먼저 저장되는 바이트는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 작은 바이트"}, {"id": "B", "text": "가장 큰 바이트"}, {"id": "C", "text": "중간 크기의 바이트"}, {"id": "D", "text": "모든 바이트가 동시에 저장된다."}]', 'B', '빅 엔디안 방식은 가장 큰 바이트가 메모리의 낮은 주소에 먼저 저장됩니다.'),
    (6547, 22, 2, 18, '주소 버스의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송 속도를 측정한다."}, {"id": "B", "text": "CPU와 메모리 간의 주소를 전달한다."}, {"id": "C", "text": "입출력 장치와 연결된다."}, {"id": "D", "text": "메모리의 데이터 저장 방식을 결정한다."}]', 'B', '주소 버스는 CPU가 특정 메모리 주소를 지정하는 데 사용됩니다.'),
    (6548, 22, 2, 19, '다음 중 페이지 테이블의 기능으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "가상 주소를 물리 주소로 변환한다."}, {"id": "B", "text": "메모리 접근 속도를 향상시킨다."}, {"id": "C", "text": "메모리의 데이터 백업을 제공한다."}, {"id": "D", "text": "프로세스 간의 메모리 격리를 수행한다."}]', '["A", "D"]', '페이지 테이블은 가상 주소를 물리 주소로 변환하고, 각 프로세스 간에 메모리 격리를 수행합니다.'),
    (6549, 22, 2, 20, 'MMU의 풀 네임은 무엇인가요?', 'SHORT_ANSWER', NULL, 'Memory Management Unit', 'MMU는 Memory Management Unit의 약어로, 메모리 관리 기능을 수행하는 하드웨어입니다.'),
    (6550, 22, 2, 21, '플래시 메모리는 어떤 유형의 메모리인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "휘발성 메모리"}, {"id": "B", "text": "비휘발성 메모리"}, {"id": "C", "text": "캐시 메모리"}, {"id": "D", "text": "레지스터 메모리"}]', 'B', '플래시 메모리는 비휘발성 저장 장치로, 전원이 꺼져도 데이터가 유지됩니다.'),
    (6551, 22, 2, 22, 'MMU의 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송을 위한 버스 관리"}, {"id": "B", "text": "가상 메모리를 물리 메모리로 매핑"}, {"id": "C", "text": "CPU의 클럭 속도 조절"}, {"id": "D", "text": "입출력 장치 관리"}]', 'B', 'MMU는 가상 메모리를 물리 메모리로 매핑하여 메모리 보호와 관리 기능을 수행합니다.'),
    (6552, 22, 2, 23, '데이터 전송 방식 중 DMA의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CPU를 거치지 않고 직접 데이터 전송"}, {"id": "B", "text": "데이터 전송 시 CPU의 부하를 증가시킴"}, {"id": "C", "text": "단일 데이터 전송만 지원"}, {"id": "D", "text": "메모리 접근 속도를 늦춤"}]', 'A', 'DMA는 CPU를 거치지 않고 장치와 메모리 간에 직접 데이터 전송을 가능하게 하여 성능을 향상시킵니다.'),
    (6553, 22, 2, 24, '리틀 엔디안과 빅 엔디안의 주요 차이는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "바이트 순서의 저장 방식"}, {"id": "B", "text": "데이터 전송 속도"}, {"id": "C", "text": "CPU의 처리 방식"}, {"id": "D", "text": "메모리의 용량"}]', '["A"]', '리틀 엔디안과 빅 엔디안은 데이터의 바이트 순서를 저장하는 방식에서 차이가 있습니다.'),
    (6554, 22, 2, 25, '폴링 기법은 무엇을 관리하는 데 사용되는가?', 'SHORT_ANSWER', NULL, '입출력 장치의 상태', '폴링 기법은 장치의 상태를 주기적으로 확인하여 관리하는 방법입니다.'),
    (6555, 22, 2, 26, '주소 버스의 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리의 주소를 지정한다."}, {"id": "B", "text": "데이터를 전송한다."}, {"id": "C", "text": "메모리의 용량을 결정한다."}, {"id": "D", "text": "CPU의 속도를 향상시킨다."}]', 'A', '주소 버스는 메모리에 접근하기 위해 필요한 주소를 전달하는 역할을 합니다.'),
    (6556, 22, 2, 27, '다음 중 비휘발성 메모리의 예로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "RAM"}, {"id": "B", "text": "ROM"}, {"id": "C", "text": "SRAM"}, {"id": "D", "text": "DRAM"}]', 'B', 'ROM은 비휘발성 메모리로, 전원이 꺼져도 데이터가 사라지지 않습니다.'),
    (6557, 22, 2, 28, '인터럽트 방식과 폴링 방식의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인터럽트는 CPU가 직접 확인하는 방식이다."}, {"id": "B", "text": "폴링은 주기적으로 상태를 확인하는 방식이다."}, {"id": "C", "text": "인터럽트는 느리지만 정확하다."}, {"id": "D", "text": "폴링은 모든 장치에 동일한 우선순위를 부여한다."}]', 'B', '폴링 방식은 CPU가 주기적으로 입출력 장치의 상태를 확인하는 방식입니다.'),
    (6558, 22, 2, 29, '메모리의 종류 중 휘발성 메모리의 두 가지를 나열하시오.', 'SHORT_ANSWER', NULL, 'RAM, SRAM', 'RAM과 SRAM은 모두 휘발성 메모리로, 전원이 끊기면 데이터가 사라집니다.'),
    (6559, 22, 2, 30, 'TLB의 기능은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "페이지 테이블을 캐시한다."}, {"id": "B", "text": "메모리 속도를 향상시킨다."}, {"id": "C", "text": "CPU의 성능을 저하시킨다."}, {"id": "D", "text": "메모리의 용량을 증가시킨다."}]', '["A", "B"]', 'TLB는 페이지 테이블의 데이터를 캐시하여 메모리 접근 속도를 증가시킵니다.'),
    (6560, 22, 2, 31, '리틀 엔디안 방식에서 데이터는 어떻게 저장되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 하위 바이트가 먼저 저장된다."}, {"id": "B", "text": "가장 상위 바이트가 먼저 저장된다."}, {"id": "C", "text": "모든 바이트가 동시에 저장된다."}, {"id": "D", "text": "데이터는 저장되지 않는다."}]', 'A', '리틀 엔디안은 데이터의 가장 하위 바이트가 메모리의 가장 낮은 주소에 저장되는 방식입니다.'),
    (6561, 22, 2, 32, 'TLB(Translation Lookaside Buffer)의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "입출력 장치의 속도를 향상시킨다."}, {"id": "B", "text": "가상 주소를 물리 주소로 변환하는 데 도움을 준다."}, {"id": "C", "text": "메모리 용량을 증가시킨다."}, {"id": "D", "text": "데이터의 암호화를 수행한다."}]', 'B', 'TLB는 CPU가 가상 주소를 물리 주소로 변환할 때 사용하는 캐시 메모리로, 변환 속도를 향상시킵니다.'),
    (6562, 22, 2, 33, '다음 중 가상 메모리의 장점이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "더 큰 메모리 공간을 제공한다."}, {"id": "B", "text": "프로그램의 메모리 사용을 효율적으로 관리한다."}, {"id": "C", "text": "메모리 접근 속도를 늘린다."}, {"id": "D", "text": "물리적 메모리의 제한을 극복한다."}]', 'C', '가상 메모리는 프로그램을 위한 더 큰 메모리 공간을 제공하지만, 물리 메모리의 접근 속도를 직접 늘리지는 않습니다.'),
    (6563, 22, 2, 34, '메모리 주소를 지정하는 데 사용하는 버스의 이름은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "주소 버스"}, {"id": "B", "text": "데이터 버스"}, {"id": "C", "text": "제어 버스"}, {"id": "D", "text": "인터럽트 버스"}]', '["A", "B", "C"]', '주소 버스는 메모리 주소를 지정하고, 데이터 버스는 실제 데이터를 전송하며, 제어 버스는 다양한 제어 신호를 전송합니다.'),
    (6564, 22, 2, 35, 'ROM의 주요 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '비휘발성 메모리로 데이터를 저장한다.', 'ROM은 비휘발성이므로 전원이 꺼져도 데이터를 유지하며, 주로 펌웨어와 같은 중요한 정보를 저장하는 데 사용됩니다.'),
    (6565, 22, 2, 36, 'RAM의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "임시 데이터 저장"}, {"id": "B", "text": "영구 데이터 저장"}, {"id": "C", "text": "프로그램 실행 시간 단축"}, {"id": "D", "text": "데이터 압축"}]', 'A', 'RAM은 주기억장치로서 데이터를 임시로 저장하는 역할을 합니다.'),
    (6566, 22, 2, 37, '리틀 엔디안 방식에서 데이터는 어떻게 저장되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "최하위 바이트가 먼저 저장"}, {"id": "B", "text": "최상위 바이트가 먼저 저장"}, {"id": "C", "text": "모든 바이트가 동시에 저장"}, {"id": "D", "text": "저장 방식에 상관없음"}]', 'A', '리틀 엔디안 방식은 최하위 바이트가 먼저 저장되는 방식입니다.'),
    (6567, 22, 2, 38, '가상 메모리 시스템에서 페이지 테이블의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가상 주소를 물리 주소로 변환"}, {"id": "B", "text": "데이터 압축"}, {"id": "C", "text": "프로세서 속도 향상"}, {"id": "D", "text": "입출력 장치 관리"}]', 'A', '페이지 테이블은 가상 주소를 물리 주소로 변환하는 역할을 합니다.'),
    (6568, 22, 2, 39, '다음 중 DMA의 특징으로 올바른 것은 무엇인가? (모두 선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "CPU 개입 없이 데이터 전송 가능"}, {"id": "B", "text": "데이터 전송 속도 향상"}, {"id": "C", "text": "프로그램 실행을 지연시킴"}, {"id": "D", "text": "메모리에 직접 접근 가능"}]', '["A", "B", "D"]', 'DMA는 CPU 개입 없이 데이터 전송이 가능하고, 데이터 전송 속도를 향상시키며, 메모리에 직접 접근할 수 있습니다.'),
    (6569, 22, 2, 40, 'TLB는 무엇의 줄임말인가?', 'SHORT_ANSWER', NULL, 'Translation Lookaside Buffer', 'TLB는 페이지 테이블의 조회를 가속화하기 위한 캐시 메모리로, ''Translation Lookaside Buffer''의 줄임말입니다.'),
    (6570, 22, 2, 41, 'DRAM의 주요 특징은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "저렴하고 대용량 저장이 가능하다."}, {"id": "B", "text": "비싸고 빠르다."}, {"id": "C", "text": "정지 전원 시 데이터가 소실된다."}, {"id": "D", "text": "모든 보기에 해당된다."}]', 'A', 'DRAM은 저렴하고 대용량 저장이 가능한 반면, 정지 전원 시 데이터가 소실됩니다.'),
    (6571, 22, 2, 42, '가상 메모리의 주 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 용량을 확장한다."}, {"id": "B", "text": "CPU의 속도를 증가시킨다."}, {"id": "C", "text": "데이터를 암호화한다."}, {"id": "D", "text": "메모리 오류를 방지한다."}]', 'A', '가상 메모리는 프로그램이 사용할 수 있는 메모리의 양을 확장하는 것입니다.'),
    (6572, 22, 2, 43, 'TLB의 주 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 암호화한다."}, {"id": "B", "text": "페이지 테이블을 캐시하여 접근 속도를 높인다."}, {"id": "C", "text": "주소 버스를 관리한다."}, {"id": "D", "text": "메모리 오류를 수정한다."}]', 'B', 'TLB는 가상 메모리에서 페이지 테이블을 캐시하여 메모리 접근 속도를 높이는 역할을 합니다.'),
    (6573, 22, 2, 44, '리틀 엔디안과 빅 엔디안의 차이는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "바이트 순서의 차이이다."}, {"id": "B", "text": "데이터 전송 속도의 차이다."}, {"id": "C", "text": "메모리 관리 방법의 차이다."}, {"id": "D", "text": "CPU 아키텍처의 차이다."}]', '["A", "D"]', '리틀 엔디안과 빅 엔디안은 데이터의 바이트 순서를 정의하며, CPU 아키텍처와 관련이 있습니다.'),
    (6574, 22, 2, 45, '주소 버스의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '메모리 주소를 전송하는 통로이다.', '주소 버스는 CPU가 메모리에 접근하기 위해 필요한 주소를 전송하는 역할을 합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 컴퓨터 구조 > 병렬 처리 (67문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (6575, 22, 3, 1, '조합론에서 n개의 아이템 중 r개를 선택하는 경우의 수는 어떤 공식을 사용하여 계산할 수 있는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "n! / (r! * (n-r)!),"}, {"id": "B", "text": "n! * r!"}, {"id": "C", "text": "n * r"}, {"id": "D", "text": "n + r"}]', 'A', '조합의 경우의 수는 n! / (r! * (n-r)!)로 계산됩니다.'),
    (6576, 22, 3, 2, '그래프 색칠에서 임의의 두 인접한 정점은 서로 다른 색으로 칠해야 할 때, 최소 몇 가지 색이 필요한가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "무한대"}]', 'B', '최소 두 가지 색이 필요합니다.'),
    (6577, 22, 3, 3, '비둘기집 원리에 따르면 n개의 비둘기를 m개의 집에 넣을 때, n > m인 경우 어떻게 되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "적어도 하나의 집에 두 마리 이상의 비둘기가 있다."}, {"id": "B", "text": "모든 집에 비둘기가 골고루 들어간다."}, {"id": "C", "text": "비둘기는 집에 들어갈 수 없다."}, {"id": "D", "text": "각 집에 비둘기가 정확히 한 마리씩 들어간다."}]', '["A"]', '비둘기집 원리에 따르면 n > m인 경우 적어도 하나의 비둘기가 같은 집에 들어가게 됩니다.'),
    (6578, 22, 3, 4, '해밀턴 경로는 그래프의 모든 정점을 몇 번씩 방문하는가?', 'SHORT_ANSWER', NULL, '한 번씩 방문한다.', '해밀턴 경로는 그래프의 모든 정점을 정확히 한 번씩 방문하는 경로를 말합니다.'),
    (6579, 22, 3, 5, '명제 논리에서 두 개의 명제가 모두 참일 때, 두 명제를 AND로 연결하면 결과는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "True"}, {"id": "B", "text": "False"}, {"id": "C", "text": "Undefined"}, {"id": "D", "text": "Can’t determine"}]', 'A', '두 명제가 모두 참이면 AND로 연결한 결과는 참입니다.'),
    (6580, 22, 3, 6, 'CUDA는 무엇을 위한 프로그래밍 모델인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "GPU를 이용한 병렬 처리"}, {"id": "B", "text": "CPU를 이용한 직렬 처리"}, {"id": "C", "text": "네트워크 프로그래밍"}, {"id": "D", "text": "데이터베이스 관리"}]', 'A', 'CUDA는 NVIDIA의 GPU를 활용한 병렬 처리 프로그래밍 모델이다.'),
    (6581, 22, 3, 7, '다음 중 MIMD 아키텍처에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단일 명령을 여러 데이터에 적용한다."}, {"id": "B", "text": "여러 명령을 여러 데이터에 적용한다."}, {"id": "C", "text": "모든 프로세서가 동일한 작업을 수행한다."}, {"id": "D", "text": "하나의 명령을 하나의 데이터에만 적용한다."}]', 'B', 'MIMD는 여러 프로세서가 서로 다른 명령과 데이터를 동시에 처리하는 아키텍처이다.'),
    (6582, 22, 3, 8, '캐시 일관성이 필요한 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세서 간의 데이터 일관성을 유지하기 위해"}, {"id": "B", "text": "메모리 속도를 증가시키기 위해"}, {"id": "C", "text": "픽셀 렌더링 속도를 높이기 위해"}, {"id": "D", "text": "전력 소모를 줄이기 위해"}]', 'A', '캐시 일관성은 멀티코어 시스템에서 프로세서 간의 데이터 일관성을 유지하는 데 필요하다.'),
    (6583, 22, 3, 9, '다음 중 병렬 처리의 성능 향상에 영향을 미치는 요소는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "암달의 법칙"}, {"id": "B", "text": "GPU의 성능"}, {"id": "C", "text": "메모리 속도"}, {"id": "D", "text": "프로그래밍 언어의 종류"}]', '["A", "B", "C"]', '암달의 법칙, GPU의 성능, 메모리 속도는 모두 병렬 처리의 성능 향상에 영향을 미치는 요소이다.'),
    (6584, 22, 3, 10, 'SIMD의 의미는 무엇인가?', 'SHORT_ANSWER', NULL, '단일 명령 다중 데이터', 'SIMD는 단일 명령어가 여러 데이터에 동시에 적용되는 아키텍처를 의미한다.'),
    (6585, 22, 3, 11, '귀납법의 주 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '일반화된 결과를 증명하기 위함', '귀납법은 특정 사례를 바탕으로 일반적인 주장을 증명하는 방법입니다.'),
    (6586, 22, 3, 12, '오토마타 이론에서 주로 다루는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정규 언어"}, {"id": "B", "text": "부울 대수"}, {"id": "C", "text": "그래프 이론"}, {"id": "D", "text": "집합 이론"}]', 'A', '오토마타 이론은 정규 언어와 관련된 계산 모델을 연구합니다.'),
    (6587, 22, 3, 13, '부울 대수에서 사용되는 기본 연산은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AND, OR, NOT"}, {"id": "B", "text": "SUM, PRODUCT, DIFFERENCE"}, {"id": "C", "text": "MAX, MIN, AVERAGE"}, {"id": "D", "text": "DIVIDE, MULTIPLY, ADD"}]', 'A', '부울 대수에서는 AND, OR, NOT 연산이 기본적으로 사용됩니다.'),
    (6588, 22, 3, 14, '다음 중 관계 이론의 요소가 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "튜플"}, {"id": "B", "text": "서브셋"}, {"id": "C", "text": "관계"}, {"id": "D", "text": "속성"}]', '["B", "D"]', '관계 이론에서는 튜플과 관계가 기본 요소입니다. 서브셋과 속성은 이론과 관련이 있지만 직접적인 요소는 아닙니다.'),
    (6589, 22, 3, 15, '점화식은 주로 어떤 상황에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "재귀적 문제 해결"}, {"id": "B", "text": "정렬 알고리즘"}, {"id": "C", "text": "다익스트라 알고리즘"}, {"id": "D", "text": "동적 프로그래밍"}]', 'A', '점화식은 재귀적 문제 해결에서 주로 사용됩니다.'),
    (6590, 22, 3, 16, '암달의 법칙이 설명하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "병렬 처리 성능의 한계"}, {"id": "B", "text": "메모리 모델의 설계"}, {"id": "C", "text": "캐시 일관성 유지 방법"}, {"id": "D", "text": "원자적 연산의 중요성"}]', 'A', '암달의 법칙은 병렬 처리 가능한 작업의 비율에 따라 전체 성능의 한계를 설명합니다.'),
    (6591, 22, 3, 17, 'MESI 프로토콜의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 암호화"}, {"id": "B", "text": "캐시 일관성 유지"}, {"id": "C", "text": "프로세서의 전력 관리"}, {"id": "D", "text": "병렬 처리의 최적화"}]', 'B', 'MESI 프로토콜은 멀티코어 아키텍처에서 캐시 일관성을 유지하기 위한 방법입니다.'),
    (6592, 22, 3, 18, '구스타프슨의 법칙은 어떤 경우에 적용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "작업량이 일정한 경우"}, {"id": "B", "text": "작업 크기가 증가하는 경우"}, {"id": "C", "text": "하드웨어 성능이 제한된 경우"}, {"id": "D", "text": "네트워크 대역폭이 제한된 경우"}]', 'B', '구스타프슨의 법칙은 문제 크기가 증가함에 따라 병렬 처리의 이점이 커진다는 것을 나타냅니다.'),
    (6593, 22, 3, 19, '병렬 처리 시스템에서 원자적 연산의 필요성은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 일관성 보장"}, {"id": "B", "text": "성능 저하 방지"}, {"id": "C", "text": "메모리 사용 최적화"}, {"id": "D", "text": "작업 분배 최적화"}]', '["A", "B"]', '원자적 연산은 병렬 처리 시스템에서 데이터의 일관성을 보장하고 성능 저하를 방지하는 데 필요합니다.'),
    (6594, 22, 3, 20, '병렬 처리와 멀티코어 아키텍처의 관계는 무엇인가?', 'SHORT_ANSWER', NULL, '병렬 처리는 멀티코어 아키텍처에서 여러 코어가 동시에 작업을 처리하여 성능을 향상시키는 기술이다.', ''),
    (6595, 22, 3, 21, '점화식이란 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "재귀적으로 정의된 수열"}, {"id": "B", "text": "단일한 숫자"}, {"id": "C", "text": "무작위 수의 나열"}, {"id": "D", "text": "어떤 연산의 결과"}]', 'A', '점화식은 재귀적으로 정의된 수열로, 이전 항의 값을 이용해 새로운 항을 정의합니다.'),
    (6596, 22, 3, 22, '귀납법의 사용 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "기본 단계와 귀납 단계"}, {"id": "B", "text": "무작위 샘플링"}, {"id": "C", "text": "비교 분석"}, {"id": "D", "text": "임의의 선택"}]', 'A', '귀납법은 기본 단계와 귀납 단계를 통해 일반화된 주장을 증명하는 방법입니다.'),
    (6597, 22, 3, 23, '다음 중 조합론에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "순열"}, {"id": "B", "text": "집합의 선택"}, {"id": "C", "text": "순차적 반복"}, {"id": "D", "text": "조합"}]', 'C', '순차적 반복은 조합론의 개념이 아니라 알고리즘의 반복 구조와 관련이 있습니다.'),
    (6598, 22, 3, 24, '명제 논리에서 사용하는 기본적인 명제의 유형은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "참 명제"}, {"id": "B", "text": "거짓 명제"}, {"id": "C", "text": "조건 명제"}, {"id": "D", "text": "복합 명제"}]', '["A", "B", "C", "D"]', '명제 논리에서는 참 명제, 거짓 명제, 조건 명제, 복합 명제 등 다양한 유형의 명제를 사용합니다.'),
    (6599, 22, 3, 25, '트리의 가장 중요한 특징은 무엇인가?', 'SHORT_ANSWER', NULL, '비순환적이며 연결된 계층 구조', '트리는 비순환적이며 연결된 계층 구조로, 노드와 간선으로 구성되어 있습니다.'),
    (6600, 22, 3, 26, '병렬 처리의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "처리 속도 향상"}, {"id": "B", "text": "메모리 용량 증가"}, {"id": "C", "text": "하드웨어 비용 절감"}, {"id": "D", "text": "소프트웨어 호환성 강화"}]', 'A', '병렬 처리의 주된 목적은 여러 계산을 동시에 수행하여 처리 속도를 향상시키는 것입니다.'),
    (6601, 22, 3, 27, 'CUDA는 어떤 용도로 사용되는 기술인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "일반적인 프로그래밍 언어"}, {"id": "B", "text": "GPU를 활용한 병렬 컴퓨팅"}, {"id": "C", "text": "웹 개발 프레임워크"}, {"id": "D", "text": "데이터베이스 관리 시스템"}]', 'B', 'CUDA는 NVIDIA에서 개발한 GPU를 활용한 병렬 컴퓨팅 플랫폼입니다.'),
    (6602, 22, 3, 28, '다음 중 병렬 알고리즘의 특징이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동시에 여러 작업 수행"}, {"id": "B", "text": "단일 처리 방식"}, {"id": "C", "text": "작업 분할 가능성"}, {"id": "D", "text": "속도 향상"}]', 'B', '병렬 알고리즘의 특징은 동시에 여러 작업을 수행하고 속도를 향상시키는 것입니다. 단일 처리 방식은 병렬 알고리즘의 특징이 아닙니다.'),
    (6603, 22, 3, 29, '동기화가 필요한 이유는 무엇인가? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 충돌 방지"}, {"id": "B", "text": "처리 속도 향상"}, {"id": "C", "text": "상태 일관성 유지"}, {"id": "D", "text": "메모리 사용 최적화"}]', '["A", "C"]', '동기화는 데이터 충돌을 방지하고 여러 프로세스의 상태를 일관되게 유지하기 위해 필요합니다.'),
    (6604, 22, 3, 30, 'MESI 프로토콜의 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '캐시 일관성 유지', 'MESI 프로토콜은 멀티코어 시스템에서 캐시의 일관성을 유지하기 위한 프로토콜입니다.'),
    (6605, 22, 3, 31, '명제 논리에서 ''명제''란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '참 또는 거짓으로 평가할 수 있는 문장', '명제는 참 또는 거짓의 값을 가질 수 있는 문장을 의미합니다.'),
    (6606, 22, 3, 32, '다음 중 순열의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서로 다른 원소들의 나열"}, {"id": "B", "text": "서로 다른 원소의 집합"}, {"id": "C", "text": "원소의 선택"}, {"id": "D", "text": "원소의 교환"}]', 'A', '순열은 서로 다른 원소들을 특정한 순서로 나열한 것을 의미합니다.'),
    (6607, 22, 3, 33, '증명 기법 중 귀류법의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "주장을 반대하는 상황을 가정하여 모순을 찾는 방법"}, {"id": "B", "text": "직접적으로 주장을 증명하는 방법"}, {"id": "C", "text": "경우를 나누어 증명하는 방법"}, {"id": "D", "text": "수학적 귀납법을 사용하는 방법"}]', 'A', '귀류법은 주장을 반대하는 가정을 통해 모순을 찾아 주장을 증명하는 방법입니다.'),
    (6608, 22, 3, 34, '신장 트리의 성질로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "모든 정점을 포함한다."}, {"id": "B", "text": "사이클을 포함한다."}, {"id": "C", "text": "가장 낮은 가중치를 가진 간선들로 구성된다."}, {"id": "D", "text": "정점과 간선의 수는 각각 n-1, n이다."}]', '["A", "D"]', '신장 트리는 모든 정점을 포함하고, 정점의 수가 n일 때 간선의 수는 n-1입니다.'),
    (6609, 22, 3, 35, '신장 트리에서 사용되는 알고리즘이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Kruskal 알고리즘"}, {"id": "B", "text": "Dijkstra 알고리즘"}, {"id": "C", "text": "Prim 알고리즘"}, {"id": "D", "text": "Boruvka 알고리즘"}]', 'B', 'Dijkstra 알고리즘은 최단 경로를 찾는 알고리즘이며, 신장 트리와는 관련이 없습니다.'),
    (6610, 22, 3, 36, '정규 언어의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유한 상태 기계로 표현 가능"}, {"id": "B", "text": "문법적으로 잘 정의됨"}, {"id": "C", "text": "모든 언어를 포함함"}, {"id": "D", "text": "정규 표현식으로 기술 가능"}]', 'C', '정규 언어는 모든 언어를 포함하지 않으며, 특정 패턴에 맞는 언어만 포함합니다.'),
    (6611, 22, 3, 37, '점화식에서 일반적으로 사용되는 기법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "귀류법"}, {"id": "B", "text": "유도법"}, {"id": "C", "text": "정수 분해"}, {"id": "D", "text": "순열 생성"}]', 'B', '점화식은 종종 유도법을 사용하여 일반 항을 도출하는 데 도움을 줍니다.'),
    (6612, 22, 3, 38, '다음 중 조합에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "순서에 상관없이 선택한다."}, {"id": "B", "text": "중복을 허용한다."}, {"id": "C", "text": "nCr로 표현된다."}, {"id": "D", "text": "최대 n개를 선택할 수 있다."}]', '["A", "C"]', '조합은 순서에 상관없이 선택하며, nCr로 표현됩니다.'),
    (6613, 22, 3, 39, '부울 대수가 주로 사용되는 분야는?', 'SHORT_ANSWER', NULL, '논리 회로 설계', '부울 대수는 논리 회로 설계에 필수적으로 사용되는 수학적 구조입니다.'),
    (6614, 22, 3, 40, '함수의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '입력에 대해 정확히 하나의 출력을 매핑하는 관계', '함수는 주어진 입력에 대해 유일한 출력을 생성하는 규칙을 정의합니다.'),
    (6615, 22, 3, 41, '비둘기집 원리에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "n개의 비둘기를 m개의 집에 넣으면, n > m일 때 적어도 하나의 집에 두 마리 이상 들어간다."}, {"id": "B", "text": "모든 비둘기는 반드시 다른 집에 들어가야 한다."}, {"id": "C", "text": "비둘기집은 집합의 다른 원소들로 구성된다."}, {"id": "D", "text": "비둘기집 원리는 조합과는 무관하다."}]', 'A', '비둘기집 원리는 n개의 항목이 m개의 집에 분배될 때, 항목 수가 집 수보다 많을 경우 적어도 하나의 집에 두 개 이상의 항목이 있어야 함을 설명합니다.'),
    (6616, 22, 3, 42, '신장 트리를 구성하는 그래프의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사이클이 존재해야 한다."}, {"id": "B", "text": "모든 정점이 연결되어 있지만 사이클이 없어야 한다."}, {"id": "C", "text": "정점이 연결되지 않아야 한다."}, {"id": "D", "text": "정점 수보다 간선 수가 많아야 한다."}]', 'B', '신장 트리는 모든 정점이 연결되어 있으면서도 사이클이 없는 트리 구조입니다.'),
    (6617, 22, 3, 43, '명제 논리에 속하는 개념은 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "명제"}, {"id": "B", "text": "조건문"}, {"id": "C", "text": "함수"}, {"id": "D", "text": "부정"}]', '["A", "B", "D"]', '명제 논리는 명제, 조건문, 부정과 같은 개념들을 다루며, 이들은 진리값을 기반으로 합니다.'),
    (6618, 22, 3, 44, '병렬 처리란 무엇인가?', 'SHORT_ANSWER', NULL, '여러 개의 연산을 동시에 수행하는 방법', '병렬 처리는 작업을 여러 개로 나누어 동시에 수행하여 처리 속도를 향상시키는 방법입니다.'),
    (6619, 22, 3, 45, '다음 중 캐시 일관성 문제를 해결하기 위한 기술은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 모델"}, {"id": "B", "text": "하이퍼스레딩"}, {"id": "C", "text": "동기화"}, {"id": "D", "text": "원자적 연산"}]', 'C', '캐시 일관성 문제를 해결하기 위해 동기화 기술이 필요합니다.'),
    (6620, 22, 3, 46, '하이퍼스레딩의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "싱글 스레드 성능 향상"}, {"id": "B", "text": "멀티코어 기술 적용"}, {"id": "C", "text": "병렬 처리 성능 향상"}, {"id": "D", "text": "메모리 용량 증가"}]', 'C', '하이퍼스레딩은 하나의 코어에서 다수의 스레드를 실행하여 병렬 처리 성능을 향상시키는 기술입니다.'),
    (6621, 22, 3, 47, '다음 중 병렬 처리에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "여러 코어를 활용한다."}, {"id": "B", "text": "작업을 동시에 실행한다."}, {"id": "C", "text": "데이터 무결성을 항상 보장한다."}, {"id": "D", "text": "성능을 향상시킨다."}]', '["A", "B", "D"]', '병렬 처리는 여러 코어를 활용하여 작업을 동시에 실행하고 성능을 향상시킵니다. 그러나 데이터 무결성을 항상 보장하지는 않습니다.'),
    (6622, 22, 3, 48, '병렬 처리를 통해 얻는 주된 이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성능 향상"}, {"id": "B", "text": "데이터 보안 강화"}, {"id": "C", "text": "에너지 소비 감소"}, {"id": "D", "text": "소프트웨어 호환성 증가"}]', 'A', '병렬 처리는 여러 작업을 동시에 수행함으로써 성능을 향상시킵니다.'),
    (6623, 22, 3, 49, '캐시 일관성 문제를 해결하는 방법 중 하나는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 복제"}, {"id": "B", "text": "메시지 전달"}, {"id": "C", "text": "하드웨어 캐시 관리"}, {"id": "D", "text": "소프트웨어 최적화"}]', 'C', '하드웨어 캐시 관리 기술을 통해 캐시 일관성 문제를 해결할 수 있습니다.'),
    (6624, 22, 3, 50, '구스타프슨의 법칙은 어떤 상황을 설명하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로그램의 스케일링"}, {"id": "B", "text": "하드웨어 비용"}, {"id": "C", "text": "메모리 접근 시간"}, {"id": "D", "text": "데이터 전송 속도"}]', 'A', '구스타프슨의 법칙은 병렬 처리가 프로그램의 실행 시간을 스케일링하는 방식에 대해 설명합니다.'),
    (6625, 22, 3, 51, '다음 중 GPGPU의 장점으로 올바른 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "대량의 데이터 처리"}, {"id": "B", "text": "저렴한 비용"}, {"id": "C", "text": "높은 전력 소비"}, {"id": "D", "text": "복잡한 알고리즘 처리"}]', '["A", "B"]', 'GPGPU는 대량의 데이터 처리와 저렴한 비용으로 높은 성능을 제공합니다.'),
    (6626, 22, 3, 52, '하이퍼스레딩의 주요 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '하나의 코어에서 두 개의 쓰레드를 동시에 처리', ''),
    (6627, 22, 3, 53, '그래프 색칠 문제에서 인접한 정점이 같은 색으로 칠해지는 것을 허용하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "허용되지 않는다"}, {"id": "B", "text": "허용된다"}, {"id": "C", "text": "상관없다"}, {"id": "D", "text": "조건에 따라 다르다"}]', 'A', '그래프 색칠 문제에서는 인접한 정점이 같은 색으로 칠해지는 것을 허용하지 않습니다.'),
    (6628, 22, 3, 54, '오일러 경로란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점을 한 번씩 방문하는 경로"}, {"id": "B", "text": "모든 간선을 한 번씩 방문하는 경로"}, {"id": "C", "text": "시작점과 끝점이 같은 경로"}, {"id": "D", "text": "정점과 간선을 모두 방문하는 경로"}]', 'B', '오일러 경로는 그래프의 모든 간선을 한 번씩만 지나면서 시작점과 끝점이 같을 필요가 없습니다.'),
    (6629, 22, 3, 55, '이항 정리는 주로 어떤 분야에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "선형 대수"}, {"id": "B", "text": "조합론"}, {"id": "C", "text": "미적분학"}, {"id": "D", "text": "확률론"}]', 'B', '이항 정리는 주로 조합론에서 사용됩니다.'),
    (6630, 22, 3, 56, '점화식의 일반적인 활용 방법은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "수열의 항을 구하기 위해"}, {"id": "B", "text": "복잡도 분석을 위해"}, {"id": "C", "text": "함수의 미분을 위해"}, {"id": "D", "text": "문제 해결 접근 방식을 찾기 위해"}]', '["A", "D"]', '점화식은 주로 수열의 항을 구하거나 문제 해결 접근 방식을 찾기 위해 활용됩니다.'),
    (6631, 22, 3, 57, '귀납법의 기본 단계에서 무엇을 증명하는가?', 'SHORT_ANSWER', NULL, '초항이 참임을 증명한다', '귀납법은 초항이 참임을 증명하는 것으로 시작합니다.'),
    (6632, 22, 3, 58, '명제 논리에서 참과 거짓의 진리값을 다루는 주체는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명제"}, {"id": "B", "text": "관계"}, {"id": "C", "text": "변수"}, {"id": "D", "text": "함수"}]', 'A', '명제는 참 또는 거짓을 판단할 수 있는 문장입니다.'),
    (6633, 22, 3, 59, '해밀턴 경로가 의미하는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 정점을 한 번만 방문하는 경로"}, {"id": "B", "text": "모든 변을 한 번만 방문하는 경로"}, {"id": "C", "text": "반복적인 경로"}, {"id": "D", "text": "상관없는 경로"}]', 'A', '해밀턴 경로는 그래프에서 모든 정점을 한 번씩만 방문하는 경로입니다.'),
    (6634, 22, 3, 60, '이항 정리는 무엇을 구하는 데 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "수열의 합"}, {"id": "B", "text": "이항식의 계수"}, {"id": "C", "text": "함수의 극값"}, {"id": "D", "text": "확률의 평균"}]', 'B', '이항 정리는 이항식의 특정 항의 계수를 계산하는 데 사용됩니다.'),
    (6635, 22, 3, 61, '비둘기집 원리에 대한 설명으로 옳지 않은 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "자원 배분 문제를 설명한다."}, {"id": "B", "text": "최소 2개의 비둘기가 같은 집에 들어간다."}, {"id": "C", "text": "모든 비둘기는 다른 집에 들어갈 수 있다."}, {"id": "D", "text": "집의 수가 비둘기 수보다 적을 때 적용된다."}]', '["C"]', '비둘기집 원리는 집의 수가 비둘기 수보다 적을 때, 최소 2개의 비둘기가 같은 집에 들어가야 함을 의미합니다.'),
    (6636, 22, 3, 62, '트리의 정의는 무엇인가요?', 'SHORT_ANSWER', NULL, '사이클이 없는 연결 그래프', '트리는 사이클이 없는 연결 그래프로, 데이터 구조에서 계층적 관계를 나타내는 데 사용됩니다.'),
    (6637, 22, 3, 63, '하이퍼스레딩 기술의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "하나의 코어에서 여러 스레드를 동시에 처리하기 위함"}, {"id": "B", "text": "메모리 용량을 증가시키기 위함"}, {"id": "C", "text": "CPU의 클럭 속도를 증가시키기 위함"}, {"id": "D", "text": "소프트웨어 버그를 수정하기 위함"}]', 'A', '하이퍼스레딩은 하나의 물리적 코어에서 두 개의 논리적 코어처럼 작동하여, 여러 스레드를 동시에 처리하는 기술입니다.'),
    (6638, 22, 3, 64, 'MESI 프로토콜의 주된 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "캐시 데이터의 일관성을 유지하기 위함"}, {"id": "B", "text": "프로세서 간의 통신을 강화하기 위함"}, {"id": "C", "text": "메모리 속도를 증가시키기 위함"}, {"id": "D", "text": "동적 메모리 할당을 관리하기 위함"}]', 'A', 'MESI 프로토콜은 여러 코어 간의 캐시 데이터 일관성을 관리하여, 데이터 충돌을 방지합니다.'),
    (6639, 22, 3, 65, '병렬 처리 성능의 한계를 설명하는 법칙은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "암달의 법칙"}, {"id": "B", "text": "구스타프슨의 법칙"}, {"id": "C", "text": "테일러의 법칙"}, {"id": "D", "text": "모스의 법칙"}]', 'A', '암달의 법칙은 프로그램의 일부분만을 병렬 처리할 수 있는 경우 성능 향상의 한계를 설명합니다.'),
    (6640, 22, 3, 66, '병렬 처리에서 원자적 연산의 중요한 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 경쟁을 방지한다"}, {"id": "B", "text": "프로세서 간의 메시징 속도를 높인다"}, {"id": "C", "text": "스레드의 실행 순서를 보장한다"}, {"id": "D", "text": "자원 접근의 안전성을 보장한다"}]', '["A", "D"]', '원자적 연산은 여러 스레드가 동시에 접근할 때 데이터 무결성을 유지하고, 동시성 문제를 방지하는 데 도움이 됩니다.'),
    (6641, 22, 3, 67, 'SIMD의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, 'Single Instruction, Multiple Data', 'SIMD는 단일 명령어로 여러 데이터 요소를 동시에 처리하는 아키텍처를 의미합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- Linux > 기본 명령어 (75문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (6642, 23, 1, 1, '`mv` 명령어의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일이나 디렉토리의 이동 및 이름 변경"}, {"id": "B", "text": "파일 내용을 출력"}, {"id": "C", "text": "특정 조건의 파일 검색"}, {"id": "D", "text": "디스크 사용량 확인"}]', 'A', '`mv` 명령어는 파일이나 디렉토리의 위치를 변경하거나 이름을 바꾸는 데 사용됩니다.'),
    (6643, 23, 1, 2, '`cat` 명령어는 어떤 기능을 수행하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일의 내용을 출력"}, {"id": "B", "text": "디렉토리 이동"}, {"id": "C", "text": "압축 해제"}, {"id": "D", "text": "사용자 관리"}]', 'A', '`cat` 명령어는 파일의 내용을 터미널에 출력하는 기능을 수행합니다.'),
    (6644, 23, 1, 3, '다음 중 `find` 명령어의 기능에 해당하지 않는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "특정 파일 검색"}, {"id": "B", "text": "파일 내용 출력"}, {"id": "C", "text": "파일 삭제"}, {"id": "D", "text": "파일 속성 변경"}]', 'B', '`find` 명령어는 파일을 검색하는 데 사용되며, 파일 내용을 출력하는 것은 `cat` 명령어의 기능입니다.'),
    (6645, 23, 1, 4, '리눅스에서 다음과 같은 명령어를 쓴 결과로 올바른 것은? (명령어: du)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "디스크 사용량 보여줌"}, {"id": "B", "text": "사용자 계정 관리"}, {"id": "C", "text": "파일 목록 출력"}, {"id": "D", "text": "현재 경로 확인"}]', '["A"]', '`du` 명령어는 디스크 사용량을 보여주는 기능을 합니다.'),
    (6646, 23, 1, 5, '현재 작업 중인 디렉토리의 경로를 확인하는 리눅스 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'pwd', '`pwd` 명령어는 현재 작업 중인 디렉토리의 경로를 출력합니다.'),
    (6647, 23, 1, 6, '리눅스에서 특정 문자열을 포함하는 파일을 찾기 위해 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "grep"}, {"id": "B", "text": "find"}, {"id": "C", "text": "locate"}, {"id": "D", "text": "search"}]', 'A', '''grep'' 명령어는 파일 내에서 특정 문자열을 검색하는 데 사용됩니다.'),
    (6648, 23, 1, 7, '실시간으로 시스템의 CPU 사용량과 프로세스를 모니터링하기 위한 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "top"}, {"id": "B", "text": "htop"}, {"id": "C", "text": "ps"}, {"id": "D", "text": "free"}]', 'A', '''top'' 명령어는 실시간으로 시스템의 프로세스와 리소스 사용량을 보여줍니다.'),
    (6649, 23, 1, 8, '다음 중 파일을 삭제하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "rm"}, {"id": "B", "text": "del"}, {"id": "C", "text": "remove"}, {"id": "D", "text": "erase"}]', 'A', '''rm'' 명령어는 파일 또는 디렉토리를 삭제하는 데 사용됩니다.'),
    (6650, 23, 1, 9, '다음 중 여러 개의 URL에서 파일을 다운로드하기 위한 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "curl"}, {"id": "B", "text": "wget"}, {"id": "C", "text": "ftp"}, {"id": "D", "text": "scp"}]', '["A", "B"]', '''curl''과 ''wget'' 모두 URL에서 파일을 다운로드하는 데 사용됩니다.'),
    (6651, 23, 1, 10, '리눅스에서 현재 디렉토리를 변경하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'cd', '''cd'' 명령어는 현재 작업 중인 디렉토리를 변경하는 데 사용됩니다.'),
    (6652, 23, 1, 11, 'find 명령어의 주된 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일이나 디렉터리 검색"}, {"id": "B", "text": "파일 압축"}, {"id": "C", "text": "원격 서버 접속"}, {"id": "D", "text": "디스크 사용량 확인"}]', 'A', 'find 명령어는 파일이나 디렉터리를 검색하는 데 사용됩니다.'),
    (6653, 23, 1, 12, '다음 중 ssh의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 전송"}, {"id": "B", "text": "원격 접속 및 실행"}, {"id": "C", "text": "디스크 사용량 확인"}, {"id": "D", "text": "파일 압축"}]', 'B', 'ssh는 안전한 원격 접속 및 실행을 위한 프로토콜입니다.'),
    (6654, 23, 1, 13, 'pwd 명령어는 어떤 정보를 제공합니다?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉터리의 경로"}, {"id": "B", "text": "파일 압축 상태"}, {"id": "C", "text": "디스크 사용량"}, {"id": "D", "text": "파일 소유자 정보"}]', 'A', 'pwd 명령어는 현재 작업 중인 디렉터리의 경로를 출력합니다.'),
    (6655, 23, 1, 14, '다음 중 chown와 zip 명령어의 기능을 올바르게 짝짓기', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "파일 소유자를 변경한다."}, {"id": "B", "text": "파일을 압축한다."}, {"id": "C", "text": "디스크 사용량을 확인한다."}, {"id": "D", "text": "특정 파일을 검색한다."}]', '["A", "B"]', 'chown은 파일 소유자를 변경하는 명령어이고, zip은 파일을 압축하는 명령어입니다.'),
    (6656, 23, 1, 15, 'df 명령어란 무엇인가요?', 'SHORT_ANSWER', NULL, '디스크의 사용량과 여유 공간을 확인하는 명령어', ''),
    (6657, 23, 1, 16, 'SSH는 무엇을 위한 프로토콜인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "안전한 원격 접속"}, {"id": "B", "text": "파일 압축"}, {"id": "C", "text": "디스크 공간 확인"}, {"id": "D", "text": "웹사이트 다운로드"}]', 'A', 'SSH는 Secure Shell의 약자로, 안전한 원격 접속을 위해 사용되는 프로토콜입니다.'),
    (6658, 23, 1, 17, 'TAR 명령어의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 다운로드"}, {"id": "B", "text": "파일 압축 및 해제"}, {"id": "C", "text": "프로세스 종료"}, {"id": "D", "text": "디스크 사용량 확인"}]', 'B', 'TAR는 여러 파일을 하나의 파일로 묶거나 해제하는 데 사용되는 명령어입니다.'),
    (6659, 23, 1, 18, '다음 중 파일을 복사하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "mv"}, {"id": "B", "text": "cp"}, {"id": "C", "text": "rm"}, {"id": "D", "text": "cat"}]', 'B', 'CP 명령어는 파일을 복사하는 데 사용됩니다.'),
    (6660, 23, 1, 19, '다음 중 DF와 CURL의 공통점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 전송 관련 명령어"}, {"id": "B", "text": "디스크 공간 관련 명령어"}, {"id": "C", "text": "파일 다운로드"}, {"id": "D", "text": "네트워크 사용"}]', '["A", "C"]', 'DF는 디스크 공간을 확인하고, CURL은 데이터를 전송하거나 다운로드할 수 있는 명령어입니다.'),
    (6661, 23, 1, 20, '리눅스에서 프로세스를 종료하려면 어떤 명령어를 사용해야 하는가?', 'SHORT_ANSWER', NULL, 'kill', 'KILL 명령어를 사용해 프로세스를 종료할 수 있습니다.'),
    (6662, 23, 1, 21, '리눅스에서 파일을 복사하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "cp"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "rm"}, {"id": "D", "text": "ls"}]', 'A', 'cp는 파일을 복사하는 명령어입니다.'),
    (6663, 23, 1, 22, '파일의 내용을 출력할 때 사용하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "cat"}, {"id": "B", "text": "echo"}, {"id": "C", "text": "nano"}, {"id": "D", "text": "head"}]', 'A', 'cat은 파일의 내용을 화면에 출력하는 명령어입니다.'),
    (6664, 23, 1, 23, '현재 디렉토리의 경로를 확인하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "pwd"}, {"id": "B", "text": "cd"}, {"id": "C", "text": "ls"}, {"id": "D", "text": "find"}]', 'A', 'pwd는 현재 작업 디렉토리의 경로를 보여주는 명령어입니다.'),
    (6665, 23, 1, 24, '다음 중 파일 다운로드에 사용되는 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "wget"}, {"id": "B", "text": "curl"}, {"id": "C", "text": "scp"}, {"id": "D", "text": "tar"}]', '["A", "B"]', 'wget과 curl은 모두 파일 다운로드에 사용되는 명령어입니다.'),
    (6666, 23, 1, 25, '시스템에서 현재 실행 중인 프로세스를 확인하는 명령어는?', 'SHORT_ANSWER', NULL, 'ps', 'ps는 현재 실행 중인 프로세스의 정보를 보여주는 명령어입니다.'),
    (6667, 23, 1, 26, '어떤 명령어로 파일의 소유자를 변경할 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "chown"}, {"id": "B", "text": "chmod"}, {"id": "C", "text": "zip"}, {"id": "D", "text": "find"}]', 'A', 'chown 명령어는 파일이나 디렉토리의 소유자를 변경하는 데 사용됩니다.'),
    (6668, 23, 1, 27, '시스템의 현재 디스크 사용량을 확인하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "df"}, {"id": "B", "text": "ps"}, {"id": "C", "text": "kill"}, {"id": "D", "text": "cd"}]', 'A', 'df 명령어는 현재 시스템의 디스크 사용량을 확인하는 데 사용됩니다.'),
    (6669, 23, 1, 28, '다음 중 파일을 압축하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "zip"}, {"id": "B", "text": "find"}, {"id": "C", "text": "chown"}, {"id": "D", "text": "chmod"}]', 'A', 'zip 명령어는 파일을 압축하는 데 사용됩니다.'),
    (6670, 23, 1, 29, '다음 중 동시에 여러 프로세스를 종료할 수 있는 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "kill"}, {"id": "B", "text": "cd"}, {"id": "C", "text": "ps"}, {"id": "D", "text": "chmod"}]', '["A", "C"]', 'kill 명령어는 특정 프로세스를 종료하고, ps 명령어는 실행 중인 프로세스를 확인하여 종료할 필요가 있는 프로세스를 찾는 데 사용됩니다.'),
    (6671, 23, 1, 30, '사용자가 특정 디렉토리로 이동하기 위해 사용하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'cd', ''),
    (6672, 23, 1, 31, '`wget` 명령어의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "웹에서 파일 다운로드"}, {"id": "B", "text": "원격 서버 접속"}, {"id": "C", "text": "프로세스 종료"}, {"id": "D", "text": "파일 이동"}]', 'A', '`wget`은 웹에서 파일을 다운로드 하는 데 사용되는 명령어입니다.'),
    (6673, 23, 1, 32, '`ssh` 명령어의 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 압축"}, {"id": "B", "text": "원격 서버에 안전하게 접속"}, {"id": "C", "text": "디스크 사용량 확인"}, {"id": "D", "text": "프로세스 실행"}]', 'B', '`ssh`는 Secure Shell의 줄임말로, 원격 서버에 안전하게 접속하기 위한 명령어입니다.'),
    (6674, 23, 1, 33, '다음 중 `ps` 명령어의 기능에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 실행 중인 프로세스 표시"}, {"id": "B", "text": "프로세스 종료"}, {"id": "C", "text": "프로세스 상태 확인"}, {"id": "D", "text": "프로세스 PID 확인"}]', 'B', '`ps` 명령어는 현재 실행 중인 프로세스를 표시하지만, 프로세스를 종료하는 기능은 없습니다.'),
    (6675, 23, 1, 34, '리눅스에서 `find` 명령어로 검색할 수 있는 항목은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "파일"}, {"id": "B", "text": "디렉토리"}, {"id": "C", "text": "프로세스"}, {"id": "D", "text": "심볼릭 링크"}]', '["A", "B", "D"]', '`find` 명령어는 파일, 디렉토리 및 심볼릭 링크 등을 검색할 수 있습니다.'),
    (6676, 23, 1, 35, '`kill` 명령어로 종료할 수 있는 프로세스는 무엇인가요?', 'SHORT_ANSWER', NULL, '지정한 PID를 가진 프로세스', '`kill` 명령어는 지정한 PID(Process ID)를 가진 프로세스를 종료할 수 있습니다.'),
    (6677, 23, 1, 36, '리눅스에서 디렉토리를 만들기 위해 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "mkdir"}, {"id": "B", "text": "cp"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "ls"}]', 'A', '''mkdir'' 명령어는 새로운 디렉토리를 생성하는 데 사용됩니다.'),
    (6678, 23, 1, 37, '파일의 용량을 확인하는 데 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "du"}, {"id": "B", "text": "df"}, {"id": "C", "text": "ls"}, {"id": "D", "text": "mv"}]', 'A', '''du'' 명령어는 디렉토리의 용량을 확인하는 데 사용됩니다.'),
    (6679, 23, 1, 38, '다음 중 파일을 압축하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "zip"}, {"id": "B", "text": "cp"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "find"}]', 'A', '''zip'' 명령어는 파일을 압축하는 데 사용됩니다.'),
    (6680, 23, 1, 39, '리눅스에서 여러 개의 파일을 복사할 때 사용하는 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "cp"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "zip"}, {"id": "D", "text": "find"}]', '["A"]', '''cp'' 명령어는 파일을 복사하는 데 사용됩니다.'),
    (6681, 23, 1, 40, '리눅스에서 특정 파일을 찾기 위해 사용하는 명령어는?', 'SHORT_ANSWER', NULL, 'find', '''find'' 명령어는 특정 조건에 맞는 파일을 검색하는 데 사용됩니다.'),
    (6682, 23, 1, 41, '''ls'' 명령어의 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉터리의 파일 목록을 보여준다."}, {"id": "B", "text": "디스크 사용량을 확인한다."}, {"id": "C", "text": "파일을 다운로드한다."}, {"id": "D", "text": "파일의 권한을 변경한다."}]', 'A', '''ls'' 명령어는 현재 디렉터리의 파일 목록을 보여주는 기능을 가지고 있습니다.'),
    (6683, 23, 1, 42, '''chmod'' 명령어를 사용하는 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "디스크 사용량을 확인한다."}, {"id": "B", "text": "파일의 권한을 변경한다."}, {"id": "C", "text": "파일을 압축한다."}, {"id": "D", "text": "파일을 삭제한다."}]', 'B', '''chmod'' 명령어는 파일 또는 디렉터리의 권한을 변경하는 데 사용됩니다.'),
    (6684, 23, 1, 43, '''df'' 명령어는 어떤 정보를 제공하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 목록을 출력한다."}, {"id": "B", "text": "현재 디렉터리의 경로를 표시한다."}, {"id": "C", "text": "디스크 사용량을 확인한다."}, {"id": "D", "text": "파일을 다운로드한다."}]', 'C', '''df'' 명령어는 시스템의 디스크 사용량을 확인하는 데 유용한 정보를 제공합니다.'),
    (6685, 23, 1, 44, '다음 중 파일 다운로드에 사용될 수 있는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "wget"}, {"id": "B", "text": "zip"}, {"id": "C", "text": "curl"}, {"id": "D", "text": "rm"}]', '["A", "C"]', '''wget''과 ''curl''은 모두 웹에서 파일을 다운로드하는 데 사용될 수 있는 명령어입니다.'),
    (6686, 23, 1, 45, '현재 작업 중인 디렉터리의 경로를 확인하기 위한 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'pwd', '''pwd'' 명령어는 현재 작업 중인 디렉터리의 경로를 출력합니다.'),
    (6687, 23, 1, 46, '현재 작업 중인 디렉토리의 경로를 출력하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "pwd"}, {"id": "B", "text": "mkdir"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "rm"}]', 'A', 'pwd 명령어는 현재 작업 중인 디렉토리의 경로를 출력합니다.'),
    (6688, 23, 1, 47, '파일을 삭제할 때 사용되는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "mv"}, {"id": "B", "text": "mkdir"}, {"id": "C", "text": "rm"}, {"id": "D", "text": "chown"}]', 'C', 'rm 명령어는 파일이나 디렉토리를 삭제하는 데 사용됩니다.'),
    (6689, 23, 1, 48, '다음 중 파일 소유자를 변경하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "chown"}, {"id": "B", "text": "grep"}, {"id": "C", "text": "find"}, {"id": "D", "text": "scp"}]', 'A', 'chown 명령어는 파일의 소유자를 변경하는 기능을 수행합니다.'),
    (6690, 23, 1, 49, '어떤 명령어를 사용하여 특정 문자열이 포함된 파일을 찾을 수 있는가? (복수정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "grep"}, {"id": "B", "text": "find"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "scp"}]', '["A", "B"]', 'grep과 find 명령어를 사용하여 파일 검색과 특정 문자열 포함 여부를 검사할 수 있습니다.'),
    (6691, 23, 1, 50, '파일을 원격 시스템으로 안전하게 전송하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'scp', 'scp 명령어는 원격 시스템 간에 파일을 안전하게 전송하는 데 사용됩니다.'),
    (6692, 23, 1, 51, '현재 작업 중인 디렉토리의 경로를 출력하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "pwd"}, {"id": "B", "text": "ls"}, {"id": "C", "text": "cd"}, {"id": "D", "text": "mv"}]', 'A', 'pwd 명령어는 현재 작업 중인 디렉토리의 경로를 출력합니다.'),
    (6693, 23, 1, 52, '다음 중 파일 삭제 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "zip"}, {"id": "B", "text": "rm"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "cat"}]', 'B', 'rm 명령어는 파일이나 디렉토리를 삭제하는 데 사용됩니다.'),
    (6694, 23, 1, 53, '파일을 다른 위치로 이동하거나 이름을 변경할 때 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "scp"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "cat"}, {"id": "D", "text": "top"}]', 'B', 'mv 명령어는 파일이나 디렉토리를 이동하거나 이름을 변경하는 데 사용됩니다.'),
    (6695, 23, 1, 54, '다음 중 여러 파일을 하나의 압축 파일로 묶는 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "zip"}, {"id": "B", "text": "scp"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "cat"}]', '["A"]', 'zip 명령어는 여러 파일을 하나의 압축 파일로 묶기 위해 사용됩니다.'),
    (6696, 23, 1, 55, '현재 실행 중인 프로세스를 실시간으로 보여주는 명령어는?', 'SHORT_ANSWER', NULL, 'top', 'top 명령어는 현재 실행 중인 프로세스의 상태를 실시간으로 보여줍니다.'),
    (6697, 23, 1, 56, '현재 디렉토리의 파일과 디렉토리를 나열하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ls"}, {"id": "B", "text": "cp"}, {"id": "C", "text": "tar"}, {"id": "D", "text": "grep"}]', 'A', 'ls 명령어는 현재 디렉토리의 파일과 디렉토리를 나열하는 데 사용됩니다.'),
    (6698, 23, 1, 57, '다음 중 파일의 소유자를 변경하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "chmod"}, {"id": "B", "text": "chown"}, {"id": "C", "text": "kill"}, {"id": "D", "text": "find"}]', 'B', 'chown 명령어는 파일의 소유자를 변경하는 데 사용됩니다.'),
    (6699, 23, 1, 58, '다음 중 특정 문자열을 포함한 텍스트를 검색하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "grep"}, {"id": "B", "text": "tar"}, {"id": "C", "text": "cp"}, {"id": "D", "text": "ls"}]', 'A', 'grep 명령어는 특정 문자열을 포함한 텍스트를 검색하는 데 사용됩니다.'),
    (6700, 23, 1, 59, '다음 중 복수의 파일을 지정하여 복사할 수 있는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "cp"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "tar"}, {"id": "D", "text": "chmod"}]', '["A", "C"]', 'cp 명령어를 사용하여 복수의 파일을 복사할 수 있으며, tar 명령어로 아카이브를 만들면서 여러 파일을 처리할 수도 있습니다.'),
    (6701, 23, 1, 60, '파일의 권한을 변경하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'chmod', 'chmod 명령어는 파일의 권한을 변경하는 데 사용됩니다.'),
    (6702, 23, 1, 61, 'URL에서 데이터를 전송하거나 받아오는 데 어떤 리눅스 명령어를 사용합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "curl"}, {"id": "B", "text": "grep"}, {"id": "C", "text": "ps"}, {"id": "D", "text": "mv"}]', 'A', 'curl은 데이터를 전송하거나 받아오는 기능을 제공하는 명령어입니다.'),
    (6703, 23, 1, 62, '파일 시스템의 사용량을 확인하는 데 사용되는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "df"}, {"id": "B", "text": "pwd"}, {"id": "C", "text": "tar"}, {"id": "D", "text": "kill"}]', 'A', 'df 명령어는 파일 시스템의 디스크 사용량을 보여주는 데 사용됩니다.'),
    (6704, 23, 1, 63, '다음 중 텍스트 파일에서 특정 패턴을 검색하는 데 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "curl"}, {"id": "B", "text": "grep"}, {"id": "C", "text": "mv"}, {"id": "D", "text": "ps"}]', 'B', 'grep은 텍스트 파일 내에서 특정 문자열이나 패턴을 검색하는 데 사용됩니다.'),
    (6705, 23, 1, 64, '리눅스에서 데이터를 압축하기 위해 사용하는 명령어는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "tar"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "df"}, {"id": "D", "text": "kill"}]', '["A"]', 'tar 명령어는 파일을 압축하거나 압축 해제하는 데 사용됩니다.'),
    (6706, 23, 1, 65, '현재 작업 중인 디렉토리를 확인하는 명령어는 무엇입니까?', 'SHORT_ANSWER', NULL, 'pwd', 'pwd 명령어는 현재 작업 중인 디렉토리의 경로를 출력합니다.'),
    (6707, 23, 1, 66, '다음 중 파일 소유자를 변경하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "chown"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "rm"}, {"id": "D", "text": "ps"}]', 'A', 'chown 명령어는 파일이나 디렉토리의 소유자를 변경하는 데 사용됩니다.'),
    (6708, 23, 1, 67, '다음 명령어 중 현재 실행 중인 프로세스를 확인하는 데 사용되는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ps"}, {"id": "B", "text": "cat"}, {"id": "C", "text": "du"}, {"id": "D", "text": "tar"}]', 'A', 'ps 명령어는 현재 실행 중인 프로세스를 목록으로 보여줍니다.'),
    (6709, 23, 1, 68, '파일을 삭제하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "mv"}, {"id": "B", "text": "rm"}, {"id": "C", "text": "scp"}, {"id": "D", "text": "chown"}]', 'B', 'rm 명령어는 파일을 삭제하는 데 사용됩니다.'),
    (6710, 23, 1, 69, '다음 중 원격 서버 간 파일 전송에 사용되는 명령어는 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "scp"}, {"id": "B", "text": "mv"}, {"id": "C", "text": "tar"}, {"id": "D", "text": "cat"}]', '["A"]', 'scp 명령어는 원격 서버 간의 파일을 안전하게 복사하는 데 사용됩니다.'),
    (6711, 23, 1, 70, '디스크 사용량을 확인하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'du', 'du 명령어는 디스크 사용량을 확인하는 데 사용됩니다.'),
    (6712, 23, 1, 71, '`ls` 명령어의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 파일 목록을 보여준다."}, {"id": "B", "text": "파일을 삭제한다."}, {"id": "C", "text": "파일을 다운로드한다."}, {"id": "D", "text": "프로세스를 종료한다."}]', 'A', '`ls` 명령어는 현재 디렉토리 내의 파일과 디렉토리 목록을 보여주는 기능을 가지고 있습니다.'),
    (6713, 23, 1, 72, '`kill` 명령어의 사용 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일을 이동한다."}, {"id": "B", "text": "프로세스를 종료한다."}, {"id": "C", "text": "디렉토리를 생성한다."}, {"id": "D", "text": "파일 목록을 확인한다."}]', 'B', '`kill` 명령어는 지정한 프로세스를 종료하는 데 사용됩니다.'),
    (6714, 23, 1, 73, '다음 중 여러 개의 정답이 가능한 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "`grep`"}, {"id": "B", "text": "`mv`"}, {"id": "C", "text": "`find`"}, {"id": "D", "text": "`mkdir`"}]', '["A", "C"]', '`grep`과 `find`는 모두 특정 문자열이나 파일을 검색하는 데 사용되는 명령어입니다.'),
    (6715, 23, 1, 74, '리눅스에서 새로운 디렉토리를 생성하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'mkdir', '`mkdir` 명령어를 사용하여 새로운 디렉토리를 생성할 수 있습니다.'),
    (6716, 23, 1, 75, '웹에서 파일을 다운로드할 때 사용하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'wget', '`wget` 명령어는 웹에서 파일을 다운로드하는 데 사용됩니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- Linux > 시스템 관리 (85문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (6717, 23, 2, 1, 'systemctl 명령어의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서비스의 관리"}, {"id": "B", "text": "파일 복사"}, {"id": "C", "text": "사용자 계정 관리"}, {"id": "D", "text": "네트워크 설정"}]', 'A', 'systemctl 명령어는 주로 서비스의 시작, 중지, 상태 확인 등을 관리하는 데 사용됩니다.'),
    (6718, 23, 2, 2, 'Linux에서 로그 파일을 조회하기 위해 주로 사용되는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "dmesg"}, {"id": "B", "text": "journalctl"}, {"id": "C", "text": "top"}, {"id": "D", "text": "ps"}]', 'B', 'journalctl 명령어는 시스템 로그를 조회하는 데 사용됩니다.'),
    (6719, 23, 2, 3, 'dnf와 yum의 주 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 리소스 모니터링"}, {"id": "B", "text": "패키지 관리"}, {"id": "C", "text": "방화벽 설정"}, {"id": "D", "text": "데몬 프로세스 실행"}]', 'B', 'dnf와 yum은 패키지를 설치, 업데이트 및 제거하는 패키지 관리 도구입니다.'),
    (6720, 23, 2, 4, '다음 중 Linux에서 프로세스를 모니터링하기 위해 사용할 수 있는 명령어는 무엇인가요? (복수 응답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "top"}, {"id": "B", "text": "systemctl"}, {"id": "C", "text": "ps"}, {"id": "D", "text": "ifconfig"}]', '["A", "C"]', 'top과 ps는 모두 프로세스를 모니터링하고 관리하는 데 유용한 명령어입니다.'),
    (6721, 23, 2, 5, '방화벽을 설정하기 위해 주로 사용하는 도구는 무엇인가요?', 'SHORT_ANSWER', NULL, 'iptables 또는 firewalld', 'iptables 또는 firewalld를 사용하여 Linux 시스템의 방화벽을 설정할 수 있습니다.'),
    (6722, 23, 2, 6, '사용자를 추가하기 위해 사용하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "useradd"}, {"id": "B", "text": "usermod"}, {"id": "C", "text": "userdel"}, {"id": "D", "text": "passwd"}]', 'A', 'useradd 명령어는 새로운 사용자를 생성하는 데 사용됩니다.'),
    (6723, 23, 2, 7, 'systemd의 주된 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패키지 관리"}, {"id": "B", "text": "서비스 관리"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "프로세스 생성"}]', 'B', 'systemd는 주로 Linux 시스템에서 서비스를 시작하고 관리하는 데 사용됩니다.'),
    (6724, 23, 2, 8, '다음 중 Linux의 패키지 관리 도구가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "apt"}, {"id": "B", "text": "yum"}, {"id": "C", "text": "install"}, {"id": "D", "text": "dpkg"}]', 'C', 'install은 패키지 관리 도구가 아니라, 특정 명령어의 일반적인 형태입니다.'),
    (6725, 23, 2, 9, 'Linux에서 프로세스를 관리하는 도구는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "top"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "ps"}, {"id": "D", "text": "yum"}]', '["A", "C"]', 'top과 ps는 모두 프로세스를 모니터링하고 관리하는 도구입니다.'),
    (6726, 23, 2, 10, '데몬이란 무엇인가?', 'SHORT_ANSWER', NULL, '백그라운드에서 실행되는 프로세스', '데몬은 시스템의 서비스 및 작업을 관리하기 위해 백그라운드에서 실행되는 프로세스입니다.'),
    (6727, 23, 2, 11, '사용자 계정을 생성하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'useradd', '''useradd'' 명령어는 새로운 사용자 계정을 생성하는 데 사용됩니다.'),
    (6728, 23, 2, 12, '''ufw''는 무엇의 약자인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Uncomplicated Firewall"}, {"id": "B", "text": "Universal Firewall"}, {"id": "C", "text": "User Firewall"}, {"id": "D", "text": "Unified Firewall"}]', 'A', '''ufw''는 ''Uncomplicated Firewall''의 약자로, 사용자가 간편하게 방화벽을 설정할 수 있도록 돕는 도구입니다.'),
    (6729, 23, 2, 13, '정기적인 작업을 설정하기 위해 사용하는 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "systemctl"}, {"id": "B", "text": "crontab"}, {"id": "C", "text": "dnf"}, {"id": "D", "text": "journalctl"}]', 'B', '''crontab'' 명령어는 사용자가 정기적인 작업을 예약할 수 있도록 해줍니다.'),
    (6730, 23, 2, 14, '다음 중 Linux에서 프로세스 관리에 사용되는 명령어는 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "systemctl"}, {"id": "B", "text": "ps"}, {"id": "C", "text": "journalctl"}, {"id": "D", "text": "top"}]', '["A", "B", "D"]', '시스템 관리에서 ''systemctl'', ''ps'', ''top'' 명령어는 모두 프로세스를 관리하는 데 사용됩니다.'),
    (6731, 23, 2, 15, '''journalctl''의 주요 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '로그 조회', '''journalctl''은 Linux 시스템의 로그를 조회하는 데 사용되는 명령어입니다.'),
    (6732, 23, 2, 16, 'systemctl의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서비스 관리"}, {"id": "B", "text": "패키지 설치"}, {"id": "C", "text": "파일 복사"}, {"id": "D", "text": "사용자 관리"}]', 'A', 'systemctl은 주로 systemd 시스템에서 서비스의 시작, 중지 및 상태를 관리하는 데 사용됩니다.'),
    (6733, 23, 2, 17, 'ufw는 무엇의 약자인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Uncomplicated Firewall"}, {"id": "B", "text": "Utility for Firewall"}, {"id": "C", "text": "Unified Firewall"}, {"id": "D", "text": "Universal Firewall"}]', 'A', 'ufw는 Uncomplicated Firewall의 약자로, 간단하게 방화벽 설정을 할 수 있도록 도와주는 도구입니다.'),
    (6734, 23, 2, 18, '다음 중 crontab의 기능이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정기적인 작업 예약"}, {"id": "B", "text": "시스템 로그 확인"}, {"id": "C", "text": "자동화된 스크립트 실행"}, {"id": "D", "text": "정해진 시간에 명령어 실행"}]', 'B', 'crontab은 정기적으로 작업을 예약하고 실행하는 기능을 제공하지만, 시스템 로그 확인은 다른 도구를 사용해야 합니다.'),
    (6735, 23, 2, 19, 'Linux에서 서비스를 백그라운드에서 실행하기 위한 명령어는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "nohup"}, {"id": "B", "text": "bg"}, {"id": "C", "text": "start"}, {"id": "D", "text": "service"}]', '["A", "B"]', 'nohup과 bg는 모두 명령어를 백그라운드에서 실행할 수 있도록 도와주는 명령어입니다.'),
    (6736, 23, 2, 20, 'Linux에서 패키지 관리를 위한 기본 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'apt 또는 yum', 'apt는 Debian 계열에서, yum은 Red Hat 계열에서 주로 사용되는 패키지 관리 시스템의 명령어입니다.'),
    (6737, 23, 2, 21, 'SELinux의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세스와 자원에 대한 접근 제어"}, {"id": "B", "text": "네트워크 트래픽 모니터링"}, {"id": "C", "text": "디스크 공간 관리"}, {"id": "D", "text": "시스템 로그 관리"}]', 'A', 'SELinux는 프로세스와 자원에 대한 세부적인 접근 제어를 제공하는 보안 모듈입니다.'),
    (6738, 23, 2, 22, 'systemctl 명령어의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패키지 설치"}, {"id": "B", "text": "서비스 관리"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "파일 시스템 검사"}]', 'B', 'systemctl은 systemd 기반의 서비스 및 데몬을 시작, 중지 및 관리하는데 사용됩니다.'),
    (6739, 23, 2, 23, '다음 중 Linux에서 방화벽 설정을 위해 사용할 수 있는 도구는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ufw"}, {"id": "B", "text": "systemctl"}, {"id": "C", "text": "ip a"}, {"id": "D", "text": "ls"}]', 'A', 'ufw는 Linux에서 쉽게 방화벽을 설정하고 관리할 수 있도록 돕는 도구입니다.'),
    (6740, 23, 2, 24, '사용자 관리와 관련하여 시스템에서 한 번에 여러 사용자를 추가할 수 있는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "adduser"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "usermod"}, {"id": "D", "text": "deluser"}]', '["A", "B"]', 'adduser와 useradd 명령어 모두 사용자를 추가하는 데 사용됩니다.'),
    (6741, 23, 2, 25, 'systemd의 주 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '부팅 및 서비스 관리', ''),
    (6742, 23, 2, 26, 'ufw는 무엇을 관리하는 도구인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "방화벽"}, {"id": "B", "text": "패키지 관리"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "서비스 관리"}]', 'A', 'ufw는 Uncomplicated Firewall의 약자로, 방화벽 설정을 간편하게 관리하는 도구입니다.'),
    (6743, 23, 2, 27, 'yum은 어떤 목적에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가상화 관리"}, {"id": "B", "text": "패키지 관리"}, {"id": "C", "text": "네트워크 관리"}, {"id": "D", "text": "서버 모니터링"}]', 'B', 'yum은 Yellowdog Updater Modified의 약자로, 리눅스에서 패키지 설치 및 관리를 위한 도구입니다.'),
    (6744, 23, 2, 28, 'systemd의 주요 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 시스템 관리"}, {"id": "B", "text": "서비스 및 프로세스 관리"}, {"id": "C", "text": "네트워크 설정"}, {"id": "D", "text": "데이터베이스 관리"}]', 'B', 'systemd는 시스템 및 서비스 매니저로서, 리눅스 시스템의 서비스와 프로세스를 관리하는 역할을 합니다.'),
    (6745, 23, 2, 29, 'Linux에서 사용자를 추가하기 위한 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "adduser"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "newuser"}, {"id": "D", "text": "createuser"}]', '["B"]', 'Linux에서 사용자를 추가하기 위해 주로 사용하는 명령어는 useradd입니다.'),
    (6746, 23, 2, 30, '그룹 관리의 중요성은 무엇인가요?', 'SHORT_ANSWER', NULL, '사용자 권한을 효율적으로 관리하고, 관련된 사용자들을 하나의 그룹으로 묶어 쉽게 관리할 수 있게 해줍니다.', '그룹 관리를 통해 사용자 권한을 효율적으로 조정하고, 관리의 복잡성을 줄일 수 있습니다.'),
    (6747, 23, 2, 31, 'SELinux의 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '시스템 보안 강화', 'SELinux는 시스템의 보안을 강화하여 악성 소프트웨어나 비인가된 접근을 차단하는 데 도움을 줍니다.'),
    (6748, 23, 2, 32, 'dnf는 무엇의 약자이며, 주로 무엇에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Dandified YUM, 패키지 관리"}, {"id": "B", "text": "Distributed Network File, 파일 전송"}, {"id": "C", "text": "Dynamic Network Framework, 네트워크 설정"}, {"id": "D", "text": "Do Not Forget, 할 일 관리"}]', 'A', 'dnf는 Dandified YUM의 약자로, 리눅스에서 패키지를 관리하는 데 사용됩니다.'),
    (6749, 23, 2, 33, 'crontab은 무엇을 관리하는 도구인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세스 관리"}, {"id": "B", "text": "주기적 작업 관리"}, {"id": "C", "text": "파일 시스템 관리"}, {"id": "D", "text": "네트워크 모니터링"}]', 'B', 'crontab은 리눅스에서 주기적인 작업을 관리하는 도구입니다.'),
    (6750, 23, 2, 34, 'systemctl 명령어의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "서비스 시작 및 정지"}, {"id": "B", "text": "패키지 설치"}, {"id": "C", "text": "시스템 재부팅"}, {"id": "D", "text": "서비스 상태 확인"}]', '["A", "D"]', 'systemctl 명령어는 서비스의 시작, 정지 및 상태 확인 등 서비스 관리를 위한 명령어입니다.'),
    (6751, 23, 2, 35, '방화벽의 주된 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "디스크 공간 관리"}, {"id": "B", "text": "네트워크 트래픽 제어"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "시스템 업데이트"}]', 'B', '방화벽은 네트워크 트래픽을 제어하여 비인가된 접근을 차단하는 기능을 수행합니다.'),
    (6752, 23, 2, 36, 'systemctl 명령어의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 로그 확인"}, {"id": "B", "text": "서비스 관리"}, {"id": "C", "text": "사용자 추가"}, {"id": "D", "text": "파일 백업"}]', 'B', 'systemctl은 시스템 서비스를 시작, 중지 및 상태를 관리하는 가벼운 명령어입니다.'),
    (6753, 23, 2, 37, 'SELinux의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 전송"}, {"id": "B", "text": "사용자 생성"}, {"id": "C", "text": "접근 제어"}, {"id": "D", "text": "시스템 모니터링"}]', 'C', 'SELinux는 시스템의 보안을 강화하고, 프로세스와 리소스에 대한 접근 제어를 설정하는 기능을 수행합니다.'),
    (6754, 23, 2, 38, 'usermod 명령어는 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 재부팅"}, {"id": "B", "text": "사용자 속성 수정"}, {"id": "C", "text": "프로세스 종료"}, {"id": "D", "text": "네트워크 설정"}]', 'B', 'usermod 명령어는 기존 사용자의 속성을 수정하는 데 사용됩니다.'),
    (6755, 23, 2, 39, '다음 중 사용자 관리에 해당하는 명령어는 무엇인가? (복수선택)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "usermod"}, {"id": "B", "text": "service"}, {"id": "C", "text": "useradd"}, {"id": "D", "text": "systemctl"}]', '["A", "C"]', 'usermod와 useradd는 사용자 계정을 관리하는 명령어입니다.'),
    (6756, 23, 2, 40, 'journalctl을 사용하는 주된 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '시스템 로그를 조회하기 위해서입니다.', 'journalctl은 시스템 로그를 효과적으로 검색하고 필터링하는 도구입니다.'),
    (6757, 23, 2, 41, 'dnf와 apt의 주요 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "dnf는 Red Hat 계열에서, apt는 Debian 계열에서 사용된다."}, {"id": "B", "text": "apt가 더 최신의 패키지 관리 시스템이다."}, {"id": "C", "text": "dnf는 그래픽 사용자 인터페이스를 제공한다."}, {"id": "D", "text": "apt는 RPM 패키지 형식을 사용한다."}]', 'A', 'dnf는 Red Hat 계열인 Fedora와 CentOS에서 사용되며, apt는 Debian 계열인 Ubuntu에서 사용됩니다.'),
    (6758, 23, 2, 42, 'SELinux의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템의 성능을 증가시키기 위해."}, {"id": "B", "text": "사용자 인터페이스를 개선하기 위해."}, {"id": "C", "text": "시스템 보안을 강화하기 위해."}, {"id": "D", "text": "패키지 설치를 자동화하기 위해."}]', 'C', 'SELinux는 시스템 보안을 강화하고 권한을 제어하기 위한 보안 모듈입니다.'),
    (6759, 23, 2, 43, 'systemctl 명령어로 할 수 없는 작업은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서비스 시작"}, {"id": "B", "text": "서비스 중지"}, {"id": "C", "text": "서비스 상태 확인"}, {"id": "D", "text": "시스템 업데이트"}]', 'D', 'systemctl 명령어는 서비스 관리와 관련된 작업을 수행하며, 시스템 업데이트는 dnf 또는 apt를 사용해야 합니다.'),
    (6760, 23, 2, 44, '다음 중 useradd 명령어의 올바른 사용법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "useradd -m newuser"}, {"id": "B", "text": "useradd -d /home newuser"}, {"id": "C", "text": "useradd newuser -s /bin/bash"}, {"id": "D", "text": "useradd newuser --password mypassword"}]', '["A", "C"]', 'useradd -m newuser는 홈 디렉토리를 만들고, useradd newuser -s /bin/bash는 로그인 쉘을 설정합니다.'),
    (6761, 23, 2, 45, 'journalctl 명령어의 주요 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '시스템 로그 조회', 'journalctl은 시스템의 모든 로그를 조회하고 관리하는 데 사용됩니다.'),
    (6762, 23, 2, 46, 'SELinux의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 자원에 대한 접근 제어"}, {"id": "B", "text": "네트워크 속도 향상"}, {"id": "C", "text": "프로세스 모니터링"}, {"id": "D", "text": "하드웨어 성능 최적화"}]', 'A', 'SELinux는 시스템 자원에 대한 접근 제어를 통해 보안을 강화하는 역할을 합니다.'),
    (6763, 23, 2, 47, 'yum과 dnf의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "dnf는 Python3로 작성되었다."}, {"id": "B", "text": "yum은 사용되지 않는 오래된 패키지 관리 도구이다."}, {"id": "C", "text": "dnf는 더 빠르다."}, {"id": "D", "text": "두 도구는 동일한 기능을 한다."}]', 'A', 'dnf는 Python3로 작성되어 있으며, 여러 개선 사항이 포함되어 있습니다.'),
    (6764, 23, 2, 48, 'UFW는 무엇을 위한 도구인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세스 관리"}, {"id": "B", "text": "패키지 설치"}, {"id": "C", "text": "방화벽 설정"}, {"id": "D", "text": "시스템 모니터링"}]', 'C', 'UFW는 방화벽 설정을 쉽게 할 수 있도록 도와주는 도구입니다.'),
    (6765, 23, 2, 49, '다음 중 usermod 명령어의 올바른 사용법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "usermod -aG sudo 사용자명"}, {"id": "B", "text": "usermod -d /newhome 사용자명"}, {"id": "C", "text": "usermod -r 사용자명"}, {"id": "D", "text": "usermod -l 새로운이름 사용자명"}]', '["A", "B", "D"]', 'usermod 명령어는 사용자의 그룹 추가, 홈 디렉토리 변경, 사용자 이름 변경 등에 사용됩니다.'),
    (6766, 23, 2, 50, 'systemctl의 주 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '시스템 및 서비스 관리', 'systemctl은 Linux 시스템에서 서비스 및 시스템 상태를 관리하는 데 사용됩니다.'),
    (6767, 23, 2, 51, '패키지 관리 도구인 dnf의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "소프트웨어 설치 및 업데이트"}, {"id": "B", "text": "사용자 계정 생성"}, {"id": "C", "text": "네트워크 모니터링"}, {"id": "D", "text": "디스크 용량 확인"}]', 'A', 'dnf는 소프트웨어 패키지를 설치하고 업데이트하는 데 사용되는 도구입니다.'),
    (6768, 23, 2, 52, 'systemctl을 사용해 수행할 수 있는 작업이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서비스 시작"}, {"id": "B", "text": "서비스 삭제"}, {"id": "C", "text": "서비스 중지"}, {"id": "D", "text": "서비스 상태 확인"}]', 'B', 'systemctl은 서비스를 시작, 중지 및 상태를 확인하는 명령어지만, 서비스 삭제는 직접적으로 지원하지 않습니다.'),
    (6769, 23, 2, 53, 'iptables에 대해 올바른 설명은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서버의 디스크 사용량을 관리한다."}, {"id": "B", "text": "네트워크 트래픽을 필터링하는 방화벽이다."}, {"id": "C", "text": "소프트웨어 패키지를 설치한다."}, {"id": "D", "text": "사용자 계정을 관리한다."}]', 'B', 'iptables는 네트워크 트래픽을 필터링하여 보안을 강화하는 방화벽 기능을 수행합니다.'),
    (6770, 23, 2, 54, 'Linux에서 백그라운드 작업을 실행하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "nohup"}, {"id": "B", "text": "kill"}, {"id": "C", "text": "bg"}, {"id": "D", "text": "fg"}]', '["A", "C"]', 'nohup은 세션 종료 후에도 프로세스를 계속 실행하고, bg 명령은 이미 중지된 작업을 백그라운드에서 수행하도록 전환합니다.'),
    (6771, 23, 2, 55, '사용자 정보를 수정하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'usermod', 'usermod는 Linux에서 사용자 정보를 수정하기 위해 사용되는 명령어입니다.'),
    (6772, 23, 2, 56, 'crontab의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정기적인 작업 자동화"}, {"id": "B", "text": "사용자 계정 관리"}, {"id": "C", "text": "방화벽 설정"}, {"id": "D", "text": "서비스 모니터링"}]', 'A', 'crontab은 정기적으로 실행해야 하는 작업을 자동화하기 위해 사용됩니다.'),
    (6773, 23, 2, 57, 'SELinux의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 보안 강화"}, {"id": "B", "text": "네트워크 모니터링"}, {"id": "C", "text": "데이터베이스 관리"}, {"id": "D", "text": "파일 압축"}]', 'A', 'SELinux는 시스템의 보안을 강화하기 위한 접근 제어 메커니즘입니다.'),
    (6774, 23, 2, 58, '다음 중 방화벽 설정에 사용되는 도구는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "iptables"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "systemctl"}, {"id": "D", "text": "crontab"}]', 'A', 'iptables는 리눅스에서 방화벽을 설정하고 관리하는 도구입니다.'),
    (6775, 23, 2, 59, '사용자 그룹을 관리할 때 사용할 수 있는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "groupadd"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "usermod"}, {"id": "D", "text": "groupdel"}]', '["A", "C", "D"]', 'groupadd, usermod, groupdel은 모두 그룹을 관리하는 데 사용되는 명령어입니다.'),
    (6776, 23, 2, 60, 'systemctl 명령어의 주 용도는 무엇인가요?', 'SHORT_ANSWER', NULL, '서비스의 시작 및 중지 관리', 'systemctl은 시스템 서비스의 상태를 관리하는 명령어입니다.'),
    (6777, 23, 2, 61, 'systemctl 명령어의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "서비스 관리"}, {"id": "B", "text": "사용자 관리"}, {"id": "C", "text": "파일 시스템 관리"}, {"id": "D", "text": "네트워크 설정"}]', 'A', 'systemctl은 서비스를 시작, 중지, 재시작하는 명령어로, 서비스 관리의 핵심입니다.'),
    (6778, 23, 2, 62, 'usermod 명령어의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사용자 속성 수정"}, {"id": "B", "text": "파일 백업"}, {"id": "C", "text": "서비스 설치"}, {"id": "D", "text": "네트워크 설정"}]', 'A', 'usermod는 기존 사용자의 속성을 수정하는 데 사용됩니다.'),
    (6779, 23, 2, 63, '다음 중 서버에서 백그라운드 작업을 수행하기 위한 프로세스는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데몬"}, {"id": "B", "text": "스크립트"}, {"id": "C", "text": "애플리케이션"}, {"id": "D", "text": "세션"}]', 'A', '데몬 프로세스는 백그라운드에서 실행되는 프로세스를 의미합니다.'),
    (6780, 23, 2, 64, '사용자 그룹 관리를 통해 무엇을 할 수 있는가? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "여러 사용자를 한 번에 관리"}, {"id": "B", "text": "소프트웨어 설치"}, {"id": "C", "text": "접근 권한 설정"}, {"id": "D", "text": "시스템 업데이트"}]', '["A", "C"]', '그룹 관리를 통해 여러 사용자를 효율적으로 관리하고, 접근 권한을 설정할 수 있습니다.'),
    (6781, 23, 2, 65, 'dnf의 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '소프트웨어 패키지 관리 및 설치', 'dnf는 소프트웨어 패키지를 설치하고 관리하는 패키지 관리자입니다.'),
    (6782, 23, 2, 66, '사용자 정보를 수정하기 위해 사용하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "usermod"}, {"id": "B", "text": "useradd"}, {"id": "C", "text": "userdel"}, {"id": "D", "text": "passwd"}]', 'A', 'usermod 명령어는 사용자 정보를 수정하는 데 사용됩니다.'),
    (6783, 23, 2, 67, 'Linux에서 로그를 확인하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "logcat"}, {"id": "B", "text": "journalctl"}, {"id": "C", "text": "syslog"}, {"id": "D", "text": "dmesg"}]', 'B', 'journalctl 명령어는 시스템 로그를 확인하는 데 사용됩니다.'),
    (6784, 23, 2, 68, '다음 중 방화벽을 관리하기 위한 도구가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "iptables"}, {"id": "B", "text": "ufw"}, {"id": "C", "text": "firewalld"}, {"id": "D", "text": "apt"}]', 'D', 'apt는 패키지 관리 도구로, 방화벽 관리 도구가 아닙니다.'),
    (6785, 23, 2, 69, '다음 중 사용자 및 그룹 관리를 위한 명령어들 중 올바른 조합은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "usermod, groupadd"}, {"id": "B", "text": "apt, journalctl"}, {"id": "C", "text": "systemctl, ufw"}, {"id": "D", "text": "userdel, useradd"}]', '["A", "D"]', 'usermod와 groupadd는 사용자 및 그룹 관리를 위한 명령어이며, userdel과 useradd도 사용자 관리와 관련이 있습니다.'),
    (6786, 23, 2, 70, 'systemd에서 서비스를 시작하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'systemctl start [서비스명]', 'systemctl start [서비스명] 명령어를 사용하여 systemd를 통해 서비스를 시작할 수 있습니다.'),
    (6787, 23, 2, 71, 'Linux에서 사용자 계정을 추가하기 위해 사용하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'useradd', 'useradd 명령어는 Linux 시스템에서 새로운 사용자 계정을 생성하는 데 사용됩니다.'),
    (6788, 23, 2, 72, 'Linux에서 방화벽을 설정하기 위해 사용할 수 있는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "firewalld"}, {"id": "B", "text": "iptables"}, {"id": "C", "text": "ufw"}, {"id": "D", "text": "netstat"}]', 'A', 'firewalld는 Linux 시스템에서 방화벽을 관리하기 위한 도구로 널리 사용됩니다.'),
    (6789, 23, 2, 73, '다음 중 Linux에서 패키지 관리를 위해 사용할 수 있는 도구는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "yum"}, {"id": "B", "text": "gcc"}, {"id": "C", "text": "make"}, {"id": "D", "text": "nano"}]', 'A', 'yum은 Red Hat 계열의 Linux 배포판에서 패키지를 설치하고 관리하는 데 사용되는 도구입니다.'),
    (6790, 23, 2, 74, 'SELinux의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "시스템 보안을 강화하기 위해"}, {"id": "B", "text": "사용자 계정을 관리하기 위해"}, {"id": "C", "text": "프로세스를 최적화하기 위해"}, {"id": "D", "text": "네트워크 트래픽을 제어하기 위해"}]', '["A"]', 'SELinux는 시스템 보안을 강화하기 위해 설계된 보안 모듈입니다.'),
    (6791, 23, 2, 75, 'systemd의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세스 관리"}, {"id": "B", "text": "파일 시스템 관리"}, {"id": "C", "text": "네트워크 설정"}, {"id": "D", "text": "사용자 관리"}]', 'A', 'systemd는 프로세스와 서비스를 관리하는 데 주요한 역할을 합니다.'),
    (6792, 23, 2, 76, 'Linux에서 패키지 관리를 위해 주로 사용하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "apt"}, {"id": "B", "text": "yum"}, {"id": "C", "text": "dnf"}, {"id": "D", "text": "pacman"}]', 'A', 'apt는 Ubuntu와 Debian 계열의 리눅스 배포판에서 패키지 관리를 위해 사용되는 명령어입니다.'),
    (6793, 23, 2, 77, 'crontab을 사용하여 설정할 수 있는 작업의 주기는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1초"}, {"id": "B", "text": "1분"}, {"id": "C", "text": "1시간"}, {"id": "D", "text": "모든 주기"}]', 'D', 'crontab은 매 분, 매 시간 등과 같은 다양한 주기로 작업을 예약할 수 있도록 해줍니다.'),
    (6794, 23, 2, 78, 'Linux에서 사용자 계정을 생성하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "useradd"}, {"id": "B", "text": "adduser"}, {"id": "C", "text": "newuser"}, {"id": "D", "text": "createuser"}]', 'A', 'useradd는 새로운 사용자를 시스템에 추가하는 명령어입니다.'),
    (6795, 23, 2, 79, '다음 중 Linux 방화벽 설정에 사용되는 명령어는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "iptables"}, {"id": "B", "text": "ufw"}, {"id": "C", "text": "firewalld"}, {"id": "D", "text": "nftables"}]', '["B", "C"]', 'ufw와 firewalld는 Linux에서 방화벽 설정을 단순화하는 도구입니다.'),
    (6796, 23, 2, 80, '백그라운드에서 프로세스를 실행하려면 어떤 기호를 사용하는가?', 'SHORT_ANSWER', NULL, '&', '프로세스를 백그라운드에서 실행할 때는 명령어 뒤에 ''&'' 기호를 붙여야 합니다.'),
    (6797, 23, 2, 81, 'ufw의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "방화벽 관리"}, {"id": "B", "text": "패키지 설치"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "백그라운드 프로세스 관리"}]', 'A', 'ufw는 Uncomplicated Firewall의 약자로, 리눅스 시스템의 방화벽 설정을 쉽게 관리하기 위한 도구입니다.'),
    (6798, 23, 2, 82, 'dnf는 주로 어떤 작업에 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "패키지 설치 및 관리"}, {"id": "B", "text": "시스템 로그 확인"}, {"id": "C", "text": "네트워크 모니터링"}, {"id": "D", "text": "사용자 추가"}]', 'A', 'dnf는 리눅스 배포판에서 소프트웨어 패키지를 설치, 업데이트, 삭제할 수 있도록 도와주는 패키지 관리 도구입니다.'),
    (6799, 23, 2, 83, 'SELinux는 무엇을 위한 기술인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시스템 보안"}, {"id": "B", "text": "데이터베이스 관리"}, {"id": "C", "text": "웹 서버 관리"}, {"id": "D", "text": "네트워크 설정"}]', 'A', 'SELinux는 Security-Enhanced Linux의 약자로, 리눅스 시스템에서 보안을 강화하기 위한 기술입니다.'),
    (6800, 23, 2, 84, '다음 중 패키지 관리 도구인 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "apt"}, {"id": "B", "text": "ufw"}, {"id": "C", "text": "dnf"}, {"id": "D", "text": "iptables"}]', '["A", "C"]', 'apt와 dnf는 각각 Debian 계열과 Red Hat 계열의 패키지 관리 도구로, 소프트웨어의 설치 및 관리를 도와줍니다.'),
    (6801, 23, 2, 85, '리눅스에서 백그라운드 프로세스를 시작하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'nohup', 'nohup 명령어를 사용하면 백그라운드에서 작업을 계속 실행할 수 있도록 합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- Linux > 셸 스크립트 (219문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (6802, 23, 3, 1, 'Bash 스크립트에서 ''sed'' 명령어의 주요 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "텍스트 변형 및 수정"}, {"id": "B", "text": "파일 복사"}, {"id": "C", "text": "네트워크 연결"}, {"id": "D", "text": "프로세스 관리"}]', 'A', '''sed''는 텍스트 파일의 내용을 변형하거나 수정하는 데 사용되는 스트림 편집기입니다.'),
    (6803, 23, 3, 2, '함수를 사용하는 주된 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드 재사용"}, {"id": "B", "text": "파일 다운로드"}, {"id": "C", "text": "디스크 사용량 확인"}, {"id": "D", "text": "시스템 정보 출력"}]', 'A', '함수를 사용하면 코드의 재사용이 가능해져 스크립트를 더 깔끔하고 관리하기 쉽게 만듭니다.'),
    (6804, 23, 3, 3, '기본적인 exit code가 0일 경우를 주로 의미하는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "성공적인 실행"}, {"id": "B", "text": "실패"}, {"id": "C", "text": "경고"}, {"id": "D", "text": "중지"}]', 'A', '기본적인 exit code 0은 명령어가 성공적으로 실행되었음을 의미합니다.'),
    (6805, 23, 3, 4, '다음 중 Bash 스크립트에서 여러 개의 인수를 처리하는 도구는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "xargs"}, {"id": "B", "text": "alias"}, {"id": "C", "text": "trap"}, {"id": "D", "text": "tee"}]', '["A"]', 'xargs는 입력된 데이터를 인수로 변환하여 다른 명령어에 전달하는 데 사용됩니다.'),
    (6806, 23, 3, 5, 'Bash 스크립트에서 조건문을 사용하는 이유는 무엇인가?', 'SHORT_ANSWER', NULL, '스크립트의 흐름을 제어하기 위해', ''),
    (6807, 23, 3, 6, 'Bash 스크립트에서 exit code는 무엇을 나타내는가?', 'SHORT_ANSWER', NULL, '명령의 성공 또는 실패 여부', 'exit code는 명령이 성공적으로 실행되었는지 실패했는지를 나타내는 값입니다.'),
    (6808, 23, 3, 7, '다음 중 파이프의 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명령의 출력을 다른 명령의 입력으로 연결한다."}, {"id": "B", "text": "파일을 생성하는 데 사용된다."}, {"id": "C", "text": "스크립트의 실행 시간을 측정한다."}, {"id": "D", "text": "변수의 값을 출력한다."}]', 'A', '파이프는 한 명령의 출력을 다른 명령의 입력으로 연결하여 데이터를 처리하는 데 사용됩니다.'),
    (6809, 23, 3, 8, '다음 중 Bash 스크립트에서 반복문을 사용하는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단일 작업을 여러 번 반복하기 위해."}, {"id": "B", "text": "스크립트를 종료하기 위해."}, {"id": "C", "text": "코드를 주석 처리하기 위해."}, {"id": "D", "text": "변수를 선언하기 위해."}]', 'A', '반복문은 특정 작업을 여러 번 수행할 수 있도록 하여 스크립트를 간소화하고 자동화하는 데 유용합니다.'),
    (6810, 23, 3, 9, '다음 중 여러 개의 파일을 동시에 처리하기 위해 xargs를 사용하는 방법은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "파일 이름을 직접 입력하는 것."}, {"id": "B", "text": "명령의 출력 결과를 인수로 넘기는 것."}, {"id": "C", "text": "스크립트에서 변수로 선언하는 것."}, {"id": "D", "text": "명령을 여러 번 반복하는 것."}]', '["B"]', 'xargs는 명령의 출력 결과를 다른 명령의 인수로 사용하여 여러 개의 파일을 동시에 처리할 수 있도록 합니다.'),
    (6811, 23, 3, 10, 'Bash 스크립트에서 trap 명령어의 주 용도는 무엇인가요?', 'SHORT_ANSWER', NULL, '스크립트 종료 시 특정 작업을 수행하기 위해', 'trap 명령어는 스크립트가 종료될 때 특정 명령을 실행하도록 설정하는 데 사용됩니다.'),
    (6812, 23, 3, 11, 'exit code는 무엇을 나타내나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로그램의 실행 결과"}, {"id": "B", "text": "스크립트의 버전"}, {"id": "C", "text": "사용자 권한"}, {"id": "D", "text": "시스템 부하"}]', 'A', 'exit code는 명령어 또는 스크립트의 실행 결과를 나타내며, 0은 성공을 의미합니다.'),
    (6813, 23, 3, 12, 'alias를 사용하는 주된 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명령어의 단축키를 만들기 위해"}, {"id": "B", "text": "파일을 삭제하기 위해"}, {"id": "C", "text": "망각을 방지하기 위해"}, {"id": "D", "text": "시스템 성능을 향상시키기 위해"}]', 'A', 'alias는 자주 사용하는 명령어의 단축키를 만들어 작업의 효율성을 높이기 위해 사용됩니다.'),
    (6814, 23, 3, 13, '다음 중 파이프와 xargs의 주된 용도로 올바른 것을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "명령어의 출력을 다른 명령어의 입력으로 연결하기 위해"}, {"id": "B", "text": "파일을 생성하기 위해"}, {"id": "C", "text": "대량의 데이터를 처리하기 위해"}, {"id": "D", "text": "스크립트의 오류를 수정하기 위해"}]', '["A", "C"]', '파이프는 명령어의 출력을 다른 명령어의 입력으로 연결하고, xargs는 대량의 데이터를 처리할 때 유용하게 사용됩니다.'),
    (6815, 23, 3, 14, 'awk의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "텍스트 파일의 데이터 처리"}, {"id": "B", "text": "디스크 파티션 관리"}, {"id": "C", "text": "네트워크 설정"}, {"id": "D", "text": "시스템 업데이트"}]', 'A', '''awk''는 텍스트 파일의 데이터 처리와 보고서 생성을 위해 주로 사용됩니다.'),
    (6816, 23, 3, 15, '''sed''는 어떤 기능을 제공하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 복사"}, {"id": "B", "text": "텍스트 변환 및 편집"}, {"id": "C", "text": "프로세스 모니터링"}, {"id": "D", "text": "시스템 로그 확인"}]', 'B', '''sed''는 스트림 편집기로, 텍스트를 변환하고 편집하는 기능을 제공합니다.'),
    (6817, 23, 3, 16, '다음 중 alias를 사용하는 올바른 방법은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "alias ll=''ls -l''"}, {"id": "B", "text": "alias ls -l"}, {"id": "C", "text": "alias ''ls -l''=''ll''"}, {"id": "D", "text": "alias = ''ls -l''"}]', 'A', 'alias를 정의할 때는 ''alias 별칭=명령어'' 형식으로 작성해야 하며 A가 맞는 예시입니다.'),
    (6818, 23, 3, 17, '다음 중 여러 개의 명령어를 동시에 사용할 때 적절한 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "명령어1 | 명령어2"}, {"id": "B", "text": "명령어1 && 명령어2"}, {"id": "C", "text": "명령어1; 명령어2"}, {"id": "D", "text": "명령어1 & 명령어2"}]', '["A", "B"]', '명령어1과 명령어2를 파이프로 연결하거나, 명령어1이 성공할 때만 명령어2를 실행하도록 할 수 있습니다.'),
    (6819, 23, 3, 18, '셸 스크립트에서 종료 코드를 확인하고 싶다면 어떤 변수를 사용해야 하나요?', 'SHORT_ANSWER', NULL, '$?', '$?는 마지막으로 실행된 명령어의 종료 코드를 나타냅니다.'),
    (6820, 23, 3, 19, 'sed 명령어의 주된 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "텍스트 변환"}, {"id": "B", "text": "파일 복사"}, {"id": "C", "text": "네트워크 통신"}, {"id": "D", "text": "디스크 관리"}]', 'A', 'sed는 스트림 편집기로 텍스트를 변환하는 데 사용됩니다.'),
    (6821, 23, 3, 20, 'alias 명령어의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명령어 단축"}, {"id": "B", "text": "파일 이동"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "시스템 모니터링"}]', 'A', 'alias는 자주 사용하는 명령어를 단축하여 보다 간편하게 사용할 수 있게 해줍니다.'),
    (6822, 23, 3, 21, '다음 중 파이프의 올바른 사용 예는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "cat file.txt | grep ''text''"}, {"id": "B", "text": "grep ''text'' | cat file.txt"}, {"id": "C", "text": "ls | cp backup.txt"}, {"id": "D", "text": "echo ''Hello'' | ls"}]', 'A', 'cat file.txt | grep ''text''는 file.txt의 내용을 grep으로 필터링하는 올바른 사용입니다.'),
    (6823, 23, 3, 22, 'xargs 명령어를 사용하는 주된 이유는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "명령어의 입력을 처리하기 위해"}, {"id": "B", "text": "파일을 생성하기 위해"}, {"id": "C", "text": "시스템 성능을 모니터링하기 위해"}, {"id": "D", "text": "스크립트의 실행 속도를 향상시키기 위해"}]', '["A", "D"]', 'xargs는 명령어의 입력을 처리하고, 스크립트 실행 시 입력을 동적으로 생성하여 속도를 향상시킬 수 있습니다.'),
    (6824, 23, 3, 23, '반복문을 사용하여 특정 작업을 반복하는 이유는 무엇인가요?', 'SHORT_ANSWER', NULL, '효율성을 높이고 코드 중복을 줄이기 위해', '반복문을 사용하면 코드 중복을 줄이고, 작업을 더 쉽게 자동화할 수 있습니다.'),
    (6825, 23, 3, 24, '다음 명령어의 출력 결과는 무엇인가? `ls -l | grep ''.txt''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 .txt 파일 목록"}, {"id": "B", "text": "현재 디렉토리의 모든 파일 목록"}, {"id": "C", "text": "현재 디렉토리의 .txt 파일을 제외한 목록"}, {"id": "D", "text": "에러 발생"}]', 'A', '이 명령어는 현재 디렉토리의 파일 목록 중에서 ''.txt'' 파일만 필터링합니다.'),
    (6826, 23, 3, 25, '다음 명령어의 빈칸을 채우시오: `echo "Test" _______ output.txt`', 'SHORT_ANSWER', NULL, '>', '이 경우, ''>''를 사용하여 output.txt 파일에 ''Test''를 씁니다.'),
    (6827, 23, 3, 26, '다음 중 리다이렉션 연산자에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": ">>는 파일을 덮어쓴다."}, {"id": "B", "text": "2>&1은 오류 출력을 표준 출력으로 리다이렉트한다."}, {"id": "C", "text": "|는 명령어의 출력을 파일로 보낸다."}, {"id": "D", "text": ">는 파일에 내용을 추가한다."}]', 'B', '2>&1은 오류 출력을 표준 출력으로 리다이렉트하여, 두 출력을 동일한 대상으로 보냅니다.'),
    (6828, 23, 3, 27, '다음 중 여러 개의 명령어 출력을 파일로 리다이렉트하는 올바른 방법은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "command1 > output.txt"}, {"id": "B", "text": "command1 >> output.txt"}, {"id": "C", "text": "command1 | command2 > output.txt"}, {"id": "D", "text": "command1 2>&1 >> output.txt"}]', '["A", "B", "C"]', 'command1의 출력을 output.txt 파일로 리다이렉트하는 방법으로 A, B, C가 맞습니다.'),
    (6829, 23, 3, 28, '다음 sed 명령어의 기능은 무엇인가? `sed ''s/old/new/g'' filename`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "filename 파일에서 ''old''를 ''new''로 전부 대체"}, {"id": "B", "text": "''old'' 문자열이 포함된 줄을 삭제"}, {"id": "C", "text": "filename 파일의 내용을 복사"}, {"id": "D", "text": "filename 파일의 모든 내용을 출력"}]', 'A', '''sed ''s/old/new/g'' filename''는 ''filename'' 파일 내의 모든 ''old''를 ''new''로 대체하는 명령입니다.'),
    (6830, 23, 3, 29, '다음 awk 명령어의 결과는 무엇인가? `awk ''{print $2}'' filename`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "filename 파일의 두 번째 필드를 출력"}, {"id": "B", "text": "filename 파일의 첫 번째 필드를 출력"}, {"id": "C", "text": "filename 파일의 모든 내용을 출력"}, {"id": "D", "text": "filename 파일의 모든 필드를 출력"}]', 'A', '''awk ''{print $2}'' filename''는 ''filename'' 파일의 각 줄에서 두 번째 필드를 출력하는 명령입니다.'),
    (6831, 23, 3, 30, '다음 코드를 작성했을 때 출력되는 결과는 무엇인가? `echo ''apple banana cherry'' | awk ''{print $1, $3}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "apple cherry"}, {"id": "B", "text": "banana cherry"}, {"id": "C", "text": "apple banana"}, {"id": "D", "text": "banana"}]', 'A', '주어진 명령은 ''apple banana cherry''라는 문자열에서 첫 번째($1)와 세 번째($3) 필드를 출력하여 ''apple cherry''를 생성합니다.'),
    (6832, 23, 3, 31, '다음 중 sed와 awk의 공통적인 용도는 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "텍스트 파일의 데이터 처리"}, {"id": "B", "text": "데이터베이스 관리"}, {"id": "C", "text": "스트링 변환 및 필터링"}, {"id": "D", "text": "웹 스크래핑"}]', '["A", "C"]', 'sed와 awk 모두 텍스트 파일의 데이터를 처리하고, 문자열을 변환 및 필터링하는 데 사용됩니다.'),
    (6833, 23, 3, 32, 'sed와 awk의 주요 차이점은 무엇인가?', 'SHORT_ANSWER', NULL, 'sed는 주로 스트림 편집에 사용되고, awk는 데이터 조작 및 처리에 강력하다.', 'sed는 텍스트를 편집하는 데 중점을 두고, awk는 데이터를 필드 단위로 처리하는 데 중점을 둡니다.'),
    (6834, 23, 3, 33, '다음 코드의 결과를 예측하시오: `ls -l | wc -l`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "디렉토리 내 파일 수"}, {"id": "B", "text": "디렉토리 내 파일 이름"}, {"id": "C", "text": "디렉토리의 총 크기"}, {"id": "D", "text": "파일의 상세 정보"}]', 'A', '`wc -l`은 입력된 라인 수를 세므로, `ls -l`의 결과로 출력된 파일 목록의 라인 수가 됩니다.'),
    (6835, 23, 3, 34, '다음 중 리다이렉션에 대한 설명으로 올바른 것을 고르시오: `command > file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt 파일을 삭제한다."}, {"id": "B", "text": "기존의 file.txt를 덮어쓴다."}, {"id": "C", "text": "file.txt에 내용을 추가한다."}, {"id": "D", "text": "command의 오류를 file.txt에 기록한다."}]', 'B', '`>`는 command의 출력을 file.txt에 덮어쓰므로, 기존의 내용은 삭제됩니다.'),
    (6836, 23, 3, 35, '다음 코드에서 빈칸에 들어갈 적절한 명령어를 고르시오: `command 2> ______`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt"}, {"id": "B", "text": "error.txt"}, {"id": "C", "text": "log.txt"}, {"id": "D", "text": "input.txt"}]', 'B', '`2>`는 표준 오류를 특정 파일로 리다이렉션하는데 사용되며, 보통 오류 메시지를 기록할 파일로 `error.txt`가 적합합니다.'),
    (6837, 23, 3, 36, '리다이렉션을 통해 표준 출력을 표준 오류로 리다이렉트하기 위한 코드는 무엇인가요?', 'SHORT_ANSWER', NULL, '2>&1', '2>&1은 표준 오류(2)를 표준 출력(1)으로 리다이렉트하는 표현입니다.'),
    (6838, 23, 3, 37, '다음 중 파이프를 사용하여 두 개의 명령어를 연결하는 올바른 예시는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ls | grep txt"}, {"id": "B", "text": "grep txt | ls"}, {"id": "C", "text": "cat file.txt | wc -l"}, {"id": "D", "text": "command > output.txt | error.log"}]', '["A", "C"]', 'A는 ls의 출력을 grep으로 필터링하고, C는 file.txt의 라인 수를 세기 위해 cat의 출력을 wc에 전달합니다.'),
    (6839, 23, 3, 38, '다음 명령어의 출력 결과는 무엇인가요? `echo ''Hello World'' | sed ''s/World/Sed/''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello Sed"}, {"id": "B", "text": "Hello World"}, {"id": "C", "text": "Goodbye World"}, {"id": "D", "text": "World Hello"}]', 'A', 'sed 명령어는 ''World''를 ''Sed''로 변경하여 ''Hello Sed''를 출력합니다.'),
    (6840, 23, 3, 39, '다음 awk 명령어의 기능은 무엇인가요? `awk ''{print $2}'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "첫 번째 필드를 출력한다."}, {"id": "B", "text": "두 번째 필드를 출력한다."}, {"id": "C", "text": "모든 필드를 출력한다."}, {"id": "D", "text": "파일을 삭제한다."}]', 'B', 'awk는 특정 필드를 선택하여 출력할 수 있으며, $2는 두 번째 필드를 나타냅니다.'),
    (6841, 23, 3, 40, '다음 빈칸에 알맞은 내용을 채우세요: `sed ''s/\\(.*\\)/\\1 test/'' file.txt`는 ___을 추가합니다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "file의 모든 줄의 끝에 ''test''을 추가한다."}, {"id": "B", "text": "file의 첫 줄을 삭제한다."}, {"id": "C", "text": "file의 내용을 모두 바꾼다."}, {"id": "D", "text": "file의 첫 번째 줄에 ''test''을 추가한다."}]', 'A', '명령어는 각 줄의 끝에 ''test''를 추가합니다.'),
    (6842, 23, 3, 41, '다음 중 sed와 awk의 공통점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "텍스트 파일을 처리할 수 있다."}, {"id": "B", "text": "스크립트 언어이다."}, {"id": "C", "text": "정규 표현식을 지원한다."}, {"id": "D", "text": "GUI 기반이다."}]', '["A", "C"]', 'sed와 awk 모두 텍스트 파일을 처리하며 정규 표현식을 지원합니다.'),
    (6843, 23, 3, 42, 'sed에서 텍스트를 삭제하는 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'd', 'sed에서 d는 특정 패턴을 포함하는 행을 삭제하는 명령어입니다.'),
    (6844, 23, 3, 43, '다음 sed 명령어의 결과로 어떤 출력이 나타나는가? 
sed ''s/foo/bar/g'' example.txt', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "example.txt의 모든 ''foo''가 ''bar''로 바뀜"}, {"id": "B", "text": "''foo''가 삭제됨"}, {"id": "C", "text": "변화 없음"}, {"id": "D", "text": "''bar''가 ''foo''로 바뀜"}]', 'A', 'sed는 ''foo''를 ''bar''로 치환하는 명령어로, 모든 발생을 변경합니다.'),
    (6845, 23, 3, 44, '다음 awk 명령어의 출력은 무엇인가? 
awk ''{print $2}'' test.txt', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 줄의 첫 번째 필드"}, {"id": "B", "text": "각 줄의 두 번째 필드"}, {"id": "C", "text": "각 줄의 세 번째 필드"}, {"id": "D", "text": "각 줄의 전체 내용"}]', 'B', 'awk는 각 줄의 두 번째 필드를 출력합니다.'),
    (6846, 23, 3, 45, '다음 중 sed와 awk의 공통적인 사용 목적으로 알맞은 것은 무엇인가?
1) 텍스트 검색
2) 텍스트 삽입
3) 데이터 필터링
4) 파일 복사', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1, 2, 3"}, {"id": "B", "text": "1, 3, 4"}, {"id": "C", "text": "2, 3, 4"}, {"id": "D", "text": "1, 2, 3, 4"}]', '["A", "B"]', 'sed와 awk 모두 텍스트 검색, 삽입, 데이터 필터링을 지원합니다.'),
    (6847, 23, 3, 46, '다음 awk 명령어에서 빈칸에 들어갈 알맞은 코드는 무엇인가? 
awk ''BEGIN {FS=";"} {print $___}'' data.txt', 'SHORT_ANSWER', NULL, '1', 'FS는 필드 구분자로, $1은 첫 번째 필드를 출력합니다.'),
    (6848, 23, 3, 47, 'sed의 정규 표현식을 사용하여 특정 문자열을 대체하는 방법은 무엇인가?', 'SHORT_ANSWER', NULL, 's/찾을_문자열/대체할_문자열/g', 'sed에서 문자열을 대체하는 기본 형식입니다.'),
    (6849, 23, 3, 48, '다음 crontab 설정은 어떤 작업을 수행합니까? ''0 2 * * * /path/to/backup.sh''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 2시에 백업 스크립트를 실행한다."}, {"id": "B", "text": "매주 월요일 오전 2시에 백업 스크립트를 실행한다."}, {"id": "C", "text": "매일 오후 2시에 백업 스크립트를 실행한다."}, {"id": "D", "text": "매일 오전 2시에 시스템 업데이트를 실행한다."}]', 'A', '0 2 * * *는 매일 오전 2시에 실행하라는 의미입니다.'),
    (6850, 23, 3, 49, '다음 스크립트의 출력은 무엇일까요? ''echo "Hello, World!"''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello, World!"}, {"id": "B", "text": "Hello World!"}, {"id": "C", "text": "Hello,World!"}, {"id": "D", "text": "Error"}]', 'A', 'echo 명령어는 문자열을 출력하며, 큰따옴표로 감싸진 경우 공백도 포함하여 출력합니다.'),
    (6851, 23, 3, 50, '아래 코드에서 빈칸에 들어갈 명령어는 무엇입니까? ''*/5 * * * * _____ /path/to/script.sh''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "run"}, {"id": "B", "text": "execute"}, {"id": "C", "text": "sh"}, {"id": "D", "text": "bash"}]', 'D', '''bash''는 스크립트를 실행하기 위한 올바른 명령어입니다.'),
    (6852, 23, 3, 51, 'cron 작업을 확인하기 위해 사용할 수 있는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "crontab -l"}, {"id": "B", "text": "ls -l"}, {"id": "C", "text": "crontab -e"}, {"id": "D", "text": "cat /etc/crontab"}]', '["A", "D"]', 'crontab -l은 현재 사용자 crontab을 보여주고, /etc/crontab은 시스템 전체의 cron 작업을 보여줍니다.'),
    (6853, 23, 3, 52, 'cron 작업에서 ''*''의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '모든 값', '''*''는 해당 필드의 모든 값을 의미합니다.'),
    (6854, 23, 3, 53, '다음 명령어의 출력은 무엇인가? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "텍스트 파일 목록"}, {"id": "B", "text": "현재 디렉토리의 모든 파일"}, {"id": "C", "text": "디렉토리의 숨김 파일"}, {"id": "D", "text": "에러 메시지"}]', 'A', 'grep 명령어는 ''txt'' 문자열이 포함된 파일만 필터링하여 출력하므로, 텍스트 파일 목록이 출력됩니다.'),
    (6855, 23, 3, 54, '다음 코드의 출력 결과를 예측하시오: `echo "Hello" > file.txt`', 'SHORT_ANSWER', NULL, 'file.txt 파일에 ''Hello''라는 텍스트가 저장됨', '이 명령은 ''Hello''라는 텍스트를 file.txt 파일에 저장합니다.'),
    (6856, 23, 3, 55, '아래 명령어에서 ''>>''의 역할은 무엇인가? `echo "World" >> file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일을 생성한다"}, {"id": "B", "text": "파일의 내용을 덮어쓴다"}, {"id": "C", "text": "파일에 내용을 추가한다"}, {"id": "D", "text": "파일을 삭제한다"}]', 'C', '''>>''는 기존 파일에 내용을 추가하는 역할을 합니다.'),
    (6857, 23, 3, 56, '다음 중 파이프와 리다이렉션을 동시에 사용하는 경우로 올바른 것은 무엇인가? `command > output.txt 2>&1 | another_command`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "올바른 예"}, {"id": "B", "text": "잘못된 예"}, {"id": "C", "text": "출력을 또 다른 명령어로 연결한다"}, {"id": "D", "text": "에러 메시지를 무시한다"}]', '["B", "D"]', '이 명령어는 리다이렉션을 사용하여 output.txt로 출력을 보낸 후, 파이프를 사용하여 another_command로 연결할 수 없으므로 잘못된 예입니다.'),
    (6858, 23, 3, 57, '다음 셸 스크립트의 출력 결과는 무엇인가요?

for i in {1..3}
do
  echo "Count: $i"
done', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Count: 1\\nCount: 2\\nCount: 3"}, {"id": "B", "text": "Count: 1\\nCount: 1\\nCount: 1"}, {"id": "C", "text": "Count: 3\\nCount: 2\\nCount: 1"}, {"id": "D", "text": "Count: 1\\nCount: 2"}]', 'A', 'for 루프는 1부터 3까지 반복하며 각 반복에서 해당 숫자를 출력합니다.'),
    (6859, 23, 3, 58, '다음 코드에서 빈칸에 들어갈 적절한 조건 연산자는 무엇인가요?

if [ __ ]; then
  echo "조건이 참입니다."
fi', 'SHORT_ANSWER', NULL, '조건', '조건 부분에는 -eq, -lt, -gt 등의 비교 연산자가 들어가야 합니다.'),
    (6860, 23, 3, 59, '다음 코드의 기능은 무엇인가요?

count=0
while [ $count -lt 5 ]; do
  echo "Count: $count"
  count=$((count + 1))
done', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "5까지의 숫자를 출력한다."}, {"id": "B", "text": "0에서 4까지의 숫자를 출력한다."}, {"id": "C", "text": "Count 변수를 증가시키지 않는다."}, {"id": "D", "text": "무한 루프를 만든다."}]', 'B', 'while 루프는 count가 5보다 작을 동안 계속 실행되며, 0부터 4까지의 숫자를 출력합니다.'),
    (6861, 23, 3, 60, '셸 스크립트에서 변수를 정의할 때 ''='' 기호의 양쪽에 공백이 있어서는 안 된다. 맞는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "O"}, {"id": "B", "text": "X"}]', '["A"]', '변수를 정의할 때 ''='' 기호의 양쪽에 공백이 있으면 오류가 발생합니다.'),
    (6862, 23, 3, 61, 'while 문을 사용하여 사용자가 ''exit''를 입력할 때까지 계속 입력을 받는 스크립트를 작성하시오.', 'SHORT_ANSWER', NULL, 'while true; do read input; [ "$input" = ''exit'' ] && break; done', '무한 루프를 통해 사용자의 입력을 받고 ''exit''이 입력되면 루프를 종료합니다.'),
    (6863, 23, 3, 62, '다음 중 파이프 `|`의 기능에 대한 설명으로 옳은 것은 무엇인가?

A. 명령어를 병렬로 실행한다.
B. 한 명령어의 출력을 다른 명령어의 입력으로 사용한다.
C. 명령어의 출력을 파일로 저장한다.
D. 명령어의 오류 출력을 무시한다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명령어를 병렬로 실행한다."}, {"id": "B", "text": "한 명령어의 출력을 다른 명령어의 입력으로 사용한다."}, {"id": "C", "text": "명령어의 출력을 파일로 저장한다."}, {"id": "D", "text": "명령어의 오류 출력을 무시한다."}]', 'B', '파이프 `|`는 한 명령어의 출력을 다음 명령어의 입력으로 사용하여 연결하는 기능을 한다.'),
    (6864, 23, 3, 63, '다음 코드를 실행했을 때, `cat file.txt > output.txt`의 결과는 무엇인가?

A. 파일 `file.txt`의 내용이 `output.txt`에 추가된다.
B. 파일 `output.txt`가 삭제된다.
C. 파일 `output.txt`에 `file.txt`의 내용이 저장된다.
D. 오류 메시지가 출력된다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일 `file.txt`의 내용이 `output.txt`에 추가된다."}, {"id": "B", "text": "파일 `output.txt`가 삭제된다."}, {"id": "C", "text": "파일 `output.txt`에 `file.txt`의 내용이 저장된다."}, {"id": "D", "text": "오류 메시지가 출력된다."}]', 'C', '리다이렉션 `>`는 `output.txt` 파일이 없다면 새로 만들고, 있다면 그 내용을 덮어쓴다.'),
    (6865, 23, 3, 64, '다음 중 `2>&1`의 의미는 무엇인가?

A. 표준 출력과 오류 출력을 모두 출력 파일로 리다이렉트한다.
B. 표준 오류를 표준 출력으로 리다이렉트한다.
C. 표준 출력을 표준 오류로 리다이렉트한다.
D. 출력 파일을 생성하지 않는다.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "표준 출력과 오류 출력을 모두 출력 파일로 리다이렉트한다."}, {"id": "B", "text": "표준 오류를 표준 출력으로 리다이렉트한다."}, {"id": "C", "text": "표준 출력을 표준 오류로 리다이렉트한다."}, {"id": "D", "text": "출력 파일을 생성하지 않는다."}]', 'B', '`2>&1`는 표준 오류(2)를 표준 출력(1)으로 리다이렉트하여 둘을 동일하게 만든다.'),
    (6866, 23, 3, 65, '다음 중 해당 명령어에서 올바른 출력을 작성하시오.

`echo ''Hello World'' > greetings.txt`

A. `Hello World`
B. `greetings.txt` 파일에 `Hello World`가 저장된다.
C. 오류 메시지가 발생한다.
D. `Hello World`가 화면에 출력된다.', 'SHORT_ANSWER', NULL, 'B', '`echo` 명령어는 ''Hello World''라는 문자열을 `greetings.txt` 파일에 저장한다.'),
    (6867, 23, 3, 66, '다음 중 `command > output.txt 2>&1` 명령어의 기능으로 올바른 것은 무엇인가? (복수 선택 가능)

A. 오류 메시지를 `output.txt`에 기록한다.
B. 표준 출력을 `output.txt`에 기록한다.
C. 표준 출력은 화면에 표시되고 오류는 파일에 기록된다.
D. 파일이 없을 경우 새로 생성한다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "오류 메시지를 `output.txt`에 기록한다."}, {"id": "B", "text": "표준 출력을 `output.txt`에 기록한다."}, {"id": "C", "text": "표준 출력은 화면에 표시되고 오류는 파일에 기록된다."}, {"id": "D", "text": "파일이 없을 경우 새로 생성한다."}]', '["A", "B", "D"]', '`command > output.txt 2>&1`는 표준 출력을 `output.txt`에 저장하고, 오류 메시지도 같은 파일에 저장하며, 파일이 없을 경우 새로 생성한다.'),
    (6868, 23, 3, 67, '다음 중 cron 작업의 형식을 올바르게 표현한 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "분 시 일 월 요일 커맨드"}, {"id": "B", "text": "시 분 일 월 요일 커맨드"}, {"id": "C", "text": "일 시 월 분 요일 커맨드"}, {"id": "D", "text": "커맨드 분 시 일 월 요일"}]', 'A', 'cron은 ''분 시 일 월 요일 커맨드'' 형식으로 설정됩니다.'),
    (6869, 23, 3, 68, '다음 crontab 라인의 결과는 무엇인가? 0 2 * * * /home/user/script.sh', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 2시에 script.sh 실행"}, {"id": "B", "text": "매일 오후 2시에 script.sh 실행"}, {"id": "C", "text": "매일 오전 2시에 script.sh 실행 후 종료"}, {"id": "D", "text": "매일 2분마다 script.sh 실행"}]', 'A', '이 crontab은 매일 오전 2시에 script.sh를 실행합니다.'),
    (6870, 23, 3, 69, '다음 중 crontab에 여러 스크립트를 동시에 실행하는 방법으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "0 3 * * * /home/user/backup.sh; /home/user/cleanup.sh"}, {"id": "B", "text": "0 3 * * * /home/user/backup.sh && /home/user/cleanup.sh"}, {"id": "C", "text": "0 3 * * * /home/user/backup.sh /home/user/cleanup.sh"}, {"id": "D", "text": "0 3 * * * /home/user/backup.sh || /home/user/cleanup.sh"}]', 'B', '&& 연산자를 사용하여 두 스크립트를 동시에 실행할 수 있습니다.'),
    (6871, 23, 3, 70, 'crontab을 사용하여 작업을 추가하려면 사용하는 명령어는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "crontab -e"}, {"id": "B", "text": "cron add"}, {"id": "C", "text": "crontab -l"}, {"id": "D", "text": "crontab -a"}]', '["A"]', '작업 추가는 ''crontab -e'' 명령어로 가능합니다.'),
    (6872, 23, 3, 71, 'cron은 어떤 유형의 작업을 자동화하기 위해 주로 사용되는가?', 'SHORT_ANSWER', NULL, '주기적인 작업(예: 백업, 데이터 수집 등)', 'cron은 주기적인 작업을 자동화하는 데 사용됩니다.'),
    (6873, 23, 3, 72, '다음 sed 명령의 작동 결과는 무엇인가요? `echo ''hello world'' | sed ''s/world/universe/''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "hello universe"}, {"id": "B", "text": "hello world"}, {"id": "C", "text": "world universe"}, {"id": "D", "text": "hello"}]', 'A', 'sed는 ''world''를 ''universe''로 치환하여 ''hello universe''를 출력합니다.'),
    (6874, 23, 3, 73, '다음 awk 명령의 출력 결과는 무엇인가요? `echo ''A B C D'' | awk ''{print $2}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "A"}, {"id": "B", "text": "B"}, {"id": "C", "text": "C"}, {"id": "D", "text": "D"}]', 'B', 'awk는 두 번째 필드를 출력하기 때문에 ''B''가 출력됩니다.'),
    (6875, 23, 3, 74, '다음 빈칸에 들어갈 적절한 awk 명령은 무엇인가요? `awk ''__________'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "{print $1}"}, {"id": "B", "text": "NR==1"}, {"id": "C", "text": "{print $0}"}, {"id": "D", "text": "NR>2"}]', 'A', '''{print $1}''는 각 행의 첫 번째 필드를 출력하는 올바른 명령입니다.'),
    (6876, 23, 3, 75, 'sed와 awk의 주된 차이점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "sed는 스트림 편집기이다."}, {"id": "B", "text": "awk는 필드 기반 텍스트 처리에 특화되어 있다."}, {"id": "C", "text": "sed는 파일 내용을 읽지 못한다."}, {"id": "D", "text": "awk는 주로 텍스트 분석에 사용된다."}]', '["A", "B", "D"]', 'sed는 스트림 편집기이고 awk는 텍스트 분석을 위해 필드 기반으로 처리하는 도구입니다.'),
    (6877, 23, 3, 76, 'sed와 awk 모두 텍스트 파일을 처리하는 데 사용된다. 이들 중 어느 것이 더 복잡한 데이터 분석에 적합한가?', 'SHORT_ANSWER', NULL, 'awk', 'awk는 복잡한 데이터 분석과 필드 기반 처리에 더 적합합니다.'),
    (6878, 23, 3, 77, '다음 명령어의 의미는 무엇인가요? `ls -l | grep ''txt''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 모든 파일을 나열한다."}, {"id": "B", "text": "현재 디렉토리의 모든 txt 파일을 나열한다."}, {"id": "C", "text": "현재 디렉토리의 모든 파일의 크기를 출력한다."}, {"id": "D", "text": "현재 디렉토리의 모든 폴더를 나열한다."}]', 'B', '`ls -l`의 결과 중에서 ''txt''가 포함된 파일만 필터링해서 출력합니다.'),
    (6879, 23, 3, 78, '아래 명령어의 결과는 무엇일까요? `echo ''Hello'' > file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일을 생성하고 ''Hello''라는 내용을 쓴다."}, {"id": "B", "text": "파일을 생성하지만 ''Hello''는 무시한다."}, {"id": "C", "text": "에러 메시지를 출력한다."}, {"id": "D", "text": "파일의 내용을 덮어쓴다."}]', 'A', '파일이 생성되고 ''Hello''라는 내용이 파일에 기록됩니다.'),
    (6880, 23, 3, 79, '아래 명령어에서 빈칸에 들어갈 내용은 무엇인가요? `command 2> ___`', 'SHORT_ANSWER', NULL, 'error.txt', '표준 오류를 ''error.txt'' 파일로 리다이렉션합니다.'),
    (6881, 23, 3, 80, '아래 명령어의 결과로 나올 수 있는 올바른 파일은 무엇인가요? `command > output.txt 2>&1`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "output.txt"}, {"id": "B", "text": "error.log"}, {"id": "C", "text": "output.txt와 error.log 모두"}, {"id": "D", "text": "없음"}]', '["A", "C"]', '모든 출력(표준 출력과 표준 오류)이 ''output.txt''로 리다이렉션됩니다.'),
    (6882, 23, 3, 81, '다음 crontab 항목은 어떤 작업을 수행하나요? 0 2 * * * /path/to/script.sh', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 2시에 스크립트를 실행한다."}, {"id": "B", "text": "매주 월요일에 스크립트를 실행한다."}, {"id": "C", "text": "매일 오후 2시에 스크립트를 실행한다."}, {"id": "D", "text": "매달 첫 번째 날에 스크립트를 실행한다."}]', 'A', '주어진 crontab 항목은 매일 오전 2시에 지정된 스크립트를 실행하는 설정입니다.'),
    (6883, 23, 3, 82, '다음 코드의 빈칸에 들어갈 적절한 명령어는 무엇인가요? crontab -e를 사용하여 다음과 같은 항목을 추가했습니다: ___ * * * * /path/to/script.sh', 'SHORT_ANSWER', NULL, '0 2', '이 항목은 매일 오전 2시에 스크립트를 실행하기 위한 설정입니다.'),
    (6884, 23, 3, 83, 'cron 로그 파일의 일반적인 경로는 어디인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "/var/log/cron"}, {"id": "B", "text": "/etc/cron.log"}, {"id": "C", "text": "/usr/bin/cron.log"}, {"id": "D", "text": "/tmp/cron.log"}]', 'A', 'cron의 로그는 일반적으로 /var/log/cron 파일에 저장됩니다.'),
    (6885, 23, 3, 84, '다음 중 cron job을 추가하는 방법으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "crontab -e"}, {"id": "B", "text": "cron add"}, {"id": "C", "text": "crontab -l"}, {"id": "D", "text": "sudo crontab"}]', '["A", "D"]', 'cron job을 추가하려면 crontab -e 명령어를 사용하거나, sudo crontab을 통해 root 사용자로 추가할 수 있습니다.'),
    (6886, 23, 3, 85, '다음 `sed` 명령의 기능은 무엇인가요? `sed ''s/apple/orange/g'' fruits.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "''fruits.txt'' 파일의 ''apple''을 ''orange''로 변경한다."}, {"id": "B", "text": "''fruits.txt'' 파일의 모든 내용을 출력한다."}, {"id": "C", "text": "''fruits.txt'' 파일에서 ''orange''를 삭제한다."}, {"id": "D", "text": "''fruits.txt'' 파일의 라인 수를 센다."}]', 'A', '''sed'' 명령은 주어진 패턴을 찾아 대체하는 역할을 합니다.'),
    (6887, 23, 3, 86, '다음 `awk` 명령의 출력 결과는 무엇인가요? `awk -F, ''{print $2}'' data.csv`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "첫 번째 컬럼을 출력한다."}, {"id": "B", "text": "두 번째 컬럼을 출력한다."}, {"id": "C", "text": "모든 컬럼을 출력한다."}, {"id": "D", "text": "CSV 파일을 정렬한다."}]', 'B', '''awk'' 명령에서 ''{print $2}''는 두 번째 컬럼을 출력합니다.'),
    (6888, 23, 3, 87, '다음 코드에서 빈칸에 들어갈 적절한 명령어는 무엇인가요? `awk -F, ''...'' data.csv`', 'SHORT_ANSWER', NULL, '{print $1}', '{print $1}는 첫 번째 컬럼을 출력하는 명령입니다.'),
    (6889, 23, 3, 88, '다음 중 `sed`와 `awk`의 공통점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "텍스트 파일을 처리할 수 있다."}, {"id": "B", "text": "프로그래밍 언어이다."}, {"id": "C", "text": "데이터를 수정할 수 있다."}, {"id": "D", "text": "정규 표현식을 사용할 수 있다."}]', '["A", "C", "D"]', '`sed`와 `awk` 모두 텍스트 파일을 처리하고, 데이터를 수정하며, 정규 표현식을 사용할 수 있습니다.'),
    (6890, 23, 3, 89, '다음 `sed` 명령어의 역할은 무엇인가요? `sed ''s/foo/bar/g'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "file.txt에서 모든 ''foo''를 ''bar''로 변경한다."}, {"id": "B", "text": "file.txt의 모든 텍스트를 삭제한다."}, {"id": "C", "text": "file.txt의 첫 번째 줄만 변경한다."}, {"id": "D", "text": "file.txt를 출력한다."}]', 'A', '''sed ''s/foo/bar/g'' file.txt'' 명령은 file.txt에서 모든 ''foo''를 ''bar''로 변경하는 역할을 합니다.'),
    (6891, 23, 3, 90, '다음 `awk` 명령어의 출력 결과는 무엇인가요? `awk ''{print $2}'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "첫 번째 필드를 출력한다."}, {"id": "B", "text": "두 번째 필드를 출력한다."}, {"id": "C", "text": "모든 필드를 출력한다."}, {"id": "D", "text": "세 번째 필드를 출력한다."}]', 'B', '''awk ''{print $2}'' file.txt'' 명령은 file.txt의 각 줄에서 두 번째 필드를 출력합니다.'),
    (6892, 23, 3, 91, '아래 코드는 어떤 기능을 수행하나요? `sed -n ''1,5p'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "file.txt의 첫 5줄을 출력한다."}, {"id": "B", "text": "file.txt의 마지막 5줄을 출력한다."}, {"id": "C", "text": "file.txt의 모든 줄을 삭제한다."}, {"id": "D", "text": "file.txt의 특정 줄을 대체한다."}]', 'A', '''sed -n ''1,5p'' file.txt'' 명령은 file.txt의 첫 5줄을 출력하는 기능을 수행합니다.'),
    (6893, 23, 3, 92, '다음 중 `awk`를 사용하여 홀수 번째 줄만 출력하는 방법은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "awk ''NR % 2 == 1'' file.txt"}, {"id": "B", "text": "awk ''NR % 2 == 0'' file.txt"}, {"id": "C", "text": "awk ''NR == 1'' file.txt"}, {"id": "D", "text": "awk ''NR > 1'' file.txt"}]', '["A"]', '''awk ''NR % 2 == 1'' file.txt'' 명령은 홀수 번째 줄만 출력하는 방법입니다.'),
    (6894, 23, 3, 93, 'sed의 기본적인 사용법을 설명하시오.', 'SHORT_ANSWER', NULL, 'sed는 텍스트 파일에서 패턴을 찾고, 해당 패턴을 변경하거나 삭제하는데 사용된다.', 'sed는 텍스트 파일에서 패턴을 찾고, 해당 패턴을 변경하거나 삭제하는 데 사용되는 스트림 편집기이다.'),
    (6895, 23, 3, 94, '다음 crontab 설정의 의미는 무엇인가요? `0 12 * * * /path/to/backup.sh`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 정오에 backup.sh를 실행한다."}, {"id": "B", "text": "매주 월요일에 backup.sh를 실행한다."}, {"id": "C", "text": "매일 오전 6시에 backup.sh를 실행한다."}, {"id": "D", "text": "매시간마다 backup.sh를 실행한다."}]', 'A', '이 crontab 설정은 매일 정오에 특정 스크립트를 실행하도록 설정한 것입니다.'),
    (6896, 23, 3, 95, '다음 코드는 어떤 기능을 수행하는가? `#!/bin/bash
 echo "Backup started..."`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "백업을 시작하는 메시지를 출력한다."}, {"id": "B", "text": "백업 파일을 생성한다."}, {"id": "C", "text": "스크립트를 실행 중지한다."}, {"id": "D", "text": "백업을 완료했다는 메시지를 출력한다."}]', 'A', '이 코드는 ''Backup started...''라는 메시지를 출력하는 간단한 스크립트입니다.'),
    (6897, 23, 3, 96, '다음 빈칸을 채우세요: `* * * * * /path/to/script.sh`에서 첫 번째 `*`는 _______을 의미합니다.', 'SHORT_ANSWER', NULL, '분', '첫 번째 ''*''는 분을 나타내며, 이 필드는 0-59 사이의 값을 가질 수 있습니다.'),
    (6898, 23, 3, 97, 'cron을 사용하여 자동으로 매주 화요일과 목요일에 스크립트를 실행하고 싶습니다. 올바른 crontab 설정을 모두 선택하세요: 
1. `0 10 * * 2 /path/to/script.sh`
2. `0 10 * * 4 /path/to/script.sh`
3. `0 10 * * 1 /path/to/script.sh` ', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "1과 2"}]', '["D"]', '1번과 2번 설정은 각각 화요일과 목요일에 스크립트를 실행하도록 설정되어 있습니다.'),
    (6899, 23, 3, 98, '다음 crontab 명령은 어떤 작업을 수행하나요? 0 2 * * * /path/to/script.sh', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 2시에 script.sh를 실행한다."}, {"id": "B", "text": "매주 월요일 오전 2시에 script.sh를 실행한다."}, {"id": "C", "text": "매달 1일 오전 2시에 script.sh를 실행한다."}, {"id": "D", "text": "매일 오후 2시에 script.sh를 실행한다."}]', 'A', '주어진 crontab 명령은 매일 오전 2시에 script.sh를 실행하게 설정되어 있습니다.'),
    (6900, 23, 3, 99, '다음 중 crontab에서 ''*''의 의미는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "특정 시점"}, {"id": "B", "text": "모든 값"}, {"id": "C", "text": "아무것도 실행하지 않음"}, {"id": "D", "text": "한 번만 실행"}]', 'B', '''*''는 모든 값을 의미하며, 이는 해당 필드에 대해 모든 가능한 값을 선택할 수 있음을 나타냅니다.'),
    (6901, 23, 3, 100, '다음 빈칸을 채우세요: crontab 명령어를 업데이트하기 위해서는 _______ 명령어를 사용해야 한다.', 'SHORT_ANSWER', NULL, 'crontab -e', 'crontab -e 명령어를 사용하여 crontab 파일을 편집할 수 있습니다.'),
    (6902, 23, 3, 101, '다음 작업은 어떤 주기로 실행될까요? */5 * * * * /path/to/script.sh', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "매 5분마다"}, {"id": "B", "text": "매 5시간마다"}, {"id": "C", "text": "매 5일마다"}, {"id": "D", "text": "매 5초마다"}]', '["A"]', '이 crontab 명령은 매 5분마다 script.sh를 실행하도록 설정되어 있습니다.'),
    (6903, 23, 3, 102, '다음 sed 명령의 출력 결과는 무엇인가? 
sed ''s/abc/xyz/g'' input.txt', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "abc가 xyz로 변경된 파일 내용"}, {"id": "B", "text": "변경 없어진 파일 내용"}, {"id": "C", "text": "파일을 삭제함"}, {"id": "D", "text": "에러가 발생함"}]', 'A', '''abc''를 ''xyz''로 변경하는 명령이므로, 해당 텍스트가 변경된 결과를 출력한다.'),
    (6904, 23, 3, 103, '다음 awk 명령의 출력 결과는 무엇인가? 
awk ''{print $2}'' data.txt', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "data.txt 파일의 첫 번째 필드 출력"}, {"id": "B", "text": "data.txt 파일의 두 번째 필드 출력"}, {"id": "C", "text": "파일 내용을 수정함"}, {"id": "D", "text": "에러가 발생함"}]', 'B', '''{print $2}''는 각 줄의 두 번째 필드를 출력하라는 명령이다.'),
    (6905, 23, 3, 104, '다음 빈칸을 채우시오: sed의 기본적인 사용법은 ''sed ______ ''s/찾는단어/대체단어/'' 파일명이다.', 'SHORT_ANSWER', NULL, 's', '''s''는 substitute의 약자로, 대체하는 기능을 의미한다.'),
    (6906, 23, 3, 105, '다음 중 sed와 awk의 특징으로 올바른 것을 모두 고르시오.
 1. sed는 스트림 편집기이다.
 2. awk는 주로 정규 표현식을 사용한다.
 3. sed는 데이터 기반 필드 처리를 지원하지 않는다.
 4. awk는 데이터 조작에 강력하다.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1과 2"}, {"id": "B", "text": "1과 4"}, {"id": "C", "text": "2와 3"}, {"id": "D", "text": "3과 4"}]', '["B"]', '1과 4는 맞는 설명이다. 2는 awk가 주로 필드 기반 처리에 강력하다는 점으로, 3은 틀린 설명이다.'),
    (6907, 23, 3, 106, '다음 중 파이프(`|`)의 용도에 대한 설명으로 옳은 것은 무엇인가요? `ls -l | grep "txt"` 명령을 사용했을 때의 역할을 설명하세요.', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ls -l 명령의 결과 중 ''txt''가 포함된 라인만 출력한다."}, {"id": "B", "text": "ls -l 명령의 결과를 ''txt''라는 파일로 저장한다."}, {"id": "C", "text": "''txt''라는 이름의 디렉토리를 생성한다."}, {"id": "D", "text": "ls -l 명령의 오류를 무시하고 출력한다."}]', 'A', '''ls -l | grep "txt"''는 ls -l 명령의 결과 중 ''txt''가 포함된 라인만 출력하기 때문에 A가 옳은 설명입니다.'),
    (6908, 23, 3, 107, '다음 명령의 결과는 무엇인가요? `echo "Hello World" > output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt 파일에 ''Hello World''가 저장된다."}, {"id": "B", "text": "Hello World가 화면에 출력된다."}, {"id": "C", "text": "output.txt 파일이 삭제된다."}, {"id": "D", "text": "에러 메시지가 출력된다."}]', 'A', '`echo "Hello World" > output.txt`는 ''Hello World''를 output.txt 파일에 저장하기 때문에 A가 정답입니다.'),
    (6909, 23, 3, 108, '다음 명령에서 ''2>&1''의 역할은 무엇인가요? `command > output.txt 2>&1`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "표준 입력을 output.txt로 리다이렉트한다."}, {"id": "B", "text": "표준 출력과 오류 출력을 모두 output.txt로 리다이렉트한다."}, {"id": "C", "text": "output.txt 파일의 내용을 표준 출력으로 보낸다."}, {"id": "D", "text": "표준 오류만 output.txt로 리다이렉트한다."}]', 'B', '`command > output.txt 2>&1`는 표준 출력과 표준 오류를 모두 output.txt로 리다이렉트하기 때문에 B가 정답입니다.'),
    (6910, 23, 3, 109, '다음 중 올바른 리다이렉션 조합은 무엇인가요? ''echo "Sample" _________ output.txt''', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": ">"}, {"id": "B", "text": ">>"}, {"id": "C", "text": "2>&1"}, {"id": "D", "text": ">>>"}]', '["A", "B"]', '''echo "Sample" > output.txt'' 또는 ''echo "Sample" >> output.txt''는 둘 다 올바른 리다이렉션 조합입니다.'),
    (6911, 23, 3, 110, '리다이렉션으로 오류 메시지를 파일에 저장하고 싶다면 어떤 방법을 사용해야 하나요?', 'SHORT_ANSWER', NULL, 'command 2> error.txt', '''command 2> error.txt''는 표준 오류 메시지를 error.txt 파일에 저장하는 방법입니다.'),
    (6912, 23, 3, 111, '다음 명령어의 출력 결과는 무엇인가요? `echo ''Hello World'' | wc -w`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "2"}, {"id": "B", "text": "Hello World"}, {"id": "C", "text": "1"}, {"id": "D", "text": "3"}]', 'A', 'wc -w는 단어 수를 카운트하는 명령어로, ''Hello World''는 2개의 단어로 구성되어 있습니다.'),
    (6913, 23, 3, 112, '다음 중 리다이렉션을 통한 오류 메시지 저장 방법으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "command > output.log"}, {"id": "B", "text": "command 2> error.log"}, {"id": "C", "text": "command >> error.log"}, {"id": "D", "text": "command 2>&1 > output.log"}]', 'B', 'command 2> error.log는 오류 메시지를 error.log 파일에 저장하는 올바른 방법입니다.'),
    (6914, 23, 3, 113, '다음 명령어의 빈칸을 채우세요: `cat file.txt > output.txt; echo ''Done'' 2>&1 ___`', 'SHORT_ANSWER', NULL, '>> output.txt', '기존 output.txt 파일에 ''Done'' 메시지를 추가하려면 ''>> output.txt''를 사용해야 합니다.'),
    (6915, 23, 3, 114, '아래 명령어의 모든 출력(정상 + 오류)을 동일한 파일에 저장하기 위해 적절한 리다이렉션을 선택하세요: `command 2>&1 ___`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "> output.log"}, {"id": "B", "text": ">> output.log"}, {"id": "C", "text": "&> output.log"}, {"id": "D", "text": "2> output.log"}]', '["A", "B", "C"]', '정상 출력과 오류를 동일한 파일에 저장하기 위해 >, >>, &>를 사용할 수 있습니다.'),
    (6916, 23, 3, 115, '다음 명령어의 출력은 무엇인가요? `echo ''Hello World'' > output.txt`', 'SHORT_ANSWER', NULL, 'Hello World', 'output.txt 파일에 ''Hello World''가 저장됩니다.'),
    (6917, 23, 3, 116, '다음 명령어의 결과는 무엇인가요? `ls | wc -l`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 파일 수"}, {"id": "B", "text": "파일의 내용"}, {"id": "C", "text": "디렉토리의 경로"}, {"id": "D", "text": "오류 메시지"}]', 'A', '이 명령어는 현재 디렉토리의 파일 수를 계산합니다.'),
    (6918, 23, 3, 117, '아래 명령어에서 빈칸에 들어갈 올바른 리다이렉션 기호는 무엇인가요? `command 2 ___ file.txt`', 'SHORT_ANSWER', NULL, '>', '오류 출력을 file.txt로 리다이렉션하기 위해 ''>''가 필요합니다.'),
    (6919, 23, 3, 118, '다음 명령어의 사용 목적은 무엇인가요? `command > output.txt 2>&1`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "표준 출력을 output.txt로 리다이렉션"}, {"id": "B", "text": "표준 오류 출력을 output.txt로 리다이렉션"}, {"id": "C", "text": "명령어의 실행 결과를 출력하지 않음"}, {"id": "D", "text": "표준 출력과 오류 출력을 모두 output.txt로 리다이렉션"}]', '["A", "B", "D"]', '이 명령어는 표준 출력과 오류 출력을 모두 output.txt로 리다이렉션합니다.'),
    (6920, 23, 3, 119, '다음 명령어의 의도는 무엇인가요? `cat file.txt >> output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt를 새로 생성"}, {"id": "B", "text": "file.txt의 내용을 output.txt에 추가"}, {"id": "C", "text": "output.txt를 삭제"}, {"id": "D", "text": "file.txt를 삭제"}]', 'B', '이 명령어는 file.txt의 내용을 output.txt 파일에 추가합니다.'),
    (6921, 23, 3, 120, '다음 crontab 항목의 의미는 무엇인가? `0 5 * * * /path/to/backup.sh`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 5시에 backup.sh 실행"}, {"id": "B", "text": "매주 월요일 오전 5시에 backup.sh 실행"}, {"id": "C", "text": "매일 오후 5시에 backup.sh 실행"}, {"id": "D", "text": "매일 저녁 5시에 backup.sh 실행"}]', 'A', '이 crontab 항목은 매일 오전 5시에 backup.sh 스크립트를 실행하도록 설정되어 있습니다.'),
    (6922, 23, 3, 121, '다음 코드에서 빈칸에 들어갈 알맞은 명령어는 무엇인가? `crontab -e` 명령어를 사용하여 ___을(를) 열 수 있다.', 'SHORT_ANSWER', NULL, '사용자 crontab 파일', 'crontab -e 명령어는 현재 사용자의 crontab 파일을 열어 작업을 추가하거나 수정할 수 있게 해줍니다.'),
    (6923, 23, 3, 122, 'Cron 작업에서 특정 스크립트를 매주 특정 요일에 실행하기 위해 설정할 수 있는 주기는 어떤 형식으로 나타낼 수 있는가? 예를 들어, 매주 화요일 오전 3시에 실행하기 위해 crontab 항목은 ___', 'SHORT_ANSWER', NULL, '0 3 * * 2', '매주 화요일 오전 3시에 실행하기 위해서는 ''0 3 * * 2''와 같이 crontab 항목을 설정해야 합니다.'),
    (6924, 23, 3, 123, 'cron을 이용하여 매일 오후 6시에 스크립트를 실행하려면 다음 중 어떤 형식으로 crontab을 작성해야 하는가? `___ /path/to/script.sh`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "0 18 * * *"}, {"id": "B", "text": "18 0 * * *"}, {"id": "C", "text": "6 18 * * *"}, {"id": "D", "text": "0 6 * * *"}]', 'A', '매일 오후 6시에 스크립트를 실행하기 위해서는 ''0 18 * * *'' 형식으로 crontab을 작성해야 합니다.'),
    (6925, 23, 3, 124, 'cron 설정에서 실행 주기를 지정하는 필드는 몇 개인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "2"}, {"id": "B", "text": "5"}, {"id": "C", "text": "3"}, {"id": "D", "text": "4"}]', '["B"]', 'cron 설정에서 실행 주기를 지정하는 필드는 총 5개입니다: 분, 시간, 일, 월, 요일.'),
    (6926, 23, 3, 125, '다음 sed 명령어의 기능은 무엇인가? sed ''s/word/replace/g'' file.txt', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일에서 ''word''를 ''replace''로 변경한다."}, {"id": "B", "text": "파일에서 ''replace''를 ''word''로 변경한다."}, {"id": "C", "text": "파일의 모든 내용을 삭제한다."}, {"id": "D", "text": "파일의 첫 번째 줄을 출력한다."}]', 'A', '''sed ''s/word/replace/g'' file.txt''는 ''file.txt''에서 ''word''를 ''replace''로 변경하는 명령어이다.'),
    (6927, 23, 3, 126, '다음 awk 명령어의 출력 결과는? awk ''{print $2}'' file.txt (file.txt의 내용: ''Hello World'')', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello"}, {"id": "B", "text": "World"}, {"id": "C", "text": "Hello World"}, {"id": "D", "text": "Error"}]', 'B', 'awk는 기본적으로 공백을 기준으로 필드를 나누므로, ''{print $2}''는 두 번째 필드인 ''World''를 출력한다.'),
    (6928, 23, 3, 127, '다음 코드에서 빈칸에 들어갈 내용은 무엇인가? sed ''___/pattern/d'' file.txt', 'SHORT_ANSWER', NULL, 'g', '빈칸에는 ''g''가 들어가야 하며, 이는 모든 패턴을 삭제하겠다는 의미이다.'),
    (6929, 23, 3, 128, '다음 중 sed와 awk의 기능으로 올바른 것을 모두 고르시오. (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "sed는 문자열 대체가 가능하다."}, {"id": "B", "text": "awk는 파일 내용을 정렬할 수 있다."}, {"id": "C", "text": "sed는 텍스트에서 패턴 검색을 한다."}, {"id": "D", "text": "awk는 수치 계산이 가능하다."}]', '["A", "C", "D"]', 'sed는 문자열 대체와 패턴 검색이 가능하며, awk는 수치 계산 및 데이터 조작이 가능하다.'),
    (6930, 23, 3, 129, '다음 Bash 명령어의 결과는 무엇인가요? `ls -l | grep ''.txt''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": ".txt 확장자를 가진 파일 목록"}, {"id": "B", "text": "모든 파일 목록"}, {"id": "C", "text": "디렉토리 정보"}, {"id": "D", "text": "에러 메시지"}]', 'A', '.txt 확장자를 가진 파일만 필터링하여 출력합니다.'),
    (6931, 23, 3, 130, '다음 명령어의 빈칸을 채우세요: `command > output.txt ___`', 'SHORT_ANSWER', NULL, '2>&1', '이 명령어는 표준 오류를 표준 출력으로 리다이렉션합니다.'),
    (6932, 23, 3, 131, '다음 중 리다이렉션을 사용하는 명령어로 올바른 것은 무엇인가요? `command > file.txt`?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "출력을 file.txt에 저장"}, {"id": "B", "text": "file.txt의 내용을 불러오기"}, {"id": "C", "text": "파일을 삭제"}, {"id": "D", "text": "에러를 무시"}]', 'A', '출력을 file.txt 파일에 저장합니다.'),
    (6933, 23, 3, 132, '다음 중 파이프를 사용하는 명령어의 조합으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ls -l | sort"}, {"id": "B", "text": "cat file.txt | wc -l"}, {"id": "C", "text": "cd /home/user | ls"}, {"id": "D", "text": "echo ''test'' | grep ''t''"}]', '["A", "B", "D"]', 'A, B, D는 파이프를 사용하여 명령어를 연결하여 실행하는 방법입니다.'),
    (6934, 23, 3, 133, '리다이렉션에서 ''>>''의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, '파일에 내용을 추가한다.', '''>>''는 기존 파일에 새로운 내용을 추가하는 리다이렉션입니다.'),
    (6935, 23, 3, 134, '다음 `sed` 명령어의 결과는 무엇인가? `sed ''s/hello/hi/'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일의 첫 번째 ''hello''를 ''hi''로 변경한 내용"}, {"id": "B", "text": "모든 ''hello''를 ''hi''로 변경한 내용"}, {"id": "C", "text": "파일의 모든 내용을 삭제한 내용"}, {"id": "D", "text": "변경 없이 원래 파일 내용 그대로"}]', 'A', '`sed ''s/hello/hi/''`는 첫 번째 ''hello''만 ''hi''로 변경합니다.'),
    (6936, 23, 3, 135, '다음 `awk` 명령어의 출력은 무엇인가? `awk ''{print $2}'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일의 첫 번째 열"}, {"id": "B", "text": "파일의 두 번째 열"}, {"id": "C", "text": "파일의 모든 내용을 출력"}, {"id": "D", "text": "파일의 마지막 열"}]', 'B', '`awk ''{print $2}''`는 각 줄의 두 번째 열을 출력합니다.'),
    (6937, 23, 3, 136, '다음 코드에서 빈칸에 들어가야 할 내용은 무엇인가? `sed ''s/\\(.*\\)\\(pattern\\)\\(.*\\)/\\1replacement\\3/'' file.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일의 모든 내용을 출력"}, {"id": "B", "text": "pattern을 찾아서 replacement로 변경"}, {"id": "C", "text": "pattern을 삭제"}, {"id": "D", "text": "파일을 복사"}]', 'B', '`sed`의 이 명령어는 ''pattern''을 찾아 ''replacement''로 변경하는 역할을 합니다.'),
    (6938, 23, 3, 137, '다음 중 `awk`의 특징으로 올바른 것은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "필드를 쉽게 다룰 수 있다."}, {"id": "B", "text": "텍스트 파일을 수정할 수 있다."}, {"id": "C", "text": "조건문과 반복문을 사용할 수 있다."}, {"id": "D", "text": "그래픽 사용자 인터페이스를 제공한다."}]', '["A", "C"]', '`awk`는 필드를 쉽게 다루고, 조건문 및 반복문을 사용할 수 있는 특징이 있습니다.'),
    (6939, 23, 3, 138, '`sed`와 `awk`의 사용 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '텍스트 데이터의 처리 및 변형', '`sed`는 주로 텍스트를 수정하고, `awk`는 데이터를 처리하는 데 사용된다.'),
    (6940, 23, 3, 139, '다음 crontab 설정에서 어떤 주기에 명령이 실행되나요? ''0 3 * * * /path/to/script.sh''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 3시"}, {"id": "B", "text": "매주 월요일 오전 3시"}, {"id": "C", "text": "매월 1일 오전 3시"}, {"id": "D", "text": "매시간 3분마다"}]', 'A', '이 crontab 설정은 매일 오전 3시에 지정된 스크립트를 실행합니다.'),
    (6941, 23, 3, 140, '다음 bash 스크립트의 출력 결과는 무엇인가요? ''echo logs_$(date +%F).tar.gz''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "logs_YYYY-MM-DD.tar.gz"}, {"id": "B", "text": "logs.tar.gz"}, {"id": "C", "text": "logs_YYYY.tar.gz"}, {"id": "D", "text": "logs_MM-DD.tar.gz"}]', 'A', '현재 날짜를 YYYY-MM-DD 형식으로 출력하여 파일명을 생성합니다.'),
    (6942, 23, 3, 141, '다음 스크립트에서 ''date +%F'' 부분을 빈칸으로 바꾸면 어떤 결과가 발생할까요? ''tar -czf logs_$(date +______).tar.gz /path/to/logs/''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "날짜가 포함된 파일명 생성"}, {"id": "B", "text": "오류 발생"}, {"id": "C", "text": "빈 이름의 파일 생성"}, {"id": "D", "text": "현재 시간 포함"}]', 'B', '빈칸으로 두면 명령이 올바르게 실행되지 않아 오류가 발생합니다.'),
    (6943, 23, 3, 142, 'cron의 주기를 지정할 때 사용하는 파일 이름은 무엇인가요?', 'SHORT_ANSWER', NULL, 'crontab', 'cron의 주기를 지정하는 파일은 ''crontab''입니다.'),
    (6944, 23, 3, 143, 'cron의 구문에서 ''분''과 ''시간''을 설정하는 필드는 몇 번째와 몇 번째인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "1번째"}, {"id": "B", "text": "2번째"}, {"id": "C", "text": "3번째"}, {"id": "D", "text": "4번째"}]', '["A", "B"]', '''분''은 1번째 필드, ''시간''은 2번째 필드입니다.'),
    (6945, 23, 3, 144, '다음 `sed` 명령의 결과로 예상되는 출력은 무엇인가요? `echo ''hello world'' | sed ''s/world/universe/''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "hello universe"}, {"id": "B", "text": "hello world"}, {"id": "C", "text": "world universe"}, {"id": "D", "text": "hello"}]', 'A', '`sed` 명령은 ''world''를 ''universe''로 치환하여 ''hello universe''를 출력합니다.'),
    (6946, 23, 3, 145, '다음 `awk` 명령이 실행되었을 때 출력되는 결과는 무엇인가요? `echo ''apple orange banana'' | awk ''{print $2}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "apple"}, {"id": "B", "text": "orange"}, {"id": "C", "text": "banana"}, {"id": "D", "text": "apple orange"}]', 'B', '`awk`는 두 번째 열을 출력하므로 ''orange''가 결과로 나오게 됩니다.'),
    (6947, 23, 3, 146, '다음 `sed` 명령의 빈칸을 채우세요: `sed ''s/\\(.*\\)\\(\\..*\\)/\\1.txt/''`는 파일 확장자를 .txt로 변경합니다. 입력: example.doc, 출력: ______', 'SHORT_ANSWER', NULL, 'example.txt', '입력 ''example.doc''에서 ''.doc'' 부분이 ''.txt''로 변경되어 ''example.txt''가 됩니다.'),
    (6948, 23, 3, 147, '다음 중 `awk`를 사용해 첫 번째와 세 번째 열을 출력하기 위한 올바른 명령어 조합은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "awk ''{print $1, $3}'' file.txt"}, {"id": "B", "text": "awk ''{print $1; print $3}'' file.txt"}, {"id": "C", "text": "awk ''{print $1 + $3}'' file.txt"}, {"id": "D", "text": "awk ''print($1, $3)'' file.txt"}]', '["A", "B"]', '`awk ''{print $1, $3}''`는 첫 번째와 세 번째 열을 동시에 출력하며, `print` 명령문을 두 번 호출하는 것도 가능합니다.'),
    (6949, 23, 3, 148, '다음과 같은 파일이 있습니다: `data.txt` 내용: `1,apple,100
2,orange,200
3,banana,300` 이 파일에서 두 번째 열만 출력하는 `awk` 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'awk -F, ''{print $2}'' data.txt', '첫 번째 필드를 콤마로 구분하기 위해 -F 옵션을 사용하고 두 번째 열을 출력하는 명령입니다.'),
    (6950, 23, 3, 149, '다음 명령어의 역할은 무엇인가요? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 모든 파일을 나열한다."}, {"id": "B", "text": "현재 디렉토리에서 ''txt''라는 문자열이 포함된 파일만 나열한다."}, {"id": "C", "text": "모든 파일을 ''txt''로 변경한다."}, {"id": "D", "text": "파일을 삭제한다."}]', 'B', '''ls -l''의 출력 중 ''txt'' 문자열이 포함된 파일만 필터링하여 나열한다.'),
    (6951, 23, 3, 150, '다음 명령의 동작 결과를 예측하시오: `echo "Hello World" > output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt 파일을 생성하고 내용은 ''Hello World''이다."}, {"id": "B", "text": "output.txt 파일에 ''Hello World''가 추가된다."}, {"id": "C", "text": "output.txt 파일의 내용이 지워진다."}, {"id": "D", "text": "output.txt 파일이 삭제된다."}]', 'A', '''>'' 연산자는 기존 파일을 덮어쓰고 새로운 내용을 작성한다.'),
    (6952, 23, 3, 151, '빈칸을 채우세요: `command 2>&1 > output.log`는 오류를 ___에 기록하게 된다.', 'SHORT_ANSWER', NULL, 'output.log', '''2>&1''은 표준 오류를 표준 출력으로 리다이렉트하고, 그 후에 출력이 ''output.log''로 리다이렉트된다.'),
    (6953, 23, 3, 152, '다음 명령어의 역할은 무엇인가요? `command > output.log 2>&1`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "명령의 표준 출력을 output.log에 기록한다."}, {"id": "B", "text": "명령의 표준 오류를 output.log에 기록한다."}, {"id": "C", "text": "명령의 출력을 화면에 표시한다."}, {"id": "D", "text": "output.log 파일이 삭제된다."}]', '["A", "B"]', '''>''는 표준 출력을 파일로 리다이렉트 하고, ''2>&1''은 표준 오류를 표준 출력으로 리다이렉트하여 같은 파일에 기록하게 한다.'),
    (6954, 23, 3, 153, '다음 코드의 출력 결과는 무엇인가?

VAR=10
if [ $VAR -eq 10 ]; then
  echo "Equal"
fi', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Equal"}, {"id": "B", "text": "Not Equal"}, {"id": "C", "text": "Error"}, {"id": "D", "text": "Nothing"}]', 'A', '변수 VAR의 값이 10이므로 조건문이 참이 되어 ''Equal''이 출력됩니다.'),
    (6955, 23, 3, 154, '다음 코드에서 빈칸에 들어갈 적절한 코드는 무엇인가?

for i in {1..5}; do
  ____
  done', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "echo $i"}, {"id": "B", "text": "print $i"}, {"id": "C", "text": "cout $i"}, {"id": "D", "text": "write $i"}]', 'A', 'Bash에서 값을 출력하기 위해서는 echo 명령어를 사용해야 합니다.'),
    (6956, 23, 3, 155, '다음 중 셸 스크립트에서 사용하는 조건문에 포함되지 않는 키워드는 무엇인가?

A. if
B. then
C. while
D. else', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "if"}, {"id": "B", "text": "then"}, {"id": "C", "text": "while"}, {"id": "D", "text": "else"}]', 'C', 'while은 반복문에서 사용하는 키워드로, 조건문에서는 사용되지 않습니다.'),
    (6957, 23, 3, 156, '조건문을 사용하는 이유는 무엇인가요?', 'SHORT_ANSWER', NULL, '조건에 따라 다른 명령을 실행하기 위해', '조건문을 통해 특정 조건이 참일 때와 거짓일 때 각각 다른 명령어를 실행할 수 있습니다.'),
    (6958, 23, 3, 157, '변수 선언 방법을 모두 선택하세요.

A. VAR=10
B. VAR:10
C. let VAR=10
D. VAR:=10', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "VAR=10"}, {"id": "B", "text": "VAR:10"}, {"id": "C", "text": "let VAR=10"}, {"id": "D", "text": "VAR:=10"}]', '["A", "C"]', 'Bash에서는 VAR=10 또는 let VAR=10 형태로 변수를 선언할 수 있습니다.'),
    (6959, 23, 3, 158, '다음 crontab 항목의 의미는 무엇인가? ''0 12 * * * /path/to/script.sh''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 정오에 script.sh를 실행한다."}, {"id": "B", "text": "매일 12시 1분에 script.sh를 실행한다."}, {"id": "C", "text": "매주 정오에 script.sh를 실행한다."}, {"id": "D", "text": "매달 정오에 script.sh를 실행한다."}]', 'A', '이 crontab 항목은 매일 정오에 지정된 스크립트를 실행하도록 설정되어 있습니다.'),
    (6960, 23, 3, 159, '다음 빈칸을 채우세요: ''*/5 * * * * ____''', 'SHORT_ANSWER', NULL, '/path/to/command', '이 항목은 매 5분마다 지정된 명령어를 실행합니다.'),
    (6961, 23, 3, 160, '다음 중 cron의 주기를 설정하는 올바른 형식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "분 시 일 월 요일"}, {"id": "B", "text": "시간 분 요일 월"}, {"id": "C", "text": "일 월 시 분"}, {"id": "D", "text": "요일 월 시 분"}]', 'A', 'cron의 주기 설정 형식은 ''분 시 일 월 요일'' 순입니다.'),
    (6962, 23, 3, 161, 'cron을 사용하여 매주 월요일과 수요일에 스크립트를 실행하고 싶습니다. 올바른 crontab 항목은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "0 0 * * 1,3 /path/to/script.sh"}, {"id": "B", "text": "0 * * * 1,3 /path/to/script.sh"}, {"id": "C", "text": "0 0 * * 2,4 /path/to/script.sh"}, {"id": "D", "text": "0 0 * * 0,6 /path/to/script.sh"}]', '["A"]', '매주 월요일과 수요일에 스크립트를 실행하려면 ''0 0 * * 1,3'' 형식이 맞습니다.'),
    (6963, 23, 3, 162, '다음 명령어의 출력은 무엇인가요? `echo ''Hello, World!'' > output.txt`', 'SHORT_ANSWER', NULL, 'Hello, World!', 'echo 명령어는 ''Hello, World!''를 출력하고, ''>''를 사용하여 output.txt 파일에 저장합니다.'),
    (6964, 23, 3, 163, '다음 명령어의 결과로 output.txt 파일에 저장되는 내용은 무엇인가요? `ls -l > output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 파일 목록"}, {"id": "B", "text": "에러 메시지"}, {"id": "C", "text": "명령어 실행 결과"}, {"id": "D", "text": "아무것도 저장되지 않음"}]', 'A', 'ls -l 명령어는 현재 디렉토리의 파일 목록을 출력하며, ''>''로 인해 output.txt에 저장됩니다.'),
    (6965, 23, 3, 164, '아래 명령어의 기능은 무엇인가요? `grep ''error'' logfile.txt 2>&1`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "logfile.txt에서 error라는 단어를 찾는다."}, {"id": "B", "text": "logfile.txt의 내용을 모두 출력한다."}, {"id": "C", "text": "error를 포함한 라인을 logfile.txt에 저장한다."}, {"id": "D", "text": "logfile.txt에서 에러 메시지를 무시하고 출력한다."}]', 'A', 'grep 명령어는 logfile.txt에서 ''error''라는 단어를 찾아 출력합니다. ''2>&1''는 에러 출력을 표준 출력으로 리다이렉션합니다.'),
    (6966, 23, 3, 165, '아래 명령어에서 리다이렉션이 사용된 부분을 모두 선택하세요: `command1 | command2 > output.txt 2>&1`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "|"}, {"id": "B", "text": ">"}, {"id": "C", "text": "2>&1"}, {"id": "D", "text": "command2"}]', '["A", "B", "C"]', '''|''는 파이프이며, ''>''와 ''2>&1''는 리다이렉션을 나타냅니다.'),
    (6967, 23, 3, 166, '파이프를 사용할 때, 명령어의 출력이 다음 명령어의 입력으로 어떻게 연결되는지 설명하세요.', 'SHORT_ANSWER', NULL, '명령어의 출력이 파이프를 통해 다음 명령어의 입력으로 전달된다.', '파이프는 이전 명령어의 출력을 다음 명령어의 입력으로 연결합니다.'),
    (6968, 23, 3, 167, '다음 crontab 설정은 어떤 작업을 의미하나요? 0 5 * * * /home/user/script.sh', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 오전 5시에 script.sh 실행"}, {"id": "B", "text": "매일 오후 5시에 script.sh 실행"}, {"id": "C", "text": "매주 월요일 오전 5시에 script.sh 실행"}, {"id": "D", "text": "매일 정오에 script.sh 실행"}]', 'A', 'cron의 형식에서 ''0 5 * * *''는 매일 오전 5시에 작업이 실행됨을 의미합니다.'),
    (6969, 23, 3, 168, '다음 빈칸을 채우세요: ''crontab -e'' 명령어는 _____ 파일을 편집하기 위해 사용됩니다.', 'SHORT_ANSWER', NULL, 'crontab', '''crontab -e''는 사용자의 crontab 설정 파일을 편집하는 명령어입니다.'),
    (6970, 23, 3, 169, '아래의 cron 설정에서 어떤 작업이 실행될까요? ''30 14 * * 1 /home/user/backup.sh''', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매주 월요일 오후 2시 30분에 backup.sh 실행"}, {"id": "B", "text": "매일 오후 2시 30분에 backup.sh 실행"}, {"id": "C", "text": "매주 일요일 오후 2시 30분에 backup.sh 실행"}, {"id": "D", "text": "매달 1일 오후 2시 30분에 backup.sh 실행"}]', 'A', 'cron 설정에서 ''30 14 * * 1''은 매주 월요일 오후 2시 30분에 작업이 실행됨을 의미합니다.'),
    (6971, 23, 3, 170, '다음 중 crontab에서 허용하는 필드가 아닌 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "분"}, {"id": "B", "text": "시간"}, {"id": "C", "text": "파일명"}, {"id": "D", "text": "요일"}]', '["C"]', 'crontab은 분, 시간, 일, 월, 요일의 필드를 허용하지만 파일명은 필드에 해당하지 않습니다.'),
    (6972, 23, 3, 171, '다음 명령어의 출력은 무엇인가? `ls -l | grep ''.txt''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 모든 .txt 파일 목록"}, {"id": "B", "text": "현재 디렉토리의 모든 파일 목록"}, {"id": "C", "text": "현재 디렉토리의 모든 디렉토리 목록"}, {"id": "D", "text": "현재 디렉토리가 비어 있다는 메시지"}]', 'A', '이 명령어는 ''ls -l''의 결과 중에서 ''.txt'' 파일만 필터링하여 출력합니다.'),
    (6973, 23, 3, 172, '다음 명령어의 기능은 무엇인가? `echo ''Error occurred'' 2> error.log`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "표준 출력을 error.log에 저장"}, {"id": "B", "text": "표준 오류를 error.log에 저장"}, {"id": "C", "text": "error.log에 메시지를 추가"}, {"id": "D", "text": "에러 메시지 없이 실행"}]', 'B', '이 명령어는 표준 오류를 error.log 파일에 저장합니다.'),
    (6974, 23, 3, 173, '다음 빈칸을 채우시오: `cat file.txt > output.txt`는 file.txt의 내용을 ________.', 'SHORT_ANSWER', NULL, 'output.txt에 저장한다', '리다이렉션을 사용하여 file.txt 내용을 output.txt에 저장합니다.'),
    (6975, 23, 3, 174, '다음 중 올바른 리다이렉션 조합은 무엇인가? (복수정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "command > file"}, {"id": "B", "text": "command >> file"}, {"id": "C", "text": "command 2>&1 file"}, {"id": "D", "text": "command 2> file"}]', '["A", "B", "D"]', 'A, B, D는 올바른 리다이렉션 조합이며, C는 오류 출력을 파일로 보내는 것이 아니라 출력으로 보내려는 문법 오류입니다.'),
    (6976, 23, 3, 175, '아래 명령어의 결과는 무엇인가요? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 모든 txt 파일 목록"}, {"id": "B", "text": "현재 디렉토리의 모든 파일 목록"}, {"id": "C", "text": "텍스트 파일의 개수"}, {"id": "D", "text": "파일의 총 크기"}]', 'A', '이 명령어는 ls -l의 결과에서 ''txt''라는 문자열이 포함된 파일만 출력합니다.'),
    (6977, 23, 3, 176, '다음 코드의 빈칸에 들어갈 알맞은 문자는 무엇인가요? `command > output.txt`는 기존의 내용을 ___합니다.', 'SHORT_ANSWER', NULL, '덮어쓴다', '리다이렉션 `>`는 파일의 기존 내용을 덮어씁니다.'),
    (6978, 23, 3, 177, '아래 코드의 결과는 무엇인가요? `echo ''Error'' >&2`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "표준 출력에 ''Error''를 출력"}, {"id": "B", "text": "표준 에러에 ''Error''를 출력"}, {"id": "C", "text": "파일에 ''Error''를 저장"}, {"id": "D", "text": "아무것도 출력하지 않는다"}]', 'B', '이 명령어는 ''Error''를 표준 에러 스트림으로 출력합니다.'),
    (6979, 23, 3, 178, '아래 명령어를 통해 어떤 작업을 수행할 수 있습니까? `cat file.txt | sort | uniq`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "file.txt 내용을 정렬한다."}, {"id": "B", "text": "file.txt의 중복된 줄을 제거한다."}, {"id": "C", "text": "file.txt의 내용을 파일로 저장한다."}, {"id": "D", "text": "file.txt의 내용을 화면에 출력한다."}]', '["A", "B", "D"]', '이 명령어는 file.txt의 내용을 정렬하고 중복된 줄을 제거한 후 결과를 화면에 출력합니다.'),
    (6980, 23, 3, 179, '다음 중 cron 표현식 ''0 12 * * *''의 의미는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "매일 정오 12시에 실행"}, {"id": "B", "text": "매일 자정 12시에 실행"}, {"id": "C", "text": "매주 월요일 12시에 실행"}, {"id": "D", "text": "매달 1일 12시에 실행"}]', 'A', '''0 12 * * *''는 매일 정오 12시에 해당 작업을 실행한다는 의미입니다.'),
    (6981, 23, 3, 180, '다음 코드를 완성하세요: ''____ * * * * /path/to/script.sh'' 이 표현식은 매 분마다 스크립트를 실행합니다.', 'SHORT_ANSWER', NULL, '*/1', '''*/1''은 매 분마다 실행된다는 의미입니다.'),
    (6982, 23, 3, 181, '다음 중 cron작업을 등록하는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "crontab -e"}, {"id": "B", "text": "cronjob add"}, {"id": "C", "text": "schedule add"}, {"id": "D", "text": "cron add"}]', 'A', '''crontab -e'' 명령어를 사용하여 cron 작업을 등록할 수 있습니다.'),
    (6983, 23, 3, 182, '아래 cron 표현식에 대해 올바른 설명을 선택하세요:
''0 8 * * 1,5''', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "매주 월요일과 금요일 8시에 실행"}, {"id": "B", "text": "매주 화요일과 목요일 8시에 실행"}, {"id": "C", "text": "매일 8시에 실행"}, {"id": "D", "text": "매주 주말 8시에 실행"}]', '["A"]', '''0 8 * * 1,5''는 매주 월요일과 금요일 8시에 해당 작업이 실행된다는 의미입니다.'),
    (6984, 23, 3, 183, 'cron을 사용하여 자동화 스크립트를 설정하면 어떤 이점이 있나요?', 'SHORT_ANSWER', NULL, '작업의 자동화와 시간 절약', 'cron을 통해 작업을 자동으로 실행하면 수동으로 작업을 수행할 필요가 없으므로 시간과 노력을 절약할 수 있습니다.'),
    (6985, 23, 3, 184, '다음 명령어의 출력은 무엇인가요? `ls -l | grep ''txt''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리의 txt 파일 목록"}, {"id": "B", "text": "현재 디렉토리의 모든 파일 목록"}, {"id": "C", "text": "에러 메시지"}, {"id": "D", "text": "빈 출력"}]', 'A', 'grep 명령은 주어진 패턴과 일치하는 문자열을 찾으며, ''txt''가 포함된 파일만 출력합니다.'),
    (6986, 23, 3, 185, '다음 코드의 결과로 생성될 파일 이름을 빈칸에 채우세요: `echo ''Hello World'' > ____`', 'SHORT_ANSWER', NULL, 'output.txt', '''>'' 리다이렉션을 사용하여 ''Hello World''를 output.txt 파일에 저장합니다.'),
    (6987, 23, 3, 186, '다음 명령어의 기능을 설명하세요: `command 2>&1`', 'SHORT_ANSWER', NULL, '표준 오류를 표준 출력으로 리다이렉션', '2>&1은 표준 오류(2)를 표준 출력(1)으로 리다이렉션하여 에러 메시지를 캡처합니다.'),
    (6988, 23, 3, 187, '다음 중 파이프와 리다이렉션에 대한 설명으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "파이프는 명령어를 연결하는 데 사용된다."}, {"id": "B", "text": "리다이렉션은 출력을 파일로 전송할 수 있다."}, {"id": "C", "text": "리다이렉션은 입력만 수정할 수 있다."}, {"id": "D", "text": "파이프와 리다이렉션은 오류처리에 사용되지 않는다."}]', '["A", "B"]', 'A와 B는 파이프와 리다이렉션의 실제 용도와 일치합니다.'),
    (6989, 23, 3, 188, '다음 리다이렉션 명령어 중 파일에 내용을 추가하는 데 사용되는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": ">"}, {"id": "B", "text": ">>"}, {"id": "C", "text": "|"}, {"id": "D", "text": "2>&1"}]', 'B', '''>>''는 기존 파일에 내용을 추가하는 리다이렉션 기호입니다.'),
    (6990, 23, 3, 189, '다음 명령어의 출력 결과는 무엇인가요? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "\\"txt\\"가 포함된 파일 목록"}, {"id": "B", "text": "모든 파일 목록"}, {"id": "C", "text": "에러 메시지"}, {"id": "D", "text": "빈 문자열"}]', 'A', '`ls -l`의 결과 중 ''txt''가 포함된 파일만 필터링하여 출력됩니다.'),
    (6991, 23, 3, 190, '다음 코드의 빈칸에 들어갈 알맞은 명령어는 무엇인가요? `command > output.txt`에서 output.txt에 덮어쓰기를 원치 않는 경우, `command ___ output.txt`를 사용하여 추가할 수 있습니다.', 'SHORT_ANSWER', NULL, '>>', '`>>`를 사용하면 파일에 내용을 추가할 수 있습니다.'),
    (6992, 23, 3, 191, '다음 중 리다이렉션 설명으로 올바른 것은 무엇인가요? `command > output.txt 2>&1`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "표준 출력과 표준 에러를 output.txt로 보낸다."}, {"id": "B", "text": "오직 표준 출력만 output.txt로 보낸다."}, {"id": "C", "text": "output.txt 파일을 생성하지 않는다."}, {"id": "D", "text": "명령어의 입력을 output.txt로 보낸다."}]', 'A', '이 명령어는 표준 출력과 표준 에러를 모두 output.txt 파일로 보냅니다.'),
    (6993, 23, 3, 192, '다음 중 파이프(`|`)의 올바른 사용 예시로 가장 적절한 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "ls -l | more"}, {"id": "B", "text": "cat file.txt | sort"}, {"id": "C", "text": "echo hello | grep h"}, {"id": "D", "text": "command > output.txt"}]', '["A", "B", "C"]', 'A, B, C 모두 파이프를 사용하여 명령어의 출력을 다음 명령어의 입력으로 전달합니다.'),
    (6994, 23, 3, 193, '다음 명령어의 결과는 무엇입니까? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "\\"txt\\"가 포함된 파일 목록"}, {"id": "B", "text": "모든 파일 목록"}, {"id": "C", "text": "오류 메시지"}, {"id": "D", "text": "빈 출력"}]', 'A', '"ls -l"의 결과 중에서 ''txt''가 포함된 줄만 보여줍니다.'),
    (6995, 23, 3, 194, '아래 명령어는 어떤 작업을 수행합니까? `echo "Hello, World!" > output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt를 생성하고 내용을 쓴다."}, {"id": "B", "text": "output.txt의 내용을 추가한다."}, {"id": "C", "text": "출력을 화면에 표시한다."}, {"id": "D", "text": "오류 메시지를 출력한다."}]', 'A', '이 명령은 output.txt 파일을 생성하고 ''Hello, World!''라는 내용을 씁니다.'),
    (6996, 23, 3, 195, '다음 빈칸에 들어갈 올바른 내용을 채우세요: `command1 2>&1 | command2`에서 `command1`의 에러 출력이 `command2`로 보내집니다.', 'SHORT_ANSWER', NULL, '표준 출력', '2>&1는 에러 출력을 표준 출력으로 리다이렉션합니다.'),
    (6997, 23, 3, 196, '아래 명령어에서 어떤 파일에 내용을 추가할까요? `echo "New line" >> existing_file.txt`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "existing_file.txt"}, {"id": "B", "text": "output.txt"}, {"id": "C", "text": "New line"}, {"id": "D", "text": "빈 파일"}]', '["A"]', '이 명령은 existing_file.txt에 ''New line''을 추가합니다.'),
    (6998, 23, 3, 197, '다음 중 cron 표현식의 올바른 형식은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "분 시 일 월 요일"}, {"id": "B", "text": "시 분 월 일 요일"}, {"id": "C", "text": "일 월 시 분 요일"}, {"id": "D", "text": "요일 월 시 일 분"}]', 'A', 'cron 표현식은 ''분 시 일 월 요일''의 형식을 따릅니다.'),
    (6999, 23, 3, 198, '다음 스크립트에서 빈칸에 들어갈 명령어는 무엇인가요? `tar -czf /backup/backup_$(date +%F).tar.gz __`', 'SHORT_ANSWER', NULL, '/home/user/data', '빈칸에는 백업할 데이터의 경로인 ''/home/user/data''가 들어갑니다.'),
    (7000, 23, 3, 199, '다음 중 자동화 스크립트의 예시로 맞는 것은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "#!/bin/bash\\necho Hello World\\n"}, {"id": "B", "text": "echo Hello World\\n"}, {"id": "C", "text": "date\\n"}, {"id": "D", "text": "#!/bin/bash\\ndate; echo Hello World\\n"}]', 'D', '예시 D는 Bash 스크립트 헤더와 함께 여러 명령을 포함하고 있어 자동화 스크립트의 형태입니다.'),
    (7001, 23, 3, 200, '다음 중 cron탭에서 매일 오후 3시에 스크립트를 실행하도록 예약하는 표현식은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "0 15 * * *"}, {"id": "B", "text": "15 3 * * *"}, {"id": "C", "text": "0 3 * * *"}, {"id": "D", "text": "0 15 * * 1"}]', '["A", "B"]', 'A와 B는 모두 매일 오후 3시에 실행되는 cron 표현식입니다.'),
    (7002, 23, 3, 201, '다음 `sed` 명령어의 결과는 무엇인가요? `echo ''apple banana cherry'' | sed ''s/banana/kiwi/''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "apple kiwi cherry"}, {"id": "B", "text": "apple banana cherry"}, {"id": "C", "text": "kiwi cherry"}, {"id": "D", "text": "banana cherry"}]', 'A', '`sed`는 ''banana''를 ''kiwi''로 치환하므로 출력은 ''apple kiwi cherry''입니다.'),
    (7003, 23, 3, 202, '다음 `awk` 명령어의 결과는 무엇인가요? `echo ''one two three'' | awk ''{print $2}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "one"}, {"id": "B", "text": "two"}, {"id": "C", "text": "three"}, {"id": "D", "text": "one two"}]', 'B', '`awk`는 각 행에서 두 번째 필드를 출력하므로 ''two''가 출력됩니다.'),
    (7004, 23, 3, 203, '다음 코드의 결과를 예측하세요. `echo ''1 2 3 4 5'' | awk ''{for(i=1;i<=NF;i++) if($i%2==0) print $i}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1 3 5"}, {"id": "B", "text": "2 4"}, {"id": "C", "text": "1 2 3 4 5"}, {"id": "D", "text": "1 2 3 4"}]', 'B', '이 코드는 짝수인 필드만 출력하므로 ''2 4''가 출력됩니다.'),
    (7005, 23, 3, 204, '다음 명령어를 사용하여 ''data.txt'' 파일에서 1열과 3열을 출력하고자 할 때 사용할 수 있는 `awk` 명령어는 무엇인가요?', 'SHORT_ANSWER', NULL, 'awk ''{print $1, $3}'' data.txt', '`awk ''{print $1, $3}'' data.txt` 명령어는 1열과 3열을 출력합니다.'),
    (7006, 23, 3, 205, '다음 `sed` 명령어를 사용하여, ''hello world''에서 ''world''를 ''there''로 바꾸는 명령어는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "sed ''s/world/there/''"}, {"id": "B", "text": "sed ''s/there/world/''"}, {"id": "C", "text": "sed ''s/hello/hi/''"}, {"id": "D", "text": "sed ''s/world/hello/''"}]', '["A"]', '''sed ''s/world/there/'''' 명령어는 ''world''를 ''there''로 바꾸는 올바른 명령어입니다.'),
    (7007, 23, 3, 206, '다음 명령어의 역할은 무엇인가요? `ls -l > output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "ls 명령의 출력을 output.txt 파일에 저장한다."}, {"id": "B", "text": "output.txt 파일을 출력한다."}, {"id": "C", "text": "ls 명령의 오류를 output.txt 파일에 저장한다."}, {"id": "D", "text": "ls 명령을 실행하지 않는다."}]', 'A', '이 명령은 ls 명령의 출력을 output.txt 파일에 리다이렉션하는 것입니다.'),
    (7008, 23, 3, 207, '아래 명령의 결과로 ''output.txt'' 파일이 어떻게 변경되나요? `echo ''Hello World'' >> output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt 파일이 삭제된다."}, {"id": "B", "text": "output.txt 파일에 ''Hello World''가 추가된다."}, {"id": "C", "text": "output.txt 파일의 내용을 덮어쓴다."}, {"id": "D", "text": "output.txt 파일이 비어있게 된다."}]', 'B', '''>>''는 파일에 내용을 추가하는 리다이렉션이므로, ''Hello World''가 output.txt에 추가됩니다.'),
    (7009, 23, 3, 208, '다음 코드의 빈칸을 채우세요: `command1 | command2 > ____`', 'SHORT_ANSWER', NULL, 'output.txt', '이 명령어는 command1의 출력을 command2에 전달한 후, command2의 출력을 output.txt 파일에 저장합니다.'),
    (7010, 23, 3, 209, '다음 중 파이프(`|`)를 사용하는 경우를 모두 고르세요: `cat file.txt | sort | uniq`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "file.txt의 내용을 정렬한다."}, {"id": "B", "text": "중복된 내용을 제거한다."}, {"id": "C", "text": "file.txt를 새 파일로 저장한다."}, {"id": "D", "text": "명령어가 실패할 경우 다음 명령어를 실행한다."}]', '["A", "B"]', '이 명령은 file.txt의 내용을 읽고, 정렬한 후 중복된 행을 제거합니다. C와 D는 파이프와 관련이 없습니다.'),
    (7011, 23, 3, 210, '다음 명령의 결과는 무엇인가요? `ls -l | grep "txt"`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 디렉토리에서 ''txt''가 포함된 파일 목록"}, {"id": "B", "text": "모든 디렉토리의 파일 목록"}, {"id": "C", "text": "오류 메시지"}, {"id": "D", "text": "빈 목록"}]', 'A', '''ls -l''의 출력 중 ''txt''라는 문자열이 포함된 파일만 필터링하기 때문입니다.'),
    (7012, 23, 3, 211, '명령의 출력을 파일에 저장할 때 사용하는 리다이렉션 기호는 무엇인가요?', 'SHORT_ANSWER', NULL, '>', '''>'' 기호는 명령의 출력을 파일에 저장하는 데 사용됩니다.'),
    (7013, 23, 3, 212, '다음 중 오류 출력을 표준 출력으로 리다이렉션하는 방법은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "command 2>&1"}, {"id": "B", "text": "command > output.txt"}, {"id": "C", "text": "command 1>&2"}, {"id": "D", "text": "command &> output.txt"}]', 'A', '''command 2>&1''은 오류 출력을 표준 출력으로 리다이렉션합니다.'),
    (7014, 23, 3, 213, '다음 명령에서 빈칸에 들어갈 알맞은 기호는 무엇인가요? `command > output.txt ____`', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "2>&1"}, {"id": "B", "text": ">>"}, {"id": "C", "text": "2>"}, {"id": "D", "text": ">&"}]', '["A", "B"]', '''2>&1''는 오류 출력을 표준 출력으로, ''>>''는 파일에 내용을 추가하는 기호입니다.'),
    (7015, 23, 3, 214, '다음 명령은 어떤 작업을 수행하나요? `command >> output.txt`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "output.txt를 생성하고 새로운 내용을 쓴다"}, {"id": "B", "text": "output.txt에 내용을 추가한다"}, {"id": "C", "text": "output.txt의 내용을 삭제한다"}, {"id": "D", "text": "명령어의 결과를 출력한다"}]', 'B', '''>>''는 기존 파일의 끝에 내용을 추가하는 것입니다.'),
    (7016, 23, 3, 215, '다음 `sed` 명령의 결과는 무엇인가요? <br> `echo ''Hello World'' | sed ''s/World/Sed/''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hello Sed"}, {"id": "B", "text": "Hello World"}, {"id": "C", "text": "Sed World"}, {"id": "D", "text": "Hello Hello"}]', 'A', '`sed` 명령은 ''World''를 ''Sed''로 바꾸기 때문에 결과는 ''Hello Sed''입니다.'),
    (7017, 23, 3, 216, '다음 `awk` 명령의 결과는 무엇인가요? <br> `echo ''1 2 3'' | awk ''{print $2}''`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "1 2 3"}]', 'B', '`awk` 명령은 두 번째 필드인 ''2''를 출력하기 때문에 결과는 ''2''입니다.'),
    (7018, 23, 3, 217, '다음 `sed` 명령에서 빈칸에 들어갈 적절한 명령어는 무엇인가요? <br> `sed ''s/old/new/g'' <blank>`', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "example.txt"}, {"id": "B", "text": "Hello World"}, {"id": "C", "text": "This is old"}, {"id": "D", "text": "new old"}]', 'A', '`sed`는 입력 파일을 지정해야 하므로, ''example.txt''가 적절합니다.'),
    (7019, 23, 3, 218, '다음 중 `awk`로 여러 필드를 출력하는 방법으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "awk ''{print $1, $2}''"}, {"id": "B", "text": "awk ''{print $3}''"}, {"id": "C", "text": "awk ''{print $1 + $2}''"}, {"id": "D", "text": "awk ''{print $*}''"}]', '["A", "B"]', '`awk ''{print $1, $2}''`와 `awk ''{print $3}''`는 각각 첫 두 필드와 세 번째 필드를 출력하는 올바른 방법입니다.'),
    (7020, 23, 3, 219, '`sed`와 `awk`의 차이점은 무엇인가요?', 'SHORT_ANSWER', NULL, 'sed는 스트림 편집기이고, awk는 데이터 처리 및 보고서 생성에 특화된 프로그래밍 언어입니다.', '`sed`는 텍스트를 직접 수정하는 데 사용되며, `awk`는 필드를 기반으로 데이터를 처리하는 데 강력합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 정보처리기사 > 데이터통신과 OS (90문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7021, 24, 1, 1, 'TDM은 어떤 방법으로 데이터를 전송하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "시간적으로 분할하여 전송한다."}, {"id": "B", "text": "주파수적으로 분할하여 전송한다."}, {"id": "C", "text": "주소적으로 분할하여 전송한다."}, {"id": "D", "text": "패킷 단위로 전송한다."}]', 'A', 'TDM(Time Division Multiplexing)은 여러 신호를 시간적으로 분할하여 동시에 전송하는 방법입니다.'),
    (7022, 24, 1, 2, 'CRC의 주요 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 암호화"}, {"id": "B", "text": "오류 검출"}, {"id": "C", "text": "속도 향상"}, {"id": "D", "text": "신호 증폭"}]', 'B', 'CRC(Cyclic Redundancy Check)는 데이터 전송 시 발생할 수 있는 오류를 검출하기 위한 방법입니다.'),
    (7023, 24, 1, 3, '아날로그 신호와 디지털 신호의 차이는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "아날로그는 이산적이고 디지털은 연속적이다."}, {"id": "B", "text": "아날로그는 연속적이고 디지털은 이산적이다."}, {"id": "C", "text": "모두 연속적이다."}, {"id": "D", "text": "모두 이산적이다."}]', 'B', '아날로그 신호는 연속적인 신호이고, 디지털 신호는 이산적인 신호입니다.'),
    (7024, 24, 1, 4, '패킷 교환의 장점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "유연성"}, {"id": "B", "text": "효율성"}, {"id": "C", "text": "보안성"}, {"id": "D", "text": "신뢰성"}]', '["A", "B"]', '패킷 교환 기술은 데이터를 패킷 단위로 나누어 전송하여 유연성과 효율성을 높입니다.'),
    (7025, 24, 1, 5, '해밍 코드는 어떤 목적으로 사용되나요?', 'SHORT_ANSWER', NULL, '오류 정정', '해밍 코드는 전송 중 발생할 수 있는 오류를 정정하기 위해 사용됩니다.'),
    (7026, 24, 1, 6, '해밍 코드의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '오류 검출 및 수정', '해밍 코드는 데이터를 전송하는 과정에서 발생할 수 있는 오류를 검출하고 수정하기 위한 방법이다.'),
    (7027, 24, 1, 7, 'TDM의 가장 큰 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "신호를 시간적으로 나누어 전송한다."}, {"id": "B", "text": "신호를 주파수적으로 나누어 전송한다."}, {"id": "C", "text": "신호를 공간적으로 나누어 전송한다."}, {"id": "D", "text": "신호를 코드로 나누어 전송한다."}]', 'A', 'TDM(시분할 다중화)은 여러 신호를 시간적으로 나누어 각각의 시간 슬롯에 따라 전송하는 방식이다.'),
    (7028, 24, 1, 8, '다중화의 종류 중에서 WDM의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다양한 파장을 이용해 데이터 전송."}, {"id": "B", "text": "시간을 나눠서 데이터 전송."}, {"id": "C", "text": "신호의 진폭을 변화시켜 데이터 전송."}, {"id": "D", "text": "데이터를 패킷으로 나누어 전송."}]', 'A', 'WDM(파장 분할 다중화)은 여러 개의 광신호를 서로 다른 파장을 이용하여 동시에 전송하는 기술이다.'),
    (7029, 24, 1, 9, '슬라이딩 윈도우 프로토콜은 어떤 목적으로 사용되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 흐름 제어."}, {"id": "B", "text": "오류 검출."}, {"id": "C", "text": "신호 증폭."}, {"id": "D", "text": "데이터 압축."}]', '["A"]', '슬라이딩 윈도우 프로토콜은 송수신 간의 데이터 흐름을 제어하고, 전송 효율을 높이기 위해 사용된다.'),
    (7030, 24, 1, 10, '패킷 교환의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "전용 경로를 설정한다."}, {"id": "B", "text": "데이터를 작은 패킷으로 나누어 전송한다."}, {"id": "C", "text": "속도가 느리다."}, {"id": "D", "text": "안정성이 높다."}]', 'B', '패킷 교환은 데이터를 작은 패킷으로 나누어 전송하여 네트워크 효율성을 극대화합니다.'),
    (7031, 24, 1, 11, 'FDM과 TDM의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "주파수를 사용한다."}, {"id": "B", "text": "시간을 분할하여 데이터를 전송한다."}, {"id": "C", "text": "다수의 신호를 동시에 전송할 수 있다."}, {"id": "D", "text": "모두 디지털 신호를 사용한다."}]', 'C', 'FDM과 TDM은 모두 다수의 신호를 동시에 전송할 수 있는 멀티플렉싱 기법입니다.'),
    (7032, 24, 1, 12, '슬라이딩 윈도우 기법은 무엇을 위해 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 암호화"}, {"id": "B", "text": "데이터 흐름 제어"}, {"id": "C", "text": "신호의 변조"}, {"id": "D", "text": "에러 검출"}]', 'B', '슬라이딩 윈도우 기법은 데이터의 흐름 제어를 위한 방법으로 사용됩니다.'),
    (7033, 24, 1, 13, 'TDM과 FDM의 차이점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "TDM은 시간 분할이고, FDM은 주파수 분할이다."}, {"id": "B", "text": "둘 다 신호의 멀티플렉싱 기법이다."}, {"id": "C", "text": "TDM은 아날로그 신호에만 사용된다."}, {"id": "D", "text": "FDM은 디지털 신호에만 사용된다."}]', '["A", "B"]', 'TDM은 시간 분할을 사용하고, FDM은 주파수 분할을 사용하며 둘 모두 신호의 멀티플렉싱 기법입니다.'),
    (7034, 24, 1, 14, 'WDM의 용도는 무엇인가?', 'SHORT_ANSWER', NULL, '광통신에서 여러 파장의 신호를 동시에 전송하기 위함입니다.', 'WDM은 파장 분할 다중화로, 광통신에서 여러 파장의 신호를 동시에 전송하여 통신 용량을 증가시키는 데 사용됩니다.'),
    (7035, 24, 1, 15, 'inode는 무엇을 저장하는 구조인가?', 'SHORT_ANSWER', NULL, '파일의 메타데이터', 'inode는 파일의 메타데이터를 저장하는 데이터 구조입니다.'),
    (7036, 24, 1, 16, 'C-SCAN 디스크 스케줄링의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원형으로 디스크를 스캔한다."}, {"id": "B", "text": "가장 짧은 접근 시간을 보장한다."}, {"id": "C", "text": "모든 요청을 처리한 후 정지한다."}, {"id": "D", "text": "FIFO 방식으로 요청을 처리한다."}]', 'A', 'C-SCAN은 디스크의 한 쪽 끝에서 다른 쪽 끝으로 원형으로 스캔하는 방식입니다.'),
    (7037, 24, 1, 17, '프로세스 상태에 포함되지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "준비"}, {"id": "B", "text": "실행"}, {"id": "C", "text": "대기"}, {"id": "D", "text": "종료"}, {"id": "E", "text": "대기 중지"}]', '["E"]', '프로세스 상태는 준비, 실행, 대기, 종료로 나뉘며, 대기 중지는 포함되지 않습니다.'),
    (7038, 24, 1, 18, '스래싱 현상은 어떤 상황을 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CPU 사용률 증가"}, {"id": "B", "text": "메모리 부족으로 성능 저하"}, {"id": "C", "text": "디스크 접근 시간 증가"}, {"id": "D", "text": "프로세스 종료"}]', 'B', '스래싱은 메모리 부족으로 인해 성능 저하가 발생하는 현상을 의미합니다.'),
    (7039, 24, 1, 19, '운영체제에서 프로세스 스케줄링의 주목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "CPU의 효율적 사용"}, {"id": "B", "text": "디스크 공간 확보"}, {"id": "C", "text": "메모리 확장"}, {"id": "D", "text": "네트워크 속도 향상"}]', 'A', '프로세스 스케줄링은 CPU 자원을 효율적으로 사용하기 위해 프로세스를 관리하는 역할을 합니다.'),
    (7040, 24, 1, 20, '교착상태를 예방하기 위한 방법 중 올바르지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자원 할당 그래프 사용"}, {"id": "B", "text": "자원 요청 순서 정하기"}, {"id": "C", "text": "우선순위 기반 스케줄링"}, {"id": "D", "text": "자원 요청 시 대기"}]', 'D', '교착상태를 예방하기 위해서는 자원 요청 시 대기를 피해야 합니다.'),
    (7041, 24, 1, 21, '워킹 셋 모델은 주로 어떤 문제를 해결하기 위해 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "페이지 교체 문제"}, {"id": "B", "text": "프로세스 스케줄링 문제"}, {"id": "C", "text": "디스크 입출력 문제"}, {"id": "D", "text": "네트워크 지연 문제"}]', 'A', '워킹 셋 모델은 프로세스의 페이지 교체를 최소화하여 성능을 향상시키기 위해 사용됩니다.'),
    (7042, 24, 1, 22, '페이지 교체 알고리즘 중 FIFO의 전체적인 원리는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "가장 오래된 페이지를 교체"}, {"id": "B", "text": "가장 최근에 사용된 페이지를 교체"}, {"id": "C", "text": "사용 빈도가 가장 낮은 페이지를 교체"}, {"id": "D", "text": "자주 사용되는 페이지를 유지"}]', '["A"]', 'FIFO(First In First Out)는 가장 오래된 페이지를 교체하는 방식입니다.'),
    (7043, 24, 1, 23, 'UNIX 운영체제의 주요 특징 중 하나는 무엇인가?', 'SHORT_ANSWER', NULL, '다중 사용자 환경 지원', 'UNIX는 여러 사용자가 동시에 시스템을 사용할 수 있도록 지원하는 다중 사용자 운영체제입니다.'),
    (7044, 24, 1, 24, 'FDM의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 신호를 동시에 전송하기 위해 주파수를 나누는 기술"}, {"id": "B", "text": "데이터 압축 방법"}, {"id": "C", "text": "신호의 오류를 체크하는 방법"}, {"id": "D", "text": "데이터 암호화 기술"}]', 'A', 'FDM은 여러 신호를 동시에 전송하기 위해 주파수를 나누는 기술입니다.'),
    (7045, 24, 1, 25, '해밍 코드의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 저장"}, {"id": "B", "text": "데이터 전송 중 오류를 검출하고 수정"}, {"id": "C", "text": "데이터를 암호화"}, {"id": "D", "text": "통신 속도 증가"}]', 'B', '해밍 코드는 데이터 전송 중 발생할 수 있는 오류를 검출하고 수정하는데 사용됩니다.'),
    (7046, 24, 1, 26, '디지털 신호의 특징이 아닌 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "명확한 두 가지 상태"}, {"id": "B", "text": "간섭에 강함"}, {"id": "C", "text": "연속적인 값"}, {"id": "D", "text": "정보를 이진수로 표현"}]', 'C', '디지털 신호는 이산적인 두 가지 상태(0과 1)를 가지며, 연속적인 값은 아날로그 신호의 특징입니다.'),
    (7047, 24, 1, 27, '오류 제어에서 사용하는 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "패리티 비트"}, {"id": "B", "text": "흐름 제어"}, {"id": "C", "text": "해밍 코드"}, {"id": "D", "text": "신호 증폭"}]', '["A", "C"]', '오류 제어에는 패리티 비트와 해밍 코드와 같은 방법이 사용됩니다.'),
    (7048, 24, 1, 28, '흐름 제어의 주요 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 송수신 속도를 조절하여 데이터 손실 방지', '흐름 제어의 주요 목적은 송신자와 수신자 간의 데이터 송수신 속도를 조절하여 데이터 손실을 방지하는 것입니다.'),
    (7049, 24, 1, 29, 'UNIX에서 파일의 메타데이터 관리를 위해 사용되는 구조체는 무엇인가?', 'SHORT_ANSWER', NULL, 'inode', 'inode는 파일의 메타데이터를 저장하는 데이터 구조로, 파일의 위치, 크기 등의 정보를 포함합니다.'),
    (7050, 24, 1, 30, '다음 중 교착상태를 방지하기 위한 알고리즘은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "은행원 알고리즘"}, {"id": "B", "text": "FCFS"}, {"id": "C", "text": "SJF"}, {"id": "D", "text": "RR"}]', 'A', '은행원 알고리즘은 프로세스의 자원 요청이 안전한지 확인하여 교착상태를 방지하는 방법입니다.'),
    (7051, 24, 1, 31, 'FCFS(First-Come, First-Served) 디스크 스케줄링의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 짧은 작업을 우선 처리한다."}, {"id": "B", "text": "요청이 들어온 순서대로 처리한다."}, {"id": "C", "text": "우선순위 큐를 사용한다."}, {"id": "D", "text": "반복적인 접근을 줄인다."}]', 'B', 'FCFS는 디스크 요청이 들어온 순서로 처리하는 스케줄링 방식입니다.'),
    (7052, 24, 1, 32, '운영체제에서 ''워킹 셋''의 개념은 어떤 목적으로 사용되는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "프로세스의 메모리 최적화"}, {"id": "B", "text": "교착상태 예방"}, {"id": "C", "text": "자원 할당 안전성 검사"}, {"id": "D", "text": "디스크 접근 최소화"}]', '["A"]', '''워킹 셋''은 프로세스의 현재 활성화된 페이지를 관리하여 메모리 사용을 최적화하는 기법입니다.'),
    (7053, 24, 1, 33, 'WDM은 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파장 분할 다중화"}, {"id": "B", "text": "주파수 분할 다중화"}, {"id": "C", "text": "시간 분할 다중화"}, {"id": "D", "text": "신호 변조"}]', 'A', 'WDM은 파장 분할 다중화를 의미하며, 하나의 광섬유에서 여러 신호를 동시에 전송할 수 있게 해줍니다.'),
    (7054, 24, 1, 34, '슬라이딩 윈도우 프로토콜의 주된 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송 중 패킷 흐름 제어"}, {"id": "B", "text": "신호 변조"}, {"id": "C", "text": "회선 교환"}, {"id": "D", "text": "다중화"}]', 'A', '슬라이딩 윈도우 프로토콜은 데이터 전송 중 패킷의 흐름을 제어하여 효율적인 전송을 가능하게 합니다.'),
    (7055, 24, 1, 35, 'TDM은 어떤 방식의 다중화인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파장 분할 다중화"}, {"id": "B", "text": "주파수 분할 다중화"}, {"id": "C", "text": "시간 분할 다중화"}, {"id": "D", "text": "패킷 분할 다중화"}]', 'C', 'TDM은 시간 분할 다중화로, 특정 시간 슬롯에 신호를 할당하여 전송하는 방식을 의미합니다.'),
    (7056, 24, 1, 36, '다음 중 디지털 신호 변조의 목적은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "전송 거리 증가"}, {"id": "B", "text": "데이터 통신의 신뢰성 향상"}, {"id": "C", "text": "전송 속도 감소"}, {"id": "D", "text": "신호 간섭 감소"}]', '["A", "B", "D"]', '디지털 신호 변조의 목적은 전송 거리 증가, 데이터 통신의 신뢰성 향상 및 신호 간섭 감소입니다.'),
    (7057, 24, 1, 37, '회선 교환의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '두 지점 간에 전송 경로를 고정하여 통신하는 방식', '회선 교환은 두 지점 간에 전송 경로를 고정하여 통신하는 방식을 의미합니다.'),
    (7058, 24, 1, 38, '다중화에서 FDM의 주된 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 개의 주파수로 아날로그 신호를 나누어 전송한다."}, {"id": "B", "text": "디지털 신호만을 처리한다."}, {"id": "C", "text": "신호를 패킷으로 나눈다."}, {"id": "D", "text": "하나의 회선을 전용으로 사용한다."}]', 'A', 'FDM은 여러 아날로그 신호를 서로 다른 주파수로 나누어 하나의 전송 매체를 통해 동시에 전송하는 방식입니다.'),
    (7059, 24, 1, 39, '패킷 교환 방식의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 신속하게 전송할 수 있다."}, {"id": "B", "text": "전용 회선을 사용할 수 있다."}, {"id": "C", "text": "통신의 안정성이 높다."}, {"id": "D", "text": "네트워크의 효율성을 높인다."}]', 'D', '패킷 교환 방식은 데이터를 패킷으로 나누어 전송하므로, 여러 사용자들이 동일한 네트워크를 공유하면서도 효율적으로 통신할 수 있습니다.'),
    (7060, 24, 1, 40, '다음 중 WDM의 특징으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "아날로그 신호만 전송 가능하다."}, {"id": "B", "text": "광섬유에서 서로 다른 파장을 이용하여 데이터 전송한다."}, {"id": "C", "text": "회선 교환 방식을 사용한다."}, {"id": "D", "text": "패킷 교환에 부적합하다."}]', 'B', 'WDM은 광섬유 통신에서 다양한 파장의 빛을 이용하여 여러 데이터를 동시에 전송할 수 있는 기술입니다.'),
    (7061, 24, 1, 41, '다중화 기술 중 사용할 수 없는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "FDM"}, {"id": "B", "text": "TDM"}, {"id": "C", "text": "IP"}, {"id": "D", "text": "WDM"}]', '["C"]', 'IP는 인터넷 프로토콜로, 다중화 기술이 아니라 데이터 전송을 위한 규칙을 정의하는 프로토콜입니다.'),
    (7062, 24, 1, 42, '데이터 통신의 기본 구성 요소는 무엇인가?', 'SHORT_ANSWER', NULL, '송신기, 수신기, 전송 매체', '데이터 통신의 기본 구성 요소는 송신기, 수신기, 그리고 이 둘을 연결하는 전송 매체입니다.'),
    (7063, 24, 1, 43, '슬라이딩 윈도우에서 무엇을 제어합니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "전송할 데이터의 양"}, {"id": "B", "text": "패킷 수"}, {"id": "C", "text": "오류 발생률"}, {"id": "D", "text": "네트워크 속도"}]', 'A', '슬라이딩 윈도우는 송신자가 전송할 수 있는 데이터의 양을 제어하여 흐름 제어를 수행합니다.'),
    (7064, 24, 1, 44, '오류 제어 기술 중 어떤 것이 오류 검출을 위해 사용됩니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "슬라이딩 윈도우"}, {"id": "B", "text": "패리티 비트"}, {"id": "C", "text": "변조"}, {"id": "D", "text": "패킷 교환"}]', 'B', '패리티 비트는 데이터 전송 중 오류를 검출하기 위해 사용되는 오류 제어 기술입니다.'),
    (7065, 24, 1, 45, 'WDM의 주요 목적은 무엇입니까?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 압축"}, {"id": "B", "text": "동시 다중 전송"}, {"id": "C", "text": "신호 증폭"}, {"id": "D", "text": "네트워크 보안"}]', 'B', 'WDM은 광섬유에서 여러 신호를 동시에 전송할 수 있도록 해주는 기술입니다.'),
    (7066, 24, 1, 46, '오류 검출을 위해 사용되는 기술은 무엇입니까?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "패리티 비트"}, {"id": "B", "text": "CRC"}, {"id": "C", "text": "슬라이딩 윈도우"}, {"id": "D", "text": "변조"}]', '["A", "B"]', '패리티 비트와 CRC는 오류 검출을 위해 사용되는 기술입니다.'),
    (7067, 24, 1, 47, '패킷 교환의 기본 개념은 무엇입니까?', 'SHORT_ANSWER', NULL, '데이터를 패킷 단위로 나누어 전송하는 방식', '패킷 교환은 데이터를 패킷 단위로 나누어 전송하여 네트워크 자원을 효율적으로 활용하는 방법입니다.'),
    (7068, 24, 1, 48, '디스크 스케줄링의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "I/O 작업의 효율성을 높이기 위해"}, {"id": "B", "text": "CPU의 성능을 극대화하기 위해"}, {"id": "C", "text": "메모리 사용량을 줄이기 위해"}, {"id": "D", "text": "네트워크 속도를 개선하기 위해"}]', 'A', '디스크 스케줄링은 I/O 작업의 효율성을 높이기 위한 목적을 가지고 있습니다.'),
    (7069, 24, 1, 49, 'C-SCAN의 동작 방식은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "헤드가 한 방향으로 이동한 후 끝에 도달하면 다시 시작점으로 돌아가는 방식"}, {"id": "B", "text": "헤드가 두 방향으로 동시에 이동하는 방식"}, {"id": "C", "text": "가장 가까운 요청부터 처리하는 방식"}, {"id": "D", "text": "정해진 시간 간격마다 요청을 처리하는 방식"}]', 'A', 'C-SCAN은 헤드가 한 방향으로 움직이다가 끝에 도달하면 다시 시작점으로 돌아가는 방식입니다.'),
    (7070, 24, 1, 50, '다음 중 스래싱을 올바르게 설명한 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 부족으로 성능이 저하되는 현상"}, {"id": "B", "text": "디스크 접근 시간을 최소화하는 기법"}, {"id": "C", "text": "프로세스가 필요한 자원을 모두 보유하고 있는 상태"}, {"id": "D", "text": "자원의 안전한 할당을 보장하는 알고리즘"}]', '["A"]', '스래싱은 메모리 부족으로 인해 성능이 저하되는 현상입니다.'),
    (7071, 24, 1, 51, '워킹 셋의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '특정 시간 동안 프로세스가 필요로 하는 페이지들의 집합', '워킹 셋은 특정 시간 동안 프로세스가 필요로 하는 페이지들의 집합을 의미합니다.'),
    (7072, 24, 1, 52, '디지털 데이터 통신에서 가장 기본적인 정보 전송 단위는 무엇인가?', 'SHORT_ANSWER', NULL, '비트', '비트는 디지털 데이터의 가장 기본적인 단위로 0 또는 1의 값을 가집니다.'),
    (7073, 24, 1, 53, '아날로그 신호의 특징으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "연속적인 신호이다."}, {"id": "B", "text": "디지털 신호로 변환이 용이하다."}, {"id": "C", "text": "주파수에 따라 변할 수 있다."}, {"id": "D", "text": "음성 신호 전송에 주로 사용된다."}]', 'B', '아날로그 신호는 디지털 신호로 변환하기 어려운 특징이 있습니다.'),
    (7074, 24, 1, 54, '프로토콜의 역할이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 형식을 정의한다."}, {"id": "B", "text": "보안 암호화를 수행한다."}, {"id": "C", "text": "전송 오류를 수정한다."}, {"id": "D", "text": "통신 규칙을 정한다."}]', 'B', '프로토콜은 데이터 전송의 규칙과 형식을 정하지만, 암호화는 별도의 보안 프로토콜에 의해 수행됩니다.'),
    (7075, 24, 1, 55, '데이터 통신에서 흐름 제어와 오류 제어의 공통점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 전송의 신뢰성을 높인다."}, {"id": "B", "text": "송신자와 수신자의 속도를 조절한다."}, {"id": "C", "text": "프로토콜의 일환으로 작동한다."}, {"id": "D", "text": "데이터를 압축한다."}]', '["A", "C"]', '흐름 제어와 오류 제어 모두 데이터 전송의 신뢰성을 높이며, 각기 다른 프로토콜의 일환으로 작동합니다.'),
    (7076, 24, 1, 56, '다중화 기술의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 신호를 동시에 전송하기 위해"}, {"id": "B", "text": "데이터를 압축하기 위해"}, {"id": "C", "text": "데이터의 무결성을 보장하기 위해"}, {"id": "D", "text": "네트워크의 보안을 강화하기 위해"}]', 'A', '다중화 기술은 여러 신호를 하나의 매체로 결합하여 효율적인 데이터 전송을 가능하게 하는 기술입니다.'),
    (7077, 24, 1, 57, '슬라이딩 윈도우 프로토콜의 주 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 암호화하는 것"}, {"id": "B", "text": "흐름 제어를 통해 전송 속도를 조절하는 것"}, {"id": "C", "text": "오류를 수정하는 것"}, {"id": "D", "text": "네트워크의 대역폭을 확장하는 것"}]', 'B', '슬라이딩 윈도우 프로토콜은 흐름 제어를 통해 전송 속도를 조절하는 기능을 가지고 있습니다.'),
    (7078, 24, 1, 58, '패리티 비트의 주 사용 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 압축하기 위해"}, {"id": "B", "text": "오류 검출을 위해"}, {"id": "C", "text": "데이터의 무결성을 보장하기 위해"}, {"id": "D", "text": "데이터 전송 속도를 증가시키기 위해"}]', 'B', '패리티 비트는 데이터 전송 중 발생할 수 있는 오류를 검출하기 위한 간단한 방법입니다.'),
    (7079, 24, 1, 59, '회선 교환과 패킷 교환의 차이점은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "회선 교환은 고정된 경로를 사용하고 패킷 교환은 동적으로 경로를 선택한다."}, {"id": "B", "text": "회선 교환은 데이터 전송 속도가 느리다."}, {"id": "C", "text": "패킷 교환은 충돌이 발생할 수 있다."}, {"id": "D", "text": "회선 교환은 주로 음성 통화에 사용된다."}]', '["A", "C", "D"]', '회선 교환은 고정된 경로를 사용하여 전송하는 반면, 패킷 교환은 데이터를 패킷화하여 동적으로 경로를 선택합니다.'),
    (7080, 24, 1, 60, '해밍 코드의 주 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '오류 검출 및 수정', '해밍 코드는 데이터 전송 중 발생할 수 있는 오류를 검출하고 수정하기 위한 방법입니다.'),
    (7081, 24, 1, 61, '패킷 교환 방식의 장점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 대역폭 사용"}, {"id": "B", "text": "데이터 손실 없음"}, {"id": "C", "text": "단일 회선 필요"}, {"id": "D", "text": "모든 데이터가 순차적으로 전송됨"}]', 'A', '패킷 교환 방식은 대역폭을 효율적으로 사용하여 데이터 전송을 최적화할 수 있는 장점이 있다.'),
    (7082, 24, 1, 62, '슬라이딩 윈도우 방식에서 ''윈도우 크기''는 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동시 전송 가능한 패킷 수"}, {"id": "B", "text": "패킷 전송 속도"}, {"id": "C", "text": "네트워크의 대역폭"}, {"id": "D", "text": "패킷 크기"}]', 'A', '슬라이딩 윈도우 방식에서 ''윈도우 크기''는 송신자가 동시에 전송할 수 있는 패킷의 개수를 의미한다.'),
    (7083, 24, 1, 63, '다음 중 TDM에 대한 설명으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 신호를 시간적으로 나누어 전송한다."}, {"id": "B", "text": "고정된 시간 슬롯을 사용한다."}, {"id": "C", "text": "패킷 교환에 비해 대역폭 효율성이 낮다."}, {"id": "D", "text": "회선 교환 방식이다."}]', 'D', 'TDM은 다중화 기술로, 회선 교환 방식이 아니라 시간 분할 방식이다.'),
    (7084, 24, 1, 64, '흐름 제어에 사용되는 기술은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "슬라이딩 윈도우"}, {"id": "B", "text": "에코 검증"}, {"id": "C", "text": "오류 검출"}, {"id": "D", "text": "정지-대기 방식"}]', '["A", "D"]', '흐름 제어에 사용되는 기술로는 슬라이딩 윈도우 방식과 정지-대기 방식이 있다.'),
    (7085, 24, 1, 65, '변조는 무엇의 절차를 통해 이루어지는가?', 'SHORT_ANSWER', NULL, '신호의 변환', '변조는 신호의 변환 과정을 통해 아날로그 신호와 디지털 신호를 서로 변환하는 절차를 의미한다.'),
    (7086, 24, 1, 66, '패리티 비트의 주된 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송 속도 조절"}, {"id": "B", "text": "오류 검출"}, {"id": "C", "text": "데이터 압축"}, {"id": "D", "text": "신호 증폭"}]', 'B', '패리티 비트는 데이터 전송 중 발생할 수 있는 오류를 검출하기 위한 용도로 사용됩니다.'),
    (7087, 24, 1, 67, '흐름 제어의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 암호화"}, {"id": "B", "text": "데이터 전송 속도 조절"}, {"id": "C", "text": "신호 변환"}, {"id": "D", "text": "다중화"}]', 'B', '흐름 제어는 송신자가 수신자의 처리 능력에 맞춰 전송 속도를 조절하는 기능입니다.'),
    (7088, 24, 1, 68, '패킷 교환 기술의 장점으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "효율적인 네트워크 자원 사용"}, {"id": "B", "text": "데이터 전송 중 단일 경로 사용"}, {"id": "C", "text": "내결함성"}, {"id": "D", "text": "비용 절감"}]', 'B', '패킷 교환은 여러 경로를 이용해 데이터가 전송되므로 단일 경로를 사용하지 않습니다.'),
    (7089, 24, 1, 69, '아날로그 신호의 특징은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "연속적인 신호"}, {"id": "B", "text": "이산적인 신호"}, {"id": "C", "text": "서로 다른 값을 가질 수 있다"}, {"id": "D", "text": "주파수 변조 가능"}]', '["A", "C", "D"]', '아날로그 신호는 연속적이며 다양한 값을 가질 수 있고, 주파수 변조가 가능합니다.'),
    (7090, 24, 1, 70, 'WDM의 전체 이름은 무엇인가?', 'SHORT_ANSWER', NULL, '파장 분다중화', 'WDM은 ''Wavelength Division Multiplexing''의 약자로, 파장 분다중화를 의미합니다.'),
    (7091, 24, 1, 71, '파일 시스템의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 저장 및 관리"}, {"id": "B", "text": "메모리 할당"}, {"id": "C", "text": "프로세스 스케줄링"}, {"id": "D", "text": "네트워크 연결"}]', 'A', '파일 시스템은 데이터를 저장하고 관리하는 구조로, 최적의 접근을 제공합니다.'),
    (7092, 24, 1, 72, '스래싱이 발생하는 주된 원인은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 부족"}, {"id": "B", "text": "프로세스 우선순위"}, {"id": "C", "text": "디스크 손상"}, {"id": "D", "text": "CPU 과부하"}]', 'A', '스래싱은 메모리 부족으로 인해 필요한 페이지를 자주 교체하는 상황입니다.'),
    (7093, 24, 1, 73, '은행원 알고리즘의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "교착 상태 방지"}, {"id": "B", "text": "메모리 최적화"}, {"id": "C", "text": "스케줄링 우선순위"}, {"id": "D", "text": "프로세스 생성"}]', 'A', '은행원 알고리즘은 자원 할당을 조정하여 교착 상태를 방지하는 기법입니다.'),
    (7094, 24, 1, 74, '디스크 스케줄링에서 SCAN 알고리즘은 어떤 방식으로 작동하는가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "상향 및 하향 이동"}, {"id": "B", "text": "임의 접근"}, {"id": "C", "text": "순차적 접근"}, {"id": "D", "text": "FIFO 접근"}]', '["A", "C"]', 'SCAN 알고리즘은 디스크의 한 쪽 끝까지 이동한 후 반대 방향으로 다시 스캔합니다.'),
    (7095, 24, 1, 75, '교착 상태의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '두 개 이상의 프로세스가 서로 자원을 요청하며 무한 대기하는 상태', ''),
    (7096, 24, 1, 76, 'SSTF 스케줄링에서 선택되는 요청은 어떤 기준으로 결정되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 가까운 요청"}, {"id": "B", "text": "가장 오래된 요청"}, {"id": "C", "text": "가장 많은 요청"}, {"id": "D", "text": "가장 적은 요청"}]', 'A', 'SSTF는 디스크의 헤드가 가장 가까운 요청을 우선적으로 처리하여 디스크 이동 시간을 최소화합니다.'),
    (7097, 24, 1, 77, '다음 중 inode에 대한 설명으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "파일의 메타데이터를 포함한다."}, {"id": "B", "text": "파일 이름을 포함한다."}, {"id": "C", "text": "파일 크기를 포함한다."}, {"id": "D", "text": "파일의 소유자 정보를 포함한다."}]', 'B', 'inode는 파일의 메타데이터를 포함하지만, 파일 이름은 포함하지 않습니다.'),
    (7098, 24, 1, 78, '워킹 셋은 무엇을 나타내는 개념인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 프로세스에서 필요한 페이지들"}, {"id": "B", "text": "모든 실행 중인 프로세스"}, {"id": "C", "text": "디스크의 모든 파일"}, {"id": "D", "text": "가장 많이 사용된 페이지들"}]', 'A', '워킹 셋은 현재 프로세스가 필요한 페이지들을 나타내며, 페이지 교체 알고리즘에 영향을 미칩니다.'),
    (7099, 24, 1, 79, '운영체제에서 프로세스 상태의 변경이 발생하는 경우는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "프로세스가 실행 중일 때"}, {"id": "B", "text": "프로세스가 대기 중일 때"}, {"id": "C", "text": "프로세스가 종료될 때"}, {"id": "D", "text": "프로세스가 생성될 때"}]', '["A", "B", "C", "D"]', '프로세스 상태는 생성, 실행, 대기, 종료 등 다양한 상황에서 변경될 수 있습니다.'),
    (7100, 24, 1, 80, '스레싱이 발생할 때, 시스템의 성능은 어떻게 될까요?', 'SHORT_ANSWER', NULL, '저하된다.', '스레싱이 발생하면 페이지 교체가 잦아져서 시스템의 성능이 저하됩니다.'),
    (7101, 24, 1, 81, 'FDM의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 신호를 동시에 전송하기 위해"}, {"id": "B", "text": "신호를 암호화하기 위해"}, {"id": "C", "text": "데이터를 압축하기 위해"}, {"id": "D", "text": "데이터 전송 속도를 줄이기 위해"}]', 'A', 'FDM은 여러 신호를 동일한 전송 매체에서 동시에 전송하기 위해 주파수 대역을 나누는 방식입니다.'),
    (7102, 24, 1, 82, 'CRC는 무엇을 위해 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송 속도 향상"}, {"id": "B", "text": "오류 검출 및 수정"}, {"id": "C", "text": "신호 변조"}, {"id": "D", "text": "프로토콜 설정"}]', 'B', 'CRC는 데이터 전송 중 발생할 수 있는 오류를 검출하고 수정하는 데 사용됩니다.'),
    (7103, 24, 1, 83, '변조의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "신호를 변환하는 과정"}, {"id": "B", "text": "데이터를 압축하는 기술"}, {"id": "C", "text": "신호를 복호화하는 작업"}, {"id": "D", "text": "프로토콜을 검증하는 방법"}]', 'A', '변조는 아날로그 신호를 디지털 정보로 변환하는 과정입니다.'),
    (7104, 24, 1, 84, '데이터 통신에서 흐름 제어의 역할은 무엇인가? (복수 정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 전송 속도 조절"}, {"id": "B", "text": "데이터 압축"}, {"id": "C", "text": "수신 장치 전송 능력 조절"}, {"id": "D", "text": "데이터 안전성 향상"}]', '["A", "C"]', '흐름 제어는 데이터가 전송되는 속도를 조절하고 수신 장치가 데이터를 소화할 수 있도록 도와줍니다.'),
    (7105, 24, 1, 85, '회선 교환의 기본 개념은 무엇인가?', 'SHORT_ANSWER', NULL, '통신 경로를 설정하여 데이터 전송', ''),
    (7106, 24, 1, 86, 'FCFS 스케줄링의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "프로세스가 도착한 순서대로 CPU를 할당한다."}, {"id": "B", "text": "가장 짧은 작업부터 처리한다."}, {"id": "C", "text": "우선순위가 높은 작업을 먼저 처리한다."}, {"id": "D", "text": "프로세스의 실행 시간을 예측하여 처리한다."}]', 'A', 'FCFS는 프로세스가 도착한 순서에 따라 CPU를 할당하는 방식입니다.'),
    (7107, 24, 1, 87, 'UNIX 운영체제의 주요 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다중 사용자 지원"}, {"id": "B", "text": "단일 사용자 전용"}, {"id": "C", "text": "안정성"}, {"id": "D", "text": "멀티태스킹"}]', 'B', 'UNIX는 다중 사용자를 지원하는 운영체제입니다.'),
    (7108, 24, 1, 88, '파일 시스템에서 디렉토리 구조의 주요 이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 방지"}, {"id": "B", "text": "파일 접근 속도 향상"}, {"id": "C", "text": "파일의 계층적 관리"}, {"id": "D", "text": "하드웨어 효율성 개선"}]', 'C', '디렉토리 구조는 파일을 계층적으로 관리하여 조직적으로 저장할 수 있게 해줍니다.'),
    (7109, 24, 1, 89, '메모리 관리 기법 중 페이징에 대해 설명하시오.', 'SHORT_ANSWER', NULL, '메모리를 페이지 단위로 나누어 관리하는 기법으로, 프로세스가 필요한 페이지만 메모리에 로드하여 효율적인 메모리 사용을 가능하게 한다.', ''),
    (7110, 24, 1, 90, '스래싱의 원인으로 올바른 것을 모두 고르시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "프로세스의 페이지 수가 많다."}, {"id": "B", "text": "메모리 공간이 부족하다."}, {"id": "C", "text": "CPU 스케줄링이 비효율적이다."}, {"id": "D", "text": "페이지 교체 알고리즘이 잘못되었다."}]', '["A", "B", "D"]', '스래싱은 프로세스가 너무 많은 페이지를 가지고 있어서 페이지 교체가 빈번하게 발생할 때 발생하며, 이는 메모리 부족과 관련이 있습니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 정보처리기사 > 정보보안 (28문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7111, 24, 2, 1, 'MAC의 의미는 무엇인가요?', 'SHORT_ANSWER', NULL, 'Mandatory Access Control', 'MAC은 사용자의 권한에 따라 자원에 대한 접근을 제어하는 기법입니다.'),
    (7112, 24, 2, 2, 'TLS의 주된 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송 시 암호화"}, {"id": "B", "text": "사용자의 접근 권한 관리"}, {"id": "C", "text": "해시 값 생성"}, {"id": "D", "text": "시스템 성능 향상"}]', 'A', 'TLS는 네트워크 통신을 보호하기 위해 데이터 전송 시 암호화를 수행합니다.'),
    (7113, 24, 2, 3, '다음 중 해시 함수로 사용되는 알고리즘은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "MD5"}, {"id": "B", "text": "AES"}, {"id": "C", "text": "TLS"}, {"id": "D", "text": "IPS"}]', 'A', 'MD5는 데이터의 무결성을 확인하기 위해 사용되는 해시 함수입니다.'),
    (7114, 24, 2, 4, '다음 중 정보를 암호화하기 위해 사용되는 알고리즘은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "AES"}, {"id": "B", "text": "MD5"}, {"id": "C", "text": "RSA"}, {"id": "D", "text": "SHA-256"}]', '["A", "C"]', 'AES와 RSA는 데이터를 암호화하는 데 사용되는 알고리즘입니다.'),
    (7115, 24, 2, 5, 'IPS의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 백업"}, {"id": "B", "text": "비정상적 접근 감지 및 차단"}, {"id": "C", "text": "암호화 키 관리"}, {"id": "D", "text": "시스템 성능 모니터링"}]', 'B', 'IPS는 시스템에 대한 비정상적인 접근을 감지하고 차단하는 기능을 가지고 있습니다.'),
    (7116, 24, 2, 6, '방화벽의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "네트워크의 불법적인 접근 차단"}, {"id": "B", "text": "데이터의 암호화"}, {"id": "C", "text": "사용자 인증"}, {"id": "D", "text": "데이터 백업"}]', 'A', '방화벽은 네트워크의 안전을 보장하고 외부의 불법적인 접근을 차단하는 역할을 합니다.'),
    (7117, 24, 2, 7, '다음 중 비대칭키 암호화 방식의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "같은 키로 데이터 암호화 및 복호화"}, {"id": "B", "text": "서로 다른 키로 데이터 암호화 및 복호화"}, {"id": "C", "text": "고정된 키만 사용"}, {"id": "D", "text": "키가 필요하지 않음"}]', 'B', '비대칭키 암호화는 서로 다른 키(공개키와 개인키)를 사용하여 데이터의 암호화와 복호화를 수행합니다.'),
    (7118, 24, 2, 8, 'MD5와 SHA의 공통점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 무결성을 검사한다"}, {"id": "B", "text": "암호화된 데이터를 복원할 수 있다"}, {"id": "C", "text": "해시 함수로 사용된다"}, {"id": "D", "text": "고유한 길이의 출력 값을 생성한다"}]', '["A", "C", "D"]', 'MD5와 SHA는 모두 해시 함수로 사용되며, 데이터의 무결성을 검사하고 고유한 길이의 해시 값을 생성합니다.'),
    (7119, 24, 2, 9, 'VPN의 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '안전한 네트워크 연결 제공', 'VPN은 공용 네트워크를 통해 안전한 사설 네트워크 연결을 제공합니다.'),
    (7120, 24, 2, 10, 'VPN의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원격지에서 안전한 네트워크 접속"}, {"id": "B", "text": "데이터를 암호화하여 저장"}, {"id": "C", "text": "사용자 인증을 강화"}, {"id": "D", "text": "데이터를 자동으로 백업"}]', 'A', 'VPN은 원격지에서 안전하게 네트워크에 접속할 수 있도록 해줍니다.'),
    (7121, 24, 2, 11, 'AES와 DES의 차이점으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AES는 128비트 키를 사용하며, DES는 56비트 키를 사용한다."}, {"id": "B", "text": "AES는 대칭키 암호화 방식이며, DES는 비대칭키 방식이다."}, {"id": "C", "text": "DES는 더 안전하다."}, {"id": "D", "text": "AES는 DES보다 빠르다."}]', 'A', 'AES는 128비트 이상의 키를 사용할 수 있고, DES는 56비트 키를 사용합니다.'),
    (7122, 24, 2, 12, '다음 중 접근 통제의 목적이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 보호"}, {"id": "B", "text": "시스템 성능 향상"}, {"id": "C", "text": "사용자 관리"}, {"id": "D", "text": "정보 유출 방지"}]', 'B', '접근 통제는 데이터 보호, 사용자 관리, 정보 유출 방지 등을 목적으로 하지만 시스템 성능 향상은 목적이 아닙니다.'),
    (7123, 24, 2, 13, '디지털 서명이 사용되는 주된 이유는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "무결성 보장"}, {"id": "B", "text": "신원 확인"}, {"id": "C", "text": "데이터 압축"}, {"id": "D", "text": "데이터 복구"}]', '["A", "B"]', '디지털 서명은 메시지의 무결성을 보장하고, 발신자의 신원을 확인하는 데 사용됩니다.'),
    (7124, 24, 2, 14, '해시 함수의 주 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 무결성 검증', '해시 함수는 데이터를 고유한 해시값으로 변환하여 데이터의 무결성을 검증하는 데 사용됩니다.'),
    (7125, 24, 2, 15, 'IDS의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이상 징후 탐지 및 알림"}, {"id": "B", "text": "데이터 암호화"}, {"id": "C", "text": "상대방의 신원 확인"}, {"id": "D", "text": "네트워크 트래픽 차단"}]', 'A', 'IDS는 네트워크나 시스템에서 이상 징후를 탐지하여 관리자에게 알리는 역할을 수행합니다.'),
    (7126, 24, 2, 16, 'TLS는 주로 어떤 용도로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 전송의 보안 제공"}, {"id": "B", "text": "시스템 모니터링"}, {"id": "C", "text": "사용자 인증"}, {"id": "D", "text": "파일 삭제"}]', 'A', 'TLS는 데이터 전송의 보안을 제공하며 안전한 통신을 보장합니다.'),
    (7127, 24, 2, 17, 'DAC(임의 접근 제어)의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "사용자 권한에 따라 자원 접근 제어"}, {"id": "B", "text": "네트워크 트래픽을 차단"}, {"id": "C", "text": "모든 사용자에게 동일한 접근 권한 부여"}, {"id": "D", "text": "고정된 접근 권한만 제공"}]', 'A', 'DAC는 사용자 권한에 따라 자원에 대한 접근을 제어하는 방식입니다.'),
    (7128, 24, 2, 18, 'SSL과 TLS의 공통점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 암호화를 제공한다."}, {"id": "B", "text": "인터넷 통신의 보안을 보장한다."}, {"id": "C", "text": "서버 인증 기능이 있다."}, {"id": "D", "text": "상대방의 신원 확인 기능이 없다."}]', '["A", "B", "C"]', 'SSL과 TLS는 데이터 암호화, 인터넷 통신의 보안, 서버 인증 기능을 제공합니다.'),
    (7129, 24, 2, 19, '디지털 서명의 주된 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '문서의 무결성과 신뢰성을 확보하는 것.', ''),
    (7130, 24, 2, 20, 'VPN의 주요 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "원격 연결과 데이터 전송 보안"}, {"id": "B", "text": "데이터베이스 쿼리 최적화"}, {"id": "C", "text": "웹사이트 트래픽 분석"}, {"id": "D", "text": "서버 가상화"}]', 'A', 'VPN은 원격 사용자와 기업 네트워크 간의 안전한 연결을 제공하여 데이터 전송을 보호합니다.'),
    (7131, 24, 2, 21, '비대칭키 암호화에서 사용되는 대표적인 알고리즘은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AES"}, {"id": "B", "text": "RSA"}, {"id": "C", "text": "DES"}, {"id": "D", "text": "RC4"}]', 'B', 'RSA는 비대칭키 암호화에서 가장 많이 사용되는 알고리즘 중 하나입니다.'),
    (7132, 24, 2, 22, 'MD5와 SHA의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "MD5는 더 안전하다."}, {"id": "B", "text": "SHA는 더 뛰어난 성능을 가진다."}, {"id": "C", "text": "SHA는 보안 취약점이 발견되지 않았다."}, {"id": "D", "text": "MD5는 해시 충돌이 가능하다."}]', 'D', 'MD5는 해시 충돌 가능성이 있어 보안적으로 취약한 반면, SHA는 더 강력한 보안을 제공합니다.'),
    (7133, 24, 2, 23, '다음 중 대칭키 암호화 방식인 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "AES"}, {"id": "B", "text": "RSA"}, {"id": "C", "text": "3DES"}, {"id": "D", "text": "SHA"}]', '["A", "C"]', 'AES와 3DES는 모두 대칭키 암호화 방식으로, 동일한 키를 사용하여 암호화 및 복호화를 수행합니다.'),
    (7134, 24, 2, 24, 'TLS는 무엇을 위한 프로토콜인가?', 'SHORT_ANSWER', NULL, '인터넷에서의 안전한 통신', 'TLS는 전송 계층에서 데이터의 기밀성과 무결성을 보장하기 위한 프로토콜입니다.'),
    (7135, 24, 2, 25, '디지털 서명의 주요 역할은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터의 무결성과 출처 보장', '디지털 서명은 문서가 변경되지 않았음을 증명하고, 서명자의 신원을 확인하는 역할을 합니다.'),
    (7136, 24, 2, 26, 'SSL의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 안전한 전송"}, {"id": "B", "text": "파일 압축"}, {"id": "C", "text": "시스템 성능 향상"}, {"id": "D", "text": "데이터 분석"}]', 'A', 'SSL은 클라이언트와 서버 간의 데이터를 안전하게 암호화하여 전송하는 프로토콜입니다.'),
    (7137, 24, 2, 27, 'RSA와 AES의 주요 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "RSA는 대칭키, AES는 비대칭키"}, {"id": "B", "text": "RSA는 비대칭키, AES는 대칭키"}, {"id": "C", "text": "둘 다 대칭키"}, {"id": "D", "text": "둘 다 비대칭키"}]', 'B', 'RSA는 비대칭키 암호화 방식이고, AES는 대칭키 암호화 방식입니다.'),
    (7138, 24, 2, 28, '다음 중 IDS와 IPS의 공통된 기능은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "네트워크 트래픽 모니터링"}, {"id": "B", "text": "신규 사용자의 인증"}, {"id": "C", "text": "침입 탐지"}, {"id": "D", "text": "침입 방지"}]', '["A", "C"]', 'IDS와 IPS 모두 네트워크 트래픽을 모니터링하며 침입 탐지 기능을 수행합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- 정보처리기사 > 프로그래밍 (62문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7139, 24, 3, 1, '상속이란 무엇인가?', 'SHORT_ANSWER', NULL, '부모 클래스의 속성과 메소드를 자식 클래스가 물려받는 개념', '상속은 객체 지향 프로그래밍에서 코드의 재사용성을 높이는 중요한 개념이다.'),
    (7140, 24, 3, 2, '다음 중 오버로딩에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "같은 이름을 가지지만 매개변수의 수나 타입이 다른 메소드 정의"}, {"id": "B", "text": "하위 클래스에서 부모 클래스의 메소드를 재정의하는 것"}, {"id": "C", "text": "메소드가 호출될 때마다 다른 동작을 수행하는 것"}, {"id": "D", "text": "재귀적으로 호출되는 메소드를 의미한다."}]', 'A', '오버로딩은 메소드가 같은 이름을 가지면서도 매개변수의 수나 타입이 다르게 정의되는 것을 의미한다.'),
    (7141, 24, 3, 3, 'Python에서 오버라이딩을 사용하는 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "기본 메소드를 변경하기 위해"}, {"id": "B", "text": "새로운 객체를 생성하기 위해"}, {"id": "C", "text": "코드를 속성으로 결합하기 위해"}, {"id": "D", "text": "변수를 선언하기 위해"}]', 'A', '오버라이딩은 자식 클래스에서 부모 클래스의 메소드를 새롭게 정의하여 기능을 변경하기 위해 사용된다.'),
    (7142, 24, 3, 4, '변수 추적의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변수의 현재 값을 확인하기 위해"}, {"id": "B", "text": "에러를 찾기 위해"}, {"id": "C", "text": "코드의 가독성을 높이기 위해"}, {"id": "D", "text": "변수의 타입을 확인하기 위해"}]', '["A", "B"]', '변수 추적은 변수의 현재 값을 확인하고, 코드의 흐름에서 발생하는 에러를 찾는 데 큰 도움이 된다.'),
    (7143, 24, 3, 5, 'C언어에서 함수 오버로딩이 가능한가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가능하다"}, {"id": "B", "text": "불가능하다"}, {"id": "C", "text": "조건에 따라 가능하다"}, {"id": "D", "text": "표준에서는 정의되어 있지 않다"}]', 'B', 'C언어는 함수 오버로딩을 지원하지 않기 때문에 동일한 이름의 함수를 여러 개 정의할 수 없다.'),
    (7144, 24, 3, 6, '다음 중 Java에서 상속을 사용하여 자식 클래스가 부모 클래스의 메서드를 재정의할 때 사용하는 키워드는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "static"}, {"id": "B", "text": "override"}, {"id": "C", "text": "extends"}, {"id": "D", "text": "super"}]', 'C', 'Java에서 상속을 통해 자식 클래스는 ''extends'' 키워드를 사용하여 부모 클래스를 상속받는다.'),
    (7145, 24, 3, 7, '다음 중 출력 예측을 위한 변수 추적의 올바른 방법은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드를 한 줄씩 실행하며 변수 값을 기록한다."}, {"id": "B", "text": "변수를 모두 0으로 초기화한다."}, {"id": "C", "text": "변수의 이름만 기억한다."}, {"id": "D", "text": "출력 결과를 무시하고 예측한다."}]', 'A', '출력 예측을 위해서는 코드를 한 줄씩 실행하며 변수 값을 기록하는 것이 중요하다.'),
    (7146, 24, 3, 8, 'C언어에서 포인터의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변수의 메모리 주소를 저장한다."}, {"id": "B", "text": "배열의 요소에 접근할 수 있다."}, {"id": "C", "text": "메모리 관리에 도움을 준다."}, {"id": "D", "text": "변수의 데이터 타입을 정의한다."}]', '["A", "B", "C"]', '포인터는 변수의 메모리 주소를 저장하고 배열의 요소에 접근하며, 메모리 관리에 큰 도움을 준다.'),
    (7147, 24, 3, 9, 'Java에서 메서드 오버로딩이란 무엇인가?', 'SHORT_ANSWER', NULL, '같은 이름의 메서드를 매개변수의 타입이나 개수에 따라 다르게 정의하는 것.', '메서드 오버로딩은 같은 이름의 메서드를 매개변수에 따라 다르게 정의하여 코드의 재사용성을 높이는 기법이다.'),
    (7148, 24, 3, 10, 'C언어에서 구조체를 사용하여 정의할 수 있는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "여러 다른 데이터 타입의 혼합"}, {"id": "B", "text": "오직 같은 데이터 타입만"}, {"id": "C", "text": "함수만"}, {"id": "D", "text": "배열만"}]', 'A', '구조체는 다양한 데이터 타입을 혼합하여 새로운 데이터 타입을 정의할 수 있습니다.'),
    (7149, 24, 3, 11, '재귀 함수의 특징으로 맞는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자기 자신을 호출할 수 있다"}, {"id": "B", "text": "반복문보다 항상 빠르다"}, {"id": "C", "text": "스택 메모리를 사용하지 않는다"}, {"id": "D", "text": "항상 종료 조건이 필요 없다"}]', 'A', '재귀 함수는 자기 자신을 호출하는 방식으로 작동합니다.'),
    (7150, 24, 3, 12, '다음 중 배열의 특징으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "고정된 크기를 가진다"}, {"id": "B", "text": "동적 크기 조정이 가능하다"}, {"id": "C", "text": "메모리에 연속적으로 저장된다"}, {"id": "D", "text": "인덱스를 통해 접근할 수 있다"}]', 'B', '배열은 고정된 크기를 가지며, 동적 크기 조정은 불가능합니다.'),
    (7151, 24, 3, 13, 'C언어에서 포인터의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "메모리 주소를 저장하기 위해"}, {"id": "B", "text": "배열 요소 접근을 위해"}, {"id": "C", "text": "구조체의 크기를 줄이기 위해"}, {"id": "D", "text": "재귀 함수 호출을 위해"}]', '["A", "B"]', '포인터는 메모리 주소를 저장하고, 배열 요소에 접근하는 데 사용됩니다.'),
    (7152, 24, 3, 14, 'C언어에서 배열의 첫 번째 요소를 가리키는 포인터 변수의 이름은 무엇인가?', 'SHORT_ANSWER', NULL, '배열 이름', 'C언어에서 배열 이름은 배열의 첫 번째 요소의 주소를 가리킵니다.'),
    (7153, 24, 3, 15, '변수의 값을 추적할 때 고려해야 할 주요 요소는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "변수의 초기화 상태"}, {"id": "B", "text": "변수의 데이터 타입"}, {"id": "C", "text": "변수의 범위(scope)"}, {"id": "D", "text": "모두 해당된다"}]', 'D', '변수의 값을 추적하기 위해서는 초기화 상태, 데이터 타입, 범위 등 모든 요소를 고려해야 합니다.'),
    (7154, 24, 3, 16, '다음 중 재귀 함수의 특징이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자기 자신을 호출한다"}, {"id": "B", "text": "항상 종료 조건이 있다"}, {"id": "C", "text": "스택 메모리를 사용한다"}, {"id": "D", "text": "반드시 파라미터가 필요하다"}]', 'D', '재귀 함수는 파라미터가 없어도 정의될 수 있습니다.'),
    (7155, 24, 3, 17, '오버로딩은 어떤 상황에서 주로 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다양한 데이터 타입을 처리할 때"}, {"id": "B", "text": "함수의 실행 시간을 단축할 때"}, {"id": "C", "text": "코드의 메모리 사용을 줄일 때"}, {"id": "D", "text": "불필요한 변수를 제거할 때"}]', 'A', '오버로딩은 다양한 데이터 타입을 처리하는 상황에서 유용하게 사용됩니다.'),
    (7156, 24, 3, 18, '다음 중 상속의 장점으로 옳지 않은 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "코드의 재사용성을 높인다"}, {"id": "B", "text": "코드의 실행 속도를 증가시킨다"}, {"id": "C", "text": "유지보수를 쉽게 한다"}, {"id": "D", "text": "다형성을 지원한다"}]', '["B"]', '상속은 코드의 재사용성과 유지보수, 다형성 지원에는 유리하지만 실행 속도를 증가시키는 것은 아닙니다.'),
    (7157, 24, 3, 19, '구조체의 주요 사용 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 그룹화', '구조체는 관련된 데이터를 그룹화하여 관리하기 위해 사용됩니다.'),
    (7158, 24, 3, 20, 'C언어에서 구조체를 정의할 때 사용하는 키워드는 무엇인가?', 'SHORT_ANSWER', NULL, 'struct', 'C언어에서 구조체를 정의할 때 ''struct'' 키워드를 사용합니다.'),
    (7159, 24, 3, 21, '다음 중 C언어에서 포인터의 주요 용도가 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 주소에 직접 접근"}, {"id": "B", "text": "배열의 크기 변경"}, {"id": "C", "text": "함수 인자로 사용"}, {"id": "D", "text": "동적 메모리 할당"}]', 'B', 'C언어에서 포인터는 메모리 주소에 접근하거나 함수 인자로 사용될 수 있지만, 배열의 크기를 변경하는 용도는 아닙니다.'),
    (7160, 24, 3, 22, 'Java에서 클래스란 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "객체를 정의하는 청사진"}, {"id": "B", "text": "변수를 저장하는 메모리 공간"}, {"id": "C", "text": "함수의 집합체"}, {"id": "D", "text": "프로그램 실행 파일"}]', 'A', 'Java에서 클래스는 객체를 정의하는 청사진으로, 속성과 행동을 포함합니다.'),
    (7161, 24, 3, 23, 'C언어의 배열과 포인터의 관계에 대해 설명하시오. (복수정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "배열 이름은 포인터와 같다"}, {"id": "B", "text": "배열은 포인터로 접근할 수 없다"}, {"id": "C", "text": "포인터 연산을 통해 배열 요소에 접근 가능"}, {"id": "D", "text": "배열은 고정 크기만 가질 수 있다"}]', '["A", "C"]', '배열 이름은 해당 배열의 첫 번째 요소의 주소를 가리키는 포인터와 같으며, 포인터 연산을 통해 배열 요소에 접근할 수 있습니다.'),
    (7162, 24, 3, 24, 'Python에서 상속의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드 재사용"}, {"id": "B", "text": "메모리 사용량 증가"}, {"id": "C", "text": "비효율적인 알고리즘"}, {"id": "D", "text": "코드 복잡성 증가"}]', 'A', '상속의 주된 목적은 코드의 재사용성입니다.'),
    (7163, 24, 3, 25, '다음 중 오버로딩을 설명하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "다양한 데이터 타입을 처리하는 메서드 정의"}, {"id": "B", "text": "하위 클래스에서 메서드 수정"}, {"id": "C", "text": "코드 블록의 반복 사용"}, {"id": "D", "text": "변수의 스코프 변경"}]', 'A', '오버로딩은 같은 이름의 메서드를 다양한 데이터 타입으로 정의하여 처리할 수 있게 합니다.'),
    (7164, 24, 3, 26, '재귀 함수의 특징으로 알맞은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "자기 자신을 호출하는 함수"}, {"id": "B", "text": "모든 문제를 반복문으로 해결함"}, {"id": "C", "text": "항상 무한 루프에 빠짐"}, {"id": "D", "text": "변수의 값을 변경하지 않음"}]', 'A', '재귀 함수는 자기 자신을 호출하여 문제를 해결하는 방식입니다.'),
    (7165, 24, 3, 27, 'Python에서 오버라이딩을 사용하는 이유는 무엇인가? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "기본 클래스의 메서드를 수정하기 위해"}, {"id": "B", "text": "메모리 절약을 위해"}, {"id": "C", "text": "더 구체적인 기능을 추가하기 위해"}, {"id": "D", "text": "코드의 가독성을 높이기 위해"}]', '["A", "C"]', '오버라이딩의 주된 이유는 기본 클래스의 메서드를 수정하고, 더 구체적인 기능을 추가하기 위함입니다.'),
    (7166, 24, 3, 28, '변수 추적이란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '변수의 값과 상태를 추적하여 프로그램의 동작을 이해하고 디버깅하는 과정.', '변수 추적은 프로그램의 흐름을 따라 변수의 상태를 지속적으로 확인하는 것을 의미합니다.'),
    (7167, 24, 3, 29, '상속의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드의 재사용성 향상"}, {"id": "B", "text": "프로그램 속도 향상"}, {"id": "C", "text": "에러 발생률 감소"}, {"id": "D", "text": "데이터베이스 구축"}, {"id": "E", "text": "디자인 개선"}]', 'A', '상속은 기존 클래스의 특성을 새로운 클래스에서 재사용하여 코드의 중복을 줄이고 유지보수성을 높이는 데 목적이 있다.'),
    (7168, 24, 3, 30, 'Java에서 메소드를 오버라이딩 하는 이유는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "상위 클래스의 메소드를 재정의하기 위해"}, {"id": "B", "text": "메모리 사용량을 줄이기 위해"}, {"id": "C", "text": "속도 향상을 위해"}, {"id": "D", "text": "데이터베이스 연결을 위해"}]', 'A', '오버라이딩은 상위 클래스에서 정의된 메소드를 하위 클래스에서 새롭게 정의하여 기능을 변경하려고 할 때 사용된다.'),
    (7169, 24, 3, 31, '다음 중 포인터에 대한 설명으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "변수의 주소를 저장하는 변수이다."}, {"id": "B", "text": "배열의 내용을 직접 복사한다."}, {"id": "C", "text": "메모리 접근 속도가 느리다."}, {"id": "D", "text": "데이터 타입에 상관없이 사용할 수 있다."}]', 'A', '포인터는 특정 변수의 메모리 주소를 저장하여 직접적으로 그 메모리 공간에 접근할 수 있도록 해주는 변수이다.'),
    (7170, 24, 3, 32, 'Java에서 배열을 사용하여 정수형 데이터를 저장할 때, 다음 중 올바른 방법은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "int[] arr = new int[5];"}, {"id": "B", "text": "int arr = new int[5];"}, {"id": "C", "text": "int arr[] = new int[];"}, {"id": "D", "text": "int arr[] = {1, 2, 3, 4, 5};"}]', '["A", "D"]', 'Java에서 배열을 선언할 때는 int[] arr = new int[5]; 또는 int arr[] = {1, 2, 3, 4, 5};와 같은 방식으로 할 수 있다.'),
    (7171, 24, 3, 33, '클래스에서 생성자는 무엇을 하는가?', 'SHORT_ANSWER', NULL, '객체를 생성할 때 초기화 작업을 수행한다.', '생성자는 클래스의 인스턴스가 생성될 때 자동으로 호출되어 객체의 초기화 작업을 수행한다.'),
    (7172, 24, 3, 34, '포인터와 배열의 관계에 대한 설명으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열의 이름은 배열의 첫 번째 요소의 주소를 가진다."}, {"id": "B", "text": "포인터는 배열의 크기를 측정할 수 있다."}, {"id": "C", "text": "배열은 포인터와 같은 크기를 갖는다."}, {"id": "D", "text": "포인터는 배열의 메모리 복사를 수행한다."}]', 'A', '배열의 이름은 해당 배열의 첫 번째 요소의 주소를 가리키므로 포인터와 배열은 밀접한 관계가 있다.'),
    (7173, 24, 3, 35, 'C++에서 오버로딩이 가능한 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "함수"}, {"id": "B", "text": "클래스 이름"}, {"id": "C", "text": "변수 이름"}, {"id": "D", "text": "구조체"}]', 'A', 'C++에서 오버로딩은 주로 함수에 적용되며, 함수 이름이 같지만 매개변수의 타입 또는 개수를 다르게 할 수 있다.'),
    (7174, 24, 3, 36, '구조체와 클래스의 차이점으로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "구조체는 private 멤버를 가질 수 없다."}, {"id": "B", "text": "클래스는 구조체보다 메모리를 더 많이 사용한다."}, {"id": "C", "text": "구조체는 함수 오버로딩을 지원하지 않는다."}, {"id": "D", "text": "클래스는 기본적으로 private 멤버를 가진다."}]', 'A', '구조체는 기본적으로 public 멤버를 가지며, 클래스는 기본적으로 private 멤버를 갖는다.'),
    (7175, 24, 3, 37, '사람을 표현하는 구조체를 정의할 때, 어떤 멤버가 포함되어야 할까요? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이름"}, {"id": "B", "text": "나이"}, {"id": "C", "text": "주소"}, {"id": "D", "text": "직업"}]', '["A", "B", "C", "D"]', '사람을 표현하는 구조체에는 일반적으로 이름, 나이, 주소, 직업 등 다양한 멤버가 포함될 수 있다.'),
    (7176, 24, 3, 38, '객체 지향 프로그래밍의 중요 개념은 무엇인가요?', 'SHORT_ANSWER', NULL, '캡슐화, 상속, 다형성', '객체 지향 프로그래밍의 중요 개념으로는 캡슐화, 상속, 다형성이 있으며, 이를 통해 코드의 재사용성과 유지보수성을 높일 수 있다.'),
    (7177, 24, 3, 39, '포인터의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 주소를 직접 조작하기 위해"}, {"id": "B", "text": "반복문을 단순화하기 위해"}, {"id": "C", "text": "변수의 값을 고정하기 위해"}, {"id": "D", "text": "디버깅을 쉽게 하기 위해"}]', 'A', '포인터는 메모리 주소를 직접 조작하여 변수의 값을 변경하거나, 배열, 구조체 등과 같은 복잡한 데이터 구조를 효율적으로 처리하는 데 사용됩니다.'),
    (7178, 24, 3, 40, 'C++에서 상속을 통해 무엇을 얻을 수 있나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드의 재사용성"}, {"id": "B", "text": "프로그램의 속도 향상"}, {"id": "C", "text": "변수의 수를 줄이기"}, {"id": "D", "text": "메모리 사용량 감소"}]', 'A', '상속을 통해 기존 클래스의 기능을 재사용할 수 있으므로 코드의 유지보수와 확장성을 높일 수 있습니다.'),
    (7179, 24, 3, 41, '다음 코드의 출력 결과는 무엇인가요? 

int arr[3] = {1, 2, 3}; 
printf(''%d'', arr[1]);', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "1"}, {"id": "B", "text": "2"}, {"id": "C", "text": "3"}, {"id": "D", "text": "오류 발생"}]', 'B', '배열 arr의 인덱스 1은 두 번째 요소이므로 값은 2입니다.'),
    (7180, 24, 3, 42, 'C언어에서 구조체를 정의하는 키워드는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "struct"}, {"id": "B", "text": "class"}, {"id": "C", "text": "typedef"}, {"id": "D", "text": "enum"}]', '["A"]', 'C언어에서 구조체를 정의하기 위해서는 ''struct'' 키워드를 사용합니다.'),
    (7181, 24, 3, 43, 'C++에서 함수 오버로딩은 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, '동일한 함수 이름을 사용하면서 매개변수의 타입이나 수를 다르게 구현하는 것', '함수 오버로딩은 동일한 이름의 함수를 여러 개 정의하고, 매개변수의 타입이나 개수에 따라 호출되는 함수를 구분하는 것을 의미합니다.'),
    (7182, 24, 3, 44, 'Python에서 오버라이딩이 사용되는 주된 이유는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "코드의 재사용성을 높이기 위해"}, {"id": "B", "text": "변수의 범위를 제한하기 위해"}, {"id": "C", "text": "주석을 추가하기 위해"}, {"id": "D", "text": "메모리 관리를 돕기 위해"}]', 'A', '오버라이딩은 상속받은 메서드를 재정의하여 클래스의 기능을 확장하거나 변경하는 방법으로, 코드의 재사용성을 높이기 위해 사용됩니다.'),
    (7183, 24, 3, 45, 'Python에서 재귀 함수의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "반복문보다 항상 더 빠르다"}, {"id": "B", "text": "자기 자신을 호출할 수 있다"}, {"id": "C", "text": "메모리를 사용하지 않는다"}, {"id": "D", "text": "다양한 데이터 타입을 지원하지 않는다"}]', 'B', '재귀 함수는 자기 자신을 호출하는 특성을 가지고 있으며, 이를 통해 복잡한 문제를 단순화할 수 있습니다.'),
    (7184, 24, 3, 46, '클래스와 구조체의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "클래스는 메서드를 포함할 수 있고, 구조체는 포함할 수 없다"}, {"id": "B", "text": "구조체는 상속을 지원하고, 클래스는 지원하지 않는다"}, {"id": "C", "text": "클래스는 변수의 접근 제한이 가능하다"}, {"id": "D", "text": "구조체는 함수형 프로그래밍을 지원한다"}]', 'A', '클래스는 메서드를 포함하고, 상속, 다형성과 같은 객체 지향 개념을 지원하지만, 구조체는 데이터 저장에 집중하며 메서드를 포함하지 않습니다.'),
    (7185, 24, 3, 47, '다음 중 변수 추적에 대한 설명으로 맞는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변수의 현재 값을 확인하는 과정이다"}, {"id": "B", "text": "변수의 메모리 주소를 확인하는 과정이다"}, {"id": "C", "text": "변수를 선언하는 방법이다"}, {"id": "D", "text": "변수의 사용 범위를 설정하는 것이다"}]', '["A", "B"]', '변수 추적은 변수의 현재 값 및 메모리 주소를 확인하여 프로그램의 동작을 이해하고 디버깅하는 데 중요한 과정입니다.'),
    (7186, 24, 3, 48, 'Python에서 함수의 기본 구조는 무엇인가?', 'SHORT_ANSWER', NULL, 'def 함수명(매개변수):', 'Python에서 함수는 ''def'' 키워드를 사용하여 정의합니다.'),
    (7187, 24, 3, 49, 'C언어에서 포인터란 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, '메모리 주소를 저장하는 변수', '포인터는 다른 변수의 메모리 주소를 저장하는 변수로, 메모리 관리와 데이터 접근을 효율적으로 할 수 있게 합니다.'),
    (7188, 24, 3, 50, 'Java에서 오버라이딩이란 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "부모 클래스의 메소드를 자식 클래스에서 재정의하는 것"}, {"id": "B", "text": "변수의 값을 덮어쓰는 것"}, {"id": "C", "text": "함수를 여러 번 호출하는 것"}, {"id": "D", "text": "클래스를 상속받는 것"}]', 'A', '오버라이딩은 자식 클래스가 부모 클래스의 메소드를 재정의하여 기능을 변경하는 것을 의미합니다.'),
    (7189, 24, 3, 51, '재귀 함수의 특징으로 옳지 않은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "함수가 자기 자신을 호출한다."}, {"id": "B", "text": "종료 조건이 필요하다."}, {"id": "C", "text": "무한 루프를 발생시킨다."}, {"id": "D", "text": "문제 해결에 효과적일 수 있다."}]', 'C', '재귀 함수는 종료 조건이 명확히 설정되어야 하며, 무한 루프를 발생시키지 않도록 주의해야 합니다.'),
    (7190, 24, 3, 52, 'C언어에서 변수 추적 시 가장 먼저 확인해야 할 점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "변수의 선언 여부"}, {"id": "B", "text": "변수의 스코프"}, {"id": "C", "text": "변수의 초기화 여부"}, {"id": "D", "text": "변수의 데이터 타입"}]', '["A", "C", "D"]', '변수 추적 시에는 변수의 선언 여부, 초기화 여부, 데이터 타입을 먼저 확인하여 올바른 값이 사용되고 있는지 점검해야 합니다.'),
    (7191, 24, 3, 53, 'C언어에서 배열의 기본적인 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "배열의 크기는 고정되어야 한다."}, {"id": "B", "text": "배열의 요소는 서로 다른 타입일 수 있다."}, {"id": "C", "text": "배열은 동적으로 크기를 변경할 수 있다."}, {"id": "D", "text": "배열은 함수의 반환값으로 사용할 수 있다."}]', 'A', 'C언어에서 배열의 크기는 정의 시 고정되어야 하며, 배열의 각 요소는 동일한 데이터 타입을 가져야 합니다.'),
    (7192, 24, 3, 54, '파이썬에서 클래스 상속의 기본 구문은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "class SubClass extends SuperClass:"}, {"id": "B", "text": "class SubClass(SuperClass):"}, {"id": "C", "text": "class SubClass inherits SuperClass:"}, {"id": "D", "text": "class SubClass from SuperClass:"}]', 'B', '파이썬에서 클래스 상속은 ''class SubClass(SuperClass):''와 같은 형태로 정의됩니다.'),
    (7193, 24, 3, 55, '재귀 함수가 종료되는 조건을 무엇이라고 하나?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "기본 사례(base case)"}, {"id": "B", "text": "재귀 사례(recursive case)"}, {"id": "C", "text": "종료 사례(end case)"}, {"id": "D", "text": "최소 사례(min case)"}]', 'A', '재귀 함수는 기본 사례(base case)로 정의된 조건을 만족할 때 종료됩니다.'),
    (7194, 24, 3, 56, 'C언어에서 포인터를 사용하여 변수의 주소를 참조하는 방법을 고르세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "&변수명"}, {"id": "B", "text": "*포인터변수"}, {"id": "C", "text": "변수명[]"}, {"id": "D", "text": "변수명."}]', '["A", "B"]', 'C언어에서 ''&''는 변수의 주소를 가져오고, ''*''는 포인터 변수가 가리키는 값을 참조하는 데 사용됩니다.'),
    (7195, 24, 3, 57, '파이썬에서 배열과 유사한 데이터 구조는 무엇인가?', 'SHORT_ANSWER', NULL, '리스트', '파이썬에서 배열과 유사한 데이터 구조는 리스트입니다.'),
    (7196, 24, 3, 58, '오버로딩의 개념에 맞는 설명은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "같은 이름의 함수가 서로 다른 매개변수를 가질 수 있다."}, {"id": "B", "text": "메모리 주소를 저장하는 변수이다."}, {"id": "C", "text": "하나의 클래스에서만 사용할 수 있다."}, {"id": "D", "text": "재귀적으로 자기 자신을 호출한다."}]', 'A', '오버로딩은 동일한 이름의 함수가 서로 다른 매개변수 목록을 가질 수 있게 하는 기능입니다.'),
    (7197, 24, 3, 59, 'C언어에서 포인터의 주요 역할은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리 주소를 직접 가리킨다."}, {"id": "B", "text": "데이터를 암호화한다."}, {"id": "C", "text": "함수의 오버로딩을 지원한다."}, {"id": "D", "text": "상속을 구현하는 데 사용된다."}]', 'A', '포인터는 메모리의 주소를 가리켜 직접적으로 메모리 데이터를 조작할 수 있게 해줍니다.'),
    (7198, 24, 3, 60, 'Python과 Java의 차이점 중 맞는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Python은 정적 타이핑 언어이다."}, {"id": "B", "text": "Java는 인터프리터 언어이다."}, {"id": "C", "text": "Python은 동적 타이핑 언어이다."}, {"id": "D", "text": "Java는 구조체를 지원한다."}]', 'C', 'Python은 동적 타이핑 언어로, 변수의 타입을 실행 시간에 결정합니다.'),
    (7199, 24, 3, 61, '재귀 함수를 사용하여 피보나치 수열을 계산할 때, 올바른 함수 호출 경로는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "fib(n) = fib(n-1) + fib(n-2)"}, {"id": "B", "text": "fib(n) = n * fib(n-1)"}, {"id": "C", "text": "fib(n) = fib(n-2) + fib(n-3)"}, {"id": "D", "text": "fib(n) = 0 if n = 0; 1 if n = 1"}]', '["A", "D"]', '피보나치 수열의 재귀적 정의는 fib(n) = fib(n-1) + fib(n-2)이며, 기본 조건으로 fib(0) = 0, fib(1) = 1을 사용합니다.'),
    (7200, 24, 3, 62, 'C언어에서 구조체를 정의하는 키워드는?', 'SHORT_ANSWER', NULL, 'struct', 'C언어에서 구조체는 ''struct'' 키워드를 사용하여 정의합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- SQLD > 데이터 모델링 (38문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7201, 25, 1, 1, '슈퍼키와 후보키의 차이점은 무엇인가?', 'SHORT_ANSWER', NULL, '슈퍼키는 데이터를 고유하게 식별할 수 있는 속성의 집합이고, 후보키는 유일성과 최소성을 만족하는 슈퍼키이다.', '슈퍼키는 데이터베이스에서 레코드를 고유하게 식별할 수 있는 속성의 조합을 의미하며, 후보키는 이 중에서 최소성을 만족하는 키로, 유일성을 가지면서도 불필요한 속성을 포함하지 않는 키이다.'),
    (7202, 25, 1, 2, '데이터 모델링에서 NULL 값의 의미는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "알 수 없는 값"}, {"id": "B", "text": "0을 의미한다"}, {"id": "C", "text": "빈 문자열이다"}, {"id": "D", "text": "위배된 데이터이다"}]', 'A', 'NULL 값은 데이터가 존재하지 않거나 알 수 없는 상태를 나타냅니다.'),
    (7203, 25, 1, 3, '정규화의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "데이터 검색 속도 향상"}, {"id": "C", "text": "코드 작성 단순화"}, {"id": "D", "text": "서버 성능 최적화"}]', 'A', '정규화는 데이터베이스 설계에서 데이터 중복을 최소화하고, 데이터 무결성을 향상시키기 위해 수행됩니다.'),
    (7204, 25, 1, 4, '다음 중 후보키의 특성을 가지고 있는 것들은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "유일성"}, {"id": "B", "text": "순서가 중요하다"}, {"id": "C", "text": "최소성"}, {"id": "D", "text": "NULL 값을 가질 수 있다"}]', '["A", "C"]', '후보키는 유일성과 최소성을 만족해야 하며, NULL 값을 가질 수 없습니다.'),
    (7205, 25, 1, 5, '정규화의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "데이터 암호화"}, {"id": "C", "text": "데이터 시각화"}, {"id": "D", "text": "데이터 백업"}]', 'A', '정규화는 데이터베이스의 중복을 줄이고 데이터 무결성을 유지하기 위해 설계된 과정입니다.'),
    (7206, 25, 1, 6, '참조 무결성이란 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL 값을 허용함"}, {"id": "B", "text": "외래 키가 유효한 값이어야 함"}, {"id": "C", "text": "모든 테이블이 반드시 기본키를 가져야 함"}, {"id": "D", "text": "데이터의 타입을 확인하는 것"}]', 'B', '참조 무결성은 외래 키의 값이 항상 유효한 값, 즉 다른 테이블의 기본 키 값과 일치해야 함을 의미합니다.'),
    (7207, 25, 1, 7, '아래 중 대체키의 정의로 옳은 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "모든 속성의 집합"}, {"id": "B", "text": "기본키가 아닌 후보키"}, {"id": "C", "text": "NULL 값을 포함하는 키"}, {"id": "D", "text": "다수의 외래키"}]', 'B', '대체키는 후보키 중에서 기본키로 선택되지 않은 키를 의미합니다.'),
    (7208, 25, 1, 8, '정규화를 통해 해결할 수 없는 문제는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 품질 문제"}, {"id": "B", "text": "비즈니스 논리의 오류"}, {"id": "C", "text": "저장공간의 제약"}, {"id": "D", "text": "성능 저하 문제"}]', '["A", "B", "D"]', '정규화는 데이터 구조를 개선하지만 데이터 품질, 비즈니스 논리의 정확성, 성능 문제를 해결하지 못할 수 있습니다.'),
    (7209, 25, 1, 9, 'NULL 값이란 무엇인가?', 'SHORT_ANSWER', NULL, '데이터 값이 존재하지 않음을 나타내는 상태', 'NULL 값은 특정 속성에 대해 값이 할당되지 않았음을 의미합니다.'),
    (7210, 25, 1, 10, '데이터 모델링에서 엔티티란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '특정 객체나 개념', '엔티티는 데이터베이스에서 특정 객체나 개념을 나타내는 요소입니다.'),
    (7211, 25, 1, 11, 'NULL 값은 언제 사용해야 하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "값이 존재하지 않을 때"}, {"id": "B", "text": "모든 경우에 사용해야 한다"}, {"id": "C", "text": "정상적인 값이 필요할 때"}, {"id": "D", "text": "어떤 데이터에도 적용할 수 없다"}]', 'A', 'NULL 값은 특정 데이터가 존재하지 않을 때 사용해야 합니다.'),
    (7212, 25, 1, 12, '정규화의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "데이터를 복잡하게 만드는 것"}, {"id": "C", "text": "모든 데이터를 하나의 테이블에 모으기"}, {"id": "D", "text": "데이터 무결성을 저하시킨다"}]', 'A', '정규화의 주된 목적은 데이터 중복을 최소화하고 데이터의 무결성을 유지하는 것입니다.'),
    (7213, 25, 1, 13, '다음 중 데이터 모델링의 구성요소로 올바른 것을 모두 선택하시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "엔티티"}, {"id": "B", "text": "정규화"}, {"id": "C", "text": "NULL"}, {"id": "D", "text": "중복 데이터"}]', '["A", "B", "C"]', '데이터 모델링의 구성요소에는 엔티티, 정규화 및 NULL 값의 적절한 사용이 포함됩니다.'),
    (7214, 25, 1, 14, '도메인 무결성의 정의는 무엇인가?', 'SHORT_ANSWER', NULL, '데이터의 유효성과 정확성을 보장하는 규칙', '도메인 무결성은 데이터의 유효성과 정확성을 보장하기 위한 규칙입니다.'),
    (7215, 25, 1, 15, '엔티티란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '실체', '엔티티는 데이터베이스에서 관리하는 주요 개체를 의미합니다.'),
    (7216, 25, 1, 16, '후보키와 대체키의 차이는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "후보키는 기본키가 될 수 있는 유일한 키이다."}, {"id": "B", "text": "후보키는 여러 개가 있을 수 있으며, 대체키는 후보키 중에서 기본키로 선택되지 않은 키이다."}, {"id": "C", "text": "대체키는 무조건 기본키여야 한다."}, {"id": "D", "text": "후보키와 대체키는 같다."}]', 'B', '후보키는 기본키가 될 수 있는 키들의 집합이며, 대체키는 후보키 중에서 기본키로 선택되지 않은 것입니다.'),
    (7217, 25, 1, 17, 'ERD는 무엇의 약자인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Entity-Relationship Diagram"}, {"id": "B", "text": "Entity-Relation Document"}, {"id": "C", "text": "Entity-Reference Diagram"}, {"id": "D", "text": "Entity-Relation Diagram"}]', 'A', 'ERD는 Entity-Relationship Diagram의 약자로, 데이터 모델을 시각적으로 표현합니다.'),
    (7218, 25, 1, 18, '다음 중 도메인 무결성을 설명하는 것에 해당하는 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "속성이 가질 수 있는 값의 범위를 제한한다."}, {"id": "B", "text": "데이터베이스의 성능을 향상시킨다."}, {"id": "C", "text": "유일한 값이 보장된다."}, {"id": "D", "text": "데이터의 관계를 정의한다."}]', '["A", "C"]', '도메인 무결성은 속성이 가질 수 있는 값의 범위를 제한하고, 유일한 값의 보장을 통해 데이터의 정확성을 유지합니다.'),
    (7219, 25, 1, 19, '반정규화는 무엇을 위한 과정인가?', 'SHORT_ANSWER', NULL, '성능 향상', '반정규화는 데이터베이스의 성능을 향상시키기 위해 구조를 약간 비정규화하는 과정입니다.'),
    (7220, 25, 1, 20, '정규화의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복을 최소화하고 무결성을 강화하기 위해"}, {"id": "B", "text": "쿼리 성능을 최적화하기 위해"}, {"id": "C", "text": "데이터베이스의 크기를 줄이기 위해"}, {"id": "D", "text": "트랜잭션 속도를 높이기 위해"}]', 'A', '정규화는 데이터 중복을 줄이고 데이터 무결성을 향상시키기 위해 수행됩니다.'),
    (7221, 25, 1, 21, 'NULL 값이 의미하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 존재하지 않음"}, {"id": "B", "text": "데이터가 0임"}, {"id": "C", "text": "데이터가 유효하지 않음"}, {"id": "D", "text": "데이터가 비어 있음"}]', 'A', 'NULL은 해당 속성의 값이 없음을 나타내며, 이는 데이터가 존재하지 않는 경우를 의미합니다.'),
    (7222, 25, 1, 22, '다음 중 슈퍼키의 정의로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 모든 속성을 포함하는 키"}, {"id": "B", "text": "각 행을 고유하게 식별할 수 있는 속성의 집합"}, {"id": "C", "text": "최소한의 속성으로 이루어진 키"}, {"id": "D", "text": "조합된 속성으로 이루어진 키"}]', 'B', '슈퍼키는 테이블에서 각 행을 고유하게 식별할 수 있는 속성의 집합을 의미합니다.'),
    (7223, 25, 1, 23, '도메인 무결성의 예시를 모두 선택하시오.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "나이 값은 0 이상이어야 한다."}, {"id": "B", "text": "이메일 주소는 형식이 맞아야 한다."}, {"id": "C", "text": "주변 환경에 따라 달라질 수 있다."}, {"id": "D", "text": "전화번호는 숫자로만 구성되어야 한다."}]', '["A", "B", "D"]', '도메인 무결성은 특정 속성이 가질 수 있는 값의 범위나 형식을 제한하여 데이터의 유효성을 보장합니다.'),
    (7224, 25, 1, 24, '논리 모델에서 사용되는 ''식별자''란 무엇인가?', 'SHORT_ANSWER', NULL, '각 엔티티를 고유하게 식별할 수 있는 속성 또는 속성의 조합', '식별자는 특정 엔티티의 고유성을 보장하기 위해 사용됩니다.'),
    (7225, 25, 1, 25, '슈퍼키의 정의는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "각 레코드를 고유하게 식별할 수 있는 속성의 집합"}, {"id": "B", "text": "모든 엔티티를 나타내는 다이어그램"}, {"id": "C", "text": "데이터베이스의 NULL 값을 처리하는 방법"}, {"id": "D", "text": "SQL 쿼리에서 사용되는 조건문"}]', 'A', '슈퍼키는 데이터베이스에서 각 레코드를 고유하게 식별할 수 있는 속성들의 집합을 의미합니다.'),
    (7226, 25, 1, 26, 'ERD는 무엇을 나타내는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스의 물리적 구조"}, {"id": "B", "text": "엔티티 간의 관계를 시각적으로 표현한 것"}, {"id": "C", "text": "SQL 쿼리를 최적화하는 방법"}, {"id": "D", "text": "NULL 값을 관리하는 절차"}]', 'B', 'ERD(엔티티-관계 다이어그램)는 엔티티들 간의 관계를 시각적으로 표현한 도구입니다.'),
    (7227, 25, 1, 27, '참조 무결성의 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 중복을 방지하기 위해"}, {"id": "B", "text": "데이터베이스의 성능을 향상시키기 위해"}, {"id": "C", "text": "모든 엔티티의 관계를 정의하기 위해"}, {"id": "D", "text": "데이터의 일관성을 유지하기 위해"}]', 'D', '참조 무결성은 데이터베이스에서 데이터의 일관성을 유지하기 위해 필수적인 규칙입니다.'),
    (7228, 25, 1, 28, '다음 중 식별자의 역할에 해당하는 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "각 엔티티를 고유하게 식별"}, {"id": "B", "text": "데이터 중복을 허용"}, {"id": "C", "text": "NULL 값을 허용"}, {"id": "D", "text": "관계의 무결성을 보장"}]', '["A", "D"]', '식별자는 각 엔티티를 고유하게 식별하고, 관리를 통해 관계의 무결성을 보장하는 역할을 합니다.'),
    (7229, 25, 1, 29, 'NULL 값이란 무엇인가?', 'SHORT_ANSWER', NULL, '정의되지 않거나 비어 있는 값을 의미한다.', 'NULL 값은 데이터베이스에서 정의되지 않거나 비어 있는 값을 나타내며, 이는 레코드에서 일부 속성이 값이 없음을 의미합니다.'),
    (7230, 25, 1, 30, '정규화의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 중복 최소화"}, {"id": "B", "text": "속도 향상"}, {"id": "C", "text": "데이터 암호화"}, {"id": "D", "text": "사용자 편의성 증대"}]', 'A', '정규화의 주된 목적은 데이터 중복을 최소화하고 무결성을 유지하는 것입니다.'),
    (7231, 25, 1, 31, '후보키와 슈퍼키의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "후보키는 최소성을 가지며, 슈퍼키는 그렇지 않다"}, {"id": "B", "text": "후보키는 NULL값을 허용하고, 슈퍼키는 허용하지 않는다"}, {"id": "C", "text": "후보키는 여러 개 존재할 수 없다"}, {"id": "D", "text": "후보키는 항상 인덱스를 가진다"}]', 'A', '후보키는 최소성을 가지며, 중복 없이 레코드를 식별할 수 있는 속성의 집합인 반면, 슈퍼키는 최소성을 요구하지 않습니다.'),
    (7232, 25, 1, 32, 'NULL 값이 의미하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터가 존재함"}, {"id": "B", "text": "데이터가 비어있음"}, {"id": "C", "text": "데이터의 부재"}, {"id": "D", "text": "데이터가 유효하지 않음"}]', 'C', 'NULL 값은 데이터가 존재하지 않거나, 부재함을 나타냅니다.'),
    (7233, 25, 1, 33, '데이터 모델링에서 식별자의 역할은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터를 고유하게 식별한다"}, {"id": "B", "text": "데이터의 무결성을 보장한다"}, {"id": "C", "text": "데이터 구조를 변경한다"}, {"id": "D", "text": "데이터의 속성을 정의한다"}]', '["A", "B"]', '식별자는 데이터의 고유 식별과 무결성을 보장하는 중요한 역할을 합니다.'),
    (7234, 25, 1, 34, '물리 모델과 논리 모델의 주된 차이점은 무엇인가?', 'SHORT_ANSWER', NULL, '물리 모델은 데이터 저장 방식과 성능을 고려하고, 논리 모델은 데이터의 구조와 관계를 정의한다.', '물리 모델은 데이터베이스의 구현적인 측면을 다루며, 논리 모델은 데이터의 개념적인 구조를 설명합니다.'),
    (7235, 25, 1, 35, '데이터 모델링에서 NULL은 무엇을 의미하나요?', 'SHORT_ANSWER', NULL, '데이터가 존재하지 않음을 나타내는 특수한 값', 'NULL은 데이터베이스에서 값이 없음을 표현하는 용도로 사용됩니다.'),
    (7236, 25, 1, 36, 'ERD에서 엔티티란 무엇을 의미하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스에서 저장되는 객체"}, {"id": "B", "text": "데이터베이스의 관계"}, {"id": "C", "text": "데이터의 무결성 규칙"}, {"id": "D", "text": "SQL 쿼리 구조"}]', 'A', '엔티티는 데이터베이스에서 구체적인 데이터를 저장하기 위해 정의된 객체를 의미합니다.'),
    (7237, 25, 1, 37, '반정규화의 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터 일관성 유지"}, {"id": "B", "text": "데이터베이스 성능 향상"}, {"id": "C", "text": "데이터 중복 최소화"}, {"id": "D", "text": "데이터 모델 복잡성 증가"}]', 'B', '반정규화는 데이터베이스의 성능을 향상시키기 위해 데이터 구조를 간소화하는 과정입니다.'),
    (7238, 25, 1, 38, '다음 중 도메인 무결성에 해당하는 규칙은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "이메일 형식 검증"}, {"id": "B", "text": "방금 입력된 데이터의 고유성"}, {"id": "C", "text": "날짜 형식 검증"}, {"id": "D", "text": "데이터 입력 순서 보장"}]', '["A", "C"]', '도메인 무결성은 데이터의 유효성을 보장하기 위한 규칙으로 특정 형식이나 값의 범위를 제한합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- SQLD > SQL 활용 (47문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7239, 25, 2, 1, 'ROW_NUMBER 함수의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "결과 집합의 각 행에 번호를 매긴다"}, {"id": "B", "text": "데이터를 삭제한다"}, {"id": "C", "text": "데이터를 삽입한다"}, {"id": "D", "text": "데이터를 암호화한다"}]', 'A', 'ROW_NUMBER 함수는 결과 집합의 각 행에 번호를 매겨 정렬된 데이터를 생성하는 데 사용됩니다.'),
    (7240, 25, 2, 2, 'PIVOT 연산자의 주 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 집계한다"}, {"id": "B", "text": "행 데이터를 열로 변환한다"}, {"id": "C", "text": "데이터를 필터링한다"}, {"id": "D", "text": "데이터를 정렬한다"}]', 'B', 'PIVOT 연산자는 행 데이터를 열로 변환하여 데이터를 더 직관적으로 분석할 수 있게 해줍니다.'),
    (7241, 25, 2, 3, 'LEAD와 LAG 함수의 주요 기능은 어떤 것인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행을 비교하는 것"}, {"id": "B", "text": "결과 집합을 정렬하는 것"}, {"id": "C", "text": "데이터를 집계하는 것"}, {"id": "D", "text": "조건을 설정하는 것"}]', 'A', 'LEAD와 LAG 함수는 결과 집합의 특정 행과 그 앞 또는 뒤의 행을 비교할 수 있게 해줍니다.'),
    (7242, 25, 2, 4, 'WHERE 절의 기능은 무엇인가? (복수 정답 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "특정 조건에 따라 데이터를 필터링한다"}, {"id": "B", "text": "결과 집합을 정렬한다"}, {"id": "C", "text": "행을 삭제한다"}, {"id": "D", "text": "조건을 기반으로 데이터를 선택한다"}]', '["A", "D"]', 'WHERE 절은 특정 조건에 따라 데이터를 필터링하고, 조건을 기반으로 데이터를 선택하는 기능을 제공합니다.'),
    (7243, 25, 2, 5, 'INTERSECT 연산자는 무엇을 산출하는가?', 'SHORT_ANSWER', NULL, '두 개의 쿼리 결과 집합에서 공통된 데이터를 반환한다', 'INTERSECT 연산자는 두 개의 쿼리 결과 집합에서 공통된 데이터를 반환합니다.'),
    (7244, 25, 2, 6, '윈도우 함수의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 그룹화하여 집계하는 것"}, {"id": "B", "text": "각 행에 대한 순위를 매기는 것"}, {"id": "C", "text": "NULL 값을 대체하는 것"}, {"id": "D", "text": "쿼리의 결과를 결합하는 것"}]', 'B', '윈도우 함수는 데이터의 각 행에 대해 순위를 매기거나 집계 정보를 제공하는 데 사용됩니다.'),
    (7245, 25, 2, 7, 'COALESCE 함수는 어떤 용도로 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 개의 값을 비교하는 것"}, {"id": "B", "text": "여러 값 중 NULL이 아닌 첫 번째 값을 반환하는 것"}, {"id": "C", "text": "데이터를 정렬하는 것"}, {"id": "D", "text": "서브쿼리를 실행하는 것"}]', 'B', 'COALESCE 함수는 인수 중 NULL이 아닌 첫 번째 값을 반환하여 데이터 처리에서 유용합니다.'),
    (7246, 25, 2, 8, 'HAVING 절은 어떤 상황에서 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHERE 절과 같은 역할을 한다"}, {"id": "B", "text": "GROUP BY에 의해 생성된 결과에 조건을 추가한다"}, {"id": "C", "text": "결과를 정렬하는 데 사용된다"}, {"id": "D", "text": "서브쿼리의 결과를 필터링한다"}]', 'B', 'HAVING 절은 GROUP BY에 의해 생성된 데이터 집합에 대해 조건을 추가하여 필터링할 때 사용됩니다.'),
    (7247, 25, 2, 9, 'SQL에서 NULL 값을 처리하기 위한 함수가 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NVL"}, {"id": "B", "text": "COALESCE"}, {"id": "C", "text": "RANK"}, {"id": "D", "text": "ISNULL"}]', '["C"]', 'RANK 함수는 데이터의 순위를 매기는 데 사용되며 NULL 값 처리와는 관련이 없습니다.'),
    (7248, 25, 2, 10, 'UNION 연산자의 기능은 무엇인가?', 'SHORT_ANSWER', NULL, '여러 SELECT 문의 결과를 결합하여 하나의 결과 집합으로 만드는 것', 'UNION 연산자는 여러 SELECT 문의 결과를 하나로 결합하여 반환합니다.'),
    (7249, 25, 2, 11, 'GROUP BY 절의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 그룹화하여 집계 함수 적용"}, {"id": "B", "text": "데이터를 삭제하기 위함"}, {"id": "C", "text": "테이블을 생성하기 위함"}, {"id": "D", "text": "데이터를 정렬하기 위함"}]', 'A', 'GROUP BY 절은 데이터를 특정 컬럼을 기준으로 그룹화하고, 집계 함수를 적용하기 위해 사용됩니다.'),
    (7250, 25, 2, 12, 'HAVING 절은 어떤 상황에서 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHERE 절과 함께 사용된다"}, {"id": "B", "text": "그룹화된 결과에 조건을 추가할 때 사용된다"}, {"id": "C", "text": "데이터 삽입 시 사용된다"}, {"id": "D", "text": "테이블을 조인할 때 사용된다"}]', 'B', 'HAVING 절은 GROUP BY로 그룹화된 데이터에 대해 조건을 추가하는 데 사용됩니다.'),
    (7251, 25, 2, 13, 'ROW_NUMBER() 함수의 주 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "NULL 값을 대체하기 위해 사용된다"}, {"id": "B", "text": "각 행에 고유한 번호를 매기기 위해 사용된다"}, {"id": "C", "text": "데이터를 집계하기 위해 사용된다"}, {"id": "D", "text": "결과를 정렬하기 위해 사용된다"}]', 'B', 'ROW_NUMBER() 함수는 쿼리 결과의 각 행에 고유한 번호를 부여하는 데 사용됩니다.'),
    (7252, 25, 2, 14, '다음 중 NVL과 COALESCE의 공통점은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "둘 다 NULL 값을 처리한다"}, {"id": "B", "text": "둘 다 특정 값을 대체할 수 있다"}, {"id": "C", "text": "둘 다 문자열을 비교한다"}, {"id": "D", "text": "둘 다 집계 함수와 함께 사용된다"}]', '["A", "B"]', 'NVL과 COALESCE는 모두 NULL 값을 처리하고 특정 값을 대체하는 데 사용됩니다.'),
    (7253, 25, 2, 15, 'SQL에서 JOIN의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, '두 개 이상의 테이블을 결합하여 관련된 데이터를 조회하는 것', 'JOIN은 서로 관련 있는 여러 테이블의 데이터를 조합하여 조회하는 역할을 합니다.'),
    (7254, 25, 2, 16, 'SQL에서 NULL 값을 대체하는 함수는 무엇인가?', 'SHORT_ANSWER', NULL, 'NVL 또는 COALESCE', 'NVL과 COALESCE 함수는 NULL 값을 다른 값으로 대체하는 데 사용됩니다.'),
    (7255, 25, 2, 17, '다음 중 집합 연산자에 해당하지 않는 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "UNION"}, {"id": "B", "text": "JOIN"}, {"id": "C", "text": "INTERSECT"}, {"id": "D", "text": "EXCEPT"}]', 'B', 'JOIN은 집합 연산자가 아닌 테이블 간의 관계를 연결하는 연산입니다.'),
    (7256, 25, 2, 18, '다음 중 PIVOT 구문을 사용하는 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "결과를 정렬하기 위해"}, {"id": "B", "text": "행 데이터를 열 데이터로 변환하기 위해"}, {"id": "C", "text": "NULL 값을 처리하기 위해"}, {"id": "D", "text": "서브쿼리를 생성하기 위해"}]', 'B', 'PIVOT 구문은 행 데이터를 열 형식으로 변환하여 데이터를 분석하는 데 용이하게 합니다.'),
    (7257, 25, 2, 19, '다음 중 SQL에서 여러 정답을 찾는 데 사용할 수 있는 함수는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NVL"}, {"id": "B", "text": "COALESCE"}, {"id": "C", "text": "UNION"}, {"id": "D", "text": "ORDER BY"}]', '["A", "B", "C"]', 'NVL, COALESCE는 NULL 값을 처리하고, UNION은 여러 결과를 결합하는 데 사용됩니다.'),
    (7258, 25, 2, 20, 'LAG 함수의 주요 용도는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 데이터를 가져온다."}, {"id": "B", "text": "다음 행의 데이터를 가져온다."}, {"id": "C", "text": "데이터를 정렬한다."}, {"id": "D", "text": "NULL 값을 대체한다."}]', 'A', 'LAG 함수는 현재 행의 이전 행 데이터를 참조하여 가져오는 데 사용됩니다.'),
    (7259, 25, 2, 21, 'GROUP BY 절과 함께 사용할 수 있는 함수는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "AVG"}, {"id": "B", "text": "ROW_NUMBER"}, {"id": "C", "text": "LEAD"}, {"id": "D", "text": "INTERSECT"}]', 'A', 'GROUP BY 절은 집계 함수와 함께 사용되어 그룹화된 데이터의 요약 정보를 제공합니다.'),
    (7260, 25, 2, 22, 'HAVING 절의 사용 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬한다."}, {"id": "B", "text": "그룹화된 데이터에 조건을 적용한다."}, {"id": "C", "text": "NULL 값을 대체한다."}, {"id": "D", "text": "행 번호를 부여한다."}]', 'B', 'HAVING 절은 GROUP BY로 그룹화된 데이터에 대해 조건을 적용하는 데 사용됩니다.'),
    (7261, 25, 2, 23, '다음 중 SQL에서 NULL 값을 처리하는 함수는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NVL"}, {"id": "B", "text": "LAG"}, {"id": "C", "text": "ISNULL"}, {"id": "D", "text": "LEAD"}]', '["A", "C"]', 'NVL 함수와 ISNULL 함수는 모두 NULL 값을 처리하여 대체 값을 제공하는 데 사용됩니다.'),
    (7262, 25, 2, 24, 'ROW_NUMBER 함수는 무엇을 반환하나요?', 'SHORT_ANSWER', NULL, '각 행에 대한 고유한 번호', ''),
    (7263, 25, 2, 25, 'LAG 함수의 주 용도는 무엇인가요?', 'SHORT_ANSWER', NULL, '이전 행의 값을 참조하기 위해 사용된다.', 'LAG 함수는 현재 행의 이전 행의 값에 접근할 수 있도록 도와줍니다.'),
    (7264, 25, 2, 26, 'HAVING 절은 어떤 상황에서 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHERE 절과 함께 사용된다."}, {"id": "B", "text": "그룹화된 결과에 조건을 추가할 때 사용된다."}, {"id": "C", "text": "데이터를 삽입할 때 사용된다."}, {"id": "D", "text": "NULL 값을 처리할 때 사용된다."}]', 'B', 'HAVING 절은 GROUP BY 절과 함께 사용되며, 집계된 결과에 조건을 추가합니다.'),
    (7265, 25, 2, 27, 'JOIN의 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "단일 테이블에서 데이터를 검색하기 위해 사용된다."}, {"id": "B", "text": "여러 테이블에서 데이터를 결합하기 위해 사용된다."}, {"id": "C", "text": "데이터를 삭제하기 위해 사용된다."}, {"id": "D", "text": "쿼리 성능을 향상시키기 위해 사용된다."}]', 'B', 'JOIN은 여러 테이블의 데이터를 결합하여 통합된 결과를 생성하는 데 필요합니다.'),
    (7266, 25, 2, 28, 'COALESCE 함수의 기능은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "NULL 값을 다른 값으로 대체한다."}, {"id": "B", "text": "여러 값을 비교한다."}, {"id": "C", "text": "조건에 따라 다른 결과를 반환한다."}, {"id": "D", "text": "데이터를 정렬한다."}]', '["A", "B"]', 'COALESCE 함수는 NULL 값을 처리하며, 여러 값 중 첫 번째로 NULL이 아닌 값을 반환합니다.'),
    (7267, 25, 2, 29, 'NVL 함수의 주된 기능은 무엇인가?', 'SHORT_ANSWER', NULL, 'NULL 값을 다른 값으로 대체하는 것', 'NVL 함수는 NULL 값을 지정한 다른 값으로 대체하여 결과를 보다 유용하게 만듭니다.'),
    (7268, 25, 2, 30, 'RANK 함수는 어떤 상황에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "행의 순위를 매기기 위해"}, {"id": "B", "text": "중복된 값을 제거하기 위해"}, {"id": "C", "text": "NULL 값을 처리하기 위해"}, {"id": "D", "text": "결합된 테이블의 데이터를 필터링하기 위해"}]', 'A', 'RANK 함수는 결과 집합의 행에 순위를 매기는 데 사용됩니다.'),
    (7269, 25, 2, 31, 'JOIN을 사용할 때 주의해야 할 점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "JOIN의 종류에 따라 결과가 다를 수 있다"}, {"id": "B", "text": "JOIN은 항상 INNER JOIN만 사용해야 한다"}, {"id": "C", "text": "JOIN은 성능에 영향을 미치지 않는다"}, {"id": "D", "text": "JOIN을 사용할 때는 반드시 GROUP BY를 사용해야 한다"}]', 'A', 'JOIN의 종류에 따라 결과가 다르게 나타나므로 상황에 맞는 JOIN을 선택해야 합니다.'),
    (7270, 25, 2, 32, '다음 중 GROUP BY와 함께 사용할 수 있는 집계 함수는 무엇인가? (복수 정답)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "SUM"}, {"id": "B", "text": "RANK"}, {"id": "C", "text": "COUNT"}, {"id": "D", "text": "DECODE"}]', '["A", "C"]', 'GROUP BY와 함께 SUM, COUNT와 같은 집계 함수를 사용하여 데이터를 요약할 수 있습니다.'),
    (7271, 25, 2, 33, 'COALESCE 함수의 주요 용도는 무엇인가?', 'SHORT_ANSWER', NULL, 'NULL 값을 다른 값으로 대체하는 것', 'COALESCE 함수는 주어진 인자 중에서 NULL이 아닌 첫 번째 값을 반환하여 NULL 값을 처리하는 데 유용합니다.'),
    (7272, 25, 2, 34, 'LEAD 함수의 주 용도는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "현재 행의 다음 값을 가져오는 것"}, {"id": "B", "text": "현재 행의 이전 값을 가져오는 것"}, {"id": "C", "text": "행을 정렬하는 것"}, {"id": "D", "text": "행의 개수를 세는 것"}]', 'A', 'LEAD 함수는 결과 집합에서 현재 행의 다음 행에 있는 값을 반환하는 데 사용됩니다.'),
    (7273, 25, 2, 35, 'HAVING 절은 주로 어떤 상황에서 사용되는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "WHERE 절과 같이 사용된다"}, {"id": "B", "text": "GROUP BY와 함께 사용된다"}, {"id": "C", "text": "INSERT 문에서 사용된다"}, {"id": "D", "text": "JOIN 문에서 사용된다"}]', 'B', 'HAVING 절은 집계된 데이터에 대한 조건을 설정하기 위해 GROUP BY와 함께 사용됩니다.'),
    (7274, 25, 2, 36, 'CASE 문과 DECODE 함수의 공통점은 무엇인가? (복수 선택 가능)', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "조건문을 작성할 수 있다"}, {"id": "B", "text": "NULL 값을 처리할 수 있다"}, {"id": "C", "text": "사용자 정의 함수이다"}, {"id": "D", "text": "값에 따라 다른 결과를 반환할 수 있다"}]', '["A", "D"]', 'CASE 문과 DECODE 함수 모두 조건식에 따라 다른 결과를 반환할 수 있으며, 이를 통해 쿼리의 흐름을 제어할 수 있습니다.'),
    (7275, 25, 2, 37, 'PIVOT을 사용할 때 주의해야 할 점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "동일한 데이터 타입만 사용할 수 있다"}, {"id": "B", "text": "항상 GROUP BY가 필요하다"}, {"id": "C", "text": "행과 열을 수동으로 설정해야 한다"}, {"id": "D", "text": "데이터베이스 버전에 따라 다르게 동작할 수 있다"}]', 'D', 'PIVOT의 동작 방식은 데이터베이스 버전에 따라 차이가 있을 수 있으므로, 관련 문서를 참조하는 것이 중요합니다.'),
    (7276, 25, 2, 38, 'SQL에서 데이터를 선택하는 기본 문장은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "SELECT"}, {"id": "B", "text": "FROM"}, {"id": "C", "text": "WHERE"}, {"id": "D", "text": "JOIN"}]', 'A', 'SELECT 문장은 SQL에서 데이터를 선택하는 기본적인 문장입니다.'),
    (7277, 25, 2, 39, 'LEAD 함수의 주요 기능은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 값을 가져오기"}, {"id": "B", "text": "다음 행의 값을 가져오기"}, {"id": "C", "text": "NULL 값을 대체하기"}, {"id": "D", "text": "행의 순위를 매기기"}]', 'B', 'LEAD 함수는 현재 행의 다음 행의 값을 가져오는 기능을 합니다.'),
    (7278, 25, 2, 40, '다음 중 CASE 문을 사용하는 이유는 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 정렬하기 위해"}, {"id": "B", "text": "조건부 논리를 구현하기 위해"}, {"id": "C", "text": "행을 결합하기 위해"}, {"id": "D", "text": "NULL 값을 대체하기 위해"}]', 'B', 'CASE 문은 SQL에서 조건부 논리를 구현하는 데 사용됩니다.'),
    (7279, 25, 2, 41, 'SQL에서 NULL 값을 ''0''으로 대체하기 위해 사용하는 함수는 무엇인가요?', 'SHORT_ANSWER', NULL, 'NVL', 'NVL 함수는 NULL 값을 특정 값으로 대체하는 데 사용됩니다.'),
    (7280, 25, 2, 42, '다음 중 UNION 연산자의 올바른 사용법으로 올바른 것은 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "두 개의 SELECT 문의 결과를 결합할 때 사용한다."}, {"id": "B", "text": "두 개의 SELECT 문의 데이터 타입이 같아야 한다."}, {"id": "C", "text": "결과에 중복된 데이터를 포함할 수 있다."}, {"id": "D", "text": "UNION을 사용할 때는 WHERE 조건이 필요하다."}]', '["A", "B"]', 'UNION 연산자는 두 개의 SELECT 문의 결과를 결합하고 데이터 타입이 같아야 하며 중복된 데이터는 제거됩니다.'),
    (7281, 25, 2, 43, 'GROUP BY 절의 주 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터를 집계하기 위함"}, {"id": "B", "text": "데이터를 삽입하기 위함"}, {"id": "C", "text": "데이터를 삭제하기 위함"}, {"id": "D", "text": "데이터를 업데이트하기 위함"}]', 'A', 'GROUP BY 절은 데이터를 특정 기준에 따라 그룹화하여 집계함수를 적용하기 위해 사용됩니다.'),
    (7282, 25, 2, 44, 'HAVING 절의 사용 목적은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "그룹화된 데이터에 필터를 적용하기 위함"}, {"id": "B", "text": "모든 데이터를 출력하기 위함"}, {"id": "C", "text": "데이터를 정렬하기 위함"}, {"id": "D", "text": "데이터를 결합하기 위함"}]', 'A', 'HAVING 절은 GROUP BY에 의해 그룹화된 결과에 필터를 적용하기 위해 사용됩니다.'),
    (7283, 25, 2, 45, 'LEAD 함수는 무엇을 수행하나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "이전 행의 값을 가져온다"}, {"id": "B", "text": "다음 행의 값을 가져온다"}, {"id": "C", "text": "특정 행을 삭제한다"}, {"id": "D", "text": "행의 개수를 계산한다"}]', 'B', 'LEAD 함수는 데이터의 다음 행의 값을 가져오는 데 유용합니다.'),
    (7284, 25, 2, 46, 'CASE 또는 DECODE 함수의 사용 예시는 무엇인가요?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "조건에 따라 다른 값을 반환하기 위해"}, {"id": "B", "text": "데이터를 삽입하기 위해"}, {"id": "C", "text": "NULL 값을 처리하기 위해"}, {"id": "D", "text": "데이터를 삭제하기 위해"}]', '["A", "C"]', 'CASE 또는 DECODE 함수는 조건에 따라 다른 값을 반환하고, NULL 값을 처리하는 데 사용됩니다.'),
    (7285, 25, 2, 47, 'NVL 함수의 역할은 무엇인가요?', 'SHORT_ANSWER', NULL, 'NULL 값을 다른 값으로 대체한다.', 'NVL 함수는 NULL 값을 다른 값으로 대체하는 기능을 제공합니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

-- SQLD > SQL 최적화 (42문제)
INSERT INTO `quiz_course_question` (`id`, `quiz_course_id`, `section_number`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `explanation`)
VALUES
    (7286, 25, 3, 1, 'Hash Join의 주요 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리에 해시 테이블을 생성하여 데이터를 결합한다."}, {"id": "B", "text": "정렬된 데이터를 기반으로 조인을 수행한다."}, {"id": "C", "text": "인덱스 없이도 빠른 조회를 제공한다."}, {"id": "D", "text": "데이터베이스의 파티셔닝을 필요로 한다."}]', 'A', 'Hash Join은 메모리에 해시 테이블을 생성하여 데이터를 결합하는 조인 방식이다.'),
    (7287, 25, 3, 2, '테이블 파티셔닝의 주된 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터의 일관성을 보장한다."}, {"id": "B", "text": "대량의 데이터를 효율적으로 관리하고 성능을 개선한다."}, {"id": "C", "text": "데이터를 암호화하는 것이다."}, {"id": "D", "text": "모든 테이블을 하나의 데이터베이스에 통합한다."}]', 'B', '테이블 파티셔닝은 대량의 데이터를 효율적으로 관리하고 성능을 개선하기 위해 사용된다.'),
    (7288, 25, 3, 3, 'Sort Merge Join의 특징으로 옳은 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 테이블을 정렬한 후 병합한다."}, {"id": "B", "text": "해시 함수를 사용하여 조인을 수행한다."}, {"id": "C", "text": "주로 소규모 데이터에 적합하다."}, {"id": "D", "text": "단일 테이블에서만 사용할 수 있다."}]', 'A', 'Sort Merge Join은 두 테이블을 정렬한 후 병합하여 결과를 생성하는 조인 방식이다.'),
    (7289, 25, 3, 4, 'SQL 최적화에서 카디널리티의 의미는 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터의 중복도"}, {"id": "B", "text": "고유값의 수"}, {"id": "C", "text": "데이터베이스 크기"}, {"id": "D", "text": "관계형 데이터의 성질"}]', '["B", "A"]', '카디널리티는 데이터베이스에서 고유값의 수와 데이터의 중복도를 의미하며, 쿼리 성능 최적화에 중요한 기준이 된다.'),
    (7290, 25, 3, 5, 'SQL에서 실행 계획을 확인하기 위해 사용하는 명령어는 무엇인가?', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하여 SQL 쿼리의 실행 계획을 확인할 수 있다.'),
    (7291, 25, 3, 6, 'Nested Loop 조인의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "작은 테이블에 대해 효율적이다."}, {"id": "B", "text": "대량의 데이터를 빠르게 처리한다."}, {"id": "C", "text": "정렬된 데이터를 사용하는 것이 필수적이다."}, {"id": "D", "text": "인덱스를 사용하지 않는다."}]', 'A', 'Nested Loop 조인은 일반적으로 작은 테이블을 다룰 때 효율성이 높습니다.'),
    (7292, 25, 3, 7, 'Sort Merge 조인이 가장 적합한 상황은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "정렬된 데이터에 대해 사용될 때."}, {"id": "B", "text": "작은 테이블 간의 조인."}, {"id": "C", "text": "인덱스를 사용할 수 없는 경우."}, {"id": "D", "text": "중복 데이터가 많은 경우."}]', 'A', 'Sort Merge 조인은 데이터가 정렬되어 있을 때 매우 빠르게 수행됩니다.'),
    (7293, 25, 3, 8, 'SQL 최적화에 있어 통계 정보의 역할은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 실행 계획을 결정하는 데 도움을 준다."}, {"id": "B", "text": "데이터 보안을 강화한다."}, {"id": "C", "text": "데이터의 정합성을 검증한다."}, {"id": "D", "text": "인덱스를 자동으로 생성한다."}]', 'A', '통계 정보는 쿼리 최적화를 위해 필요한 실행 계획을 결정하는 데 도움을 줍니다.'),
    (7294, 25, 3, 9, 'SQL 최적화에서 여러 개의 인덱스를 사용할 때의 장점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리 성능을 향상시킨다."}, {"id": "B", "text": "데이터 저장 공간을 줄인다."}, {"id": "C", "text": "다양한 쿼리에 대해 유연성을 제공한다."}, {"id": "D", "text": "데이터 중복을 방지한다."}]', '["A", "C"]', '여러 개의 인덱스를 사용하면 쿼리 성능을 향상시키고 다양한 쿼리에 대해 유연한 처리가 가능합니다.'),
    (7295, 25, 3, 10, '테이블 파티셔닝이 SQL 최적화에 미치는 영향은?', 'SHORT_ANSWER', NULL, '데이터 접근 성능을 향상시키고 유지 관리를 용이하게 한다.', '테이블 파티셔닝은 대량의 데이터를 관리하기 쉽게 만들고 필요한 데이터에 빠르게 접근할 수 있도록 합니다.'),
    (7296, 25, 3, 11, '해시 조인의 주요 목적은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "대량의 데이터를 효율적으로 조인하기 위해"}, {"id": "B", "text": "데이터를 정렬하기 위해"}, {"id": "C", "text": "뷰를 생성하기 위해"}, {"id": "D", "text": "시퀀스를 만들기 위해"}]', 'A', '해시 조인은 두 테이블을 조인할 때 해시 테이블을 사용하여 대량 데이터를 효율적으로 처리하기 위해 사용됩니다.'),
    (7297, 25, 3, 12, '옵티마이저의 기능은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "가장 효율적인 실행 계획을 수립하는 것"}, {"id": "B", "text": "테이블을 파티셔닝하는 것"}, {"id": "C", "text": "뷰를 삭제하는 것"}, {"id": "D", "text": "시퀀스를 재설정하는 것"}]', 'A', '옵티마이저는 SQL 쿼리를 실행하는 데 가장 효율적인 실행 계획을 수립하는 역할을 합니다.'),
    (7298, 25, 3, 13, '다음 중 SQL 최적화와 관련되지 않은 것은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "테이블 파티셔닝"}, {"id": "B", "text": "보안 정책"}, {"id": "C", "text": "해시 조인"}, {"id": "D", "text": "정렬 병합 조인"}]', '["B"]', '보안 정책은 SQL 최적화와 직접적인 관련이 없는 요소입니다.'),
    (7299, 25, 3, 14, '테이블 파티셔닝의 주된 장점은 무엇인가?', 'SHORT_ANSWER', NULL, '성능 향상', '테이블 파티셔닝은 큰 테이블을 여러 개의 작은 파티션으로 나누어 성능을 향상시키는 기술입니다.'),
    (7300, 25, 3, 15, '다음 중 Hash Join의 특징으로 올바른 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "대량의 데이터에서 성능이 우수하다."}, {"id": "B", "text": "인덱스를 사용할 필요가 없다."}, {"id": "C", "text": "결과가 항상 정렬된 상태로 반환된다."}, {"id": "D", "text": "하나의 테이블만 조인할 수 있다."}]', 'A', 'Hash Join은 대량의 데이터 조인 시 성능이 우수합니다.'),
    (7301, 25, 3, 16, '실행 계획을 확인하는 SQL 명령어는?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "EXPLAIN"}, {"id": "B", "text": "ANALYZE"}, {"id": "C", "text": "DESCRIBE"}, {"id": "D", "text": "PLAN"}]', 'A', 'EXPLAIN 명령어를 통해 쿼리의 실행 계획을 확인할 수 있습니다.'),
    (7302, 25, 3, 17, '선택도가 높다는 것은 무엇을 의미하는가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "많은 행이 조건을 만족함."}, {"id": "B", "text": "거의 모든 행이 조건을 만족함."}, {"id": "C", "text": "적은 수의 행이 조건을 만족함."}, {"id": "D", "text": "조건이 없는 쿼리임."}]', 'C', '선택도가 높다는 것은 조건을 만족하는 행이 적다는 것을 의미합니다.'),
    (7303, 25, 3, 18, 'Hash Join과 Nested Loop 중 성능이 더 좋은 경우는?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터가 정렬되어 있는 경우"}, {"id": "B", "text": "데이터가 대량인 경우"}, {"id": "C", "text": "인덱스를 사용할 수 있는 경우"}, {"id": "D", "text": "소량의 데이터 조인 시"}]', '["B", "C"]', 'Hash Join은 대량의 데이터에서 성능이 좋고, 인덱스를 사용할 수 있는 경우에도 유리합니다.'),
    (7304, 25, 3, 19, 'SQL에서 통계 정보의 역할은 무엇인가?', 'SHORT_ANSWER', NULL, '쿼리 최적화와 실행 계획 수립을 위한 데이터 분포 정보 제공', ''),
    (7305, 25, 3, 20, '카디널리티란 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '테이블의 행 수', '카디널리티는 데이터베이스에서 테이블의 행 수를 의미하며, 이는 쿼리 성능에 큰 영향을 미친다.'),
    (7306, 25, 3, 21, '다음 중 옵티마이저의 역할이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "쿼리 실행 계획을 수립한다."}, {"id": "B", "text": "데이터를 백업한다."}, {"id": "C", "text": "인덱스를 최적화한다."}, {"id": "D", "text": "최적의 쿼리 경로를 선택한다."}]', 'B', '옵티마이저는 쿼리 실행 계획을 수립하고 최적의 쿼리 경로를 선택하는 역할을 하며, 데이터를 백업하는 것은 다른 작업이다.'),
    (7307, 25, 3, 22, 'Hash Join과 Sort Merge Join의 차이점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Hash Join은 해시 테이블을 사용한다."}, {"id": "B", "text": "Sort Merge Join은 데이터를 정렬한다."}, {"id": "C", "text": "둘 다 동일한 성능을 가진다."}, {"id": "D", "text": "Hash Join은 항상 더 빠르다."}]', 'A', 'Hash Join은 해시 테이블을 사용하여 조인을 수행하며, Sort Merge Join은 먼저 데이터를 정렬한 후 병합하는 방식이다.'),
    (7308, 25, 3, 23, '다음 중 테이블 파티셔닝의 장점이 아닌 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "데이터 관리를 용이하게 한다."}, {"id": "B", "text": "쿼리 성능을 향상시킨다."}, {"id": "C", "text": "데이터 저장 공간을 무제한으로 증가시킨다."}, {"id": "D", "text": "대량의 데이터를 더 효율적으로 처리할 수 있다."}]', '["C"]', '테이블 파티셔닝은 데이터 관리를 용이하게 하고 쿼리 성능을 향상시키지만, 데이터 저장 공간을 무제한으로 증가시키는 것은 아니다.'),
    (7309, 25, 3, 24, '다음 중 조인 기법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "Sort Merge"}, {"id": "B", "text": "Hash Join"}, {"id": "C", "text": "Index Scan"}, {"id": "D", "text": "Nested Loop Join"}]', 'C', 'Index Scan은 조인 기법이 아니라 인덱스를 활용한 검색 방법입니다.'),
    (7310, 25, 3, 25, '카디널리티가 낮은 데이터셋의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "유일한 값이 적다"}, {"id": "B", "text": "유일한 값이 많다"}, {"id": "C", "text": "데이터의 필터링력이 높다"}, {"id": "D", "text": "쿼리 성능이 항상 좋다"}]', 'A', '카디널리티가 낮다는 것은 유일한 값이 적다는 것을 의미합니다.'),
    (7311, 25, 3, 26, '다음 중 인덱스의 장점이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "검색 속도 향상"}, {"id": "B", "text": "디스크 공간 절약"}, {"id": "C", "text": "정렬된 결과 제공"}, {"id": "D", "text": "쿼리 성능 개선"}]', 'B', '인덱스는 검색 성능을 향상시키지만, 추가적인 디스크 공간을 소모합니다.'),
    (7312, 25, 3, 27, 'Hash Join의 장점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "대량의 데이터 처리에 효율적이다"}, {"id": "B", "text": "정렬이 필요 없다"}, {"id": "C", "text": "지속적으로 수행하는 것이 용이하다"}, {"id": "D", "text": "작은 테이블 처리에 최적화되어 있다"}]', '["A", "B"]', 'Hash Join은 대량의 데이터 처리에 효율적이며 정렬이 필요 없다는 장점을 가집니다.'),
    (7313, 25, 3, 28, 'SQL에서 실행 계획을 확인하는 명령어는?', 'SHORT_ANSWER', NULL, 'EXPLAIN', 'EXPLAIN 명령어를 사용하면 SQL 쿼리의 실행 계획을 확인할 수 있습니다.'),
    (7314, 25, 3, 29, 'SQL 최적화에서 Hash Join의 특징은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "메모리에 해시 테이블을 생성하여 조인하는 방법이다."}, {"id": "B", "text": "정렬된 데이터를 기반으로 조인하는 방법이다."}, {"id": "C", "text": "단순히 두 테이블을 순차적으로 비교하는 방법이다."}, {"id": "D", "text": "인덱스를 사용하지 않는 가장 느린 조인 방법이다."}]', 'A', 'Hash Join은 메모리에 해시 테이블을 생성하여 조인을 수행하는 방법으로, 큰 테이블 간의 조인에서 효율적이다.'),
    (7315, 25, 3, 30, 'Nested Loop Join이 가장 효과적인 경우는 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 테이블 모두 큰 경우에 적합하다."}, {"id": "B", "text": "하나의 테이블이 작은 경우에 적합하다."}, {"id": "C", "text": "모든 데이터가 정렬되어 있는 경우에 적합하다."}, {"id": "D", "text": "조인 조건이 없는 경우에 적합하다."}]', 'B', 'Nested Loop Join은 하나의 테이블이 작고 다른 테이블이 클 때 빠르게 결과를 찾을 수 있다.'),
    (7316, 25, 3, 31, 'SQL에서 카디널리티(Cardinality)가 의미하는 것은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "테이블의 총 행 수를 의미한다."}, {"id": "B", "text": "쿼리 실행 시간이 얼마나 걸리는지를 의미한다."}, {"id": "C", "text": "열의 고유 값 수를 의미한다."}, {"id": "D", "text": "인덱스의 종류를 의미한다."}]', 'C', '카디널리티는 특정 열의 고유한 값의 수를 뜻하며, 쿼리 최적화에 큰 영향을 미친다.'),
    (7317, 25, 3, 32, 'SQL 최적화를 위해 실행 계획을 분석할 때 주의해야 할 점은 무엇인가?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "쿼리의 전체 실행 시간 분석하기"}, {"id": "B", "text": "여러 실행 계획 비교하기"}, {"id": "C", "text": "데이터베이스 버전 확인하기"}, {"id": "D", "text": "조인 방식 확인하기"}]', '["A", "B", "D"]', '실행 계획 분석 시 전체 실행 시간, 다양한 실행 계획 비교, 조인 방식을 확인해야 적절한 최적화를 수행할 수 있다.'),
    (7318, 25, 3, 33, 'SQL에서 동의어(Synonyms)의 주 목적은 무엇인가?', 'SHORT_ANSWER', NULL, '객체 이름을 간소화하여 사용하기 위함이다.', '동의어는 데이터베이스 객체의 이름을 간소화하여 사용하고 접근성을 향상시키기 위해 사용된다.'),
    (7319, 25, 3, 34, '선택도가 무엇을 의미하는가?', 'SHORT_ANSWER', NULL, '쿼리의 특정 조건이 만족될 가능성', '선택도는 데이터베이스 쿼리에서 특정 조건이 충족될 확률을 나타냅니다.'),
    (7320, 25, 3, 35, '다음 중 실행 계획을 최적화하는 방법이 아닌 것은?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "인덱스 활용"}, {"id": "B", "text": "비효율적인 쿼리 작성"}, {"id": "C", "text": "힌트 사용"}, {"id": "D", "text": "정규화된 데이터 모델"}]', 'B', '비효율적인 쿼리 작성은 실행 계획을 최적화하는 방법이 아닙니다.'),
    (7321, 25, 3, 36, 'Sort Merge와 Hash Join의 공통점은 무엇인가?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "두 테이블을 결합하는 방법이다."}, {"id": "B", "text": "인덱스를 필요로 한다."}, {"id": "C", "text": "서브쿼리를 사용한다."}, {"id": "D", "text": "그룹화된 결과를 반환한다."}]', 'A', 'Sort Merge와 Hash Join은 둘 다 두 개의 테이블을 결합하는 방법입니다.'),
    (7322, 25, 3, 37, '다음 중 SQL 최적화 기법으로 올바른 것은?', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "인덱스 생성"}, {"id": "B", "text": "시퀀스 사용"}, {"id": "C", "text": "비효율적인 쿼리 작성"}, {"id": "D", "text": "뷰 활용"}]', '["A", "B", "D"]', '인덱스 생성, 시퀀스 사용, 뷰 활용은 SQL 최적화 기법입니다.'),
    (7323, 25, 3, 38, '뷰(View)는 어떤 목적을 위해 사용되나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "복잡한 쿼리를 단순화하기 위해"}, {"id": "B", "text": "데이터를 삭제하기 위해"}, {"id": "C", "text": "성능을 저하시키기 위해"}, {"id": "D", "text": "데이터베이스를 백업하기 위해"}]', 'A', '뷰는 복잡한 SQL 쿼리를 간단하게 표현할 수 있도록 도와줍니다.'),
    (7324, 25, 3, 39, 'Nested Loop와 Sort Merge 중 어떤 것이 빠른 성능을 보이는 경우가 많나요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "항상 Nested Loop가 빠르다"}, {"id": "B", "text": "Sort Merge가 일반적으로 빠르다"}, {"id": "C", "text": "두 방법의 성능은 동일하다"}, {"id": "D", "text": "항상 Sort Merge가 느리다"}]', 'B', 'Sort Merge 연산은 특정 조건에서 더 빠른 성능을 보여줄 수 있습니다.'),
    (7325, 25, 3, 40, '옵티마이저가 사용하는 실행 계획(Execution Plan)의 역할은 무엇인가요?', 'MULTIPLE_CHOICE', '[{"id": "A", "text": "데이터베이스를 초기화하는 것"}, {"id": "B", "text": "SQL 쿼리를 최적의 경로로 실행하는 것"}, {"id": "C", "text": "사용자에게 결과를 보여주는 것"}, {"id": "D", "text": "디스크 공간을 관리하는 것"}]', 'B', '실행 계획은 SQL 쿼리를 가장 효율적으로 수행하기 위한 경로를 결정합니다.'),
    (7326, 25, 3, 41, '다음 중 SQL 최적화와 관련된 키워드로 올바른 것을 모두 선택하세요.', 'MULTIPLE_CHOICE_MULTIPLE', '[{"id": "A", "text": "카디널리티"}, {"id": "B", "text": "데이터베이스 모델링"}, {"id": "C", "text": "힌트"}, {"id": "D", "text": "정규화"}]', '["A", "C"]', '카디널리티와 힌트는 SQL 성능 최적화에 직접적으로 관련된 요소입니다.'),
    (7327, 25, 3, 42, 'SQL 최적화에서 ''힌트''란 무엇인가요?', 'SHORT_ANSWER', NULL, '쿼리 실행 시 옵티마이저에게 특정한 경로를 선택하도록 지시하는 메커니즘', '힌트는 옵티마이저에게 실행 계획을 최적화하는 데 도움을 줍니다.')
AS new
ON DUPLICATE KEY UPDATE
    `question_text` = new.`question_text`;

